window.HADITH_CACHE = window.HADITH_CACHE || {};
window.HADITH_CACHE["tirmidzi_0"] = {"1":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ ح و حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُقْبَلُ صَلَاةٌ بِغَيْرِ طُهُورٍ وَلَا صَدَقَةٌ مِنْ غُلُولٍقَالَ هَنَّادٌ فِي حَدِيثِهِ إِلَّا بِطُهُورٍ قَالَ أَبُو عِيسَى هَذَا الْحَدِيثُ أَصَحُّ شَيْءٍ فِي هَذَا الْبَابِ وَأَحْسَنُ وَفِي الْبَاب عَنْ أَبِي الْمَلِيحِ عَنْ أَبِيهِ وَأَبِي هُرَيْرَةَ وَأَنَسٍ وَأَبُو الْمَلِيحِ بْنُ أُسَامَةَ اسْمُهُ عَامِرٌ وَيُقَالُ زَيْدُ بْنُ أُسَامَةَ بْنِ عُمَيْرٍ الْهُذَلِيُّ","id":"telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Simak bin Harb], dan telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Waki'] dari [Israil] dari [Simak] dari [Mush'ab bin Sa'd] dari [Ibnu Umar] dari Nabi Shallahu 'alaihi wa Sallam, beliau bersabda: \" Tidak akan diterima shalat yang dilakukan tanpa bersuci, dan tidak akan diterima sedekah yang berasal dari harta curian.\" Hannad menyebutkan dalam haditsnya, \"tidak suci.\" Abu Isa berkata; \"Hadits ini adalah yang paling shahih dan paling baik dalam bab ini.\" Dalam bab tersebut juga ada hadits dari Abu Al Malih dari Bapaknya dan Abu Hurairah dan Anas. Dan Abu Al Malih bin Usamah namanya adalah Amir, disebut juga Zaid bin Usamah bin Umair Al Hudzali.\""},"2":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنُ بْنُ عِيسَى الْقَزَّازُ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ ح و حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأَ الْعَبْدُ الْمُسْلِمُ أَوْ الْمُؤْمِنُ فَغَسَلَ وَجْهَهُ خَرَجَتْ مِنْ وَجْهِهِ كُلُّ خَطِيئَةٍ نَظَرَ إِلَيْهَا بِعَيْنَيْهِ مَعَ الْمَاءِ أَوْ مَعَ آخِرِ قَطْرِ الْمَاءِ أَوْ نَحْوَ هَذَا وَإِذَا غَسَلَ يَدَيْهِ خَرَجَتْ مِنْ يَدَيْهِ كُلُّ خَطِيئَةٍ بَطَشَتْهَا يَدَاهُ مَعَ الْمَاءِ أَوْ مَعَ آخِرِ قَطْرِ الْمَاءِ حَتَّى يَخْرُجَ نَقِيًّا مِنْ الذُّنُوبِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ حَدِيثُ مَالِكٍ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ وَأَبُو صَالِحٍ وَالِدُ سُهَيْلٍ هُوَ أَبُو صَالِحٍ السَّمَّانُ وَاسْمُهُ ذَكْوَانُ وَأَبُو هُرَيْرَةَ اخْتُلِفَ فِي اسْمِهِ فَقَالُوا عَبْدُ شَمْسٍ وَقَالُوا عَبْدُ اللَّهِ بْنُ عَمْرٍو وَهَكَذَا قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ وَهُوَ الْأَصَحُّ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُثْمَانَ بْنِ عَفَّانَ وَثَوْبَانَ وَالصُّنَابِحِيِّ وَعَمْرِو بْنِ عَبَسَةَ وَسَلْمَانَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَالصُّنَابِحِيُّ الَّذِي رَوَى عَنْ أَبِي بَكْرٍ الصِّدِّيقِ لَيْسَ لَهُ سَمَاعٌ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْمُهُ عَبْدُ الرَّحْمَنِ بْنُ عُسَيْلَةَ وَيُكْنَى أَبَا عَبْدِ اللَّهِ رَحَلَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُبِضَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي الطَّرِيقِ وَقَدْ رَوَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَادِيثَ وَالصُّنَابِحُ بْنُ الْأَعْسَرِ الْأَحْمَسِيُّ صَاحِبُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَالُ لَهُ الصُّنَابِحِيُّ أَيْضًا وَإِنَّمَا حَدِيثُهُ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنِّي مُكَاثِرٌ بِكُمْ الْأُمَمَ فَلَا تَقْتَتِلُنَّ بَعْدِي","id":"Telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] berkata, telah menceritakan kepada kami [Ma'n bin Isa Al Qazzaz] berkata, telah menceritakan kepada kami [Malik bin Anas]. Dari jalur yang lain; dan telah menceritakan kepada kami [Qutaibah] dari [Malik] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] ia berkata, Rasulullah Shallahu 'alaihi wa Sallam bersabda: \" Jika seorang muslim, atau seorang mukmin berwudlu, lalu ia membasuh wajahnya, maka dosa-dosa yang berada di wajahnya karena pandangan mata akan keluar bersama air, atau bersama tetesan air yang terakhir, atau yang semisal itu. Jika ia membasuh tangan, maka dosa-dosa dari tangannya akan keluar bersama air, atau bersama tetesan air yang terakhir hingga ia keluar tanpa dosa sedikitpun.\" Abu Isa berkata; \"Ini adalah hadits hasan shahih, yaitu hadits riwayat Malik dari Suhail dari bapaknya dari Abu Hurairah dan Abu Shalih, ayah Suhail, yaitu Abu Shalih As Samman, dan namanya adalah Dzakwan. Abu Hurairah sendiri masih diperselisihkan tentang namanya; sebagian mengatakan Abdu Syamsi, sebagian mengatakan Abdullah bin 'Amru dan seperti inilah, Muhammad bin Isma'il berkata; \"Itu yang paling benar.\" Abu Isa berkata; dalam bab ini juga ada riwayat dari Utsman bin 'Affan, Tsauban, Ash Shunabihi, Umar bin Abasah, Salman, Abdullah bin 'Amru, dan Ash Shunabihi yang meriwayatkan dari Abu Bakar Ash Shiddiq, namun ia tidak mendengar langsung dari Rasulullah Shallahu 'alaihi wa Sallam. Namanya adalah Abdurrahman bin Usailah, sedang julukannya Abu Abdullah, ia melakukan perjalanan untuk menemui Rasulullah Shallahu 'alaihi wa Sallam, sedangkan Nabi Shallahu 'alaihi wa Sallam sendiri telah wafat ketika ia masih dalam perjalanan. Ia telah meriwayatkan beberapa hadits dari Nabi Shallahu 'alaihi wa Sallam. Ash Shunabi Ibnul A'sar Al Ahmasi adalah seorang sahabat Nabi Shallahu 'alaihi wa Sallam, ia disebut juga dengan nama Ash Shunabihi. Hadits yang ia riwayatkan adalah; ia berkata; aku mendengar Nabi Shallahu 'alaihi wa Sallam bersabda: \"Sesungguhnya aku akan berbanyak-banyakkan umat, maka jangan sekali-kali kalian saling membunuh setelahku.\""},"3":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَهَنَّادٌ وَمَحْمُودُ بْنُ غَيْلَانَ قَالُوا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ مُحَمَّدِ بْنِ الْحَنَفِيَّةِ عَنْ عَلِيٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مِفْتَاحُ الصَّلَاةِ الطُّهُورُ وَتَحْرِيمُهَا التَّكْبِيرُ وَتَحْلِيلُهَا التَّسْلِيمُقَالَ أَبُو عِيسَى هَذَا الْحَدِيثُ أَصَحُّ شَيْءٍ فِي هَذَا الْبَابِ وَأَحْسَنُ وَعَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَقِيلٍ هُوَ صَدُوقٌ وَقَدْ تَكَلَّمَ فِيهِ بَعْضُ أَهْلِ الْعِلْمِ مِنْ قِبَلِ حِفْظِهِ قَالَ أَبُو عِيسَى و سَمِعْت مُحَمَّدَ بْنَ إِسْمَعِيلَ يَقُولُ كَانَ أَحْمَدُ بْنُ حَنْبَلٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَالْحُمَيْدِيُّ يَحْتَجُّونَ بِحَدِيثِ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ قَالَ مُحَمَّدٌ وَهُوَ مُقَارِبُ الْحَدِيثِ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ جَابِرٍ وَأَبِي سَعِيدٍ","id":"Telah menceritakan kepada kami [Qutaibah] dan [Hannad] dan [Mahmud bin Ghailan] mereka berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basyar] berkata, telah menceritakan kepada kami [Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Muhammad bin Aqil] dari [Muhammad Ibnul Hanafiah] dari [Ali] dari Nabi Shallahu 'alaihi wa Sallam, beliau bersabda: \" Kunci shalat adalah bersuci, keharamannya adalah takbir dan penghalalannya adalah salam.\" Abu Isa berkata; \"Hadits ini adalah yang paling shahih dan paling baik dalam bab ini. Abdullah bin Muhammad bin Aqil adalah seorang yang jujur, namun ada beberapa ahli ilmu yang memperbincangkan tentang hafalannya. Abu Isa berkata; \"Aku telah mendengar Muhammad bin Isma'il berkata; \"Ahmad bin Hanbal, Ishaq bin Ibrahim dan Al Humaidi, mereka berdalil dengan hadits Abdullah bin Muhammad bin Aqil. Muhammad berkata; \"Masanya berdekatan.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Jabir dan Abu Sa'id.\""},"4":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ مُحَمَّدُ بْنُ زَنْجَوَيْهِ الْبَغْدَادِيُّ وَغَيْرُ وَاحِدٍ قَالَ حَدَّثَنَا الْحُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ قَرْمٍ عَنْ أَبِي يَحْيَى الْقَتَّاتِ عَنْ مُجَاهِدٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِفْتَاحُ الْجَنَّةِ الصَّلَاةُ وَمِفْتَاحُ الصَّلَاةِ الْوُضُوءُ","id":"telah menceritakan kepada kami [Abu Bakr Muhammad bin Zanjawih Al Baghdadi] dan tidak hanya satu, ia berkata; telah menceritakan kepada kami [Husain bin Muhammad] berkata, telah menceritakan kepada kami [Sulaiman bin Qarn] dari [Abu Yahya Al Qattat] dari [Mujahid] dari [Jabir bin Abdullah] Radliaallahu 'anhuma, ia berkata, Rasulullah Shallahu 'alaihi wa Sallam bersabda: \" Kunci surga adalah shalat, sedang kunci shalat adalah wudlu.\""},"5":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَهَنَّادٌ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ الْخَلَاءَ قَالَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ قَالَ شُعْبَةُ وَقَدْ قَالَ مَرَّةً أُخْرَى أَعُوذُ بِكَ مِنْ الْخُبْثِ وَالْخَبِيثِ أَوْ الْخُبُثِ وَالْخَبَائِثِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَلِيٍّ وَزَيْدِ بْنِ أَرْقَمَ وَجَابِرٍ وَابْنِ مَسْعُودٍ قَالَ أَبُو عِيسَى حَدِيثُ أَنَسٍ أَصَحُّ شَيْءٍ فِي هَذَا الْبَابِ وَأَحْسَنُ وَحَدِيثُ زَيْدِ بْنِ أَرْقَمَ فِي إِسْنَادِهِ اضْطِرَابٌ رَوَى هِشَامٌ الدَّسْتُوَائِيُّ وَسَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ فَقَالَ سَعِيدٌ عَنْ الْقَاسِمِ بْنِ عَوْفٍ الشَّيْبَانِيِّ عَنْ زَيْدِ بْنِ أَرْقَمَ و قَالَ هِشَامٌ الدَّسْتُوَائِيُّ عَنْ قَتَادَةَ عَنْ زَيْدِ بْنِ أَرْقَمَ وَرَوَاهُ شُعْبَةُ وَمَعْمَرٌ عَنْ قَتَادَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ فَقَالَ شُعْبَةُ عَنْ زَيْدِ بْنِ أَرْقَمَ وَقَالَ مَعْمَرٌ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عِيسَى سَأَلْتُ مُحَمَّدًا عَنْ هَذَا فَقَالَ يُحْتَمَلُ أَنْ يَكُونَ قَتَادَةُ رَوَى عَنْهُمَا جَمِيعًا","id":"telah menceritakan kepada kami [Qutaibah] dan [Hannad] mereka berkata; telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] ia berkata, Nabi Shallahu 'alaihi wa Sallam jika akan masuk WC beliau mengucapkan: \"ALLAHUMMA INNI A'UUDZU BIKA (Ya Allah, sesungguhnya aku berlindung kepada-Mu).\" Syu'bah berkata; \"Dalam waktu lain beliau mengucapkan: \"A'UUDZU BIKA MINAL KHUBTSI WAL KHUBIIS (Aku berlindung kepada-Mu dari setan laki-laki dan setan perempuan) atau AL KHUBUTSI WAL KHABA`ITS (Aku berlindung kepada-Mu dari setan laki-laki dan setan perempuan).\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Ali, Zaid bin Arqam, Jabir dan Ibnu Mas'ud.\" Abu Isa berkata; \"Hadits Anas bin Isa adalah yang paling shahih dan paling baik dalam bab ini. Sedangkan dalam hadits Zaid bin Arqam dalam sanadnya ada kerancuan. Hadits ini juga diriwayatkan oleh Hisyam Ad Dastuwa`i dan Sa'id bin Abu Arubah dari Qatadah. Sa'id menyebutkan dari Al Qasim bin 'Auf Asy Syaibani dari Zaid bin Arqam. Dan Hisyam Ad Dastuwa`i dari Qatadah dari Zaid bin Arqam, sedang Syu'bah dan Ma'mar meriwayatkannya dari Qatadah dari An Nadlr bin Anas. Syu'bah menyebutkan dari Zaid bin Arqam. Ma'mar menyebutkan dari An Nadlr bin Anas dari bapaknya, dari Nabi Shallahu 'alaihi wa Sallam. Abu Isa berkata; \"Aku bertanya kepada Muhammad tentang riwayat tersebut, maka ia menjawab, \"Masih dimungkinkan bahwa Qatadah meriwayatkan dari keduanya.\""},"6":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ الْبَصْرِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا دَخَلَ الْخَلَاءَ قَالَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْخُبْثِ وَالْخَبَائِثِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Ahmad bin Abdah Adl Dlabbi Al Bashri] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] berkata; \"Nabi Shallahu 'alaihi wa Sallam jika masuk ke dalam WC beliau mengucapkan: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL KHUBUTSI WAL KHABA`ITS (Ya Allah, aku berlindung kepada-Mu dari setan laki-laki dan perempuan).\" Abu Isa berkata; \"Ini adalah hadits hasan shahih.\""},"7":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا مَالِكُ بْنُ إِسْمَعِيلَ عَنْ إِسْرَائِيلَ بْنِ يُونُسَ عَنْ يُوسُفَ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَرَجَ مِنْ الْخَلَاءِ قَالَ غُفْرَانَكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ إِسْرَائِيلَ عَنْ يُوسُفَ بْنِ أَبِي بُرْدَةَ وَأَبُو بُرْدَةَ بْنُ أَبِي مُوسَى اسْمُهُ عَامِرُ بْنُ عَبْدِ اللَّهِ بْنِ قَيْسٍ الْأَشْعَرِيُّ وَلَا نَعْرِفُ فِي هَذَا الْبَابِ إِلَّا حَدِيثَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"telah menceritakan kepada kami [Muhammad bin Isma'il] berkata, telah menceritakan kepada kami [Malik bin Isma'il] dari [Isra'il bin Yunus] dari [Yusuf bin Abu Burdah] dari [Bapaknya] dari [Aisyah] Radliaallahu 'anha, ia berkata; \"Apabila Nabi Shallahu 'alaihi wa Sallam keluar dari WC, beliau membaca: \" GHUFRAANAKA (Aku mengharap ampunan-Mu).\" Abu Isa berkata; \"Hadits ini derajatnya Hasan Gharib, kami tidak mengetahuinya kecuali ia adalah dari hadits Israil, dari Yusuf bin Abu Burdah, sedangkan Abu Burdah bin Abu Musa namanya adalah 'Amir bin Abdullah bin Qais Al Asy'ari. Dan kami tidak mengetahui dalam bab ini kecuali hadits Aisyah Radliaallahu 'anha dari Nabi Shallahu 'alaihi wa Sallam.\" "},"8":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عَطَاءَ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَيْتُمْ الْغَائِطَ فَلَا تَسْتَقْبِلُوا الْقِبْلَةَ بِغَائِطٍ وَلَا بَوْلٍ وَلَا تَسْتَدْ��ِرُوهَا وَلَكِنْ شَرِّقُوا أَوْ غَرِّبُواقَالَ أَبُو أَيُّوبَ فَقَدِمْنَا الشَّامَ فَوَجَدْنَا مَرَاحِيضَ قَدْ بُنِيَتْ مُسْتَقْبَلَ الْقِبْلَةِ فَنَنْحَرِفُ عَنْهَا وَنَسْتَغْفِرُ اللَّهَ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ جَزْءٍ الزُّبَيْدِيِّ وَمَعْقِلِ بْنِ أَبِي الْهَيْثَمِ وَيُقَالُ مَعْقِلُ بْنُ أَبِي مَعْقِلٍ وَأَبِي أُمَامَةَ وَأَبِي هُرَيْرَةَ وَسَهْلِ بْنِ حُنَيْفٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي أَيُّوبَ أَحْسَنُ شَيْءٍ فِي هَذَا الْبَابِ وَأَصَحُّ وَأَبُو أَيُّوبَ اسْمُهُ خَالِدُ بْنُ زَيْدٍ وَالزُّهْرِيُّ اسْمُهُ مُحَمَّدُ بْنُ مُسْلِمٍ بْنِ عُبَيْدِ اللَّهِ بْنِ شِهَابٍ الزُّهْرِيُّ وَكُنْيَتُهُ أَبُو بَكْرٍ قَالَ أَبُو الْوَلِيدِ الْمَكِّيُّ قَالَ أَبُو عَبْدِ اللَّهِ مُحَمَّدُ بْنُ إِدْرِيسَ الشَّافِعِيُّ إِنَّمَا مَعْنَى قَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسْتَقْبِلُوا الْقِبْلَةَ بِغَائِطٍ وَلَا بِبَوْلٍ وَلَا تَسْتَدْبِرُوهَا إِنَّمَا هَذَا فِي الْفَيَافِي وَأَمَّا فِي الْكُنُفِ الْمَبْنِيَّةِ لَهُ رُخْصَةٌ فِي أَنْ يَسْتَقْبِلَهَا وَهَكَذَا قَالَ إِسْحَقُ بْنُ إِبْرَاهِيمَ و قَالَ أَحْمَدُ بْنُ حَنْبَلٍ رَحِمَهُ اللَّهُ إِنَّمَا الرُّخْصَةُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي اسْتِدْبَارِ الْقِبْلَةِ بِغَائِطٍ أَوْ بَوْلٍ وَأَمَّا اسْتِقْبَالُ الْقِبْلَةِ فَلَا يَسْتَقْبِلُهَا كَأَنَّهُ لَمْ يَرَ فِي الصَّحْرَاءِ وَلَا فِي الْكُنُفِ أَنْ يَسْتَقْبِلَ الْقِبْلَةَ","id":"telah menceritakan kepada kami [Sa'id bin Abdurrahman Al Makhzumi] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari ['Atho` bin Yazid Al Laitsi] dari [Abu Ayyub Al Anshari] ia berkata, Rasulullah Shallahu 'alaihi wa Sallam bersabda: \" Jika engkau buang hajat maka janganlah menghadap kiblat atau membelakanginya, baik buang air besar ataupun air kecil. Akan tetapi menghadaplah ke timur atau ke barat.\" Abu Ayyub berkata; \"Ketika kami tiba di Syam, kami mendapati WC mereka dibangun menghadap arah kiblat, maka kami berpaling darinya dan beristighfar kepada Allah.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin Al Harits bin Jaz`i Az Zubaidi dan Ma'qil bin Abu Al Haitsam -disebut juga dengan Ma'qil bin Abu Umamah-, Abu Hurairah dan Suhail bin Hanif.\" Abu Isa berkata; \"Dalam bab ini hadits riwayat Abu Ayyub adalah yang paling baik dan paling shahih. Abu Ayyub namanya adalah Khalid bin Zaid, sedangkan Az Zuhri namanya adalah Muhammad bin Muslim bin Ubaidullah bin Syihab Az Zuhri, julukannya adalah Abu Bakr.\" Abu Al Walid Al Makki berkata; Abu Abdullah Muhammad bin bin Idris Asy Syafi'i berkata; \"Hanyasanya makna dari sabda Nabi Shallahu 'alaihi wa Sallam \"Janganlah kalian menghadap kiblat atau membelakanginya ketika buang air besar atau kecil\" adalah di tempat yang terbuka. Adapun jika di dalam bangunan yang tertutup maka di sana ada keringanan untuk menghadap ke arah kiblat.\" Seperti ini pula yang dikatakan oleh Ishaq bin Ibrahim. Sedangkan Ahmad bin Hanbal Rahimahullah mengatakan; \"Keringanan ketika buang air besar atau kecil dari Nabi Shallahu 'alaihi wa Sallam itu hanya untuk membelakanginya, adapun menghadap ke arahnya tetap tidak diperbolehkan.\" Seakan-akan Imam Ahmad tidak membedakan di padang pasir atau dalam bangunan yang tertutup untuk menghadap ke arah kiblat.\""},"9":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ أَبَانَ بْنِ صَالِحٍ عَنْ مُجَاهِدٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَسْتَقْبِلَ الْقِبْلَةَ بِبَوْلٍ فَرَأَيْتُهُ قَبْلَ أَنْ يُقْبَضَ بِعَامٍ يَسْتَقْبِلُهَاوَفِي الْبَاب عَنْ أَبِي قَتَادَةَ وَعَائِشَةَ وَعَمَّارِ بْنِ يَاسِرٍ قَالَ أَبُو عِيسَى حَدِيثُ جَابِرٍ فِي هَذَا الْبَابِ حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"telah menceritakan kepada kami [Muhammad bin Basyar] dan [Muhammad bin Al Mutsanna] keduanya berkata; telah menceritakan kepada kami [Wahb bin Jarir] berkata, telah menceritakan kepada kami [Bapakku] dari [Muhammad bin Ishaq] dari [Aban bin Shalih] dari [Mujahid] dari [Jabir bin Abdullah] ia berkata; Nabi Shallahu 'alaihi wa Sallam melarang menghadap arah kiblat ketika hendak kencing, namun aku melihat beliau setahun sebelum wafat menghadap arah kiblat.\" Dalam bab ini juga ada riwayat dari Abu Qatadah, Aisyah dan Ammar bin Yasir.\" Abu Isa berkata; \"Dalam bab ini, hadits riwayat Jabir derajatnya adalah hasan gharib.\""},"10":{"ar":"وَقَدْ رَوَى هَذَا الْحَدِيثَ ابْنُ لَهِيعَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ أَبِي قَتَادَةَأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبُولُ مُسْتَقْبِلَ الْقِبْلَةِحَدَّثَنَا بِذَلِكَ قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ وَحَدِيثُ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَحُّ مِنْ حَدِيثِ ابْنِ لَهِيعَةَ وَابْنُ لَهِيعَةَ ضَعِيفٌ عِنْدَ أَهْلِ الْحَدِيثِ ضَعَّفَهُ يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ وَغَيْرُهُ مِنْ قِبَلِ حِفْظِهِ","id":"Dan hadits ini telah diriwayatkan oleh [Ibnu Lahi'ah], dari [Abu Zubair], dari [Jabir], dari [Abu Qatadah], bahwa dia pernah melihat Nabi Shallahu 'alaihi wa Sallam kencing menghadap ke arah Qiblat.\" [Qutaibah] telah menceritakan demikian kepada kami, ia berkata; \"Ibnu Lahi'ah telah menceritakan kepada kami.\" Dan hadits Jabir yang diriwayatkan dari Nabi Shallahu 'alaihi wa Sallam lebih shahih dari hadits Ibnu Lahi'ah, karena Ibnu Lahi'ah adalah seorang yang lemah menurut para ahli hadits, Imam Yahya bin Sa'id Al Qaththan dan yang lainnya telah mendla'ifkannya dari sisi hafalannya.\""},"11":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ عَمِّهِ وَاسِعِ بْنِ حَبَّانَ عَنْ ابْنِ عُمَرَ قَالَرَقِيتُ يَوْمًا عَلَى بَيْتِ حَفْصَةَ فَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى حَاجَتِهِ مُسْتَقْبِلَ الشَّامِ مُسْتَدْبِرَ الْكَعْبَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Ubaidullah bin Umar] dari [Muhammad bin Yahya bin Habban] dari pamannya - [Wasi' bin Habban] - dari [Ibnu Umar] ia berkata; \"Suatu hari aku naik ke loteng rumah Hafshah, lalu aku melihat Nabi Shallahu 'alaihi wa Sallam sedang membuang hajat sambil menghadap arah Syam dengan membelakangi Ka'bah.\" Abu Isa berkata; \"Hadits ini derajatnya adalah hasan shahih.\""},"12":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا شَرِيكٌ عَنْ الْمِقْدَامِ بْنِ شُرَيْحٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْمَنْ حَدَّثَكُمْ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَبُولُ قَائِمًا فَلَا تُصَدِّقُوهُ مَا كَانَ يَبُولُ إِلَّا قَاعِدًاقَالَ وَفِي الْبَاب عَنْ عُمَرَ وَبُرَيْدَةَ وَعَبْدِ الرَّحْمَنِ بْنِ حَسَنَةَ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ أَحْسَنُ شَيْءٍ فِي هَذَا الْبَابِ وَأَصَحُّ وَحَدِيثُ عُمَرَ إِنَّمَا رُوِيَ مِنْ حَدِيثِ عَبْدِ الْكَرِيمِ بْنِ أَبِي الْمُخَارِقِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ قَالَ رَآنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَبُولُ قَائِمًا فَقَالَ يَا عُمَرُ لَا تَبُلْ قَائِمًا فَمَا بُلْتُ قَائِمًا بَعْدُ قَالَ أَبُو عِيسَى وَإِنَّمَا رَفَعَ هَذَا الْحَدِيثَ عَبْدُ الْكَرِيمِ بْنُ أَبِي الْمُخَارِقِ وَهُوَ ضَعِيفٌ عِنْدَ أَهْلِ الْحَدِيثِ ضَعَّفَهُ أَيُّوبُ السَّخْتِيَانِيُّ وَتَكَلَّمَ فِيهِ وَرَوَى عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ مَا بُلْتُ قَائِمًا مُنْذُ أَسْلَمْتُ وَهَذَا أَصَحُّ مِنْ حَدِيثِ عَبْدِ الْكَرِيمِ وَحَدِيثُ بُرَيْدَةَ فِي هَذَا غَيْرُ مَحْفُوظٍ وَمَعْنَى النَّهْيِ عَنْ الْبَوْلِ قَائِمًا عَلَى التَّأْدِيبِ لَا عَلَى التَّحْرِيمِ وَقَدْ رُوِيَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَ إِنَّ مِنْ الْجَفَاءِ أَنْ تَبُولَ وَأَنْتَ قَائِمٌ","id":"telah menceritakan kepada kami [Ali Bin Hujr] berkata, telah mengabarkan kepada kami [Syarik] dari [Al Miqdam bin Syuraih] dari [Bapaknya] dari [Aisyah] ia berkata; \" Barangsiapa menceritakan kepada kalian bahwa Nabi Shallahu 'alaihi wa Sallam buang air kecil dengan berdiri maka janganlah kalian percayai, karena beliau tidaklah buang air kecil kecuali dengan duduk.\" Dia berkata; \"Dalam bab ini ada juga hadits dari sahabat Umar, Buraidah dan Abdurrahman bin Hasanah.\" Abu Isa berkata; \"Hadits Aisyah adalah yang paling baik dan paling shahih dalam bab ini, sedangkan hadits Umar diriwayatkan dari hadits Abdul Karim bin Abul Mukhariq, dari Nafi', dari Ibnu Umar, dari Umar, ia berkata; \"Nabi Shallahu 'alaihi wa Sallam pernah melihatku kencing dalam keadaan berdiri, kemudian beliau bersabda: \"Wahai Umar, janganlah kamu kencing dengan berdiri, \" maka setelah itu aku tidak pernah lagi kencing dengan berdiri.\" Abu Isa berkata; \"Hanyasanya yang memarfu'kan hadits ini adalah Abdul Karim bin Abul Mukhariq, dan dia adalah seorang yang lemah menurut para ahli hadits. Abu Ayyub As Sikhtiyani juga telah melemahkan dan memperbincangkannya.\" Ubaidullah telah meriwayatkan dari Nafi', dari Ibnu Umar, ia berkata; Umar Radliaallahu 'anhu berkata; \"Aku tidak pernah kencing dengan berdiri sejak aku masuk Islam.\" Dan hadits ini lebih shahih ketimbang hadits Abdul Karim, sedangkan hadits Buraidah dalam bab ini tidaklah mahfudz (terjaga).\" Sedangkan makna larangan kencing berdiri adalah berkaitan dengan tatakrama, bukan larangan yang bersifat pengharaman. Diriwayatkan dari Abdullah bin Mas'ud, ia berkata; \"Sesungguhnya termasuk perangai buruk apabila kamu kencing dengan berdiri.\""},"13":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى سُبَاطَةَ قَوْمٍ فَبَالَ عَلَيْهَا قَائِمًا فَأَتَيْتُهُ بِوَضُوءٍ فَذَهَبْتُ لِأَتَأَخَّرَ عَنْهُ فَدَعَانِي حَتَّى كُنْتُ عِنْدَ عَقِبَيْهِ فَتَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِقَالَ أَبُو عِيسَى و سَمِعْت الْجَارُودَ يَقُولُ سَمِعْتُ وَكِيعًا يُحَدِّثُ بِهَذَا الْحَدِيثِ عَنْ الْأَعْمَشِ ثُمَّ قَالَ وَكِيعٌ هَذَا أَصَحُّ حَدِيثٍ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْحِ و سَمِعْت أَبَا عَمَّارٍ الْحُسَيْنَ بْنَ حُرَيْثٍ يَقُولُ سَمِعْتُ وَكِيعًا فَذَكَرَ نَحْوَهُ قَالَ أَبُو عِيسَى وَهَكَذَا رَوَى مَنْصُورٌ وَعُبَيْدَةُ الضَّبِّيُّ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ مِثْلَ رِوَايَةِ الْأَعْمَشِ وَرَوَى حَمَّادُ بْنُ أَبِي سُلَيْمَانَ وَعَاصِمُ بْنُ بَهْدَلَةَ عَنْ أَبِي وَائِلٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَدِيثُ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ أَصَحُّ وَقَدْ رَخَّصَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ فِي الْبَوْلِ قَائِمًا قَالَ أَبُو عِيسَى وَعَبِيدَةُ بْنُ عَمْرٍو السَّلْمَانِيُّ رَوَى عَنْهُ إِبْرَاهِيمُ النَّخَعِيُّ وَعَبِيدَةُ مِنْ كِبَارِ التَّابِعِينَ يُرْوَى عَنْ عَبِيدَةَ أَنَّهُ قَالَ أَسْلَمْتُ قَبْلَ وَفَاةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَنَتَيْنِ وَعُبَيْدَةُ الضَّبِّيُّ صَاحِبُ إِبْرَاهِيمَ هُوَ عُبَيْدَةُ بْنُ مُعَتِّبٍ الضَّبِّيُّ وَيُكْنَى أَبَا عَبْدِ الْكَرِيمِ","id":"telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Abu Wa`il] dari [Hudzaifah] berkata; \"Nabi Shallahu 'alaihi wa Sallam pernah mendatangi tempat pembuangan sampah suatu kaum, lalu beliau kencing sambil berdiri. Aku pergi agar menjauh dari beliau, namun beliau justru memanggilku hingga aku berada di sisinya, kemudian beliau berwudlu dan mengusap khufnya.\" Abu Isa berkata; \"Aku mendengar [Al Jarud] berkata; \"Aku mendengar [Waki'] menceritakan hadits ini dari [Al A'masy], setelah itu Waki' berkata; \"Ini adalah hadits yang paling shahih yang diriwayatkan dari Nabi Shallahu 'alaihi wa Sallam tentang mengusap khuf. Dan aku juga mendengar Abu Ammar Al Husain bin Huraib berkata; \"Aku mendengar Waki', lalu ia menyebutkan seperti itu.\" Abu Isa berkata; \"Seperti inilah [Manshur] dan [Ubaidah Adl Dlabbi] meriwayatkan dari [Abu Wa`il] dari [Hudzaifah], sebagaimana riwayat Al A'masy.\" [Hammad bin Abu Sulaiman] dan [Ashim bin Badalah] juga meriwayatkan dari [Abu Wa`il], dari [Al Mughirah bin Syu'bah], dari Nabi Shallahu 'alaihi wa Sallam.\" Sedangkan hadits Abu Wa`il dari Hudzaifah adalah hadits yang paling shahih. Sebagian ahlu ilmu telah memberi keringanan kencing sambil berdiri.\" Abu Isa berkata; \"Ibrahin An Nakha'i telah meriwayatkan dari Abidah bin 'Amru As Salmani, dan 'Abidah adalah termasuk ulama Tabi`in senior.\" Diriwayatkan bahwa Abidah pernah berkata; \"Aku masuk Islam dua tahun sebelum wafatnya Nabi Shallahu 'alaihi wa Sallam.\" Sedangkan Ubaidah Adl Dlabbi adalah sahabat Ibrahim, yaitu Ubaidah bin Mu'attib Adl Dlabbi, yang dijuluki dengan Abu Abdul Karim.\""},"14":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ الْمُلَائِيُّ عَنْ الْأَعْمَشِ عَنْ أَنَسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ الْحَاجَةَ لَمْ يَرْفَعْ ثَوْبَهُ حَتَّى يَدْنُوَ مِنْ الْأَرْضِقَالَ أَبُو عِيسَى هَكَذَا رَوَى مُحَمَّدُ بْنُ رَبِيعَةَ عَنْ الْأَعْمَشِ عَنْ أَنَسٍ هَذَا الْحَدِيثَ وَرَوَى وَكِيعٌ وَأَبُو يَحْيَى الْحِمَّانِيُّ عَنْ الْأَعْمَشِ قَالَ قَالَ ابْنُ عُمَرَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ الْحَاجَةَ لَمْ يَرْفَعْ ثَوْبَهُ حَتَّى يَدْنُوَ مِنْ الْأَرْضِ وَكِلَا الْحَدِيثَيْنِ مُرْسَلٌ وَيُقَالُ لَمْ يَسْمَعْ الْأَعْمَشُ مِنْ أَنَسٍ وَلَا مِنْ أَحَدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ نَظَرَ إِلَى أَنَسِ بْنِ مَالِكٍ قَالَ رَأَيْتُهُ يُصَلِّي فَذَكَرَ عَنْهُ حِكَايَةً فِي الصَّلَاةِ وَالْأَعْمَشُ اسْمُهُ سُلَيْمَانُ بْنُ مِهْرَانَ أَبُو مُحَمَّدٍ الْكَاهِلِيُّ وَهُوَ مَوْلًى لَهُمْ قَالَ الْأَعْمَشُ كَانَ أَبِي حَمِيلًا فَوَرَّثَهُ مَسْرُوقٌ","id":"telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Abdussalam bin Harb Al Mula`i] dari [Al A'masy] dari [Anas] ia berkata; \" Apabila Nabi Shallahu 'alaihi wa Sallam hendak buang hajat beliau tidak mengangkat kainnya hingga hampir menyentuh tanah.\" Abu Isa berkata; \"Demikianlah [Muhammad bin Rabi'ah] meriwayatkan hadits ini dari [Al A'masy], dari [Anas].\" Sementara [Waki'] dan [Abu Yahya Al Himmani] meriwayatkan dari [Al A'masy], ia berkata; \" [Ibnu Umar] berkata; \"Apabila Nabi Shallahu 'alaihi wa Sallam hendak buang hajat beliau tidak mengangkat kainnya hingga hampir menyentuh tanah.\" Dan kedua hadits ini adalah mursal. Dikatakan juga bahwa Al A'masy tidak mendengar dari Anas, dan tidak juga dari salah seorang sahabat Nabi Shallahu 'alaihi wa Sallam. Ia melihat Anas bin Malik, lalu ia berkata; \"Aku melihat Anas sedang shalat, \" lalu ia menyebutkan darinya tentang shalat.\" Sedangkan nama Al A'masy adalah Sulaiman bin Mihran Abu Muhammad Al Kahili, dan ia adalah seorang mantan budak dari bani Kahili. Al A'masy berkata; \"Bapakku dulu memiliki anak yang masih dalam kandungan kemudian diwarisi oleh Masruq.\" "},"15":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْمَكِّيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مَعْمَرٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَمَسَّ الرَّجُلُ ذَكَرَهُ بِيَمِينِهِوَفِي هَذَا الْبَاب عَنْ عَائِشَةَ وَسَلْمَانَ وَأبِي هُرَيْرَةَ وَسَهْلِ بْنِ حُنَيْفٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو قَتَادَةَ الْأَنْصَارِيُّ اسْمُهُ الْحَارِثُ بْنُ رِبْعِيٍّ وَالْعَمَلُ عَلَى هَذَا عِنْدَ عَامَّةِ أَهْلِ الْعِلْمِ كَرِهُوا الِاسْتِنْجَاءَ بِالْيَمِينِ","id":"telah menceritakan kepada kami [Muhammad bin Abu Umar Al Makki] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ma'mar] dari [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dari [Bapaknya] berkata; \"Nabi Shallahu 'alaihi wa Sallam melarang seorang laki-laki menyentuh kemaluannya dengan tangan kanannya.\" Dalam bab ini juga ada riwayat dari Aisyah, Salman, Abu Hurairah dan Suhail bin Hanif. Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\" Sedangkan Abu Qatadah Al Anshari namanya adalah Al Harits Ar Rib'i. Menurut para ahli ilmu penerapan hadits ini adalah dimakruhkannya melakukan istinja` (cebok) dengan menggunakan tangan kanan.\""},"16":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَ قِيلَ لِسَلْمَانَقَدْ عَلَّمَكُمْ نَبِيُّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلَّ شَيْءٍ حَتَّى الْخِرَاءَةَ فَقَالَ سَلْمَانُ أَجَلْ نَهَانَا أَنْ نَسْتَقْبِلَ الْقِبْلَةَ بِغَائِطٍ أَوْ بَوْلٍ وَأَنْ نَسْتَنْجِيَ بِالْيَمِينِ أَوْ أَنْ يَسْتَنْجِيَ أَحَدُنَا بِأَقَلَّ مِنْ ثَلَاثَةِ أَحْجَارٍ أَوْ أَنْ نَسْتَنْجِيَ بِرَجِيعٍ أَوْ بِعَظْمٍقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَائِشَةَ وَخُزَيْمَةَ بْنِ ثَابِتٍ وَجَابِرٍ وَخَلَّادِ بْنِ السَّائِبِ عَنْ أَبِيهِ قَالَ أَبُو عِيسَى وَحَدِيثُ سَلْمَانَ فِي هَذَا الْبَابِ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ رَأَوْا أَنَّ الِاسْتِنْجَاءَ بِالْحِجَارَةِ يُجْزِئُ وَإِنْ لَمْ يَسْتَنْجِ بِالْمَاءِ إِذَا أَنْقَى أَثَرَ الْغَائِطِ وَالْبَوْلِ وَبِهِ يَقُولُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ","id":"telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Abdurrahman bin Yazid] ia berkata: \"Apakah Nabi kalian Shallahu 'alaihi wa Sallam mengajarkan segala sesuatu hingga cara buang hajat?\" [Salman] menjawab, \"Benar, beliau melarang kami menghadap kiblat saat buang air besar atau air kecil, beristinja` dengan tangan kanan, dan beristinja` dengan batu kurang dari tiga buah, serta beristinja` dengan menggunakan kotoran binatang atau tulang.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Aisyah, Khuzaimah bin Tsabit, Jabir, Khallad Ibnu As Sa`ib, dari bapaknya.\" Abu Isa berkata; \"dalam bab ini hadits Salman derajatnya hasan shahih, ini adalah pendapat kebanyakan ahli ilmu dari kalangan sahabat Nabi Shallahu 'alaihi wa Sallam dan orang-orang setelahnya. Mereka berpendapat bahwa beristinja` dengan batu sudah mencukupi meskipun ia tidak melakukannya dengan air, yaitu ketika batu tersebut telah dapat membersihkan kotoran yang ada. Pendapat ini juga diambil oleh Ats Tsauri, Ibnul Mubarak, Asy Syafi'i, Ahmad dan Ishaq.\""},"17":{"ar":"حَدَّثَنَا هَنَّادٌ وَقُتَيْبَةُ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحَاجَتِهِ فَقَالَ الْتَمِسْ لِي ثَلَاثَةَ أَحْجَارٍ قَالَ فَأَتَيْتُهُ بِحَجَرَيْنِ وَرَوْثَةٍ فَأَخَذَ الْحَجَرَيْنِ وَأَلْقَى الرَّوْثَةَ وَقَالَ إِنَّهَا رِكْسٌقَالَ أَبُو عِيسَى وَهَكَذَا رَوَى قَيْسُ بْنُ الرَّبِيعِ هَذَا الْحَدِيثَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ نَحْوَ حَدِيثِ إِسْرَائِيلَ وَرَوَى مَعْمَرٌ وَعَمَّارُ بْنُ رُزَيْقٍ عَنْ أَبِي إِسْحَقَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ وَرَوَى زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ وَرَوَى زَكَرِيَّا بْنُ أَبِي زَائِدَةَ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ وَهَذَا حَدِيثٌ فِيهِ اضْطِرَابٌ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ الْعَبْدِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَأَلْتُ أَبَا عُبَيْدَةَ بْنَ عَبْدِ اللَّهِ هَلْ تَذْكُرُ مِنْ عَبْدِ اللَّهِ شَيْئًا قَالَ لَا قَالَ أَبُو عِيسَى سَأَلْتُ عَبْدَ اللَّهِ بْنَ عَبْدِ الرَّحْمَنِ أَيُّ الرِّوَايَاتِ فِي هَذَا الْحَدِيثِ عَنْ أَبِي إِسْحَقَ أَصَحُّ فَلَمْ يَقْضِ فِيهِ بِشَيْءٍ وَسَأَلْتُ مُحَمَّدًا عَنْ هَذَا فَلَمْ يَقْضِ فِيهِ بِشَيْءٍ وَكَأَنَّهُ رَأَى حَدِيثَ زُهَيْرٍ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ أَشْبَهَ وَوَضَعَهُ فِي كِتَابِ الْجَامِعِ قَالَ أَبُو عِيسَى وَأَصَحُّ شَيْءٍ فِي هَذَا عِنْدِي حَدِيثُ إِسْرَائِيلَ وَقَيْسٍ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ لِأَنَّ إِسْرَائِيلَ أَثْبَتُ وَأَحْفَظُ لِحَدِيثِ أَبِي إِسْحَقَ مِنْ هَؤُلَاءِ وَتَابَعَهُ عَلَى ذَلِكَ قَيْسُ بْنُ الرَّبِيعِ قَالَ أَبُو عِيسَى و سَمِعْت أَبَا مُوسَى مُحَمَّدَ بْنَ الْمُثَنَّى يَقُولُ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ مَهْدِيٍّ يَقُولُ مَا فَاتَنِي الَّذِي فَاتَنِي مِنْ حَدِيثِ سُفْيَانَ الثَّوْرِيِّ عَنْ أَبِي إِسْحَقَ إِلَّا لِمَا اتَّكَلْتُ بِهِ عَلَى إِسْرَائِيلَ لِأَنَّهُ كَانَ يَأْتِي بِهِ أَتَمَّ قَالَ أَبُو عِيسَى وَزُهَيْرٌ فِي أَبِي إِسْحَقَ لَيْسَ بِذَاكَ لِأَنَّ سَمَاعَهُ مِنْهُ بِآخِرَةٍ قَالَ و سَمِعْت أَحْمَدَ بْنَ الْحَسَنِ التِّرْمِذِيَّ يَقُولُ سَمِعْتُ أَحْمَدَ بْنَ حَنْبَلٍ يَقُولُ إِذَا سَمِعْتَ الْحَدِيثَ عَنْ زَائِدَةَ وَزُهَيْرٍ فَلَا تُبَالِي أَنْ لَا تَسْمَعَهُ مِنْ غَيْرِهِمَا إِلَّا حَدِيثَ أَبِي إِسْحَقَ وَأَبُو إِسْحَقَ اسْمُهُ عَمْرُو بْنُ عَبْدِ اللَّهِ السَّبِيعِيُّ الْهَمْدَانِيُّ وَأَبُو عُبَيْدَةَ بْنُ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ لَمْ يَسْمَعْ مِنْ أَبِيهِ وَلَا يُعْرَفُ اسْمُهُ","id":"telah menceritakan kepada kami [Hannad] dan [Qutaibah] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Isra'il] dari [Abu Ishaq] dari [Abu Ubaidah] dari [Abdullah] ia berkata, Nabi Shallahu 'alaihi wa Sallam keluar untuk buang hajat, beliau lalu bersabda: \" Carikanlah tiga buah batu untukku, \" Abu Ubaid berkata; \"Maka aku pun membawakan beliau dua batu dan satu kotoran binatang yang telah kering, beliau hanya mengambil dua batu dan melemparkan kotoran binatang tersebut kemudian bersabda: \"Sesungguhnya kotoran binatang itu najis.\" Abu Isa berkata; \"Seperti inilah [Qais bin Ar Rabi'] meriwayatkan hadits ini dari [Abu Ishaq], dari [Abu Ubaidah], dari [Abdullah] sebagaimana hadits riwayat Israil. [Ma'mar] dan ['Ammar bin Ruzaiq] juga meriwayatkan dari [Abu Ishaq], dari [Alqamah], dari [Abdullah]. [Zuhair] meriwayatkan dari [Abu Ishaq], dari [Abdurrahman Ibnul Aswad], dari bapaknya - [Al Aswad bin Yazid] -, dari [Abdullah]. Namun hadits ini ada kekacauan di dalamnya. Telah menceritakan kepada kami Muhammad bin Basysyar Al Abdi berkata, telah menceritakan kepada kami Muhammad bin Ja'far berkata, telah menceritakan kepada kami Syu'bah dari 'Amru bin Murrah ia berkata; \"Apakah engkau mengingat sesuatu dari Abdullah?\" ia menjawab, \"Tidak.\" Abu Isa berkata; \"Aku bertanya kepada Abdullah bin Abdurrahman; riwayat manakah yang paling shahih dalam hadits Abu Ishaq ini?\" namun ia tidak menjawab dengan sesuatu pun. Dan aku juga bertanya kepada Muhammad, namun ia juga tidak memberikan menjawab apapun.\" Seakan-akan ia melihat bahwa hadits Zuhair dari Abu Ishaq, dari Abdurrahman Ibnul Aswad, dari bapaknya, dari Abdullah mempunyai kemiripan, lalu ia meletakkannya dalam kitab Al Jami'.\" Abu Isa berkata; \"Dalam bab ini menurutku yang paling shahih adalah hadits Israil dan Qais dari Abu Ishaq, dari Abu Ubaidah, dari Abdullah. Sebab Israil adalah seorang yang lebih kuat dan hafal dengan hadits Abu Ishaq dari yang lainnya. Hal itu diperkuat oleh Qais bin Ar Rabi'.\" Abu Isa berkata; \"Aku mendengar Abu Musa Muhammad Ibnul Mutsanna berkata; aku mendengar Abdurrahman bin Mahdi berkata; \"Tidaklah hilang dariku sebagaimana hilang dariku dari hadits Sufyan Ats Tsauri, dari Abu Ishaq kecuali sesuatu yang aku pegang atas Israil, karena ia meriwayatkan dengan sesuatu yang lebih sempurna.\" Abu Isa berkata; \"Riwayat Zuhair dari Abu Ishaq tidaklah demikian, karena ia mendengarnya disaat-saat akhir.\" Ia berkata; \"Aku mendengar Ahmad Ibnul Hasan At Turmudzi berkata; \"Aku mendengar Ahmad bin Hanbal mengatakan; \"Apabila engkau mendengar hadits dari Za`idah dan Zuhair maka mantaplah, meskipun engkau tidak mendengarnya dari yang lain, kecuali hadits dari Abu Ishaq, sedang Abu Ishaq namanya adalah 'Amru bin Abdullah As Sabi'i Al Hamdani, dan Abu Ubaidah bin Abdullah bin Mas'ud tidak mendengar dari bapaknya, dan namanya juga tidak dikenal.\""},"18":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسْتَنْجُوا بِالرَّوْثِ وَلَا بِالْعِظَامِ فَإِنَّهُ زَادُ إِخْوَانِكُمْ مِنْ الْجِنِّوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَسَلْمَانَ وَجَابِرٍ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى وَقَدْ رَوَى هَذَا الْحَدِيثَ إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ وَغَيْرُهُ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ أَنَّهُ كَانَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ الْجِنِّ الْحَدِيثَ بِطُولِهِ فَقَالَ الشَّعْبِيُّ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَسْتَنْجُوا بِالرَّوْثِ وَلَا بِالْعِظَامِ فَإِنَّهُ زَادُ إِخْوَانِكُمْ مِنْ الْجِنِّ وَكَأَنَّ رِوَايَةَ إِسْمَعِيلَ أَصَحُّ مِنْ رِوَايَةِ حَفْصِ بْنِ غِيَاثٍ وَالْعَمَلُ عَلَى هَذَا الْحَدِيثِ عِنْدَ أَهْلِ الْعِلْمِ وَفِي الْبَاب عَنْ جَابِرٍ وَابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا","id":"telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Alqamah] dari [Abdullah bin Mas'ud] ia berkata, Rasulullah Shallahu 'alaihi wa Sallam bersabda: \" Janganlah kalian beristinja` dengan menggunakan kotoran hewan dan tulang, karena sesungguhnya ia adalah makanan saudara kalian dari bangsa jin.\" Dalam bab ini ada juga hadits dari Abu Hurairah, Salman, Jabir dan Ibnu Umar.\" Abu Isa berkata; \" [Isma'il bin Ibrahim] dan selainnya meriwayatkan hadits ini dari [Dawud bin Abu Hind], dari [Asy Sya'bi], dari [Alqamah], dari [Abdullah], bahwasanya ia bersama Nabi Shallahu 'alaihi wa Sallam pada malam lailatul qadar…haditsnya panjang. Asy Sya'bi berkata, Nabi Shallahu 'alaihi wa Sallam bersabda: \"Janganlah kalian beristinja` dengan kotoran dan tulang karena sesungguhnya ia adalah makanan saudara kalian dari bangsa jin.\" Seakan-akan hadits riwayat Isma'il lebih shahih dari riwayat Hafsh bin Ghiyats. Para ulama mengamalkan hadits ini. Dan dalam hadits ada hadits lain juga yang diriwayatkan oleh Jabir dan Ibnu Umar Radliaallahu 'anhuma.\""},"19":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَمُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ الْبَصْرِيُّ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ مُعَاذَةَ عَنْ عَائِشَةَ قَالَتْمُرْنَ أَزْوَاجَكُنَّ أَنْ يَسْتَطِيبُوا بِالْمَاءِ فَإِنِّي أَسْتَحْيِيهِمْ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَفْعَلُهُوَفِي الْبَاب عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ الْبَجَلِيِّ وَأَنَسٍ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَعَلَيْهِ الْعَمَلُ عِنْدَ أَهْلِ الْعِلْمِ يَخْتَارُونَ الِاسْتِنْجَاءَ بِالْمَاءِ وَإِنْ كَانَ الِاسْتِنْجَاءُ بِالْحِجَارَةِ يُجْزِئُ عِنْدَهُمْ فَإِنَّهُمْ اسْتَحَبُّوا الِاسْتِنْجَاءَ بِالْمَاءِ وَرَأَوْهُ أَفْضَلَ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ","id":"telah menceritakan kepada kami [Qutaibah] dan [Muhammad bin Abdul Malik bin Abu Asy Syawarib Al Bashri] keduanya berkata; telah menceritakan kepada kami [Abu Awanah] dari [Qotadah] dari [Mu'adzah] dari [Aisyah] berkata; \" Perintahkanlah suami-suami kalian bersuci dengan air, aku malu dengan mereka, sesungguhnya Rasulullah Shallahu 'alaihi wa Sallam melakukannya.\" Dalam bab ini ada juga hadits dari sahabat Jarir bin Abdullah Al Bajali, Anas dan Abu Hurairah. Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, dan para Ahlul Ilmi mengamalkan hadits ini, mereka memilih bersuci dengan air sekalipun bersuci dengan batu menurut mereka sah, Dan mereka lebih menyukai bersuci dengan air karena mereka melihat hal itu lebih utama. Pendapat ini diambil oleh Sufyan Ats Tsauri, Ibnul Mubarak, Syafi'i, Ahmad dan Ishaq.\""},"20":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَأَتَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَاجَتَهُ فَأَبْعَدَ فِي الْمَذْهَبِقَالَ وَفِي الْبَاب عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي قُرَادٍ وَأَبِي قَتَادَةَ وَجَابِرٍ وَيَحْيَى بْنِ عُبَيْدٍ عَنْ أَبِيهِ وَأَبِي مُوسَى وَابْنِ عَبَّاسٍ وَبِلَالِ بْنِ الْحَارِثِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَيُرْوَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَرْتَادُ لِبَوْلِهِ مَكَانًا كَمَا يَرْتَادُ مَنْزِلًا وَأَبُو سَلَمَةَ اسْمُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ الزُّهْرِيُّ","id":"telah menceritakan kepada kami [Muhammad bin Basyar] berkata, telah menceritakan kepada kami [Abdul Wahab Ats Tsaqafi] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Al Mughirah bin Syu'bah] ia berkata; \"Aku bersama Nabi Shallahu 'alaihi wa Sallam dalam suatu perjalanan, kemudian Nabi Shallahu 'alaihi wa Sallam membuang hajat dan pergi ke tempat yang lebih jauh.\" Abu Isa berkata; \"Dalam bab ini ada juga hadits dari sahabat Abdurrahman bin Abu Qurad, Abu Qatadah, Jabir, Yahya bin Ubaid dari bapaknya, Abu Musa, Ibnu Abbas dan sahabat Bilal bin Harits.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, dan diriwayatkan juga dari Nabi shallallahu 'alaihi wasallam, bahwa beliau menutupi tempat kencing ketika kencing sebagaimana tertutupnya sebuah rumah. Dan Abu Salamah namanya adalah Abdullah bin Abdurrahman bin 'Auf Az Zuhri.\""},"21":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ وَأَحْمَدُ بْنُ مُحَمَّدِ بْنِ مُوسَى مَرْدَوَيْهِ قَالَا أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ أَشْعَثَ بْنِ عَبْدِ اللَّهِ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَبُولَ الرَّجُلُ فِي مُسْتَحَمِّهِ وَقَالَ إِنَّ عَامَّةَ الْوَسْوَاسِ مِنْهُقَالَ وَفِي الْبَاب عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مَرْفُوعًا إِلَّا مِنْ حَدِيثِ أَشْعَثَ بْنِ عَبْدِ اللَّهِ وَيُقَالُ لَهُ أَشْعَثُ الْأَعْمَى وَقَدْ كَرِهَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ الْبَوْلَ فِي الْمُغْتَسَلِ وَقَالُوا عَامَّةُ الْوَسْوَاسِ مِنْهُ وَرَخَّصَ فِيهِ بَعْضُ أَهْلِ الْعِلْمِ مِنْهُمْ ابْنُ سِيرِينَ وَقِيلَ لَهُ إِنَّهُ يُقَالُ إِنَّ عَامَّةَ الْوَسْوَاسِ مِنْهُ فَقَالَ رَبُّنَا اللَّهُ لَا شَرِيكَ لَهُ و قَالَ ابْنُ الْمُبَارَكِ قَدْ وُسِّعَ فِي الْبَوْلِ فِي الْمُغْتَسَلِ إِذَا جَرَى فِيهِ الْمَاءُ قَالَ أَبُو عِيسَى حَدَّثَنَا بِذَلِكَ أَحْمَدُ بْنُ عَبْدَةَ الْآمُلِيُّ عَنْ حِبَّانَ عَنْ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ","id":"telah menceritakan kepada kami [Ali bin Hajar] dan [Ahmad bin Muhammad bin Musa Mardawih] mereka berdua berkata; telah mengabarkan kepada kami [Abdullah Ibnul Mubarak] dari [Ma'mar] dari [Asy'ats bin Abdullah] dari [Al Hasan] dari [Abdullah bin Mughaffal] berkata, Nabi Shallahu 'alaihi wa Sallam melarang seseorang kencing di tempat mandinya, dan beliau juga bersabda: \"Umumnya waswas datang darinya.\" Ia berkata; \"Dalam bab ini ada juga hadits dari salah seorang sahabat Nabi Shallahu 'alaihi wa Sallam.\" Abu Isa berakta, \"Hadits ini gharib (asing), kami tidak mengetahui hadits itu marfu' kecuali hadits dari Asy'ats bin Abdullah, dan ia juga disebut dengan Asy'ats Al A'ma.\" Sebagian ahli ilmu memakruhkan kencing di tempat pemandian, mereka mengatakan; \"Umumnya was-was berasal darinya.\" Dan sebagian ahlul ilmi memberikan keringanan dalam perkara tersebut, di antaranya adalah Ibnu Sirin. Dan ketika dikatakan kepadanya, \"Sesungguhnya umumnya was-was datang darinya, \" maka ia menjawab, \"Rabb kita adalah Allah, tidak ada sekutu bagi-Nya.\" Ibnul Mubarak berkata; \"Ada kelonggaran kencing di tempat pemandian jika airnya mengalir.\" Abu Isa berkata; \"Hal tersebut telah diceritakan kepada kami oleh Ahmad bin Abdah Al Amuli, dari Hibban, dari Abdullah bin Al Mubarak.\""},"22":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ بِالسِّوَاكِ عِنْدَ كُلِّ صَلَاةٍقَالَ أَبُو عِيسَى وَقَدْ رَوَى هَذَا الْحَدِيثَ مُحَمَّدُ بْنُ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ زَيْدِ بْنِ خَالِدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَدِيثُ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كِلَاهُمَا عِنْدِي صَحِيحٌ لِأَنَّهُ قَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا الْحَدِيثُ وَحَدِيثُ أَبِي هُرَيْرَةَ إِنَّمَا صَحَّ لِأَنَّهُ قَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ وَأَمَّا مُحَمَّدُ بْنُ إِسْمَعِيلَ فَزَعَمَ أَنَّ حَدِيثَ أَبِي سَلَمَةَ عَنْ زَيْدِ بْنِ خَالِدٍ أَصَحُّ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي بَكْرٍ الصِّدِّيقِ وَعَلِيٍّ وَعَائِشَةَ وَابْنِ عَبَّاسٍ وَحُذَيْفَةَ وَزَيْدِ بْنِ خَالِدٍ وَأَنَسٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَابْنِ عُمَرَ وَأُمِّ حَبِيبَةَ وَأَبِي أُمَامَةَ وَأَبِي أَيُّوبَ وَتَمَّامِ بْنِ عَبَّاسٍ وَعَبْدِ اللَّهِ بْنِ حَنْظَلَةَ وَأُمِّ سَلَمَةَ وَوَاثِلَةَ بْنِ الْأَسْقَعِ وَأَبِي مُوسَى","id":"telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, Rasulullah Shallahu 'alaihi wa Sallam bersabda: \" Sekiranya tidak memberatkan umatku sungguh akan aku perintahkan untuk bersiwak setiap kali akan shalat.\" Abu Isa berkata; \"Hadits ini diriwayatkan oleh [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim], dari [Abu Salamah,] dari [Zaid bin Khalid], dari Nabi shallallahu 'alaihi wasallam.\" Dan hadits Abu Salamah yang diriwayatkan oleh Abu Hurairah dan Zaid bin Khalid dari Nabi Shallahu 'alaihi wa Sallam, menurutku keduanya shahih. Karena hadits itu tidak hanya diriwayatkan oleh satu jalur, yaitu dari Abu Hurairah dari Nabi Shallahu 'alaihi wa Sallam, tetapi dari jalur lainnya, sehingga hadits riwayat Abu Hurairah menjadi shahih. Sedangkan Muhammad bin Isma'il mengklaim bahwa hadits Abu Salamah yang diriwayatkan dari Zaid bin Khalid derajatnya lebih shahih. Abu Isa berkata; \"Dalam bab ini juga terdapat riwayat dari Abu Bakar Ash Shiddiq, Ali, Aisyah, Ibnu Abbas, Hudzaifah, Zaid bin Khalid, Anas, Abdullah bin 'Amru, Ibnu Umar, Ummu Habibah, Abu Ayyub, Tammam bin Abbas, Abdullah bin Handlallah, Ummu Salamah, Watsilah Al Asqa' dan Abu Musa.\""},"23":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ بِالسِّوَاكِ عِنْدَ كُلِّ صَلَاةٍ وَلَأَخَّرْتُ صَلَاةَ الْعِشَاءِ إِلَى ثُلُثِ اللَّيْلِقَالَ فَكَانَ زَيْدُ بْنُ خَالِدٍ يَشْهَدُ الصَّلَوَاتِ فِي الْمَسْجِدِ وَسِوَاكُهُ عَلَى أُذُنِهِ مَوْضِعَ الْقَلَمِ مِنْ أُذُنِ الْكَاتِبِ لَا يَقُومُ إِلَى الصَّلَاةِ إِلَّا أُسْتَنَّ ثُمَّ رَدَّهُ إِلَى مَوْضِعِهِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Zaid bin Khalid Al Juhani] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" Seandainya tidak memberatkan ummatku niscaya aku akan perintahkan mereka bersiwak setiap kali akan shalat, dan aku juga akan akhirkan shalat Isya hingga sepertiga malam.\" Ia berkata; \"Zaid bin Khalid menghadiri shalat di masjid, sementara siwaknya berada di telinganya seperti pena yang selalu berada di telinga seorang penulis, ia tidak bangkit menegakkan shalat hingga ia melakukan siwak terlebih dahulu. Setelah itu ia meletakkannya kembali pada tempatnya.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\""},"24":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ أَحْمَدُ بْنُ بَكَّارٍ الدِّمَشْقِيُّ يُقَالُ هُوَ مِنْ وَلَدِ بُسْرِ بْنِ أَرْطَاةَ صَاحِبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اسْتَيْقَظَ أَحَدُكُمْ مِنْ اللَّيْلِ فَلَا يُدْخِلْ يَدَهُ فِي الْإِنَاءِ حَتَّى يُفْرِغَ عَلَيْهَا مَرَّتَيْنِ أَوْ ثَلَاثًا فَإِنَّهُ لَا يَدْرِي أَيْنَ بَاتَتْ يَدُهُوَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَجَابِرٍ وَعَائِشَةَ قَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ الشَّافِعِيُّ وَأُحِبُّ لِكُلِّ مَنْ اسْتَيْقَظَ مِنْ النَّوْمِ قَائِلَةً كَانَتْ أَوْ غَيْرَهَا أَنْ لَا يُدْخِلَ يَدَهُ فِي وَضُوئِهِ حَتَّى يَغْسِلَهَا فَإِنْ أَدْخَلَ يَدَهُ قَبْلَ أَنْ يَغْسِلَهَا كَرِهْتُ ذَلِكَ لَهُ وَلَمْ يُفْسِدْ ذَلِكَ الْمَاءَ إِذَا لَمْ يَكُنْ عَلَى يَدِهِ نَجَاسَةٌ و قَالَ أَحْمَدُ بْنُ حَنْبَلٍ إِذَا اسْتَيْقَظَ مِنْ النَّوْمِ مِنْ اللَّيْلِ فَأَدْخَلَ يَدَهُ فِي وَضُوئِهِ قَبْلَ أَنْ يَغْسِلَهَا فَأَعْجَبُ إِلَيَّ أَنْ يُهْرِيقَ الْمَاءَ و قَالَ إِسْحَقُ إِذَا اسْتَيْقَظَ مِنْ النَّوْمِ بِاللَّيْلِ أَوْ بِالنَّهَارِ فَلَا يُدْخِلْ يَدَهُ فِي وَضُوئِهِ حَتَّى يَغْسِلَهَا","id":"Telah menceritakan kepada kami [Abul Walid Ahmad bin Bakkar Ad Dimasqi] ada yang mengatakan bahwa ia termasuk anak Busr bin Artha`ah, sahabat Nabi shallallahu 'alaihi wasallam. Ia berkata; telah menceritakan kepada kami [Al Walid bin Muslim] dari [Al Auza'i] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dan [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \" Jika salah seorang dari kalian bangun dari tidur maka janganlah memasukkan tangannya ke dalam bejana hingga ia menuangkan air ke tangannya dua atau tiga kali, karena ia tidak tahu dimana tangannya bermalam.\" Dalam bab ini juga terdapat riwayat dari Ibnu Umar, Jabir dan Aisyah. Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Asy Syafi'i berkata; \"Aku menyukai pada setiap orang yang bangun dari tidur, baik tidur siang atau yang selainnya, untuk tidak memasukkan tangannya ke dalam air wudlunya hingga ia mencucinya dengan air terlebih dahulu, dan aku benci jika seseorang memasukkannya sebelum mencucinya terlebih dahulu. Meskipun hal itu tidak merusak kesucian air tersebut selama dalam tangannya tidak terdapat najis.\" Ahmad bin Hanbal berkata; \"Apabila seseorang bangun di waktu malam kemudian memasukkan tangannya ke dalam air wudlu sebelum mencucinya, maka akan membuat aku keheranan jika ia membuang air tersebut.\" Dan Ishaq juga mengatakan; \"Jika seseorang bangun di waktu malam atau siang hari maka janganlah memasukkan tangannya ke dalam air wudlu hingga ia mencucinya.\""},"25":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ وَبِشْرُ بْنُ مُعَاذٍ الْعَقَدِيُّ قَالَا حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حَرْمَلَةَ عَنْ أَبِي ثِفَالٍ الْمُرِّيِّ عَنْ رَبَاحِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سُفْيَانَ بْنِ حُوَيْطِبٍ عَنْ جَدَّتِهِ عَنْ أَبِيهَا قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا وُضُوءَ لِمَنْ لَمْ يَذْكُرْ اسْمَ اللَّهِ عَلَيْهِقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَأَبِي سَعِيدٍ وَأَبِي هُرَيْرَةَ وَسَهْلِ بْنِ سَعْدٍ وَأَنَسٍ قَالَ أَبُو عِيسَى قَالَ أَحْمَدُ بْنُ حَنْبَلٍ لَا أَعْلَمُ فِي هَذَا الْبَابِ حَدِيثًا لَهُ إِسْنَادٌ جَيِّدٌ و قَالَ إِسْحَقُ إِنْ تَرَكَ التَّسْمِيَةَ عَامِدًا أَعَادَ الْوُضُوءَ وَإِنْ كَانَ نَاسِيًا أَوْ مُتَأَوِّلًا أَجْزَأَهُ قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ أَحْسَنُ شَيْءٍ فِي هَذَا الْبَابِ حَدِيثُ رَبَاحِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ أَبُو عِيسَى وَرَبَاحُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ جَدَّتِهِ عَنْ أَبِيهَا وَأَبُوهَا سَعِيدُ بْنُ زَيْدِ بْنِ عَمْرِو بْنِ نُفَيْلٍ وَأَبُو ثِفَالٍ الْمُرِّيُّ اسْمُهُ ثُمَامَةُ بْنُ حُصَيْنٍ وَرَبَاحُ بْنُ عَبْدِ الرَّحْمَنِ هُوَ أَبُو بَكْرِ بْنُ حُوَيْطِبٍ مِنْهُمْ مَنْ رَوَى هَذَا الْحَدِيثَ فَقَالَ عَنْ أَبِي بَكْرِ بْنِ حُوَيْطِبٍ فَنَسَبَهُ إِلَى جَدِّهِ حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ يَزِيدَ بْنِ عِيَاضٍ عَنْ أَبِي ثِفَالٍ الْمُرِّيِّ عَنْ رَبَاحِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سُفْيَانَ بْنِ حُوَيْطِبٍ عَنْ جَدَّتِهِ بِنْتِ سَعِيدِ بْنِ زَيْدٍ عَنْ أَبِيهَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] dan [Bisyr bin Mu'adz Al Aqadi] mereka berkata; telah menceritakan kepada kami [Bisyr Ibnul Mufadldlal] dari [Abdurrahman bin Harmalah] dari [Abu Tsifal Al Murri] dari [Rabah bin Abdurrahman bin Abu Sufyan bin Huwaittib] dari [Neneknya] dari [Bapaknya] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" Tidak ada wudlu bagi orang yang tidak menyebut nama Allah (ketika akan berwudlu).\" Ia berkata; \"Dalam bab ini juga terdapat riwayat dari Aisyah, Abu Sa'id, Abu Hurairah, Sahl bin Sa'd dan Anas.\" Abu Isa berkata; \"Imam Ahmad bin Hambal berkata; \"Aku tidak mengetahui dalam bab ini hadits yang memiliki sanad jayyid (bagus).\" Ishaq berkata; \"Jika ia meninggalkan bacaan basmalah dengan sengaja maka harus mengulangi wudlunya, namun jika lupa atau karena mentakwil maka wudlunya tetap sah.\" Muhammad bin Isma'il berkata; \"Hadits yang paling baik dalam bab ini adalah hadits Rabah bin Abdurrahman.\" Abu Isa berkata; \"Rabah bin Abdurrahman menceritakan dari neneknya, dari bapaknya. Sedangkan nama bapaknya adalah Sa'id bin Zaid bin 'Amru bin Nufail, Abu Tsifal Al Murri namanya Tsumamah bin Hushain, dan Rabah bin Abdurrahman namanya Abu Bakr bin Huwaithib. Di antara mereka ada yang meriwayatkan hadits ini, lalu ia berkata; \"Dari Abu Bakr bin Huwaithib, \" lalu ia menasabkannya pada kakeknya.\" Telah menceritakan kepada kami [Al Hasan bin Ali Al Hulwani] berkata, telah menceritakan kepada kami [Yazid bin Harun] dari [Yazid bin Iyadl] dari [Abu Tsifal Al Murri] dari [Rabah bin Abdurrahman bin Abu Sufyan bin Huwaithib] dari [Neneknya binti Sa'id bin Zaid] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam dengan hadits yang serupa.\""},"26":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ وَجَرِيرٌ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ سَلَمَةَ بْنِ قَيْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأْتَ فَانْتَثِرْ وَإِذَا اسْتَجْمَرْتَ فَأَوْتِرْقَالَ وَفِي الْبَاب عَنْ عُثْمَانَ وَلَقِيطِ بْنِ صَبِرَةَ وَابْنِ عَبَّاسٍ وَالْمِقْدَامِ بْنِ مَعْدِي كَرِبَ وَوَائِلِ بْنِ حُجْرٍ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى حَدِيثُ سَلَمَةَ بْنِ قَيْسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَاخْتَلَفَ أَهْلُ الْعِلْمِ فِيمَنْ تَرَكَ الْمَضْمَضَةَ وَالِاسْتِنْشَاقَ فَقَالَتْ طَائِفَةٌ مِنْهُمْ إِذَا تَرَكَهُمَا فِي الْوُضُوءِ حَتَّى صَلَّى أَعَادَ الصَّلَاةَ وَرَأَوْا ذَلِكَ فِي الْوُضُوءِ وَالْجَنَابَةِ سَوَاءً وَبِهِ يَقُولُ ابْنُ أَبِي لَيْلَى وَعَبْدُ اللَّهِ بْنُ الْمُبَارَكِ وَأَحْمَدُ وَإِسْحَقُ و قَالَ أَحْمَدُ الِاسْتِنْشَاقُ أَوْكَدُ مِنْ الْمَضْمَضَةِ قَالَ أَبُو عِيسَى وَقَالَتْ طَائِفَةٌ مِنْ أَهْلِ الْعِلْمِ يُعِيدُ فِي الْجَنَابَةِ وَلَا يُعِيدُ فِي الْوُضُوءِ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَبَعْضِ أَهْلِ الْكُوفَةِ وَقَالَتْ طَائِفَةٌ لَا يُعِيدُ فِي الْوُضُوءِ وَلَا فِي الْجَنَابَةِ لِأَنَّهُمَا سُنَّةٌ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا تَجِبُ الْإِعَادَةُ عَلَى مَنْ تَرَكَهُمَا فِي الْوُضُوءِ وَلَا فِي الْجَنَابَةِ وَهُوَ قَوْلُ مَالِكٍ وَالشَّافِعِيِّ فِي آخِرَةٍ","id":"telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dan [Jarir] dari [Manshur] dari [Hilal bin Yasaf] dari [Salamah bin Qais] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Jika engkau berwudlu maka masukkanlah air ke dalam hidung, dan jika engkau beristijmar maka lakukanlah dengan bilangan ganjil.\" Dalam bab ini juga ada riwayat dari Utsman, Laqith bin Shabrah, Ibnu Abbas, Al Migdam bin Ma'di Karib, Wa`il bin Hujr dan Abu Hurairah.\" Abu Isa berkata; \"Hadits Salamah bin Qais derajatnya hasan shahih. Dan para ahli ilmu saling berbeda pendapat tentang hukum orang yang meninggalkan berkumur dan istinsyaq. Sebagian kelompok mengatakan; \"Jika seseorang meninggalkannya hingga ia melaksanakan shalat, maka ia harus mengulangi shalatnya. Mereka berpendapat bahwa hal itu berlaku dalam wudlu dan mandi janabah. Yang berpendapat demikian adalah Ibnu Abu Laila, Abdullah Ibnul Mubarak, Ahmad dan Ishaq. Sedangkan Ahmad berpendapat bahwa melakukan istinsyaq lebih ditekankan pada wudlu. Abu Isa berkata; \"Dan sebagian ulama yang lain berpendapat bahwa hal itu berlaku dalam keadaan junub, bukan dalam wudlu.\" Ini adalah pendapat Sufyan Ats Tsauri dan sebagian dari penduduk Kufah. Dan sebagian ulama yang lain mengatakan bahwa hal itu tidak berlaku dalam wudlu dan junub, karena keduanya adalah perkara sunnah, maka tidak ada kewajiban untuk mengulanginya bagi seseorang yang meninggalkan keduanya. Ini adalah pendapat Malik, Asy Syafi'i dalam qaul jadid.\" "},"27":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَضْمَضَ وَاسْتَنْشَقَ مِنْ كَفٍّ وَاحِدٍ فَعَلَ ذَلِكَ ثَلَاثًاقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى وَحَدِيثُ عَبْدِ اللَّهِ بْنِ زَيْدٍ حَدِيثٌ حَسَنٌ غَرِيبٌ وَقَدْ رَوَى مَالِكٌ وَابْنُ عُيَيْنَةَ وَغَيْرُ وَاحِدٍ هَذَا الْحَدِيثَ عَنْ عَمْرِو بْنِ يَحْيَى وَلَمْ يَذْكُرُوا هَذَا الْحَرْفَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَضْمَضَ وَاسْتَنْشَقَ مِنْ كَفٍّ وَاحِدٍ وَإِنَّمَا ذَكَرَهُ خَالِدُ بْنُ عَبْدِ اللَّهِ وَخَالِدُ بْنُ عَبْدِ اللَّهِ ثِقَةٌ حَافِظٌ عِنْدَ أَهْلِ الْحَدِيثِ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ الْمَضْمَضَةُ وَالِاسْتِنْشَاقُ مِنْ كَفٍّ وَاحِدٍ يُجْزِئُ و قَالَ بَعْضُهُمْ تَفْرِيقُهُمَا أَحَبُّ إِلَيْنَا و قَالَ الشَّافِعِيُّ إِنْ جَمَعَهُمَا فِي كَفٍّ وَاحِدٍ فَهُوَ جَائِزٌ وَإِنْ فَرَّقَهُمَا فَهُوَ أَحَبُّ إِلَيْنَا","id":"telah menceritakan kepada kami [Yahya bin Musa] berkata, telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi] berkata, telah menceritakan kepada kami [Khalid bin Abdullah] dari [Amru bin Yahya] dari [Bapaknya] dari [Abdullah bin Zaid] ia berkata; \"Aku melihat Nabi shallallahu 'alaihi wasallam berkumur dan memasukkan air ke dalam hidung dari satu telapak tangan, beliau lakukan hal itu tiga kali.\" Dan bab ini ada riwayat dari Abdullah bin Abbas.\" Abu Isa berkata; \"Hadits Abdullah bin Zaid adalah hadits yang derajatnya hasan gharib. Hadits ini juga diriwayatkan oleh [Malik] dan [Ibnu Uyainah] juga selainnya dari [Amru bin Yahya], namun mereka tidak menyebutkan lafadz, \"Nabi shallallahu 'alaihi wasallam berkumur dan memasukkan air ke dalam hidung dari satu telapak tangan.\" Namun yang menyebutkan itu adalah Khalid bin Abdullah. Menurut ahli hadits, Khalid bin Abdullah adalah seorang yang dipercaya dan banyak hafalannya. Sebagian ahli ilmu berpendapat bahwa berkumur dan memasukkan air ke dalam hidung dari satu telapak tangan adalah sah. Namun sebagian yang lain mengatakan; \"Memisahkan antara keduanya adalah lebih kami sukai.\" Asy Syafi'i berkata; \"Jika ia menghimpun dalam satu tangan maka itu telah sah, namun jika ia memisahkan antara keduanya maka hal itu lebih kami sukai.\""},"28":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الْكَرِيمِ بْنِ أَبِي الْمُخَارِقِ أَبِي أُمَيَّةَ عَنْ حَسَّانَ بْنِ بِلَالٍ قَالَرَأَيْتُ عَمَّارَ بْنَ يَاسِرٍ تَوَضَّأَ فَخَلَّلَ لِحْيَتَهُ فَقِيلَ لَهُ أَوْ قَالَ فَقُلْتُ لَهُ أَتُخَلِّلُ لِحْيَتَكَ قَالَ وَمَا يَمْنَعُنِي وَلَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَلِّلُ لِحْيَتَهُحَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ حَسَّانَ بْنِ بِلَالٍ عَنْ عَمَّارٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُثْمَانَ وَعَائِشَةَ وَأُمِّ سَلَمَةَ وَأَنَسٍ وَابْنِ أَبِي أَوْفَى وَأَبِي أَيُّوبَ قَالَ أَبُو عِيسَى و سَمِعْت إِسْحَقَ بْنَ مَنْصُورٍ يَقُولُ سَمِعْتُ أَحْمَدَ بْنَ حَنْبَلٍ قَالَ قَالَ ابْنُ عُيَيْنَةَ لَمْ يَسْمَعْ عَبْدُ الْكَرِيمِ مِنْ حَسَّانَ بْنِ بِلَالٍ حَدِيثَ التَّخْلِيلِ","id":"telah menceritakan kepada kami [Ibnu Abu Umar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abdul Karim bin Abu Al Mukhariq Abu Umayyah] dari [Hassan bin Hilal] ia berkata; \"Aku melihat ['Amar bin Yasir] berwudlu seraya menyela-nyela jenggotnya, lalu ditanyakan padanya, atau ia berkata; Aku bertanya kepadanya, \"kenapa engkau menyela-nyela jenggotmu?\" dia menjawab, \"Apa yang menghalangiku, padahal aku telah melihat Rasulullah shallallahu 'alaihi wasallam menyela-nyela jenggotnya.\" Telah menceritakan kepada kami [Ibnu Abu Umar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Sa'id bin Abu Arubah] dari [Qotadah] dari [Hassan bin Hilal] dari ['Ammar] dari Nabi shallallahu 'alaihi wasallam sebagimana hadits tersebut. Abu Isa berkata; \"Dalam bab ini ada juga riwayat dari Utsman, Aisyah, Ummu Salamah, Anas, Ibnu Abu Aufa dan Abu Ayyub.\" Abu Isa berkata; Aku mendengar Ishaq bin Manshur berkata; Aku mendengar Ahmad bin Hanbal berkata; Ibnu Uyainah berkata; \"Abdul Karim tidak mendengar dari Hassan bin Bilal tentang hadits tahlil (menyela-nyela jenggot).\""},"29":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ إِسْرَائِيلَ عَنْ عَامِرِ بْنِ شَقِيقٍ عَنْ أَبِي وَائِلٍ عَنْ عُثْمَانَ بْنِ عَفَّانَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُخَلِّلُ لِحْيَتَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ و قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ أَصَحُّ شَيْءٍ فِي هَذَا الْبَابِ حَدِيثُ عَامِرِ بْنِ شَقِيقٍ عَنْ أَبِي وَائِلٍ عَنْ عُثْمَانَ قَالَ أَبُو عِيسَى و قَالَ بِهَذَا أَكْثَرُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ رَأَوْا تَخْلِيلَ اللِّحْيَةِ وَبِهِ يَقُولُ الشَّافِعِيُّ و قَالَ أَحْمَدُ إِنْ سَهَا عَنْ تَخْلِيلِ اللِّحْيَةِ فَهُوَ جَائِزٌ و قَالَ إِسْحَقُ إِنْ تَرَكَهُ نَاسِيًا أَوْ مُتَأَوِّلًا أَجْزَأَهُ وَإِنْ تَرَكَهُ عَامِدًا أَعَادَ","id":"telah menceritakan kepada kami [Yahya bin Musa] berkata, telah menceritakan kepada kami [Abdurrazaq] dari [Israil] dari ['Amir bin Syaqiq] dari [Abu Wa`il] dari [Utsman bin 'Affan] bahwa Nabi shallallahu 'alaihi wasallam menyela-nyela jenggotnya.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\" Muhammad bin Isma'il berkata; \"Hadits yang paling shahih dalam bab ini adalah hadits 'Amir bin Syaqiq, dari Abu Wa`il dari Utsman.\" Abu Isa berkata; \"Pendapat ini banyak diambil kebanyakan ahlul ilmi dari para sahabat Nabi shallallahu 'alaihi wasallam dan orang yang sesudah mereka mengatakan demikian. Pendapat ini juga diambil oleh Imam Syafi'i. Imam Ahmad berkata; \"Jika ia lupa menyela-nyela jenggot, maka itu tidaklah mengapa.\" Sementara Ishaq berkata; \"Jika ia meninggalkannya karena lupa atau karena takwil, maka hal itu sah baginya. Namun jika meninggalkannya dengan sengaja maka ia harus mengulanginya.\""},"30":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنُ بْنُ عِيسَى الْقَزَّازُ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ رَأْسَهُ بِيَدَيْهِ فَأَقْبَلَ بِهِمَا وَأَدْبَرَ بَدَأَ بِمُقَدَّمِ رَأْسِهِ ثُمَّ ذَهَبَ بِهِمَا إِلَى قَفَاهُ ثُمَّ رَدَّهُمَا حَتَّى رَجَعَ إِلَى الْمَكَانِ الَّذِي بَدَأَ مِنْهُ ثُمَّ غَسَلَ رِجْلَيْهِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ مُعَاوِيَةَ وَالْمِقْدَامِ بْنِ مَعْدِي كَرِبَ وَعَائِشَةَ قَالَ أَبُو عِيسَى حَدِيثُ عَبْدِ اللَّهِ بْنِ زَيْدٍ أَصَحُّ شَيْءٍ فِي هَذَا الْبَابِ وَأَحْسَنُ وَبِهِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ","id":"telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] berkata, telah menceritakan kepada kami [Ma'n bin Isa Al Qazzaz] berkata, telah menceritakan kepada kami [Malik bin Anas] dari ['Amru bin Yahya] dari [Bapaknya] dari [Abdullah bin Zaid] bahwa Rasulullah shallallahu 'alaihi wasallam mengusap kepalanya dengan kedua tangannya, beliau memajukan dan mengundurkan keduanya, memulai dengan bagian depan kepalanya kemudian menjalankan keduanya sampai pada bagian tengkuk, setelah itu mengembalikan keduanya sampai kembali pada tempat yang semula, setelah itu mencuci kedua kakinya.\" Abu Isa berkata; \"Dalam bab ini ada riwayat dari Mu'awiyah, Al Miqdam bin Ma'di Karib dan Aisyah.\" Abu Isa berkata; \"Hadits Abdullah bin Zaid adalah hadits yang paling shahih dan paling baik dalam bab ini. Pendapat ini diambil oleh Asy Syafi'i, Ahmad dan Ishaq.\""},"31":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الرُّبَيِّعِ بِنْتِ مُعَوِّذِ ابْنِ عَفْرَاءَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ بِرَأْسِهِ مَرَّتَيْنِ بَدَأَ بِمُؤَخَّرِ رَأْسِهِ ثُمَّ بِمُقَدَّمِهِ وَبِأُذُنَيْهِ كِلْتَيْهِمَا ظُهُورِهِمَا وَبُطُونِهِمَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَحَدِيثُ عَبْدِ اللَّهِ بْنِ زَيْدٍ أَصَحُّ مِنْ هَذَا وَأَجْوَدُ إِسْنَادًا وَقَدْ ذَهَبَ بَعْضُ أَهْلِ الْكُوفَةِ إِلَى هَذَا الْحَدِيثِ مِنْهُمْ وَكِيعُ بْنُ الْجَرَّاحِ","id":"telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Bisyr Ibnul Mufadldlal] dari [Abdullah bin Muhammad bin Aqil] dari [Ar Rabi' binti Mu'awwidz bin Afra`] bahwa Nabi shallallahu 'alaihi wasallam mengusap kepalanya dua kali; beliau memulainya dari bagian belakang, lalu ke bagian ke depan. Juga kedua telinganya, bagian luar dan dalamnya.\" Abu Isa berkata; \"Hadits ini derajatnya hasan, sedangkan hadits riwayat Abdullah bin Zaid lebih shahih dan lebih baik sanadnya dari hadits tersebut. Dan sebagian penduduk Kufah mengamalkan hadits ini, di antaranya adalah Waki' Ibnul Jarrah.\""},"32":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا بَكْرُ بْنُ مُضَرَ عَنْ ابْنِ عَجْلَانَ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الرُّبَيِّعِ بِنْتِ مُعَوِّذِ ابْنِ عَفْرَاءَأَنَّهَا رَأَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ قَالَتْ مَسَحَ رَأْسَهُ وَمَسَحَ مَا أَقْبَلَ مِنْهُ وَمَا أَدْبَرَ وَصُدْغَيْهِ وَأُذُنَيْهِ مَرَّةً وَاحِدَةًقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَجَدِّ طَلْحَةَ بْنِ مُصَرِّفِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى وَحَدِيثُ الرُّبَيِّعِ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ مَسَحَ بِرَأْسِهِ مَرَّةً وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ وَبِهِ يَقُولُ جَعْفَرُ بْنُ مُحَمَّدٍ وَسُفْيَانُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ رَأَوْا مَسْحَ الرَّأْسِ مَرَّةً وَاحِدَةً حَدَّثَنَا مُحَمَّدُ بْنُ مَنْصُورٍ الْمَكِّيُّ قَال سَمِعْتُ سُفْيَانَ بْنَ عُيَيْنَةَ يَقُولُ سَأَلْتُ جَعْفَرَ بْنَ مُحَمَّدٍ عَنْ مَسْحِ الرَّأْسِ أَيُجْزِئُ مَرَّةً فَقَالَ إِي وَاللَّهِ","id":"telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Bakr bin Mudlar] dari [Ibnu 'Ajlan] dari [Abdullah bin Muhammad bin Aqil] dari [Ar Rabi' binti Mu'awwidz bin Afra`] bahwasanya ia melihat Nabi shallallahu 'alaihi wasallam sedang berwudlu, ia berkata; \" Beliau mengusap kepala bagian depan dan belakang, kedua pelipis dan pada kedua telinganya satu kali.\" Ia berkata; \"Dalam bab ini ada juga riwayat dari Ali serta kakek Thalhah bin Musharrif bin 'Amru.\" Abu Isa berkata; \"Hadits Ar Rabi' ini derajatnya hasan shahih. Dan hadits ini telah diriwayatkan tidak hanya dari satu jalur sampai kepada Nabi shallallahu 'alaihi wasallam, bahwa beliau mengusap kepalanya satu kali.\" Hadits ini banyak diamalkan oleh sebagian besar dari para sahabat dan orang-orang setelahnya. Ja'far bin Muhammad, Sufyan Ats Tsauri, Ibnul Mubarak, Asy Syafi'i, Ahmad dan Ishaq berpendapat bahwa mengusap kepala hanya satu kali. Telah menceritakan kepada kami Muhammad bin Manshur Al Makki berkata; aku mendengar Sufyan bin Uyainah berkata; Aku bertanya kepada Ja'far bin Muhammad tentang hukum mengusap kepala, apakah ia cukup dengan satu usapan saja?\" ia menjawab, \"Ya, demi Allah.\""},"33":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنَا عَمْرُو بْنُ الْحَارِثِ عَنْ حَبَّانَ بْنِ وَاسِعٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ وَأَنَّهُ مَسَحَ رَأْسَهُ بِمَاءٍ غَيْرِ فَضْلِ يَدَيْهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَى ابْنُ لَهِيعَةَ هَذَا الْحَدِيثَ عَنْ حَبَّانَ بْنِ وَاسِعٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ وَأَنَّهُ مَسَحَ رَأْسَهُ بِمَاءٍ غَيْرِ فَضْلِ يَدَيْهِ وَرِوَايَةُ عَمْرِو بْنِ الْحَارِثِ عَنْ حَبَّانَ أَصَحُّ لِأَنَّهُ قَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ هَذَا الْحَدِيثُ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ وَغَيْرِهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ لِرَأْسِهِ مَاءً جَدِيدًا وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ رَأَوْا أَنْ يَأْخُذَ لِرَأْسِهِ مَاءً جَدِيدًا","id":"telah menceritakan kepada kami [Ali bin Khasyram] berkata, telah mengabarkan kepada kami [Abdullah bin Wahb] berkata, telah menceritakan kepada kami [Amru Ibnul Harits] dari [Habban bin Wasi'] dari [Bapaknya] dari [Abdullah bin Zaid] bahwasanya ia melihat Nabi shallallahu 'alaihi wasallam berwudlu, beliau mengusap kepalanya dengan air yang bukan kelebihan kedua tangannya.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\" [Ibnu Lahi'ah] meriwayatkan hadits ini dari [Habban bin Wasi'], dari [bapaknya], dari [Abdullah bin Zaid], bahwa Nabi shallallahu 'alaihi wasallam berwudlu mengusap kepalanya dengan air yang bukan sisa kedua tangannya.\" Dan Hadits riwayat 'Amru Ibnul Harits dari Habban lebih shahih, karena diriwayatkan tidak hanya dari satu jalur. Hadits ini dari Abdullah bin Zaid dan selainnya, bahwa Nabi shallallahu 'alaihi wasallam mengambil air baru untuk mengusap kepalanya. Hadits ini banyak diamalkan oleh kebanyakan ahli ilmu, mereka berpendapat bahwasanya beliau mengambil air baru untuk mengusap kepalanya.\""},"34":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ بِرَأْسِهِ وَأُذُنَيْهِ ظَاهِرِهِمَا وَبَاطِنِهِمَاقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ الرُّبَيِّعِ قَالَ أَبُو عِيسَى وَحَدِيثُ ابْنِ عَبَّاسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ يَرَوْنَ مَسْحَ الْأُذُنَيْنِ ظُهُورِهِمَا وَبُطُونِهِمَا","id":"telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [Muhammad bin 'Ajlan] dari [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [Ibnu Abbas]; Bawasanya Nabi shallallahu 'alaihi wasallam mengusap kepala dan kedua telinga bagian luar dan bagian dalamnya.\" Abu Isa berkata; \"Dalam bab ini ada juga hadits riwayat dari Ar Rabi'.\" Abu Isa berkata lagi, \"Hadits Ibnu Abbas derajatnya hasan shahih. Dan hadits ini banyak diamalkan oleh ahli Ilmu, mereka berpendapat bahwa mengusap kedua telinga itu pada bagian luar dan dalamnya.\""},"35":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ سِنَانِ بْنِ رَبِيعَةَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي أُمَامَةَ قَالَتَوَضَّأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَغَسَلَ وَجْهَهُ ثَلَاثًا وَيَدَيْهِ ثَلَاثًا وَمَسَحَ بِرَأْسِهِ وَقَالَ الْأُذُنَانِ مِنْ الرَّأْسِقَالَ أَبُو عِيسَى قَالَ قُتَيْبَةُ قَالَ حَمَّادٌ لَا أَدْرِي هَذَا مِنْ قَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ مِنْ قَوْلِ أَبِي أُمَامَةَ قَالَ وَفِي الْبَاب عَنْ أَنَسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَيْسَ إِسْنَادُهُ بِذَاكَ الْقَائِمِ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ أَنَّ الْأُذُنَيْنِ مِنْ الرَّأْسِ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ مَا أَقْبَلَ مِنْ الْأُذُنَيْنِ فَمِنْ الْوَجْهِ وَمَا أَدْبَرَ فَمِنْ الرَّأْسِ قَالَ إِسْحَقُ وَأَخْتَارُ أَنْ يَمْسَحَ مُقَدَّمَهُمَا مَعَ الْوَجْهِ وَمُؤَخَّرَهُمَا مَعَ رَأْسِهِ و قَالَ الشَّافِعِيُّ هُمَا سُنَّةٌ عَلَى حِيَالِهِمَا يَمْسَحُهُمَا بِمَاءٍ جَدِيدٍ","id":"telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Sinan bin Rabi'ah] dari [Syahr bin Hausyab] dari [Abu Umamah] ia berkata; Nabi shallallahu 'alaihi wasallam berwudlu, beliau membasuh wajahnya tiga kali, dan kedua tangannya tiga kali, lalu mengusap kepalanya seraya bersabda: \"Kedua telinga adalah termasuk bagian dari kepala.\" Abu Isa berkata; Qutaibah berkata; bahwa Hammad berkata; \"Aku tidak tahu apakah ini perkataan Nabi shallallahu 'alaihi wasallam atau dari Abu Umamah.\" Abu Isa berkata; \"Dalam bab ini ada juga hadits dari Anas, \" ia berkata lagi, \"Hadits ini sanadnya tidak sesuai dengan susunannya.\" Dan hadits ini diamalkan oleh kebanyakan ahli ilmu dari para sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka, bahwa kedua telinga termasuk bagian dari kepala. Pendapat ini diambil juga oleh Sufyan Ats Tsauri, Ibnul Mubarak, Syafi'i, Ahmad dan Ishaq. Sementara ulama lain berpendapat, bahwa telinga bagian depan adalah termasuk wajah, sementara telinga bagian belakang adalah termasuk kepala. Ishaq berkata; \"Aku memilih mengusap bagian depannya bersama wajah dan bagian belakangnya bersama kepala.\" Sedangkan Syafi'i berkata; \"Keduanya adalah sunnah, bahwasanya beliau mengusap keduanya dengan air yang baru.\""},"36":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَهَنَّادٌ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي هَاشِمٍ عَنْ عَاصِمِ بْنِ لَقِيطِ بْنِ صَبِرَةَ عَنْ أَبِيهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأْتَ فَخَلِّلْ الْأَصَابِعَقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَالْمُسَتَوْرِدِ وَهُوَ ابْنُ شَدَّادٍ الْفِهْرِيُّ وَأبِي أَيُّوبَ الْأَنْصَارِيِّ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ أَنَّهُ يُخَلِّلُ أَصَابِعَ رِجْلَيْهِ فِي الْوُضُوءِ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ قَالَ إِسْحَقُ يُخَلِّلُ أَصَابِعَ يَدَيْهِ وَرِجْلَيْهِ فِي الْوُضُوءِ وَأَبُو هَاشِمٍ اسْمُهُ إِسْمَعِيلُ بْنُ كَثِيرٍ الْمَكِّيُّ","id":"telah menceritakan kepada kami [Qutaibah] dan [Hannad] mereka berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Hasyim] dari ['Ashim bin Laqith bin Shabirah] dari [Bapaknya] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Jika kamu berwudlu maka hendaklah menyela-nyela jari-jari.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Abbas, Al Mustaurid, yaitu Ibnu Syaddad Al Fihri, dan Abu Ayyub Al Anshari.\" Abu Isa berkata lagi, \"Hadits ini derajatnya hasan shahih, dan para ahli ilmu mengamalkan hadits ini, yaitu menyela antara jari-jari kaki ketika berwudlu. Pendapat ini juga diambil oleh Ahmad dan Ishaq.\" Ishaq berkata; \"Ketika wudlu Ia menyela antara jari-jari tangan dan kakinya.\" Sedangkan Abu Hasyim nama sebenarnya adalah Isma'il bin Katsir Al Makki.\""},"37":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعِيدٍ وَهُوَ الْجَوْهَرِيُّ حَدَّثَنَا سَعْدُ بْنُ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ صَالِحٍ مَوْلَى التَّوْأَمَةِ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَوَضَّأْتَ فَخَلِّلْ بَيْنَ أَصَابِعِ يَدَيْكَ وَرِجْلَيْكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"telah menceritakan kepada kami [Ibrahim bin Sa'id] -yaitu Al Jauhari- berkata, telah menceritakan kepada kami [Sa'd bin Abdul Hamid bin Ja'far] berkata, telah menceritakan kepada kami [Abdurrahman bin Abu Az Zinad] dari [Musa bin Uqbah] dari [Shalih] mantan budak At Tau`amah, dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Jika engkau berwudlu maka selalah antara jemari kedua tangan dan kedua kakimu.\" Abu Isa berkata; \"Hadits ini derajatnya hasan gharib.\""},"38":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ عَمْرٍو عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ الْمُسْتَوْرِدِ بْنِ شَدَّادٍ الْفِهْرِيِّ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأَ دَلَكَ أَصَابِعَ رِجْلَيْهِ بِخِنْصَرِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ ابْنِ لَهِيعَةَ","id":"telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Yazid bin 'Amru] dari [Abu Abdurrahman Al Hubuli] dari [Al Mustaurid bin Syaddad Al Fihri] ia berkata; \"Aku melihat Nabi shallallahu 'alaihi wasallam berwudlu, dan ternyata beliau menggosok jari-jari kakinya menggunakan jari kelingkingnya.\" Abu Isa berkata; \"Hadits ini derajatnya hasan gharib, dan kami tidak mengetahuinya kecuali dari hadits Ibnu Lahi'ah.\""},"39":{"ar":"حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَيْلٌ لِلْأَعْقَابِ مِنْ النَّارِقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَعَائِشَةَ وَجَابِرٍ بْنِ عَبْدِ اللَّهِ بْنِ الْحَارِثِ هُوَ ابْنُ جَزْءٍ الزُّبَيْدِيُّ وَمُعَيْقِيبٍ وَخَالِدِ بْنِ الْوَلِيدِ وَشُرَحْبِيلَ ابْنِ حَسَنَةَ وَعَمْرِو بْنِ الْعَاصِ وَيَزِيدَ بْنِ أَبِي سُفْيَانَ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ وَيْلٌ لِلْأَعْقَابِ وَبُطُونِ الْأَقْدَامِ مِنْ النَّارِ قَالَ وَفِقْهُ هَذَا الْحَدِيثِ أَنَّهُ لَا يَجُوزُ الْمَسْحُ عَلَى الْقَدَمَيْنِ إِذَا لَمْ يَكُنْ عَلَيْهِمَا خُفَّانِ أَوْ جَوْرَبَانِ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \" Celakalah tumit-tumit (yang tidak terbasuh oleh air wudlu) dari api neraka.\" Abu Isa berkata; \"Dalam bab ini ada juga riwayat dari Abdullah bin 'Amru, Aisyah, Jabir bin Abdullah Ibnul Harits, yaitu Ibnu Jaz`i Az Zubaidi, Mu'aiqib, Khalid Ibnul Walid, Syurahbil bin Hasanah, 'Amru Ibnul 'Ash dan Yazid bin Abu Sufyan.\" Abu Isa berkata; \"Hadits Abu Hurairah derajatnya hasan shahih.\" Telah diriwayatkan dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau bersabda: \"Celakalah tumit-tumit dan telapak kaki bagian dalam (yang tidak terkena air wudlu) dari api neraka.\" Abu Isa berkata; \"Fikih dari hadits ini adalah; tidak boleh mengusap kedua telapak kaki jika keduanya tidak mengenakan khuf atau kaus kaki.\""},"40":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ وَهَنَّادٌ وَقُتَيْبَةُ قَالُوا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ ح قَالَ و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَ��َّثَنَا سُفْيَانُ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ مَرَّةً مَرَّةًقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُمَرَ وَجَابِرٍ وَبُرَيْدَةَ وَأبِي رَافِعٍ وَابْنِ الْفَاكِهِ قَالَ أَبُو عِيسَى وَحَدِيثُ ابْنِ عَبَّاسٍ أَحْسَنُ شَيْءٍ فِي هَذَا الْبَابِ وَأَصَحُّ وَرَوَى رِشْدِينُ بْنُ سَعْدٍ وَغَيْرُهُ هَذَا الْحَدِيثَ عَنْ الضَّحَّاكِ بْنِ شُرَحْبِيلَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ الْخَطَّابِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ مَرَّةً مَرَّةً قَالَ وَلَيْسَ هَذَا بِشَيْءٍ وَالصَّحِيحُ مَا رَوَى ابْنُ عَجْلَانَ وَهِشَامُ بْنُ سَعْدٍ وَسُفْيَانُ الثَّوْرِيُّ وَعَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"telah menceritakan kepada kami [Abu Kuraib], [Hannad] dan [Qutaibah] mereka berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan]. Dan dari jalur yang lain disebutkan; Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata; telah menceritakan kepada kami [Sufyan] dari [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [Ibnu Abbas] berkata; \" Nabi shallallahu 'alaihi wasallam berwudlu satu kali satu kali.\" Abu Isa berkata; \"Dalam bab ini ada juga hadits dari Umar, Jabir, Buraidah, Abu Rafi' dan Ibnul Fakihi.\" Abu Isa berkata lagi, \"Dan hadits riwayat Ibnu Abbas adalah yang paling baik dan paling shahih dalam bab ini. Risydin bin Sa'd dan yang lainnya meriwayatkan hadits ini dari Adl Dlahak bin Syurahbil, dari Zaid bin Aslam, dari bapaknya, dari Umar bin Khaththab berkata; \"Nabi shallallahu 'alaihi wasallam berwudlu satu kali satu kali.\" Kemudian Abu Isa berkata; \"Namun hadits ini tidak benar, sedangkan yang shahih adalah hadits yang diriwayatkan oleh [Ibnu 'Ajlan], [Hisyam bin Sa'd], [Sufyan Ats Tsauri] dan [Abdul Aziz bin Muhammad], dari [Zaid bin Aslam], dari ['Atho` bin Yasar], dari [Ibnu Abbas], dari Nabi shallallahu 'alaihi wasallam.\""},"41":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ وَمُحَمَّدُ بْنُ رَافِعٍ قَالَا حَدَّثَنَا زَيْدُ بْنُ حُبَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ ثَابِتِ بْنِ ثَوْبَانَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ الْفَضْلِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هُرْمُزَ هُوَ الْأَعْرَجُ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ مَرَّتَيْنِ مَرَّتَيْنِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ جَابِرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ ابْنِ ثَوْبَانَ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ وَهُوَ إِسْنَادٌ حَسَنٌ صَحِيحٌ قَالَ أَبُو عِيسَى وَقَدْ رَوَى هَمَّامٌ عَنْ عَامِرٍ الْأَحْوَلِ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ ثَلَاثًا ثَلَاثًا","id":"telah menceritakan kepada kami [Abu Kuraib] dan [Muhammad bin Rafi'] mereka berkata; telah menceritakan kepada kami [Zaid bin Hubab] dari [Abdurrahman bin Tsabit bin Tsauban] berkata; telah menceritakan kepadaku [Abdullah Ibnul Fadll] dari [Abdurrahman bin Hurmuz] -yaitu Al A'raj- dari [Abu Hurairah] berkata; \" Nabi shallallahu 'alaihi wasallam berwudlu dua kali dua kali.\" Abu Isa berkata; \"Dalam bab ini ada juga hadits dari Jabir.\" Abu Isa berkata lagi, \"Hadits ini hasan gharib, kami tidak mengetahuinya kecuali dari hadits Ibnu Tsauban dari Abdullah bin Al Fadll, dan sanadnya hasan shahih.\" Abu Isa berkata; \" [Hammam] telah meriwayatkan dari ['Amir Al Ahwal], dari ['Atho`], dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam berwudlu tiga kali tiga kali.\""},"42":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي حَيَّةَ عَنْ عَلِيٍّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ ثَلَاثًا ثَلَاثًاقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُثْمَانَ وَعَائِشَةَ وَالرُّبَيِّعِ وَابْنِ عُمَرَ وَأَبِي أُمَامَةَ وَأَبِي رَافِعٍ وَعَبْدِ اللَّهِ بْنِ عَمْروٍ وَمُعَاوِيَةَ وَأَبِي هُرَيْرَةَ وَجَابِرٍ وَعَبْدِ اللَّهِ بْنِ زَيْدٍ وَأُبَيِّ بْنِ كَعْبٍ قَالَ أَبُو عِيسَى حَدِيثُ عَلِيٍّ أَحْسَنُ شَيْءٍ فِي هَذَا الْبَابِ وَأَصَحُّ لِأَنَّهُ قَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ عَلِيٍّ رِضْوَانُ اللَّهِ عَلَيْهِ وَالْعَمَلُ عَلَى هَذَا عِنْدَ عَامَّةِ أَهْلِ الْعِلْمِ أَنَّ الْوُضُوءَ يُجْزِئُ مَرَّةً مَرَّةً وَمَرَّتَيْنِ أَفْضَلُ وَأَفْضَلُهُ ثَلَاثٌ وَلَيْسَ بَعْدَهُ شَيْءٌ و قَالَ ابْنُ الْمُبَارَكِ لَا آمَنُ إِذَا زَادَ فِي الْوُضُوءِ عَلَى الثَّلَاثِ أَنْ يَأْثَمَ و قَالَ أَحْمَدُ وَإِسْحَقُ لَا يَزِيدُ عَلَى الثَّلَاثِ إِلَّا رَجُلٌ مُبْتَلًى","id":"telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Abu Ishaq] dari [Abu Hayyah] dari [Ali] berkata; \"Nabi shallallahu 'alaihi wasallam berwudlu tiga kali-tiga kali.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Utsman, Aisyah, Ar Rabi', Ibnu Umar, Abu Umamah, Abu Rafi', Abdullah bin 'Amru, Mu'awiyah, Abu Hurairah, Jabir bin Abdullah bin Zaid, dan Ubai bin Ka'ab.\" Abu Isa berkata; \"Hadits Ali adalah hadits yang paling shahih dan paling baik dalam bab ini, karena hadits yang diriwayatkan dari imam Ali tidak hanya dari satu jalur.\" Para ahli ilmu mengamalkan hadits ini, yaitu bahwa wudlu itu cukup sekali-sekali, dua kali-dua kali lebih utama, dan lebih utama lagi bila dilakukan dengan tiga kali-tiga kali. Sedangkan selebihnya tidak ada keutamaannya.\" Ibnul Mubarak berkata; \"Aku khawatir seseorang akan berbuat dosa manakala ia menambahkan lebih dari tiga kali dalam wudlu.\" Ahmad bin Ishaq berkata; \"Tidak akan menambah lebih dari tiga kali kecuali orang yang dalam hatinya terkena was-was.\""},"43":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى الْفَزَارِيُّ حَدَّثَنَا شَرِيكٌ عَنْ ثَابِتِ بْنِ أَبِي صَفِيَّةَ قَالَ قُلْتُ لِأَبِي جَعْفَرٍ حَدَّثَكَ جَابِرٌأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ مَرَّةً مَرَّةً وَمَرَّتَيْنِ مَرَّتَيْنِ وَثَلَاثًا ثَلَاثًا قَالَ نَعَمْقَالَ أَبُو عِيسَى وَرَوَى وَكِيعٌ هَذَا الْحَدِيثَ عَنْ ثَابِتِ بْنِ أَبِي صَفِيَّةَ قَالَ قُلْتُ لِأَبِي جَعْفَرٍ حَدَّثَكَ جَابِرٌ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ مَرَّةً مَرَّةً قَالَ نَعَمْ و حَدَّثَنَا بِذَلِكَ هَنَّادٌ وَقُتَيْبَةُ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ ثَابِتِ بْنِ أَبِي صَفِيَّة قَالَ أَبُو عِيسَى وَهَذَا أَصَحُّ مِنْ حَدِيثِ شَرِيكٍ لِأَنَّهُ قَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ هَذَا عَنْ ثَابِتٍ نَحْوَ رِوَايَةِ وَكِيعٍ وَشَرِيكٌ كَثِيرُ الْغَلَطِ وَثَابِتُ بْنُ أَبِي صَفِيَّةَ هُوَ أَبُو حَمْزَةَ الثُّمَالِيُّ","id":"telah menceritakan kepada kami [Isma'il bin Musa Al Fazari] berkata, telah menceritakan kepada kami [Syarik] dari [Tsabit bin Abu Shafiah] berkata; aku berkata kepada [Abu Ja'far], \"Apakah [Jabir] menceritakan kepadamu bahwa Nabi shallallahu 'alaihi wasallam berwudlu sekali-sekali, dua kali-dua kali dan tiga kali-tiga kali?\" ia menjawab, \"Benar.\" Abu Isa berkata; \"(Sedangkan) [Waki'] meriwayatkan hadits ini dari [Tsabit bin Abu Shafiah], ia berkata; Aku berkata kepada [Abu Ja'far], \"Apakah [Jabir] menceritakan kepadamu bahwa Nabi shallallahu 'alaihi wasallam berwudlu sekali-kali?\" ia menjawab, \"Benar.\" [Hannad] dan [Qutaibah] menceritakan kepada kami tentang hal itu, mereka berkata; \" [Waki'] telah menceritakan kepada kami dari [Tsabit bin Abu Shafiah].\" Abu Isa berkata; \"Hadits ini lebih shahih ketimbang hadits yang diriwayatkan oleh Syarik, karena hadits ini juga diriwayatkan dari jalur lainnya. Dan riwayat ini dari Tsabit seperti periwayatan Waki'. Sedangkan Syarik adalah orang yang banyak melakukan kesalahan. Tsabit bin Abu Shafiah adalah Abu Hamzah Ats Tsumali.\""},"44":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَغَسَلَ وَجْهَهُ ثَلَاثًا وَغَسَلَ يَدَيْهِ مَرَّتَيْنِ مَرَّتَيْنِ وَمَسَحَ بِرَأْسِهِ وَغَسَلَ رِجْلَيْهِ مَرَّتَيْنِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ ذُكِرَ فِي غَيْرِ حَدِيثٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ بَعْضَ وُضُوئِهِ مَرَّةً وَبَعْضَهُ ثَلَاثًا وَقَدْ رَخَّصَ بَعْضُ أَهْلِ الْعِلْمِ فِي ذَلِكَ لَمْ يَرَوْا بَأْسًا أَنْ يَتَوَضَّأَ الرَّجُلُ بَعْضَ وُضُوئِهِ ثَلَاثًا وَبَعْضَهُ مَرَّتَيْنِ أَوْ مَرَّةً","id":"telah menceritakan kepada kami [Muhammad bin Abu Umar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari ['Amru bin Yahya] dari [Bapaknya] dari [Abdullah bin Zaid] ia berkata; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam berwudlu, beliau membasuh mukanya tiga kali, membasuh tangannya dua kali-dua kali, dan mengusap kepala serta kakinya dua kali-dua kali.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, dan disebutkan pula dalam hadits lain bahwa Nabi shallallahu 'alaihi wasallam kadang dalam wudlunya dengan jumlah sekali-sekali dan kadang dengan jumlah tiga kali-tiga kali. Para ulama juga memberikan keringanan dalam hal ini, mereka berpendapat bahwa seseorang dibolehkan berwudlu sesekali waktu dengan jumlah tiga kali-tiga kali dan sesekali waktu yang lain dengan sekali-sekali.\""},"45":{"ar":"حَدَّثَنَا هَنَّادٌ وَقُتَيْبَةُ قَالَا حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي حَيَّةَ قَالَرَأَيْتُ عَلِيًّا تَوَضَّأَ فَغَسَلَ كَفَّيْهِ حَتَّى أَنْقَاهُمَا ثُمَّ مَضْمَضَ ثَلَاثًا وَاسْتَنْشَقَ ثَلَاثًا وَغَسَلَ وَجْهَهُ ثَلَاثًا وَذِرَاعَيْهِ ثَلَاثًا وَمَسَحَ بِرَأْسِهِ مَرَّةً ثُمَّ غَسَلَ قَدَمَيْهِ إِلَى الْكَعْبَيْنِ ثُمَّ قَامَ فَأَخَذَ فَضْلَ طَهُورِهِ فَشَرِبَهُ وَهُوَ قَائِمٌ ثُمَّ قَالَ أَحْبَبْتُ أَنْ أُرِيَكُمْ كَيْفَ كَانَ طُهُورُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُثْمَانَ وَعَبْدِ اللَّهِ بْنِ زَيْدٍ وَابْنِ عَبَّاسٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَالرُّبَيِّعِ وَعَبْدِ اللَّهِ بْنِ أُنَيْسٍ وَعَائِشَةَ رِضْوَانُ اللَّهِ عَلَيْهِمْ حَدَّثَنَا قُتَيْبَةُ وَهَنَّادٌ قَالَا حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ خَيْرٍ ذَكَرَ عَنْ عَلِيٍّ مِثْلَ حَدِيثِ أَبِي حَيَّةَ إِلَّا أَنَّ عَبْدَ خَيْرٍ قَالَ كَانَ إِذَا فَرَغَ مِنْ طُهُورِهِ أَخَذَ مِنْ فَضْلِ طَهُورِهِ بِكَفِّهِ فَشَرِبَهُ قَالَ أَبُو عِيسَى حَدِيثُ عَلِيٍّ رَوَاهُ أَبُو إِسْحَقَ الْهَمْدَانِيُّ عَنْ أَبِي حَيَّةَ وَعَبْدِ خَيْرٍ وَالْحَارِثِ عَنْ عَلِيٍّ وَقَدْ رَوَاهُ زَائِدَةُ بْنُ قُدَامَةَ وَغَيْرُ وَاحِدٍ عَنْ خَالِدِ بْنِ عَلْقَمَةَ عَنْ عَبْدِ خَيْرٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ حَدِيثَ الْوُضُوءِ بِطُولِهِ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ وَرَوَى شُعْبَةُ هَذَا الْحَدِيثَ عَنْ خَالِدِ بْنِ عَلْقَمَةَ فَأَخْطَأَ فِي اسْمِهِ وَاسْمِ أَبِيهِ فَقَالَ مَالِكُ بْنُ عُرْفُطَةَ عَنْ عَبْدِ خَيْرٍ عَنْ عَلِيٍّ قَالَ وَرُوِيَ عَنْ أَبِي عَوَانَةَ عَنْ خَالِدِ بْنِ عَلْقَمَةَ عَنْ عَبْدِ خَيْرٍ عَنْ عَلِيٍّ قَالَ وَرُوِيَ عَنْهُ عَنْ مَالِكِ بْنِ عُرْفُطَةَ مِثْلُ رِوَايَةِ شُعْبَةَ وَالصَّحِيحُ خَالِدُ بْنُ عَلْقَمَةَ","id":"telah menceritakan kepada kami [Hannad] dan [Qutaibah] mereka berkata; telah menceritakan kepada kami [Abul Ahwash] dari [Abu Ishaq] dari [Abu Hayyah] ia berkata; \"Aku melihat [Ali] berwudlu, ia membasuh kedua telapak tangannya hingga bersih, lalu ia berkumur tiga kali, memasukkan air ke dalam hidung tiga kali, membasuh wajah tiga kali, membasuh kedua siku tiga kali, dan mengusap kepalanya satu kali. Lalu membasuh telapak kakinya hingga mata kaki, kemudian ia berdiri seraya mengambil sisa air wudlu dan meminumnya, sedang ia masih dalam keadaan berdiri. Setelah itu ia berkata; \"Aku senang bisa memperlihatkan kepada kalian bagaimana Rasulullah shallallahu 'alaihi wasallam berwudlu.\" Dalam bab ini juga ada riwayat dari Utsman, Abdullah bin Zaid, Ibnu Abbas, Abdullah bin 'Amru, Ar Rabi', Abdullah bin Unais dan Aisyah, semoga Allah meridlai mereka.\" Telah menceritakan kepada kami [Qutaibah] dan [Hannad] mereka berkata; telah menceritakan kepada kami [Abul Ahwash] dari [Abu Ishaq] dari [Abdu Khair], ia menyebutkan dari [Ali] sebagaimana hadits Abu Hayyah, hanya saja Abdu Khair mengatakan; \"Jika Ali selesai dari bersuci, ia mengambil sisa air wudlunya dengan telapak tangan, setelah itu ia meminumnya.\" Abu Isa berkata; \"Hadits Ali ini diriwayatkan oleh [Abu Ishaq Al Hamdani], dari [Abdu Khair] dan [Al Harits] dari [Ali]. Dan diriwayatkan pula oleh [Za`idah bin Qudamah] dan selainnya dari [Khalid bin Alqamah], dari [Abdu Khair], dari [Ali] Radliaallahu 'ahu (hadits tentang wudlu secara sempurna). Dan hadits ini derajatnya hasan shahih. Abu Isa berkata; \"Syu'bah meriwayatkan hadits ini dari Khalid bin Alqamah, namun ia keliru dalam menyebutkan namanya dan juga nama bapaknya. Ia mengatakan; \"Malik bin Urfuthah dari Abdu Khair dari Ali.\" Abu Isa berkata; \"Hadits ini juga diriwayatkan oleh [Abu 'Awanah], dari [Khalid bin Alqamah], dari [Abdu Khair], dari [Ali].\" Ia berkata; \"Hadits diriwayatkan dari Malik bin Urfuthah sebagaimana dalam riwayat Syu'bah. Sedang yang benar adalah Khalid bin Alqamah.\""},"46":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ وَأَحْمَدُ بْنُ أَبِي عُبَيْدِ اللَّهِ السَّلِيمِيُّ الْبَصْرِيُّ قَالَا حَدَّثَنَا أَبُو قُتَيْبَةَ سَلْمُ بْنُ قُتَيْبَةَ عَنْ الْحَسَنِ بْنِ عَلِيٍّ الْهَاشِمِيِّ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جَاءَنِي جِبْرِيلُ فَقَالَ يَا مُحَمَّدُ إِذَا تَوَضَّأْتَ فَانْتَضِحْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ قَالَ و سَمِعْت مُحَمَّدًا يَقُولُ الْحَسَنُ بْنُ عَلِيٍ الْهَاشِمِيُّ مُنْكَرُ الْحَدِيثِ وَفِي الْبَاب عَنْ أَبِي الْحَكَمِ بْنِ سُفْيَانَ وَابْنِ عَبَّاسٍ وَزَيْدِ بْنِ حَارِثَةَ وَأَبِي سَعِيدٍ الْخُدْرِيِّ و قَالَ بَعْضُهُمْ سُفْيَانُ بْنُ الْحَكَمِ أَوْ الْحَكَمُ بْنُ سُفْيَانَ وَاضْطَرَبُوا فِي هَذَا الْحَدِيثِ","id":"telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] dan [Ahmad bin Abu Ubaidullah As Salimi Al Bashri] keduanya berkata; telah menceritakan kepada kami [Abu Qutaibah Salam bin Qutaibah] dari [Al Hasan bin Ali Al Hasyimi] dari [Abdurrahman Al A'raj] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jibril telah datang kepadaku kemudian berkata; 'Wahai Muhammad, jika kamu berwudlu maka bersucilah terlebih dahulu.'\" Abu Isa berkata; \"Hadits ini gharib.\" Dan ia berkata lagi; Aku mendengar Muhammad berkata; \"Al Hasan bin Ali Al Hasyimi adalah Munkarul hadits.\" Dan dalam bab ini ada juga hadits dari Abul Hakam bin Sufyan, Ibnu Abbas, Zaid bin Haritsah dan Abu Sa'id Al Khudri, sebagian yang lain mengatakan Sufyan bin Al Hakam, atau Al Hakam bin Sufyan, dan mereka idltirab (berbeda beda) dalam hadits ini.\""},"47":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أَدُلُّكُمْ عَلَى مَا يَمْحُو اللَّهُ بِهِ الْخَطَايَا وَيَرْفَعُ بِهِ الدَّرَجَاتِ قَالُوا بَلَى يَا رَسُولَ اللَّهِ قَالَ إِسْبَاغُ الْوُضُوءِ عَلَى الْمَكَارِهِ وَكَثْرَةُ الْخُطَا إِلَى الْمَسَاجِدِ وَانْتِظَارُ الصَّلَاةِ بَعْدَ الصَّلَاةِ فَذَلِكُمْ الرِّبَاطُو حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ الْعَلَاءِ نَحْوَهُ و قَالَ قُتَيْبَةُ فِي حَدِيثِهِ فَذَلِكُمْ الرِّبَاطُ فَذَلِكُمْ الرِّبَاطُ فَذَلِكُمْ الرِّبَاطُ ثَلَاثًا قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَلِيٍّ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَابْنِ عَبَّاسٍ وَعَبِيدَةَ وَيُقَالُ عُبَيْدَةُ بْنُ عَمْرٍو وَعَائِشَةَ وَعَبْدِ الرَّحْمَنِ بْنِ عَائِشٍ الْحَضْرَمِيِّ وَأَنَسٍ قَالَ أَبُو عِيسَى وَحَدِيثُ أَبِي هُرَيْرَةَ فِي هَذَا الْبَابِ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَلَاءُ بْنُ عَبْدِ الرَّحْمَنِ هُوَ ابْنُ يَعْقُوبَ الْجُهَنِيُّ الْحُرَقِيُّ وَهُوَ ثِقَةٌ عِنْدَ أَهْلِ الْحَدِيثِ","id":"telah menceritakan kepada kami [Ali bin Hujr] berkata, telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Al 'Ala` bin Abdurrahman] dari [Bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Maukah aku tunjukkan kepada kalian sesuatu yang dapat menghapus kesalahan dan menaikkan derajat?\" para sahabat menjawab, \"Tentu, wahai Rasulullah.\" Beliau bersabda: \"Menyempurnakan shalat disaat yang tidak disukai, memperbanyak langkah menuju masjid dan menunggu shalat setelah shalat. Dan itulah ribath.\" Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Al 'Ala`] sebagaimana hadits tersebut. Qutaibah menyebutkan dalam haditsnya, \"Itulah ribath, itulah ribath, itulah ribath.\" Tiga kali. Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Ali, Abdullah bin 'Amru, Ibnu Abbas dan Abidah, disebut juga Ubaidah bin Amru, Aisyah, Abdurrahman bin 'A`isy Al Hadlrami, dan Anas.\" Abu Isa berkata; \"Dan hadits Abu Hurairah dalam bab ini adalah hadits yang paling baik dan derajatnya shahih.\" Dan Al 'Ala` bin Abdurrahman adalah Ibnu Ya'qub Al Juhani Al Huraqi, ia adalah seorang yang dapat dipercaya menurut ahli hadits.\""},"48":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعِ بْنِ الْجَرَّاحِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ زَيْدِ بْنِ حُبَابٍ عَنْ أَبِي مُعَاذٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خِرْقَةٌ يُنَشِّفُ بِهَا بَعْدَ الْوُضُوءِقَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ لَيْسَ بِالْقَائِمِ وَلَا يَصِحُّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْبَابِ شَيْءٌ وَأَبُو مُعَاذٍ يَقُولُونَ هُوَ سُلَيْمَانُ بْنُ أَرْقَمَ وَهُوَ ضَعِيفٌ عِنْدَ أَهْلِ الْحَدِيثِ قَالَ وَفِي الْبَاب عَنْ مُعَاذِ بْنِ جَبَلٍ","id":"telah menceritakan kepada kami [Sufyan bin Waki' bin Al Jarrah] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] dari [Zaid bin Hubab] dari [Abu Mu'adz] dari [Az Zuhri] dari [Urwah] dari [Aisyah] ia berkata; \" Rasulullah shallallahu 'alaihi wasallam memiliki kain yang beliau gunakan untuk mengeringkan setelah berwudlu.\" Abu Isa berkata; \"Hadits Aisyah tidak kuat dan tidak ada hadits yang shahih dari Nabi shallallahu 'alaihi wasallam dalam bab ini, tentang Abu Mu'adz, mereka berkata; bahwa dia adalah Sulaiman bin Arqam, dan ia adalah orang yang lemah menurut para ahli hadits. Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Mu'adz bin Jabal.\""},"49":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا رِشْدِينُ بْنُ سَعْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ زِيَادِ بْنِ أَنْعُمٍ عَنْ عُتْبَةَ بْنِ حُمَيْدٍ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأَ مَسَحَ وَجْهَهُ بِطَرَفِ ثَوْبِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَإِسْنَادُهُ ضَعِيفٌ وَرِشْدِينُ بْنُ سَعْدٍ وَعَبْدُ الرَّحْمَنِ بْنُ زِيَادِ بْنِ أَنْعُمٍ الْأَفْرِيقِيُّ يُضَعَّفَانِ فِي الْحَدِيثِ وَقَدْ رَخَّصَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ فِي التَّمَنْدُلِ بَعْدَ الْوُضُوءِ وَمَنْ كَرِهَهُ إِنَّمَا كَرِهَهُ مِنْ قِبَلِ أَنَّهُ قِيلَ إِنَّ الْوُضُوءَ يُوزَنُ وَرُوِيَ ذَلِكَ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ وَالزُّهْرِيِّ حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ الرَّازِيُّ حَدَّثَنَا جَرِيرٌ قَالَ حَدَّثَنِيهِ عَلِيُّ بْنُ مُجَاهِدٍ عَنِّي وَهُوَ عِنْدِي ثِقَةٌ عَنْ ثَعْلَبَة عَنْ الزُّهْرِيِّ قَالَ إِنَّمَا كُرِهَ الْمِنْدِيلُ بَعْدَ الْوُضُوءِ لِأَنَّ الْوُضُوءَ يُوزَنُ","id":"telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Risydin bin Sa'd] dari [Abdurrahman bin Ziyad bin An'um] dari [Utbah bin Humaid] dari [Ubadah bin Nusai] dari [Abdurrahman bin Ghanmi] dari [Mu'adz bin Jabal] ia berkata; \"Aku melihat Nabi shallallahu 'alaihi wasallam setelah selesai berwudlu mengusap wajahnya dengan ujung kainnya.\" Abu Isa berkata; \"Hadits ini derajatnya gharib dan dalam sanadnya lemah. Risydin bin Sa'd dan Abdurrahman bin Ziyad bin An'um Al Afriqi melemahkan haditsnya. Beberapa ulama dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka memberikan keringanan untuk mengelap sisa wudlu, adapun bagi mereka yang memakruhkannya, hal itu hanya berdasarkan atas sebuah pendapat bahwa wudlu akan ditimbang dalam timbangan amal. Hal itu diriwayatkan dari Sa'id Ibnul Musayyab dan Az Zuhri. Telah menceritakan kepada kami Muhammad bin Humaid Ar Razi berkata, telah menceritakan kepada kami Jarir ia berkata; Ali bin Mujahid telah menceritakannya kepadaku, dan menurutku dia adalah seorang yang dapat dipercaya, yaitu dari Tsa'labah, dari Az Zuhri, ia berkata; \"Tidak disukainya mengusap sisa wudlu karena itu akan ditimbang.\""},"50":{"ar":"حَدَّثَنَا جَعْفَرُ بْنُ مُحَمَّدِ بْنِ عِمْرَانَ الثَّعْلَبِيُّ الْكُوفِيُّ حَدَّثَنَا زَيْدُ بْنُ حُبَابٍ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ رَبِيعَةَ بْنِ يَزِيدَ الدِّمَشْقِيِّ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ وَأَبِي عُثْمَانَ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ قَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ اللَّهُمَّ اجْعَلْنِي مِنْ التَّوَّابِينَ وَاجْعَلْنِي مِنْ الْمُتَطَهِّرِينَ فُتِحَتْ لَهُ ثَمَانِيَةُ أَبْوَابِ الْجَنَّةِ يَدْخُلُ مِنْ أَيِّهَا شَاءَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَنَسٍ وَعُقْبَةَ بْنِ عَامِرٍ قَالَ أَبُو عِيسَى حَدِيثُ عُمَرَ قَدْ خُولِفَ زَيْدُ بْنُ حُبَابٍ فِي هَذَا الْحَدِيثِ قَالَ وَرَوَى عَبْدُ اللَّهِ بْنُ صَالِحٍ وَغَيْرُهُ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ رَبِيعَةَ بْنِ يَزِيدَ عَنْ أَبِي إِدْرِيسَ عَنْ عُقْبَةَ بْنِ عَامِرٍ عَنْ عُمَرَ وَعَنْ رَبِيعَةَ عَنْ أَبِي عُثْمَانَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ عُمَرَ وَهَذَا حَدِيثٌ فِي إِسْنَادِهِ اضْطِرَابٌ وَلَا يَصِحُّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْبَابِ كَبِيرُ شَيْءٍ قَالَ مُحَمَّدٌ وَأَبُو إِدْرِيسَ لَمْ يَسْمَعْ مِنْ عُمَرَ شَيْئًا","id":"telah menceritakan kepada kami [Ja'far bin Muhammad bin Imran Ats Tsa'labi Al Kufi] berkata, telah menceritakan kepada kami [Zaid bin Hubab] dari [Mu'awiyah bin Shalih] dari [Rabi'ah bin Yazid Ad Dimasyqi] dari [Abu Idris Al Khaulani] dan [Abu Utsman] dari [Umar bin Khaththab] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berwudlu dan menyempurnakan wudlunya kemudian membaca; ASYHADU ANLAA ILAAHA ILLALLAAH WAHDAHUU LAA SYARIIKALAHU WA ASYHADU ANNA MUHAMMADAN ABDUHU WA RASUULUHU, ALLAAHUMMAJ'ALNI MINAT TAWWAABIINA WAJ'ALNI MINAL MUTATAHHIRIIN (aku bersaksi bahwa tidak ada Tuhan yang berhak disembah kecuali Allah Yang Maha Esa dan tidak ada sekutu bagi-Nya, dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya. Ya Allah, jadikanlah aku termasuk orang-orang yang bertaubat dan jadikanlah aku termasuk orang-orang yang mensucikan diri), niscaya akan dibukakan baginya delapan pintu surga, ia dipersilahkan masuk dari pintu mana saja yang ia kehendaki.\" Abu Isa berkata; \"Dalam bab ini ada juga hadits dari Anas dan Uqbah bin 'Amir.\" Abu Isa berkata; \"Hadits Umar telah diselisihi Zaid bin Hubab dalam hadits ini.\" Abu Isa berkata; \" [Abdullah bin Shalih] dan yang lainnya telah meriwayatkan dari [Mu'awiyah bin Shalih], dari [Rabi'ah bin Yazid], dari [Abu Idris], dari [Uqbah bin A'mir], dari [Umar]. Dan [Rabi'ah] meriwayatkan dari [Abu Utsman], dari [Jubair bin Nufair], dari [Umar]. Dan hadits ini dalam sanadnya mengalami idltirab (pertentangan), dan dalam bab ini tidak ada hadits yang sah dari Nabi shallallahu 'alaihi wasallam.\" Muhammad berkata; \"Abu Idris tidak mendengar sesuatu pun dari Umar.\""},"51":{"ar":"و حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ وَعَليُّ بْنُ حُجْرٍ قَالَا حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ أَبِي رَيْحَانَةَ عَنْ سَفِينَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَوَضَّأُ بِالْمُدِّ وَيَغْتَسِلُ بِالصَّاعِقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَجَابِرٍ وَأَنَسِ بْنِ مَالِكٍ قَالَ أَبُو عِيسَى حَدِيثُ سَفِينَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو رَيْحَانَةَ اسْمُهُ عَبْدُ اللَّهِ بْنُ مَطَرٍ وَهَكَذَا رَأَى بَعْضُ أَهْلِ الْعِلْمِ الْوُضُوءَ بِالْمُدِّ وَالْغُسْلَ بِالصَّاعِ و قَالَ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ لَيْسَ مَعْنَى هَذَا الْحَدِيثِ عَلَى التَّوَقِّي أَنَّهُ لَا يَجُوزُ أَكْثَرُ مِنْهُ وَلَا أَقَلُّ مِنْهُ وَهُوَ قَدْرُ مَا يَكْفِي","id":"telah menceritakan kepada kami [Ahmad bin Mani'] dan [Ali bin Hujr] keduanya berkata; telah menceritakan kepada kami [Isma'il bin Ulaiyyah] dari [Abu Raihanah] dari [Safinah] berkata; \"Nabi shallallahu 'alaihi wasallam berwudlu hanya dengan air satu mud dan mandi dengan satu sha'.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Aisyah, Jabir, dan Anas bin Malik.\" Abu Isa berkata; \"Hadits Safinah derajatnya hasan shahih, sedangkan Abu Raihanan namanya adalah Abdullah bin Mathar.\" Demikanlah, para ahli ilmu berpendapat bahwa wudlu cukup dengan air satu mud dan mandi dengan satu sha'. Imam Syafi'i, Ahmad dan Ishak mengatakan; \"Hadits ini bukan bermakna sebagai pembatasan, bahwa hal itu tidak boleh terlalu banyak atau sedikit, tetapi menurut kadarnya.\""},"52":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاودَ الطَّيَالِسِيُّ حَدَّثَنَا خَارِجَةُ بْنُ مُصْعَبٍ عَنْ يُونُسَ بْنِ عُبَيْدٍ عَنْ الْحَسَنِ عَنْ عُتَيِّ بْنِ ضَمْرَةَ السَّعْدِيِّ عَنْ أُبَيِّ بْنِ كَعْبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ لِلْوُضُوءِ شَيْطَانًا يُقَالُ لَهُ الْوَلَهَانُ فَاتَّقُوا وَسْوَاسَ الْمَاءِقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَعَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَ أَبُو عِيسَى حَدِيثُ أُبَيِّ بْنِ كَعْبٍ حَدِيثٌ غَرِيبٌ وَلَيْسَ إِسْنَادُهُ بِالْقَوِيِّ عِنْدَ أَهْلِ الْحَدِيثِ لَأَنَّا لَا نَعْلَمُ أَحَدًا أَسْنَدَهُ غَيْرَ خَارِجَةَ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ الْحَسَنِ قَوْلَهُ وَلَا يَصِحُّ فِي هَذَا الْبَابِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْءٌ وَخَارِجَةُ لَيْسَ بِالْقَوِيِّ عِنْدَ أَصْحَابِنَا وَضَعَّفَهُ ابْنُ الْمُبَارَكِ","id":"telah menceritakan kepada kami [Muhammad Bin Basysyar] berkata, telah menceritakan kepada kami [Abu Dawud Ath Thayalisi] berkata, telah menceritakan kepada kami [Kharijah bin Mush'ab] dari [Yunus bin Ubaid] dari [Al Hasan] dari [Utai bin Dlamrah As Sa'di] dari [Ubai bin Ka'ab] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \" Sesungguhnya pada tiap wudlu ada Setan yang dinamakan dengan Al Walhan, maka jauhilah was-was dalam air.\" Ia berkata; \"Dalam bab ini ada juga hadits dari Abdullah bin 'Amru dan Abdullah bin Mughaffal.\" Abu Isa berkata; \"Hadits Ubai bin Ka'ab adalah hadits gharib dan sanadnya tidak kuat menurut ahli hadits, karena kami tidak mengetahui seorang pun yang menyandarkan hadits ini kecuali Kharijah. Hadits ini juga telah diriwayatkan dari beberapa jalur dari perkataan Al Hasan. Dan tidak ada hadits yang sah dari Nabi shallallahu 'alaihi wasallam dalam bab ini. Menurut sahabat sahabat kami, Kharijah adalah seorang yang tidak kuat, dan Ibnul Mubarak melemahkannya.\""},"53":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ الرَّازِيُّ حَدَّثَنَا سَلَمَةُ بْنُ الْفَضْلِ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ حُمَيْدٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَوَضَّأُ لِكُلِّ صَلَاةٍ طَاهِرًا أَوْ غَيْرَ طَاهِرٍقَالَ قُلْتُ لِأَنَسٍ فَكَيْفَ كُنْتُمْ تَصْنَعُونَ أَنْتُمْ قَالَ كُنَّا نَتَوَضَّأُ وُضُوءًا وَاحِدًا قَالَ أَبُو عِيسَى وَحَدِيثُ حُمَيْدٍ عَنْ أَنَسٍ حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَالْمَشْهُورُ عَنْدَ أَهْلِ الْحَدِيثِ حَدِيثُ عَمْرِو بْنِ عَامِرٍ الْأَنْصَارِيِّ عَنْ أَنَسٍ وَقَدْ كَانَ بَعْضُ أَهْلِ الْعِلْمِ يَرَى الْوُضُوءَ لِكُلِّ صَلَاةٍ اسْتِحْبَابًا لَا عَلَى الْوُجُوبِ","id":"telah menceritakan kepada kami [Muhammad bin Humaid Ar Razi] berkata, telah menceritakan kepada kami [Salamah Ibnul Fadll] dari [Muhammad bin Ishaq] dari [Humaid] dari [Anas] berkata; \"Nabi shallallahu 'alaihi wasallam selalu berwudlu ketika akan shalat, baik dalam keadaan suci atau tidak.\" Humaid berkata; Aku berkata kepada Anas; \"Lalu bagaimana dengan kalian, apa yang kalian lakukan?\" ia menjawab, \"Kami hanya berwudlu sekali.\" Abu Isa berkata; \"Hadits Humaid dari Anas derajatnya hasan gharib dari sisi ini. Tetapi yang mashur menurut ahli hadits adalah hadits 'Amru bin 'Amir Al Anshari. Dan sebagian ahli ilmu berpendapat bahwa wudlu setiap akan melakukan shalat adalah dianjurkan, bukan diwajibkan."},"54":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَعَبْدُ الرَّحْمَنِ هُوَ ابْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ سَعِيدٍ عَنْ عَمْرِو بْنِ عَامِرٍ الْأنْصَارِيِّ قَال سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ عِنْدَ كُلِّ صَلَاةٍقُلْتُ فَأَنْتُمْ مَا كُنْتُمْ تَصْنَعُونَ قَالَ كُنَّا نُصَلِّي الصَّلَوَاتِ كُلَّهَا بِوُضُوءٍ وَاحِدٍ مَا لَمْ نُحْدِثْ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَحَدِيثُ حُمَيْدٍ عَنْ أَنَسٍ حَدِيثٌ جَيِّدٌ غَرِيبٌ حَسَنٌ","id":"telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dan [Abdurrahman] -yaitu Ibnu Mahdi- mereka berkata; telah menceritakan kepada kami [Sufyan bin Sa'id] dari ['Amru bin 'Amir Al Anshari] berkata; Aku mendengar [Anas bin Malik] berkata; \"Nabi shallallahu 'alaihi wasallam selalu berwudlu setiap kali shalat.\" Aku berkata; \"Lalu, kalian sendiri apa yang kalian perbuat?\" ia menjawab, \"Kami mengerjakan semua shalat dengan satu kali wudlu, selama kami belum batal.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, sedangkan hadits Humaid dari Anas haditsnya baik, namun gharib hasan.\""},"55":{"ar":"وَقَدْ رُوِيَ فِي حَدِيثٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ تَوَضَّأَ عَلَى طُهْرٍ كَتَبَ اللَّهُ لَهُ بِهِ عَشْرَ حَسَنَاتٍقَالَ وَرَوَى هَذَا الْحَدِيثَ الْأَفْرِيقِيُّ عَنْ أَبِي غُطَيْفٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا بِذَلِكَ الْحُسَيْنُ بْنُ حُرَيْثٍ الْمَرْوَزِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ يَزِيدَ الْوَاسِطِيُّ عَنْ الْأَفْرِيقِيِّ وَهُوَ إِسْنَادٌ ضَعِيفٌ قَالَ عَلِيُّ بْنُ الْمَدِينِيِّ قَالَ يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ ذَكَرَ لِهِشَامِ بْنِ عُرْوَةَ هَذَا الْحَدِيثُ فَقَالَ هَذَا إِسْنَادٌ مَشْرِقِيٌ قَالَ سَمِعْت أَحْمَدَ بْنَ الْحَسَنِ يَقُولُ سَمِعْتُ أَحْمَدَ بْنَ حَنْبَلٍ يَقُولُ مَا رَأَيْتُ بِعَيْنِي مِثْلَ يَحْيَى بْنِ سَعِيدٍ الْقَطَّانِ","id":"Telah diriwayatkan dalam sebuah hadits dari Ibnu Umar, dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau bersabda: \" Barangsiapa berwudlu dalam keadaan suci maka Allah akan mencatat baginya sepuluh kebaikan.\" Ia berkata; \" [Al Afriqi] telah meriwayatkan hadits ini dari [Abu Ghuthaif], dari [Ibnu Umar], dari Nabi shallallahu 'alaihi wasallam. [Al Husain bin Huraits Al Marwazi] telah bercerita kepada kami seperti itu juga, bahwa [Muhammad bin Yazid Al Wasithi] telah bercerita kepada kami dari [Al Afriqi], dan sanadnya adalah lemah. Ali bin Al Madini berkata; \"Yahya bin Sa'id Al Qaththan berkata; \"Ketika disebutkan hadits ini kepada Hisyam bin Urwah dia menjawab, \"Ini adalah sanad orang-orang timur.\" Abu Isa berkata; \"Aku mendengar Ahmad bin Al Hasan berkata; \"Aku mendengar Ahmad bin Hambal berkata; \"Aku tidak pernah melihat seseorang dengan kedua mataku seperti Yahya bin Sa'id Al Qaththan.\" "},"56":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ لِكُلِّ صَلَاةٍ فَلَمَّا كَانَ عَامُ الْفَتْحِ صَلَّى الصَّلَوَاتِ كُلَّهَا بِوُضُوءٍ وَاحِدٍ وَمَسَحَ عَلَى خُفَّيْهِ فَقَالَ عُمَرُ إِنَّكَ فَعَلْتَ شَيْئًا لَمْ تَكُنْ فَعَلْتَهُ قَالَ عَمْدًا فَعَلْتُهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَى هَذَا الْحَدِيثَ عَلِيُّ بْنُ قَادِمٍ عَنْ سُفْيَانَ الثَّوْرِيِّ وَزَادَ فِيهِ تَوَضَّأَ مَرَّةً مَرَّةً قَالَ وَرَوَى سُفْيَانُ الثَّوْرِيُّ هَذَا الْحَدِيثَ أَيْضًا عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَوَضَّأُ لِكُلِّ صَلَاةٍ وَرَوَاهُ وَكِيعٌ عَنْ سُفْيَانَ عَنْ مُحَارِبٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَ وَرَوَاهُ عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَغَيْرُهُ عَنْ سُفْيَانَ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا وَهَذَا أَصَحُّ مِنْ حَدِيثِ وَكِيعٍ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ أَنَّهُ يُصَلِّي الصَّلَوَاتِ بِوُضُوءٍ وَاحِدٍ مَا لَمْ يُحْدِثْ وَكَانَ بَعْضُهُمْ يَتَوَضَّأُ لِكُلِّ صَلَاةٍ اسْتِحْبَابًا وَإِرَادَةَ الْفَضْلِ وَيُرْوَى عَنْ الْأَفْرِيقِيِّ عَنْ أَبِي غُطَيْفٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَوَضَّأَ عَلَى طُهْرٍ كَتَبَ اللَّهُ لَهُ بِهِ عَشْرَ حَسَنَاتٍ وَهَذَا إِسْنَادٌ ضَعِيفٌ وَفِي الْبَاب عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ وَالْعَصْرَ بِوُضُوءٍ وَاحِدٍ","id":"telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Alqamah bin Martsad] dari [Sulaiman bin Buraidah] dari [Bapaknya] ia berkata; \"Nabi shallallahu 'alaihi wasallam selalu berwudlu ketika akan shalat. Dan pada hari penaklukan kota Makkah, beliau mengerjakan semua shalat dengan satu wudlu dan mengusap khufnya. Lalu Umar berkata; \"Sungguh, engkau melakukan sesuatu yang tidak biasa engkau lakukan, \" beliau menjawab: \"Aku sengaja melakukannya.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\" [Ali bin Qadim] meriwayatkan hadits ini dari [Sufyan Ats Tsauri], lalu ia menambahkan, \"Rasulullah berwudlu dengan satu kali-satu kali.\" Ia berkata; \"Dan [Sufyan Ats Tsauri] juga meriwayatkan hadits ini dari [Muharib bin Ditsar], dari [Sulaiman bin Buraidah], dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau selalu berwudlu ketika akan shalat. Dan [Waki'] meriwayatkannya dari [Sufyan], dari [Muharib], dari [Sulaiman bin Buraidah], dari [bapaknya]. [Abdurrahman bin Mahdi] dan selainnya meriwayatkannya dari [Sufyan], dari [Muharib bin Ditsar], dari [Sulaiman bin Buraidah], dari Nabi shallallahu 'alaihi wasallam secara mursal, dan ini lebih shahih dari hadits Waki'. Para ahli ilmu mengamalkan hadits ini, yaitu bahwa Rasulullah melakukan beberapa shalat dengan satu kali wudlu selama belum batal. Namun di antara mereka ada yang berwudlu setiap kali akan mengerjakan shalat karena ada anjuran dan demi mendapatkan keutamaan.\" Diriwayatkan pula dari Al Afriqi, dari Abu Ghuthaif, dari Ibnu Umar dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa berwudlu dalam keadaan masih suci maka Allah akan menuliskan baginya sepuluh kebaikan.\" Namun hadits ini sanadnya lemah. Dan dalam bab ini ada riwayat dari Jabir bin Abdullah bahwa Nabi shallallahu 'alaihi wasallam shalat zhuhur dan ashar dengan satu wudlu.\""},"57":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ أَبِي الشَّعْثَاءِ عَنْ ابْنِ عَبَّاسٍ قَالَ حَدَّثَتْنِي مَيْمُونَةُ قَالَتْكُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ مِنْ الْجَنَابَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ عَامَّةِ الْفُقَهَاءِ أَنْ لَا بَأْسَ أَنْ يَغْتَسِلَ الرَّجُلُ وَالْمَرْأَةُ مِنْ إِنَاءٍ وَاحِدٍ قَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَعَائِشَةَ وَأَنَسٍ وَأُمِّ هَانِئٍ وَأُمِّ صُبَيَّةَ الْجُهَنِيَّةِ وَأُمِّ سَلَمَةَ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى وَأَبُو الشَّعْثَاءِ اسْمُهُ جَابِرُ بْنُ زَيْدٍ","id":"telah menceritakan kepada kami [Ibnu Abu Umar] berkata, telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Amru bin Dinar] dari [Abu Sya'tsa`] dari [Ibnu Abbas] berkata; [Maimunah] berkata kepadaku, \" Aku pernah mandi bersama Rasulullah shallallahu 'alaihi wasallam dengan satu bejana ketika junub.\" Abu Isa berkata; \"Ini adalah hadits hasan shahih, dan ini adalah pendapat kebanyakan fuqaha, bahwa seorang laki-laki boleh mandi dengan seorang wanita dalam satu bejana.\" Dalam bab ini juga ada riwayat dari Ali, Aisyah, Anas, Ummu Hani`, Ummu Shubayyah Al Juhanniah, Ummu Salamah, dan Ibnu Umar.\" Abu Isa berkata; \"Dan Abu Asy Sya'tsa` namanya adalah Jabir bin Zaid.\""},"58":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي حَاجِبٍ عَنْ رَجُلٍ مِنْ بَنِي غِفَارٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ فَضْلِ طَهُورِ الْمَرْأَةِقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ قَالَ أَبُو عِيسَى وَكَرِهَ بَعْضُ الْفُقَهَاءِ الْوُضُوءَ بِفَضْلِ طَهُورِ الْمَرْأَةِ وَهُوَ قَوْلُ أَحْمَدَ وَإِسْحَقَ كَرِهَا فَضْلَ طَهُورِهَا وَلَمْ يَرَيَا بِفَضْلِ سُؤْرِهَا بَأْسًا","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Sulaiman At Taimi] dari [Abu Hajib] dari [Seorang laki-laki dari bani Ghifar], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang dari air sisa mandi seorang wanita.\" Dan dalam bab ini ada juga riwayat dari Abdullah bin Sarjis. Abu Isa berkata; \"Sebagian fuqaha memakruhkan berwudlu dari air sisa mandi seorang wanita. Dan ini adalah perkataan Ahmad dan Ishaq, mereka memakruhkan air sisa bersucinya mereka, bukan sisa air yang masih dalam bejananya.\" "},"59":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمَحْمُودُ بْنُ غَيْلَانَ قَالَا حَدَّثَنَا أَبُو دَاوُدَ عَنْ شُعْبَةَ عَنْ عَاصِمٍ قَال سَمِعْتُ أَبَا حَاجِبٍ يُحَدِّثُ عَنْ الْحَكَمِ بْنِ عَمْرٍو الْغِفَارِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَتَوَضَّأَ الرَّجُلُ بِفَضْلِ طَهُورِ الْمَرْأَةِ أَوْ قَالَ بِسُؤْرِهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَأَبُو حَاجِبٍ اسْمُهُ سَوَادَةُ بْنُ عَاصِمٍ و قَالَ مُحَمَّدُ بْنُ بَشَّارٍ فِي حَدِيثِهِ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَتَوَضَّأَ الرَّجُلُ بِفَضْلِ طَهُورِ الْمَرْأَةِ وَلَمْ يَشُكَّ فِيهِ مُحَمَّدُ بْنُ بَشَّارٍ","id":"telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad bin Ghailan] mereka berkata; telah menceritakan kepada kami [Abu Dawud] dari [Syu'bah] dari ['Ashim] berkata; Aku mendengar [Abu Hajib] menceritakan dari [Al Hakam bin 'Amru Al Ghifari] bahwa Nabi shallallahu 'alaihi wasallam melarang seorang laki-laki berwudlu dengan air sisa bersucinya wanita, atau ia mengatakan; \"Air sisa yang masih di dalam bejananya.\" Abu Isa berkata; \"Ini adalah hadits hasan. Dan Abu Hajib namanya adalah Sawadah bin 'Ashim.\" Muhammad bin Basysyar menyebutkan dalam haditsnya; \"Rasulullah shallallahu 'alaihi wasallam melarang seorang laki-laki berwudlu dengan air sisa bersucinya seorang wanita, \" dan Muhammad bin Basysyar tidak ragu di dalamnya."},"60":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَاغْتَسَلَ بَعْضُ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَفْنَةٍ فَأَرَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَتَوَضَّأَ مِنْهُ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي كُنْتُ جُنُبًا فَقَالَ إِنَّ الْمَاءَ لَا يُجْنِبُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَمَالِكٍ وَالشَّافِعِيِّ","id":"telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak bin Harb] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; \"Beberapa istri Nabi shallallahu 'alaihi wasallam mandi dalam satu bejana, kemudian Rasulullah shallallahu 'alaihi wasallam hendak berwudlu darinya, namun ia berkata; \"Wahai Rasulullah, sesungguhnya aku junub, \" beliau lalu menjawab: \"Sesungguhnya air itu tidak junub (tidak najis).\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, dan hadits ini dipegang oleh Sufyan Ats Tsauri, Malik dan Syafi'i.\""},"61":{"ar":"حَدَّثَنَا هَنَّادٌ وَالْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْوَلِيدِ بْنِ كَثِيرٍ عَنْ مُحَمَّدِ بْنِ كَعْبٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ رَافِعِ بْنِ خَدِيجٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقِيلَ يَا رَسُولَ اللَّهِ أَنَتَوَضَّأُ مِنْ بِئْرِ بُضَاعَةَ وَهِيَ بِئْرٌ يُلْقَى فِيهَا الْحِيَضُ وَلُحُومُ الْكِلَابِ وَالنَّتْنُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمَاءَ طَهُورٌ لَا يُنَجِّسُهُ شَيْءٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ جَوَّدَ أَبُو أُسَامَةَ هَذَا الْحَدِيثَ فَلَمْ يَرْوِ أَحَدٌ حَدِيثَ أَبِي سَعِيدٍ فِي بِئْرِ بُضَاعَةَ أَحْسَنَ مِمَّا رَوَى أَبُو أُسَامَةَ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي سَعِيدٍ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَعَائِشَةَ","id":"telah menceritakan kepada kami [Hannad] dan [Al Hasan bin Ali Al khallal] dan yang lainnya, mereka berkata; telah menceritakan kepada kami [Abu Usamah] dari [Al Walid bin Katsir] dari [Muhammad bin Ka'ab] dari [Ubaidullah bin Abdullah bin Rafi' bin Khadij] dari [Abu Sa'id Al Khudri] ia berkata; ada yang bertanya; \"Wahai Rasulullah, apakah kami boleh berwudlu dari air sumur Budla'ah yang dibuang ke dalamnya terdapat kain bekas pembalut haid, daging anjing dan bangkai?\" maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Sungguh air itu suci tidak ada sesuatu yang membuatnya najis.\" Abu Isa berkata; \"Hadits ini hasan, Abu Usamah telah menyatakan bahwa dia adalah hadits yang baik, dan tidak ada seorangpun yang meriwayatkan hadits Abu Sa'id tentang sumur Budla'ah yang lebih baik dari apa yang diriwayatkan oleh Abu Usamah. Dan hadits ini telah diriwayatkan dari beberapa jalur dari Abu Sa'id. Juga dalam bab ini ada hadits dari Ibnu Abbas dan Aisyah.\""},"62":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ الزُّبَيْرِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ ابْنِ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُسْأَلُ عَنْ الْمَاءِ يَكُونُ فِي الْفَلَاةِ مِنْ الْأَرْضِ وَمَا يَنُوبُهُ مِنْ السِّبَاعِ وَالدَّوَابِّ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ الْمَاءُ قُلَّتَيْنِ لَمْ يَحْمِلْ الْخَبَثَقَالَ عَبْدَةُ قَالَ مُحَمَّدُ بْنُ إِسْحَقَ الْقُلَّةُ هِيَ الْجِرَارُ وَالْقُلَّةُ الَّتِي يُسْتَقَى فِيهَا قَالَ أَبُو عِيسَى وَهُوَ قَوْلُ الشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ قَالُوا إِذَا كَانَ الْمَاءُ قُلَّتَيْنِ لَمْ يُنَجِّسْهُ شَيْءٌ مَا لَمْ يَتَغَيَّرْ رِيحُهُ أَوْ طَعْمُهُ وَقَالُوا يَكُونُ نَحْوًا مِنْ خَمْسِ قِرَبٍ","id":"telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Abdah] dari [Muhammad bin Ishaq] dari [Muhammad bin Ja'far bin Az Zubair] dari [Ubaidullah bin Abdullah bin Umar] dari [Ibnu Umar] ia berkata; \"Aku mendengar dari Rasulullah shallallahu 'alaihi wasallam ketika beliau ditanya tentang air yang ada di tanah lapang dan sering dikunjungi oleh binatang buas dan hewan hewan lainnya, \" Ibnu Umar berkata; Maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Apabila air itu mencapai dua Qulah maka tidak akan mengandung kotoran (najis).\" Abdah berkata; Muhammad bin Ishaq berkata; \"Al Qullah adalah beberapa guci besar, dan Qullah adalah air yang biasa dipakai untuk minum.\" Abu Isa berkata; \"Dan itu adalah pendapat Imam Syafi'i, Ahmad, dan Ishaq. Mereka mengatakan; \"Apabila air itu mencapai dua Qullah maka tidak ada sesuatu yang menjadikannya najis, yaitu selama tidak berubah bau atau rasanya, dan mereka mengatakan; \"kira-kira airnya sebanyak lima Qirbah (kendi).\""},"63":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَبُولَنَّ أَحَدُكُمْ فِي الْمَاءِ الدَّائِمِ ثُمَّ يَتَوَضَّأُ مِنْهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ جَابِرٍ","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jangan sekali-kali salah seorang dari kalian kencing di air yang diam (tidak mengalir) kemudian berwudlu darinya.\" Abu Isa berkata; \"Ini adalah hadits yang hasan shahih, dan dalam bab ini juga ada riwayat dari Jabir.\""},"64":{"ar":"حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ ح و حَدَّثَنَا الْأَنْصَارِيُّ إِسْحَقُ بْنُ مُوسَى حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ سَعِيدِ بْنِ سَلَمَةَ مِنْ آلِ ابْنِ الْأَزْرَقِ أَنَّ الْمُغِيرَةَ بْنَ أَبِي بُرْدَةَ وَهُوَ مِنْ بَنِي عَبْدِ الدَّارِ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُسَأَلَ رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّا نَرْكَبُ الْبَحْرَ وَنَحْمِلُ مَعَنَا الْقَلِيلَ مِنْ الْمَاءِ فَإِنْ تَوَضَّأْنَا بِهِ عَطِشْنَا أَفَنَتَوَضَّأُ مِنْ مَاءِ الْبَحْرِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ الطَّهُورُ مَاؤُهُ الْحِلُّ مَيْتَتُهُقَالَ وَفِي الْبَاب عَنْ جَابِرٍ وَالْفِرَاسِيِّ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ أَكْثَرِ الْفُقَهَاءِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ أَبُو بَكْرٍ وَعُمَرُ وَابْنُ عَبَّاسٍ لَمْ يَرَوْا بَأْسًا بِمَاءِ الْبَحْرِ وَقَدْ كَرِهَ بَعْضُ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوُضُوءَ بِمَاءِ الْبَحْرِ مِنْهُمْ ابْنُ عُمَرَ وَعَبْدُ اللَّهِ بْنُ عَمْرٍو وَقَالَ عَبْدُ اللَّهِ بْنُ عَمْرٍو هُوَ نَارٌ","id":"telah menceritakan kepada kami [Qutaibah] dari [Malik]. Dan dari jalur yang lain; Telah menceritakan kepada kami [Al Anshari Ishaq bin Musa] berkata, telah menceritakan kepada kami [Ma'n] berkata, telah menceritakan kepada kami [Malik] dari [Shafwan bin Sulaim] dari [Sa'id bin Salamah] keluarga Ibnu Al Azraq, bahwa [Al Mughirah bin Abu burdah] bani Abdu Ad Dar, mengabarkan kepadanya, bahwasanya ia mendengar [Abu Hurairah] berkata; bahwa seseorang bertanya kepada Nabi shallallahu 'alaihi wasallam; \"Wahai Rasulullah, sesungguhnya kami mengarungi lautan dan kami hanya membawa sedikit air, jika kami gunakan air itu untuk wudlu maka kami akan kehausan. Lalu apakah kami boleh berwudlu dengan air laut?\" maka Rasulullah shallallahu 'alaihi wasallam pun menjawab: \"Laut itu suci airnya dan halal bangkainya.\" Dalam bab ini juga ada riwayat dari Jabir dan Al Firasi. Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, dan ini adalah pendapat yang diambil oleh kebanyakan fuqaha dari kalangan sahabat Nabi shallallahu 'alaihi wasallam. Di antaranya adalah Abu Bakar, Umar dan Ibnu Abbas. Mereka berpendapat bahwa bersuci dengan air laut itu dibolehkan. Namun ada juga sebagian sahabat Nabi shallallahu 'alaihi wasallam yang memakruhkan hal itu, di antara mereka adalah Ibnu Umar dan Abdullah bin 'Amru. Dan Abdullah bin 'Amru berkata; \"Itu adalah api.\""},"65":{"ar":"حَدَّثَنَا هَنَّادٌ وَقُتَيْبَةُ وَأَبُو كُرَيْبٍ قَالُوا حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ قَال سَمِعْتُ مُجَاهِدًا يُحَدِّثُ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ عَلَى قَبْرَيْنِ فَقَالَ إِنَّهُمَا يُعَذَّبَانِ وَمَا يُعَذَّبَانِ فِي كَبِيرٍ أَمَّا هَذَا فَكَانَ لَا يَسْتَتِرُ مِنْ بَوْلِهِ وَأَمَّا هَذَا فَكَانَ يَمْشِي بِالنَّمِيمَةِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَبِي مُوسَى وَعَبْدِ الرَّحْمَنِ بْنِ حَسَنَةَ وَزَيْدِ بْنِ ثَابِتٍ وَأَبِي بَكْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَى مَنْصُورٌ هَذَا الْحَدِيثَ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ وَلَمْ يَذْكُرْ فِيهِ عَنْ طَاوُسٍ وَرِوَايَةُ الْأَعْمَشِ أَصَحُّ قَالَ و سَمِعْت أَبَا بَكْرٍ مُحَمَّدَ بْنَ أَبَانَ الْبَلْخِيَّ مُسْتَمْلِي وَكِيعٍ يَقُولُ سَمِعْتُ وَكِيعًا يَقُولُ الْأَعْمَشُ أَحْفَظُ لِإِسْنَادِ إِبْرَاهِيمَ مِنْ مَنْصُورٍ","id":"telah menceritakan kepada kami [Hannad] dan [Qutaibah] dan [Abu Kuraib] mereka berkata; telah menceritakan kepada kami [Waki'] dari [Al A'masy] ia berkata; aku mendengar [Mujahid] menceritakan dari [Thawus] dari [Ibnu Abbas] berkata; Nabi shallallahu 'alaihi wasallam melewati dua kuburan, kemudian beliau bersabda: \" Keduanya sedang disiksa, dan mereka disiksa bukan karena dosa besar. Yang ini disiksa karena tidak menutup diri ketika kencing, dan yang satu lagi karena mengadu domba.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\" Dan [Manshur] meriwayatkan hadits ini dari [Mujahid], dari [Ibnu Abbas], namun dia tidak menyebutkan dari Thawus. Sedangkan hadits riwayat Al A'masy lebih shahih. Ia berkata; \"Aku mendengar Abu Bakr bin Abn Al Balkhi -orang yang minta dibacakan oleh Waki'- berkata; \"Al A'masy lebih hafal dengan sanad Ibrahim daripada Manshur.\""},"66":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَأَحْمَدُ بْنُ مَنِيعٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍ قَالَتْدَخَلْتُ بِابْنٍ لِي عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَأْكُلْ الطَّعَامَ فَبَالَ عَلَيْهِ فَدَعَا بِمَاءٍ فَرَشَّهُ عَلَيْهِقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَعَائِشَةَ وَزَيْنَبَ وَلُبَابَةَ بِنْتِ الْحَارِثِ وَهِيَ أُمُّ الْفَضْلِ بْنِ عَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ وَأَبِي السَّمْحِ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَأَبِي لَيْلَى وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ مِثْلِ أَحْمَدَ وَإِسْحَقَ قَالُوا يُنْضَحُ بَوْلُ الْغُلَامِ وَيُغْسَلُ بَوْلُ الْجَارِيَةِ وَهَذَا مَا لَمْ يَطْعَمَا فَإِذَا طَعِمَا غُسِلَا جَمِيعًا","id":"telah menceritakan kepada kami [Qutaibah] dan [Ahmad bin Muni'] mereka berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Ubaidillah bin Abdullah bin Utbah] dari [Ummu Qais binti Mihshan] ia berkata; \"Aku menemui Nabi shallallahu 'alaihi wasallam bersama anakku yang belum makan makanan (masih bayi), lalu ia mengencinginya. Maka Nabi pun minta untuk diambilkan air, lalu beliau menyiramkan air itu pada kencing tersebut.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ali, Aisyah, Zainab, Lubabah binti Al Harits, yaitu Ummu Al Fadll bin Abbas bin Abdul Muthallib, Abu As Samh, Abdullah bin 'Amru, Abu Laila dan Ibnu Abbas. Ini pendapat banyak orang dari ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang setelah mereka seperti Ahmad dan Ishaq. Mereka berkata; \"Kencing anak laki-laki itu disiram (percikan) sedangkan kencing anak perempuan dicuci, hal ini jika keduanya belum makan, jika keduanya telah makan maka harus dicuci.\""},"67":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدٍ الزَّعْفَرَانِيُّ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا حُمَيْدٌ وَقَتَادَةُ وَثَابِتٌ عَنْ أَنَسٍأَنَّ نَاسًا مِنْ عُرَيْنَةَ قَدِمُوا الْمَدِينَةَ فَاجْتَوَوْهَا فَبَعَثَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِبِلِ الصَّدَقَةِ وَقَالَ اشْرَبُوا مِنْ أَلْبَانِهَا وَأَبْوَالِهَا فَقَتَلُوا رَاعِيَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتَاقُوا الْإِبِلَ وَارْتَدُّوا عَنْ الْإِسْلَامِ فَأُتِيَ بِهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَطَعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ مِنْ خِلَافٍ وَسَمَرَ أَعْيُنَهُمْ وَأَلْقَاهُمْ بِالْحَرَّةِقَالَ أَنَسٌ فَكُنْتُ أَرَى أَحَدَهُمْ يَكُدُّ الْأَرْضَ بِفِيهِ حَتَّى مَاتُوا وَرُبَّمَا قَالَ حَمَّادٌ يَكْدُمُ الْأَرْضَ بِفِيهِ حَتَّى مَاتُوا قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ أَنَسٍ وَهُوَ قَوْلُ أَكْثَرِ أَهْلِ الْعِلْمِ قَالُوا لَا بَأْسَ بِبَوْلِ مَا يُؤْكَلُ لَحْمُهُ","id":"telah menceritakan kepada kami [Al Hasan bin Muhammad Az Za'farani] berkata, telah menceritakan kepada kami ['Affan bin Muslim] berkata, telah menceritakan kepada kami [Hammad bin Salamah] berkata, telah menceritakan kepada kami [Humaid] dan [Qotadah] dan [Tsabit] dari [Anas] berkata; \" Beberapa orang dari Urainah datang ke Madinah, namun mereka tidak cocok dengan iklim Madinah, maka Rasulullah shallallahu 'alaihi wasallam pun mengirim mereka ke (tempat) unta zakat. Beliau bersabda: \"Minumlah kalian susu dan air kencingnya.\" Namun mereka membunuh pengembala Rasulullah shallallahu 'alaihi wasallam dan menggiring unta-unta tersebut, setelah itu mereka murtad. Lalu mereka pun dihadapkan kepada Nabi shallallahu 'alaihi wasallam, beliau kemudian memotong tangan dan kaki mereka secara bersilang, mata mereka dicongkel lalu dibuang ke harrah (padang pasir yang panas).\" Anas berkata; \"Aku melihat salah seorang dari mereka jatuh tersungkur hingga pasir masuk ke dalam mulut, lalu mereka mati.\" Dan mungkin Hammad berkata; \"Ia menggigit tanah dengan mulutnya hingga mereka mati.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, dan hadits ini juga telah diriwayatkan dari Anas dengan jalur lain. ini adalah pendapat sebagian besar ahli ilmu, Mereka mengatakan; \"Tidak apa-apa air kencing binatang yang boleh dimakan dagingnya.\""},"68":{"ar":"حَدَّثَنَا الْفَضْلُ بْنُ سَهْلٍ الْأَعْرَجُ الْبَغْدَادِيُّ حَدَّثَنَا يَحْيَى بْنُ غَيْلَانَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سُلَيْمَانُ الْتَّيْمِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَإِنَّمَا سَمَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْيُنَهُمْ لِأَنَّهُمْ سَمَلُوا أَعْيُنَ الرُّعَاةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْلَمُ أَحَدًا ذَكَرَهُ غَيْرَ هَذَا الشَّيْخِ عَنْ يَزِيدَ بْنِ زُرَيْعٍ وَهُوَ مَعْنَى قَوْلِهِ{ وَالْجُرُوحَ قِصَاصٌ }وَقَدْ رُوِيَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَ إِنَّمَا فَعَلَ بِهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا قَبْلَ أَنْ تَنْزِلَ الْحُدُودُ","id":"telah menceritakan kepada kami [Al Fadll bin Sahl Al A'raj Al Baghdadi] berkata, telah menceritakan kepada kami [Yahya bin Ghailan] berkata; telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepada kami [Sulaiman At Taimi] dari [Anas bin Malik] ia berkata; \"Nabi shallallahu 'alaihi wasallam mencongkel mata mereka karena mereka mencongkel mata pengembala tersebut.\" Abu Isa berkata; \"Hadits ini derajatnya gharib, kami tidak mengetahui yang menyebutkan hadits ini selain syaikh ini, dari Yazid bin Zurai', dan ini sesuai dengan firman-Nya: (dan luka luka (pun) ada qishasnya). Hadits ini juga telah diriwayatkan oleh Muhammad bin Sirin, ia berkata; \"Nabi shallallahu 'alaihi wasallam melakukan hal itu kepada mereka sebelum turunnya ayat yang berbicara masalah hudud.\""},"69":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَهَنَّادٌ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا وُضُوءَ إِلَّا مِنْ صَوْتٍ أَوْ رِيحٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Qutaibah] dan [Hannad] mereka berkata; telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] berkata; \"Bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada wudlu kecuali karena sebab suara atau bau.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\""},"70":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ أَحَدُكُمْ فِي الْمَسْجِدِ فَوَجَدَ رِيحًا بَيْنَ أَلْيَتَيْهِ فَلَا يَخْرُجْ حَتَّى يَسْمَعَ صَوْتًا أَوْ يَجِدَ رِيحًاقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ وَعَلِيِّ بْنِ طَلْقٍ وَعَائِشَةَ وَابْنِ عَبَّاسٍ وَابْنِ مَسْعُودٍ وَأَبِي سَعِيدٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ الْعُلَمَاءِ أَنْ لَا يَجِبَ عَلَيْهِ الْوُضُوءُ إِلَّا مِنْ حَدَثٍ يَسْمَعُ صَوْتًا أَوْ يَجِدُ رِيحًا و قَالَ عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ إِذَا شَكَّ فِي الْحَدَثِ فَإِنَّهُ لَا يَجِبُ عَلَيْهِ الْوُضُوءُ حَتَّى يَسْتَيْقِنَ اسْتِيقَانًا يَقْدِرُ أَنْ يَحْلِفَ عَلَيْهِ وَقَالَ إِذَا خَرَجَ مِنْ قُبُلِ الْمَرْأَةِ الرِّيحُ وَجَبَ عَلَيْهَا الْوُضُوءُ وَهُوَ قَوْلُ الشَّافِعِيِّ وَإِسْحَقَ","id":"telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah]; \"Bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \" Jika salah seorang dari kalian berada dalam masjid lalu mendapatkan angin antara belahan pantatnya, maka janganlah ia keluar hingga ia mendengar suara atau mencium bau.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin Zaid, Ali bin Thalq, Aisyah, Ibnu Abbas, Ibnu Mas'ud dan Abu Sa'id.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, ini adalah pendapat para ulama, bahwa seseorang tidak harus wudlu hingga ia mendengar suara atau mendapatkan bau. Abdullah Ibnul Mubarak berkata; \"Jika seseorang merasa ragu berhadas atau tidak, maka ia tidak harus berwudlu hingga yakin, sehingga ia berani sumpah dengannya.\" Ia berkata lagi, \"Jika ada suara yang keluar dari kamaluan seorang perempuan, maka ia wajib wudlu.\" Ini adalah pendapat Imam Syafi'i dan Ahmad."},"71":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ لَا يَقْبَلُ صَلَاةَ أَحَدِكُمْ إِذَا أَحْدَثَ حَتَّى يَتَوَضَّأَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \" Sesungguhnya Allah tidak akan menerima shalat salah seorang dari kalian jika berhadats hingga ia berwudlu.\" Abu Isa berkata; \"Hadits ini derajatnaya adalah hasan shahih.\""},"72":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى كُوفِيٌّ وَهَنَّادٌ وَمُحَمَّدُ بْنُ عُبَيْدٍ الْمُحَارِبِيُّ الْمَعْنَى وَاحِدٌ قَالُوا حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ الْمُلَائِيُّ عَنْ أَبِي خَالِدٍ الدَّالَانِيِّ عَنْ قَتَادَةَ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَامَ وَهُوَ سَاجِدٌ حَتَّى غَطَّ أَوْ نَفَخَ ثُمَّ قَامَ يُصَلِّي فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّكَ قَدْ نِمْتَ قَالَ إِنَّ الْوُضُوءَ لَا يَجِبُ إِلّ��ا عَلَى مَنْ نَامَ مُضْطَجِعًا فَإِنَّهُ إِذَا اضْطَجَعَ اسْتَرْخَتْ مَفَاصِلُهُقَالَ أَبُو عِيسَى وَأَبُو خَالِدٍ اسْمُهُ يَزِيدُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَابْنِ مَسْعُودٍ وَأَبِي هُرَيْرَةَ","id":"telah menceritakan kepada kami [Isma'il bin Musa] penduduk Kufah, dan [Hannad] dan [Muhammad bin Ubaid Al Muharibi] dengan satu makna, mereka berkata; telah menceritakan kepada kami [Abdussalam bin Harb Al Mula`i] dari [Abu Khalid Ad Dalani] dari [Qotadah] dari [Abul Aliyah] dari [Ibnu Abbas] bahwasanya ia melihat Nabi shallallahu 'alaihi wasallam tidur dalam keadaan sujud hingga beliau mendengkur, setelah itu beliau bangun shalat. Lalu aku berkata; \"Wahai Rasulullah, engkau telah tertidur!\" beliau bersabda: \"Sesungguhnya wudlu itu tidak wajib kecuali bagi orang yang tidur dalam keadaan berbaring. Karena orang yang tidur dalam keadaan berbaring semua persendiannya akan menjadi lunak (merenggang).\" Abu Isa berkata; \"Abu Khalid namanya Yazid bin Abdurrahman.\" Ia berkata lagi, \"Dalam bab ini juga ada riwayat dari Aisyah, Ibnu Mas'ud dan Abu Hurairah.\""},"73":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنَامُونَ ثُمَّ يَقُومُونَ فَيُصَلُّونَ وَلَا يَتَوَضَّئُونَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ و سَمِعْت صَالِحَ بْنَ عَبْدِ اللَّهِ يَقُولُ سَأَلْتُ عَبْدَ اللَّهِ بْنَ الْمُبَارَكِ عَمَّنْ نَامَ قَاعِدًا مُعْتَمِدًا فَقَالَ لَا وُضُوءَ عَلَيْهِ قَالَ أَبُو عِيسَى وَقَدْ رَوَى حَدِيثَ ابْنِ عَبَّاسٍ سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ ابْنِ عَبَّاسٍ قَوْلَهُ وَلَمْ يَذْكُرْ فِيهِ أَبَا الْعَالِيَةِ وَلَمْ يَرْفَعْهُ وَاخْتَلَفَ الْعُلَمَاءُ فِي الْوُضُوءِ مِنْ النَّوْمِ فَرَأَى أَكْثَرُهُمْ أَنْ لَا يَجِبَ عَلَيْهِ الْوُضُوءُ إِذَا نَامَ قَاعِدًا أَوْ قَائِمًا حَتَّى يَنَامَ مُضْطَجِعًا وَبِهِ يَقُولُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَأَحْمَدُ قَالَ بَعْضُهُمْ إِذَا نَامَ حَتَّى غُلِبَ عَلَى عَقْلِهِ وَجَبَ عَلَيْهِ الْوُضُوءُ وَبِهِ يَقُولُ إِسْحَقُ و قَالَ الشَّافِعِيُّ مَنْ نَامَ قَاعِدًا فَرَأَى رُؤْيَا أَوْ زَالَتْ مَقْعَدَتُهُ لِوَسَنِ النَّوْمِ فَعَلَيْهِ الْوُضُوءُ","id":"telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] dari [Qatadah] dari [Anas bin Malik] ia berkata; \" Para sahabat Nabi shallallahu 'alaihi wasallam tidur, lalu mereka bangun dan melaksanakan shalat tanpa berwudlu lagi.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\" Ia berkata; \"Aku mendengar Shalih bin Abdullah berkata; \"Aku bertanya kepada Abdullah Ibnul Mubarak tentang hukum orang yang tidur dalam keadaan duduk dengan sengaja, ia menjawab, \"Ia tidak harus berwudlu.\" Abu Isa berkata; \"Sa'id bin Arubah meriwayatkan hadits Ibnu Abbas dari Qatadah dari Ibnu Abbas. Ia tidak menyebutkan di dalamnya nama Abul Aliyah dan tidak memarfu'kannya. Para ulama berbeda pendapat tentang wudlu karena tidur, sebagian ulama berpendapat atas tidak wajibnya berwudlu apabila tidur itu dilakukan dengan duduk atau berdiri, hingga ia tidur dengan berbaring. Pendapat ini diambil oleh Ats Tsauri, Ibnul Mubarak dan Ahmad. Namun sebagian mereka berkata; \"Jika ia tidur hingga akalnya tidak berfungsi, maka ia wajib wudlu.\" Pendapat ini di ambil oleh Ishaq. Imam Asy Syafi'i berkata; \"Jika seseorang tidur hingga bermimpi, atau hingga tempat duduknya bergeser karena tidur, maka ia wajib berwudlu.\""},"74":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ قَالَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوُضُوءُ مِمَّا مَسَّتْ النَّارُ وَلَوْ مِنْ ثَوْرِ أَقِطٍقَالَ فَقَالَ لَهُ ابْنُ عَبَّاسٍ يَا أَبَا هُرَيْرَةَ أَنَتَوَضَّأُ مِنْ الدُّهْنِ أَنَتَوَضَّأُ مِنْ الْحَمِيمِ قَالَ فَقَالَ أَبُو هُرَيْرَةَ يَا ابْنَ أَخِي إِذَا سَمِعْتَ حَدِيثًا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا تَضْرِبْ لَهُ مَثَلًا قَالَ وَفِي الْبَاب عَنْ أُمِّ حَبِيبَةَ وأُمِّ سَلَمَةَ وَزَيْدِ بْنِ ثَابِتٍ وَأَبِي طَلْحَةَ وَأَبِي أَيُّوبَ وَأَبِي مُوسَى قَالَ أَبُو عِيسَى وَقَدْ رَأَى بَعْضُ أَهْلِ الْعِلْمِ الْوُضُوءَ مِمَّا غَيَّرَتْ النَّارُ وَأَكْثَرُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ عَلَى تَرْكِ الْوُضُوءِ مِمَّا غَيَّرَتْ النَّارُ","id":"telah menceritakan kepada kami [Ibnu Abu Umar] berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Hendaknya berwudlu karena sesuatu yang disentuh api, meskipun itu susu kering (keju).\" Abu Salamah berkata; Ibnu Abbas bertanya kepadanya, \"Wahai Abu Hurairah, apakah kami harus berwudlu karena makan minyak samin? Dan apakah kami juga harus wudlu karena minum air hangat?\" Abu Salamah berkata; Abu Hurairah lalu menjawab, \"Wahai anak saudaraku, jika engkau mendengar hadits dari Rasulullah shallallahu 'alaihi wasallam, maka janganlah kamu membuat permisalan-permisalan (padanan).\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Ummu Habibah, Ummu Salamah, Zaid bin Tsabit, Abu Salamah, Abu Ayyub dan Abu Musa.\" Abu Isa berkata lagi, \"Sebagian ulama berpendapat bahwa wudlu wajib dilakukan karena sesuatu yang dirubah oleh api (mentah menjadi matang), namun sebagian besar ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang setelahnya tidak berwudlu karena sesuatu yang dirubah oleh api.\""},"75":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَقِيلٍ سَمِعَ جَابِرًا قَالَ سُفْيَانُ وَحَدَّثَنَا مُحَمَّدُ بْنُ الْمُنْكَدِرِ عَنْ جَابِرٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَعَهُ فَدَخَلَ عَلَى امْرَأَةٍ مِنْ الْأَنْصَارِ فَذَبَحَتْ لَهُ شَاةً فَأَكَلَ وَأَتَتْهُ بِقِنَاعٍ مِنْ رُطَبٍ فَأَكَلَ مِنْهُ ثُمَّ تَوَضَّأَ لِلظُّهْرِ وَصَلَّى ثُمَّ انْصَرَفَ فَأَتَتْهُ بِعُلَالَةٍ مِنْ عُلَالَةِ الشَّاةِ فَأَكَلَ ثُمَّ صَلَّى الْعَصْرَ وَلَمْ يَتَوَضَّأْقَالَ وَفِي الْبَاب عَنْ أَبِي بَكْرٍ الصِّدِّيقِ وَابْنِ عَبَّاسٍ وَأَبِي هُرَيرَةَ وَابْنِ مَسْعُودٍ وَأَبِي رَافِعٍ وَأُمِّ الْحَكَمِ وَعَمْرِو بْنِ أُمَيَّةَ وَأُمِّ عَامِرٍ وَسُوَيْدِ بْنِ النُّعْمَانِ وَأُمِّ سَلَمَةَ قَالَ أَبُو عِيسَى وَلَا يَصِحُّ حَدِيثُ أَبِي بَكْرٍ فِي هَذَا الْبَابِ مِنْ قِبَلِ إِسْنَادِهِ إِنَّمَا رَوَاهُ حُسَامُ بْنُ مِصَكٍّ عَنْ ابْنِ سِيرِينَ عَنْ ابْنِ عَبَّاسٍ عَنْ أَبِي بَكْرٍ الصِّدِّيقِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالصَّحِيحُ إِنَّمَا هُوَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا رَوَاهُ الْحُفَّاظُ وَرُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ ابْنِ سِيرِينَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَاهُ عَطَاءُ بْنُ يَسَارٍ وَعِكْرِمَةُ وَمُحَمَّدُ بْنُ عَمْرِو بْنِ عَطَاءٍ وَعَلِيُّ بْنُ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ وَغَيْرُ وَاحِدٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَذْكُرُوا فِيهِ عَنْ أَبِي بَكْرٍ الصِّدِّيقِ وَهَذَا أَصَحُّ قَالَ أَبُو عِيسَى وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ مِثْلِ سُفْيَانَ الثَّوْرِيِّ وَابْنِ الْمُبَارَكِ وَالشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ رَأَوْا تَرْكَ الْوُضُوءِ مِمَّا مَسَّتْ النَّارُ وَهَذَا آخِرُ الْأَمْرَيْنِ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَأَنَّ هَذَا الْحَدِيثَ نَاسِخٌ لِلْحَدِيثِ الْأَوَّلِ حَدِيثِ الْوُضُوءِ مِمَّا مَسَّتْ النَّارُ","id":"telah menceritakan kepada kami [Ibnu Abu Umar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] berkata; telah menceritakan kepada kami [Abdullah bin Muhammad bin Aqil] ia mendengar [Jabir]. [Sufyan] berkata; dan telah menceritakan kepada kami [Muhammad Ibnul Munkadir] dari [Jabir] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam keluar bersamaku. Beliau mengunjungi seorang wanita Anshar, lalu wanita itu menyembelih seekor kambing untuknya beliau pun memakannya, kemudian wanita itu juga membawakan sebuah keranjang berisi kurma segar, dan beliau juga memakannya. Setelah itu beliau berwudlu karena zhuhur, shalat dan pergi. Wanita itu kemudian membawakan sisa kambing tersebut, beliau pun memakannya, setelah itu melaksanakan shalat asar tanpa berwudlu terlebih dahulu.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Bakar, Ibnu Abbas, Abu Hurairah, Ibnu Mas'ud, Abu Rafi', Ummu Al Hakam, 'Amru bin Umayyah, Ummu 'Amir, Suwaid bin An Nu'man dan Ummu Salamah.\" Abu Isa berkata; \"Hadits Abu Bakar dalam bab ini tidak sah dari sisi sanadnya.\" Dan yang meriwayatkannya adalah Husan bin Mishak, dari Ibnu Sirin, dari Ibnu Abbas, dari Abu Bakar dari Nabi shallallahu 'alaihi wasallam. Tetapi hadits yang shahih adalah riwayat dari Ibnu Abbas, dari Nabi shallallahu 'alaihi wasallam, demikianlah para hafidz (ahli hadits) meriwayatkannya. Diriwayatkan juga dari jalur lain; dari Ibnu Sirin, Ibnu Abbas, dari Nabi shallallahu 'alaihi wasallam. Hadits itu juga diriwayatkan oleh 'Atho` bin Yasar, Ikrimah, Muhammad bin 'Amru bin 'Atha, Ali bin Abdullah bin Abbas, dan masih banyak lagi dari Ibnu Abbas, dari Nabi shallallahu 'alaihi wasallam tanpa menyebutkan dalam sanadnya nama Abu Bakar Ash Shiddiq. Dan inilah yang paling shahih. Kebanyakan ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang setelah mereka mengamalkan hadits ini. Mereka berpendapat bahwasanya tidak harus berwudlu karena makan sesuatu yang disentuh api. Ini adalah akhir dua hal dari Rasulullah shallallahu 'alaihi wasallam, seakan-akan ini menghapus hadits pertama, yaitu hadits tentang wudlu karena sesuatu yang disentuh api.\""},"76":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ الرَّازِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْوُضُوءِ مِنْ لُحُومِ الْإِبِلِ فَقَالَ تَوَضَّئُوا مِنْهَا وَسُئِلَ عَنْ الْوُضُوءِ مِنْ لُحُومِ الْغَنَمِ فَقَالَ لَا تَتَوَضَّئُوا مِنْهَاقَالَ وَفِي الْبَاب عَنْ جَابِرِ بْنِ سَمُرَةَ وَأُسَيْدِ بْنِ حُضَيْرٍ قَالَ أَبُو عِيسَى وَقَدْ رَوَى الْحَجَّاجُ بْنُ أَرْطَاةَ هَذَا الْحَدِيثَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أُسَيْدِ بْنِ حُضَيْرٍ وَالصَّحِيحُ حَدِيثُ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ بْنِ عَازِبٍ وَهُوَ قَوْلُ أَحْمَدَ وَإِسْحَقَ وَرَوَى عُبَيْدَةُ الضَّبِّيُّ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ الرَّازِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ ذِي الْغُرَّةِ الْجُهَنِيِّ وَرَوَى حَمَّادُ بْنُ سَلَمَةَ هَذَا الْحَدِيثَ عَنْ الْحَجَّاجِ بْنِ أَرْطَاةَ فَأَخْطَأَ فِيهِ وَقَالَ فِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِيهِ عَنْ أُسَيْدِ بْنِ حُضَيْرٍ وَالصَّحِيحُ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ الرَّازِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَ إِسْحَقُ صَحَّ فِي هَذَا الْبَابِ حَدِيثَانِ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثُ الْ��َرَاءِ وَحَدِيثُ جَابِرِ بْنِ سَمُرَةَ وَهُوَ قَوْلُ أَحْمَدَ وَإِسْحَقَ وَقَدْ رُوِيَ عَنْ بَعْضِ أَهْلِ الْعِلْمِ مِنْ التَّابِعِينَ وَغَيْرِهِمْ أَنَّهُمْ لَمْ يَرَوْا الْوُضُوءَ مِنْ لُحُومِ الْإِبِلِ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَأَهْلِ الْكُوفَةِ","id":"telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abdullah bin Abdullah Ar Razi] dari [Abdurrahman bin Abu Laila] dari [Al Barro` bin 'Azib] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang hukum wudlu karena maka daging unta, beliau menjawab: \"Berwudlulah karenanya.\" Lalu beliau ditanya tentang hukum wudlu karena makan daging kambing, beliau menjawab: \"Janganlah kalian berwudlu karenanya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Jabir bin Samurah dan Usaid bin Hudlair.\" Abu Isa berkata; \"Al Hajjaj bin Artha`ah telah meriwayatkan hadits ini dari Abdullah bin Abdullah, dari Abdurrahman bin Abu Laila, dari Usaid bin Hudlair. Tetapi yang benar adalah hadits Abdurrahman bin Abu Laila dari Al Bara` bin 'Azib. Ini adalah pendapat Ahmad dan Ishaq. Dan [Ubaidah Adl Dlabbi] meriwayatkan dari [Abdullah bin Abdullah Ar Razi], dari [Abdurrahman bin Abu Laila], dari [Dzul Ghurrah Al Juhanni]. Sedangkan Hammad bin Salamah meriwayatkan hadits ini dari Al Hajjaj bin Artha`ah, namun ia melakukan kesalahan dalam periwayatannya. Ia mengatakan; \"Abdullah bin Abdurrahman bin Abu Laila, dari bapaknya, dari Usaid bin Hudlair. Dan yang shahih adalah, dari Abdullah bin Abdullah Ar Razi, dari Abdurrahman bin Abu Laila, dari Al Bara` bin 'Azib. Ishaq berkata; \"Dalam bab ini ada dua hadits dari Rasulullah shallallahu 'alaihi wasallam yang shahih; yaitu hadits Barra` dan hadits Jabir bin Samurah.\" Ini pendapat Ahmad dan Ishaq. Dan telah diriwayatkan dari sebagian ahli ilmu dari kalangan tabi'in dan selainnya, mereka berpendapat bahwasanya tidak harus wudlu karena makan daging unta. Ini adalah pendapat Sufyan Ats Tsauri dan penduduk Kufah.\""},"77":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ هِشَامِ بْنِ عُرْوَةَ قَالَ أَخْبَرَنِي أَبِي عَنْ بُسْرَةَ بِنْتِ صَفْوَانَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ مَسَّ ذَكَرَهُ فَلَا يُصَلِّ حَتَّى يَتَوَضَّأَقَالَ وَفِي الْبَاب عَنْ أُمِّ حَبِيبَةَ وَأَبِي أَيُّوبَ وَأَبِي هُرَيْرَةَ وأَرْوَى ابْنَةِ أُنَيْسٍ وَعَائِشَةَ وَجَابِرٍ وَزَيْدِ بْنِ خَالِدٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ هَكَذَا رَوَاهُ غَيْرُ وَاحِدٍ مِثْلَ هَذَا عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ بُسْرَةَ وَرَوَى أَبُو أُسَامَةَ وَغَيْرُ وَاحِدٍ هَذَا الْحَدِيثَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ مَرْوَانَ عَنْ بُسْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ حَدَّثَنَا بِذَلِكَ إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا أَبُو أُسَامَةَ بِهَذَا وَرَوَى هَذَا الْحَدِيثَ أَبُو الزِّنَادِ عَنْ عُرْوَةَ عَنْ بُسْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا بِذَلِكَ عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ عُرْوَةَ عَنْ بُسْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَبِهِ يَقُولُ الْأَوْزَاعِيُّ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ قَالَ مُحَمَّدٌ وَأَصَحُّ شَيْءٍ فِي هَذَا الْبَابِ حَدِيثُ بُسْرَةَ و قَالَ أَبُو زُرْعَةَ حَدِيثُ أُمِّ حَبِيبَةَ فِي هَذَا الْبَابِ صَحِيحٌ وَهُوَ حَدِيثُ الْعَلَاءِ بْنِ الْحَارِثِ عَنْ مَكْحُولٍ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُمِّ حَبِيبَةَ و قَالَ مُحَمَّدٌ لَمْ يَسْمَعْ مَكْحُولٌ مِنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ وَرَوَى مَكْحُولٌ عَنْ رَجُلٍ عَنْ عَنْبَسَةَ غَيْرَ هَذَا الْحَدِيثِ وَكَأَنَّهُ لَمْ يَرَ هَذَا الْحَدِيثَ صَحِيحًا","id":"telah menceritakan kepada kami [Ishaq bin Manshur] berkata; telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dari [Hisyam bin Urwah] berkata; telah mengabarkan kepadaku [Bapakku] dari [Busrah binti Shafwan] bahwa Nabi shallallahu 'alaihi wasallam, beliau bersabda: \" Barangsiapa menyentuh kemaluannya maka janganlah shalat hingga ia berwudlu.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ummu Habibah, Abu Ayyub, Abu Hurairah, Arwa binti Unais, Aisyah, Jabir, Zaid bin Khalid dan Abdullah bin 'Amru. Abu Isa berkata; \"Hadits ini riwayatnya hasan shahih.\" Ia berkata; \"Demikianlah, tidak hanya satu yang meriwayatkan hadits ini, dari Hisyam bin Urwah, dari bapaknya, dari Busrah. Dan riwayat [Abu Usamah] juga tidak hanya satu yang meriwayatkan hadits ini, dari [Hisyam bin Urwah], dari [bapaknya], dari [Marwan], dari [Busrah], dari Nabi shallallahu 'alaihi wasallam. Dan telah meriwayatkan seperti itu pula Ishaq bin Manshur, ia berkata; \"Abu Usamah menceritakan kepada kami seperti ini.\" Dan hadits ini juga diriwayatkan oleh Abu Az Zinad, dari Urwah, dari Busrah, dari Nabi shallallahu 'alaihi wasallam. Seperti itu pula yang diriwayatkan kepada kami oleh [Ali bin Hujr]. Ia berkata; \"Telah menceritakan kepada kami [Abdurrahman bin Abu Az Zinad], dari [bapaknya], dari [Urwah], dari [Busrah], dari Nabi shallallahu 'alaihi wasallam seperti itu. Dan ini adalah pendapat tidak hanya seorang, dari para sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in. hal ini juga diambil oleh Al Auza'i, Syafi'i, Ahmad dan Ishaq.\" Muhammad berkata; \"Hadits yang paling shahih dalam bab ini adalah hadits Busrah.\" Dan Abu Zur'ah berkata; \"Dalam bab ini, hadits Ummu Habibah juga shahih, yaitu hadits Al 'Ala` Ibnul Harits, dari Makhul, dari 'Anbasah bin Abu Sufyan, dari Ummu Habibah.\" Muhammad berkata; \"Makhul belum pernah mendengar dari 'Anbasah bin Abu Sufyan.\" Sedangkan 'Anbasah meriwayatkan dari seorang laki-laki, dari 'Anbasah selain hadits ini, seakan-akan ia berpendapat bahwa hadits ini shahih.\""},"78":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا مُلَازِمُ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ بَدْرٍ عَنْ قَيْسِ بْنِ طَلْقِ بْنِ عَلِيٍّ هُوَ الْحَنَفِيُّ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَهَلْ هُوَ إِلَّا مُضْغَةٌ مِنْهُ أَوْ بَضْعَةٌ مِنْهُقَالَ وَفِي الْبَاب عَنْ أَبِي أُمَامَةَ قَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ غَيْرِ وَاحِدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَعْضِ التَّابِعِينَ أَنَّهُمْ لَمْ يَرَوْا الْوُضُوءَ مِنْ مَسِّ الذَّكَرِ وَهُوَ قَوْلُ أَهْلِ الْكُوفَةِ وَابْنِ الْمُبَارَكِ وَهَذَا الْحَدِيثُ أَحَسَنُ شَيْءٍ رُوِيَ فِي هَذَا الْبَابِ وَقَدْ رَوَى هَذَا الْحَدِيثَ أَيُّوبُ بْنُ عُتْبَةَ وَمُحَمَّدُ بْنُ جَابِرٍ عَنْ قَيْسِ بْنِ طَلْقٍ عَنْ أَبِيهِ وَقَدْ تَكَلَّمَ بَعْضُ أَهْلِ الْحَدِيثِ فِي مُحَمَّدِ بْنِ جَابِرٍ وَأَيُّوبَ بْنِ عُتْبَةَ وَحَدِيثُ مُلَازِمِ بْنِ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ بَدْرٍ أَصَحُّ وَأَحْسَنُ","id":"telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Mulazim bin 'Amru] dari [Abdullah bin Badr] dari [Qais bin Thalq bin Ali Al Hanafi], dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \" Kemaluan hanyalah segumpal atau sepotong daging dari seseorang.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Umamah.\" Abu Isa berkata; \"Diriwayatkan tidak hanya dari satu sahabat Nabi shallallahu 'alaihi wasallam dan sebagian tabi'in, mereka berpendapat bahwa tidak ada wudlu karena menyentuh kemaluan. Ini adalah pendapat yang diambil oleh penduduk Kufah dan Ibnul Mubarak.\" Dan hadits ini adalah sebaik-baik hadits yang diriwayatkan dalam bab ini. Hadits ini diriwayatkan oleh [Ayyub bin Utbah] dan [Muhammad bin Jabir] dari [Qais bin Thalq], dari [bapaknya]. Namun ada beberapa ulama yang masih memperbincangkan tentang Muhammad bin Jabir dan Ayyub bin Utbah. Dan hadits Mulazim bin Amru dari Abdullah bin Badr lebih shahih dan lebih baik.\""},"79":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَهَنَّادٌ وَأَبُو كُرَيْبٍ وَأَحْمَدُ بْنُ مَنِيعٍ وَمَحْمُودُ بْنُ غَيْلَانَ وَأَبُو عَمَّارٍ الْحُسَيْنُ بْنُ حُرَيْثٍ قَالُوا حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبَّلَ بَعْضَ نِسَائِهِ ثُمَّ خَرَجَ إِلَى الصَّلَاةِ وَلَمْ يَتَوَضَّأْقَالَ قُلْتُ مَنْ هِيَ إِلَّا أَنْتِ قَالَ فَضَحِكَتْ قَالَ أَبُو عِيسَى وَقَدْ رُوِيَ نَحْوُ هَذَا عَنْ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَأَهْلِ الْكُوفَةِ قَالُوا لَيْسَ فِي الْقُبْلَةِ وُضُوءٌ و قَالَ مَالِكُ بْنُ أَنَسٍ وَالْأَوْزَاعِيُّ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ فِي الْقُبْلَةِ وُضُوءٌ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَإِنَّمَا تَرَكَ أَصْحَابُنَا حَدِيثَ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا لِأَنَّهُ لَا يَصِحُّ عِنْدَهُمْ لِحَالِ الْإِسْنَادِ قَالَ و سَمِعْت أَبَا بَكْرٍ الْعَطَّارَ الْبَصْرِيَّ يَذْكُرُ عَنْ عَلِيِّ بْنِ الْمَدِينِيِّ قَالَ ضَعَّفَ يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ هَذَا الْحَدِيثَ جِدًّا وَقَالَ هُوَ شِبْهُ لَا شَيْءَ قَالَ و سَمِعْت مُحَمَّدَ بْنَ إِسْمَعِيلَ يُضَعِّفُ هَذَا الْحَدِيثَ و قَالَ حَبِيبُ بْنُ أَبِي ثَابِتٍ لَمْ يَسْمَعْ مِنْ عُرْوَةَ وَقَدْ رُوِيَ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ عَائِشَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبَّلَهَا وَلَمْ يَتَوَضَّأْ وَهَذَا لَا يَصِحُّ أَيْضًا وَلَا نَعْرِفُ لِإِبْرَاهِيمَ التَّيْمِيِّ سَمَاعًا مِنْ عَائِشَةَ وَلَيْسَ يَصِحُّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْبَابِ شَيْءٌ","id":"telah menceritakan kepada kami [Qutaibah] dan [Hannad] dan [Abu Kuraib] dan [Ahmad bin Muni'] dan [Mahmud bin Ghailan] dan [Abu 'Ammar Al Husain bin Huraits] mereka berkata; [Waki'] menceritakan kepada kami dari [Al A'masy] dari [Habib bin Abu Tsabit] dari [Urwah] dari [Aisyah] berkata; \" Nabi shallallahu 'alaihi wasallam mencium sebagian istrinya, setelah itu keluar shalat dan tidak berwudlu lagi.\" Urwah berkata; \"Itu pasti engkau sendiri, \" Urwah berkata; \"Lalu ia pun tertawa.\" Abu Isa berkata; \"Yang telah meriwayatkan hadits ini bukan hanya seorang dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in.\" pendapat ini diambil oleh Sufyan Ats Tsauri dan penduduk Kufah. Mereka mengatakan; \"Tidak ada kewajiban berwudlu karena mencium.\" Sedangkan Malik bin Anas, Al Auza'i, Syafi'i, Ahmad, dan Ishaq berpendapat; bahwa mencium itu mengharuskan wudlu. Pendapat ini diambil tidak hanya satu dari kalangan ahli ilmu dari sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in. Namun sahabat-sahabat kami meninggalkan hadits dari Aisyah karena menurut mereka lemah dari sisi sanad. Abu Isa berkata; \"Aku mendengar Abu Bakr Al Aththar Al Bashri menyebutkan dari Ali Ibnul Madini, ia berkata; \"Yahya bin Sa'id Al Qaththan melemahkan hadits ini. dan ia berkata, \"Itu sama dengan sesuatu yang tidak ada apa-apanya.\" Ia juga berkata; \"Aku mendengar Muhammad bin Isma'il melemahkan hadits ini, dan Habib bin Abu Tsabit belum pernah mendengar dari Urwah.\" Telah diriwayatkan dari [Ibrahim At Taimi], dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam pernah menciumnya dan beliau tidak berwudlu lagi. Namun hadits ini juga tidak sah. Kami tidak pernah mengetahui bahwa Ibrahim At Taimi pernah mendengar dari Aisyah. Tidak ada hadits yang shahih dari Nabi shallallahu 'alaihi wasallam dalam bab ini.\""},"80":{"ar":"حَدَّثَنَا أَبُو عُبَيْدَةَ بْنُ أَبِي السَّفَرِ وَهُوَ أَحْمَدُ بْنُ عَبْدِ اللَّهِ الْهَمْدَانِيُّ الْكُوفِيُّ وَإِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَبُو عُبَيْدَةَ حَدَّثَنَا وَقَالَ إِسْحَقُ أَخْبَرَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنِي أَبِي عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَمْرٍو الْأَوْزَاعِيُّ عَنْ يَعِيشَ بْنِ الْوَلِيدِ الْمَخ��زُومِيِّ عَنْ أَبِيهِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ عَنْ أَبِي الدَّرْدَاءِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاءَ فَأَفْطَرَ فَتَوَضَّأَفَلَقِيتُ ثَوْبَانَ فِي مَسْجِدِ دِمَشْقَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ صَدَقَ أَنَا صَبَبْتُ لَهُ وَضُوءَهُ قَالَ أَبُو عِيسَى و قَالَ إِسْحَقُ بْنُ مَنْصُورٍ مَعْدَانُ بْنُ طَلْحَةَ قَالَ أَبُو عِيسَى وَابْنُ أَبِي طَلْحَةَ أَصَحُّ قَالَ أَبُو عِيسَى وَقَدْ رَأَى غَيْرُ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ مِنْ التَّابِعِينَ الْوُضُوءَ مِنْ الْقَيْءِ وَالرُّعَافِ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَابْنِ الْمُبَارَكِ وَأَحْمَدَ وَإِسْحَقَ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ لَيْسَ فِي الْقَيْءِ وَالرُّعَافِ وُضُوءٌ وَهُوَ قَوْلُ مَالِكٍ وَالشَّافِعِيِّ وَقَدْ جَوَّدَ حُسَيْنٌ الْمُعَلِّمُ هَذَا الْحَدِيثَ وَحَدِيثُ حُسَيْنٍ أَصَحُّ شَيْءٍ فِي هَذَا الْبَابِ وَرَوَى مَعْمَرٌ هَذَا الْحَدِيثَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ فَأَخْطَأَ فِيهِ فَقَالَ عَنْ يَعِيشَ بْنِ الْوَلِيدِ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ أَبِي الدَّرْدَاءِ وَلَمْ يَذْكُرْ فِيهِ الْأَوْزَاعِيَّ وَقَالَ عَنْ خَالِدِ بْنِ مَعْدَانَ وَإِنَّمَا هُوَ مَعْدَانُ بْنُ أَبِي طَلْحَةَ","id":"telah menceritakan kepada kami [Abu Ubaidah bin Abu As Safar (yaitu) Ahmad bin Abdullah Al Hamdani Al Kufi]. Dan [Ishaq bin Manshur] berkata; telah menceritakan kepada kami [Abu Ubaidah], Ishaq berkata; telah mengabarkan kepada kami [Abdu Ashshamad bin Abdul Warits] berkata, telah menceritakan kepadaku [Bapakku] dari [Husain Al Mu'allim] dari [Yahya bin Abu Katsir] berkata; telah menceritakan kepadaku [Abdurrahman bin 'Amru Al Auza'i] dari [Ya'isy Ibnul Walid Al Makhzumi] dari [Bapaknya] dari [Ma'dan bin Abu Thalhah] dari [Abu Darda`] bahwa Rasulullah shallallahu 'alaihi wasallam muntah, lalu beliau berbuka dan berwudlu. Abu Darda' berkata; \"Lalu aku bertemu dengan [Tsauban] di masjid Damaskus, aku kabarkan hal itu kepadanya, maka ia pun berkata, \"Benar, bahkan akulah yang menuangkan air wudlu kepada beliau.\" Abu Isa berkata; Ishaq bin Manshur berkata; \"Ma'dan bin Thalhah.\" Abu Isa berkata; \"Sedangkan Ibnu Abu Thalhah lebih shahih.\" Abu Isa berkata; \"Tidak hanya satu orang ulama dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in yang berpendapat bahwa seseorang itu harus berwudlu karena muntah atau darah (mimisan). Pendapat ini diambil oleh Sufyan Ats Tsauri, Ibnul Mubarak, Ahmad dan Ishaq.\" Sedangkan sebagian ulama berpendapat bahwa seseorang tidak harus berwudlu karena muntah atau mimisan. Pendapat ini diambil oleh Malik dan Syafi'. Husain Al Mu'allim menganggap bahwa hadits ini baik. Dan hadits Husain adalah hadits yang paling baik dalam bab ini. Ma'mar meriwayatkan hadits ini dari Yahya bin Abu Katsir, namun ia salah di dalamnya. Ia berkata; \"Dari Ya`isy Ibnul Walid, dari Khalid bin Ma'dan, dari Abu Darda`, dan ia tidak menyebutkan di dalamnya nama Al Auza'i. Ia menyebutkan dari Khalid bin Ma'dan, padahal ia adalah Ma'dan bin Abu Thalhah.\""},"81":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي فَزَارَةَ عَنْ أَبِي زَيْدٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَسَأَلَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا فِي إِدَاوَتِكَ فَقُلْتُ نَبِيذٌ فَقَالَ تَمْرَةٌ طَيِّبَةٌ وَمَاءٌ طَهُورٌ قَالَ فَتَوَضَّأَ مِنْهُقَالَ أَبُو عِيسَى وَإِنَّمَا رُوِيَ هَذَا الْحَدِيثُ عَنْ أَبِي زَيْدٍ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو زَيْدٍ رَجُلٌ مَجْهُولٌ عِنْدَ أَهْلِ الْحَدِيثِ لَا تُعْرَفُ لَهُ رِوَايَةٌ غَيْرُ هَذَا الْحَدِيثِ وَقَدْ رَأَى بَعْضُ أَهْلِ الْعِلْمِ الْوُضُوءَ بِالنَّبِيذِ مِنْهُمْ سُفْيَانُ الثَّوْرِيُّ وَغَيْرُهُ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ لَا يُتَوَضَّأُ بِالنَّبِيذِ وَهُوَ قَوْلُ الشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ و قَالَ إِسْحَقُ إِنْ ابْتُلِيَ رَجُلٌ بِهَذَا فَتَوَضَّأَ بِالنَّبِيذِ وَتَيَمَّمَ أَحَبُّ إِلَيَّ قَالَ أَبُو عِيسَى وَقَوْلُ مَنْ يَقُولُ لَا يُتَوَضَّأُ بِالنَّبِيذِ أَقْرَبُ إِلَى الْكِتَابِ وَأَشْبَهُ لِأَنَّ اللَّهَ تَعَالَى قَالَ{ فَلَمْ تَجِدُوا مَاءً فَتَيَمَّمُوا صَعِيدًا طَيِّبًا }","id":"telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Syarik] dari [Abu Fazarah] dari [Abu Zaid] dari [Abdullah bin Mas'ud] ia berkata; \"Nabi shallallahu 'alaihi wasallam bertanya kepadaku: \"Apa yang ada di dalam embermu?\" Aku pun menjawab, \"Arak, \" beliau lalu bersabda: \" Kurma yang baik dan air yang suci, \" Ibnu Mas'ud berkata; \"Maka beliau pun berwudlu dengannya.\" Abu Isa berkata; \"Hanyasanya hadits ini diriwayatkan dari Abu Zaid dari Abdullah dari Nabi shallallahu 'alaihi wasallam. Sedangkan Abu Zaid adalah seorang yang belum dikenal oleh para ahli hadits. Dia tidak diketahui pernah meriwayatkan hadits kecuali hadits ini. Sebagian ahli ilmu berpandangan bahwa seseorang boleh berwudlu dengan nabidz (arak). Di antaranya adalah Sufyan Ats Tsauri dan selainnya. Dan sebagian yang lain berpandangan bahwa seseorang tidak boleh berwudlu dengan arak. Ini adalah pendapat Syafi'i, Ahmad dan Ishaq. Ishaq berkata; \"Jika seseorang diuji dengan ini, maka hendaklah ia berwudlu dengan arak, tetapi aku lebih suka jika ia bertayammum.\" Abu Isa berkata; Adapun perkataan seseorang; \"Tidak boleh berwudlu dengan arak, \" adalah lebih dekat dengan Al Qur`an dan lebih layak. Karena Allah Ta'ala berfirman, \"(lalu kamu tidak memperoleh air, maka bertayamumlah dengan tanah yang baik (bersih)).\""},"82":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَرِبَ لَبَنًا فَدَعَا بِمَاءٍ فَمَضْمَضَ وَقَالَ إِنَّ لَهُ دَسَمًاقَالَ وَفِي الْبَاب عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ وَأُمِّ سَلَمَةَ قَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَأَى بَعْضُ أَهْلِ الْعِلْمِ الْمَضْمَضَةَ مِنْ اللَّبَنِ وَهَذَا عِنْدَنَا عَلَى الِاسْتِحْبَابِ وَلَمْ يَرَ بَعْضُهُمْ الْمَضْمَضَةَ مِنْ اللَّبَنِ","id":"telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Az Zuhri] dari [Ubaidillah bin Abdullah] dari [Ibnu Abbas] berkata; \"Nabi shallallahu 'alaihi wasallam minum susu, lalu beliau minta diambilkan air seraya berkumur dengan air tersebut, setelah itu beliau bersabda: \"Sesungguhnya pada susu itu ada lemaknya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Sahl bin Sa'd As Sa'idi dan Ummu Salamah.\" Abu Isa berkata; \"Ini adalah hadits yang derajatnya hasan shahih, sebagian ahi ilmu berpandangan bahwa seseorang diharuskan berkumur dengan air setelah minum susu. Sedangkan menurut kami itu hanyalah sekedar disunahkan saja. Dan sebagian dari mereka bahkan tidak mengharuskan seseorang berkumur karena minum susu.\""},"83":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا أَبُو أَحْمَدَ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الزُّبَيْرِيُّ عَنْ سُفْيَانَ عَنْ الضَّحَّاكِ بْنِ عُثْمَانَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَجُلًا سَلَّمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَبُولُ فَلَمْ يَرُدَّ عَلَيْهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَإِنَّمَا يُكْرَهُ هَذَا عِنْدَنَا إِذَا كَانَ عَلَى الْغَائِطِ وَالْبَوْلِ وَقَدْ فَسَّرَ بَعْضُ أَهْلِ الْعِلْمِ ذَلِكَ وَهَذَا أَحَسَنُ شَيْءٍ رُوِيَ فِي هَذَا الْبَابِ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ الْمُهَاجِرِ بْنِ قُنْفُذٍ وَعَبْدِ اللَّهِ بْنِ حَنْظَلَةَ وَعَلْقَمَةَ بْنِ الْفَغْوَاءِ وَجَابِرٍ وَالْبَرَاءِ","id":"telah menceritakan kepada kami [Nashr bin Ali] dan [Muhammad bin Basysyar] keduanya berkata; telah menceritakan kepada kami [Abu Ahmad Muhammad bin Abdullah Az Zubair] dari [Sufyan] dari [Adl Dlahhak bin Utsman] dari [Nafi'] dari [Ibnu Umar] berkata; \"Ada seorang lelaki mengucapkan salam kepada Nabi shallallahu 'alaihi wasallam ketika Nabi sedang kencing, maka beliau pun tidak menjawabnya.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, hanyasannya hal ini (menjawab salam) menjadi makruh dikalangan kami apabila sedang buang air besar atau kencing, sebagaimana yang telah ditafsirkan oleh sebagian ahli Ilmu. Dan hadits ini adalah hadits yang paling baik yang diriwayatkan dalam bab ini. Abu Isa berkata; \"Dalam bab ini terdapat juga hadits dari Al Muhajir bin Qunfudz, Abdullah bin Hanzhalah, Alqamah bin Al Afra', Jabir dan Al Barra`.\""},"84":{"ar":"حَدَّثَنَا سَوَّارُ بْنُ عَبْدِ اللَّهِ الْعَنْبَرِيُّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ قَال سَمِعْتُ أَيُّوبَ يُحَدِّثُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ يُغْسَلُ الْإِنَاءُ إِذَا وَلَغَ فِيهِ الْكَلْبُ سَبْعَ مَرَّاتٍ أُولَاهُنَّ أَوْ أُخْرَاهُنَّ بِالتُّرَابِ وَإِذَا وَلَغَتْ فِيهِ الْهِرَّةُ غُسِلَ مَرَّةً قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ الشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا وَلَمْ يُذْكَرْ فِيهِ إِذَا وَلَغَتْ فِيهِ الْهِرَّةُ غُسِلَ مَرَّةً وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ","id":"telah menceritakan kepada kami [Sawwar bin Abdullah Al 'Anbari] berkata, telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] berkata; aku mendengar [Ayyub] menceritakan dari [Muhammad bin Sirin] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau bersabda: \" Jika bejana dijilat oleh anjing maka harus dicuci tujuh kali, yang salah satunya atau yang terakhir dengan tanah. Namun jika bejana tersebut dijilat oleh kucing cukup dicuci sekali.\" Abu Isa berkata; \"Hadits ini derajatnya adalah hasan shahih. Ini adalah pendapat Syafi'i, Ahmad dan Ishaq. Hadits ini juga dirwayatkan dengan jalur lain dari Abu Hurairah, dari Nabi shallallahu 'alaihi wasallam seperti ini. Hanya saja, tidak disebutkan di dalamnya, \"Jika bejana tersebut dijilat oleh kucing cukup dicuci sekali.\" Dalam bab ini juga ada riwayat dari Abdullah bin Mughaffal.\""},"85":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ حُمَيْدَةَ بِنْتِ عُبَيْدِ بْنِ رِفَاعَةَ عَنْ كَبْشَةَ بِنْتِ كَعْبِ بْنِ مَالِكٍ وَكَانَتْ عِنْدَ ابْنِ أَبِي قَتَادَةَ أَنَّ أَبَا قَتَادَةَ دَخَلَ عَلَيْهَا قَالَتْ فَسَكَبْتُ لَهُ وَضُوءًا قَالَتْ فَجَاءَتْ هِرَّةٌ تَشْرَبُ فَأَصْغَى لَهَا الْإِنَاءَ حَتَّى شَرِبَتْ قَالَتْ كَبْشَةُ فَرَآنِي أَنْظُرُ إِلَيْهِ فَقَالَ أَتَعْجَبِينَ يَا بِنْتَ أَخِي فَقُلْتُ نَعَمْ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّهَا لَيْسَتْ بِنَجَسٍ إِنَّمَا هِيَ مِنْ الطَّوَّافِينَ عَلَيْكُمْ أَوْ الطَّوَّافَاتِ وَقَدْ رَوَى بَعْضُهُمْ عَنْ مَالِكٍ وَكَانَتْ عِنْدَ أَبِي قَتَادَةَ وَالصَّحِيحُ ابْنُ أَبِي قَتَادَةَ قَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ أَكْثَرِ الْعُلَمَاءِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ مِثْلِ الشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ لَمْ يَرَوْا بِسُؤْرِ الْهِرَّةِ بَأْسًا وَهَذَا أَحَسَنُ شَيْءٍ رُوِيَ فِي هَذَا الْبَابِ وَقَدْ جَوَّدَ مَالِكٌ هَذَا الْحَدِيثَ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ وَلَمْ يَأْتِ بِهِ أَحَدٌ أَتَمَّ مِنْ مَالِكٍ","id":"telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] berkata, telah menceritakan kepada kami [Ma'n] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Humaid binti 'Ubaid bin Rifa'ah] dari [Kabsyah binti Ka'ab bin Malik] istri Ibnu Abu Qatadah, bahwa [Abu Qatadah] masuk menemuinya. (Kabsyah) berkata; \"Aku menuangkan air untuknya, tiba-tiba seekor kucing masuk dan meminumnya, Abu Qatadah kemudian memiringkan bejana tersebut hingga kucing tersebut dapat minum.\" Kabsyah berkata; \"Abu Qatadah tahu bahwa aku sedang memperhatikannya, maka ia pun berkata; \"Apakah engkau heran wahai putri saudaraku?\" aku menjawab, \"Ya, \" ia berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \" Kucing tidak najis. Ia merupakan hewan yang biasa berkeliaran di sekelilingmu.\" Dan sebagian mereka meriwayatkan dari Malik, ia (Kabsyah) adalah istri Abu Qatadah, namun yang benar bahwa ia adalah istri Ibnu Abu Qatadah. Ia berkata; \"Dalam bab ini juga ada riwayat dari Aisyah dan Abu Hurairah.\" Abu Isa berkata; \"Hadits ini derajatnya adalah hasan shahih, ini adalah pendapat kebanyakan ulama dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang setelah mereka seperti Syafi'i, Ahmad dan Ishaq. Mereka berpendapat bahwa sisa minum kucing tidak apa-apa. Dan ini adalah hadits yang paling baik dalam bab ini. Imam Malik menganggap baik hadits ini, yaitu dari Ishaq bin Abdullah bin Abu Thalhah. Dan tidak ada yangleb h sempurna dalam periwayatannya selain Malik.\""},"86":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامِ بْنِ الْحَارِثِ قَالَبَالَ جَرِيرُ بْنُ عَبْدِ اللَّهِ ثُمَّ تَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ فَقِيلَ لَهُ أَتَفْعَلُ هَذَا قَالَ وَمَا يَمْنَعُنِي وَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُهُقَالَ إِبْرَاهِيمُ وَكَانَ يُعْجِبُهُمْ حَدِيثُ جَرِيرٍ لِأَنَّ إِسْلَامَهُ كَانَ بَعْدَ نُزُولِ الْمَائِدَةِ هَذَا قَوْلُ إِبْرَاهِيمَ يَعْنِي كَانَ يُعْجِبُهُمْ قَالَ وَفِي الْبَاب عَنْ عُمَرَ وَعَلِيٍّ وَحُذَيْفَةَ وَالْمُغِيرَةِ وَبِلَالٍ وَسَعْدٍ وَأَبِي أَيُّوبَ وَسَلْمَانَ وَبُرَيْدَةَ وَعَمْرِو بْنِ أُمَيَّةَ وَأَنَسٍ وَسَهْلِ بْنِ سَعْدٍ وَيَعْلَى بْنِ مُرَّةَ وَعُبَادَةَ بْنِ الصَّامِتِ وَأُسَامَةَ بْنِ شَرِيكٍ وَأَبِي أُمَامَةِ وَجَابِرٍ وَأُسَامَةَ بْنِ زَيْدٍ وَابْنِ عُبَادَةَ وَيُقَالُ ابْنُ عِمَارَةَ وَأُبَيُّ بْنُ عِمَارَةَ قَالَ أَبُو عِيسَى وَحَدِيثُ جَرِيرٍ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Ibrahim] dari [Hammam Ibnul Harits] ia berkata; [Jarir bin Abdullah] buang air kecil, lalu berwudlu dan mengusap keduan khufnya. Lalu dikatakan kepadanya, \"kenapa engkau melakukan ini?\" ia berkata; \"Apa yang menghalangiku untuk melakukan ini? aku pernah melihat Rasulullah shallallahu 'alaihi wasallam melakukannya.\" Ibrahim berkata; \"Hadits Jarir ini membuat orang-orang merasa ta'ajub, karena Jarir masuk Islam setelah turunnya surat Al Maidah.\" Ini adalah perkataan Ibrahim, yakni perkataan, \"Hadits ini membuat orang-orang merasa ta'ajub.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Umar, Ali, Hudzaifah, Al Mughirah, Bilal, Sa'd, Abu Ayyub, Salman, Buraidah, 'Amru bin Umayyah, Anas, Sahl bin Sa'd, Ya'la bin Murrah, Ubadah Ibnu Shamid, Usamah bin Syarik, Abu Umamah, Jabir, Usamah bin Zaid dan Ibnu Ubadah, ada juga yang mengatakan, Ibnu Umarah dan Ubai bin Imarah.\" Abu Isa berkata; \"Hadits Jarir ini derajatnya adalah hasan shahih.\""},"87":{"ar":"وَيُرْوَى عَنْ شَهْرِ بْنِ حَوْشَبٍ قَالَرَأَيْتُ جَرِيرَ بْنَ عَبْدِ اللَّهِ تَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ فَقُلْتُ لَهُ فِي ذَلِكَ فَقَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ فَقُلْتُ لَهُ أَقَبْلَ الْمَائِدَةِ أَمْ بَعْدَ الْمَائِدَةِ فَقَالَ مَا أَسْلَمْتُ إِلَّا بَعْدَ الْمَائِدَةِحَدَّثَنَا بِذَلِكَ قُتَيْبَةُ حَدَّثَنَا خَالِدُ بْنُ زِيَادٍ التِّرْمِذِيُّ عَنْ مُقَاتِلِ بْنِ حَيَّانَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ جَرِيرٍ قَالَ وَرَوَى بَقِيَّةُ عَنْ إِبْرَاهِيمَ بْنِ أَدْهَمَ عَنْ مُقَاتِلِ بْنِ حَيَّانَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ جَرِيرٍ وَهَذَا حَدِيثٌ مُفَسَّرٌ لِأَنَّ بَعْضَ مَنْ أَنْكَرَ الْمَسْحَ عَلَى الْخُفَّيْنِ تَأَوَّلَ أَنَّ مَسْحَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْخُفَّيْنِ كَانَ قَبْلَ نُزُولِ الْمَائِدَةِ وَذَكَرَ جَرِيرٌ فِي حَدِيثِهِ أَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ عَلَى الْخُفَّيْنِ بَعْدَ نُزُولِ الْمَائِدَةِ","id":"Diriwayatkan dari [Syahr bin Hausyab], ia berkata; \"Aku melihat [Jarir bin Abdullah] berwudlu, lalu ia mengusap sepasang khufnya. Maka aku pun bertanya kepadanya tentang hal itu, ia menjawab, \"Aku melihat Nabi shallallahu 'alaihi wasallam berwudlu lalu mengusap kedua khufnya.\" Maka aku pun bertanya kepadanya, \"Apakah itu sebelum turunnya surat Al Maidah atau sesudahnya?\" Ia menjawab, \"Aku belum masuk Islam kecuali setelah turunnya surat Al Maidah.\" [Qutaibah] menceritakan hal itu kepada kami, ia berkata; \"Telah menceritakan kepada kami [Khalid bin Ziyad At Tirmidzi], dari [Muqatil bin Hayyan], dari [Syahr bin Hausyab], dari [Jarir].\" Perawi berkata; \" [Baqiyyah] meriwayatkan dari [Ibrahim bin Adham], dari [Muqatil bin Hayyan], dari [Syahr bin Hausyab], dari [Jarir]. Dan ini adalah hadits yang telah jelas, karena sebagian orang yang mengingkari tentang mengusap khuf mentakwilkan bahwa Nabi shallallahu 'alaihi wasallam mengusap khuf sebelum turunnya surat Al Maidah. Dan Jarir menyebutkan dalam haditsnya bahwa ia melihat Nabi shallallahu 'alaihi wasallam mengusap khufnya setelah turunnya surat Al Maidah.\""},"88":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ أَبِي عَبْدِ اللَّهِ الْجَدَلِيِّ عَنْ خُزَيْمَةَ بْنِ ثَابِتٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سُئِلَ عَنْ الْمَسْحِ عَلَى الْخُفَّيْنِ فَقَالَ لِلْمُسَافِرِ ثَلَاثَةٌ وَلِلْمُقِيمِ يَوْمٌ وَذُكِرَ عَنْ يَحْيَى بْنِ مَعِينٍ أَنَّهُ صَحَّحَ حَدِيثَ خُزَيْمَةَ بْنِ ثَابِتٍ فِي الْمَسْحِ وَأَبُو عَبْدِ اللَّهِ الْجَدَلِيُّ اسْمُهُ عَبْدُ بْنُ عَبْدٍ وَيُقَالُ عَبْدُ الرَّحْمَنِ بْنُ عَبْدٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ عَلِيٍّ وَأَبِي بَكْرَةَ وَأَبِي هُرَيْرَةَ وَصَفْوَانَ بْنِ عَسَّالٍ وَعَوْفِ بْنِ مَالِكٍ وَابْنِ عُمَرَ وَجَرِيرٍ","id":"telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Abu 'Awanah] dari [Sa'id bin Masruq] dari [Ibrahim At Taimi] dari ['Amru bin Maimun] dari [Abu Abdullah Al Jadali] dari [Khuzaimah bin Tsabit] dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau ditanya tentang mengusap sepasang khuf, beliau bersabda: \"Tiga hari bagi orang yang dalam perjalanan dan satu hari untuk yang tinggal di rumah.\" Disebutkan pula dari Yahya bin Ma'in bahwasanya ia menshahihkan hadits Khuzaimah bin Tsabit mengenai mengusap khuf. Dan Abu Abdullah Al Jadali namanya adalah Abd bin Abd, biasa dipanggil Abdurrahman bin Abd. Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, dalam bab ini juga ada riwayat dari Ali, Abu Bakrah, Abu Hurairah, Shafwan bin Assal, Auf bin Malik, Ibnu Umar dan Jarir.\""},"89":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ عَاصِمِ بْنِ أَبِي النَّجُودِ عَنْ زِرِّ بْنِ حُبَيْشٍ عَنْ صَفْوَانَ بْنِ عَسَّالٍ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا إِذَا كُنَّا سَفَرًا أَنْ لَا نَنْزِعَ خِفَافَنَا ثَلَاثَةَ أَيَّامٍ وَلَيَالِيهِنَّ إِلَّا مِنْ جَنَابَةٍ وَلَكِنْ مِنْ غَائِطٍ وَبَوْلٍ وَنَوْمٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَى الْحَكَمُ بْنُ عُتَيْبَةَ وَحَمَّادٌ عَنْ إِبْرَاهِيمَ النَّخَعِيِّ عَنْ أَبِي عَبْدِ اللَّهِ الْجَدَلِيِّ عَنْ خُزَيْمَةَ بْنِ ثَابِتٍ وَلَا يَصِحُّ قَالَ عَلِيُّ بْنُ الْمَدِينِيِّ قَالَ يَحْيَى بْنُ سَعِيدٍ قَالَ شُعْبَةُ لَمْ يَسْمَعْ إِبْرَاهِيمُ النَّخَعِيُّ مِنْ أَبِي عَبْدِ اللَّهِ الْجَدَلِيِّ حَدِيثَ الْمَسْحِ و قَالَ زَائِدَةُ عَنْ مَنْصُورٍ كُنَّا فِي حُجْرَةِ إِبْرَاهِيمَ التَّيْمِيِّ وَمَعَنَا إِبْرَاهِيمُ النَّخَعِيُّ فَحَدَّثَنَا إِبْرَاهِيمُ التَّيْمِيُّ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ أَبِي عَبْدِ اللَّهِ الْجَدَلِيِّ عَنْ خُزَيْمَةَ بْنِ ثَابِتٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْحِ عَلَى الْخُفَّيْنِ قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ أَحْسَنُ شَيْءٍ فِي هَذَا الْبَابِ حَدِيثُ صَفْوَانَ بْنِ عَسَّالٍ الْمُرَادِيِّ قَالَ أَبُو عِيسَى وَهُوَ قَوْلُ أَكْثَرِ الْعُلَمَاءِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ مِنْ الْفُقَهَاءِ مِثْلِ سُفْيَانَ الثَّوْرِيِّ وَابْنِ الْمُبَارَكِ وَالشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ قَالُوا يَمْسَحُ الْمُقِيمُ يَوْمًا وَلَيْلَةً وَالْمُسَافِرُ ثَلَاثَةَ أَيَّامٍ وَلَيَالِيهِنَّ قَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ بَعْضِ أَهْلِ الْعِلْمِ أَنَّهُمْ لَمْ يُوَقِّتُوا فِي الْمَسْحِ عَلَى الْخُفَّيْنِ وَهُوَ قَوْلُ مَالِكِ بْنِ أَنَسٍ قَالَ أَبُو عِيسَى وَالتَّوْقِيتُ أَصَحُّ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ صَفْوَانَ بْنِ عَسَّالٍ أَيْضًا مِنْ غَيْرِ حَدِيثِ عَاصِمٍ","id":"telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari ['Ashim bin Abu An Nujud] dari [Zirr bin Hubaisy] dari [Shafwan bin 'Assal] ia berkata; \" Jika kami sedang bepergian, Rasulullah shallallahu 'alaihi wasallam memerintahkan agar kami tidak membukanya selama tiga hari tiga malam kecuali ketika kami junub. Dan tetap boleh untuk mengusapkan karena buang air besar, buang air kecil dan tidur.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Al Hakam bin Utbah dan Hammad meriwayatkan hadits ini dari Ibrahim An Nakha'i, dari Abu Abdullah Al Jadali, dari Khuzaimah bin Tsabit, namun ini tidak shahih.\" Ali Ibnul Madini berkata; \"Yahya bin Sa'id mengatakan bahwa Syu'bah berkata; \"Ibrahim An Nakha'i belum pernah mendengar dari Abu Abdullah Al Jadali tentang hadits mengusap khuf.\" Za'idah berkata dari Manshur, \"Kami pernah di kamar Ibrahim At Taimi, sedang waktu itu kami bersama Ibrahim An Nakha'i, lalu Ibrahim At Taimi menceritakan kepada kami dari 'Amru bin Maimun, dari Abu Abdullah Al Jadali, dari Khuzaimah bin Tsabit, dari Nabi shallallahu 'alaihi wasallam tentang hadits mengusap dua khuf.\" Muhammad bin Isma'il berkata; \"Dalam bab ini hadits yang paling baik adalah hadits riwayat Shafwan bin 'Assal Al Muradi.\" Abu Isa berkata; \"Ini adalah pendapat kebanyak ulama dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang setelah mereka dari kalangan fuqaha. Seperti Sufyan Ats Tsauri, Ibnul Mubarak, Syafi'i, Ahmad dan Ishaq. Mereka berkata; \"Orang yang tinggal di rumah mengusap khuf selama sehari semalam dan orang yang dalam perjalanan mengusap selama tiga hari tiga malam.\" Abu Isa berkata; \"Diriwayatkan pula dari sebagian ahli ilmu bahwa mereka tidak memberikan batasan waktu dalam mengusap sepasang khuf. Pendapat ini dipegang oleh Malik bin Anas.\" Abu Isa berkata lagi, \"Pendapat yang memberikan batasan waktu adalah lebih shahih.\" Hadits ini juga diriwayatkan oleh Shafwan bin 'Assal, selain dari hadits 'Ashim.\""},"90":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ أَخْبَرَنِي ثَوْرُ بْنُ يَزِيدَ عَنْ رَجَاءِ بْنِ حَيْوَةَ عَنْ كَاتِبِ الْمُغِيرَةِ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ أَعْلَى الْخُفِّ وَأَسْفَلَهُ قَالَ أَبُو عِيسَى وَهَذَا قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ مِنْ الْفُقَهَاءِ وَبِهِ يَقُولُ مَالِكٌ وَالشَّافِعِيُّ وَإِسْحَقُ وَهَذَا حَدِيثٌ مَعْلُولٌ لَمْ يُسْنِدْهُ عَنْ ثَوْرِ بْنِ يَزِيدَ غَيْرُ الْوَلِيدِ بْنِ مُسْلِمٍ قَالَ أَبُو عِيسَى وَسَأَلْتُ أَبَا زُرْعَةَ وَمُحَمَّدَ بْنَ إِسْمَعِيلَ عَنْ هَذَا الْحَدِيثِ فَقَالَا لَيْسَ بِصَحِيحٍ لِأَنَّ ابْنَ الْمُبَارَكِ رَوَى هَذَا عَنْ ثَوْرٍ عَنْ رَجَاءِ بْنِ ح��يْوَةَ قَالَ حُدِّثْتُ عَنْ كَاتِبِ الْمُغِيرَةِ مُرْسَلٌ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يُذْكَرْ فِيهِ الْمُغِيرَةُ","id":"telah menceritakan kepada kami [Abul Walid Ad Dimasqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah mengabarkan kepadaku [Tsaur bin Yazid] dari [Raja` bin Haiwah] dari [Juru tulis Al Mughirah] dari [Al Mughirah bin Syu'bah] berkata; \"Nabi shallallahu 'alaihi wasallam mengusap bagian atas dan bawah khufnya.\" Abu Isa berkata, \"Ini pendapat tidak hanya seorang dari sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang setelah mereka dari kalangan fuqaha. Pendapat ini juga diambil oleh Malik, Syafi'i dan Ishaq. Ini adalah hadits yang bermasalah, tidak ada yang menyandarkan kepada Tsaur bin Yazid selain Al Walid bin Muslim. Abu Isa berkata; \"Aku bertanya kepada Abu Zur'ah dan Muhammad bin Isma'il tentang hadits ini, keduanya menjawab, \"Hadits ini tidak shahih, sebab Ibnul Mubarak meriwayatkan hadits ini dari Tsaur, dari Raja` bin Haiwah.\" Ia berkata; \"diceritakan kepadaku dari juru tulis Al Mughirah secara mursal, dari Nabi shallallahu 'alaihi wasallam, dan tidak disebutkan di dalamnya Al Mughirah.\""},"91":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ عَلَى الْخُفَّيْنِ عَلَى ظَاهِرِهِمَاقَالَ أَبُو عِيسَى حَدِيثُ الْمُغِيرَةِ حَدِيثٌ حَسَنٌ وَهُوَ حَدِيثُ عَبْدِ الرَّحْمَنِ بْنِ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ عُرْوَةَ عَنْ الْمُغِيرَةِ وَلَا نَعْلَمُ أَحَدًا يَذْكُرُ عَنْ عُرْوَةَ عَنْ الْمُغِيرَةِ عَلَى ظَاهِرِهِمَا غَيْرَهُ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَأَحْمَدُ قَالَ مُحَمَّدٌ وَكَانَ مَالِكُ بْنُ أَنَسٍ يُشِيرُ بِعَبْدِ الرَّحْمَنِ بْنِ أَبِي الزِّنَادِ","id":"telah menceritakan kepada kami [Ali bin Hujr] berkata; telah menceritakan kepada kami [Abdurrahman bin Abu Az Zinad] dari [Bapaknya] dari [Urwah bin Az Zubair] dari [Al Mughirah bin Syu'bah] ia berkata; \" Aku melihat Nabi shallallahu 'alaihi wasallam mengusap bagian atas kedua khufnya.\" Abu Isa berkata; \"Hadits Al Mughirah ini derajatnya hasan, yaitu hadits Abdurrahman bin Abu Az Zinad, dari bapaknya, dari Urwah, dari Al Mughirah. Dan kami tidak pernah mengetahui ada seseorang yang menyebutkan dari Urwah dari Al Mughirah tentang lafadz, \"pada bagian atas kedua khufnya, \" selain dia. Ini adalah pendapat kebanyakan ahli ilmu. Pendapat ini juga diambil oleh Sufyan Ats Tsauri dan Ahmad. Muhammad berkata; \"Malik bin Anas memberi isyarat kepada Abdurrahman bin Abu Az Zinad.\""},"92":{"ar":"حَدَّثَنَا هَنَّادٌ وَمَحْمُودُ بْنُ غَيْلَانَ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي قَيْسٍ عَنْ هُزَيْلِ بْنِ شُرَحْبِيلَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَتَوَضَّأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَسَحَ عَلَى الْجَوْرَبَيْنِ وَالنَّعْلَيْنِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ قَالُوا يَمْسَحُ عَلَى الْجَوْرَبَيْنِ وَإِنْ لَمْ تَكُنْ نَعْلَيْنِ إِذَا كَانَا ثَخِينَيْنِ قَالَ وَفِي الْبَاب عَنْ أَبِي مُوسَى قَالَ أَبُو عِيسَى سَمِعْت صَالِحَ بْنَ مُحَمَّدٍ التِّرْمِذِيَّ قَال سَمِعْتُ أَبَا مُقَاتِلٍ السَّمَرْقَنْدِيَّ يَقُولُ دَخَلْتُ عَلَى أَبِي حَنِيفَةَ فِي مَرَضِهِ الَّذِي مَاتَ فِيهِ فَدَعَا بِمَاءٍ فَتَوَضَّأَ وَعَلَيْهِ جَوْرَبَانِ فَمَسْحَ عَلَيْهِمَا ثُمَّ قَالَ فَعَلْتُ الْيَوْمَ شَيْئًا لَمْ أَكُنْ أَفْعَلُهُ مَسَحْتُ عَلَى الْجَوْرَبَيْنِ وَهُمَا غَيْرُ مُنَعَّلَيْنِ","id":"telah menceritakan kepada kami [Hannad] dan [Mahmud bin Ghailan] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Qais] dari [Huzail bin Syurahbil] dari [Al Mughirah bin Syu'bah] ia berkata; \"Nabi shallallahu 'alaihi wasallam berwudlu, mengusap kedua kaus kaki dan kedua sandalnya.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, dan ini adalah pendapat tidak sedikit dari ahli ilmu. Pendapat ini juga diambil oleh Sufyan Ats Tsauri, Ibnul Mubarak, Syafi'i, Ahmad dan Ishaq. Mereka mengatakan; \"Seseorang boleh mengusap kedua kaus kaki walaupun bukan sandal jika keduanya tebal.\" Abu Isa berkata; \"Dalam bab ini ada juga hadits yang diriwayatkan oleh Abu Musa.\" Abu Isa berkata; \"Aku mendengar Shalih bin Muhammad At Tirmidzi berkata; \"Aku mendengar Abu Muqatil As Samarqandi berkata; \"Aku datang menemui Abu Hanifah ketika sakit menjelang kematiannya, ia minta untuk diambilkan air, lalu ia berwudlu dalam keadaan memakai kaus kaki. Setelah itu ia mengusap keduanya seraya berkata; \"Hari ini aku melakukan sesuatu yang belum pernah aku lakukan, aku mengusap kedua kaus kaki, padahal keduanya bukan sandal.\""},"93":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ الْمُزَنِيِّ عَنْ الْحَسَنِ عَنْ ابْنِ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ أَبِيهِ قَالَتَوَضَّأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَسَحَ عَلَى الْخُفَّيْنِ وَالْعِمَامَةِقَالَ بَكْرٌ وَقَدْ سَمِعْتُهُ مِنَ ابْنِ الْمُغِيرَةِ قَالَ وَذَكَرَ مُحَمَّدُ بْنُ بَشَّارٍ فِي هَذَا الْحَدِيثِ فِي مَوْضِعٍ آخَرَ أَنَّهُ مَسَحَ عَلَى نَاصِيَتِهِ وَعِمَامَتِهِ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ ذَكَرَ بَعْضُهُمْ الْمَسْحَ عَلَى النَّاصِيَةِ وَالْعِمَامَةِ وَلَمْ يَذْكُرْ بَعْضُهُمْ النَّاصِيَةَ و سَمِعْت أَحْمَدَ بْنَ الْحَسَنِ يَقُولُ سَمِعْتُ أَحْمَدَ بْنَ حَنْبَلٍ يَقُولُ مَا رَأَيْتُ بِعَيْنِي مِثْلَ يَحْيَى بْنِ سَعِيدٍ الْقَطَّانِ قَالَ وَفِي الْبَاب عَنْ عَمْرِو بْنِ أُمَيَّةِ وَسَلْمَانَ وَثَوْبَانَ وَأَبِي أُمَامَةَ قَالَ أَبُو عِيسَى حَدِيثُ الْمُغِيرَةِ بْنِ شُعْبَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ أَبُو بَكْرٍ وَعُمَرُ وَأَنَسٌ وَبِهِ يَقُولُ الْأَوْزَاعِيُّ وَأَحْمَدُ وَإِسْحَقُ قَالُوا يَمْسَحُ عَلَى الْعِمَامَةِ و قَالَ غَيْرُ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ لَا يَمْسَحُ عَلَى الْعِمَامَةِ إِلَّا بِرَأْسِهِ مَعَ الْعِمَامَةِ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَمَالِكِ بْنِ أَنَسٍ وَابْنِ الْمُبَارَكِ وَالشَّافِعِيِّ قَالَ أَبُو عِيسَى و سَمِعْت الْجَارُودَ بْنَ مُعَاذٍ يَقُولُ سَمِعْتُ وَكِيعَ بْنَ الْجَرَّاحِ يَقُولُ إِنْ مَسَحَ عَلَى الْعِمَامَةِ يُجْزِئُهُ لِلْأَثَرِ","id":"telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dari [Sulaiman At Taimi] dari [Bakr bin Abdullah Al Muzani] dari [Al Hasan] dari [Ibnul Mughirah bin Syu'bah] dari [Bapaknya] ia berkata; \"Nabi shallallahu 'alaihi wasallam berwudlu, dan beliau mengusap khuf dan imamah (semacam surban yang diikatkan pada kepala).\" [Bakr] berkata; \"Aku telah mendengarnya dari [Ibnul Mughirah]. Perawi berkata; \"Muhammad bin Basysyar menyebutkan tentang hadits ini di tempat lain, bahwa beliau mengusap ubun-ubun dan surbannya.\" Hadits ini juga diriwayatkan dari jalur lain, dari Al Mughirah bin Syu'bah. Sebagian mereka menyebutkan lafadz; \"mengusap ubun-ubun serta surbannya\", sedang yang sebagian tidak menyebutkannya. Dan aku mendengar Ahmad Ibnul Hasan berkata; Aku mendengar Ahmad bin Hanbal berkata; \"Aku tidak pernah melihat seseorang semisal Yahya bin Sa'id Al Qaththan dengan kedua mataku.\" Perawi berkata, \"Dalam bab ini juga ada riwayat dari Amru bin Umayyah, Salman, Tsauban dan Abu Umamah.\" Abu Isa berkata; \"Hadits Al Mughirah bin Syu'bah derajatnya hasan shahih, pendapat ini banyak diambil oleh banyak ulama dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, seperti Abu Bakar, Umar dan Anas.\" Pendapat ini juga dipegang oleh Al Auza'i, Ahmad dan Ishaq. Mereka berkata; \"Seseorang boleh mengusap surbannya.\" Dan banyak ulama dari para sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in mengatakan; \"Seseorang tidak boleh mengusap surbannya kecuali jika ia mengusap kepala dan surbannya.\" Ini adalah pendapat Sufyan Ats Tsauri, Malik bin Anas, Ibnul Mubarak dan Syafri'i. Abu Isa berkata; Aku mendengar Al Jarud bin Mu'adz berkata; Aku mendengar Waki' Ibnul Jarrah berkata; \"Jika ia hanya mengusap surbannya maka itu sudah mencukupinya, karena itu adalah sunnah.\""},"94":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ عَنْ بِلَالٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ عَلَى الْخُفَّيْنِ وَالْخِمَارِ","id":"telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Ali bin Mushir] dari [Al A'masy] dari [Al Hakam] dari [Abdurrahman bin Abu Laila] dari [Ka'ab bin Ujrah] dari [Bilal] berkata; \" Nabi shallallahu 'alaihi wasallam mengusap sepasang khuf dan serban.\""},"95":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ هُوَ الْقُرَشِيُّ عَنْ أَبِي عُبَيْدَةَ بْنِ مُحَمَّدِ بْنِ عَمَّارِ بْنِ يَاسِرٍ قَالَسَأَلْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ عَنْ الْمَسْحِ عَلَى الْخُفَّيْنِ فَقَالَ السُّنَّةُ يَا ابْنَ أَخِي قَالَ وَسَأَلْتُهُ عَنْ الْمَسْحِ عَلَى الْعِمَامَةِ فَقَالَ أَمِسَّ الشَّعَرَ الْمَاءَ","id":"telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Bisyr bin Al Mufaddlal] dari [Abdurrahman bin Ishaq Al Qurasyi], dari [Abu Ubaidah bin Muhammad bin 'Ammar bin Yasir] ia berkata; \"Aku pernah bertanya kepada [Jabir bin Abdullah] tentang mengusap kedua khuf, lalu dia menjawab, \"Itu adalah sunnah wahai anak saudaraku.\" berkata; Dan aku juga bertanya kepadanya tentang mengusap Imamah, maka ia menjawab, \"Usaplah rambut dengan air.\""},"96":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ عَنْ خَالَتِهِ مَيْمُونَةَ قَالَتْ وَضَعْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُسْلًا فَاغْتَسَلَ مِنْ الْجَنَابَةِ فَأَكْفَأَ الْإِنَاءَ بِشِمَالِهِ عَلَى يَمِينِهِ فَغَسَلَ كَفَّيْهِ ثُمَّ أَدْخَلَ يَدَهُ فِي الْإِنَاءِ فَأَفَاضَ عَلَى فَرْجِهِ ثُمَّ دَلَكَ بِيَدِهِ الْحَائِطَ أَوْ الْأَرْضَ ثُمَّ مَضْمَضَ وَاسْتَنْشَقَ وَغَسَلَ وَجْهَهُ وَذِرَاعَيْهِ ثُمَّ أَفَاضَ عَلَى رَأْسِهِ ثَلَاثًا ثُمَّ أَفَاضَ عَلَى سَائِرِ جَسَدِهِ ثُمَّ تَنَحَّى فَغَسَلَ رِجْلَيْهِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ أُمِّ سَلَمَةَ وَجَابِرٍ وَأَبِي سَعِيدٍ وَجُبَيْرِ بْنِ مُطْعِمٍ وَأَبِي هُرَيْرَةَ","id":"telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Salim bin Abu Al Ju'd] dari [Kuraib] dari [Ibnu Abbas] dari bibinya - [Maimunah] - ia berkata; \" Aku meletakkan air mandi untuk Nabi shallallahu 'alaihi wasallam, lalu beliau mandi junub dengannya. Beliau memiringkan bejana dengan tangan kirinya pada tangan kanan, lalu beliau mencuci kedua telapak tangannya. Setelah itu beliau memasukkan tangannya ke dalam bejana, menyiram kemaluan dengan air dan menggosokkan tangannya ke dinding atau tanah. Kemudian beliau berkumur dan memasukkan air ke dalam lubang hidung, membasuh muka dan kedua lengan sikunya. Lalu mengalirkan air ke atas kepalanya tiga kali, mengalirkan air ke seluruh tubuhnya, lalu menjauh dan membasuh kedua kakinya.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, dan dalam bab ini juga ada riwayat dari Ummu Salamah, Jabir, Abu Sa'id, Jubair bin Muth'im dan Abu Hurairah.\""},"97":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَغْتَسِلَ مِنْ الْجَنَابَةِ بَدَأَ فَغَسَلَ يَدَيْهِ قَبْلَ أَنْ يُدْخِلَهُمَا الْإِنَاءَ ثُمَّ غَسَلَ فَرْجَهُ وَيَتَوَضَّأُ وُضُوءَهُ لِلصَّلَاةِ ثُمَّ يُشَرِّبُ شَعْرَهُ الْمَاءَ ثُمَّ يَحْثِي عَلَى رَأْسِهِ ثَلَاثَ حَثَيَاتٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ الَّذِي اخْتَارَهُ أَهْلُ الْعِلْمِ فِي الْغُسْلِ مِنْ الْجَنَابَةِ أَنَّهُ يَتَوَضَّأُ وُضُوءَهُ لِلصَّلَاةِ ثُمَّ يُفْرِغُ عَلَى رَأْسِهِ ثَلَاثَ مَرَّاتٍ ثُمَّ يُفِيضُ الْمَاءَ عَلَى سَائِرِ جَسَدِهِ ثُمَّ يَغْسِلُ قَدَمَيْهِ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ وَقَالُوا إِنْ انْغَمَسَ الْجُنُبُ فِي الْمَاءِ وَلَمْ يَتَوَضَّأْ أَجْزَأَهُ وَهُوَ قَوْلُ الشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ","id":"telah menceritakan kepada kami [Ibnu Abu Umar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] ia berkata; \" Jika Rasulullah shallallahu 'alaihi wasallam akan mandi junub, beliau mencuci kedua tangannya terlebih dahulu sebelum memasukkan tangannya ke dalam bejana. Setelah itu beliau mencuci kemaluannya, berwudlu sebagaimana wudlu untuk shalat dan menyela-nyela rambut dengan air. Setelah itu beliau menyiramkan tiga siraman ke atas kepalanya.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, dan hadits inilah yang dipilih oleh para ahli ilmu dalam hal mandi junub. Bahwa seseorang hendaknya berwudlu sebagaimana wudlu shalat, kemudian menuangkan tiga siraman ke atas kepalanya. Setelah itu mengalirkan air ke seluruh tubuh dan membasuh kedua kakinya.\" Ahli ilmu mengamalkan hadits ini, mereka mengatakan; \"Jika seseorang yang junub membenamkan diri dalam air meskipun tidak berwudlu maka itu telah mencukupi.\" Ini adalah pendapat Syafi'i, Ahmad dan Ishaq.\" "},"98":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ رَافِعٍ عَنْ أُمِّ سَلَمَةَ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي امْرَأَةٌ أَشُدُّ ضَفْرَ رَأْسِي أَفَأَنْقُضُهُ لِغُسْلِ الْجَنَابَةِ قَالَ لَا إِنَّمَا يَكْفِيكِ أَنْ تَحْثِينَ عَلَى رَأْسِكِ ثَلَاثَ حَثَيَاتٍ مِنْ مَاءٍ ثُمَّ تُفِيضِينَ عَلَى سَائِرِ جَسَدِكِ الْمَاءَ فَتَطْهُرِينَ أَوْ قَالَ فَإِذَا أَنْتِ قَدْ تَطَهَّرْتِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ أَنَّ الْمَرْأَةَ إِذَا اغْتَسَلَتْ مِنْ الْجَنَابَةِ فَلَمْ تَنْقُضْ شَعْرَهَا أَنَّ ذَلِكَ يُجْزِئُهَا بَعْدَ أَنْ تُفِيضَ الْمَاءَ عَلَى رَأْسِهَا","id":"telah menceritakan kepada kami [Ibnu Abu Umar] berkata, telah menceritakan kepada kami [Sufyan] dari [Ayyub bin Musa] dari [Sa'id Al Maqburi] dari [Abdullah bin Rafi'] dari [Ummu Salamah] ia berkata; \"Wahai Rasulullah, sesungguhnya aku adalah seorang wanita yang biasa mengencangkan tali ikatan rambut (kepang), jika aku mandi junub apakah aku harus melepasnya?\" beliau menjawab: \" Tidak, tapi cukup engkau tuangkan di atas kepalamu tiga tuangan air, setelah itu alirkan air ke seluruh tubuhmu maka engkau akan suci, atau beliau mengatakan: \"engkau telah suci.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Banyak ahli ilmu yang mengamalkan hadits ini, mereka mengatakan jika seorang wanita mandi junub, dan tidak mengurai rambutnya maka hal itu telah cukup setelah mengalirkan air ke tubuhnya.\""},"99":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا الْحَارِثُ بْنُ وَجِيهٍ قَالَ حَدَّثَنَا مَالِكُ بْنُ دِينَارٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَحْتَ كُلِّ شَعْرَةٍ جَنَابَةٌ فَاغْسِلُوا الشَّعْرَ وَأَنْقُوا الْبَشَرَ وَفِي الْبَاب عَنْ عَلِيٍّ وَأَنَسٍ قَالَ أَبُو عِيسَى حَدِيثُ الْحَارِثِ بْنِ وَجِيهٍ حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِهِ وَهُوَ شَيْخٌ لَيْسَ بِذَاكَ وَقَدْ رَوَى عَنْهُ غَيْرُ وَاحِدٍ مِنْ الْأَئِمَّةِ وَقَدْ تَفَرَّدَ بِهَذَا الْحَدِيثِ عَنْ مَالِكِ بْنِ دِينَارٍ وَيُقَالُ الْحَارِثُ بْنُ وَجِيهٍ وَيُقَالُ ابْنُ وَجْبَةَ","id":"telah menceritakan kepada kami [Nashr bin Ali] berkata, telah menceritakan kepada kami [Al Harits bin Wajih] berkata; telah menceritakan kepada kami [Malik bin Dinar] dari [Muhammad bin Sirin] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \" Di bawah setiap lembar rambut adalah junub, maka basuhlah rambut dan bersihkanlah kulit.\" Dalam bab ini juga ada riwayat dari Ali dan Anas. Abu Isa berkata; \"Hadits Al Harits bin Wajih adalah hadits gharib yang kami tidak mengetahui kecuali darinya, sedangkan ia adalah seorang syaikh yang lemah. Tidak sedikit para ulama yang meriwayatkan darinya, namun ia meriwayatkan hadits ini dengan sendirian, dari Malik bin Dinar. Terkadang ia disebut dengan nama Al Harits bin Wajih dan kadang dengan nama Ibnu Wajbah.\""},"100":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَتَوَضَّأُ بَعْدَ الْغُسْلِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ أَبُو عِيسَى وَهَذَا قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ أَنْ لَا يَتَوَضَّأَ بَعْدَ الْغُسْلِ","id":"telah menceritakan kepada kami [Isma'il bin Musa] berkata, telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dari [Al Aswad] dari [Aisyah] berkata, \" Nabi shallallahu 'alaihi wasallam tidak berwudlu setelah mandi.\" Abu Isa berkata; \"Hadits ini derajatnya hadits hasan shahih.\" Abu Isa berkata; \"Dan ini adalah pendapat tidak sedikit dari para sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in, yaitu tidak berwudlu setelah mandi.\""},"101":{"ar":"حَدَّثَنَا أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْأَوْزَاعِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْإِذَا جَاوَزَ الْخِتَانُ الْخِتَانَ فَقَدْ وَجَبَ الْغُسْلُ فَعَلْتُهُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاغْتَسَلْنَاقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَرَافِعِ بْنِ خَدِيجٍ","id":"Telah menceritakan kepada kami [Abu Musa Muhammad bin Al Mutsanna] berkata; telah menceritakan kepada kami [Al Walid bin Muslim] dari [Al Auza'i] dari [Abdurrahman bin Al Qosim] dari [ayahnya] dari ['Aisyah] ia berkata; \"Jika khitan bertemu khitan maka telah wajib mandi. Aku pernah melakukan dengan Rasulullah shallallahu 'alaihi wasallam, lalu kami mandi junub.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Hurairah, Abdullah bin Umar dan Rafi' bin Khadij.\""},"102":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ عَائِشَةَ قَالَتْقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَاوَزَ الْخِتَانُ الْخِتَانَ وَجَبَ الْغُسْلُقَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَيْرِ وَجْهٍ إِذَا جَاوَزَ الْخِتَانُ الْخِتَانَ فَقَدْ وَجَبَ الْغُسْلُ وَهُوَ قَوْلُ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ أَبُو بَكْرٍ وَعُمَرُ وَعُثْمَانُ وَعَلِيٌّ وَعَائِشَةُ وَالْفُقَهَاءِ مِنْ التَّابِعِينَ وَمَنْ بَعْدَهُمْ مِثْلِ سُفْيَانَ الثَّوْرِيِّ وَالشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ قَالُوا إِذَا الْتَقَى الْخِتَانَانِ وَجَبَ الْغُسْلُ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ali bin Zaid] dari [Sa'id bin Al Musayyib] dari ['Aisyah] ia berkata; \"Nabi shallallahu 'alaihi wasallam bersabda: \"Jika khitan melampaui khitan, maka telah wajib mandi.\" Abu Isa berkata; \"Hadits 'Aisyah ini derajatnya hasan shahih.\" Ia berkata; \"Hadits ini telah diriwayatkan dari 'Aisyah dengan banyak jalur, yaitu hadits, \"Jika khitan melampaui khitan, maka telah wajib mandi.\" Ini adalah pendapat kebanyakan ulama dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, seperti Abu Bakar, Umar, Utsman, Ali dan 'Aisyah. Juga dari kalangan fuqaha tabi'in dan orang-orang setelah mereka seperti Sufyan Ats Tsauri, Syafi'i, Ahmad dan Ishaq. Mereka berkata; \"Jika khitan bertemu dengan khitan maka telah wajib mandi.\""},"103":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا يُونُسُ بْنُ يَزِيدَ عَنْ الزُّهْرِيِّ عَنْ سَهْلِ بْنِ سَعْدٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَإِنَّمَا كَانَ الْمَاءُ مِنْ الْمَاءِ رُخْصَةً فِي أَوَّلِ الْإِسْلَامِ ثُمَّ نُهِيَ عَنْهَاحَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ مِثْلَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَإِنَّمَا كَانَ الْمَاءُ مِنْ الْمَاءِ فِي أَوَّلِ الْإِسْلَامِ ثُمَّ نُسِخَ بَعْدَ ذَلِكَ وَهَكَذَا رَوَى غَيْرُ وَاحِدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ أُبَيُّ بْنُ كَعْبٍ وَرَافِعُ بْنُ خَدِيجٍ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ عَلَى أَنَّهُ إِذَا جَامَعَ الرَّجُلُ امْرَأَتَهُ فِي الْفَرْجِ وَجَبَ عَلَيْهِمَا الْغُسْلُ وَإِنْ لَمْ يُنْزِلَا","id":"telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Abdullah bin Al Mubarak] berkata; telah mengabarkan kepada kami [Yunus bin Yazid] dari [Az Zuhri] dari [Sahl bin Sa'd] dari [Ubai bin Ka'ab] ia berkata; \"Adanya air (mandi) karena air (mani) itu asalnya adalah keringanan di awal-awal Islam, setelah itu dilarang.\" Telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Abdullah bin Al Mubarak] berkata; telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dengan sanad ini, seperti dalam hadits.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, adanya air karena air itu hanya di awal-awal Islam, setelah itu dilarang.\" Seperti inilah, tidak sedikit orang yang telah meriwayatkan hadits ini dari sahabat Nabi shallallahu 'alaihi wasallam, di antara mereka adalah Ubai bin Ka'ab dan Rafi' bin Khudij. Banyak ahli ilmu yang mengamalkan hadits ini, bahwasanya jika seorang laki-laki mengumpuli isterinya pada kemaluan, maka telah wajib mandi meskipun tidak keluar air mani.\""},"104":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا شَرِيكٌ عَنْ أَبِي الْجَحَّافِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَإِنَّمَا الْمَاءُ مِنْ الْمَاءِ فِي الِاحْتِلَامِقَالَ أَبُو عِيسَى سَمِعْت الْجَارُودَ يَقُولُ سَمِعْتُ وَكِيعًا يَقُولُ لَمْ نَجِدْ هَذَا الْحَدِيثَ إِلَّا عِنْدَ شَرِيكٍ قَالَ أَبُو عِيسَى وَأَبُو الْجَحَّافِ اسْمُهُ دَاوُدُ بْنُ أَبِي عَوْفٍ وَيُرْوَى عَنْ سُفْيَانَ الثَّوْرِيِّ قَالَ حَدَّثَنَا أَبُو الْجَحَّافِ وَكَانَ مَرْضِيًّا قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُثْمَانَ بْنِ عَفَّانَ وَعَلِيِّ بْنِ أَبِي طَالِبٍ وَالزُّبَيْرِ وَطَلْحَةَ وَأَبِي أَيُّوبَ وَأَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الْمَاءُ مِنْ الْمَاءِ","id":"telah menceritakan kepada kami [Ali bin Hujr] berkata; telah mengabarkan kepada kami [Syarik] dari [Abu Al Hajjaf] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; \"Adanya air (mandi) karena air (mani) dalam mimpi.\" Abu Isa berkata; \"Aku mendengar Al Jarud berkata; \"Aku mendengar Waki' berkata; \"Kami tidak mendapat hadits ini selain dari Syarik.\" Abu Isa berkata; \"Abu Al Jahhaf namanya adalah Dawud bin Abu Auf.\" Hadits ini juga telah diriwayatkan dari Sufyan Ats Tsauri. Ia berkata; \"Telah menceritakan kepada kami Abu Al Jahhaf, ia adalah seorang yang diridlai.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Utsman bin 'Affan, Ali bin Abu Thalib, Az Zubair, Thalhah, Abu Ayyub dan Abu Sa'id dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau bersabda: \"Air (mandi) itu karena air (mani).\""},"105":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ الْخَيَّاطُ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ هُوَ الْعُمَرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجُلِ يَجِدُ الْبَلَلَ وَلَا يَذْكُرُ احْتِلَامًا قَالَ يَغْتَسِلُ وَعَنْ الرَّجُلِ يَرَى أَنَّهُ قَدْ احْتَلَمَ وَلَمْ يَجِدْ بَلَلًا قَالَ لَا غُسْلَ عَلَيْهِ قَالَتْ أُمُّ سَلَمَةَ يَا رَسُولَ اللَّهِ هَلْ عَلَى الْمَرْأَةِ تَرَى ذَلِكَ غُسْلٌ قَالَ نَعَمْ إِنَّ النِّسَاءَ شَقَائِقُ الرِّجَالِقَالَ أَبُو عِيسَى وَإِنَّمَا رَوَى هَذَا الْحَدِيثَ عَبْدُ اللَّهِ بْنُ عُمَرَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ حَدِيثَ عَائِشَةَ فِي الرَّجُلِ يَجِدُ الْبَلَلَ وَلَا يَذْكُرُ احْتِلَامًا وَعَبْدُ اللَّهِ بْنُ عُمَرَ ضَعَّفَهُ يَحْيَى بْنُ سَعِيدٍ مِنْ قِبَلِ حِفْظِهِ فِي الْحَدِيثِ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ إِذَا اسْتَيْقَظَ الرَّجُلُ فَرَأَى بِلَّةً أَنَّهُ يَغْتَسِلُ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَأَحْمَدَ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ مِنْ التَّابِعِينَ إِنَّمَا يَجِبُ عَلَيْهِ الْغُسْلُ إِذَا كَانَتْ الْبِلَّةُ بِلَّةَ نُطْفَةٍ وَهُوَ قَوْلُ الشَّافِعِيِّ وَإِسْحَقَ وَإِذَا رَأَى احْتِلَامًا وَلَمْ يَرَ بِلَّةً فَلَا غُسْلَ عَلَيْهِ عِنْدَ عَامَّةِ أَهْلِ الْعِلْمِ","id":"telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Hammad bin Khalid Al Khayyath] dari [Abdullah bin Umar] -yaitu Al Umari- dari [Ubaidullah bin Umar] dari [Al Qasim bin Muhammad] dari ['Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang seorang laki-laki yang mendapatkan basah namun ia tidak ingat jika bermimpi, beliau menjawab: \"Ia wajib mandi.\" Dan beliau juga ditanya tentang seorang laki-laki bermimpi namun tidak mendapatkan sesuatu yang basah (mani), beliau menjawab: \"Ia tidak wajib mandi.\" Ummu Salamah bertanya, \"Wahai Rasulullah, jika seorang wanita bermimpi seperti itu apakah ia juga harus mandi?\" beliau menjawab: \"Ya, karena wanita adalah saudara(sepadan) laki-laki.\" Abu Isa berkata; \"Yang meriwayatkan hadits ini, yakni hadits 'Aisyah tentang seorang laki-laki yang mendapatkan sesuatu yang basah, namun ia tidak mengingat jika ia bermimpi, adalah Abdullah bin Umar dari Ubadidullah bin Umar. Namun Yahya bin Sa'id melemahkan Abdullah bin Umar dari sisi hafalan terdapat haditsnya. Ini adalah pendapat banyak ulama dari sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in, bahwa seorang laki-laki jika bangun lalu mendapatkan sesuatu yang basah maka ia wajib mandi.\" Pendapat ini juga diambil oleh Sufyan Ats Tsauri dan Ahmad. Dan sebagian ulama dari kalangan tabi'in mengatakan bahwa seseorang wajib mandi jika basah itu berupa mani. Ini adalah pendapat Syafi'i dan Ishaq. Apabila seseorang bermimpi namun tidak melihat sesuatu yang basah (mani), maka ia tidak wajib mandi.\""},"106":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو السَّوَّاقُ الْبَلْخِيُّ حَدَّثَنَا هُشَيْمٌ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ ح قَالَ و حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا حُسَيْنٌ الْجُعْفِيُّ عَنْ زَائِدَةَ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَلِيٍّ قَالَ سَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمَذْيِ فَقَالَ مِنْ الْمَذْيِ الْوُضُوءُ وَمِنْ الْمَنِيِّ الْغُسْلُ قَالَ وَفِي الْبَاب عَنْ الْمِقْدَادِ بْنِ الْأَسْوَدِ وَأُبَيِّ بْنِ كَعْبٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَيْرِ وَجْهٍ مِنْ الْمَذْيِ الْوُضُوءُ وَمِنْ الْمَنِيِّ الْغُسْلُ وَهُوَ قَوْلُ عَامَّةِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ وَبِهِ يَقُولُ سُفْيَانُ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ","id":"telah menceritakan kepada kami [Muhammad bin 'Amru As Sawwaq Al Balkhi] berkata; telah menceritakan kepada kami [Husyaim] dari [Yazid bin Abu Ziyad], dan ia berkata; telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Husain Al Ju'fi] dari [Za`idah] dari [Yazid bin Abu Ziyad] dari [Abdurrahman bin Abu Laila] dari [Ali] ia berkata; \"Aku bertanya kepada Nabi shallallahu 'alaihi wasallam tentang madzi, maka beliau menjawab: \"Keluarnya madzi itu mengharuskan wudlu, dan keluarnya mani itu mengharuskan mandi.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Al Miqdad bin Al Aswad dan Ubai bin Ka'ab.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Hadits ini juga telah diriwayatkan dari Ali bin Abu Thalib, dari Nabi shallallahu 'alaihi wasallam dari jalur yang lain, yaitu hadits, \"Keluarnya madzi itu mengharuskan wudlu, dan keluarnya mani itu mengharuskan mandi.\" Ini adalah pendapat kebanyakan ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang setelah mereka. Pendapat ini juga diambil oleh Sufyan, Syafi'i, Ahmad dan Ishaq.\""},"107":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ سَعِيدِ بْنِ عُبَيْدٍ هُوَ ابْنُ السَّبَّاقِ عَنْ أَبِيهِ عَنْ سَهْلِ بْنِ حُنَيْفٍ قَالَ كُنْتُ أَلْقَى مِنْ الْمَذْيِ شِدَّةً وَعَنَاءً فَكُنْتُ أُكْثِرُ مِنْهُ الْغُسْلَ فَذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَأَلْتُهُ عَنْهُ فَقَالَ إِنَّمَا يُجْزِئُكَ مِنْ ذَلِكَ الْوُضُوءُ فَقُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ بِمَا يُصِيبُ ثَوْبِي مِنْهُ قَالَ يَكْفِيكَ أَنْ تَأْخُذَ كَفًّا مِنْ مَاءٍ فَتَنْضَحَ بِهِ ثَوْبَكَ حَيْثُ تَرَى أَنَّهُ أَصَابَ مِنْهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَلَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ مُحَمَّدِ بْنِ إِسْحَقَ فِي الْمَذْيِ مِثْلَ هَذَا وَقَدْ اخْتَلَفَ أَهْلُ الْعِلْمِ فِي الْمَذْيِ يُصِيبُ الثَّوْبَ فَقَالَ بَعْضُهُمْ لَا يُجْزِئُ إِلَّا الْغَسْلُ وَهُوَ قَوْلُ الشَّافِعِيِّ وَإِسْحَقَ وَقَالَ بَعْضُهُمْ يُجْزِئُهُ النَّضْحُ و قَالَ أَحْمَدُ أَرْجُو أَنْ يُجْزِئَهُ النَّضْحُ بِالْمَاءِ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abdah] dari [Muhammad bin Ishaq] dari [Sa'id bin Ubaid] -yaitu Ibnu As Sabbaq, dari [Ayahnya] dari [Sahl bin Hunaif] ia berkata; \"Aku sering mengeluarkan madzi karena lelah, hingga aku sering mandi karena hal itu. Lalu aku ceritakan dan menanyakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, beliau menjawab: \"Cukuplah kamu berwudlu.\" Lalu aku bertanya lagi, \"Wahai Rasulullah, bagaimana dengan kain yang terkena?\" beliau menjawab: \"Cukup bagimu mengambil air setangkup telapak tangan, lalu percikkanlah pada bagian yang terkena.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Dan kami tidak mengetahui hadits tersebut kecuali dari hadits Muhammad bin Ishaq tentang madzi. Para ulama masih berselisih tentang madzi yang mengenai kain, sebagian mereka berkata; \"Harus mandi.\" Ini adalah pendapat Syafi'i dan Ishaq. Sedangkan yang lainnya mengatakan, \"Cukup diperciki dengan air.\" Dan Ahmad berkata; \"Aku berharap bahwa hal itu cukup diperciki dengan air.\""},"108":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامِ بْنِ الْحَارِثِ قَالَ ضَافَ عَائِشَةَ ضَيْفٌ فَأَمَرَتْ لَهُ بِمِلْحَفَةٍ صَفْرَاءَ فَنَامَ فِيهَا فَاحْتَلَمَ فَاسْتَحْيَا أَنْ يُرْسِلَ بِهَا وَبِهَا أَثَرُ الِاحْتِلَامِ فَغَمَسَهَا فِي الْمَاءِ ثُمَّ أَرْسَلَ بِهَا فَقَالَتْ عَائِشَةُ لِمَ أَفْسَدَ عَلَيْنَا ثَوْبَنَا إِنَّمَا كَانَ يَكْفِيهِ أَنْ يَفْرُكَهُ بِأَصَابِعِهِ وَرُبَّمَا فَرَكْتُهُ مِنْ ثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَصَابِعِي قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ مِنْ الْفُقَهَاءِ مِثْلِ سُفْيَانَ الثَّوْرِيِّ وَالشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ قَالُوا فِي الْمَنِيِّ يُصِيبُ الثَّوْبَ يُجْزِئُهُ الْفَرْكُ وَإِنْ لَمْ يُغْسَلْ وَهَكَذَا رُوِيَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامِ بْنِ الْحَارِثِ عَنْ عَائِشَةَ مِثْلَ رِوَايَةِ الْأَعْمَشِ وَرَوَى أَبُو مَعْشَرٍ هَذَا الْحَدِيثَ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ وَحَدِيثُ الْأَعْمَشِ أَصَحُّ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Hammam bin Al Harits] ia berkata; \"Ada seorang tamu datang ke rumah 'Aisyah, lalu 'Aisyah menyuruhnya tidur dengan selimut berwarna kuning, maka ia pun tidur dengan selimut tersebut. Tamu itu mimpi basah, dan ia malu untuk mengembalikan selimut tersebut karena di dalamnya terdapat bekas mani, sehingga ia mencelupkannya ke dalam air. Baru setelah itu ia mengembalikannya kepada 'Aisyah. Maka berkatalah ['Aisyah], \"Kenapa ia merusak (membuat basah) kain kami? Padahal cukup baginya mengerik bekasnya dengan jari, aku pernah mengerik kain Rasulullah shallallahu 'alaihi wasallam dengan jari-jariku.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Ini adalah pendapat beberapa sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang setelah mereka dari kalangan fuqaha. Seperti Sufyan Ats Tsauri, Syafi'i, Ahmad dan Ishaq. Mereka berkata berkenaan dengan mani yang mengenai kain, \"Cukup baginya mengerik, meskipun tidak mencucinya.\" Seperti inilah diriwayatkan dari [Manshur] dari [Hammam bin Al Harits] dari ['Aisyah]. Seperti riwayat Al A'masy. Dan [Abu Ma'syar] meriwayatkan hadits ini dari [Ibrahim] dari [Al Aswad] dari ['Aisyah]. Dan hadits Al A'masy lebih shahih.\""},"109":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ عَمْرِو بْنِ مَيْمُونِ بْنِ مِهْرَانَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَائِشَةَ أَنَّهَا غَسَلَتْ مَنِيًّا مِنْ ثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَحَدِيثُ عَائِشَةَ أَنَّهَا غَسَلَتْ مَنِيًّا مِنْ ثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ بِمُخَالِفٍ لِحَدِيثِ الْفَرْكِ لِأَنَّهُ وَإِنْ كَانَ الْفَرْكُ يُجْزِئُ فَقَدْ يُسْتَحَبُّ لِلرَّجُلِ أَنْ لَا يُرَى عَلَى ثَوْبِهِ أَثَرُهُ قَالَ ابْنُ عَبَّاسٍ الْمَنِيُّ بِمَنْزِلَةِ الْمُخَاطِ فَأَمِطْهُ عَنْكَ وَلَوْ بِإِذْخِرَةٍ","id":"telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Amru bin Maimun bin Mihran] dari [Sulaiman bin Yasar] dari ['Aisyah] bahwasanya ia pernah mencuci bekas mani pada kain Rasulullah shallallahu 'alaihi wasallam.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Dalam bab ini juga ada riwayat dari Ibnu Abbas. Sedangkan hadits 'Aisyah, bahwasanya ia pernah mencuci bekas mani pada kain Rasulullah shallallahu 'alaihi wasallam tidak bertentangan dengan hadits mengerik. Sebab meskipun dikerik itu sudah mencukupi, namun terkadang seorang laki-laki tidak suka jika bekas pada kainnya masih terlihat. Ibnu Abbas berkata; \"Mani itu seperti ingus, maka hendaklah ia buang meskipun dengan idzkhir (kayu).\""},"110":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ الْأَعْمَشِ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنَامُ وَهُوَ جُنُبٌ وَلَا يَمَسُّ مَاءً حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ سُفِيانَ عَنْ أَبِي إِسْحَقَ نَحْوَهُ قَالَ أَبُو عِيسَى وَهَذَا قَوْلُ سَعِيدِ بْنِ الْمُسَيِّبِ وَغَيْرِهِ وَقَدْ رَوَى غَيْرُ وَاحِدٍ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ عَنْ النَّبِيّ�� صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَتَوَضَّأُ قَبْلَ أَنْ يَنَامَ وَهَذَا أَصَحُّ مِنْ حَدِيثِ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ وَقَدْ رَوَى عَنْ أَبِي إِسْحَقَ هَذَا الْحَدِيثَ شُعْبَةُ وَالثَّوْرِيُّ وَغَيْرُ وَاحِدٍ وَيَرَوْنَ أَنَّ هَذَا غَلَطٌ مِنْ أَبِي إِسْحَقَ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abu Bakr bin Ayyasy] dari [Al A'masy] dari [Abu Ishaq] dari [Al Aswad] dari ['Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah tidur dalam keadaan junub, dan beliau tidak menyentuh air.\" Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Ishaq] seperti itu. Abu Isa berkata; \"Ini adalah perkataan Sa'id bin Al Musayyib dan selainnya.\" Hadits ini diriwayatkan tidak hanya satu orang, dari Al Aswad, dari 'Aisyah, dari Nabi shallallahu 'alaihi wasallam, bahwa beliau berwudlu sebelum tidur. Dan ini lebih shahih ketimbang hadits Abu Ishaq dari Al Aswad. Hadits juga ini telah diriwayatkan dari Abu Ishaq oleh Syu'nah, Ats Tsauri dan selain mereka. Dan mereka memandang bahwa ini adalah kesalahan yang dilakukan oleh Abu Ishaq.\""},"111":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَأَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَنَامُ أَحَدُنَا وَهُوَ جُنُبٌ قَالَ نَعَمْ إِذَا تَوَضَّأَقَالَ وَفِي الْبَاب عَنْ عَمَّارٍ وَعَائِشَةَ وَجَابِرٍ وَأَبِي سَعِيدٍ وَأُمِّ سَلَمَةَ قَالَ أَبُو عِيسَى حَدِيثُ عُمَرَ أَحْسَنُ شَيْءٍ فِي هَذَا الْبَابِ وَأَصَحُّ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ قَالُوا إِذَا أَرَادَ الْجُنُبُ أَنْ يَنَامَ تَوَضَّأَ قَبْلَ أَنْ يَنَامَ","id":"telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] dari [Umar] bahwa ia pernah bertanya Nabi shallallahu 'alaihi wasallam, \"Apakah salah seorang dari kami boleh tidur dalam keadaan junub?\" beliau menjawab: \"Ya, selama ia berwudlu.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari 'Ammar, 'Aisyah, Jabir, Abu Sa'id dan Ummu Salamah.\" Abu Isa berkata; \"Hadits Umar adalah yang paling baik dan paling shahih dalam bab ini, pendapat ini diambil oleh Sufyan Ats Tausri, bin Al Mubarak, Ahmad dan Ishaq. Mereka berkata; \"Jika seorang junub ingin tidur hendaklah ia berwudlu.\""},"112":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ حَدَّثَنَا حُمَيْدٌ الطَّوِيلُ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ الْمُزَنِيِّ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقِيَهُ وَهُوَ جُنُبٌ قَالَ فَانْبَجَسْتُ أَيْ فَانْخَنَسْتُ فَاغْتَسَلْتُ ثُمَّ جِئْتُ فَقَالَ أَيْنَ كُنْتَ أَوْ أَيْنَ ذَهَبْتَ قُلْتُ إِنِّي كُنْتُ جُنُبًا قَالَ إِنَّ الْمُسْلِمَ لَا يَنْجُسُقَالَ وَفِي الْبَاب عَنْ حُذَيْفَةَ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى وَحَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَمَعْنَى قَوْلِهِ فَانْخَنَسْتُ يَعْنِي تَنَحَّيْتُ عَنْهُ وَقَدْ رَخَّصَ غَيْرُ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ فِي مُصَافَحَةِ الْجُنُبِ وَلَمْ يَرَوْا بِعَرَقِ الْجُنُبِ وَالْحَائِضِ بَأْسًا","id":"telah menceritakan kepada kami [Ishaq bin Manshur] berkata; telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] berkata; telah menceritakan kepada kami [Humaid Ath Thawil] dari [Bakr bin Abdullah Al Muzani] dari [Abu Rafi'] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bertemu dengannya sedang ia dalam keadaan junub. Abu Hurairahberkata; \"Lalu aku bersembunyi dan mandi, baru kemudian aku datang lagi.\" Beliau bertanya: \"Kamu dimana?\" atau beliau mengatakan: \"Kamu pergi kemana?\" aku menjawab, \"Sesungguhnya aku dalam keadaan junub, \" beliau bersabda: \"Orang muslim itu tidak najis.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Hudzaifah dan Ibnu Abbas.\" Abu Isa berkata; \"Hadits Abu Hurairah ini derajatnya hasan shahih. Adapun makna \"aku bersembunyi\" adalah \"aku menjauh darinya\". Dan tidak hanya seorang ulama saja yang memberikan keringanan atas bolehnya berjabat tangan dengan orang junub, dan mereka tidak melihat adanya larangan dalam masalah keringat orang yang junub atau wanita haid.\""},"113":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْجَاءَتْ أُمُّ سُلَيْمٍ بِنْتُ مِلْحَانَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ لَا يَسْتَحْيِي مِنْ الْحَقِّ فَهَلْ عَلَى الْمَرْأَةِ تَعْنِي غُسْلًا إِذَا هِيَ رَأَتْ فِي الْمَنَامِ مِثْلَ مَا يَرَى الرَّجُلُ قَالَ نَعَمْ إِذَا هِيَ رَأَتْ الْمَاءَ فَلْتَغْتَسِلْ قَالَتْ أُمُّ سَلَمَةَ قُلْتُ لَهَا فَضَحْتِ النِّسَاءَ يَا أُمَّ سُلَيْمٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ عَامَّةِ الْفُقَهَاءِ أَنَّ الْمَرْأَةَ إِذَا رَأَتْ فِي الْمَنَامِ مِثْلَ مَا يَرَى الرَّجُلُ فَأَنْزَلَتْ أَنَّ عَلَيْهَا الْغُسْلَ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَالشَّافِعِيُّ قَالَ وَفِي الْبَاب عَنْ أُمِّ سُلَيْمٍ وَخَوْلَةَ وَعَائِشَةَ وَأَنَسٍ","id":"telah menceritakan kepada kami [Ibnu Abu Umar] berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Hisyam bin Urwah] dari [Ayahnya] dari [Zainah binti Abu Salamah] dari [Ummu Salamah] ia berkata; \"Ummu Sulaim binti Milhan datang menemui Nabi shallallahu 'alaihi wasallam seraya berkata; \"Wahai Rasulullah, sesungguhnya Allah tidak malu dengan kebenaran, apakah seorang wanita juga wajib mandi jika bermimpi sebagaimana laki-laki bermimpi?\" beliau menjawab: \"Ya, jika melihat air maka ia harus mandi.\" Ummu Salamah berkata; \"Aku bertanya kepada Ummu Sulaim, \"Engkau telah membuka rahasia para wanita wahai ummu Sulaim!\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Ini adalah pendapat mayoritas fuqaha, bahwa seorang wanita jika bermimpi sebagaimana laki-laki bermimpi, hingga ia mengeluarkan cairan, maka ia wajib mandi. Pendapat ini juga diambil oleh Sufyan Ats Tsauri dan Syafi'i.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari ummu Sulaim, Khaulah, 'Aisyah dan Anas.\""},"114":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ حُرَيْثٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْرُبَّمَا اغْتَسَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْجَنَابَةِ ثُمَّ جَاءَ فَاسْتَدْفَأَ بِي فَضَمَمْتُهُ إِلَيَّ وَلَمْ أَغْتَسِلْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَيْسَ بِإِسْنَادِهِ بَأْسٌ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ وَالتَّابِعِينَ أَنَّ الرَّجُلَ إِذَا اغْتَسَلَ فَلَا بَأْسَ بِأَنْ يَسْتَدْفِئَ بِامْرَأَتِهِ وَيَنَامَ مَعَهَا قَبْلَ أَنْ تَغْتَسِلَ الْمَرْأَةُ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Waki'] dari [Huraits] dari [Asy Sya'bi] dari [Masruq] dari ['Aisyah] ia berkata; \"Nabi shallallahu 'alaihi wasallam mandi junub kemudian beliau datang untuk menghangatkan badan, maka aku mendekapnya sementara aku belum mandi.\" Abu Isa berkata; \"Hadits ini sanadnya tidak ada masalah. Ini pendapat banyak orang dari ahli ilmu, dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in, mereka berkata; \"Apabila laki-laki telah mandi, maka tidak mengapa ia menghangatkan badan pada istrinya dan tidur bersamanya sebelum istrinya mandi.\" Ini adalah pendapat Sufyan Ats Tsauri, Syafi'i, Ahmad dan Ishaq.\""},"115":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمَحْمُودُ بْنُ غَيْلَانَ قَالَا حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا سُفْيَانُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ عَمْرِو بْنِ بُجْدَانَ عَنْ أَبِي ذَرٍّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الصَّعِيدَ الطَّيِّبَ طَهُورُ الْمُسْلِمِ وَإِنْ لَمْ يَجِدْ الْمَاءَ عَشْرَ سِنِينَ فَإِذَا وَجَدَ الْمَاءَ فَلْيُمِسَّهُ بَشَرَتَهُ فَإِنَّ ذَلِكَ خَيْرٌو قَالَ مَحْمُودٌ فِي حَدِيثِهِ إِنَّ الصَّعِيدَ الطَّيِّبَ وَضُوءُ الْمُسْلِمِ قَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَعِمْرَانَ بْنِ حُصَيْنٍ قَالَ أَبُو عِيسَى وَهَكَذَا رَوَى غَيْرُ وَاحِدٍ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ عَمْرِو بْنِ بُجْدَانَ عَنْ أَبِي ذَرٍّ وَقَدْ رَوَى هَذَا الْحَدِيثَ أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ رَجُلٍ مِنْ بَنِي عَامِرٍ عَنْ أَبِي ذَرٍّ وَلَمْ يُسَمِّهِ قَالَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ عَامَّةِ الْفُقَهَاءِ أَنَّ الْجُنُبَ وَالْحَائِضَ إِذَا لَمْ يَجِدَا الْمَاءَ تَيَمَّمَا وَصَلَّيَا وَيُرْوَى عَنْ ابْنِ مَسْعُودٍ أَنَّهُ كَانَ لَا يَرَى التَّيَمُّمَ لِلْجُنُبِ وَإِنْ لَمْ يَجِدْ الْمَاءَ وَيُرْوَى عَنْهُ أَنَّهُ رَجَعَ عَنْ قَوْلِهِ فَقَالَ يَتَيَمَّمُ إِذَا لَمْ يَجِدْ الْمَاءَ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَمَالِكٌ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ","id":"telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Mahmud bin Ghailan] mereka berkata; telah menceritakan kepada kami [Abu Ahmad Az Zubairi] berkata; telah menceritakan kepada kami [Sufyan] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari ['Amru bin Bujdan] dari [Abu Dzar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Debu yang baik itu alat bersucinya seorang muslim meskipun ia tidak mendapatkan air selama sepuluh tahun. Maka jika ia telah mendapatkan air, hendaklah ia mengusapkan pada kulitnya karena itu lebih baik.\" Mahmud menyebutkan dalam haditsnya, \"Debu yang baik itu alat bersucinya seorang muslim.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Hurairah, Abdullah bin Amru dan Imran bin Hushain.\" Abu Isa berkata; \"Seperti inilah, tidak hanya satu orang yang meriwayatkan dari Khalid Al Hadzdza` dari Abu Qilabah, dari 'Amru bin Bujdan dari Abu Dzar.\" [Ayyub] meriwayatkan hadits ini dari [Abu Qilabah] dari [seorang laki-laki dari bani 'Amir] dari [Abu Dzar], namun ia tidak menyebut namanya. Ia berkata; \"Hadits ini derajatnya hasan shahih. Ini adalah perkataan mayoritas fuqaha, bahwa orang yang junub dan haid jika tidak mendapatkan air hendaklah ia bertayamum lalu shalat.\" Diriwayatkan pula dari Ibnu Mas'ud, bahwasanya seorang junub tidak boleh bertayamum meskipun tidak mendapatkan air. Namun diriwayatkan darinya, bahwa ia telah mencabut pendapatnya, lalu ia berkata; \"Ia tidak boleh bertayamum jika tidak mendapatkan air.\" Pendapat ini diambil oleh Sufyan Ats Tsauri, Malik, Syafi'i, Ahmad dan Ishaq.\""},"116":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ وَعَبْدَةُ وَأَبُو مُعَاوِيَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْجَاءَتْ فَاطِمَةُ بِنْتُ أَبِي حُبَيْشٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي امْرَأَةٌ أُسْتَحَاضُ فَلَا أَطْهُرُ أَفَأَدَعُ الصَّلَاةَ قَالَ لَا إِنَّمَا ذَلِكَ عِرْقٌ وَلَيْسَتْ بِالْحَيْضَةِ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْسِلِي عَنْكِ الدَّمَ وَصَلِّيقَالَ أَبُو مُعَاوِيَةَ فِي حَدِيثِهِ وَقَالَ تَوَضَّئِي لِكُلِّ صَلَاةٍ حَتَّى يَجِيءَ ذَلِكَ الْوَقْتُ قَالَ وَفِي الْبَاب عَنْ أُمِّ سَلَمَةَ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَمَالِكٌ وَابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ أَنَّ الْمُسْتَحَاضَةَ إِذَا جَاوَزَتْ أَيَّامَ أَقْرَائِهَا اغْتَسَلَتْ وَتَوَضَّأَتْ لِكُلِّ صَلَاةٍ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Waki'] dan [Abdah] dan [Abu Mu'awiyah] dari [Hisyam bin Urwah] dari [ayahnya] dari ['Aisyah] ia berkata; \"Fatimah binti Hubaisy datang menemui Nabi shallallahu 'alaihi wasallam, lalu ia berkata; \"Wahai Rasulullah, aku mengeluarkan darah istihadlah, hingga aku tidak suci. Maka apakah aku boleh meninggalkan shalat?\" beliau bersabda: \"Tidak, itu hanyalah darah penyakit, bukan darah haid. Jika darah haid tiba maka tinggalkanlah shalat, jika telah selesai maka mandi dan bersihkanlah darahmu, setelah itu kerjakanalah shalat.\" Abu Mu'awiyah berkata dalam haditsnya, \"Berwudlulah untuk setiap shalat hingga waktu itu tiba.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ummu Salamah.\" Abu Isa berkata; \"Hadits 'Aisyah ini derajatnya hasan shahih. Ini adalah pendapat tidak hanya seorang dari ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in. Pendapat ini dipegang juga oleh Sufyan Ats Tsauri, Malik, bin Al Mubarak dan Syafi'i, bahwa seorang wanita mustahadlah melewati hari-hari haidnya, hendaklah ia mandi dan berwudlu setiap kali shalat.\""},"117":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي الْيَقْظَانِ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ فِي الْمُسْتَحَاضَةِ تَدَعُ الصَّلَاةَ أَيَّامَ أَقْرَائِهَا الَّتِي كَانَتْ تَحِيضُ فِيهَا ثُمَّ تَغْتَسِلُ وَتَتَوَضَّأُ عِنْدَ كُلِّ صَلَاةٍ وَتَصُومُ وَتُصَلِّيحَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا شُرَيْكٌ نَحْوَهُ بِمَعْنَاهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ قَدْ تَفَرَّدَ بِهِ شَرِيكٌ عَنْ أَبِي الْيَقْظَانِ قَالَ وَسَأَلْتُ مُحَمَّدًا عَنْ هَذَا الْحَدِيثِ فَقُلْتُ عَدِيُّ بْنُ ثَابِتٍ عَنْ أَبِيهِ عَنْ جَدِّهِ جَدُّ عَدِيٍّ مَا اسْمُهُ فَلَمْ يَعْرِفْ مُحَمَّدٌ اسْمَهُ وَذَكَرْتُ لِمُحَمَّدٍ قَوْلَ يَحْيَى بْنِ مَعِينٍ أَنَّ اسْمَهُ دِينَارٌ فَلَمْ يَعْبَأْ بِهِ و قَالَ أَحْمَدُ وَإِسْحَقُ فِي الْمُسْتَحَاضَةِ إِنْ اغْتَسَلَتْ لِكُلِّ صَلَاةٍ هُوَ أَحْوَطُ لَهَا وَإِنْ تَوَضَّأَتْ لِكُلِّ صَلَاةٍ أَجْزَأَهَا وَإِنْ جَمَعَتْ بَيْنَ الصَّلَاتَيْنِ بِغُسْلٍ وَاحِدٍ أَجْزَأَهَا","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Syarik] dari [Abu Al Yaqzhan] dari [Adi bin Tsabit] dari [ayahku] dari [Kakeknya] dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau bersabda tentang wanita yang sedang istihadlah: \"Hendaklah ia meninggalkan shalat pada hari-hari ia mengalami haid, setelah itu hendaklah ia mandi dan berwudlu pada setiap shalat, berpuasa dan shalat.\" [Ali bin Hujr] bercerita kepada kami bahwa [Syarik] mengkhabarkan kepada kami dengan hadits yang semisal secara makna.\" Abu Isa berkata; \"Hadits ini diriwayatkan oleh Syarik secara tunggal, tidak dengan Abu Al Yaqzhan.\" Ia berkata; \"Aku bertanya kepada Muhammad tentang hadits ini, aku katakan, \"Adi bin Tsabit, dari ayahnya, dari kakeknya, siapakah nama kakeknya?\" Namun Muhammad tidak tahu siapa namanya. Kemudian aku sebutkan pada Muhammad perkataan Yahya bin Ma'in bahwa namanya adalah Dinar, namun dia tidak menggubrisnya.\" Ahmad dan Ishaq berkata tentang wanita yang istihadlah, \"Jika ia mandi pada setiap waktu shalat maka itu adalah lebih hati-hati bagi dia, jika ia berwudlu pada setiap waktu shalat maka itu sudah sah baginya, dan jika ia menggabungkan antara dua shalat dengan satu kali mandi maka itupun sudah sah baginya.\""},"118":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامَرٍ الْعَقَدِيُّ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ طَلْحَةَ عَنْ عَمِّهِ عِمْرَانَ بْنِ طَلْحَةَ عَنْ أُمِّهِ حَمْنَةَ بِنْتِ جَحْشٍ قَالَتْكُنْتُ أُسْتَحَاضُ حَيْضَةً كَثِيرَةً شَدِيدَةً فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْتَفْتِيهِ وَأُخْبِرُهُ فَوَجَدْتُهُ فِي بَيْتِ أُخْتِي زَيْنَبَ بِنْتِ جَحْشٍ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أُسْتَحَاضُ حَيْضَةً كَثِيرَةً شَدِيدَةً فَمَا تَأْمُرُنِي فِيهَا قَدْ مَنَعَتْنِي الصِّيَامَ وَالصَّلَاةَ قَالَ أَنْعَتُ لَكِ الْكُرْسُفَ فَإِنَّهُ يُذْهِبُ الدَّمَ قَالَتْ هُوَ أَكْثَرُ مِنْ ذَلِكَ قَالَ فَتَلَجَّمِي قَالَتْ هُوَ أَكْثَرُ مِنْ ذَلِكَ قَالَ فَاتَّخِذِي ثَوْبًا قَالَتْ هُوَ أَكْثَرُ مِنْ ذَلِكَ إِنَّمَا أَثُجُّ ثَجًّا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَآمُرُكِ بِأَمْرَيْنِ أَيَّهُمَا صَنَعْتِ أَجْزَأَ عَنْكِ فَإِنْ قَوِيتِ عَلَيْهِمَا فَأَنْتِ أَعْلَمُ فَقَالَ إِنَّمَا هِيَ رَكْضَةٌ مِنْ الشَّيْطَانِ فَتَحَيَّضِي سِتَّةَ أَيَّامٍ أَوْ سَبْعَةَ أَيَّامٍ فِي عِلْمِ اللَّهِ ثُمَّ اغْتَسِلِي فَإِذَا رَأَيْتِ أَنَّكِ قَدْ طَهُرْتِ وَاسْتَنْقَأْتِ فَصَلِّي أَرْبَعًا وَعِشْرِينَ لَيْلَةً أَوْ ثَلَاثًا وَعِشْرِينَ لَيْلَةً وَأَيَّامَهَا وَصُومِي وَصَلِّي فَإِنَّ ذَلِكِ يُجْزِئُكِ وَكَذَلِكِ فَافْعَلِي كَمَا تَحِيضُ النِّسَاءُ وَكَمَا يَطْهُرْنَ لِمِيقَاتِ حَيْضِهِنَّ وَطُهْرِهِنَّ فَإِنْ قَوِيتِ عَلَى أَنْ تُؤَخِّرِي الظُّهْرَ وَتُعَجِّلِي الْعَصْرَ ثُمَّ تَغْتَسِلِينَ حِينَ تَطْهُرِينَ وَتُصَلِّينَ الظُّهْرَ وَالْعَصْرَ جَمِيعًا ثُمَّ تُؤَخِّرِينَ الْمَغْرِبَ وَتُعَجِّلِينَ الْعِشَاءَ ثُمَّ تَغْتَسِلِينَ وَتَجْمَعِينَ بَيْنَ الصَّلَاتَيْنِ فَافْعَلِي وَتَغْتَسِلِينَ مَعَ الصُّبْحِ وَتُصَلِّينَ وَكَذَلِكِ فَافْعَلِي وَصُومِي إِنْ قَوِيتِ عَلَى ذَلِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ أَعْجَبُ الْأَمْرَيْنِ إِلَيَّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَاهُ عُبَيْدُ اللَّهِ بْنُ عَمْرٍو الرَّقِّيُّ وَابْنُ جُرَيْجٍ وَشَرِيكٌ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ طَلْحَةَ عَنْ عَمِّهِ عِمْرَانَ عَنْ أُمِّهِ حَمْنَةَ إِلَّا أَنَّ ابْنَ جُرَيجٍ يَقُولُ عُمَرُ بْنُ طَلْحَةَ وَالصَّحِيحُ عِمْرَانُ بْنُ طَلْحَةَ قَالَ وَسَأَلْتُ مُحَمَّدًا عَنْ هَذَا الْحَدِيثِ فَقَالَ هُوَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهَكَذَا قَالَ أَحْمَدُ بْنُ حَنْبَلٍ هُوَ حَدِيثٌ حَسَنٌ صَحِيحٌ و قَالَ أَحْمَدُ وَإِسْحَقُ فِي الْمُسْتَحَاضَةِ إِذَا كَانَتْ تَعْرِفُ حَيْضَهَا بِإِقْبَالِ الدَّمِ وَإِدْبَارِهِ وَإِقْبَالُهُ أَنْ يَكُونَ أَسْوَدَ وَإِدْبَارُهُ أَنْ يَتَغَيَّرَ إِلَى الصُّفْرَةِ فَالْحُكْمُ لَهَا عَلَى حَدِيثِ فَاطِمَةَ بِنْتِ أَبِي حُبَيْشٍ وَإِنْ كَانَتْ الْمُسْتَحَاضَةُ لَهَا أَيَّامٌ مَعْرُوفَةٌ قَبْلَ أَنْ تُسْتَحَاضَ فَإِنَّهَا تَدَعُ الصَّلَاةَ أَيَّامَ أَقْرَائِهَا ثُمَّ تَغْتَسِلُ وَتَتَوَضَّأُ لِكُلِّ صَلَاةٍ وَتُصَلِّي وَإِذَا اسْتَمَرَّ بِهَا الدَّمُ وَلَمْ يَكُنْ لَهَا أَيَّامٌ مَعْرُوفَةٌ وَلَمْ تَعْرِفْ الْحَيْضَ بِإِقْبَالِ الدَّمِ وَإِدْبَارِهِ فَالْحُكْمُ لَهَا عَلَى حَدِيثِ حَمْنَةَ بِنْتِ جَحْشٍ وَكَذَلِكَ قَالَ أَبُو عُبَيْدٍ و قَالَ الشَّافِعِيُّ الْمُسْتَحَاضَةُ إِذَا اسْتَمَرَّ بِهَا الدَّمُ فِي أَوَّلِ مَا رَأَتْ فَدَامَتْ عَلَى ذَلِكَ فَإِنَّهَا تَدَعُ الصَّلَاةَ مَا بَيْنَهَا وَبَيْنَ خَمْسَةَ عَشَرَ يَوْمًا فَإِذَا طَهُرَتْ فِي خَمْسَةَ عَشَرَ يَوْمًا أَوْ قَبْلَ ذَلِكَ فَإِنَّهَا أَيَّامُ حَيْضٍ فَإِذَا رَأَتْ الدَّمَ أَكْثَرَ مِنْ خَمْسَةَ عَشَرَ يَوْمًا فَإِنَّهَا تَقْضِي صَلَاةَ أَرْبَعَةَ عَشَرَ يَوْمًا ثُمَّ تَدَعُ الصَّلَاةَ بَعْدَ ذَلِكَ أَقَلَّ مَا تَحِيضُ النِّسَاءُ وَهُوَ يَوْمٌ وَلَيْلَةٌ قَالَ أَبُو عِيسَى وَاخْتَلَفَ أَهْلُ الْعِلْمِ فِي أَقَلِّ الْحَيْضِ وَأَكْثَرِهِ فَقَالَ بَعْضُ أَهْلِ الْعِلْمِ أَقَلُّ الْحَيْضِ ثَلَاثَةٌ وَأَكْثَرُهُ عَشَرَةٌ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَأَهْلِ الْكُوفَةِ وَبِهِ يَأْخُذُ ابْنُ الْمُبَارَكِ وَرُوِيَ عَنْهُ خِلَافُ هَذَا و قَالَ بَعْضُ أَهْلِ الْعِلْمِ مِنْهُمْ عَطَاءُ بْنُ أَبِي رَبَاحٍ أَقَلُّ الْحَيْضِ يَوْمٌ وَلَيْلَةٌ وَأَكْثَرُهُ خَمْسَةَ عَشَرَ يَوْمًا وَهُوَ قَوْلُ مَالِكٍ وَالْأَوْزَاعِيِّ وَالشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ وَأَبِي عُبَيْدٍ","id":"telah menceritakan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Abu 'Amir Al Aqadi] berkata; telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Abdullah bin Muhammad bin Aqil] dari [Ibrahim bin Muhammad bin Thalhah] dari pamannya [Imran bin Thalhah] dari ibunya [Hamnah binti Jahsy] ia berkata; \"Aku banyak mengeluarkan darah haid yang banyak dan deras, maka aku mendatangi Nabi shallallahu 'alaihi wasallam untuk memberi kabar dan meminta fatwa kepadanya. Aku mendapati beliau di rumah saudara perempuanku, Zainab binti Jahsy, lalu aku berkata; \"Wahai Rasulullah, sesungguhnya aku mengeluarkan darah haid yang banyak dan deras, hal ini telah menghalangiku untuk shalat dan puasa, lalu apa yang engkau perintahkan kepadaku dalam hal ini?\" beliau bersabda: \"Berilah kapas, karena itu akan menghilangkan darah, \" ia berkata; \"Darahnya lebih banyak dari itu?\" beliau bersabda: \"Sumbatlah ia dengan sesuatu yang dapat menghalangi keluarnya darah, \" ia berkata; \"Darahnya sangat deras.\" Beliau bersabda: \"Ambillah kain, \" ia berkata; \"Darahnya lebih banyak dan deras, \" maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Akan aku perintahkan kepadamu dengan dua hal, manapun yang engkau lakukan maka itu telah cukup. Dan jika engkau mampu atas keduanya maka engkau lebih tahu.\" Beliau bersabda: \"Sesungguhnya itu adalah pukulan setan, maka berhaidlah selama enam atau tujuh hari dalam hitungan ilmu Allah, setelah itu mandilah. Jika engkau merasa bahwa engkau telah suci dan bersih maka shalatlah dua puluh empat malam atau dua puluh tiga siang dan malamnya, puasa dan shalatlah karena itu telah cukup bagimu. Seperti itu pula, lakukanlah sebagaimana wanita haid dan bersuci untuk waktu-waktu haid dan suci mereka. Jika kamu kuat mengakhirkan shalat zhuhur dan mensegerakan shalat asar, kemudian kalian mandi ketika kalian telah suci, lalu engkau shalat zhuhur dan asar. Setelah itu engkau akhirkan shalat maghrib dan mensegerakan shalat isya, lalu mandi dan menjamak antara dua shalat maka lakukanlah. Engkau mandi di waktu subuh maka kerjakanlah. Demikianlah, maka lakukanlah. Dan puasalah engkau jika kuat.\" Setelah itu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Itulah dua hal yang paling aku kagumi.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. [Ubaidullah bin Amru Ar Raqi] dan [Ibnu Juraij] dan [Syarik] meriwayatkan dari [Abdullah bin Muhammad bin Aqil] dari [Ibrahim bin Muhammad bin Thalhah] dari pamannya [Imran] dari ibunya [Hamnah]. Hanya saja Ibnu Juraij menyebutkan dengan nama Umar bin Thalhah. Yang benar adalah Imran bin Thalhah. Ia berkata; \"Aku bertanya Muhammad tentang hadits ini, maka ia pun bertanya, \"Hadits hasan shahih.\" Demikian juga dengan Ahmad bin Hanbal, ia mengatakan, \"Hadits ini derajatnya hasan shahih.\" Ahmad dan Ishaq berkata tentang wanita yang mustahadlah, \"Jika ia mengetahui haidnya……….maka hukumnya sebagaimana yang disebutkan dalam hadits Fatimah binti Abu Hubaisy. Jika wanita yang mengalami istihadlah itu mempunyai hari-hari yang diketahui sebelum istihadlah, maka hendaklah ia meninggalkan shalat pada hari-hari haidnya. Kemudian ia mandi dan berwudlu setiap shalat, maka ia boleh mengerjakan shalat. Apabila darah itu masih keluar dan ia tidak mempunyai hari-hari yang diketahui, atau tidak mengetahui haid dengan datang dan berlalunya darah, maka hukum yang sesuai baginya adalah hadits Hamnah binti Jahsy. Abu Ubaid juga berkata demikian. Syafi'i berkata; \"Apabila wanita yang mengalami istihadlah, darahnya selalu mengalir pada awal mula ia melihat dan terus-menerus seperti itu, maka ia harus meninggalkan shalat di antara waktu itu selama lima belas hari. Namun jika ia dalam keadaan suci dalam jangka waktu lima belas hari atau sebelum itu, maka itu termasuk hari-hari haid. Apabila wanita itu melihat darah lebih dari lima belas hari, maka ia harus mengqadla shalat selama empat belas hari. Kemudian setelah itu ia meninggalkan shalat selama masa haid yang paling sebentar untuk ukuran wanita, yaitu sehari semalam.\" Abu Isa berkata; \"Ulama berpeda pendapat tentang masa haid yang paling sebentar dan paling lama. Sebagian ulama berkata; \"Masa haid yang paling cepat adalah tiga hari dan yang paling lama adalah sepuluh hari.\" Ini adalah pendapat Sufyan Ats Tsauri, bin Al Mubarak dan penduduk Kufah. Dan sebagian ulama yang lain seperti 'Atha bin Abu Rabah mengatakan, \"Masa cepat yang paling cepat adalah sehari semalam, dan yang paling lama adalah lima belas hari. Ini adalah pendapat Malik, Al Auza'I, Syafi'i, Ahmad, Ishaq dan Abu Ubaid.\""},"119":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْاسْتَفْتَتْ أُمُّ حَبِيبَةَ ابْنَةُ جَحْشٍ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنِّي أُسْتَحَاضُ فَلَا أَطْهُرُ أَفَأَدَعُ الصَّلَاةَ فَقَالَ لَا إِنَّمَا ذَلِكَ عِرْقٌ فَاغْتَسِلِي ثُمَّ صَلِّي فَكَانَتْ تَغْتَسِلُ لِكُلِّ صَلَاةٍقَالَ قُتَيْبَةُ قَالَ اللَّيْثُ لَمْ يَذْكُرْ ابْنُ شِهَابٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ أُمَّ حَبِيبَةَ أَنْ تَغْتَسِلَ عِنْدَ كُلِّ صَلَاةٍ وَلَكِنَّهُ شَيْءٌ فَعَلَتْهُ هِيَ قَالَ أَبُو عِيسَى وَيُرْوَى هَذَا الْحَدِيثُ عَنْ الزُّهْرِيِّ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْ اسْتَفْتَتْ أُمُّ حَبِيبَةَ بِنْتُ جَحْشٍ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ قَالَ بَعْضُ أَهْلِ الْعِلْمِ الْمُسْتَحَاضَةُ تَغْتَسِلُ عِنْدَ كُلِّ صَلَاةٍ وَرَوَى الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ وَعَمْرَةَ عَنْ عَائِشَةَ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Urwah] dari ['Aisyah] bahwasanya ia berkata; \"Ummu Habibah binti Jahsy meminta fatwa Rasulullah shallallahu 'alaihi wasallam, ia berkata; \"Sesungguhnya aku mengalami istihadlah, sehingga aku menjadi tidak suci, maka apakah aku harus meninggalkan shalat?\" beliau bersabda: \"Tidak, itu hanyalah darah penyakit, hendaklah engkau mandi dan shalat.\" Maka Ummu Habibah pun selalu mandi ketika akan shalat.\" Qutaibah berkata; \"Al Laits berkata; \"Ibnu Syihab tidak menyebutkan bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan Ummu Habibah untuk mandi setiap kali akan shalat, namun itu adalah sesuatu yang biasa ia lakukan.\" Abu Isa berkata; \"Hadits ini juga diriwayatkan dari Az Zuhri, dari Amrah, dari 'Aisyah, ia berkata; \"Ummu Habibah binti Jahasy meminta fatwa Rasulullah shallallahu 'alaihi wasallam.\" Dan sebagian ulama mengatakan bahwa wanita yang mengalami istihadlah hendaknya mandi pada setiap kali akan shalat.\" [Al Auza'i] meriwayatkan dari [Az Zuhri] dari [Urwah] dan [Amrah] dari ['Aisyah]."},"120":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ مُعَاذَةَأَنَّ امْرَأَةً سَأَلَتْ عَائِشَةَ قَالَتْ أَتَقْضِي إِحْدَانَا صَلَاتَهَا أَيَّامَ مَحِيضِهَا فَقَالَتْ أَحَرُورِيَّةٌ أَنْتِ قَدْ كَانَتْ إِحْدَانَا تَحِيضُ فَلَا تُؤْمَرُ بِقَضَاءٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ عَائِشَةَ مِنْ غَيْرِ وَجْهٍ أَنَّ الْحَائِضَ لَا تَقْضِي الصَّلَاةَ وَهُوَ قَوْلُ عَامَّةِ الْفُقَهَاءِ لَا اخْتِلَافَ بَيْنَهُمْ فِي أَنَّ الْحَائِضَ تَقْضِي الصَّوْمَ وَلَا تَقْضِي الصَّلَاةَ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Mu'adzah] bahwa seorang wanita bertanya kepada ['Aisyah], ia berkata; \"Apakah salah seorang dari kami harus mengqadla shalatnya ketika masa-masa haid?\" maka ia menjawab, \"Apakah engkau Haruriah (khawarij)? Sungguh di antara kami (istri-istri Nabi) ada yang mengalami haid, namun ia tidak diperintahkan untuk mengqadlanya.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, ada juga yang telah meriwayatkan dari 'Aisyah bukan dari jalur ini, bahwa seorang wanita haid tidak harus mengqadla shalatnya. Ini adalah pendapat yang diambil oleh mayoritas fuqaha, dan tidak ada perselisihan di antara mereka bahwa seorang wanita yang mengalami haid harus mengqadla puasa dan tidak mengqadla shalat.\""},"121":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ وَالْحَسَنُ بْنُ عَرَفَةَ قَالَا حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقْرَأْ الْحَائِضُ وَلَا الْجُنُبُ شَيْئًا مِنْ الْقُرْآنِقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ إِسْمَعِيلَ بْنِ عَيَّاشٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقْرَأْ الْجُنُبُ وَلَا الْحَائِضُ وَهُوَ قَوْلُ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ مِثْلِ سُفْيَانَ الثَّوْرِيِّ وَابْنِ الْمُبَارَكِ وَالشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ قَالُوا لَا تَقْرَأْ الْحَائِضُ وَلَا الْجُنُبُ مِنْ الْقُرْآنِ شَيْئًا إِلَّا طَرَفَ الْآيَةِ وَالْحَرْفَ وَنَحْوَ ذَلِكَ وَرَخَّصُوا لِلْجُنُبِ وَالْحَائِضِ فِي التَّسْبِيحِ وَالتَّهْلِيلِ قَالَ و سَمِعْت مُحَمَّدَ بْنَ إِسْمَعِيلَ يَقُولُ إِنَّ إِسْمَعِيلَ بْنَ عَيَّاشٍ يَرْوِي عَنْ أَهْلِ الْحِجَازِ وَأَهْلِ الْعِرَاقِ أَحَادِيثَ مَنَاكِيرَ كَأَنَّهُ ضَعَّفَ رِوَايَتَهُ عَنْهُمْ فِيمَا يَنْفَرِدُ بِهِ وَقَالَ إِنَّمَا حَدِيثُ إِسْمَعِيلَ بْنَ عَيَّاشٍ عَنْ أَهْلِ الشَّأْمِ و قَالَ أَحْمَدُ بْنُ حَنْبَلٍ إِسْمَعِيلُ بْنُ عَيَّاشٍ أَصْلَحُ مِنْ بَقِيَّةَ وَلِبَقِيَّةَ أَحَادِيثُ مَنَاكِيرُ عَنْ الثِّقَاتِ قَالَ أَبُو عِيسَى حَدَّثَنِي أَحْمَدُ بْنُ الْحَسَنِ قَال سَمِعْتُ أَحْمَدَ بْنَ حَنْبَلٍ يَقُولُ ذَلِكَ","id":"telah menceritakan kepada kami [Ali bin Hujr] dan [Al Hasan bin Arafah] keduanya berkata; telah bercerita kepada kami bahwa [Isma'il bin Ayyasy] dari [Musa bin Uqbah] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Wanita haid dan orang yang junub tidak boleh membaca sesuatu pun dari Al Qur'an.\" Ia berkata; \"Dalam bab ini ada juga hadits dari Ali.\" Abu Isa berkata; \"Hadits Ibnu Umar, kami tidak mengetahuinya kecuali dari hadits Isma'il bin Ayyasy, dari Musa bin Uqbah, dari Nafi', dari Ibnu Umar, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda, \"Seorang yang junub dan wanita haid tidak boleh membaca Al Qur`an.\" Ini adalah pendapat kebanyakan ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang setelah mereka seperti Sufyan Ats Tsauri, bin Al Mubarak, Syafi'i, Ahmad dan Ishaq. Mereka mengatakan, \"Wanita haid dan orang junub tidak boleh membaca sesuatu dari Al Qur'an, kecuali ujung ayat, atau satu huruf, serta yang semisalnya. Namun mereka memberi keringan bagi orang junub dan wanita haid untuk membaca tasbih (Subhanallah) dan tahlil (Laa Ilaaha Illalaah).\" Abu Isa berkata; \"Aku mendengar Muhammad bin Isma'il berkata; \"Sesungguhya banyak hadits munkar telah diriwayatkan oleh Isma'il bin Ayyasy dari penduduk Hijaz dan penduduk Irak, sepertinya dia melemahkan riwayat Isma'il bin Ayyasy dari mereka, apabila ia dalam meriwayatkannya sendirian.\" Ia berkata; \"Akan tetapi hadits Isma'il bin Ayyasy adalah dari penduduk Syam.\" Ahmad bin Hambal berkata; \"Isma'il bin Ayyasy lebih baik dari Baqiyyah, karena Baqiyyah mempunyai hadits-hadits munkar yang diriwayatkannya dari orang-orang tsiqqah (dapat dipercaya).\" Abu Isa berkata; \"Ahmad bin Al Hasan telah bercerita kepadaku, ia berkata; \"Aku mendengar Ahmad bin Hambal berkata seperti itu.\""},"122":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ مِنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حِضْتُ يَأْمُرُنِي أَنْ أَتَّزِرَ ثُمَّ يُبَاشِرُنِيقَالَ وَفِي الْبَاب عَنْ أُمِّ سَلَمَةَ وَمَيْمُونَةَ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَبِهِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ","id":"telah menceritakan kepada kami [Bundar] berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] ia berkata; \"Jika aku sedang haid Rasulullah shallallahu 'alaihi wasallam menyuruhku memakai kain, lalu beliau mencumbuiku.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ummu Salamah dan Maimunah.\" Abu Isa berkata; \"Hadits 'Aisyah ini derajatnya hasan shahih. Ini adalah pendapat banyak ulama dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in. Pendapat ini juga dipegang oleh Syafi'i, Ahmad dan Ishaq.\""},"123":{"ar":"حَدَّثَنَا عَبَّاسٌ الْعَنْبَرِيُّ وَمُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ الْعَلَاءِ بْنِ الْحَارِثِ عَنْ حَرَامِ بْنِ مُعَاوِيَةَ عَنْ عَمِّهِ عَبْدِ اللَّهِ بْنِ سَعْدٍ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ مُوَاكَلَةِ الْحَائِضِ فَقَالَ وَاكِلْهَاقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَأَنَسٍ قَالَ أَبُو عِيسَى حَدِيثُ عَبْدِ اللَّهِ بْنِ سَعْدٍ حَدِيثٌ حَسَنٌ غَرِيبٌ وَهُوَ قَوْلُ عَامَّةِ أَهْلِ الْعِلْمِ لَمْ يَرَوْا بِمُوَاكَلَةِ الْحَائِضِ بَأْسًا وَاخْتَلَفُوا فِي فَضْلِ وَضُوئِهَا فَرَخَّصَ فِي ذَلِكَ بَعْضُهُمْ وَكَرِهَ بَعْضُهُمْ فَضْلَ طَهُورِهَا","id":"telah menceritakan kepada kami [Abbas Al 'Anbari] dan [Muhammad bin Abd Al A'la] mereka berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] berkata; telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Al 'Ala` bin Al Harits] dari [Haram bin Mu'awiyah] dari pamannya [Abdullah bin Sa'd] ia berkata; \"Aku bertanya Nabi shallallahu 'alaihi wasallam tentang makan bersama wanita haid, maka beliau bersabda: \"Makanlah bersamanya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari 'Aisyah dan Anas.\" Abu Isa berkata; \"Hadits riwayat Abdullah bin Sa'd ini derajatnya hasan gharib. Ini adalah pendapat mayoritas ahli ilmu, mereka berpandangan bahwa makan bersama dengan wanita haid tidaklah mengapa. Namun mereka berselisih tentang sisa air wudlunya, sebagian dari mereka memberi keringanan dan sebagian yang lain memakruhkannya.\""},"124":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ عَنْ الْأَعْمَشِ عَنْ ثابِتِ بْنِ عُبَيْدٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ قَالَقَالَتْ لِي عَائِشَةُ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاوِلِينِي الْخُمْرَةَ مِنْ الْمَسْجِدِ قَالَتْ قُلْتُ إِنِّي حَائِضٌ قَالَ إِنَّ حَيْضَتَكِ لَيْسَتْ فِي يَدِكِقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ عَامَّةِ أَهْلِ الْعِلْمِ لَا نَعْلَمُ بَيْنَهُمْ اخْتِلَافًا فِي ذَلِكَ بِأَنْ لَا بَأْسَ أَنْ تَتَنَاوَلَ الْحَائِضُ شَيْئًا مِنْ الْمَسْجِدِ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Ubaidah bin Humaid] dari [Al A'masy] dari [Tsabit bin Ubaid] dari [Al Qasim bin Muhammad] ia berkata; \" ['Aisyah] berkata kepadaku, \"Rasulullah shallallahu 'alaihi wasallam pernah bersabda kepadaku: \"Ambilkanlah tikar kecil dari masjid, \" 'Aisyah berkata; \"Lalu aku berkata; \"Aku sedang haid, \" beliau bersabda: \"Sesungguhnya darah haidmu tidak berada di tanganmu.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Umar dan Abu Hurairah.\" Abu Isa berkata; \"Hadits 'Aisyah ini derajatnya hasan shahih. Ini adalah pendapat mayoritas ahli ilmu, dan kami tidak mengetahui mereka berselisih dalam hal ini. Yaitu, bahwa wanita haid boleh mengambil sesuatu dari dalam masjid.\""},"125":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَبَهْزُ بْنُ أَسَدٍ قَالُوا حَدَّثَنَا حَمَادُ بْنُ سَلَمَةِ عَنْ حَكِيمٍ الْأَثْرَمِ عَنْ أَبِي تَمِيمَةَ الهُجَيْمِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَ��ْ أَتَى حَائِضًا أَوْ امْرَأَةً فِي دُبُرِهَا أَوْ كَاهِنًا فَقَدْ كَفَرَ بِمَا أُنْزِلَ عَلَى مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عِيسَى لَا نَعْرِفُ هَذَا الْحَدِيثَ إِلَّا مِنْ حَدِيثِ حَكِيمٍ الْأَثْرَمِ عَنْ أَبِي تَمِيمَةَ الْهُجَيْمِيِّ عَنْ أَبِي هُرَيْرَةَ وَإِنَّمَا مَعْنَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ عَلَى التَّغْلِيظِ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَتَى حَائِضًا فَلْيَتَصَدَّقْ بِدِينَارٍ فَلَوْ كَانَ إِتْيَانُ الْحَائِضِ كُفْرًا لَمْ يُؤْمَرْ فِيهِ بِالْكَفَّارَةِ وَضَعَّفَ مُحَمَّدٌ هَذَا الْحَدِيثَ مِنْ قِبَلِ إِسْنَادِهِ وَأَبُو تَمِيمَةَ الْهُجَيْمِيِّ اسْمُهُ طَرِيفُ بْنُ مُجَالِدٍ","id":"telah menceritakan kepada kami [Bundar] berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dan [Abdurrahman bin Mahdi] dan [Bahz bin Asad] mereka berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Hakim Al Atsram] dari [Abu Tamimah Al Hujaimi] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa menggauli wanita haid, atau menggauli wanita dari dubur, atau mendatangi dukun maka ia telah kafir terhadap apa yang diturunkan kepada Muhammad shallallahu 'alaihi wasallam.\" Abu Isa berkata; \"Kami tidak mengetahui hadits ini kecuali dari hadits Hakim Al Atsram, dari Abu Tamimah Al Hujaimi, dari Abu Hurairah. Dan hanyasanya makna hadits ini menurut ahli ilmu adalah sebagai pemberat saja. Telah diriwayatkan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa mendatangi (mensetubuhi) wanita haid, maka hendaklah bersedekah dengan satu dinar.\" Sekiranya mendatangi wanita yang sedang haid sebuah kekufuran, maka ia tidak akan diperintahkan untuk bersedekah sebagai kafarahnya! Namun Muhammad melemahkan hadits ini dari sisi sanadnya. Dan Abu Tamimah Al Hujaimi namnya adalah Tharif bin Mujalid.\""},"126":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا شَرِيكٌ عَنْ خُصَيْفٍ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الرَّجُلِ يَقَعُ عَلَى امْرَأَتِهِ وَهِيَ حَائِضٌ قَالَ يَتَصَدَّقُ بِنِصْفِ دِينَارٍ","id":"telah menceritakan kepada kami [Ali bin Hujr] berkata; telah mengabarkan kepada kami [Syarik] dari [Khushaim] dari [Miqsam] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam tentang seorang laki-laki yang mendatangi isterinya di saat haid, beliau bersabda: \"Barangsiapa mendatangi isterinya yang sedang haid hendaklah bersedekah dengan setengah dinar.\""},"127":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ أَخْبَرَنَا الْفَضْلُ بْنُ مُوسَى عَنْ أَبِي حَمْزَةَ السُّكَّرِيِّ عَنْ عَبْدِ الْكَرِيمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ دَمًا أَحْمَرَ فَدِينَارٌ وَإِذَا كَانَ دَمًا أَصْفَرَ فَنِصْفُ دِينَارٍقَالَ أَبُو عِيسَى حَدِيثُ الْكَفَّارَةِ فِي إِتْيَانِ الْحَائِضِ قَدْ رُوِيَ عَنْ ابْنِ عَبَّاسٍ مَوْقُوفًا وَمَرْفُوعًا وَهُوَ قَوْلُ بَعْضِ أَهْلِ الْعِلْمِ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ قَالَ ابْنُ الْمُبَارَكِ يَسْتَغْفِرُ رَبَّهُ وَلَا كَفَّارَةَ عَلَيْهِ وَقَدْ رُوِيَ نَحْوُ قَوْلِ ابْنِ الْمُبَارَكِ عَنْ بَعْضِ التَّابِعِينَ مِنْهُمْ سَعِيدُ بْنُ جُبَيْرٍ وَإِبْرَاهِيمُ النَّخَعِيُّ وَهُوَ قَوْلُ عَامَّةِ عُلَمَاءِ الْأَمْصَارِ","id":"telah menceritakan kepada kami [Al Husain bin Huraits] berkata; telah mengabarkan kepada kami [Al Fadll bin Musa] dari [Abu Hamzah As Sukkari] dari [Abdul Karim] dari [Miqsam] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika darah tersebut warnanya merah maka dendanya satu dinar, dan jika warnanya kuning maka dendanya adalah setengah dinar.\" Abu Isa berkata; \"Hadits yang berbicara masalah denda menggauli wanita yang sedang haid diriwayatkan oleh Ibnu Abbas dengan riwayat mauquf dan marfu'. Ini adalah perkataan sebagian ahli ilmu. Dan pendapat ini juga diambil oleh Ahmad dan Ishaq. bin Al Mubarak berkata; \"Hendaklah ia meminta maaf kepada Rabbnya dan tidak ada kafarah.\" Perkataan seperti bin Al Mubarak ini juga diriwayatkan dari sebagian ulama tabi'in, seperti Sa'id bin Jubair dan Ibrahim An Nakha'I. Dan ini adalah perkataan kebanyakan ulama dunia.\""},"128":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍأَنَّ امْرَأَةً سَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الثَّوْبِ يُصِيبُهُ الدَّمُ مِنْ الْحَيْضَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُتِّيهِ ثُمَّ اقْرُصِيهِ بِالْمَاءِ ثُمَّ رُشِّيهِ وَصَلِّي فِيهِقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأُمِّ قَيْسِ بْنتِ مِحْصَنٍ قَالَ أَبُو عِيسَى حَدِيثُ أَسْمَاءَ فِي غَسْلِ الدَّمِ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ اخْتَلَفَ أَهْلُ الْعِلْمِ فِي الدَّمِ يَكُونُ عَلَى الثَّوْبِ فَيُصَلِّي فِيهِ قَبْلَ أَنْ يَغْسِلَهُ قَالَ بَعْضُ أَهْلِ الْعِلْمِ مِنْ التَّابِعِينَ إِذَا كَانَ الدَّمُ مِقْدَارَ الدِّرْهَمِ فَلَمْ يَغْسِلْهُ وَصَلَّى فِيهِ أَعَادَ الصَّلَاةَ و قَالَ بَعْضُهُمْ إِذَا كَانَ الدَّمُ أَكْثَرَ مِنْ قَدْرِ الدِّرْهَمِ أَعَادَ الصَّلَاةَ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَابْنِ الْمُبَارَكِ وَلَمْ يُوجِبْ بَعْضُ أَهْلِ الْعِلْمِ مِنْ التَّابِعِينَ وَغَيْرِهِمْ عَلَيْهِ الْإِعَادَةَ وَإِنْ كَانَ أَكْثَرَ مِنْ قَدْرِ الدِّرْهَمِ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ و قَالَ الشَّافِعِيُّ يَجِبُ عَلَيْهِ الْغَسْلُ وَإِنْ كَانَ أَقَلَّ مِنْ قَدْرِ الدِّرْهَمِ وَشَدَّدَ فِي ذَلِكَ","id":"telah menceritakan kepada kami [Ibnu Abu Umar] berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Hisyam bin Urwah] dari [Fathimah binti Al Mundzir] dari [Asma binti Abu Bakr] berkata; \"Seorang wanita bertanya Nabi shallallahu 'alaihi wasallam tentang pakaian yang terkena darah haid?\" maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Gosoklah kain tersebut, kemudian basahi dan basuhlah dengan air, setelah itu shalatlah dengannya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Hurairah dan Ummu Qais binti Mihshan.\" Abu Isa berkata; \"Hadits Asma tentang mencuci darah haid derajatnya hasan shahih.\" Para ulama telah berbeda pendapat tentang darah yang mengenai kain lalu dipakai shalat sebelum dicuci. Sebagian ulama dari tabi'in berkata; \"Apabila darah tersebut seukuran (sebesar) dirham, lalu ia mengenakannya sebelum dicuci, maka ia harus mengulangi shalatnya.\" Sedangkan sebagian yang lain berkata; \"Apabila darah itu lebih besar dari ukuran satu dirham, maka ia harus mengulangi shalatnya.\" Pendapat ini dipegang oleh Sufyan Ats Tsauri dan bin Al Mubarak. Namun sebagian ulama yang lain dari kalangan tabi'in dan selainnya tidak mewajibkan untuk mengulangi shalatnya, meskipun darah itu lebih banyak (besar) dari uang dirham. Pendapat ini dipegang oleh Ahmad dan Ishaq. Syafi'i berkata; \"Wajib mencucinya meskipun darahnya kurang daru seukuran uang dirham.\" Dan Ia berpegang teguh dengan itu.\""},"129":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا شُجَاعُ بْنُ الْوَلِيدِ أَبُو بَدْرٍ عَنْ عَلِيِّ بْنِ عَبْدِ الْأَعْلَى عَنْ أَبِي سَهْلٍ عَنْ مُسَّةَ الْأَزْدِيَّةِ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَتْ النُّفَسَاءُ تَجْلِسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعِينَ يَوْمًا فَكُنَّا نَطْلِي وُجُوهَنَا بِالْوَرْسِ مِنْ الْكَلَفِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ أَبِي سَهْلٍ عَنْ مُسَّةَ الْأَزْدِيَّةِ عَنْ أُمِّ سَلَمَةَ وَاسْمُ أَبِي سَهْلٍ كَثِيرُ بْنُ زِيَادٍ قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ عَلِيُّ بْنُ عَبْدِ الْأَعْلَى ثِقَةٌ وَأَبُو سَهْلٍ ثِقَةٌ وَلَمْ يَعْرِفْ مُحَمَّدٌ هَذَا الْحَدِيثَ إِلَّا مِنْ حَدِيثِ أَبِي سَهْلٍ وَقَدْ أَجْمَعَ أَهْلُ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ عَلَى أَنَّ النُّفَسَاءَ تَدَعُ الصَّلَاةَ أَرْبَعِينَ يَوْمًا إِلَّا أَنْ تَرَى الطُّهْرَ قَبْلَ ذَلِكَ فَإِنَّهَا تَغْتَسِلُ وَتُصَلِّي فَإِذَا رَأَتْ الدَّمَ بَعْدَ الْأَرْبَعِينَ فَإِنَّ أَكْثَرَ أَهْلِ الْعِلْمِ قَالُوا لَا تَدَعُ الصَّلَاةَ بَعْدَ الْأَرْبَعِينَ وَهُوَ قَوْلُ أَكْثَرِ الْفُقَهَاءِ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ وَيُرْوَى عَنْ الْحَسَنِ الْبَصْرِيِّ أَنَّهُ قَالَ إِنَّهَا تَدَعُ الصَّلَاةَ خَمْسِينَ يَوْمًا إِذَا لَمْ تَرَ الطُّهْرَ وَيُرْوَى عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ وَالشَّعْبِيِّ سِتِّينَ يَوْمًا","id":"telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata; telah menceritakan kepada kami [Syuja' bin Al Walid Abu Badr] dari [Ali bin Abdul A'la] dari [Abu Sahl] dari [Mussah Al Azdiah] dari [Ummu Salamah] ia berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam wanita-wanita yang habis melahirkan duduk berdiam diri selama empat puluh hari, kami memoles wajah kami dengan waras (sejenis tumbuhan) karena sebab warna hitam.\" Abu Isa berkata; \"Ini adalah hadits gharib, kami tidak mengetahuinya kecuali dari hadits Abu Sahl, dari Mussah Al Azdiah dari Ummu Salamah.\" Dan Nama Abu Sahl adalah Katsir bin Ziyad. Dalam hal ini Muhammad bin Isma'il berkata; \"Ali bin Abdul A'la dan Abu Sahl adalah orang yang terpercaya.\" Dan Muhammad tidak mengetahui hadits ini kecuali dari hadits Abu Sahl. Para ulama telah sepakat bahwa para sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang sesudah mereka telah sepakat, bahwa wanita yang habis melahirkan boleh meninggalkan shalat selama empat puluh hari, kecuali jika ia telah suci sebelum itu, maka ia harus mandi dan shalat. Apabila ia melihat darah setelah empat puluh hari, maka sebagian ulama berkata; \"Ia tidak boleh meninggalkan shalat setelah empat puluh hari.\" Ini adalah pendapat sebagian besar fuqaha seperti Sufyan Ats Tsauri, bin Al Mubarak, Syafi'i, Ahmad dan Ishaq. Dan diriwayatkan pula dari Al Hasan Al Bashri, ia berkata; \"Sesungguhnya wanita yang habis melahirkan ia tidak shalat selama lima puluh hari jika ia tidak melihat bahwa ia telah suci.\" Dan diriwayatkan pula dari 'Atha bin Abu Rabah dan Asy Sya'bi; yaitu enam puluh hari.\""},"130":{"ar":"حَدَّثَنَا بُنْدَارٌ مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ مَعْمَرٍ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَطُوفُ عَلَى نِسَائِهِ فِي غُسْلٍ وَاحِدٍقَالَ وَفِي الْبَاب عَنْ أَبِي رَافِعٍ قَالَ أَبُو عِيسَى حَدِيثُ أَنَسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَطُوفُ عَلَى نِسَائِهِ بِغُسْلٍ وَاحِدٍ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ مِنْهُمْ الْحَسَنُ الْبَصْرِيُّ أَنْ لَا بَأْسَ أَنْ يَعُودَ قَبْلَ أَنْ يَتَوَضَّأَ وَقَدْ رَوَى مُحَمَّدُ بْنُ يُوسُفَ هَذَا عَنْ سُفْيَانَ فَقَالَ عَنْ أَبِي عُرْوَةَ عَنْ أَبِي الْخَطَّابِ عَنْ أَنَسٍ وَأَبُو عُرْوَةَ هُوَ مَعْمَرُ بْنُ رَاشِدٍ وَأَبُو الْخَطَّابِ قَتَادَةُ بْنُ دِعَامَةَ قَالَ أَبُو عِيسَى وَرَوَاهُ بَعْضُهُمْ عَنْ مُحَمَّدِ بْنِ يُوسُفَ عَنْ سُفْيَانَ عَنْ ابْنِ أَبِي عُرْوَةَ عَنْ أَبِي الْخَطَّابِ وَهُوَ خَطَأٌ وَالصَّحِيحُ عَنْ أَبِي عُرْوَةَ","id":"telah menceritakan kepada kami [Bundar Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Abu Ahmad] berkata; telah menceritakan kepada kami [Sufyan] dari [Ma'mar] dari [Qatadah] dari [Anas] berkata; \"Nabi shallallahu 'alaihi wasallam pernah menggilir para istrinya dalam satu mandi.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Rafi'.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, bahwa Nabi shallallahu 'alaihi wasallam mengilir semua istrinya dengan satu kali mandi.\" Ini adalah pendapat banyak ahli ilmu, di antara mereka adalah Al Hasan Al Bashri, bahwa seseorang tidak dipermasalahkan untuk mengulangi (bersetubuh) meskipun belum berwudlu.\" [Muhammad bin Yusuf] meriwayatkan hadits ini dari [Sufyan], -Abu Urwah mengatakan dari Abu Al Khaththab-, dari [Anas], Abu Urwah -dia adalah Ma'mar bin Rasyid-, dan Abu Al khaththab Qatadah bin Di'amah. Abu Isa berkata; \"Sebagian mereka meriwayatkan dari Muhammad bin Yusuf, dari Sufyan, dari Ibnu Abu Urwah dari Abu Al Khaththab.\""},"131":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَتَى أَحَدُكُمْ أَهْلَهُ ثُمَّ أَرَادَ أَنْ يَعُودَ فَلْيَتَوَضَّأْ بَيْنَهُمَا وُضُوءًاقَالَ وَفِي الْبَاب عَنْ عُمَرَ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي سَعِيدٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ عُمَرَ بْنِ الْخَطَّابِ و قَالَ بِهِ غَيْرُ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ قَالُوا إِذَا جَامَعَ الرَّجُلُ امْرَأَتَهُ ثُمَّ أَرَادَ أَنْ يَعُودَ فَلْيَتَوَضَّأْ قَبْلَ أَنْ يَعُودَ وَأَبُو الْمُتَوَكِّلِ اسْمُهُ عَلِيُّ بْنُ دَاوُدَ وَأَبُو سَعِيدٍ الْخُدْرِيُّ اسْمُهُ سَعْدُ بْنُ مَالِكِ بْنِ سِنَانٍ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Hafsh bin Ghiyats] dari ['Ashim Al Ahwal] dari [Abu Al Mutawakkil] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari kalian mendatangi istrinya dan ingin mengulanginya, maka hendaklah ia berwudlu di antara keduanya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Umar.\" Abu Isa berkata; \"Hadits riwayat Abu Sa'id ini derajatnya hasan shahih. Ini adalah pendapat Umar bin Al Khaththab. Dan tidak sedikit pula dari kalangan ahli ilmu yang berpegang dengan pendapat ini, mereka mengatakan, \"Jika seorang laki-laki mensetubuhi istrinya dan ingin mengulanginya lagi, maka hendaklah ia berwudlu terlebih dahulu.\" Abu Al Mutawakkil namanya adalah Ali bin Dawud. Sedangkan Abu Sa'id Al Khudri namanya adalah Sa'd bin Malik bin Sinan.\""},"132":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ الْأَرْقَمِ قَالَأُقِيمَتْ الصَّلَاةُ فَأَخَذَ بِيَدِ رَجُلٍ فَقَدَّمَهُ وَكَانَ إِمَامَ قَوْمِهِ وَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا أُقِيمَتْ الصَّلَاةُ وَوَجَدَ أَحَدُكُمْ الْخَلَاءَ فَلْيَبْدَأْ بِالْخَلَاءِقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَأَبِي هُرَيْرَةَ وَثَوْبَانَ وَأَبِي أُمَامَةَ قَالَ أَبُو عِيسَى حَدِيثُ عَبْدِ اللَّهِ بْنِ الْأَرْقَمِ حَدِيثٌ حَسَنٌ صَحِيحٌ هَكَذَا رَوَى مَالِكُ بْنُ أَنَسٍ وَيَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ وَغَيْرُ وَاحِدٍ مِنْ الْحُفَّاظِ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ الْأَرْقَمِ وَرَوَى وُهَيْبٌ وَغَيْرُهُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ رَجُلٍ عَنْ عَبْدِ اللَّهِ بْنِ الْأَرْقَمِ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ قَالَا لَا يَقُومُ إِلَى الصَّلَاةِ وَهُوَ يَجِدُ شَيْئًا مِنْ الْغَائِطِ وَالْبَوْلِ وَقَالَا إِنْ دَخَلَ فِي الصَّلَاةِ فَوَجَدَ شَيْئًا مِنْ ذَلِكَ فَلَا يَنْصَرِفْ مَا لَمْ يَشْغَلْهُ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ لَا بَأْسَ أَنْ يُصَلِّيَ وَبِهِ غَائِطٌ أَوْ بَوْلٌ مَا لَمْ يَشْغَلْهُ ذَلِكَ عَنْ الصَّلَاةِ","id":"telah menceritakan kepada kami [Hannad bin As Sari] berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hisyam bin Urwah] dari [Ayahnya] dari [Abdullah bin Al Arqam] ia berkata; \"Iqamah telah dikumandangkan, lalu ia mengambil tangan seorang laki-laki seraya menyuruhnya ke depan, padahal ia adalah imam bagi kaumnya. Lalu ia berkata; \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika shalat telah dikumandangkan, dan salah seorang dari kalian ingin ke WC, maka hendaklah ia ke WC terlebih dahulu.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari 'Aisyah, Abu Hurairah, Tsauban dan Abu Umamah.\" Abu Isa berkata; \"Hadits Abdullah bin Al Arqam adalah hadits hasan shahih. Seperti inilah [Malik bin Anas] dan [Yahya bin Sa'id Al Qaththan] dan tidak sedikit pula dari kalangan penghafal (ahli hadits) meriwayatkan dari [Hisyam bin Urwah] dari [ayahnya] dari [Abdullah bin Al Arqam].\" [Wuhaib] dan selainnya juga meriwayatkan dari [Hisyam bin Urwah] dari [ayahnya] dari [seorang laki-laki] dari [Abdullah bin Al Arqam]. Ini adalah pendapat tidak seorang saja dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in. Pendapat ini juga dipegang oleh Ahmad dan Ishaq, mereka mengatakan, \"Janganlah seseorang melakukan shalat jika ia merasakan (ingin) buang air besar atau air kecil.\" Mereka berkata lagi, \"Jika ia telah berdiri shalat, ia tidak harus membatalkan shalatnya selama hal itu tidak mengganggu.\" Sebagian ahli ilmu berpendapat, \"Seseorang tidak apa-apa melaksanakan shalat dalam keadaan ingin buang air besar atau air kecil, selama hal itu tidak mengganggunya dalam shalat.\""},"133":{"ar":"حَدَّثَنَا أَبُو رَجَاءٍ قُتَيْبَةُ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ مُحَمَّدِ بْنِ عُمَارَةَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أُمِّ وَلَدٍ لِعَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ قَالَتْ قُلْتُ لِأُمِّ سَلَمَةَإِنِّي امْرَأَةٌ أُطِيلُ ذَيْلِي وَأَمْشِي فِي الْمَكَانِ الْقَذِرِ فَقَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُطَهِّرُهُ مَا بَعْدَهُقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَتَوَضَّأُ مِنْ الْمَوْطَإِ قَالَ أَبُو عِيسَى وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ قَالُوا إِذَا وَطِيءَ الرَّجُلُ عَلَى الْمَكَانِ الْقَذِرِ أَنَّهُ لَا يَجِبُ عَلَيْهِ غَسْلُ الْقَدَمِ إِلَّا أَنْ يَكُونَ رَطْبًا فَيَغْسِلَ مَا أَصَابَهُ قَالَ أَبُو عِيسَى وَرَوَى عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ هَذَا الْحَدِيثَ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ مُحَمَّدِ بْنِ عُمَارَةَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أُمِّ وَلَدٍ لِهُودِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أُمِّ سَلَمَةَ وَهُوَ وَهَمٌ وَلَيْسَ لِعَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ ابْنٌ يُقَالَ لَهُ هُودٌ وَإِنَّمَا هُوَ عَنْ أُمِّ وَلَدٍ لِإِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أُمِّ سَلَمَةَ وَهَذَا الصَّحِيحُ","id":"telah menceritakan kepada kami [Abu Raja` Qutaibah] berkata; telah menceritakan kepada kami [Malik bin Anas] dari [Muhammad bin Umarah] dari [Muhammad bin Ibrahim] dari [budak wanita milik Abdurrahman bin Auf] ia berkata; \"Aku pernah berkata kepada [Ummu Salamah], \"Sesungguhnya aku ini adalah seorang wanita yang kainnya panjang, dan aku berjalan di tempat yang kotor?\" lalu ia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Kain akan suci dengan tanah setelahnya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin Mas'ud, ia berkata; \"Aku pernah bersama Rasulullah shallallahu 'alaihi wasallam di tempat yang kotor, dan kami tidak berwudlu.\" Abu Isa berkata; \"Tidak hanya seorang dari ahli ilmu yang berpendapat seperti ini, mereka mengatakan, \"Seseorang yang menginjak tempat kotor tidak harus membasuh telapak kakinya kecuali jika kotoran tersebut masih basah, maka ia dianjurkan untuk menghilangkan bekasnya.\" Abu Isa berkata; \" [Abdullah bin Al Mubarak] juga meriwayatkan hadits ini dari [Malik bin Anas] dari [Muhammad bin Umarah] dari [Muhammad bin Ibrahim] dari [budak wanita milik Hud bin Abdurrahman bin Auf] dari [Ummu Salamah]. Tapi di dalamnya ada keraguan, sebab Abdurrahman bin Auf tidak mempunyai anak yang bernama Hud. Tapi itu adalah riwayat dari budak wanita milik Ibrahim bin Abdurrahman bin Auf dari Ummu Salamah, dan inilah yang benar.\""},"134":{"ar":"حَدَّثَنَا أَبُو حَفْصٍ عَمْرُو بْنُ عَلِيٍّ الْفَلَّاسُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ عَزْرَةَ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ عَمَّارِ بْنِ يَاسِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُ بِالتَّيَمُّمِ لِلْوَجْهِ وَالْكَفَّيْنِقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى حَدِيثُ عَمَّارٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ عَمَّارٍ مِنْ غَيْرِ وَجْهٍ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ عَلِيٌّ وَعَمَّارٌ وَابْنُ عَبَّاسٍ وَغَيْرِ وَاحِدٍ مِنْ التَّابِعِينَ مِنْهُمْ الشَّعْبِيُّ وَعَطَاءٌ وَمَكْحُولٌ قَالُوا التَّيَمُّمُ ضَرْبَةٌ لِلْوَجْهِ وَالْكَفَّيْنِ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ مِنْهُمْ ابْنُ عُمَرَ وَجَابِرٌ وَإِبْرَاهِيمُ وَالْحَسَنُ قَالُوا التَّيَمُّمُ ضَرْبَةٌ لِلْوَجْهِ وَضَرْبَةٌ لِلْيَدَيْنِ إِلَى الْمِرْفَقَيْنِ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَمَالِكٌ وَابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ عَمَّارٍ فِي التَّيَمُّمِ أَنَّهُ قَالَ لِلْوَجْهِ وَالْكَفَّيْنِ مِنْ غَيْرِ وَجْهٍ وَقَدْ رُوِيَ عَنْ عَمَّارٍ أَنَّهُ قَالَ تَيَمَّمْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمَنَاكِبِ وَالْآبَاطِ فَضَعَّفَ بَعْضُ أَهْلِ الْعِلْمِ حَدِيثَ عَمَّارٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي التَّيَمُّمِ لِلْوَجْهِ وَالْكَفَّيْنِ لَمَّا رُوِيَ عَنْهُ حَدِيثُ الْمَنَاكِبِ وَالْآبَاطِ قَالَ إِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ مَخْلَدٍ الْحَنْظَلِيُّ حَدِيثُ عَمَّارٍ فِي التَّيَمُّمِ لِلْوَجْهِ وَالْكَفَّيْنِ هُوَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَحَدِيثُ عَمَّارٍ تَيَمَّمْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمَنَاكِبِ وَالْآبَاطِ لَيْسَ هُوَ بِمُخَالِفٍ لِحَدِيثِ الْوَجْهِ وَالْكَفَّيْنِ لِأَنَّ عَمَّارًا لَمْ يَذْكُرْ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُمْ بِذَلِكَ وَإِنَّمَا قَالَ فَعَلْنَا كَذَا وَكَذَا فَلَمَّا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُ بِالْوَجْهِ وَالْكَفَّيْنِ فَانْتَهَى إِلَى مَا عَلَّمَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَجْهِ وَالْكَفَّيْنِ وَالدَّلِيلُ عَلَى ذَلِكَ مَا أَفْتَى بِهِ عَمَّارٌ بَعْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي التَّيَمُّمِ أَنَّهُ قَالَ الْوَجْهِ وَالْكَفَّيْنِ فَفِي هَذَا دَلَالَةٌ أَنَّهُ انْتَهَى إِلَى مَا عَلَّمَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَّمَهُ إِلَى الْوَجْهِ وَالْكَفَّيْنِ قَالَ و سَمِعْت أَبَا زُرْعَةَ عُبَيْدَ اللَّهِ بْنَ عَبْدِ الْكَرِيمِ يَقُولُ لَمْ أَرَ بِالْبَصْرَةِ أَحْفَظَ مِنْ هَؤُلَاءِ الثَّلَاثَةِ عَلِيِّ بْنِ الْمَدِينِيِّ وَابْنِ الشَّاذَكُونِيِّ وَعَمْرِو بْنِ عَلِيٍّ الْفَلَّاسِ قَالَ أَبُو زُرْعَةَ وَرَوَى عَفَّانُ بْنُ مُسْلِمٍ عَنْ عَمْرِو بْنِ عَلِيٍّ حَدِيثًا","id":"telah menceritakan kepada kami [Abu Hafsh 'Amru bin Ali Al Falas] berkata; telah menceritakan kepada kami [Yazid Ibnu Zurai'] berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Azrah] dari [Sa'id bin Abdurrahman bin Abza] dari [ayahnya] dari ['Ammar bin Yasir] berkata; \"Nabi shallallahu 'alaihi wasallam memerintahkan kepadanya bertayamum pada muka dan kedua telapak tangan.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari 'Aisyah dan Ibnu Abbas.\" Abu Isa berkata; \"Hadits Ammar ini derajatnya hasan shahih. Telah diriwayatkan pula dari 'Ammar dari banyak jalur. Ini adalah pendapat tidak hanya seorang saja dari kalangan sahabat Nabi shallallahu 'alaihi wasallam. Di antara mereka adalah Ali, 'Ammar, Ibnu Abbas dan banyak lagi dari kalangan tabi'in seperti Asy Sya'bi, 'Atha` dan Makhul. Mereka mengatakan, \"Tayamum itu satu pukulan untuk muka dan kedua telapak tangan.\" Pendapat ini diambil oleh Ahmad dan Ishaq. Dan sebagian ahli ilmu seperti Ibnu Umar, Jabir, Ibrahim dan Al Hasan mengatakan, \"Tayamum itu satu pukulan untuk wajah dan satu pukulan untuk kedua telapak tangan hingga siku.\" Pendapat ini diambil oleh Sufyan Ats Tsauri, Malik, bin Al Mubarak dan Syafi'i. Hadits tentang tayamum ini, yaitu bahwa Nabi shallallahu 'alaihi wasallam mengatakan, \"untuk muka dan kedua telapak tangan, \" juga diriwayatkan dari Ammar dengan jalur lain. Hadits ini juga diriwayatkan dari 'Ammar, bahwa ia berkata; \"Kami pernah bersama Nabi shallallahu 'alaihi wasallam bertayamum hingga pundak dan ketiak.\" Namun sebagian ulama melemahkan hadits 'Ammar dari Nabi shallallahu 'alaihi wasallam, tentang tayamum pada muka dan kedua telapak tangan, ketika diriwayatkan pula darinya hadits tayamum hingga pundak dan ketiak. Ishaq bin Ibrahim bin Makhlad Al Hanzhali berkata; \"Hadits 'Ammar tentang tayamum untuk muka dan kedua telapak tangan adalah hadits yang derajatnya hasan shahih. Sedangkan hadits Ammar yang menyebutkan, \"Kami pernah bersama Nabi shallallahu 'alaihi wasallam bertayamum hingga pundak dan ketiak, \" tidak bertentangan dengan hadits untuk muka dan kedua telapak tangan. Sebab 'Ammar tidak menyebutkan bahwa Nabi shallallahu 'alaihi wasallam memerintahkan mereka untuk melakukan yang demikian itu. Namun ia hanya mengatakan, \"Kami melakukan begini dan begini.\" Ketika ia bertanya Nabi shallallahu 'alaihi wasallam, beliau memerintahkan kepadanya untuk mengusap muka dan kedua telapak tangan, maka berakhirlah atas apa yang Rasulullah shallallahu 'alaihi wasallam ajarkan kepadanya, yaitu mengusap muka dan kedua telapak tangan. Dalil dari hal itu adalah apa yang 'Ammar fatwakan dari Nabi shallallahu 'alaihi wasallam tentang tayamum, bahwa beliau bersabda: \"(mengusap) muka dan kedua telapak tangan.\" Maka dalam persoalan ini dalilnya adalah apa yang telah diajarkan oleh Nabi shallallahu 'alaihi wasallam, beliau mengajarkan untuk mengusap wajah dan kedua telapak tangan.\" Ia bersabda, \"Aku mendengar Abu Zur'ah bin Abdul Karim berkata; \"Aku belum pernah melihat di kota Bashrah orang yang lebih bagus hafalannya selain tiga orang; Ali bin Al Madini, Ibnu Asy Syadzakuni dan 'Amru bin Ali Al Fallas.\" Abu Zur'ah berkata; \"Affan bin Muslim meriwayatkan sebuah hadits dari 'Amru bin Ali.\""},"135":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ حَدَّثَنَا هُشَيْمٌ عَنْ مُحَمَّدِ بْنِ خَالِدٍ الْقُرَشِيِّ عَنْ دَاودَ بْنِ حُصَيْنٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّهُ سُئِلَ عَنْ التَّيَمُّمِ فَقَالَ إِنَّ اللَّهَ قَالَ فِي كِتَابِهِ حِينَ ذَكَرَ الْوُضُوءَ{ فَاغْسِلُوا وُجُوهَكُمْ وَأَيْدِيَكُمْ إِلَى الْمَرَافِقِ }وَقَالَ فِي التَّيَمُّمِ{ فَامْسَحُوا بِوُجُوهِكُمْ وَأَيْدِيكُمْ }وَقَالَ{ وَالسَّارِقُ وَالسَّارِقَةُ فَاقْطَعُوا أَيْدِيَهُمَا }فَكَانَتْ السُّنَّةُ فِي الْقَطْعِ الْكَفَّيْنِ إِنَّمَا هُوَ الْوَجْهُ وَالْكَفَّانِ يَعْنِي التَّيَمُّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَذِيٌّ صَحِيحٌ","id":"Telah bercerita kepada kami [Yahya bin Musa] berkata; telah menceritakan kepada kami [Sa'id bin Sulaiman] berkata; telah menceritakan kepada kami [Husyaim] dari [Muhammad bin Khalid Al Qurasyi] dari [Daud bin Hushain] dari [Ikrimah] dari [Ibnu Abbas] bahwa ia pernah ditanya tentang tayamum, ia lalu menjawab, \"Sesungguhnya Allah telah berfirman dalam kitab-Nya ketika menyebutkan tentang wudlu: \"(Maka basuhlah mukamu dan tanganmu sampai dengan siku), \" dan Allah juga berfirman tentang tayamum: \"(Maka sapulah mukamu dan tanganmu).\" Lalu berfirman: \"(Laki-laki yang mencuri dan perempuan yang mencuri, potonglah tangan keduanya).\" Maka secara sunnah, dalam memotong tangan adalah pada kedua telapak tangan, dan yang dibasuh dalam tayamum adalah bagian wajah dan kedua telapak tangan.\" Abu Isa berkata; \"Hadits ini derajatnya shahih gharib.\""},"136":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ عَبْدُ اللَّهِ بْنِ سَعِيدٍ الْأَشَجُّ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ وَعُقْبَةُ بْنُ خَالِدٍ قَالَا حَدَّثَنَا الْأَعْمَشُ وَابْنُ أَبِي لَيْلَى عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ سَلِمَةَ عَنْ عَلِيٍّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقْرِئُنَا الْقُرْآنَ عَلَى كُلِّ حَالٍ مَا لَمْ يَكُنْ جُنُبًاقَالَ أَبُو عِيسَى حَدِيثُ عَلِيٍّ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَبِهِ قَالَ غَيْرُ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ قَالُوا يَقْرَأُ الرَّجُلُ الْقُرْآنَ عَلَى غَيْرِ وُضُوءٍ وَلَا يَقْرَأُ فِي الْمُصْحَفِ إِلَّا وَهُوَ طَاهِرٌ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ","id":"telah menceritakan kepada kami [Abu Sa'id Abdullah bin Sa'id Al Asyaj] berkata; telah menceritakan kepada kami [Hafsh bin Ghiyats] dan [Uqbah bin Khalid] mereka berkata; telah menceritakan kepada kami [Al A'masy] dan [Ibnu Abu Laila] dari ['Amru bin Murrah] dari [Abdullah bin Salamah] dari [Ali] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam membacakan Al Qur'an dalam setiap kesempatan, selama beliau tidak junub.\" Abu Isa berkata; \"Hadits Ali ini adalah hadits yang hasan shahih. Pendapat ini banyak diambil oleh ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in. Mereka berkata; \"Seorang laki-laki boleh membaca Al Qur`an tanpa wudlu, namun ia tidak boleh membaca kecuali dalam keadaan suci. Pendapat ini diambil oleh Sufyan Ats Tsauri, Syafi'i, Ahmad dan Ishaq.\""},"137":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ وَسَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَدَخَلَ أَعْرَابِيٌّ الْمَسْجِدَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ فَصَلَّى فَلَمَّا فَرَغَ قَالَ اللَّهُمَّ ارْحَمْنِي وَمُحَمَّدًا وَلَا تَرْحَمْ مَعَنَا أَحَدًا فَالْتَفَتَ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَقَدْ تَحَجَّرْتَ وَاسِعًا فَلَمْ يَلْبَثْ أَنْ بَالَ فِي الْمَسْجِدِ فَأَسْرَعَ إِلَيْهِ النَّاسُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْرِيقُوا عَلَيْهِ سَجْلًا مِنْ مَاءٍ أَوْ دَلْوًا مِنْ مَاءٍ ثُمَّ قَالَ إِنَّمَا بُعِثْتُمْ مُيَسِّرِينَ وَلَمْ تُبْعَثُوا مُعَسِّرِينَقَالَ سَعِيدٌ قَالَ سُفْيَانُ وَحَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ عَنْ أَنَسِ بْنِ مَالِكٍ نَحْوَ هَذَا قَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَابْنِ عَبَّاسٍ وَوَاثِلَةَ بْنِ الْأَسْقَعِ قَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ وَهُوَ قَوْلُ أَحْمَدَ وَإِسْحَقَ وَقَدْ رَوَى يُونُسُ هَذَا الْحَدِيثَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ","id":"telah menceritakan kepada kami [Ibnu Abu Umar] dan [Sa'id bin Abdurrahman Al Makhzumi] mereka berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Sa'id bin Al Musayyib] dari [Abu Hurairah] ia berkata; \"Seorang arab dusun masuk ke dalam masjid ketika Nabi shallallahu 'alaihi wasallam shalat, arab dusun itu lalu shalat. Setelah shalat ia berdo'a, \"Ya Allah, sayangilah aku dan Muhammad, dan jangan engkau sayangi seorang pun bersama kami.\" Nabi shallallahu 'alaihi wasallam lalu berpaling ke arahnya seraya bersabda: \"Sungguh engkau telah mempersempit sesuatu yang luas.\" Setelah itu ia kencing di dalam masjid hingga membuat orang-orang segera menghampirinya, namun Nabi shallallahu 'alaihi wasallam bersabda: \"Siramlah dengan seember air, \" atau beliau mengatakan: \"dengan satu timba air.\" Setelah itu beliau bersabda lagi: \"Sesungguhnya kalian diutus dengan memberi kemudahan dan tidak diutus untuk memberi kesulitan.\" [Sa'id] berkata; \" [Sufyan] berkata; \"Telah menceritakan kepadaku [Yahya bin Sa'id] dari [Anas bin Malik] seperti ini.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin Mas'ud, Ibnu Abbas dan Watsilah bin Al Asqa'.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, dan sebagian ahli ilmu beramal dengan hadits ini. Ini adalah pendapat Ahmad dan Ishaq. [Yunus] juga meriwayatkan hadits ini dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Abu Hurairah].\""},"138":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ عَيَّاشِ بْنِ أَبِي رَبِيعَةَ عَنْ حَكِيمِ بْنِ حَكِيمٍ وَهُوَ ابْنُ عَبَّادِ بْنِ حُنَيْفٍ أَخْبَرَنِي نَافِعُ بْنُ جُبَيْرِ بْنِ مُطْعِمٍ قَالَ أَخْبَرَنِي ابْنُ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَمَّنِي جِبْرِيلُ عَلَيْهِ السَّلَام عِنْدَ الْبَيْتِ مَرَّتَيْنِ فَصَلَّى الظُّهْرَ فِي الْأُولَى مِنْهُمَا حِينَ كَانَ الْفَيْءُ مِثْلَ الشِّرَاكِ ثُمَّ صَلَّى الْعَصْرَ حِينَ كَانَ كُلُّ شَيْءٍ مِثْلَ ظِلِّهِ ثُمَّ صَلَّى الْمَغْرِبَ حِينَ وَجَبَتْ الشَّمْسُ وَأَفْطَرَ الصَّائِمُ ثُمَّ صَلَّى الْعِشَاءَ حِينَ غَابَ الشَّفَقُ ثُمَّ صَلَّى الْفَجْرَ حِينَ بَرَقَ الْفَجْرُ وَحَرُمَ الطَّعَامُ عَلَى الصَّائِمِ وَصَلَّى الْمَرَّةَ الثَّانِيَةَ الظُّهْرَ حِينَ كَانَ ظِلُّ كُلِّ شَيْءٍ مِثْلَهُ لِوَقْتِ الْعَصْرِ بِالْأَمْسِ ثُمَّ صَلَّى الْعَصْرَ حِينَ كَانَ ظِلُّ كُلِّ شَيْءٍ مِثْلَيْهِ ثُمَّ صَلَّى الْمَغْرِبَ لِوَقْتِهِ الْأَوَّلِ ثُمَّ صَلَّى الْعِشَاءَ الْآخِرَةَ حِينَ ذَهَبَ ثُلُثُ اللَّيْلِ ثُمَّ صَلَّى الصُّبْحَ حِينَ أَسْفَرَتْ الْأَرْضُ ثُمَّ الْتَفَتَ إِلَيَّ جِبْرِيلُ فَقَالَ يَا مُحَمَّدُ هَذَا وَقْتُ الْأَنْبِيَاءِ مِنْ قَبْلِكَ وَالْوَقْتُ فِيمَا بَيْنَ هَذَيْنِ الْوَقْتَيْنِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَبُرَيْدَةَ وَأَبِي مُوسَى وَأَبِي مَسْعُودٍ الْأَنْصَارِيِّ وَأَبِي سَعِيدٍ وَجَابِرٍ وَعَمْرِو بْنِ حَزْمٍ وَالْبَرَاءِ وَأَنَسٍ أَخْبَرَنِي أَحْمَدُ بْنُ مُحَمَّدِ بْنِ مُوسَى أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا حُسَيْنُ بْنُ عَلِيِّ بْنِ حُسَيْنٍ أَخْبَرَنِي وَهْبُ بْنُ كَيْسَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَمَّنِي جِبْرِيلُ فَذَكَرَ نَحْوَ حَدِيثِ ابْنِ عَبَّاسٍ بِمَعْنَاهُ وَلَمْ يَذْكُرْ فِيهِ لِوَقْتِ الْعَصْرِ بِالْأَمْسِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَحَدِيثُ ابْنِ عَبَّاسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ و قَالَ مُحَمَّدٌ أَصَحُّ شَيْءٍ فِي الْمَوَاقِيتِ حَدِيثُ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَحَدِيثُ جَابِرٍ فِي الْمَوَاقِيتِ قَدْ رَوَاهُ عَطَاءُ بْنُ أَبِي رَبَاحٍ وَعَمْرُو بْنُ دِينَارٍ وَأَبُو الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ حَدِيثِ وَهْبِ بْنِ كَيْسَانَ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"telah menceritakan kepada kami [Hannad bin As Sari] berkata; telah menceritakan kepada kami [Abdurrahman bin Abu Az Zinad] dari [Abdurrahman bin Al Harits bin Ayyasy bin Abu Rabi'ah] dari [Hakim bin Hakim] -yaitu Ibnu Abbad bin Hunaif- berkata; telah mengabarkan kepadaku [Nafi' bin Jubair bin Muth'im] berkata; telah mengabarkan kepadaku [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jibril 'Alaihis Salam pernah mengimamiku di sisi Ka'bah dua kali. Pertama kali, ia shalat zhuhur ketika bayang-bayang seperti tali sandal. Kemudian ia shalat asar ketika bayangan sesuatu seperti benda aslinya. Kemudian shalat maghrib ketika matahari terbenam dan orang-orang yang berpuasa berbuka. Kemudian shalat isya ketika warna merah di langit hilang. Setelah itu ia shalat subuh ketika fajar terbit dan makanan menjadi haram bagi orang yang berpuasa. Pada kali kedua, ia shalat zhuhur bayangan sesuatu sebagaimana aslinya, persis untuk waktu shalat asar kemarin. Lalu ia shalat asar ketika bayangan setiap sesuatu dua kali dari benda aslinya. Kemudian ia shalat maghrib sebagaimana waktu yang lalu, lalu shalat isya yang akhir ketika telah berlalu sepertiga waktu malam. Kemudian shalat subuh ketika matahari matahari telah merekah menyinari bumi. Setelah itu Jibril menoleh ke arahku seraya berkata; \"Wahai Muhammad, ini adalah waktu para Nabi sebelummu, dan waktu shalat adalah antara kedua waktu ini.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Abu Hurairah, Buraidah, Abu Musa, Abu Mas'ud Al Anshari, Abu Sa'id, Jabir, 'Amru bin Hazm, Al Bara dan Anas.\" Telah mengabarkan kepadaku [Ahmad bin Musa] berkata; telah mengabarkan kepada kami [Abdullah bin Al Mubarak] berkata; telah mengabarkan kepada kami [Husain bin Ali bin Husain] berkata; telah mengabarkan kepadaku [Wahb bin Kaisan] dari [Jabir bin Abdullah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Jibril mengimamiku……lalu ia menyebutkan sebagaimana dalam hadits Ibnu Abbas secara makna. Dan ia tidak menyebutkan dalam hadits tersebut, \"Untuk waktu asar seperti yang kemarin.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih gharib. Dan hadits Ibnu Abbas derajatnya hadits hasan shahih. Muhammad berkata; \"Riwayat yang paling shahih dalam hal waktu shalat adalah hadits Jabir dari Nabi shallallahu 'alaihi wasallam.\" Ia berkata; \"Hadits Jabir tentang waktu-waktu shalat telah diriwayatkan oleh ['Atha bin Abu Rabah] dan [Amru bin Dinar] dan [Abu Az Zubair] dari [Jabir bin Abdullah] dari Nabi shallallahu 'alaihi wasallam, seperti hadits Wahb bin kaisan, dari Jabir, dari Nabi shallallahu 'alaihi wasallam.\""},"139":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِلصَّلَاةِ أَوَّلًا وَآخِرًا وَإِنَّ أَوَّلَ وَقْتِ صَلَاةِ الظُّهْرِ حِينَ تَزُولُ الشَّمْسُ وَآخِرَ وَقْتِهَا حِينَ يَدْخُلُ وَقْتُ الْعَصْرِ وَإِنَّ أَوَّلَ وَقْتِ صَلَاةِ الْعَصْرِ حِينَ يَدْخُلُ وَقْتُهَا وَإِنَّ آخِرَ وَقْتِهَا حِينَ تَصْفَرُّ الشَّمْسُ وَإِنَّ أَوَّلَ وَقْتِ الْمَغْرِبِ حِينَ تَغْرُبُ الشَّمْسُ وَإِنَّ آخِرَ وَقْتِهَا حِينَ يَغِيبُ الْأُفُقُ وَإِنَّ أَوَّلَ وَقْتِ الْعِشَاءِ الْآخِرَةِ حِينَ يَغِيبُ الْأُفُقُ وَإِنَّ آخِرَ وَقْتِهَا حِينَ يَنْتَصِفُ اللَّيْلُ وَإِنَّ أَوَّلَ وَقْتِ الْفَجْرِ حِينَ يَطْلُعُ الْفَجْرُ وَإِنَّ آخِرَ وَقْتِهَا حِينَ تَطْلُعُ الشَّمْسُقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى و سَمِعْت مُحَمَّدًا يَقُولُ حَدِيثُ الْأَعْمَشِ عَنْ مُجَاهِدٍ فِي الْمَوَاقِيتِ أَصَحُّ مِنْ حَدِيثِ مُحَمَّدِ بْنِ فُضَيْلٍ عَنْ الْأَعْمَشِ وَحَدِيثُ مُحَمَّدِ بْنِ فُضَيْلٍ خَطَأٌ أَخْطَأَ فِيهِ مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ أَبِي إِسْحَقَ الْفَزَارِيِّ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ قَالَ كَانَ يُقَالُ إِنَّ لِلصَّلَاةِ أَوَّلًا وَآخِرًا فَذَكَرَ نَحْوَ حَدِيثِ مُحَمَّدِ بْنِ فُضَيْلٍ عَنْ الْأَعْمَشِ نَحْوَهُ بِمَعْنَاهُ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Muhammad Ibnu Fudlail] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya shalat mempunyai waktu awal dan waktu akhir. Awal waktu shalat zhuhur adalah ketika matahari tergelincir dan waktu akhirnya adalah ketika telah masuk waktu asar. Awal waktu shalat asar adalah ketika telah masuk waktunya dan akhirnya adalah ketika matahari berwarna kekuningan. Awal waktu shalat maghrib adalah ketika matahari terbenam dan waktu akhirnya adalah ketika warna kemerahan telah menghilang. Awal waktu isya adalah ketika warna merah telah menghilang dan waktu akhirnya adalah pertengahan malam. Dan awal shalat subuh adalah ketika terbit fajar, dan akhir waktunya adalah ketika matahari terbit.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin Amru. Abu Isa berkata; \"Dan aku mendengar Muhammad berkata; \"Hadits Al A'masy dari Mujahid dalam hal waktu shalat adalah lebih shahih dari hadits Muhammad bin Fudlail dari Al A'masy, sedangkan hadits Muhammad bin Fudlail terdapat kesalahan yang dilakukan Muhammad bin Fudlail. Telah menceritakan kepada kami [Abu Usamah] dari [Abu Ishaq Al Fazari] dari [Al A'masy] dari [Mujahid] \". Ia berkata; \"Terkadang disebutkan; Sesungguhnya shalat memiliki waktu awal dan akhirnya, lalu ia menyebutkan seperti hadits Muhammad bin Fudlail dari Al A'masy seperti itu dengan maknanya."},"140":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ وَالْحَسَنُ بْنُ الصَّبَّاحِ الْبَزَّارُ وَأَحْمَدُ بْنُ مُحَمَّدِ بْنِ مُوسَى الْمَعْنَى وَاحِدٌ قَالُوا حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ الْأَزْرَقُ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَسَأَلَهُ عَنْ مَوَاقِيتِ الصَّلَاةِ فَقَالَ أَقِمْ مَعَنَا إِنْ شَاءَ اللَّهُ فَأَمَرَ بِلَالًا فَأَقَامَ حِينَ طَلَعَ الْفَجْرُ ثُمَّ أَمَرَهُ فَأَقَامَ حِينَ زَالَتْ الشَّمْسُ فَصَلَّى الظُّهْرَ ثُمَّ أَمَرَهُ فَأَقَامَ فَصَلَّى الْعَصْرَ وَالشَّمْسُ بَيْضَاءُ مُرْتَفِعَةٌ ثُمَّ أَمَرَهُ بِالْمَغْرِبِ حِينَ وَقَعَ حَاجِبُ الشَّمْسِ ثُمَّ أَمَرَهُ بِالْعِشَاءِ فَأَقَامَ حِينَ غَابَ الشَّفَقُ ثُمَّ أَمَرَهُ مِنْ الْغَدِ فَنَوَّرَ بِالْفَجْرِ ثُمَّ أَمَرَهُ بِالظُّهْرِ فَأَبْرَدَ وَأَنْعَمَ أَنْ يُبْرِدَ ثُمَّ أَمَرَهُ بِالْعَصْرِ فَأَقَامَ وَالشَّمْسُ آخِرَ وَقْتِهَا فَوْقَ مَا كَانَتْ ثُمَّ أَمَرَهُ فَأَخَّرَ الْمَغْرِبَ إِلَى قُبَيْلِ أَنْ يَغِيبَ الشَّفَقُ ثُمَّ أَمَرَهُ بِالْعِشَاءِ فَأَقَامَ حِينَ ذَهَبَ ثُلُثُ اللَّيْلِ ثُمَّ قَالَ أَيْنَ السَّائِلُ عَنْ مَوَاقِيتِ الصَّلَاةِ فَقَالَ الرَّجُلُ أَنَا فَقَالَ مَوَاقِيتُ الصَّلَاةِ كَمَا بَيْنَ هَذَيْنِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ قَالَ وَقَدْ رَوَاهُ شُعْبَةُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ أَيْضًا","id":"telah menceritakan kepada kami [Ahmad bin Mani'] dan [Al Hasan bin Ash Shabbah Al Bazzar] dan [Ahmad bin Muhammad bin Musa] dengan satu makna. Mereka berkata; \"Telah menceritakan kepada kami [Ishaq bin Yusuf Al Azraq] dari [Sufyan Ats Tsauri] dari [Alqamah bin Martsad] dari [Sulaiman bin Buraidah] dari [Ayahnya] ia berkata; \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan bertanya tentang waktu shalat, maka beliau pun bersabda: \"Ikutlah shalat bersama kami -insyaallah-.\" Lalu beliau memerintahkan Bilal untuk iqamah. Maka ia iqamah ketika terbit fajar. Kemudian beliau memerintahkan iqamah, Bilal pun iqamah ketika matahari telah condong, maka beliau pun shalat zhuhur. Kemudian beliau memerintahkan untuk iqamah, Bilal pun iqamah dan beliau shalat asar ketika matahari berwarna putih dan masih tinggi. Kemudian beliau memerintahkan shalat maghrib ketika sinar marahari terbenam. Kemudian beliau memerintahkan iqamah shalat isya ketika warna merah di langit telah hilang. Dan pada keesokan harinya, beliau memerintahkan iqamah shalat subuh ketika matahari telah terang. Lalu beliau memerintahkan shalat zhuhur, dan beliau tetap menunggu hingga udara terasa sejuk dan enak. Lalu beliau memerintahkan shalat asar, beliau pun melaksanakan shalat sedangkan akhir waktunya tinggal sedikit lagi. Kemudian beliau memerintahkan iqamah lagi, namun beliau mengakhirkan maghrib hingga warna merah di langit hampir menghilang. Lalu beliau memerintahkan untuk shalat isya, dan beliau melaksanakannya ketika telah lewat dari waktu sepertiga malam. Setelah itu beliau bersabda: \"Dimana orang yang bertanya tentang waktu shalat?\" laki-laki itu menjawab, \"Saya.\" Lalu beliau bersabda: \"Waktu-waktu shalat itu antara dua waktu ini.\" Abu Isa berkata; \"Hadits ini derajatnya hasan gharib shahih.\" Ia berkata; \" [Syu'bah] juga meriwayatkannya dari [Alqamah bin Martsad].\""},"141":{"ar":"حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكِ بْنِ أَنَسٍ قَالَ و حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْإِنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُصَلِّي الصُّبْحَ فَيَنْصَرِفُ النِّسَاءُ قَالَ الْأَنْصَارِيُّ فَيَمُرُّ النِّسَاءُ مُتَلَفِّفَاتٍ بِمُرُوطِهِنَّ مَا يُعْرَفْنَ مِنْ الْغَلَسِو قَالَ قُتَيْبَةُ مُتَلَفِّعَاتٍ قَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَأَنَسٍ وَقَيْلَةَ بِنْتِ مَخْرَمَةَ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ الزُّهْرِيُّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ نَحْوَهُ وَهُوَ الَّذِي اخْتَارَهُ غَيْرُ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ أَبُو بَكْرٍ وَعُمَرُ وَمَنْ بَعْدَهُمْ مِنْ التَّابِعِينَ وَبِهِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ يَسْتَحِبُّونَ التَّغْلِيسَ بِصَلَاةِ الْفَجْرِ","id":"telah menceritakan kepada kami [Qutaibah] dari [Malik bin Anas] berkata; dan telah menceritakan kepada kami [Al Anshari] berkata; telah menceritakan kepada kami [Ma'n] berkata; telah menceritakan kepada kami [Malik] dari [Yahya bin Sa'id] dari [Amrah] dari ['Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat subuh, lalu kaum wanita pergi berlalu (ke rumah).\" Al Anshari berkata; \"Kaum wanita tersebut lewat dengan berselimut kain yang tidak berjahit hingga mereka tidak bisa dikenali.\" Dan Qutaibah menyebutkan dengan lafadz mutalaffifat (berselimut kain).\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Umar, Anas dan Qailah binti Makhramah.\" Abu Isa berkata; \"Hadits 'Aisyah ini derajatnya hasan shahih. [Az Zuhri] juga telah meriwayatkannya dari [Urwah] dari ['Aisyah] seperti itu. Pendapat ini diambil oleh banyak ulama dari kalangan sahabat Nabi shallallahu 'alaihi wasallam seperti Abu Bakar, Umar dan orang-orang setelah mereka dari kalangan tabi'in. Pendapat ini juga dipegang oleh Syafi'i, Ahmad dan Ishaq. Mereka menyukai shalat fajar ketika masih gelap.\""},"142":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ هُوَ ابْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَسْفِرُوا بِالْفَجْرِ فَإِنَّهُ أَعْظَمُ لِلْأَجْرِقَالَ وَقَدْ رَوَى شُعْبَةُ وَالثَّوْرِيُّ هَذَا الْحَدِيثَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ قَالَ وَرَوَاهُ مُحَمَّدُ بْنُ عَجْلَانَ أَيْضًا عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ قَالَ وَفِي الْبَاب عَنْ أَبِي بَرْزَةَ الْأَسْلَمِيِّ وَجَابِرٍ وَبِلَالٍ قَالَ أَبُو عِيسَى حَدِيثُ رَافِعِ بْنِ خَدِيجٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَأَى غَيْرُ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ الْإِسْفَارَ بِصَلَاةِ الْفَجْرِ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ و قَالَ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ مَعْنَى الْإِسْفَارِ أَنْ يَضِحَ الْفَجْرُ فَلَا يُشَكَّ فِيهِ وَلَمْ يَرَوْا أَنَّ مَعْنَى الْإِسْفَارِ تَأْخِيرُ الصَّلَاةِ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abdah] -yaitu Ibnu Sulaiman- dari [Muhammad bin Ishaq] dari ['Ashim bin Umar bin Qatadah] dari [Mahmud bin Labid] dari [Rafi' bin Khadij] ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalatlah subuh ketika agak siang, karena itu lebih banyak pahalanya.\" Ia berkata; \" [Syu'bah] dan [Ats Tsauri] meriwayatkan hadits ini dari [Muhammad bin Ishaq].\" Ia berkata; \"Hadits ini juga diriwayatkan oleh [Muhammad bin 'Ajlan] dari ['Ashim bin Umar bin Qatadah].\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Barzah Al Aslami dan Jabir dan Bilal.\" Abu Isa berkata; \"Hadits Rafi' bin Khadij adalah hadits hasan shahih. Dan bukan hanya satu ulama dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in yang berpendapat bahwa shalat subuh dikerjakan ketika hari sudah agak terang. Pendapat ini juga dipegang oleh Sufyan Ats Tsauri. Syafi'i, Ahmad dan Ishaq mengatakan bahwa makna isfar adalah ketika fajar telah terang. Tidak diragukan lagi bahwa mereka tidak mengatakan bahwa makana isfar adalah mengakhirkan shalat.\""},"143":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ حَكِيمِ بْنِ جُبَيْرٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْمَا رَأَيْتُ أَحَدًا كَانَ أَشَدَّ تَعْجِيلًا لِلظُّهْرِ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا مِنْ أَبِي بَكْرٍ وَلَا مِنْ عُمَرَقَالَ وَفِي الْبَاب عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ وَخَبَّابٍ وَأَبِي بَرْزَةَ وَابْنِ مَسْعُودٍ وَزَيْدِ بْنِ ثَابِتٍ وَأَنَسٍ وَجَابِرِ بْنِ سَمُرَةَ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ وَهُوَ الَّذِي اخْتَارَهُ أَهْلُ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ قَالَ عَلِيُّ بْنُ الْمَدِينِيِّ قَالَ يَحْيَى بْنُ سَعِيدٍ وَقَدْ تَكَلَّمَ شُعْبَةُ فِي حَكِيمِ بْنِ جُبَيْرٍ مِنْ أَجْلِ حَدِيثِهِ الَّذِي رَوَى عَنْ ابْنِ مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَأَلَ النَّاسَ وَلَهُ مَا يُغْنِيهِ قَالَ يَحْيَى وَرَوَى لَهُ سُفْيَانُ وَزَائِدَةُ وَلَمْ يَرَ يَحْيَى بِحَدِيثِهِ بَأْسًا قَالَ مُحَمَّدٌ وَقَدْ رُوِيَ عَنْ حَكِيمِ بْنِ جُبَيْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي تَعْجِيلِ الظُّهْرِ","id":"telah menceritakan kepada kami [Hannad bin As Sari] berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Hakim bin Jubair] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] ia berkata; \"Aku tidak pernah melihat seorang pun yang bersegera dalam melaksanakan shalat zhuhur kecuali Rasulullah shallallahu 'alaihi wasallam, tidak Abu Bakar dan tidak pula Umar.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Jabir bin Abdullah, Khabbab, Abu Barzah, Ibnu Mas'ud, Zaid bin Tsabit, Anas dan Jabir bin Samrah.\" Abu Isa berkata; \"Hadits 'Aisyah ini derajatnya hasan. Pendapat inilah yang diambil oleh ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka. Ali Al Madini berkata; \"Yahya bin Sa'id berkata; \"Syu'bah telah memperbincangkan tentang Hakim bin Jubair karena hadits yang telah ia meriwayakan dari Ibnu Mas'ud dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa meminta kepada manusia sedang dia tidak membutuhkannya ………..\" Yahya berkata; sofyan meriwayatkan hadits ini demikian juga Zaidah meriwayatkannya, Yahya tidak melihat ada masalah dalam hadits ini, Muhammad berkata: telah diriwayatkan dari Hakim bin Jubair dari Aisyah dari Nabi shallalahu 'alaihi wa sallam dalam masalah mempercepat shalat zhuhur \""},"144":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ حِينَ زَالَتْ الشَّمْسُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ وَهُوَ أَحْسَنُ حَدِيثٍ فِي هَذَا الْبَابِ وَفِي الْبَاب عَنْ جَابِرٍ","id":"telah menceritakan kepada kami [Al Hasan bin Ali Al Hulwani] berkata; telah mengabarkan kepada kami [Abdurrazaq] berkata; telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] ia berkata; telah mengabarkan kepadaku [Anas bin Malik] berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat zhuhur ketika matahari telah tergelincir.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, dan hadits ini adalah hadits yang paling baik dalam bab ini. Dan dalam bab ini juga ada riwayat dari Jabir.\""},"145":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اشْتَدَّ الْحَرُّ فَأَبْرِدُوا عَنْ الصَّلَاةِ فَإِنَّ شِدَّةَ الْحَرِّ مِنْ فَيْحِ جَهَنَّمَقَالَ وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ وَأَبِي ذَرٍّ وَابْنِ عُمَرَ وَالْمُغِيرَةِ وَالْقَاسِمِ بْنِ صَفْوَانَ عَنْ أَبِيهِ وَأَبِي مُوسَى وَابْنِ عَبَّاسٍ وَأَنَسٍ قَالَ وَرُوِيَ عَنْ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا وَلَا يَصِحُّ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ اخْتَارَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ تَأْخِيرَ صَلَاةِ الظُّهْرِ فِي شِدَّةِ الْحَرِّ وَهُوَ قَوْلُ ابْنِ الْمُبَارَكِ وَأَحْمَدَ وَإِسْحَقَ قَالَ الشَّافِعِيُّ إِنَّمَا الْإِبْرَادُ بِصَلَاةِ الظُّهْرِ إِذَا كَانَ مَسْجِدًا يَنْتَابُ أَهْلُهُ مِنْ الْبُعْدِ فَأَمَّا الْمُصَلِّي وَحْدَهُ وَالَّذِي يُصَلِّي فِي مَسْجِدِ قَوْمِهِ فَالَّذِي أُحِبُّ لَهُ أَنْ لَا يُؤَخِّرَ الصَّلَاةَ فِي شِدَّةِ الْحَرِّ قَالَ أَبُو عِيسَى وَمَعْنَى مَنْ ذَهَبَ إِلَى تَأْخِيرِ الظُّهْرِ فِي شِدَّةِ الْحَرِّ هُوَ أَوْلَى وَأَشْبَهُ بِالِاتِّبَاعِ وَأَمَّا مَا ذَهَبَ إِلَيْهِ الشَّافِعِيُّ أَنَّ الرُّخْصَةَ لِمَنْ يَنْتَابُ مِنْ الْبُعْدِ وَالْمَشَقَّةِ عَلَى النَّاسِ فَإِنَّ فِي حَدِيثِ أَبِي ذَرٍّ مَا يَدُلُّ عَلَى خِلَافِ مَا قَالَ الشَّافِعِيُّ قَالَ أَبُو ذَرٍّ كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَأَذَّنَ بِلَالٌ بِصَلَاةِ الظُّهْرِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بِلَالُ أَبْرِدْ ثُمَّ أَبْرِدْ فَلَوْ كَانَ الْأَمْرُ عَلَى مَا ذَهَبَ إِلَيْهِ الشَّافِعِيُّ لَمْ يَكُنْ لِلْإِبْرَادِ فِي ذَلِكَ الْوَقْتِ مَعْنًى لِاجْتِمَاعِهِمْ فِي السَّفَرِ وَكَانُوا لَا يَحْتَاجُونَ أَنْ يَنْتَابُوا مِنْ الْبُعْدِ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyib] dan [Abu Salamah] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika hari sangat panas maka tunggulah hingga dingin untuk shalat, karena terik yang panas adalah dari hembusan neraka jahannam.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Sa'id, Abu Dzar, Ibnu Umar, Al Mughirah, Al Qasim bin Shofwan dari ayahnya, Abu Musa, Ibnu Abbas dan Anas. Ia berkata; \"Diriwayatkan juga dari Umar dari Nabi shallallahu 'alaihi wasallam tentang hal ini, namun riwayat tersebut juga tidak shahih.\" Abu Isa berkata; \"Hadits Abu Hurairah derajatnya hasan shahih. Dan satu golongan dari ahli ilmu memilih untuk mengakhirkan shalat zhuhur ketika matahari sangat terik. Pendapat ini dipegang oleh bin Al Mubarak, Ahmad dan Ishaq.\" Syafi'i berkata; \"Dibolehkannya menunggu shalat zhuhur hingga suasana menjadi sejuk adalah jika masjid tersebut membuat orang-orang kepanasan (ketika menuju masjid) karena jauhnya tempat. Adapun orang yang shalat sendirian atau seseorang yang shalat di masjid kaumnya, maka aku lebih suka jika ia tetap shalat meskipun matahari sangat terik.\" Abu Isa berkata; \"Orang-orang yang mengakhirkan shalat zhuhur disaat matahari terik, maka hal itu lebih utama dan sesuai dengan sunnah.\" Adapun pendapat yang diambil oleh Syafi'i bahwa keringanan itu diperuntukkan bangi orang yang tempat tinggalnya jauh dan sulit, maka dalam hadits Abu Dzar terdapat suatu dalil yang menunjukkan sebaliknya dari yang dikatakan oleh Syafi'i. Abu Dzar berkata; \"Kami pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, lalu Bilal adzan shalat zhuhur, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Bilal, tunggulah hingga dingin.\" Jika mengikuti pendapat Syafi'i, maka tidak ada artinya untuk menunggu dulu karena mereka telah berkumpul dalam perjalanan dan mereka tidak harus bersusah payah karena datang dari tempat yang jauh.\""},"146":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ مُهَاجِرٍ أَبِي الْحَسَنِ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ أَبِي ذَرٍّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي سَفَرٍ وَمَعَهُ بِلَالٌ فَأَرَادَ أَنْ يُقِيمَ فَقَالَ أَبْرِدْ ثُمَّ أَرَادَ أَنْ يُقِيمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْرِدْ فِي الظُّهْرِ قَالَ حَتَّى رَأَيْنَا فَيْءَ التُّلُولِ ثُمَّ أَقَامَ فَصَلَّى فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ شِدَّةَ الْحَرِّ مِنْ فَيْحِ جَهَنَّمَ فَأَبْرِدُوا عَنْ الصَّلَاةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Abu Dawud Ath Thayalisi] ia berkata; telah memberitakan kepada kami [Syu'bah] dari [Muhajir Abu Al Hasan] dari [Zaid bin Wahb] dari [Abu Dzar] berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah dalam perjalanan, sedang waktu itu beliau bersama Bilal, lalu Bilal ingin mengumandangkan iqamah, maka beliau bersabda: \"Tunggulah hingga dingin, \" lalu Bilal ingin mengumandangkan iqamah lagi, maka Rasulullah shallallahu 'alaihi wasallam bersabda: Tunggulah hingga dingin untuk shalat zhuhur.\" Abu Dzar berkata; \"Hingga kami dapat melihat bayang-gayang, \" akhirnya Bilal mengumandangkan iqamah dan beliau pun melaksanakan shalat. Setelah itu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya, panas yang terik adalah dari hembusan jahannam, maka dinginkanlah untuk melaksanakan shalat.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\""},"147":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ وَالشَّمْسُ فِي حُجْرَتِهَا وَلَمْ يَظْهَرْ الْفَيْءُ مِنْ حُجْرَتِهَاقَالَ وَفِي الْبَاب عَنْ أَنَسٍ وَأَبِي أَرْوَى وَجَابِرٍ وَرَافِعِ بْنِ خَدِيجٍ قَالَ وَيُرْوَى عَنْ رَافِعٍ أَيْضًا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي تَأْخِيرِ الْعَصْرِ وَلَا يَصِحُّ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ الَّذِي اخْتَارَهُ بَعْضُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ عُمَرُ وَعَبْدُ اللَّهِ بْنُ مَسْعُودٍ وَعَائِشَةُ وَأَنَسٌ وَغَيْرُ وَاحِدٍ مِنْ التَّابِعِينَ تَعْجِيلَ صَلَاةِ الْعَصْرِ وَكَرِهُوا تَأْخِيرَهَا وَبِهِ يَقُولُ عَبْدُ اللَّهِ ابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Urwah] dari ['Aisyah] bahwasanya ia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah melaksanakan shalat asar, sedangkan sinar matahari masuk ke dalam kamarnya, dan belum tampak bayangan dalam kamarnya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Anas, Abu Arwa, Jabir, dan Rafi' bin Khadij.\" Ia berkata; \"Diriwayatkan juga dari Rafi' dari Nabi shallallahu 'alaihi wasallam tentang mengakhirkan shalat asar, namun riwayat tersebut tidak sah.\" Abu Isa berkata; \"Hadits 'Aisyah derajatnya hadits hasan shahih.\" Pendapat itulah yang dipilih oleh sebagian ahlul Ilmi dari kalangan sahabat Nabi shallallahu 'alaihi wasallam. Di antaranya adalah Umar, Abdullah bin Mas'ud, 'Aisyah, Anas dan beberapa orang dari kalangan tabi'in, yaitu tentang menyegerakan shalat asar, dan mereka memakruhkan untuk mengakhirkan shalat asar. Pendapat ini juga diambil oleh Abdullah bin Mubarak, Syafi'i, Ahmad dan Ishaq.\""},"148":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِأَنَّهُ دَخَلَ عَلَى أَنَسِ بْنِ مَالِكٍ فِي دَارِهِ بِالْبَصْرَةِ حِينَ انْصَرَفَ مِنْ الظُّهْرِ وَدَارُهُ بِجَنْبِ الْمَسْجِدِ فَقَالَ قُومُوا فَصَلُّوا الْعَصْرَ قَالَ فَقُمْنَا فَصَلَّيْنَا فَلَمَّا انْصَرَفْنَا قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تِلْكَ صَلَاةُ الْمُنَافِقِ يَجْلِسُ يَرْقُبُ الشَّمْسَ حَتَّى إِذَا كَانَتْ بَيْنَ قَرْنَيْ الشَّيْطَانِ قَامَ فَنَقَرَ أَرْبَعًا لَا يَذْكُرُ اللَّهَ فِيهَا إِلَّا قَلِيلًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Ali bin Hujr] berkata; telah menceritakan kepada kami [Isma'il bin Ja'far] dari ['Ala bin Abdurrahman] bahwa selepas shalat zhuhur ia masuk menemui [Anas bin Malik] di rumah kediamannya di Bashrah, sedang rumahnya waktu itu ada di sisi masjid. Ia berkata; \"Berdiri dan kerjakanlah shalat asar.\" Al 'Ala bin Abdurrahman berkata; \"Maka kami pun berdiri dan shalat, setelah shalat kami berlalu pergi. Ia lalu berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Itu adalah shalatnya munafik, duduk menunggu matahari hingga apabila matahari berada di antara dua tanduk setan ia berdiri lalu mematuk empat kali, dan tidaklah ia berdzikir kepada Allah kecuali sedikit.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\""},"149":{"ar":"حَد��َثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ أُمِّ سَلَمَةَ أَنَّهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشَدَّ تَعْجِيلًا لِلظُّهْرِ مِنْكُمْ وَأَنْتُمْ أَشَدُّ تَعْجِيلًا لِلْعَصْرِ مِنْهُقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ إِسْمَعِيلَ ابْنِ عُلَيَّةَ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ أُمِّ سَلَمَةَ نَحْوَهُ وَوَجَدْتُ فِي كِتَابِي أَخْبَرَنِي عَلِيُّ بْنُ حُجْرٍ عَنْ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ عَنْ ابْنِ جُرَيْجٍ و حَدَّثَنَا بِشْرُ بْنُ مُعَاذٍ الْبَصْرِيُّ قَالَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ ابْنِ جُرَيْجٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ وَهَذَا أَصَحُّ","id":"telah menceritakan kepada kami [Ali bin Hujr] berkata; telah menceritakan kepada kami [Isma'il Ibnu Ulayyah] dari [Ayyub] dari [Ibnu Abu Mulaikah] dari [Ummu Salamah] bahwasanya ia berkata; \"Rasulullah shallallahu 'alaihi wasallam lebih bersegera dalam melaksanakan shalat zhuhur daripada kalian. Dan kalian lebih bersegera dalam melaksanakan shalat asar daripada beliau.\" Abu Isa berkata; \"Hadits ini juga diriwayatkan dari [Isma'il bin Ulayyah] dari [Ibnu Juraij] dari [Ibnu Abu Mulaikah] dari [Ummu Salamah] seperti itu. Dan aku mendapatkan dalam kitab ayahku, \"Telah mengabarkan kepadaku [Ali bin Hujr] dari [Isma'il bin Ibrahim] dari [Ibnu Juraij], dan telah menceritakan kepada kami [Bisyr bin Mu'adz Al Bashri], ia berkata; telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Ibnu Juraij] dengan sanad ini sebagaimana dalam hadits tersebut. Dan ini lebih shahih.\""},"150":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الْمَغْرِبَ إِذَا غَرَبَتْ الشَّمْسُ وَتَوَارَتْ بِالْحِجَابِقَالَ وَفِي الْبَاب عَنْ جَابِرٍ وَالصُّنَابِحِيِّ وَزَيْدِ بْنِ خَالِدٍ وَأَنَسٍ وَرَافِعِ بْنِ خَدِيجٍ وَأَبِي أَيُّوبَ وَأُمِّ حَبِيبَةَ وَعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ وَابْنِ عَبَّاسٍ وَحَدِيثُ الْعَبَّاسِ قَدْ رُوِيَ مَوْقُوفًا عَنْهُ وَهُوَ أَصَحُّ وَالصُّنَابِحِيُّ لَمْ يَسْمَعْ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ صَاحِبُ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ قَالَ أَبُو عِيسَى حَدِيثُ سَلَمَةَ بْنِ الْأَكْوَعِ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ مِنْ التَّابِعِينَ اخْتَارُوا تَعْجِيلَ صَلَاةِ الْمَغْرِبِ وَكَرِهُوا تَأْخِيرَهَا حَتَّى قَالَ بَعْضُ أَهْلِ الْعِلْمِ لَيْسَ لِصَلَاةِ الْمَغْرِبِ إِلَّا وَقْتٌ وَاحِدٌ وَذَهَبُوا إِلَى حَدِيثِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيْثُ صَلَّى بِهِ جِبْرِيلُ وَهُوَ قَوْلُ ابْنِ الْمُبَارَكِ وَالشَّافِعِيِّ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Hatim bin Isma'il] dari [Yazid bin Abu Ubaid] dari [Salamah bin Al Akwa'] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat maghrib ketika matahari telah terbenam dan tak terlihat.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Jabir Ash Shunabihi, Yazid bin Khalid, Anas, Rafi' bin Khadij, Abu Ayyub, Ummu Habibah, Abbas bin Abdul Muthallib dan Ibnu Abbas. Hadits Al Abbas telah diriwayatkan darinya secara mauquf, dan ini lebih shahih. Sedangkan Ash Shunabihi belum pernah mendengar dari Nabi shallallahu 'alaihi wasallam, dan ia adalah sahabat Abu Bakar Radliaallahu 'anhu. Abu Isa berkata; \"Hadits Salamah bin Al Akwa' derajatnya hasan shahih, ini adalah pendapat yang diambil oleh kebanyakan ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka dari kalangan tabi'in. Mereka memilih untuk menyegerakan shalat maghrib dan memakruhkan untuk mengakhirkannya. Hingga sebagian ahli ilmu mengatakan, \"Shalat maghrib hanya mempunyai satu waktu.\" Mereka berpegangan dengan hadits Nabi shallallahu 'alaihi wasallam ketika diimami oleh Jibril. Dan ini adalah pendapat yang diambil oleh Ibnu Al Mubarak dan Syafi'i.\""},"151":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ بَشِيرِ بْنِ ثَابِتٍ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَأَنَا أَعْلَمُ النَّاسِ بِوَقْتِ هَذِهِ الصَّلَاةِ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّيهَا لِسُقُوطِ الْقَمَرِ لِثَالِثَةٍحَدَّثَنَا أَبُو بَكْرٍ مُحَمَّدُ بْنُ أَبَانَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ أَبِي عَوَانَةَ بِهَذَا الْإِسْنَادِ نَحْوَهُ قَالَ أَبُو عِيسَى رَوَى هَذَا الْحَدِيثَ هُشَيْمٌ عَنْ أَبِي بِشْرٍ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ وَلَمْ يَذْكُرْ فِيهِ هُشَيْمٌ عَنْ بَشِيرِ بْنِ ثَابِتٍ وَحَدِيثُ أَبِي عَوَانَةَ أَصَحُّ عِنْدَنَا لِأَنَّ يَزِيدَ بْنَ هَارُونَ رَوَى عَنْ شُعْبَةَ عَنْ أَبِي بِشْرٍ نَحْوَ رِوَايَةِ أَبِي عَوَانَةَ","id":"telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] berkata; telah menceritakan kepada kami [Abu Awanah] dari [Abu Bisyr] dari [Basyir bin Tsabit] dari [Habib bin Salim] dari [An Nu'man bin Basyir] ia berkata; \"Aku adalah orang yang paling tahu tentang waktu shalat ini, Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat tersebut ketika rembulan telah terbenam di malam ke tiga.\" Telah menceritakan kepada kami [Abu Bakr Muhammad bin Aban] berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Abu Awanah] dengan sanad ini seperti dalam hadits tersebut. Abu Isa berkata; \" [Husyaim] telah meriwayatkan meriwayatkan hadits ini dari [Abu Bisyr] dari [Habib bin Salim] dari [An Nu'man bin Basyir]. Namun Husyaim tidak menyebutkan dalam riwayat tersebut nama Basyir bin Tsabit. Dan hadits Abu Awanah menurut kami lebih shahih, sebab [Yazid bin Harun] meriwayatkan dari [Syu'bah] dari [Abu Bisyr] seperti riwayat Abu Awanah.\""},"152":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ أَنْ يُؤَخِّرُوا الْعِشَاءَ إِلَى ثُلُثِ اللَّيْلِ أَوْ نِصْفِهِقَالَ وَفِي الْبَاب عَنْ جَابِرِ بْنِ سَمُرَةَ وَجَابِرِ بْنِ عَبْدِ اللَّهِ وَأَبِي بَرْزَةَ وَابْنِ عَبَّاسٍ وَأَبِي سَعِيدٍ الْخُدْرِيِّ وَزَيْدِ بْنِ خَالِدٍ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ الَّذِي اخْتَارَهُ أَكْثَرُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَغَيْرِهِمْ رَأَوْا تَأْخِيرَ صَلَاةِ الْعِشَاءِ الْآخِرَةِ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abdah] dari [Ubaidullah bin Umar] dari [Sa'id Al Maqburi] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya tidak memberatkan umatku, sungguh akan aku perintahkan mereka untuk mengakhirkan shalat isya hingga sepertiga atau pertengahan malam.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Jabir bin Samrah, Jabir bin Abdullah, Abu Barzah, Ibnu Abbas, Abu Sa'id Al Khudri, Zaid bin Khalid dan Ibnu Umar.\" Abu Isa berkata; \"Hadits Abu Hurairah ini derajatnya hasan shahih. Pendapat inilah yang dipilih oleh kebanyakan ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan selain mereka. Mereka berpendapat bahwa mengakhirkan shalat isya akhir (diperintahkan). Pendapat ini juga diambil oleh Ahmad dan Ishaq.\""},"153":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا عَوْفٌ قَالَ أَحْمَدُ وَحَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ هُوَ الْمُهَلَّبِيُّ وَإِسْمَعِيلُ ابْنُ عُلَيَّةَ جَمِيعًا عَنْ عَوْفٍ عَنْ سَيَّارِ بْنِ سَلَامَةَ هُوَ أَبُو الْمِنْهَالِ الرِّيَاحِيُّ عَنْ أَبِي بَرْزَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكْرَهُ النَّوْمَ قَبْلَ الْعِشَاءِ وَالْحَدِيثَ بَعْدَهَاقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَعَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَأَنَسٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي بَرْزَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ كَرِهَ أَكْثَرُ أَهْلِ الْعِلْمِ النَّوْمَ قَبْلَ صَلَاةِ الْعِشَاءِ وَالْحَدِيثَ بَعْدَهَا وَرَخَّصَ فِي ذَلِكَ بَعْضُهُمْ و قَالَ عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَكْثَرُ الْأَحَادِيثِ عَلَى الْكَرَاهِيَةِ وَرَخَّصَ بَعْضُهُمْ فِي النَّوْمِ قَبْلَ صَلَاةِ الْعِشَاءِ فِي رَمَضَانَ وَسَيَّارُ بْنُ سَلَامَةَ هُوَ أَبُو الْمِنْهَالِ الرِّيَاحِيُّ","id":"telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Husyaim] berkata; telah mengabarkan kepada kami [Auf]. [Ahmad] berkata; Dan telah menceritakan kepada kami [Abbad bin Abbad] -yaitu Al Muhallabi- dan [Isma'il bin Ulayyah] menceritakan dari [Auf] dari [Sayyar bin Salamah] -dia adalah Abu Al Minhal Ar Riyahi-, dari [Abu Barzah], ia berkata; \"Nabi shallallahu 'alaihi wasallam tidak menyukai tidur sebelum isya dan setelahnya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari 'Aisyah, Abdullah bin Mas'ud dan Anas.\" Abu Isa berkata; \"Hadits Abu Barzah derajatnya hasan shahih. Kebanykan ahli ilmu memakruhkan tidur sebelum isya dan berbincang-bincang setelahnya, sedangkan yang lainnya memberikan keringanan.\" Dan Abdullah bin Al Mubarak berkata; \"Kebanyakan hadits menunjukan atas dimakruhkannya hal itu. Meskipun sebagian mereka memberikan keringanan atas dibolehkannya tidur sebelum shalat tidur di bulan ramadlan.\" Dan Sayyar bin Salamah adalah Abu Al Minhal Ar Riyahi.\""},"154":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْمُرُ مَعَ أَبِي بَكْرٍ فِي الْأَمْرِ مِنْ أَمْرِ الْمُسْلِمِينَ وَأَنَا مَعَهُمَاوَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَأَوْسِ بْنِ حُذَيْفَةَ وَعِمْرَانَ بْنِ حُصَيْنٍ قَالَ أَبُو عِيسَى حَدِيثُ عُمَرَ حَدِيثٌ حَسَنٌ وَقَدْ رَوَى هَذَا الْحَدِيثَ الْحَسَنُ بْنُ عُبَيْدِ اللَّهِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ رَجُلٍ مِنْ جُعْفِيٍّ يُقَالُ لَهُ قَيْسٌ أَوْ ابْنُ قَيْسٍ عَنْ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا الْحَدِيثَ فِي قِصَّةٍ طَوِيلَةٍ وَقَدْ اخْتَلَفَ أَهْلُ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ فِي السَّمَرِ بَعْدَ صَلَاةِ الْعِشَاءِ الْآخِرَةِ فَكَرِهَ قَوْمٌ مِنْهُمْ السَّمَرَ بَعْدَ صَلَاةِ الْعِشَاءِ وَرَخَّصَ بَعْضُهُمْ إِذَا كَانَ فِي مَعْنَى الْعِلْمِ وَمَا لَا بُدَّ مِنْهُ مِنْ الْحَوَائِجِ وَأَكْثَرُ الْحَدِيثِ عَلَى الرُّخْصَةِ قَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا سَمَرَ إِلَّا لِمُصَلٍّ أَوْ مُسَافِرٍ","id":"telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dari [Umar bin Al Khaththab] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah berbincang-bincang dengan Abu Bakar dalam permasalahan kaum muslimin, sedang aku bersama keduanya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin Amru, Amru bin Hudzaifah dan Imran bin Hushain.\" Abu Isa berkata; \"Hadits Umar derajatnya hasan shahih. [Al Hasan bin Ubaidullah] telah meriwayatkan hadits ini dari [Ibrahim] dari [Alqamah] dari seorang laki-laki dari Ju'fi yang disebut dengan nama [Qais atau Ibnu Qais] dari [Umar] dari Nabi shallallahu 'alaihi wasallam, dan hadits ini ada dalam kisah yang panjang. Para ulama dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang setelah mereka berselisih tentang hukum berbincang-bincang setelah shalat isya akhir. Sebagian mereka memakruhkan perbincangan setelah shalat isya, sedang sebagian yang lain memberi keringanan jika hal itu masih dalam koridor ilmu, atau keperluan yang penting. Dan kebanyakan hadits memberikan keringanan tersebut.\" Telah diriwayatkan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak boleh berbincang-bincang kecuali bagi orang yang shalat atau musafir.\""},"155":{"ar":"حَدَّثَنَا أَبُو عَمَّارٍ الْحُسَيْنُ بْنُ حُرَيْثٍ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ الْعُمَرِيِّ عَنْ الْقَاسِمِ بْنِ غَنَّامٍ عَنْ عَمَّتِهِ أُمِّ فَرْوَةَ وَكَانَتْ مِمَّنْ بَايَعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ الصَّلَاةُ لِأَوَّلِ وَقْتِهَا","id":"telah menceritakan kepada kami [Abu 'Ammar Al Husain bin Huraits] berkata; telah menceritakan kepada kami [Al Fadll bin Musa] dari [Abdullah bin Umar Al Umari] dari [Al Qasim bin Ghannam] dari bibinya [Ummu Farwah] -dan dia termasuk orang yang ikut serta berbai'at kepada Nabi shallallahu 'alaihi wasallam- bahwasanya ia berkata; \"Nabi shallallahu 'alaihi wasallam pernah ditanya, \"Amalan apakah yang paling utama?\" beliau menjawab: \"Shalat pada awal waktu.\""},"156":{"ar":"حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ سَعِيدِ بْنِ عَبْدِ اللَّهِ الْجُهَنِيِّ عَنْ مُحَمَّدِ بْنِ عُمَرَ بْنِ عَلِيِّ بْنِ أَبِي طَالِبٍ عَنْ أَبِيهِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ يَا عَلِيُّ ثَلَاثٌ لَا تُؤَخِّرْهَا الصَّلَاةُ إِذَا آنَتْ وَالْجَنَازَةُ إِذَا حَضَرَتْ وَالْأَيِّمُ إِذَا وَجَدْتَ لَهَا كُفْئًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ حَسَنٌ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abdullah bin Wahb] dari [Sa'id bin Abdullah AlJuhani] dari [Muhammad bin Umar bin Ali bin Abu Thalib] dari [Ayahnya] dari [Ali bin Abu Thalib] bahwa Nabi shallallahu 'alaihi wasallam pernah bersabda kepadanya: \"Perhatikanlah tiga perkara, janganlah engkau akhirkan shalat jika telah datang waktunya, jenazah jika telah tiba dan (menikahi) seorang janda jika engkau telah merasa cocok(sepadan).\" Abu Isa berkata; \"Hadits ini derajatnya gharib hasan.\""},"157":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَعْقُوبُ بْنُ الْوَلِيدِ الْمَدَنِيُّ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَقْتُ الْأَوَّلُ مِنْ الصَّلَاةِ رِضْوَانُ اللَّهِ وَالْوَقْتُ الْآخِرُ عَفْوُ اللَّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَقَدْ رَوَى ابْنُ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَابْنِ عُمَرَ وَعَائِشَةَ وَابْنِ مَسْعُودٍ قَالَ أَبُو عِيسَى حَدِيثُ أُمِّ فَرْوَةَ لَا يُرْوَى إِلَّا مِنْ حَدِيثِ عَبْدِ اللَّهِ بْنِ عُمَرَ الْعُمَرِيِّ وَلَيْسَ هُوَ بِالْقَوِيِّ عِنْدَ أَهْلِ الْحَدِيثِ وَاضْطَرَبُوا عَنْهُ فِي هَذَا الْحَدِيثِ وَهُوَ صَدُوقٌ وَقَدْ تَكَلَّمَ فِيهِ يَحْيَى بْنُ سَعِيدٍ مِنْ قِبَلِ حِفْظِهِ","id":"Telah bercerita kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Ya'qub bin Al Walid Al Madani] dari [Abdullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda; \"Ridla Allah ada diawal waktu shalat, dan ampunan Allah ada di akhir waktu.\" Abu Isa berkata; \"Hadits ini derajatnya gharib, dan sahabat Ibnu Abbas juga telah meriwayatkan dari Nabi shallallahu 'alaihi wasallam seperti itu.\" Abu Isa berkata; \"Dalam bab ini ada juga hadits riwayat Ali, Ibnu Umar, 'Aisyah dan Ibnu Mas'ud.\" Abu Isa berkata; \"Hadits Ummu Farwah tidak diriwayatkan kecuali dari hadits Abdullah bin Umar Al Umari, sedangkan dia (Abdullah bin Umar Al Umari) menurut para ahli hadits termasuk orang yang tidak kuat, dan para perawi yang meriwayatkan hadits darinya mengalami Idlthirab (satu dengan yang lain banyak pertentangan), sedangkan ia adalah shaduq (jujur). Imam Yahya bin Sa'id telah memberikan komentar berkenaan dengan hafalannya.\""},"158":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ عَنْ أَبِي يَعْفُورٍ عَنْ الْوَلِيدِ بْنِ الْعَيْزَارِ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّأَنَّ رَجُلًا قَالَ لِابْنِ مَسْعُودٍ أَيُّ الْعَمَلِ أَفْضَلُ قَالَ سَأَلْتُ عَنْهُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ الصَّلَاةُ عَلَى مَوَاقِيتِهَا قُلْتُ وَمَاذَا يَا رَسُولَ اللَّهِ قَالَ وَبِرُّ الْوَالِدَيْنِ قُلْتُ وَمَاذَا يَا رَسُولَ اللَّهِ قَالَ وَالْجِهَادُ فِي سَبِيلِ اللَّهِقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَى الْمَسْعُودِيُّ وَشُعْبَةُ وَسُلَيْمَانُ هُوَ أَبُو إِسْحَقَ الشَّيْبَانِيُّ وَغَيْرُ وَاحِدٍ عَنْ الْوَلِيدِ بْنِ الْعَيْزَارِ هَذَا الْحَدِيثَ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Marwan bin Mu'awiyah Al Fazari] dari [Abu Ya'fur] dari [Al Walid bin Al 'Aizar] dari [Abu 'Amru Asy Syaibani] bahwa seorang laki-laki berkata kepada [Ibnu Mas'ud], \"Amal apakah yang paling utama?\" ia berkata; \"Aku pernah bertanya Rasulullah shallallahu 'alaihi wasallam tentang hal itu, maka beliau pun menjawab: \"Shalat sesuai dengan waktunya, \" aku bertanya lagi, \"Wahai Rasulullah, lalu apa lagi?\" beliau menjawab: \"Berbuat baik kepada kedua orang tua, \" aku bertanya lagi, \"Wahai Rasulullah, lalu apa lagi?\" beliau menjawab: \"Jihad di jalan Allah.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Dan hadits ini telah diriwayatkan oleh [Al Mas'udi] dan [Syu'bah] dan [Sulaiman] -yakni Abu Ishaq Asy Syaibani- dan yang lain-lain dari [Al Walid bin Al 'Aizar].\""},"159":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ إِسْحَقَ بْنِ عُمَرَ عَنْ عَائِشَةَ قَالَتْمَا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةً لِوَقْتِهَا الْآخِرِ مَرَّتَيْنِ حَتَّى قَبَضَهُ اللَّهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَلَيْسَ إِسْنَادُهُ بِمُتَّصِلٍ قَالَ الشَّافِعِيُّ وَالْوَقْتُ الْأَوَّلُ مِنْ الصَّلَاةِ أَفْضَلُ وَمِمَّا يَدُلُّ عَلَى فَضْلِ أَوَّلِ الْوَقْتِ عَلَى آخِرِهِ اخْتِيَارُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ فَلَمْ يَكُونُوا يَخْتَارُونَ إِلَّا مَا هُوَ أَفْضَلُ وَلَمْ يَكُونُوا يَدَعُونَ الْفَضْلَ وَكَانُوا يُصَلُّونَ فِي أَوَّلِ الْوَقْتِ قَالَ حَدَّثَنَا بِذَلِكَ أَبُو الْوَلِيدِ الْمَكِّيُّ عَنْ الشَّافِعِيِّ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Laits] dari [Khalid bin Yazid] dari [Sa'id bin Abu Bilal] dari [Ishaq bin Umar] dari ['Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak pernah mengerjakan shalat pada akhir waktunya sebanyak dua kali berturut-turut hingga Allah mewafatkannya.\" Abu Isa berkata; \"Ini adalah hadits yang derajatnya hasan gharib dan sanadnya tidak bersambung.\" Syafi'i berkata; \"Shalat di awal waktu adalah sesuatu yang utama. Dan sesuatu yang menunjukkan keutamaan shalat di awal waktu dari yang akhir adalah memilihnya Nabi shallallahu 'alaihi wasallam, Abu bakar dan Umar, mereka selalu mengerjakannya di awal waktu, dan mereka tidak memilih kecuali sesuatu yang utama. Mereka tidak pernah meninggalkan yang utama, dan mereka selalu melaksanakan shalat di awal waktu.\" Ia berkata; \"Abu Al Walid Al Makki menceritakan kepada kami dari Syafi'i seperti itu.\""},"160":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الَّذِي تَفُوتُهُ صَلَاةُ الْعَصْرِ فَكَأَنَّمَا وُتِرَ أَهْلَهُ وَمَالَهُوَفِي الْبَاب عَنْ بُرَيْدَةَ وَنَوْفَلِ بْنِ مُعَاوِيَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ الزُّهْرِيُّ أَيْضًا عَنْ سَالِمٍ عَنْ أَبِيهِ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang yang kehilangan shalat asar (berjama'ah) seperti orang yang kehilangan keluarga dan hartanya.\" Abu Isa berkata; \"Hadits Ibnu Umar ini derajatnya hasan shahih. Hadits ini juga diriwayatkan oleh [Az Zuhri] dari [Salim] dari ayahnya [Ibnu Umar], dari Nabi shallallahu 'alaihi wasallam.\""},"161":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى الْبَصْرِيُّ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ الضُّبَعِيُّ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا ذَرٍّ أُمَرَاءُ يَكُونُونَ بَعْدِي يُمِيتُونَ الصَّلَاةَ فَصَلِّ الصَّلَاةَ لِوَقْتِهَا فَإِنْ صُلِّيَتْ لِوَقْتِهَا كَانَتْ لَكَ نَافِلَةً وَإِلَّا كُنْتَ قَدْ أَحْرَزْتَ صَلَاتَكَوَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَعُبَادَةَ بْنِ الصَّامِتِ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي ذَرٍّ حَدِيثٌ حَسَنٌ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ يَسْتَحِبُّونَ أَنْ يُصَلِّيَ الرَّجُلُ الصَّلَاةَ لِمِيقَاتِهَا إِذَا أَخَّرَهَا الْإِمَامُ ثُمَّ يُصَلِّي مَعَ الْإِمَامِ وَالصَّلَاةُ الْأُولَى هِيَ الْمَكْتُوبَةُ عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ وَأَبُو عِمْرَانَ الْجَوْنِيُّ اسْمُهُ عَبْدُ الْمَلِكِ بْنُ حَبِيبٍ","id":"telah menceritakan kepada kami [Muhammad bin Musa Al Bashri] berkata; telah menceritakan kepada kami [Ja'far bin Sulaiman Adl Dluba'i] dari [Abu Imran Al Jauni] dari [Abdullah bin Ash Shamit] dari [Abu Dzar] ia berkata; \"Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Abu Dzar, para pemimpin setelahku akan mematikan (meremehkan) shalat, maka shalatlah pada waktunya, jika shalat tersebut dikerjakan sesuai dengan waktunya maka engkau akan mendapatkan pahala nafilah, jika tidak maka engkau telah menjaga shalatmu.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin Mas'ud dan Ubadah bin Ash Shamit.\" Abu Isa berkata; \"Hadits Abu Dzar derajatnya hasan shahih. Ini adalah pendapat yang diambil oleh banyak ulama. Mereka menyukai seorang laki-laki mengerjakan shalat pada waktunya jika imam mengakhirkannya, setelah itu baru ia shalat dengan bergabung bersama imam. Dan menurut kebanyakan ahli ilmu shalat yang ia kerjakan di awal waktu itu adalah shalat (yang wajib). Abu Imran Al Jauni namanya adalah Abdul Malik bin Habib.\""},"162":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ الْأَنْصَارِيِّ عَنْ أَبِي قَتَادَةَ قَالَذَكَرُوا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَوْمَهُمْ عَنْ الصَّلَاةِ فَقَالَ إِنَّهُ لَيْسَ فِي النَّوْمِ تَفْرِيطٌ إِنَّمَا التَّفْرِيطُ فِي الْيَقَظَةِ فَإِذَا نَسِيَ أَحَدُكُمْ صَلَاةً أَوْ نَامَ عَنْهَا فَلْيُصَلِّهَا إِذَا ذَكَرَهَاوَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَأَبِي مَرْيَمَ وَعِمْرَانَ بْنِ حُصَيْنٍ وَجُبَيْرِ بْنِ مُطْعِمٍ وَأَبِي جُحَيْفَةَ وَأَبِي سَعِيدٍ وَعَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيِّ وَذِي مِخْبَرٍ وَيُقَالُ ذِي مِخْمَرٍ وَهُوَ ابْنُ أَخِي النَّجَاشِيِّ قَالَ أَبُو عِيسَى وَحَدِيثُ أَبِي قَتَادَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ اخْتَلَفَ أَهْلُ الْعِلْمِ فِي الرَّجُلِ يَنَامُ عَنْ الصَّلَاةِ أَوْ يَنْسَاهَا فَيَسْتَيْقِظُ أَوْ يَذْكُرُ وَهُوَ فِي غَيْرِ وَقْتِ صَلَاةٍ عِنْدَ طُلُوعِ الشَّمْسِ أَوْ عِنْدَ غُرُوبِهَا فَقَالَ بَعْضُهُمْ يُصَلِّيهَا إِذَا اسْتَيْقَظَ أَوْ ذَكَرَ وَإِنْ كَانَ عِنْدَ طُلُوعِ الشَّمْسِ أَوْ عِنْدَ غُرُوبِهَا وَهُوَ قَوْلُ أَحْمَدَ وَإِسْحَقَ وَالشَّافِعِيِّ وَمَالِكٍ و قَالَ بَعْضُهُمْ لَا يُصَلِّي حَتَّى تَطْلُعَ الشَّمْسُ أَوْ تَغْرُبَ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit Al Bunani] dari [Abdullah bin Rabah Al Anshari] dari [Abu Qatadah] ia berkata; \"Para sahabat menyebutkan kepada Nabi shallallahu 'alaihi wasallam bahwa mereka ketinggalan shalat karena tidur, maka beliau pun bersabda: \"Dalam tidur tidak ada istilah meremehkan, tetapi meremehkan itu ketika dalam keadaan sadar (tidak tidur). Maka jika salah seorang dari kalian lupa tidak mengerjakan shalat, atau ketiduran, maka hendaklah ia shalat ketika telah ingat.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Mas'ud, Abu Maryam, Imran bin Hushain, Jubair bin Muth'im, Abu Juhaifah, Abu Sa'id, 'Amru bin Umayyah Adl Dlamri dan Dzu Mikhbar, disebut juga dengan nama Dzu Mikhmar -yaitu anak laki-laki dari anak laki-laki An Najasyi-.\" Abu Isa berkata; \"Hadits Abu Qatadah derajatnya hasan shahih. Para ulama berbeda pendapat mengenai seseorang yang lalai mengerjakan shalat karena ketiduran atau lupa, lalu ia terbangun atau ingat ketika waktu shalat telah habis, yaitu ketika matahari telah terbit atau telah terbenam. Sebagian dari mereka berkata; \"Ia harus mengerjakannya jika telah bangun atau ingat, meskipun matahari ketika itu sedang terbit atau sedang terbenam.\" Ini adalah pendapat Ahmad, Ishaq, Syafi'i dan Malik. Sedangkan sebagian lain berkata; \"Ia tidak boleh melaksanakan shalat hingga matahari terbit atau tenggelam.\""},"163":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَبِشْرُ بْنُ مُعَاذٍ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَسِيَ صَلَاةً فَلْيُصَلِّهَا إِذَا ذَكَرَهَاوَفِي الْبَاب عَنْ سَمُرَةَ وَأَبِي قَتَادَةَ قَالَ أَبُو عِيسَى حَدِيثُ أَنَسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَيُرْوَى عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ أَنَّهُ قَالَ فِي الرَّجُلِ يَنْسَى الصَّلَاةَ قَالَ يُصَلِّيهَا مَتَى مَا ذَكَرَهَا فِي وَقْتٍ أَوْ فِي غَيْرِ وَقْتٍ وَهُوَ قَوْلُ الشَّافِعِيِّ وَأَحْمَدَ بْنِ حَنْبَلٍ وَإِسْحَقَ وَيُرْوَى عَنْ أَبِي بَكْرَةَ أَنَّهُ نَامَ عَنْ صَلَاةِ الْعَصْرِ فَاسْتَيْقَظَ عِنْدَ غُرُوبِ الشَّمْسِ فَلَمْ يُصَلِّ حَتَّى غَرَبَتْ الشَّمْسُ وَقَدْ ذَهَبَ قَوْمٌ مِنْ أَهْلِ الْكُوفَةِ إِلَى هَذَا وَأَمَّا أَصْحَابُنَا فَذَهَبُوا إِلَى قَوْلِ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ","id":"telah menceritakan kepada kami [Qutaibah] dan [Bisyr bin Mu'adz] mereka berkata; telah menceritakan kepada kami [Abu Awanah] dari [Qatadah] dari [Anas bin Malik] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa lupa mengerjakan shalat, maka hendaklah ia mengerjakannya ketika telah ingat.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Samrah dan Abu Qatadah.\" Abu Isa berkata; \"Hadits Anas ini derajatnya hasan shahih.\" Telah diriwayatkan dari Ali bin Abu Thalib, bahwa ia berkata tentang seorang laki-laki yang lupa mengerjakan shalat, beliau bersabda: \"Hendaklah ia shalat kapan saja ia mengingatnya, baik dalam waktu atau di luar waktunya.\" Ini adalah pendapat yang diambil oleh Syafi'i, Ahmad bin Hambal dan Ishaq.\" Diriwayatkan pula dari Abu Bakrah bahwa ia pernah tertidur hingga tidak mengerjakan shalat asar, dan ia terbangun ketika matahari telah terbenam, maka ia pun tidak mengerjakan shalat hingga matahari terbenam.\" Sebagian penduduk Kufah berpendapat seperti ini, adapun kawan-kawan kami mereka berpegangan sebagaimana yang diamalkan oleh Ali bin Abu Thalib Radliaallahu 'anhu.\""},"164":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا هُشَيْمٌ عَنْ أَبِي الزُّبَيْرِ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِي عُبَيْدَةَ بْنِ عَبْدِ اللَّهِ ابْنِ مَسْعُودٍ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍإِنَّ الْمُشْرِكِينَ شَغَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَرْبَعِ صَلَوَاتٍ يَوْمَ الْخَنْدَقِ حَتَّى ذَهَبَ مِنْ اللَّيْلِ مَا شَاءَ اللَّهُ فَأَمَرَ بِلَالًا فَأَذَّنَ ثُمَّ أَقَامَ فَصَلَّى الظُّهْرَ ثُمَّ أَقَامَ فَصَلَّى الْعَصْرَ ثُمَّ أَقَامَ فَصَلَّى الْمَغْرِبَ ثُمَّ أَقَامَ فَصَلَّى الْعِشَاءَقَالَ وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ وَجَابِرٍ قَالَ أَبُو عِيسَى حَدِيثُ عَبْدِ اللَّهِ لَيْسَ بِإِسْنَادِهِ بَأْسٌ إِلَّا أَنَّ أَبَا عُبَيْدَةَ لَمْ يَسْمَعْ مِنْ عَبْدِ اللَّهِ وَهُوَ الَّذِي اخْتَارَهُ بَعْضُ أَهْلِ الْعِلْمِ فِي الْفَوَائِتِ أَنْ يُقِيمَ الرَّجُلُ لِكُلِّ صَلَاةٍ إِذَا قَضَاهَا وَإِنْ لَمْ يُقِمْ أَجْزَأَهُ وَهُوَ قَوْلُ الشَّافِعِيِّ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Husyaim] dari [Abu Az Zubair] dari [Nafi' bin Jubair bin Muth'im] dari [Abu Ubaidah bin Abdullah bin Mas'ud] ia berkata; \" [Abdullah bin Mas'ud] berkata; \"Orang orang Musyrik telah menyibukkan Rasulullah shallallahu 'alaihi wasallam dari melaksanakan empat waktu shalat, pada hari perang Khandaq sampai malam berlalu dengan kehendak Allah. Kemudian beliau memerintahkan Bilal (untuk mengumandangkan adzan), maka Bilal pun mengumandangkan adzan dan Iqamat. Beliau kemudian melaksanakan shalat zhuhur, kemudian Bilal iqamat lalu beliau shalat asar. Kemudian Bilal iqamat lalu beliau shalat maghrib. Kemudian Bilal iqamat lalu beliau melaksanakan shalat isya.\" Ia berkata; \"Dalam bab ini terdapat hadits dari Abu Sa'id dan Jabir.\" Abu Isa berkata; \"Hadits Abdullah dalam sanadnya tidak ada masalah, akan tetapi Abu Ubaidah tidak mendengar dari Abdullah.\" Inilah yang dipilih oleh sebagian ulama mengenai shalat yang ketinggalan, bahwa seorang laki-laki hendaklah mengumandangkan iqamah pada setiap shalat jika ia mengqadlanya, dan sekiranya tidak mengumandangkannya maka itu telah cukup. Ini adalah pendapat Syafi'i.\""},"165":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ بُنْدَارٌ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ حَدَّثَنَا أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَ يَوْمَ الْخَنْدَقِ وَجَعَلَ يَسُبُّ كُفَّارَ قُرَيْشٍ قَالَ يَا رَسُولَ اللَّهِ مَا كِدْتُ أُصَلِّي الْعَصْرَ حَتَّى تَغْرُبَ الشَّمْسُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ إِنْ صَلَّيْتُهَا قَالَ فَنَزَلْنَا بُطْحَانَ فَتَوَضَّأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَوَضَّأْنَا فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ بَعْدَ مَا غَرَبَتْ الشَّمْسُ ثُمَّ صَلَّى بَعْدَهَا الْمَغْرِبَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Muhammad bin Basyar Bundar] berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam] berkata; telah menceritakan kepadaku [Ayahku] dari [Yahya bin Abu Katsir] berkata; telah menceritakan kepada kami [Abu Salamah bin Abdurrahman] dari [Jabir bin Abdullah] berkata: \"Pada saat perang Khandaq, Umar bin Khaththab mencerca orang-orang kafir Quraisy seraya mengatakan, \"Wahai Rasulullah, hampir-hampir saya tidak bisa melaksanakan shalat asar hingga matahari tenggelam!\" Rasulullah shallallahu 'alaihi wasallam kemudian menjawab: \"Demi Allah, aku juga belum melaksanakannya.\" Jabir berkata; \"Kemudian kami singgah di Buthhan (sebuah lembah di Madinah), lalu Rasulullah shallallahu 'alaihi wasallam berwudlu dan kamipun ikut berwudlu, Rasulullah shallallahu 'alaihi wasallam kemudian melaksanakan shalat asar setelah matahari tenggelam, setelah itu beliau melaksanakan shalat maghrib.\" Abu Isa berkata; \"Hadits ini derejatnya hasan shahih.\""},"166":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ وَأَبُو النَّضْرِ عَنْ مُحَمَّدِ بْنِ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ زُبَيْدٍ عَنْ مُرَّةَ الْهَمْدَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ الْوُسْطَى صَلَاةُ الْعَصْرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Abu Dawud Ath Thayalisi] dan [Abu An Nadlr] dari [Muhammad bin Thalhah bin Musharrif] dari [Zubaid] dari [Al Hamdani] dari [Abdullah bin Mas'ud] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat wustha adalah shalat asar.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\""},"167":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ صَلَاةُ الْوُسْطَى صَلَاةُ الْعَصْرِقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَعَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَزَيْدِ بْنِ ثَابِتٍ وَعَائِشَةَ وَحَفْصَةَ وَأَبِي هُرَيْرَةَ وَأَبِي هَاشِمِ بْنِ عُتْبَةَ قَالَ أَبُو عِيسَى قَالَ مُحَمَّدٌ قَالَ عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدِيثُ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ حَدِيثٌ صَحِيحٌ وَقَدْ سَمِعَ مِنْهُ قَالَ أَبُو عِيسَى حَدِيثُ سَمُرَةَ فِي صَلَاةِ الْوُسْطَى حَدِيثٌ حَسَنٌ وَهُوَ قَوْلُ أَكْثَرِ الْعُلَمَاءِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ و قَالَ زَيْدُ بْنُ ثَابِتٍ وَعَائِشَةُ صَلَاةُ الْوُسْطَى صَلَاةُ الظُّهْرِ و قَالَ ابْنُ عَبَّاسٍ وَابْنُ عُمَرَ صَلَاةُ الْوُسْطَى صَلَاةُ الصُّبْحِ حَدَّثَنَا أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا قُرَيْشُ بْنُ أَنَسٍ عَنْ حَبِيبِ بْنِ الشَّهِيدِ قَالَ قَالَ لِي مُحَمَّدُ بْنُ سِيرِينَ سَلِ الْحَسَنَ مِمَّنْ سَمِعَ حَدِيثَ الْعَقِيقَةِ فَسَأَلْتُهُ فَقَالَ سَمِعْتُهُ مِنْ سَمُرَةَ بْنِ جُنْدَبٍ قَالَ أَبُو عِيسَى و أَخْبَرَنِي مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ بْنِ الْمَدِينِيِّ عَنْ قُرَيْشِ بْنِ أَنَسٍ بِهَذَا الْحَدِيثِ قَالَ مُحَمَّدٌ قَالَ عَلِيٌّ وَسَمَاعُ الْحَسَنِ مِنْ سَمُرَةَ صَحِيحٌ وَاحْتَجَّ بِهَذَا الْحَدِيثِ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abdah] dari [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Samrah bin Jundab] dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau bersabda: \"Shalat wustha adalah shalat asar.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ali, Abdullah bin Mas'ud, Zaid bin Tsabit, 'Aisyah, Hafshah, Abu Hurairah dan Abu Hasyim bin Utbah.\" Abu Isa berkata; \"Muhammad berkata; \"Ali bin Abdullah mengatakan bahwa hadits Samrah bin Jundab derajatnya hasan shahih, dan ia telah mendengar darinya.\" Abu Isa berkata; \"Hadits Samrah tentang shalat wustha adalah shalat asar, derajatnya hasan shahih. Ini adalah pendapat yang diambil oleh sebagian besar ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan selain mereka.\" Zaid bin Tsabit dan 'Aisyah mengatakan, \"Shalat wustha adalah shalat zhuhur.\" Sedangkan Ibnu Abbas dan Ibnu Umar mengatakan, \"Shalat wustha adalah shalat subuh.\" Telah menceritakan kepada kami Abu Musa Muhammad bin Al Mutsanna berkata; telah menceritakan kepada kami Quraisy bin Anas dari Habib Ibnu Asy Syahid ia berkata; \"Muhammad bin Sirin berkata; \"Bertanyalah kepada Al Hasan dari siapa ia mendengar hadits tentang Aqiqah?\" maka aku pun bertanya kepadanya, lalu ia menjawab, \"Aku mendengarnya dari Samrah bin Jundab.\" Abu Isa berkata; \"Telah menceritakan kepada kami Muhammad bin Isma'il berkata; telah menceritakan kepada kami Ali bin Abdullah bin Al Madini dari Quraisy bin Anas dengan hadits ini.\" Muhammad berkata; \"Ali berkata; \"Mendengarnya Al Hasan dari Samrah adalah benar, dan ia berdasar dengan hadits ini.\""},"168":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا مَنْصُورٌ وَهُوَ ابْنُ زَاذَانَ عَنْ قَتَادَةَ قَالَ أَخْبَرَنَا أَبُو الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍ قَال سَمِعْتُ غَيْرَ وَاحِدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ عُمَرُ بْنُ الْخَطَّابِ وَكَانَ مِنْ أَحَبِّهِمْ إِلَيَّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الصَّلَاةِ بَعْدَ الْفَجْرِ حَتَّى تَطْلُعَ الشَّمْسُ وَعَنْ الصَّلَاةِ بَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَابْنِ مَسْعُودٍ وَعُقْبَةَ بْنِ عَامِرٍ وَأَبِي هُرَيْرَةَ وَابْنِ عُمَرَ وَسَمُرَةَ بْنِ جُنْدَبٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَمُعَاذِ ابْنِ عَفْرَاءَ وَالصُّنَابِحِيِّ وَلَمْ يَسْمَعْ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَلَمَةَ بْنِ الْأَكْوَعِ وَزَيْدِ بْنِ ثَابِتٍ وَعَائِشَةَ وَكَعْبِ بْنِ مُرَّةَ وَأَبِي أُمَامَةَ وَعَمْرِو بْنِ عَبَسَةَ وَيَعْلَى بْنِ أُمَيَّةَ وَمُعَاوِيَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عَبَّاسٍ عَنْ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ أَكْثَرِ الْفُقَهَاءِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ أَنَّهُمْ كَرِهُوا الصَّلَاةَ بَعْدَ صَلَاةِ الصُّبْحِ حَتَّى تَطْلُعَ الشَّمْسُ وَبَعْدَ صَلَاةِ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ وَأَمَّا الصَّلَوَاتُ الْفَوَائِتُ فَلَا بَأْسَ أَنْ تُقْضَى بَعْدَ الْعَصْرِ وَبَعْدَ الصُّبْحِ قَالَ عَلِيُّ ابْنُ الْمَدِينِيِّ قَالَ يَحْيَى بْنُ سَعِيدٍ قَالَ شُعْبَةُ لَمْ يَسْمَعْ قَتَادَةُ مِنْ أَبِي الْعَالِيَةِ إِلَّا ثَلَاثَةَ أَشْيَاءَ حَدِيثَ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الصَّلَاةِ بَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ وَبَعْدَ الصُّبْحِ حَتَّى تَطْلُعَ الشَّمْسُ وَحَدِيثَ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَنْبَغِي لِأَحَدٍ أَنْ يَقُولَ أَنَا خَيْرٌ مِنْ يُونُسَ بْنِ مَتَّى وَحَدِيثَ عَلِيٍّ الْقُضَاةُ ثَلَاثَةٌ","id":"telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Husyaim] berkata; telah mengabarkan kepada kami [Manshur] - dia adalah Ibnu Zadzan- dari [Qatadah] berkata; telah mengabarkan kepada kami [Abu Al Aliyah] dari [Ibnu Abbas] berkata; aku banyak mendengar dari sahabat Nabi shallallahu 'alaihi wasallam, seperti [Umar bin Al Khaththab], dan ia termasuk orang yang paling aku sukai, \"Rasulullah shallallahu 'alaihi wasallam melarang shalat setelah fajar hingga matahari terbit, dan melarang shalat setelah asar hingga matahari terbenam.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ali, Ibnu Mas'ud, Uqbah bin Amir, Abu Hurairah, Ibnu Umar, Samrah bin Jundab, Abdullah bin Amru, Mu'adz bin 'Afra`, Ash Shunabihi -namun ia tidak mendengar dari Nabi shallallahu 'alaihi wasallam-, Salamah bin Al Akwa', Zaid bin Tsabit, 'Aisyah, Ka'ab bin Murrah, Abu Umamah, Amru bin Abasah, Ya'la bin Umayyah dan Mu'awiyah.\" Abu Isa berkata; \"Hadits Ibnu Abbas dari Umar derajatnya hasan shahih. Ini adalah pendapat kebanyakan fuqaha dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka, bahwasanya mereka memakruhkan shalat setelah subuh hingga matahari terbit dan setelah asar hingga matahari terbenam. Adapun shalat-shalat yang tertinggal, maka tidak apa-apa untuk dikerjakan (mengqadlanya) setelah subuh atau asar. Ali bin Al Madini berkata; \"Yahya bin Sa'id berkata; \"Syu'bah tidak pernah mendengar dari Qatadah yang diriwayatkan dari Abu Al Aliyah kecuali tiga hadits; Hadits Umar; \"Nabi shallallahu 'alaihi wasallam melarang shalat setelah subuh hingga matahari terbit dan shalat setelah asar hingga matahari terbenam.\" Hadits Ibnu Abbas dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak selayaknya seseorang mengatakan, \"Aku lebih baik dari Yahya bin Mata.\" Hadits Ali, bahwa Qadli itu ada tiga tipe."},"169":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَإِنَّمَا صَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّكْعَتَيْنِ بَعْدَ الْعَصْرِ لِأَنَّهُ أَتَاهُ مَالٌ فَشَغَلَهُ عَنْ الرَّكْعَتَيْنِ بَعْدَ الظُّهْرِ فَصَلَّاهُمَا بَعْدَ الْعَصْرِ ثُمَّ لَمْ يَعُدْ لَهُمَاوَفِي الْبَاب عَنْ عَائِشَةَ وَأُمِّ سَلَمَةَ وَمَيْمُونَةَ وَأَبِي مُوسَى قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عَبَّاسٍ حَدِيثٌ حَسَنٌ وَقَدْ رَوَى غَيْرُ وَاحِدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى بَعْدَ الْعَصْرِ رَكْعَتَيْنِ وَهَذَا خِلَافُ مَا رُوِيَ عَنْهُ أَنَّهُ نَهَى عَنْ الصَّلَاةِ بَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ وَحَدِيثُ ابْنِ عَبَّاسٍ أَصَحُّ حَيْثُ قَالَ لَمْ يَعُدْ لَهُمَا وَقَدْ رُوِيَ عَنْ زَيْدِ بْنِ ثَابِتٍ نَحْوُ حَدِيثِ ابْنِ عَبَّاسٍ وَقَدْ رُوِيَ عَنْ عَائِشَةَ فِي هَذَا الْبَابِ رِوَايَاتٌ رُوِيَ عَنْهَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا دَخَلَ عَلَيْهَا بَعْدَ الْعَصْرِ إِلَّا صَلَّى رَكْعَتَيْنِ وَرُوِيَ عَنْهَا عَنْ أُمِّ سَلَمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ الصَّلَاةِ بَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ وَبَعْدَ الصُّبْحِ حَتَّى تَطْلُعَ الشَّمْسُ وَالَّذِي اجْتَمَعَ عَلَيْهِ أَكْثَرُ أَهْلِ الْعِلْمِ عَلَى كَرَاهِيَةِ الصَّلَاةِ بَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ وَبَعْدَ الصُّبْحِ حَتَّى تَطْلُعَ الشَّمْسُ إِلَّا مَا اسْتُثْنِيَ مِنْ ذَلِكَ مِثْلُ الصَّلَاةِ بِمَكَّةَ بَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ وَبَعْدَ الصُّبْحِ حَتَّى تَطْلُعَ الشَّمْسُ بَعْدَ الطَّوَافِ فَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُخْصَةٌ فِي ذَلِكَ وَقَدْ قَالَ بِهِ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ وَبِهِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ وَقَدْ كَرِهَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ الصَّلَاةَ بِمَكَّةَ أَيْضًا بَعْدَ الْعَصْرِ وَبَعْدَ الصُّبْحِ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَمَالِكُ بْنُ أَنَسٍ وَبَعْضُ أَهْلِ الْكُوفَةِ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Jarir] dari ['Atha` bin Sa'ib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata; \"Nabi shallallahu 'alaihi wasallam mengerjakan shalat dua rakaat setelah asar karena beliau mengurusi masalah harta kaum muslimin, sehingga beliau sibuk dan tidak dapat melaksanakan shalat dua rakaat setelah zhuhur. Maka beliau pun melaksanakan dua rakaat itu setelah asar, dan beliau tidak lagi melakukannya.\" Dalam bab ini ada juga hadits dari 'Aisyah, Ummu Salamah, Maimunah, dan Abu Musa.\" Abu Isa berkata; \"Hadits Ibnu Abbas adalah hadits hasan, dan banyak perawi telah meriwayatkan dari Nabi shallallahu 'alaihi wasallam bahwa beliau shalat dua rakaat setelah asar. Dan ini menyelisihi apa yang diriwayatkan darinya (Nabi) bahwa beliau melarang shalat setelah asar sampai matahari tenggelam. Haditsnya Ibnu Abbas adalah lebih shahih karena disebutkan di dalamnya, bahwa beliau tidak mengulangi melakukan shalat dua rakaat tersebut.\" Dan telah diriwayatkan pula sebuah hadits dari Zaid bin Tsabit yang semakna dengan hadits Ibnu Abbas. Dan telah diriwayatkan pula dari 'Aisyah beberapa hadits yang mengatakan bahwa Nabi shallallahu 'alaihi wasallam tidak pernah masuk menemuinya ('Aisyah) setelah waktu asar kecuali beliau shalat dua rakaat. Dan riwayat lain dari 'Aisyah, dari Ummu Salamah, dari Nabi shallallahu 'alaihi wasallam bahwa beliau melarang shalat setelah asar hingga matahari tenggelam, dan melarang shalat setelah subuh hingga matahari terbit. Dan yang menjadi kesepakatan para ahli ilmu adalah dimakruhkannya shalat setelah asar hingga matahari tenggelam, dan shalat setelah subuh hingga matahari terbit. Kecuali yang sudah dikecualikan seperti shalat di Makkah setelah asar hingga matahari tenggelam dan setelah subuh hingga matahari terbit setelah melaksanakan tawaf. Telah diriwayatkan dari Nabi shallallahu 'alaihi wasallam bahwa beliau memberikan keringanan dalam hal ini. Ini telah menjadi pendapat sekelompok ahli ilmu dari para sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka. Pendapat ini juga diambil oleh Imam Syafi'i, Ahmad dan Ishaq. Sedangkan sekelompok ahli ilmu yang lainnya, dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelahnya, mereka juga memakruhkan shalat setelah asar dan subuh di Makkah. Pendapat ini diambil oleh Sufyan Ats Tsauri, Malik bin Anas dan sebagian penduduk Kufah.\""},"170":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ كَهْمَسِ بْنِ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَ كُلِّ أَذَانَيْنِ صَلَاةٌ لِمَنْ شَاءَوَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ قَالَ أَبُو عِيسَى حَدِيثُ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ اخْتَلَفَ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّلَاةِ قَبْلَ الْمَغْرِبِ فَلَمْ يَرَ بَعْضُهُمْ الصَّلَاةَ قَبْلَ الْمَغْرِبِ وَقَدْ رُوِيَ عَنْ غَيْرِ وَاحِدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمْ كَانُوا يُصَلُّونَ قَبْلَ صَلَاةِ الْمَغْرِبِ رَكْعَتَيْنِ بَيْنَ الْأَذَانِ وَالْإِقَامَةِ و قَالَ أَحْمَدُ وَإِسْحَقُ إِنْ صَلَّاهُمَا فَحَسَنٌ وَهَذَا عِنْدَهُمَا عَلَى الِاسْتِحْبَابِ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Waki'] dari [Kahmas bin Al Hasan] dari [Abdullah bin Buraidah] dari [Abdullah bin Mughaffal] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Antara dua adzan ada shalat bagi yang ingin mengerjakannya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin Az Zubair.\" Abu Isa berkata; \"Hadits Abdullah bin Al Mughaffal derajatnya hasan shahih.\" Sebagian sahabat Nabi shallallahu 'alaihi wasallam berselisih pendapat tentang shalat sebelum maghrib, sebagian mereka berpendapat bahwa shalat sebelum maghrib tidak ada. Dan telah diriwayatkan dari banyak sahabat Nabi shallallahu 'alaihi wasallam bahwa mereka melaksanakan shalat dua rakaat sebelum maghrib, yaitu antara iqamah dan adzan. Ahmad dan Ishaq berkata; \"Jika seseorang mengerjakannya maka itu sebuah kebaikan.\" Mereka berdua menganggap bahwa hal itu hukumnya sunah.\""},"171":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ وَعَنْ بُسْرِ بْنِ سَعِيدٍ وَعَنْ الْأَعْرَجِ يُحَدِّثُونَهُ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ مِنْ الصُّبْحِ رَكْعَةً قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ فَقَدْ أَدْرَكَ الصُّبْحَ وَمَنْ أَدْرَكَ مِنْ الْعَصْرِ رَكْعَةً قَبْلَ أَنْ تَغْرُبَ الشَّمْسُ فَقَدْ أَدْرَكَ الْعَصْرَوَفِي الْبَاب عَنْ عَائِشَةَ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَبِهِ يَقُولُ أَصْحَابُنَا وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ وَمَعْنَى هَذَا الْحَدِيثِ عِنْدَهُمْ لِصَاحِبِ الْعُذْرِ مِثْلُ الرَّجُلِ الَّذِي يَنَامُ عَنْ الصَّلَاةِ أَوْ يَنْسَاهَا فَيَسْتَيْقِظُ وَيَذْكُرُ عِنْدَ طُلُوعِ الشَّمْسِ وَعِنْدَ غُرُوبِهَا","id":"telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] berkata; telah menceritakan kepada kami [Ma'n] berkata; telah menceritakan kepada kami [Malik bin Anas] dari [Zaid bin Aslam] dari ['Atha` bin Yasar], dan dari [Busr bin Sa'id] dan dari [Al A'raj] mereka menceritakannya dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendapatkan satu rakaat shalat subuh sebelum terbitnya matahari maka ia telah mendapatkannya. Dan barangsiapa mendapatkan saru rakaat shalat asar sebelum terbenamnya matahari maka ia telah mendapatkannya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari 'Aisyah.\" Abu Isa berkata; \"Hadits Abu Hurairah derajatnya hasan shahih. Pendapat inilah yang diambil oleh para sahabat kami, Syafi'i, Ahmad dan Ishaq. Menurut mereka, hadits ini berlaku bagi seseorang yang udzur, seperti seorang laki-laki yang ketinggalan shalat karena tidur atau lupa, lalu ia bangun atau teringat ketika matahari terbit atau terbenam.\""},"172":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَجَمَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الظُّهْرِ وَالْعَصْرِ وَبَيْنَ الْمَغْرِبِ وَالْعِشَاءِ بِالْمَدِينَةِ مِنْ غَيْرِ خَوْفٍ وَلَا مَطَرٍقَالَ فَقِيلَ لِابْنِ عَبَّاسٍ مَا أَرَادَ بِذَلِكَ قَالَ أَرَادَ أَنْ لَا يُحْرِجَ أُمَّتَهُ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عَبَّاسٍ قَدْ رُوِيَ عَنْهُ مِنْ غَيْرِ وَجْهٍ رَوَاهُ جَابِرُ بْنُ زَيْدٍ وَسَعِيدُ بْنُ جُبَيْرٍ وَعَبْدُ اللَّهِ بْنُ شَقِيقٍ الْعُقَيْلِيُّ وَقَدْ رُوِيَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرُ هَذَا","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata; \"Di Madinah Rasulullah shallallahu 'alaihi wasallam pernah menjamak antara shalat zhuhur dan asar, serta antara maghrib dan isya, bukan karena takut atau hujan.\" Sa'id berkata; \"Dikatakan kepada Ibnu Abbas, \"Apa yang beliau kehendaki dari hal itu?\" ia menjawab, \"Beliau tidak ingin mempersulit rakyatnya.\" Ia berkata; \"Dalam bab ini juga terdapat hadits dari Abu Hurairah.\" Abu Isa berkata; \"Hadits Ibnu Abbas ini diriwayatkan dari beberapa jalur. Yaitu [Jabir bin Zaid] dan [Sa'id bin Jubair] dan [Abdullah bin Syaqiq Al 'Uqaili]. Juga diriwayatkan selain dari jalur ini; dari Ibnu Abbas, dari Nabi shallallahu 'alaihi wasallam.\""},"173":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ يَحْيَى بْنُ خَلَفٍ الْبَصْرِيُّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ عَنْ حَنَشٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ جَمَعَ بَيْنَ الصَّلَاتَيْنِ مِنْ غَيْرِ عُذْرٍ فَقَدْ أَتَى بَابًا مِنْ أَبْوَابِ الْكَبَائِرِقَالَ أَبُو عِيسَى وَحَنَشٌ هَذَا هُوَ أَبُو عَلِيٍّ الرَّحَبِيُّ وَهُوَ حُسَيْنُ بْنُ قَيْسٍ وَهُوَ ضَعِيفٌ عِنْدَ أَهْلِ الْحَدِيثِ ضَعَّفَهُ أَحْمَدُ وَغَيْرُهُ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ أَنْ لَا يَجْمَعَ بَيْنَ الصَّلَاتَيْنِ إِلَّا فِي السَّفَرِ أَوْ بِعَرَفَةَ وَرَخَّصَ بَعْضُ أَهْلِ الْعِلْمِ مِنْ التَّابِعِينَ فِي الْجَمْعِ بَيْنَ الصَّلَاتَيْنِ لِلْمَرِيضِ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ يَجْمَعُ بَيْنَ الصَّلَاتَيْنِ فِي الْمَطَرِ وَبِهِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ وَلَمْ يَرَ الشَّافِعِيُّ لِلْمَرِيضِ أَنْ يَجْمَعَ بَيْنَ الصَّلَاتَيْنِ","id":"telah menceritakan kepada kami [Abu Salamah Yahya bin Khalaf Al Bashri] berkata; telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari [ayahnya] dari [Hanasy] dari [Ikrimah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa menjamak antara dua shalat tanpa udzur, maka ia telah mendatangi salah satu pintu dari pintu pintu dosa besar.\" Abu Isa berkata; \"Hanasy adalah Abu Ali Ar Rahabi, yaitu Husain bin Qais. Menurut para ahli hadits ia adalah seorang yang lemah. Imam Ahmad dan yang lainnya juga telah melemahkannya.\" Hadits ini diamalkan oleh para ahli ilmu, bahwa tidak boleh menjamak dua shalat kecuali pada saat safar atau pada waktu di Arafah. Dan sebagian ahli ilmu dari kalangan tabi'in memberikan keringan untuk menjamak dua shalat bagi orang yang sakit. Ini adalah pendapat yang diambil oleh Ahmad dan Ishaq. Sedangkan sebagian ahli ilmu mengatakan bahwa menjamak dua shalat itu hanya pada waktu turun hujan. Ini adalah pendapat yang diambil oleh Syafi'i, Ahmad dan Ishaq. Sedangkan Imam Syafi'i tidak berpendapat bahwa orang sakit boleh menjamak dua shalat.\""},"174":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ الْأُمَوِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيِّ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ زَيْدٍ عَنْ أَبِيهِ قَالَلَمَّا أَصْبَحْنَا أَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ بِالرُّؤْيَا فَقَالَ إِنَّ هَذِهِ لَرُؤْيَا حَقٍّ فَقُمْ مَعَ بِلَالٍ فَإِنَّهُ أَنْدَى وَأَمَدُّ صَوْتًا مِنْكَ فَأَلْقِ عَلَيْهِ مَا قِيلَ لَكَ وَلْيُنَادِ بِذَلِكَ قَالَ فَلَمَّا سَمِعَ عُمَرُ بْنُ الْخَطَّابِ نِدَاءَ بِلَالٍ بِالصَّلَاةِ خَرَجَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَجُرُّ إِزَارَهُ وَهُوَ يَقُولُ يَا رَسُولَ اللَّهِ وَالَّذِي بَعَثَكَ بِالْحَقِّ لَقَدْ رَأَيْتُ مِثْلَ الَّذِي قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلِلَّهِ الْحَمْدُ فَذَلِكَ أَثْبَتُقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ قَالَ أَبُو عِيسَى حَدِيثُ عَبْدِ اللَّهِ بْنِ زَيْدٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَى هَذَا الْحَدِيثَ إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ أَتَمَّ مِنْ هَذَا الْحَدِيثِ وَأَطْوَلَ وَذَكَرَ فِيهِ قِصَّةَ الْأَذَانِ مَثْنَى مَثْنَى وَالْإِقَامَةِ مَرَّةً مَرَّةً وَعَبْدُ اللَّهِ بْنُ زَيْدٍ هُوَ ابْنُ عَبْدِ رَبِّهِ وَيُقَالُ ابْنُ عَبْدِ رَبٍّ وَلَا نَعْرِفُ لَهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا يَصِحُّ إِلَّا هَذَا الْحَدِيثَ الْوَاحِدَ فِي الْأَذَانِ وَعَبْدُ اللَّهِ بْنُ زَيْدِ بْنِ عَاصِمٍ الْمَازِنِيُّ لَهُ أَحَادِيثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَمُّ عَبَّادِ بْنِ تَمِيمٍ","id":"telah menceritakan kepada kami [Sa'id bin Yahya bin Sa'id Al Umawi] berkata; telah menceritakan kepada kami [ayahku] berkata; telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim Al Harits At Taimi] dari [Muhammad bin Abdullah bin Zaid] dari [Ayahnya] ia berkata; \"Pada suatu pagi kami mendatangi Rasulullah shallallahu 'alaihi wasallam, aku lalu mengabarkan kepadanya perihal mimpi yang aku alami, beliau lalu bersabda: \"Ini mimpi yang benar, maka berdirilah bersama Bilal, karena suaranya lebih lantang dan panjang daripada kamu, sampaikanlah padanya apa yang dikatakan padamu (impikan), suruhlah agar ia menyeru dengannya.\" Abdullah bin Zaid berkata; \"Ketika Umar bin Al Khaththab mendengar seruan Bilal, maka ia pun keluar menemui Rasulullah shallallahu 'alaihi wasallam seraya menjinjing kain sarungnya, ia lantas berkata; \"Wahai Rasulullah, demi Dzat yang mengutusmu dengan kebenaran, aku juga telah mengimpikan sebagaimana yang ia serukan.\" Abdullah bin Zaid berkata; \"Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Milik Allah lah segala pujian, maka itu akan lebih menguatkan lagi.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Umar.\" Abu Isa berkata; \"Hadits Abdullah bin Zaid ini derajatnya hasan shahih. [Ibrahim bin Sa'd] telah meriwayatkan hadits ini dari [Muhammad bin Ishaq] dengan lafadz yang lebih sempurna dan lebih panjang. Disebutkan dalam hadits tersebut bahwa adzan dua kali-dua kali, sedangkan iqamah dengan satu kali-satu kali.\" Abdullah bin Zaid adalah Ibnu Abdu Rabbih, dan disebut juga dengan Ibnu Abdu Rabbi. Dan kami tidak pernah mengetahui hadits shahih darinya yang diriwayatkan dari Nabi shallallahu 'alaihi wasallam selain hadits yang berkenaan dengan adzan ini. sedangkan Abdullah bin Zaid bin 'Ashim Al Mazini, ia mempunyai beberapa hadits yang diriwayatkan dari Nabi shallallahu 'alaihi wasallam. Ia adalah paman Abbad bin Tamim.\""},"175":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ النَّضْرِ بْنِ أَبِي النَّضْرِ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنَا نَافِعٌ عَنْ ابْنِ عُمَرَ قَالَكَانَ الْمُسْلِمُونَ حِينَ قَدِمُوا الْمَدِينَةَ يَجْتَمِعُونَ فَيَتَحَيَّنُونَ الصَّلَوَاتِ وَلَيْسَ يُنَادِي بِهَا أَحَدٌ فَتَكَلَّمُوا يَوْمًا فِي ذَلِكَ فَقَالَ بَعْضُهُمْ اتَّخِذُوا نَاقُوسًا مِثْلَ نَاقُوسِ النَّصَارَى وَقَالَ بَعْضُهُمْ اتَّخِذُوا قَرْنًا مِثْلَ قَرْنِ الْيَهُودِ قَالَ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ أَوَلَا تَبْعَثُونَ رَجُلًا يُنَادِي بِالصَّلَاةِ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بِلَالُ قُمْ فَنَادِ بِالصَّلَاةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ ابْنِ عُمَرَ","id":"telah menceritakan kepada kami [Abu Bakr bin An Nadlr bin Abu An Nadlr] berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad] ia berkata; [Ibnu Jurair] berkata; telah mengabarkan kepada kami [Nafi'] dari [Ibnu Umar] ia berkata; \"Ketika kaum muslimin datang ke Madinah, mereka berkumpul dan menunggu shalat namun tidak ada seorang pun yang menyeru (adzan). Lalu pada suatu hari mereka membicarakan hal itu, sebagian mereka berkata; \"Gunakanlah lonceng sebagaimana orang-orang Nashrani, \" Sebagian yang lain berkata; \"Gunakanlah terompet sebagaimana orang-orang Yahudi.\" Ibnu Umar berkata; \"Maka Umar pun berkata; \"Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Wahai Bilal, berdiri dan serulah untuk mendirikan shalat.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih gharib, dari hadits Ibnu Umar.\""},"176":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُعَاذٍ الْبَصْرِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ عَبْدِ الْعَزِيزِ بْنِ عَبْدِ الْمَلِكِ بْنِ أَبِي مَحْذُورَةَ قَالَ أَخْبَرَنِي أَبِي وَجَدِّي جَمِيعًا عَنْ أَبِي مَحْذُورَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْعَدَهُ وَأَلْقَى عَلَيْهِ الْأَذَانَ حَرْفًا حَرْفًاقَالَ إِبْرَاهِيمُ مِثْلَ أَذَانِنَا قَالَ بِشْرٌ فَقُلْتُ لَهُ أَعِدْ عَلَيَّ فَوَصَفَ الْأَذَانَ بِالتَّرْجِيعِ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي مَحْذُورَةَ فِي الْأَذَانِ حَدِيثٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْهُ مِنْ غَيْرِ وَجْهٍ وَعَلَيْهِ الْعَمَلُ بِمَكَّةَ وَهُوَ قَوْلُ الشَّافِعِيِّ","id":"telah menceritakan kepada kami [Biysr bin Mu'adz Al Bashri] berkata; telah menceritakan kepada kami [Ibrahim bin Abdul Aziz bin Abdul Malik bin Abu Mahdzurah] ia berkata; telah mengabarkan kepadaku [ayahku] dan [kakekku] dari [Abu Mahdzurah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mendudukkannya lalu membacakan kepadanya huruf demi huruf. Ibrahim lalu berkata; \"(Persis) sebagaimana adzan kita.\" Bisyr berkata; \"Lalu aku berkata kepadanya, \"Ulangilah untukku!\" maka ia pun mensifati adzan dengan diulang-ulang.\" Abu Isa berkata; \"Hadits Abu Mahdzurah tentang adzan ini derajatnya shahih. Hadits ini juga telah diriwayatkan darinya dengan jalur yang lain. Hadits ini banyak diamalkan oleh penduduk Makkah, dan ini adalah pendapat Syafi'i.\""},"177":{"ar":"حَدَّثَنَا أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ عَنْ عَامِرِ بْنِ عَبْدِ الْوَاحِدِ الْأَحْوَلِ عَنْ مَكْحُولٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَيْرِيزٍ عَنْ أَبِي مَحْذُورَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَّمَهُ الْأَذَانَ تِسْعَ عَشْرَةَ كَلِمَةً وَالْإِقَامَةَ سَبْعَ عَشْرَةَ كَلِمَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو مَحْذُورَةَ اسْمُهُ سَمُرَةُ بْنُ مِعْيَرٍ وَقَدْ ذَهَبَ بَعْضُ أَهْلِ الْعِلْمِ إِلَى هَذَا فِي الْأَذَانِ وَقَدْ رُوِيَ عَنْ أَبِي مَحْذُورَةَ أَنَّهُ كَانَ يُفْرِدُ الْإِقَامَةَ","id":"telah menceritakan kepada kami [Abu Musa Muhammad bin Al Mutsanna] berkata; telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Hammam] dari ['Amir bin Abdul Wahid Al Ahwal] dari [Makhul] dari [Abdullah bin Muhairiz] dari [Abu Mahdzurah] bahwa Nabi shallallahu 'alaihi wasallam mengajarkan adzan kepadanya sembilan belas kalimat, sedangkan iqamah tujuh belas kalimat.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, sednagkan Abu Mahdzurah namanya adalah Samrah bin Mi'yar.\" Dalam persoalan adzan banyak ahli ilmu yang berpegangan dengan hadits ini. pernah diriwayatkan dari Abu Mahdzurah bahwa ia mengucapkan satu kalimat-satu kalimat dalam iqamah.\""},"178":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ وَيَزِيدُ بْنُ زُرَيْعٍ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأُمِرَ بِلَالٌ أَنْ يَشْفَعَ الْأَذَانَ وَيُوتِرَ الْإِقَامَةَوَفِي الْبَاب عَنْ ابْنِ عُمَرَ قَالَ أَبُو عِيسَى وَحَدِيثُ أَنَسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ بَعْضِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَبِهِ يَقُولُ مَالِكٌ وَالشَّافِعِيُّ وَ��َحْمَدُ وَإِسْحَقُ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abdul Wahhab Ats Tsaqfi] dan [Yazid bin Zurai'] dari [Khalid Al Hadza`] dari [Abu Qilabah] dari [Anas bin Malik] ia berkata; \"Bilal diperintahkan untuk menggenapkan bilangan dalam adzan dan mengganjilkan bilangan dalam iqamah.\" Dalam bab ini juga ada riwayat dari Ibnu Umar. Abu Isa berkata; \"Hadits Anas ini derajatnya hasan shahih. Ini adalah pendapat yang diambil oleh sebagian ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in. pendapat ini juga diambil oleh Malik, Syafi'i, Ahmad dan Ishaq.\""},"179":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ قَالَكَانَ أَذَانُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَفْعًا شَفْعًا فِي الْأَذَانِ وَالْإِقَامَةِقَالَ أَبُو عِيسَى حَدِيثُ عَبْدِ اللَّهِ بْنِ زَيْدٍ رَوَاهُ وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَالَ حَدَّثَنَا أَصْحَابُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ عَبْدَ اللَّهِ بْنَ زَيْدٍ رَأَى الْأَذَانَ فِي الْمَنَامِ و قَالَ شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى أَنَّ عَبْدَ اللَّهِ بْنَ زَيْدٍ رَأَى الْأَذَانَ فِي الْمَنَامِ وَهَذَا أَصَحُّ مِنْ حَدِيثِ ابْنِ أَبِي لَيْلَى وَعَبْدُ الرَّحْمَنِ بْنُ أَبِي لَيْلَى لَمْ يَسْمَعْ مِنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ الْأَذَانُ مَثْنَى مَثْنَى وَالْإِقَامَةُ مَثْنَى مَثْنَى وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَأَهْلُ الْكُوفَةِ قَالَ أَبُو عِيسَى ابْنُ أَبِي لَيْلَى هُوَ مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى كَانَ قَاضِيَ الْكُوفَةِ وَلَمْ يَسْمَعْ مِنْ أَبِيهِ شَيْئًا إِلَّا أَنَّهُ يَرْوِي عَنْ رَجُلٍ عَنْ أَبِيهِ","id":"telah menceritakan kepada kami [Abu Sa'id Al Asyajj] berkata; telah menceritakan kepada kami [Uqbah bin Khalid] dari [Ibnu Abu Laila] dari ['Amru bin Murrah] dari [Abdurrahman bin Abu Laila] dari [Abdullah bin Zaid] ia berkata; \"Seruan Rasulullah shallallahu 'alaihi wasallam dua kali-dua kali dalam baik dalam adzan maupun iqamah.\" Abu Isa berkata; \"Hadits Abdullah bin Zaid ini telah diriwayatkan oleh [Waki'] dari [Al A'masy] dari ['Amru bin Murrah] dari [Abdurrahman bin Abu Laila]. Ia berkata; \" [Para sahabat Muhammad shallallahu 'alaihi wasallam] meriwayatkan kepada kami bahwa [Abdullah bin Zaid] bermimpi tentang adzan ketika tidur.\" Sedangkan [Syu'bah] meriwayatkan dari ['Amru bin Murrah] dari [Abdurrahman bin Abu Laila] bahwa [Abdullah bin Zaid] bermimpi tentang adzan ketika tidur. Dan ini lebih shahih daripada hadits riwayat Ibnu Abu Laila. Dan Abdurrahman juga belum pernah mendengar dari Abdullah bin Zaid. Sebagian ahli ilmu mengatakan bahwa adzan itu dua kali-dua kali. Pendapat ini diambil oleh Sufyan Ats Tsauri, bin Al Mubarak dan penduduk Kufah. Abu Isa berkata; \"Ibnu Abu Laila adalah Muhammad bin Abdurrahman bin Abu Laila, ia adalah seorang hakim di Kufah, dan ia belum pernah mendengar dari ayahnya suatu hadits pun. Hanya saja ia pernah mendengarnya dari seorang laki-laki yang meriwayatkan dari ayahnya.\""},"180":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْحَسَنِ حَدَّثَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ الْمُنْعِمِ هُوَ صَاحِبُ السِّقَاءِ قَالَ حَدَّثَنَا يَحْيَى بْنُ مُسْلِمٍ عَنْ الْحَسَنِ وَعَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِبِلَالٍ يَا بِلَالُ إِذَا أَذَّنْتَ فَتَرَسَّلْ فِي أَذَانِكَ وَإِذَا أَقَمْتَ فَاحْدُرْ وَاجْعَلْ بَيْنَ أَذَانِكَ وَإِقَامَتِكَ قَدْرَ مَا يَفْرُغُ الْآكِلُ مِنْ أَكْلِهِ وَالشَّارِبُ مِنْ شُرْبِهِ وَالْمُعْتَصِرُ إِذَا دَخَلَ لِقَضَاءِ حَاجَتِهِ وَلَا تَقُومُوا حَتَّى تَرَوْنِيحَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ عَنْ عَبْدِ الْمُنْعِمِ نَحْوَهُ قَالَ أَبُو عِيسَى حَدِيثُ جَابِرٍ هَذَا حَدِيثٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ عَبْدِ الْمُنْعِمِ وَهُوَ إِسْنَادٌ مَجْهُولٌ وَعَبْدُ الْمُنْعِمِ شَيْخٌ بَصْرِيٌّ","id":"telah menceritakan kepada kami [Ahmad bin Al Hasan] berkata; telah menceritakan kepada kami [Al Mu'alla bin Asad] berkata; telah menceritakan kepada kami [Abdul Mun'im] -ia adalah pemilik bejana- ia berkata; telah menceritakan kepada kami [Yahya bin Muslim] dari [Al Hasan] dan ['Atha`] dari [Jabir bin Abdullah] berkata; \"Rasulullah shallallahu 'alaihi wasallam berkata kepada Bilal: \"Wahai Bilal, jika engkau adzan maka lambatkanlah adzanmu, dan jika engkau iqamat maka percepatlah. Jadikanlah jarak antara adzan dan iqamatmu sekadar dengan seorang yang makan hingga selesai makannya, orang yang minum hingga selesai minummnya, orang yang buang hajat dapat menyelesaikan hajatnya, dan janganlah berdiri hingga kalian melihatku.\" Telah menceritakan kepada kami [Abd bin Humaid] berkata; telah menceritakan kepada kami [Yunus bin Muhammad] dari [Abdul Mun'im] dengan hadits yang semakna.\" Abu Isa berkata; \"Kami tidak mengetahui hadits Jabir ini kecuali dari jalur ini, yaitu dari hadits Abdul Mun'im yang sanadnya majhul (tidak diketahui). Dan Abdul Mun'im adalah seorang syaikh dari Bashrah.\""},"181":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ قَالَرَأَيْتُ بِلَالًا يُؤَذِّنُ وَيَدُورُ وَيُتْبِعُ فَاهُ هَا هُنَا وَهَا هُنَا وَإِصْبَعَاهُ فِي أُذُنَيْهِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قُبَّةٍ لَهُ حَمْرَاءَ أُرَاهُ قَالَ مِنْ أَدَمٍ فَخَرَجَ بِلَالٌ بَيْنَ يَدَيْهِ بِالْعَنَزَةِ فَرَكَزَهَا بِالْبَطْحَاءِ فَصَلَّى إِلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمُرُّ بَيْنَ يَدَيْهِ الْكَلْبُ وَالْحِمَارُ وَعَلَيْهِ حُلَّةٌ حَمْرَاءُ كَأَنِّي أَنْظُرُ إِلَى بَرِيقِ سَاقَيْهِقَالَ سُفْيَانُ نُرَاهُ حِبَرَةً قَالَ أَبُو عِيسَى حَدِيثُ أَبِي جُحَيْفَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَعَلَيْهِ الْعَمَلُ عِنْدَ أَهْلِ الْعِلْمِ يَسْتَحِبُّونَ أَنْ يُدْخِلَ الْمُؤَذِّنُ إِصْبَعَيْهِ فِي أُذُنَيْهِ فِي الْأَذَانِ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ وَفِي الْإِقَامَةِ أَيْضًا يُدْخِلُ إِصْبَعَيْهِ فِي أُذُنَيْهِ وَهُوَ قَوْلُ الْأَوْزَاعِيِّ وَأَبُو جُحَيْفَةَ اسْمُهُ وَهْبُ بْنُ عَبْدِ اللَّهِ السُّوَائِيُّ","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Abdurrazaq] berkata; telah mengabarkan kepada kami [Sufyan Ats Tsauri] dari ['Aun bin Abu Juhaifah] dari [Ayahnya] ia berkata; \"Aku melihat Bilal mengumandangkan adzan seraya berputar mengikuti mulutnya ke sini dan ke sini, sedang jari-jarinya ada di telinganya. Dan Rasulullah shallallahu 'alaihi wasallam waktu itu berada di dalam kubah merahnya. Menurutku ia mengatakan, \"Dari kulit.\" Lalu Bilal keluar dari dalam kubah tersebut dengan membawa tombak kecil, ia menancapkan tombak itu di tanah yang lapang. Setelah itu Rasulullah shallallahu 'alaihi wasallam shalat menghadap ke arah tombak tersebut, dan lewatlah seekor anjing dan keledai di hadapannya. Beliau waktu itu mengenakan pakaian merah dan seolah-olah aku dapat melihat kilatan kedua betisnya.\" Sufyan berkata; \"Kami memperkirakan bahwa pakaian itu adalah hibrah (pakaian yang terbuat dari sutra dan wol.\" Abu Isa berkata; \"Hadits Abu Juhaifah ini derajatnya hasan shahih. Hadits ini diamalkan oleh para ulama, mereka menyukai sekiranya seorang mu'adzin memasukkan jari-jarinya ke dalam telinga saat adzan. Sedangkan ulama lain mengatakan, \"Saat iqamah seseorang juga disunahkan untuk memasukkan jari-jarinya ke dalam telinganya.\" Ini adalah pendapat yang diambil oleh Al Auza'i. Dan Abu Juhaifah namanya adalah Wahb bin Abdullah As Suwa'i.\""},"182":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا أَبُو إِسْرَائِيلَ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ بِلَالٍ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُثَوِّبَنَّ فِي شَيْءٍ مِنْ الصَّلَوَاتِ إِلَّا فِي صَلَاةِ الْفَجْرِقَالَ وَفِي الْبَاب عَنْ أَبِي مَحْذُورَةَ قَالَ أَبُو عِيسَى حَدِيثُ بِلَالٍ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ أَبِي إِسْرَائِيلَ الْمُلَائِيِّ وَأَبُو إِسْرَائِيلَ لَمْ يَسْمَعْ هَذَا الْحَدِيثَ مِنْ الْحَكَمِ بْنِ عُتَيْبَةَ قَالَ إِنَّمَا رَوَاهُ عَنْ الْحَسَنِ بْنِ عُمَارَةَ عَنْ الْحَكَمِ بْنِ عُتَيْبَةَ وَأَبُو إِسْرَائِيلَ اسْمُهُ إِسْمَعِيلُ بْنُ أَبِي إِسْحَقَ وَلَيْسَ هُوَ بِذَاكَ الْقَوِيِّ عِنْدَ أَهْلِ الْحَدِيثِ وَقَدْ اخْتَلَفَ أَهْلُ الْعِلْمِ فِي تَفْسِيرِ التَّثْوِيبِ فَقَالَ بَعْضُهُمْ التَّثْوِيبُ أَنْ يَقُولَ فِي أَذَانِ الْفَجْرِ الصَّلَاةُ خَيْرٌ مِنْ النَّوْمِ وَهُوَ قَوْلُ ابْنِ الْمُبَارَكِ وَأَحْمَدَ و قَالَ إِسْحَقُ فِي التَّثْوِيبِ غَيْرَ هَذَا قَالَ التَّثْوِيبُ الْمَكْرُوهُ هُوَ شَيْءٌ أَحْدَثَهُ النَّاسُ بَعْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَذَّنَ الْمُؤَذِّنُ فَاسْتَبْطَأَ الْقَوْمَ قَالَ بَيْنَ الْأَذَانِ وَالْإِقَامَةِ قَدْ قَامَتْ الصَّلَاةُ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ قَالَ وَهَذَا الَّذِي قَالَ إِسْحَقُ هُوَ التَّثْوِيبُ الَّذِي قَدْ كَرِهَهُ أَهْلُ الْعِلْمِ وَالَّذِي أَحْدَثُوهُ بَعْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي فَسَّرَ ابْنُ الْمُبَارَكِ وَأَحْمَدُ أَنَّ التَّثْوِيبَ أَنْ يَقُولَ الْمُؤَذِّنُ فِي أَذَانِ الْفَجْرِ الصَّلَاةُ خَيْرٌ مِنْ النَّوْمِ وَهُوَ قَوْلٌ صَحِيحٌ وَيُقَالُ لَهُ التَّثْوِيبُ أَيْضًا وَهُوَ الَّذِي اخْتَارَهُ أَهْلُ الْعِلْمِ وَرَأَوْهُ وَرُوِيَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّهُ كَانَ يَقُولُ فِي صَلَاةِ الْفَجْرِ الصَّلَاةُ خَيْرٌ مِنْ النَّوْمِ وَرُوِيَ عَنْ مُجَاهِدٍ قَالَ دَخَلْتُ مَعَ عَبْدِ اللَّهِ بْنِ عُمَرَ مَسْجِدًا وَقَدْ أُذِّنَ فِيهِ وَنَحْنُ نُرِيدُ أَنْ نُصَلِّيَ فِيهِ فَثَوَّبَ الْمُؤَذِّنُ فَخَرَجَ عَبْدُ اللَّهِ بْنُ عُمَرَ مِنْ الْمَسْجِدِ وَقَالَ اخْرُجْ بِنَا مِنْ عِنْدِ هَذَا الْمُبْتَدِعِ وَلَمْ يُصَلِّ فِيهِ قَالَ وَإِنَّمَا كَرِهَ عَبْدُ اللَّهِ التَّثْوِيبَ الَّذِي أَحْدَثَهُ النَّاسُ بَعْدُ","id":"telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Abu Ahmad Az Zubair] berkata; telah menceritakan kepada kami [Abu Isra`il] dari [Al Hakam] dari [Abdurrahman bin Abu Laila] dari [Bilal] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah sekali-kali kamu melakukan tastwib (menguap) pada waktu-waktu shalat kecuali dalam shalat subuh.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Mahdlurah.\" Abu Isa berkata; \"Kami tidak mengetahui hadits Bilal kecuali dari Abu Isra'il Al Mula'I, dan Abu Isma'il belum pernah mendengar hadits ini dari Al Hakam bin Utaibah.\" Ia berkata; \"Hanyasanya ia meriwayatkan hadits ini dari Al Hasan bin Umarah, dari Al Hakam bin Utaibah. Dan Abu Isma'il namanya adalah Isma'il bin Abu Ishaq. Namun menurut ahli hadits ia bukan seorang yang kuat.\" Para ulama berselisih dalam menafsirkan lafadz tatswib, sebagian dari mereka mengatakan bahwa tastwid adalah, seseorang mengucapkan dalam adzan shalat subuh ASH SHALATU KHAIRUN MINAN NAUM (shalat lebih baik daripada tidur). Ini adalah pendapat yang diambil oleh bin Al Mubarak dan Ahmad. Sedangkan Ishaq punya pendapat lain dalam hal tatswib, ia berkata; \"Tatswib yang dibenci adalah sesuatu yang diada-adakan oleh manusia setelah Nabi shallallahu 'alaihi wasallam, jika mu'adzin melakukan adzan kemudian orang-orang bermalas-malas dalam memenuhinya, ia mengucapkan antara adzan dan iqamah; QAD QAAMATISH SHALAT - HAYYA 'ALA ASH SHALAT - HAYYA 'ALAL FALAH (shalat telah didirikan, mari menegakkan shalat, mari menuju kemenangan).\" Ia berkata; \"Apa yang dikatakan oleh Ishaq ini adalah model tatswib yang diada-adakan setelah Nabi shallallahu 'alaihi wasallam dan dibenci oleh para ahli ilmu.\" Yang ditafsirkan oleh bin Al Mubarak dan Ahmad bahwa tatswib itu adalah ucapan seorang mu'adzin pada adzan subuh; ASH SHALATU KHAIRUN MINAN NAUM (shalat itu lebih baik daripada tidur).\" Ini adalah pendapat yang benar. Itulah yang disebut dengan tatswid sebagaimana yang diambil dan dipilih oleh ahli ilmu. Diriwayatkan dari Ibnu Umar bahwa dalam adzan shalat subuh ia mengucapkan; ASH SHALATU KHAIRUN MINAN NAUM (shalat itu lebih baik daripada tidur). Diriwayatkan dari Mujahid bahwa ia berkata; \"Aku bersama Abdullah bin Umar masuk ke dalam masjid ketika adzan telah dikumandangkan, namun mu'adzin mengucapkan tatswib. Maka Abdullah bin Umar pun keluar dari masjid dan berkata; \"Ikutlah keluar bersamaku dari sisi tukang bid'ah ini!\" dan ia tidak jadi melaksanakan shalat di dalamnya.\" Ia berkata; \"Hanyasanya tatswid yang dibenci oleh Abdullah adalah (tatswib) yang diada-adakan oleh manusia.\""},"183":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ وَيَعْلَى بْنُ عُبَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ زِيَادِ بْنِ أَنْعُمٍ الْأَفْرِيقِيِّ عَنْ زِيَادِ بْنِ نُعَيْمٍ الْحَضْرَمِيِّ عَنْ زِيَادِ بْنِ الْحَارِثِ الصُّدَائِيِّ قَالَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أُؤَذِّنَ فِي صَلَاةِ الْفَجْرِ فَأَذَّنْتُ فَأَرَادَ بِلَالٌ أَنْ يُقِيمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَخَا صُدَاءٍ قَدْ أَذَّنَ وَمَنْ أَذَّنَ فَهُوَ يُقِيمُقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ قَالَ أَبُو عِيسَى وَحَدِيثُ زِيَادٍ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ الْأَفْرِيقِيِّ وَالْأَفْرِيقِيُّ هُوَ ضَعِيفٌ عِنْدَ أَهْلِ الْحَدِيثِ ضَعَّفَهُ يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ وَغَيْرُهُ قَالَ أَحْمَدُ لَا أَكْتُبُ حَدِيثَ الْأَفْرِيقِيِّ قَالَ وَرَأَيْتُ مُحَمَّدَ بْنَ إِسْمَعِيلَ يُقَوِّي أَمْرَهُ وَيَقُولُ هُوَ مُقَارِبُ الْحَدِيثِ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ أَنَّ مَنْ أَذَّنَ فَهُوَ يُقِيمُ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abdah] dan [Ya'la bin Ubaid] dari [Abdurrahman bin Ziyad bin An'um Al Afriqi] dari [Ziyad bin Nu'aim Al Hadlrami] dari [Ziyad bin Al Harits Ash Shudafi] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kepadaku untuk adzan subuh maka aku pun adzan. Kemudian Bilal ingin mengumandangkan iqamah, namun Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Saudara Shuda` telah mengumandangkan adzan, maka dialah yang berhak untuk melakukan iqamah.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Umar.\" Abu Isa berkata; \"Kami mengetahui hadits Ziyad dari hadits yang diriwayatkan oleh Al Afriqi, dan Al Afriqi menurut ahli hadits adalah seorang yang lemah. Ia telah dilemahkan oleh Yahya bin Sa'id bin Al Qaththan dan selainnya.\" Ahmad berkata; \"Aku tidak menulis hadits Al Afriqi.\" Ia berkata; \"Aku melihat Muhammad bin Isma'il menguatkan pendapatnya dia berpendapat hal ini lebih mendekati hadits yang lain, hadits ini juga diamalkan oleh ahli ilmu, bahwa barangsiapa melakukan adzan maka dialah yang melakukan iqamah.\""},"184":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ مُعَاوِيَةَ بْنِ يَحْيَى الصَّدَفِيِّ عَنْ الزُّهْرِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُؤَذِّنُ إِلَّا مُتَوَضِّئٌ","id":"telah menceritakan kepada kami [Ali bin Hujr] berkata; telah menceritakan kepada kami [Al Walid bin Muslim] dari [Mu'awiyah bin Yahya Ash Shadafi] dari [Az Zuhri] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak boleh melakukan adzan kecuali orang yang telah berwudlu.\""},"185":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ قَالَ أَبُو هُرَيْرَةَلَا يُنَادِي بِالصَّلَاةِ إِلَّا مُتَوَضِّئٌقَالَ أَبُو عِيسَى وَهَذَا أَصَحُّ مِنْ الْحَدِيثِ الْأَوَّلِ قَالَ أَبُو عِيسَى وَحَدِيثُ أَبِي هُرَيْرَةَ لَمْ يَرْفَعْهُ ابْنُ وَهْبٍ وَهُوَ أَصَحُّ مِنْ حَدِيثِ الْوَلِيدِ بْنِ مُسْلِمٍ وَالزُّهْرِيُّ لَمْ يَسْمَعْ مِنْ أَبِي هُرَيْرَةَ وَاخْتَلَفَ أَهْلُ الْعِلْمِ فِي الْأَذَانِ عَلَى غَيْرِ وُضُوءٍ فَكَرِهَهُ بَعْضُ أَهْلِ الْعِلْمِ وَبِهِ يَقُولُ الشَّافِعِيُّ وَإِسْحَقُ وَرَخَّصَ فِي ذَلِكَ بَعْضُ أَهْلِ الْعِلْمِ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَأَحْمَدُ","id":"telah menceritakan kepada kami [Yahya bin Musa] berkata; telah menceritakan kepada kami [Abdullah bin Wahb] dari [Yunus] dari [Ibnu Syihab] ia berkata; \" [Abu Hurairah] berkata; \"Tidak sepantasnya mengumandangkan adzan kecuali orang yang telah berwudlu.\" Abu Isa berkata; \"Hadits ini lebih shahih daripada hadits yang pertama.\" Abu Isa berkata; \"Dan hadits Abu Hurairah tidak ada yang memarfu'kannya kepada Rasulullah shallallahu 'alaihi wasallam kecuali Ibnu Wahb, namun hadits ini lebih shahih daripada hadits riwayat Al Walid Ibnu Muslim. Sedangkan Az Zuhri juga tidak mendengar dari Abu Hurairah. Para ulama berselisih tentang hukum adzan yang dilakukan tanpa berwudlu terlebih dahulu. Sebagian dari mereka memakruhkannya, pendapat ini diambil oleh Syafi'i dan Ishaq. Sedangkan sebagian lain memberi keringanan, pendapat ini diambil oleh Sufyan Ats Tsauri, bin Al Mubarak dan Ahmad.\""},"186":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا إِسْرَائِيلُ أَخْبَرَنِي سِمَاكُ بْنُ حَرْبٍ سَمِعَ جَابِرَ بْنَ سَمُرَةَ يَقُولُكَانَ مُؤَذِّنُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُمْهِلُ فَلَا يُقِيمُ حَتَّى إِذَا رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ خَرَجَ أَقَامَ الصَّلَاةَ حِينَ يَرَاهُقَالَ أَبُو عِيسَى حَدِيثُ جَابِرِ بْنِ سَمُرَةَ هُوَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَحَدِيثُ إِسْرَائِيلَ عَنْ سِمَاكٍ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَهَكَذَا قَالَ بَعْضُ أَهْلِ الْعِلْمِ إِنَّ الْمُؤَذِّنَ أَمْلَكُ بِالْأَذَانِ وَالْإِمَامُ أَمْلَكُ بِالْإِقَامَةِ","id":"telah menceritakan kepada kami [Yahya bin Musa] berkata; telah menceritakan kepada kami [Abdurrazaq] berkata; telah mengabarkan kepada kami [Isra'il] berkata; telah mengabarkan kepadaku [Simak bin Harb] ia mendengar [Jabir bin Samrah] berkata; \"Mu'adzin Rasulullah shallallahu 'alaihi wasallam tidak segera mengumandangkan iqamah, maka ketika ia melihat Rasulullah shallallahu 'alaihi wasallam keluar, ia pun mengumandangkannya.\" Abu Isa berkata; \"Hadits Jabir bin Samrah derajatnya hasan shahih, sedangkan hadits Isra'il kami tidak mengetahuinya kecuali dari jalur ini.\" Sebagian ulama berkata; \"Seorang mu'adzin lebih berhak dalam menentukan waktu adzan, sedangkan imam lebih berhak dalam menentukan waktu iqamah.\""},"187":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ بِلَالًا يُؤَذِّنُ بِلَيْلٍ فَكُلُوا وَاشْرَبُوا حَتَّى تَسْمَعُوا تَأْذِينَ ابْنِ أُمِّ مَكْتُومٍقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَعَائِشَةَ وَأُنَيْسَةَ وَأَنَسٍ وَأَبِي ذَرٍّ وَسَمُرَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ اخْتَلَفَ أَهْلُ الْعِلْمِ فِي الْأَذَانِ بِاللَّيْلِ فَقَالَ بَعْضُ أَهْلِ الْعِلْمِ إِذَا أَذَّنَ الْمُؤَذِّنُ بِاللَّيْلِ أَجْزَأَهُ وَلَا يُعِيدُ وَهُوَ قَوْلُ مَالِكٍ وَابْنِ الْمُبَارَكِ وَالشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ إِذَا أَذَّنَ بِلَيْلٍ أَعَادَ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَرَوَى حَمَّادُ بْنُ سَلَمَةَ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ بِلَالًا أَذَّنَ بِلَيْلٍ فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُنَادِيَ إِنَّ الْعَبْدَ نَامَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَيْرُ مَحْفُوظٍ وَالصَّحِيحُ مَا رَوَى عُبَيْدُ اللَّهِ بْنُ عُمَرَ وَغَيْرُهُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ بِلَالًا يُؤَذِّنُ بِلَيْلٍ فَكُلُوا وَاشْرَبُوا حَتَّى يُؤَذِّنَ ابْنُ أُمِّ مَكْتُومٍ وَرَوَى عَبْدُ الْعَزِيزِ بْنُ أَبِي رَوَّادٍ عَنْ نَافِعٍ أَنَّ مُؤَذِّنًا لِعُمَرَ أَذَّنَ بِلَيْلٍ فَأَمَرَهُ عُمَرُ أَنْ يُعِيدَ الْأَذَانَ وَهَذَا لَا يَصِحُّ أَيْضًا لِأَنَّهُ عَنْ نَافِعٍ عَنْ عُمَرَ مُنْقَطِعٌ وَلَعَلَّ حَمَّادَ بْنَ سَلَمَةَ أَرَادَ هَذَا الْحَدِيثَ وَالصَّحِيحُ رِوَايَةُ عُبَيْدِ اللَّهِ وَغَيْرِ وَاحِدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ وَالزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ بِلَالًا يُؤَذِّنُ بِلَيْلٍ قَالَ أَبُو عِيسَى وَلَوْ كَانَ حَدِيثُ حَمَّادٍ صَحِيحًا لَمْ يَكُنْ لِهَذَا الْحَدِيثِ مَعْنًى إِذْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بِلَالًا يُؤَذِّنُ بِلَيْلٍ فَإِنَّمَا أَمَرَهُمْ فِيمَا يُسْتَقْبَلُ و قَالَ إِنَّ بِلَالًا يُؤَذِّنُ بِلَيْلٍ وَلَوْ أَنَّهُ أَمَرَهُ بِإِعَادَةِ الْأَذَانِ حِينَ أَذَّنَ قَبْلَ طُلُوعِ الْفَجْرِ لَمْ يَقُلْ إِنَّ بِلَالًا يُؤَذِّنُ بِلَيْلٍ قَالَ عَلِيُّ بْنُ الْمَدِينِيِّ حَدِيثُ حَمَّادِ بْنِ سَلَمَةَ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرُ مَحْفُوظٍ وَأَخْطَأَ فِيهِ حَمَّادُ بْنُ سَلَمَةَ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Salim] dari [Ayahnya] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Bilal adzan di waktu yang masih malam, maka hendaklah kalian tetap makan dan minum hingga mendengar adzan Ibnu Ummi Maktum.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Mas'ud, 'Aisyah, Unaisah, Anas, Abu Dzar dan Samrah.\" Abu Isa berkata; \"Hadits Ibnu Umar derajatnya hasan shahih. Dan para ulama telah berselisih pendapat tentang adzan di waktu malam. Sebagian mereka mengatakan, \"Jika seorang mu'adzin mengumandangkan adzan di waktu yang masih malam maka hal itu telah mencukupi dan tidak perlu mengulanginya.\" Pendapat ini diambil oleh Malik, bin Al Mubarak, Ahmad dan Ishaq. Sedangkan sebagian ulama yang lain mengatakan, \"Jika ia melakukan adzan di waktu yang masih malam maka ia harus mengulanginya.\" Pendapat ini diambil oleh Sufyan Ats Tsauri. Hammad bin Salamah meriwayatkan dari Ayyub, dari Nafi' dari Ibnu Umar bahwa Bilal pernah mengumandangkan adzan di waktu yang masih malam, maka Nabi shallallahu 'alaihi wasallam pun memerintahkan kepadanya untuk menyeru, \"Sesungguhnya seorang hamba telah tidur.\" Abu Isa berkata; \"Hadits ini tidak akurat. Tetapi yang shahih adalah hadits yang diriwayatkan oleh [Ubaidullah bin Umar] dan selainnya dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda; \"Sesungguhnya Bilal adzan di waktu yang masih malam, maka hendakalah kalian tetap makan dan minum hingga mendengar adzan Ibnu Ummi Maktum.\" Telah diriwayatkan pula bahwa Abdul Aziz bin Abu Rawwad dari Nafi', bahwa tukang adzan Umar pernah mengumandangkan adzan di waktu yang masih malam, maka ia pun memerintahkan kepadanya untuk mengulangi, namun hadits ini juga tidak sah. Sebab antara Nafi' dan Umar sanadnya terputus. Barangkali Hammad bin Salamah menghendaki hadits ini. Yang benar adalah hadits yang diriwayatkan oleh Ubaidullah dan yang lainnya dari Nafi' dari Ibnu Umar, dan Az Zuhri dari Salim bin Umar, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Bilal adzan di waktu yang masih malam.\" Abu Isa berkata; \"Sekiranya hadits riwayat Hammad shahih, tentu hadits ini tidak ada maknanya. Sebab Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Bilal Adzan di waktu yang masih malam, \" beliau memerintahkan kepada para sahabat untuk sesuatu yang akan datang. Dan beliau bersabda: \"Sesungguhnya Bilal adzan di waktu yang masih malam, \" sekiranya beliau memerintahkan mengulangi adzan ketika adzan itu dilakukan sebelum fajar, maka Nabi tidak akan mengatakan: \"Sesungguhnya Bilal adzan di waktu yang masih malam.\" Ali bin Al Madini berkata; \"Hadits Hammad bin Salamah dari Ayyub, dari Nafi', dari Ibnu Umar dari Nabi shallallahu 'alaihi wasallam tidak akurat, dan Hammad bin Salamah melakukan kesalahan di dalamnya.\""},"188":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ إِبْرَاهِيمَ بْنِ الْمُهَاجِرِ عَنْ أَبِي الشَّعْثَاءِ قَالَخَرَجَ رَجُلٌ مِنْ الْمَسْجِدِ بَعْدَ مَا أُذِّنَ فِيهِ بِالْعَصْرِ فَقَالَ أَبُو هُرَيْرَةَ أَمَّا هَذَا فَقَدْ عَصَى أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُثْمَانَ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَعَلَى هَذَا الْعَمَلُ عِنْدَ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ أَنْ لَا يَخْرُجَ أَحَدٌ مِنْ الْمَسْجِدِ بَعْدَ الْأَذَانِ إِلَّا مِنْ عُذْرٍ أَنْ يَكُونَ عَلَى غَيْرِ وُضُوءٍ أَوْ أَمْرٍ لَا بُدَّ مِنْهُ وَيُرْوَى عَنْ إِبْرَاهِيمَ النَّخَعِيِّ أَنَّهُ قَالَ يَخْرُجُ مَا لَمْ يَأْخُذْ الْمُؤَذِّنُ فِي الْإِقَامَةِ قَالَ أَبُو عِيسَى وَهَذَا عِنْدَنَا لِمَنْ لَهُ عُذْرٌ فِي الْخُرُوجِ مِنْهُ وَأَبُو الشَّعْثَاءِ اسْمُهُ سُلَيْمُ بْنُ أَسْوَدَ وَهُوَ وَالِدُ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ وَقَدْ رَوَى أَشْعَثُ بْنُ أَبِي الشَّعْثَاءِ هَذَا الْحَدِيثَ عَنْ أَبِيهِ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ibrahim bin Al Muhajir] dari [Abu Asy Sya'tsa`] ia berkata; \"Setelah adzan dikumandangkan, seorang laki-laki keluar dari masjid, maka [Abu Hurairah] pun berkata; \"Orang ini telah durhaka kepada Abu Qasim shallallahu 'alaihi wasallam.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Utsman.\" Abu Isa berkata; \"Hadits Abu Hurairah derajatnya hasan shahih. Hadits ini diamalkan pula oleh ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka. Yaitu, seseorang tidak diperbolehkan keluar dari dalam masjid setelah adzan dikumandangkan kecuali karena ada udzur; seperti belum berwudlu atau karena perkara lain yang harus dikerjakan.\" Telah diriwayatkan dari Ibrahim An Nakha'i bahwa ia pernah berkata; \"Seseorang boleh keluar dari dalam masjid selama mu'adzin belum mengumandangkan iqamah.\" Abu Isa berkata; \"Kami juga setuju dengan pendapat tersebut, seseorang boleh keluar lantaran ada udzur.\" Abu Sya'tsa` namanya adalah Sulaim bin Aswad, dan ia adalah orang tua Asy'ats bin Abu Asy Sya'tsa`. Dan [Asy'ats bin Abu Asy Sya'tsa`] telah meriwayatkan hadits ini dari [ayahnya].\""},"189":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَقَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَابْنُ عَمٍّ لِي فَقَالَ لَنَا إِذَا سَافَرْتُمَا فَأَذِّنَا وَأَقِيمَا وَلْيَؤُمَّكُمَا أَكْبَرُكُمَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ اخْتَارُوا الْأَذَانَ فِي السَّفَرِ و قَالَ بَعْضُهُمْ تُجْزِئُ الْإِقَامَةُ إِنَّمَا الْأَذَانُ عَلَى مَنْ يُرِيدُ أَنْ يَجْمَعَ النَّاسَ وَالْقَوْلُ الْأَوَّلُ أَصَحُّ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Khalid Al Hidza`] dari [Abu Qilabah] dari [Malik bin Al Huwairits] ia berkata; \"Aku bersama dengan putra saudara laki-lakiku datang menemui Rasulullah shallallahu 'alaihi wasallam, beliau lalu bersabda kepada kami: \"Jika kalian sedang dalam perjalanan, maka hendaklah kalian adzan dan iqamah, dan orang yang paling besar hendaklah yang menjadi imam.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, para ahli ilmu juga mengamalkan hadits ini. Tetap melakukan adzan dalam safar adalah pendapat yang mereka pilih. Namun sebagian mereka berkata; \"Cukup dengan iqamah, sebab adzan itu bagi orang yang ingin mengumpulkan orang banyak.\" Pendapat pertama adalah pendapat yang lebih shahih. Pendapat ini (pertama) diambil pula oleh Ahmad dan Ishaq.\""},"190":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ الرَّازِيُّ حَدَّثَنَا أَبُو تُمَيْلَةَ حَدَّثَنَا أَبُو حَمْزَةَ عَنْ جَابِرٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَذَّنَ سَبْعَ سِنِينَ مُحْتَسِبًا كُتِبَتْ لَهُ بَرَاءَةٌ مِنْ النَّارِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَثَوْبَانَ وَمُعَاوِيَةَ وَأَنَسٍ وَأَبِي هُرَيْرَةَ وَأَبِي سَعِيدٍ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عَبَّاسٍ حَدِيثٌ غَرِيبٌ وَأَبُو تُمَيْلَةَ اسْمُهُ يَحْيَى بْنُ وَاضِحٍ وَأَبُو حَمْزَةَ السُّكَّرِيُّ اسْمُهُ مُحَمَّدُ بْنُ مَيْمُونٍ وَجَابِرُ بْنُ يَزِيدَ الْجُعْفِيُّ ضَعَّفُوهُ تَرَكَهُ يَحْيَى بْنُ سَعِيدٍ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ أَبُو عِيسَى سَمِعْت الْجَارُودَ يَقُولُ سَمِعْتُ وَكِيعًا يَقُولُ لَوْلَا جَابِرٌ الْجُعْفِيُّ لَكَانَ أَهْلُ الْكُوفَةِ بِغَيْرِ حَدِيثٍ وَلَوْلَا حَمَّادٌ لَكَانَ أَهْلُ الْكُوفَةِ بِغَيْرِ فِقْهٍ","id":"telah menceritakan kepada kami [Muhammad bin Humaid Ar Razi] berkata; telah menceritakan kepada kami [Abu Tumailah] berkata; telah menceritakan kepada kami [Abu Hamzah] dari [Jabir] dari [Mujahid] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengumandangkan adzan selama tujuh tahun dengan mengharap ridla Allah, maka ia akan terbebas dari api neraka.\" Abu Isa berkata; \"Dalam bab ini ada juga hadits dari Abdullah bin Mas'ud, Tsauban, Mu'awiyah, Anas, Abu Hurairah dan Abu Sa'id.\" Abu Isa berkata; \"Hadits Ibnu Abbas ini derajatnya gharib. Dan Abu Tumailah namanya adalah Yahya bin Wadlih, sedangkan Abu Hamzah As Sukkari namanya adalah Muhammad bin Maimun. Dan Jabir bin Yazid Al Ju'fi juga telah dilemahkan oleh para ulama, haditsnya tidak dianggap oleh Yahya bin Sa'id dan Abdurrahman bin Mahdi.\" Abu Isa berkata; \"Aku mendengar Al Jarud berkata; \"Aku mendengar Waki' berkata; \"Sekiranya tidak ada Jabir Al Ju'fi, tentu penduduk Kufah tidak akan mempunyai hadits. Dan sekiranya tidak ada Hammad maka penduduk Kufah tidak akan mempunyai fikih.\""},"191":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو الْأَحْوَصِ وَأَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْإِمَامُ ضَامِنٌ وَالْمُؤَذِّنُ مُؤْتَمَنٌ اللَّهُمَّ أَرْشِدْ الْأَئِمَّةَ وَاغْفِرْ لِلْمُؤَذِّنِينَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَائِشَةَ وَسَهْلِ بْنِ سَعْدٍ وَعُقْبَةَ بْنِ عَامِرٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ رَوَاهُ سُفْيَانُ الثَّوْرِيُّ وَحَفْصُ بْنُ غِيَاثٍ وَغَيْرُ وَاحِدٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَى أَسْبَاطُ بْنُ مُحَمَّدٍ عَنْ الْأَعْمَشِ قَالَ حُدِّثْتُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَى نَافِعُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا الْحَدِيثَ قَالَ أَبُو عِيسَى و سَمِعْت أَبَا زُرْعَةَ يَقُولُ حَدِيثُ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ أَصَحُّ مِنْ حَدِيثِ أَبِي صَالِحٍ عَنْ عَائِشَةَ قَالَ أَبُو عِيسَى و سَمِعْت مُحَمَّدًا يَقُولُ حَدِيثُ أَبِي صَالِحٍ عَنْ عَائِشَةَ أَصَحُّ وَذَكَرَ عَنْ عَلِيِّ بْنِ الْمَدِينِيِّ أَنَّهُ لَمْ يُثْبِتْ حَدِيثَ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ وَلَا حَدِيثَ أَبِي صَالِحٍ عَنْ عَائِشَةَ فِي هَذَا","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abu Al Ahwash] dan [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Imam sebagai penjamin sedangkan mu'adzin sebagai orang yang dipercaya. Ya Allah, luruskanlah para imam dan ampunilah para mu'adzin.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari 'Aisyah, Sahl bin Sa'd dan Uqbah bin 'Amir.\" Abu Isa berkata; \"Hadits Abu Hurairah diriwayatkan oleh [Sufyan Ats Tsauri] dan [Hafsh bin Ghiyats] dan [beberapa orang] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam.\" [Asbath bin Muhammad] juga meriwayatkan dari [Al A'masy], ia berkata; \"Aku pernah dibacakan sebuah hadits dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam. Dan [Nafi' bin Sulaiman] meriwayatkan hadits ini dari [Muhammad bin Abu Shalih] dari [ayahnya] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam. Abu Isa berkata; \"Aku mendengar Abu Zur'ah berkata; \"Hadits Abu Shalih dari Abu Hurairah lebih shahih dari hadits Abu Shalih yang diriwayatkan dari 'Aisyah.\" Abu Isa berkata; \"Aku mendengar Muhammad berkata; \"Hadits Abu Shalih dari 'Aisyah derajatnya lebih shahih.\" Dan ia juga menyebutkan dari Ali bin Al Madini, bahwasanya ia tidak pernah menetapkan (shahih) hadits riwayat Abu Shalih dari Abu Hurairah, dan hadits Abu Shalih dari 'Aisyah tentang permasalahan ini.\""},"192":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ ح قَالَ حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَمِعْتُمْ النِّدَاءَ فَقُولُوا مِثْلَ مَا يَقُولُ الْمُؤَذِّنُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي رَافِعٍ وَأَبِي هُرَيْرَةَ وَأُمِّ حَبِيبَةَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَعَبْدِ اللَّهِ بْنِ رَبِيعَةَ وَعَائِشَةَ وَمُعَاذِ بْنِ أَنَسٍ وَمُعَاوِيَةَ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي سَعِيدٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهَكَذَا رَوَى مَعْمَرٌ وَغَيْرُ وَاحِدٍ عَنْ الزُّهْرِيِّ مِثْلَ حَدِيثِ مَالِكٍ وَرَوَى عَبْدُ الرَّحْمَنِ بْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ هَذَا الْحَدِيثَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرِوَايَةُ مَالِكٍ أَصَحُّ","id":"telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] berkata; telah menceritakan kepada kami [Ma'n] berkata; telah menceritakan kepada kami [Malik], Ia berkata; telah menceritakan kepada kami [Qutaibah] dari [Malik] dari [Az Zuhri] dari ['Atha` bin Yazid Al Laits] dari [Abu Sa'id] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian mendengar suara adzan maka ucapkanlah sebagaimana yang diucapkan oleh mu'adzin.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Abu Rafi', Abu Hurairah, Ummu Habibah, Abdullah bin 'Amru, Abdullah bin Rabi'ah, 'Aisyah, Mu'adz bin Anas dan Mu'awiyah.\" Abu Isa berkata; \"Hadits Abu Sa'id ini derajatnya hasan shahih. [Ma'mar] dan selainnya juga meriwayatkan dari [Az Zuhri] seperti hadits riwayat Malik. Sedangkan [Abdurrahman bin Ishaq] meriwayatkan hadits ini dari [Az Zuhri] dari [Sa'id bin Al Musayyib] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam. Dan riwayat Malik lebih shahih.\""},"193":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو زُبَيْدٍ وَهُوَ عَبْثَرُ بْنُ الْقَاسِمِ عَنْ أَشْعَثَ عَنْ الْحَسَنِ عَنْ عُثْمَانَ بْنِ أَبِي الْعَاصِ قَالَإِنَّ مِنْ آخِرِ مَا عَهِدَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ اتَّخِذْ مُؤَذِّنًا لَا يَأْخُذُ عَلَى أَذَانِهِ أَجْرًاقَالَ أَبُو عِيسَى حَدِيثُ عُثْمَانَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ كَرِهُوا أَنْ يَأْخُذَ الْمُؤَذِّنُ عَلَى الْأَذَانِ أَجْرًا وَاسْتَحَبُّوا لِلْمُؤَذِّنِ أَنْ يَحْتَسِبَ فِي أَذَانِهِ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abu Zubaid] -yaitu Abtsar bin Al Qasim- dari [Asy'ats] dari [Al Hasan] dari [Utsman bin Abu Al 'Ash] ia berkata; \"Amanah terakhir yang Rasulullah shallallahu 'alaihi wasallam berikan kepadaku adalah agar aku mengangkat seorang mu'adzin yang tidak mengambil upah dari adzannya tersebut.\" Abu Isa, \"Hadits Utsman ini derajatnya hasan shahih. Pengamalan terhadap hadits ini menurut ulama adalah, bahwa mereka memakruhkan bagi tukang adzan mengambil upah atas adzannya, dan mereka lebih menyukai jika mereka (mu'adzin) mengharapkan pahala dari adzan yang ia lakukan.\""},"194":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ الْحُكَيْمِ بْنِ عَبْدِ اللَّهِ بْنِ قَيْسٍ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ حِينَ يَسْمَعُ الْمُؤَذِّنَ وَأَنَا أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ رَضِيتُ بِاللَّهِ رَبًّا وَبِمُحَمَّدٍ رَسُولًا وَبِالْإِسْلَامِ دِينًا غُفِرَ لَهُ ذَنْبُهُقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ اللَّيْثِ بْنِ سَعْدٍ عَنْ حُكَيْمِ بْنِ عَبْدِ اللَّهِ بْنِ قَيْسٍ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Laits] dari [Al Hukaim bin Abdullah bin Qais] dari ['Amir bin Sa'd] dari [Sa'd bin Abu Waqash] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa ketika mendengar mu'adzin lalu mengucapkan: \"WA ANA ASYHADU AN LAA ILAAHA ILLAALLAHU WAHDAHUU LAA SYARIIKALAH WA ANNA MUHAMMADAN ABDUHU WA RASUULUHU RADLIITU BILLAHI RABBAN WA BI MUHAMMADIN RASUULAN WA BIL ISLAMI DIINAN (Aku bersaksi, bahwa tidak ada Tuhan yang berhak untuk disembah selain Allah, Yang Maha Esa, tidak ada sekutu bagi-Nya dan sesungguhnya Muhammad adalah hamba dan utusan-Nya. Aku rela Allah sebagai Tuhan, Muhammad sebagai Rasul dan Islam sebagai agama), maka dosa-dosanya akan diampuni.\""},"195":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَهْلِ بْنِ عَسْكَرٍ الْبَغْدَادِيُّ وَإِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَا حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ الْحِمْصِيُّ حَدَّثَنَا شُعَيْبُ بْنُ أَبِي حَمْزَةَ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ حِينَ يَسْمَعُ النِّدَاءَ اللَّهُمَّ رَبَّ هَذِهِ الدَّعْوَةِ التَّامَّةِ وَالصَّلَاةِ الْقَائِمَةِ آتِ مُحَمَّدًا الْوَسِيلَةَ وَالْفَضِيلَةَ وَابْعَثْهُ مَقَامًا مَحْمُودًا الَّذِي وَعَدْتَهُ إِلَّا حَلَّتْ لَهُ الشَّفَاعَةُ يَوْمَ الْقِيَامَةِقَالَ أَبُو عِيسَى حَدِيثُ جَابِرٍ حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ مُحَمَّدِ بْنِ الْمُنْكَدِرِ لَا نَعْلَمُ أَحَدًا رَوَاهُ غَيْرَ شُعَيْبِ بْنِ أَبِي حَمْزَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ وَأَبُو حَمْزَةَ اسْمُهُ دِينَارٌ","id":"telah menceritakan kepada kami [Muhammad bin Sahl bin 'Askar Al Baghdadi] dan [Ibrahim bin Ya'qub] mereka berkata; telah menceritakan kepada kami [Ali bin Ayyasy Al Himshi] berkata; telah menceritakan kepada kami [Syu'aib bin Abu Hamzah] berkata; telah menceritakan kepada kami [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ketika mendengar adzan mengucapkan: \"ALLAHUMMA RABBA HADZIHI AD DA'WATIT TAMMAH WASH SHALAATIL QAA`IMAH AATI MUHAMMADANIL WASIILATA WAL WAL FADLIILAH WAB'ATSHU MAQAAMAN MAHMUUDANILLADZI WA'ADTAH (Ya Allah, Tuhan Pemilik panggilan yang sempurna (adzan) ini dan shalat (wajib) yang didirikan. Berilah Al Wasilah (derajat di surga, yang tidak diberikan kecuali kepada Muhammad) dan fadlilah kepada Muhammad. Dan bangkitkanlah beliau sehingga bisa menempati kedudukan terpuji yang telah Engkau janjikan), maka ia akan mendapatkan syafa'at pada hari kiamat.\""},"196":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ وَعَبْدُ الرَّزَّاقِ وَأَبُو أَحْمَدَ وَأَبُو نُعَيْمٍ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ زَيْدٍ الْعَمِّيِّ عَنْ أَبِي إِيَاسٍ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الدُّعَاءُ لَا يُرَدُّ بَيْنَ الْأَذَانِ وَالْإِقَامَةِقَالَ أَبُو عِيسَى حَدِيثُ أَنَسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ أَبُو إِسْحَقَ الْهَمْدَانِيُّ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ هَذَا","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Waki'] dan [Abdurrazaq] dan [Abu Ahmad] dan [Abu Nu'aim] mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Zaid Al 'Ammi] dari [Abu Iyas Mu'awiyah bin Qurrah] dari [Anas bin Malik] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Do`a antara adzan dan iqamah tidak akan ditolak.\" Abu Isa berkata; \"Hadits Anas ini derajatnya hasan shahih. Dan hadits ini juga telah diriwayatkan oleh [Abu Ishaq Al Hamdani] dari [Buraid bin Abu Maryam] dari Nabi shallallahu 'alaihi wasallam seperti hadits tersebut.\""},"197":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى النَّيْسَابُورِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَفُرِضَتْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ أُسْرِيَ بِهِ الصَّلَوَاتُ خَمْسِينَ ثُمَّ نُقِصَتْ حَتَّى جُعِلَتْ خَمْسًا ثُمَّ نُودِيَ يَا مُحَمَّدُ إِنَّهُ لَا يُبَدَّلُ الْقَوْلُ لَدَيَّ وَإِنَّ لَكَ بِهَذِهِ الْخَمْسِ خَمْسِينَقَالَ وَفِي الْبَاب عَنْ عُبَادَةَ بْنِ الصَّامِتِ وَطَلْحَةَ بْنِ عُبَيْدِ اللَّهِ وَأَبِي ذَرٍّ وَأَبِي قَتَادَةَ وَمَالِكِ بْنِ صَعْصَعَةَ وَأَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ أَبُو عِيسَى حَدِيثُ أَنَسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"telah menceritakan kepada kami [Muhammad bin Yahya An Naisaburi] berkata; telah menceritakan kepada kami [Abdurrazaq] berkata; telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Anas bin Malik] ia berkata; \"Di malam isra` Nabi shallallahu 'alaihi wasallam diberi kewajiban untuk melaksanakan shalat sebanyak lima puluh kali. Kemudian bilangan tersebut dikurangi hingga menjadi lima kali, beliau lalu diseru, \"Wahai Muhammad, sesungguhnya ketentuan yang ada di sisi-Ku tidak bisa dirubah, maka engkau akan mendapatkan pahala lima puluh (waktu shalat) dengan lima (waktu shalat) ini.\" Ia berkata; \"Dalam bab ini ada juga hadits dari Ubadah bin Ash Shamit, Thalhah bin Ubaidullah, Abu Dzar, Abu Qatadah, Malik bin Sha'sha'ah dan Abu Sa'id Al Khudri.\" Abu Isa berkata; \"Hadits Anas adalah hadits hasan shahih gharib.\""},"198":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الصَّلَوَاتُ الْخَمْسُ وَالْجُمُعَةُ إِلَى الْجُمُعَةِ كَفَّارَاتٌ لِمَا بَيْنَهُنَّ مَا لَمْ تُغْشَ الْكَبَائِرُقَالَ وَفِي الْبَاب عَنْ جَابِرٍ وَأَنَسٍ وَحَنْظَلَةَ الْأُسَيِّدِيِّ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Ali bin Hujr] berkata; telah mengabarkan kepada kami [Isma'il bin Ja'far] dari ['Ala` bin Abdurrahman] dari [Ayahnya] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat lima waktu dan jum'at hingga jum'at adalah sebagai penghapus dosa antara waktu-waktu tersebut, selama ia menjauhi dosa-dosa besar.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Jabir, Anas dan Handlalah Al Usaid.\" Abu Isa berkata; \"Hadits Abu Hurairah ini derajatnya hasan shahih.\""},"199":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ الْجَمَاعَةِ تَفْضُلُ عَلَى صَلَاةِ الرَّجُلِ وَحْدَهُ بِسَبْعٍ وَعِشْرِينَ دَرَجَةًقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَأُبَيِّ بْنِ كَعْبٍ وَمُعَاذِ بْنِ جَبَلٍ وَأَبِي سَعِيدٍ وَأَبِي هُرَيْرَةَ وَأَنَسِ بْنِ مَالِكٍ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهَكَذَا رَوَى نَافِعٌ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ تَفْضُلُ صَلَاةُ الْجَمِيعِ عَلَى صَلَاةِ الرَّجُلِ وَحْدَهُ بِسَبْعٍ وَعِشْرِينَ دَرَجَةً قَالَ أَبُو عِيسَى وَعَامَّةُ مَنْ رَوَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا قَالُوا خَمْسٍ وَعِشْرِينَ إِلَّا ابْنَ عُمَرَ فَإِنَّهُ قَالَ بِسَبْعٍ وَعِشْرِينَ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abdah] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat seorang laki-laki secara berjama'ah lebih utama dua puluh tujuh derajat dari shalat sendirian.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin Mas'ud, Ubai bin Ka'ab, Mu'adz bin Jabal, Abu Sa'id, Abu Hurairah dan Anas bin Malik.\" Abu Isa berkata; \"Hadits Ibnu Umar ini derajatnya hasan shahih. Seperti ini pula Nafi' meriwayatkan dari Ibnu Umar, dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Shalat jama'ah lebih utama dua puluh tujuh derajat daripada shalatnya seorang laki-laki sendirian.\" Abu Isa berkata; \"Kebanyakan orang yang meriwayatkan dari Nabi shallallahu 'alaihi wasallam, mereka mengatakan, \"dua puluh lima derajat, \" namun Ibnu Umar menyebutkan, \"Dua puluh tujuh derajat.\""},"200":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ صَلَاةَ الرَّجُلِ فِي الْجَمَاعَةِ تَزِيدُ عَلَى صَلَاتِهِ وَحْدَهُ بِخَمْسَةٍ وَعِشْرِينَ جُزْءًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] berkata; telah menceritakan kepada kami [Ma'n] berkata; telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyib] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya shalat seorang laki-laki dengan berjama'ah lebih utama dengan dua puluh lima derajat daripada shalat sendirian.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\""},"201":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ جَعْفَرِ بْنِ بُرْقَانَ عَنْ يَزِيدَ بْنِ الْأَصَمِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَقَدْ هَمَمْتُ أَنْ آمُرَ فِتْيَتِي أَنْ يَجْمَعُوا حُزَمَ الْحَطَبِ ثُمَّ آمُرَ بِالصَّلَاةِ فَتُقَامَ ثُمَّ أُحَرِّقَ عَلَى أَقْوَامٍ لَا يَشْهَدُونَ الصَّلَاةَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَأَبِي الدَّرْدَاءِ وَابْنِ عَبَّاسٍ وَمُعَاذِ بْنِ أَنَسٍ وَجَابِرٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ غَيْرِ وَاحِدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمْ قَالُوا مَنْ سَمِعَ النِّدَاءَ فَلَمْ يُجِبْ فَلَا صَلَاةَ لَهُ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ هَذَا عَلَى التَّغْلِيظِ وَالتَّشْدِيدِ وَلَا رُخْصَةَ لِأَحَدٍ فِي تَرْكِ الْجَمَاعَةِ إِلَّا مِنْ عُذْرٍ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Waki'] dari [Ja'far bin Burqan] dari [Yazid bin Al Asham] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku sangat berkeinginan untuk memerintahkan para pemudaku mengumpulkan kayu bakar, lalu aku perintahkan agar shalat didirikan, setelah itu aku membakar rumah orang-orang yang tidak ikut melaksanakan shalat berjama'ah.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin Mas'ud, Abu Darda, Ibnu Abbas, Mu'adz bin Anas dan Jabir.\" Abu Isa berkata; \"Hadits Abu Hurairah ini derajatnya hasan shahih. Telah diriwayatkan dari sahabat Nabi shallallahu 'alaihi wasallam dengan banyak jalur, mereka mengatakan, \"Barangsiapa mendengar adzan lalu tidak memenuhi panggilannya, maka tidak ada shalat baginya.\" Dan sebagian para ahli ilmu berkata; \"Hal ini sangat ditekankan dan tidak dan keringanan bagi seseorang untuk meninggalkan shalat berjama'ah kecuali dengan udzur.\""},"202":{"ar":"قَالَ مُجَاهِدٌوَسُئِلَ ابْنُ عَبَّاسٍ عَنْ رَجُلٍ يَصُومُ النَّهَارَ وَيَقُومُ اللَّيْلَ لَا يَشْهَدُ جُمْعَةً وَلَا جَمَاعَةً قَالَ هُوَ فِي ��لنَّارِقَالَ حَدَّثَنَا بِذَلِكَ هَنَّادٌ حَدَّثَنَا الْمُحَارِبِيُّ عَنْ لَيْثٍ عَنْ مُجَاهِدٍ قَالَ وَمَعْنَى الْحَدِيثِ أَنْ لَا يَشْهَدَ الْجَمَاعَةَ وَالْجُمُعَةَ رَغْبَةً عَنْهَا وَاسْتِخْفَافًا بِحَقِّهَا وَتَهَاوُنًا بِهَا","id":"[Mujahid] berkata; \"[Ibnu Abbas] pernah ditanya tentang seorang laki-laki yang melaksanakan puasa di siang hari dan shalat di malam hari, namun ia tidak menghadiri shalat jum'at dan shalat berjama'ah di masjid?\" ia menjawab, \"Orang itu di neraka.\" Ia berkata; \"Hal itu diceritakan kepada kami oleh [Hannad] berkata; telah menceritakan kepada kami [Al Muharibi] dari [AL Laits] dari [Mujahid] ia berkata; \"Makna hadits ini adalah tidak boleh menghadiri shalat jum'at dan shalat jama'ah dengan rasa benci, serta mengurangi dan meremehkan haknya.\""},"203":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا يَعْلَى بْنُ عَطَاءٍ حَدَّثَنَا جَابِرُ بْنُ يَزِيدَ بْنِ الْأَسْوَدِ الْعَامِرِيُّ عَنْ أَبِيهِ قَالَشَهِدْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَجَّتَهُ فَصَلَّيْتُ مَعَهُ صَلَاةَ الصُّبْحِ فِي مَسْجِدِ الْخَيْفِ قَالَ فَلَمَّا قَضَى صَلَاتَهُ وَانْحَرَفَ إِذَا هُوَ بِرَجُلَيْنِ فِي أُخْرَى الْقَوْمِ لَمْ يُصَلِّيَا مَعَهُ فَقَالَ عَلَيَّ بِهِمَا فَجِيءَ بِهِمَا تُرْعَدُ فَرَائِصُهُمَا فَقَالَ مَا مَنَعَكُمَا أَنْ تُصَلِّيَا مَعَنَا فَقَالَا يَا رَسُولَ اللَّهِ إِنَّا كُنَّا قَدْ صَلَّيْنَا فِي رِحَالِنَا قَالَ فَلَا تَفْعَلَا إِذَا صَلَّيْتُمَا فِي رِحَالِكُمَا ثُمَّ أَتَيْتُمَا مَسْجِدَ جَمَاعَةٍ فَصَلِّيَا مَعَهُمْ فَإِنَّهَا لَكُمَا نَافِلَةٌقَالَ وَفِي الْبَاب عَنْ مِحْجَنٍ الدِّيلِيِّ وَيَزِيدَ بْنِ عَامِرٍ قَالَ أَبُو عِيسَى حَدِيثُ يَزِيدَ بْنِ الْأَسْوَدِ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ قَالُوا إِذَا صَلَّى الرَّجُلُ وَحْدَهُ ثُمَّ أَدْرَكَ الْجَمَاعَةَ فَإِنَّهُ يُعِيدُ الصَّلَوَاتِ كُلَّهَا فِي الْجَمَاعَةِ وَإِذَا صَلَّى الرَّجُلُ الْمَغْرِبَ وَحْدَهُ ثُمَّ أَدْرَكَ الْجَمَاعَةَ قَالُوا فَإِنَّهُ يُصَلِّيهَا مَعَهُمْ وَيَشْفَعُ بِرَكْعَةٍ وَالَّتِي صَلَّى وَحْدَهُ هِيَ الْمَكْتُوبَةُ عِنْدَهُمْ","id":"telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Husyaim] berkata; telah mengabarkan kepada kami [Ya'la bin 'Atha`] berkata; telah menceritakan kepada kami [Jabir bin Yazid bin Al Aswad Al 'Amiri] dari [Ayahnya] ia berkata; \"Aku pernah berhaji bersama Nabi shallallahu 'alaihi wasallam, lalu aku shalat subuh bersamanya di masjid Al Khaif.\" Ia berkata; \"Ketika beliau selesai melakasanakan shalat subuh dan berpaling, tiba-tiba ada dua orang laki-laki dari kaum lain yang tidak ikut shalat berjama'ah bersama beliau. Maka beliau pun bersabda: \"Bawalah dua orang itu kemari!\" maka mereka pun dibawa ke hadapan Nabi sedang urat mereka bergetar. Beliau bersabda: \"Apa yang menghalangi kalian untuk shalat bersama kami?\" mereka menjawab, \"Wahai Rasulullah, kami telah shalat di tempat kami, \" beliau bersabda: \"Janganlah kalian lakukan, jika kalian telah melaksanakannya di tempat kalian, lalu kalian datang ke masjid yang melaksanakan shalat berjama'ah maka shalatlah bersama mereka, karena hal itu akan menjadi pahala nafilah kalian berdua.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Mihjan Ad Dili dan Yazid bin Amir.\" Abu Isa berkata; \"Hadits Yazid bin Al Aswad derajatnya hasan shahih, ini adalah pendapat banyak ulama. Pendapat ini juga dipegang oleh Sufyan Ats Tsauri, Syafi'i, Ahmad dan Ishaq.\" Mereka berkata; \"Jika seorang laki-laki telah shalat sendirian kemudian mendapatkan shalat berjama'ah, maka hendaklah ia mengulangi semua shalatnya dengan berjama'ah. Dan jika seorang laki-laki telah shalat maghrib sendirian kemudian mendapatkan shalat berjama'ah, maka mereka berpendapat, \"Hendaklah ia shalat bersama mereka dan menggenapkan, sedangkan shalat yang ia lakukan sendirian itulah yang fardlu bagi mereka.\""},"204":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ سُلَيْمَانَ النَّاجِيِّ الْبَصْرِيِّ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ قَالَجَاءَ رَجُلٌ وَقَدْ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيُّكُمْ يَتَّجِرُ عَلَى هَذَا فَقَامَ رَجُلٌ فَصَلَّى مَعَهُقَالَ وَفِي الْبَاب عَنْ أَبِي أُمَامَةَ وَأَبِي مُوسَى وَالْحَكَمِ بْنِ عُمَيْرٍ قَالَ أَبُو عِيسَى وَحَدِيثُ أَبِي سَعِيدٍ حَدِيثٌ حَسَنٌ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ مِنْ التَّابِعِينَ قَالُوا لَا بَأْسَ أَنْ يُصَلِّيَ الْقَوْمُ جَمَاعَةً فِي مَسْجِدٍ قَدْ صَلَّى فِيهِ جَمَاعَةٌ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ و قَالَ آخَرُونَ مِنْ أَهْلِ الْعِلْمِ يُصَلُّونَ فُرَادَى وَبِهِ يَقُولُ سُفْيَانُ وَابْنُ الْمُبَارَكِ وَمَالِكٌ وَالشَّافِعِيُّ يَخْتَارُونَ الصَّلَاةَ فُرَادَى وَسُلَيْمَانُ النَّاجِيُّ بَصْرِيٌّ وَيُقَالُ سُلَيْمَانُ بْنُ الْأَسْوَدِ وَأَبُو الْمُتَوَكِّلِ اسْمُهُ عَلِيُّ بْنُ دَاوُدَ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abdah] dari [Sa'id bin Abu Arubah] dari [Sulaiman An Naji Al Bashri] dari [Abu Al Mutawakkil] dari [Abu Sa'id] ia berkata; \"Seorang laki-laki datang sedangkan Rasulullah shallallahu 'alaihi wasallam telah melaksanakan shalat, lalu beliau bersabda: \"Siapa yang ingin berdagang (mencari pahala) dengan orang ini?\" lalu berdirilah seorang laki-laki dan shalat bersamanya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Umamah, Abu Musa dan Al Hakam bin Umair.\" Abu Isa berkata; \"Hadits Abu Sa'id derajatnya hasan, ini adalah pendapat yang diambil tidak hanya oleh seorang saja dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan selain mereka dari kalangan tabi'in. Mereka berkata; \"Tidak apa-apa mereka melaksanakan shalat berjama'ah di suatu masjid yang telah dilaksanakan shalat berjama'ah di dalamnya.\" Pendapat ini diambil oleh Ahmad dan Ishaq. Sedangkan ulama lain mengatakan, \"Hendaklah mereka melaksanakan shalat sendiri-sendiri.\" Pendapat ini diambil oleh Sufyan Ats Tsauri, bin Al Mubarak, Malik dan Syafi'i. Mereka memilih untuk shalat sendiri-sendiri. Sulaiman An Naji adalah orang Bashrah, ia disebut dengan nama Sulaiman bin Al Aswad. Sedangkan Abu Al Mutawakkil namanya adalah Ali bin Dawud.\""},"205":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا بِشْرُ بْنُ السَّرِيِّ حَدَّثَنَا سُفْيَانُ عَنْ عُثْمَانَ بْنِ حَكِيمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَمْرَةَ عَنْ عُثْمَانَ بْنِ عَفَّانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَهِدَ الْعِشَاءَ فِي جَمَاعَةٍ كَانَ لَهُ قِيَامُ نِصْفِ لَيْلَةٍ وَمَنْ صَلَّى الْعِشَاءَ وَالْفَجْرَ فِي جَمَاعَةٍ كَانَ لَهُ كَقِيَامِ لَيْلَةٍقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَأَبِي هُرَيْرَةَ وَأَنَسٍ وَعُمَارَةَ بْنِ رُوَيْبَةَ وَجُنْدَبِ بْنِ عَبْدِ اللَّهِ بْنِ سُفْيَانَ الْبَجَلِيِّ وَأُبَيِّ بْنِ كَعْبٍ وَأَبِي مُوسَى وَبُرَيْدَةَ قَالَ أَبُو عِيسَى حَدِيثُ عُثْمَانَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَمْرَةَ عَنْ عُثْمَانَ مَوْقُوفًا وَرُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ عُثْمَانَ مَرْفُوعًا","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Bisyr bin As Sari] berkata; telah menceritakan kepada kami [Sufyan] dari [Utsman bin Hakim] dari [Abdurrahman bin Abu Amrah] dari [Utsman bin 'Affan] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melaksanakan shalat isya berjama'ah maka ia mendapatkan pahala shalat setengah malam, dan barangsiapa melaksanakan shalat isya dan subuh dengan berjama'ah maka ia mendapatkan pahala shalat satu malam.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Umar, Abu Hurairah, Anas, Umarah bin Ruwaibah, Jundab bin Abdullah bin Sufyan Al Bajali, Ubai bin Ka'ab, Abu Musa dan Buraidah.\" Abu Isa berkata; \"Hadits Utsman ini derajatnya hasan shahih. Hadits ini juga telah diriwayatkan dari Abdurrahman bin Abu Amrah dari Utsman secara mauquf. Dan hadits ini juga telah diriwayatkan dari Utsman secara marfu' dengan banyak jalur.\""},"206":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الْحَسَنِ عَنْ جُنْدَبِ بْنِ سُفْيَانَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى الصُّبْحَ فَهُوَ فِي ذِمَّةِ اللَّهِ فَلَا تُخْفِرُوا اللَّهَ فِي ذِمَّتِهِقَالَ أَبُو عِيسَى حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Dawud bin Abu Hind] dari [Al Hasan] dari [Jundab bin Sufyan] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa shalat subuh maka ia dalam jaminan Allah, oleh sebab itu janganlah membatalkan jaminan Allah.\""},"207":{"ar":"حَدَّثَنَا عَبَّاسٌ الْعَنْبَرِيُّ حَدَّثَنَا يَحْيَى بْنُ كَثِيرٍ أَبُو غَسَّانَ الْعَنْبَرِيُّ عَنْ إِسْمَعِيلَ الْكَحَّالِ عَنْ عَبْدِ اللَّهِ بْنِ أَوْسٍ الْخُزَاعِيِّ عَنْ بُرَيْدَةَ الْأَسْلَمِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَشِّرْ الْمَشَّائِينَ فِي الظُّلَمِ إِلَى الْمَسَاجِدِ بِالنُّورِ التَّامِّ يَوْمَ الْقِيَامَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ مَرْفُوعٌ هُوَ صَحِيحٌ مُسْنَدٌ وَمَوْقُوفٌ إِلَى أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يُسْنَدْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"telah menceritakan kepada kami [Abbas Al Anbari] berkata; telah menceritakan kepada kami [Yahya bin Katsir Abu Ghassan Al Anbari] dari [Isma'il Al Kahhal] dari [Abdullah bin Aus Al Khuza'i] dari [Buraidah Al Aslami] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Berilah kabar gembira kepada orang-orang yang berjalan di kegelapan malam menuju masjid dengan cahaya sempurna kelak di hari kiamat.\" Abu Isa berkata; \"Hadits ini gharib dari jalur ini, namun ia marfu' dan sanadnya shahih. Ia hanya sampai kepada sahabat Nabi shallallahu 'alaihi wasallam dan tidak sampai kepada Nabi shallallahu 'alaihi wasallam.\""},"208":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ صُفُوفِ الرِّجَالِ أَوَّلُهَا وَشَرُّهَا آخِرُهَا وَخَيْرُ صُفُوفِ النِّسَاءِ آخِرُهَا وَشَرُّهَا أَوَّلُهَاقَالَ وَفِي الْبَاب عَنْ جَابِرٍ وَابْنِ عَبَّاسٍ وَأَبِي سَعِيدٍ وَأُبَيٍّ وَعَائِشَةَ وَالْعِرْبَاضِ بْنِ سَارِيَةَ وَأَنَسٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَسْتَغْفِرُ لِلصَّفِّ الْأَوَّلِ ثَلَاثًا وَلِلثَّانِي مَرَّةً","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Suhail bin Abu Shalih] dari [Ayahnya] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik barisan shalat laki-laki adalah yang paling depan dan yang paling buruk adalah yang terakhir. Dan sebaik-baik barisan shalat wanita adalah yang paling belakang dan yang paling buruk adalah yang paling depan.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Jabir, Ibnu Abbas, Abu Sa'id, Ubai, 'Aisyah, Irbadl bin Sariyah dan Anas.\" Abu Isa berkata; \"Hadits Abu Hurairah ini derajatnya hasan shahih. Dan telah diriwayatkan pula bahwa Nabi shallallahu 'alaihi wasallam memintakan ampun untuk orang-orang yang berada di shaf pertama sebanyak tiga kali, dan shaf kedua sebanyak dua kali.\""},"209":{"ar":"و قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَنَّ النَّاسَ يَعْلَمُونَ مَا فِي النِّدَاءِ وَالصَّفِّ الْأَوَّلِ ثُمَّ لَمْ يَجِدُوا إِلَّا أَنْ يَسْتَهِمُوا عَلَيْهِ لَاسْتَهَمُوا عَلَيْهِقَالَ حَدَّثَنَا بِذَلِكَ إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ و حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ نَحْوَهُ","id":"Nabi shallallahu 'alaihi wasallam bersabda: \"Sekiranya orang-orang mengetahui pahala memenuhi panggilan adzan dan shaf pertama, kemudian mereka tidak akan mendapatkannya kecuali harus berundi, sungguh mereka akan berundi untuk mendapatkannya.\" Ia berkata; \" [Ishaq bin Musa] menceritakan hal itu kepada kami dari [Ma'n] berkata; telah menceritakan kepada kami [Malik] dari [Sumai] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits. Dan [Qutaibah] juga telah menceritakan kepada kami dari [Malik] sebagaimana dalam hadits tersebut.\""},"210":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَوِّي صُفُوفَنَا فَخَرَجَ يَوْمًا فَرَأَى رَجُلًا خَارِجًا صَدْرُهُ عَنْ الْقَوْمِ فَقَالَ لَتُسَوُّنَّ صُفُوفَكُمْ أَوْ لَيُخَالِفَنَّ اللَّهُ بَيْنَ وُجُوهِكُمْقَالَ وَفِي الْبَاب عَنْ جَابِرِ بْنِ سَمُرَةَ وَالْبَرَاءِ وَجَابِرِ بْنِ عَبْدِ اللَّهِ وَأَنَسٍ وَأَبِي هُرَيْرَةَ وَعَائِشَةَ قَالَ أَبُو عِيسَى حَدِيثُ النُّعْمَانِ بْنِ بَشِيرٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مِنْ تَمَامِ الصَّلَاةِ إِقَامَةُ الصَّفِّ وَرُوِيَ عَنْ عُمَرَ أَنَّهُ كَانَ يُوَكِّلُ رِجَالًا بِإِقَامَةِ الصُّفُوفِ فَلَا يُكَبِّرُ حَتَّى يُخْبَرَ أَنَّ الصُّفُوفَ قَدْ اسْتَوَتْ وَرُوِيَ عَنْ عَلِيٍّ وَعُثْمَانَ أَنَّهُمَا كَانَا يَتَعَاهَدَانِ ذَلِكَ وَيَقُولَانِ اسْتَوُوا وَكَانَ عَلِيٌّ يَقُولُ تَقَدَّمْ يَا فُلَانُ تَأَخَّرْ يَا فُلَانُ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abu Awanah] dari [Simak bin Harb] dari [An Nu'man bin Basyir] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa meluruskan barisan shalat kami. Maka pada suatu hari beliau keluar dan melihat seseorang yang dadanya lebih menjorok ke depan dari yang lain, beliau bersabda: \"Kalian luruskan barisan kalian atau Allah akan memecah-belah antara kalian.\" Imam Tirmidzi bekata, \"Dalam bab ini ada juga hadits dari Jabir bin Samrah, Al Barra, Jabir bin Abdullah, Anas, Abu Hurairah dan 'Aisyah.\" Abu Isa berkata; \"Hadits Nu'man bin Basyir ini derajatnya hasan shahih.\" Telah diriwayatkan dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Termasuk dari kesempurnaan shalat adalah meluruskan barisan shalat.\" Diriwayatkan juga dari Umar bahwa dia memerintahkan beberapa orang lelaki untuk meluruskan barisan shalat, dan ia tidak memulai takbir hingga mendapat kabar bahwa barisan shalat telah lurus. Telah diriwayatkan juga dari Ali dan Utsman, bahwa keduanya selalu memperhatikan hal itu. Keduanya berkata: \"Luruskanlah (barisan shalat kalian).\" Ali kadang berkata; \"Maju wahai fulan, mundur wahai fulan.\""},"211":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي مَعْشَرٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِيَلِيَنِّي مِنْكُمْ أُولُو الْأَحْلَامِ وَالنُّهَى ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ وَلَا تَخْتَلِفُوا فَتَخْتَلِفَ قُلُوبُكُمْ وَإِيَّاكُمْ وَهَيْشَاتِ الْأَسْوَاقِقَالَ وَفِي الْبَاب عَنْ أُبَيِّ بْنِ كَعْبٍ وَأَبِي مَسْعُودٍ وَأَبِي سَعِيدٍ وَالْبَرَاءِ وَأَنَسٍ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ مَسْعُودٍ حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يُعْجِبُهُ أَنْ يَلِيَهُ الْمُهَاجِرُونَ وَالْأَنْصَارُ لِيَحْفَظُوا عَنْهُ قَالَ وَخَالِدٌ الْحَذَّاءُ هُوَ خَالِدُ بْنُ مِهْرَانَ يُكْنَى أَبَا الْمُنَازِلِ قَالَ و سَمِعْت مُحَمَّدَ بْنَ إِسْمَعِيلَ يَقُولُ يُقَالُ إِنَّ خَالِدًا الْحَذَّاءَ مَا حَذَا نَعْلًا قَطُّ إِنَّمَا كَانَ يَجْلِسُ إِلَى حَذَّاءٍ فَنُسِبَ إِلَيْهِ قَالَ وَأَبُو مَعْشَرٍ اسْمُهُ زِيَادُ بْنُ كُلَيْبٍ","id":"telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata; telah menceritakan kepada kami [Yazid bin Zurai'] berkata; telah menceritakan kepada kami [Khalid Al Hadza`] dari [Abu Ma'syar] dari [Ibrahim] dari [Alqamah] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Hendaklah orang yang di belakangku orang yang paling berilmu dan tua di antara kalian, lalu setelahnya, lalu setelahnya. Dan janganlah berselisih hingga hati kalian akan berselisih. Dan jauhilah oleh kalian kegaduhan pasar-pasar.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ubai bin Ka'ab, Abu Mas'ud, Abu Sa'id, Al Bara dan Anas.\" Diriwayatkan pula dari Nabi shallallahu 'alaihi wasallam bahwa beliau lebih menyukai jika yang berada di belakangnya adalah orang-orang Muhajirin dan Anshar, hingga mereka dapat menjaganya.\" Ia berkata; \"Khalid Al Hadza` adalah Khalid bin Mihran, ia dijuluki dengan Abu Al Manazil.\" Ia berkata; \"Aku mendengar Muhammad bin Isma'il berkata; \"Dikatakan bahwa Khalid Al Hadza` tidak pernah memakai sepatu. Ia terbiasa duduk di atas sepatu hingga ia dijuluki seperti itu.\" Ia berkata; \"Abu Ma'syar namanya adalah Ziyad bin Kulaib.\""},"212":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ يَحْيَى بْنِ هَانِئِ بْنِ عُرْوَةَ الْمُرَادِيِّ عَنْ عَبْدِ الْحَمِيدِ بْنِ مَحْمُودٍ قَالَصَلَّيْنَا خَلْفَ أَمِيرٍ مِنْ الْأُمَرَاءِ فَاضْطَرَّنَا النَّاسُ فَصَلَّيْنَا بَيْنَ السَّارِيَتَيْنِ فَلَمَّا صَلَّيْنَا قَالَ أَنَسُ بْنُ مَالِكٍ كُنَّا نَتَّقِي هَذَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَفِي الْبَاب عَنْ قُرَّةَ بْنِ إِيَاسٍ الْمُزَنِيِّ قَالَ أَبُو عِيسَى حَدِيثُ أَنَسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ كَرِهَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ أَنْ يُصَفَّ بَيْنَ السَّوَارِي وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ وَقَدْ رَخَّصَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ فِي ذَلِكَ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Yahya bin Hani` bin Urwah Al Muradi] dari [Abdul Hamid bin Mahmud] ia berkata; \"Kami pernah shalat di belakang salah seorang pemimpin kami, lalu orang-orang mendesak (mempersempit) hingga kami shalat di antara dua tiang. Setelah kami selesai shalat [Anas bin Malik] berkata; \"Kami menghindari hal seperti ini pada masa Rasulullah shallallahu 'alaihi wasallam.\" Ia berkata; \"Dalam bab ini ada juga hadits dari Qurrah bin Iyas Al Muzani.\" Abu Isa berkata; \"Hadits Anas ini derajatnya hasan shahih. Sebagian ahli ilmu memakruhkan membuat barisan shalat antara dua tiang. Ini adalah pendapat yang diambil oleh Imam Ahmad dan Ishaq, namun sebagian ahli ilmu yang lain memberikan keringanan.\""},"213":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ حُصَيْنٍ عَنْ هِلَالِ بْنِ يَسَافٍ قَالَأَخَذَ زِيَادُ بْنُ أَبِي الْجَعْدِ بِيَدِي وَنَحْنُ بِالرَّقَّةِ فَقَامَ بِي عَلَى شَيْخٍ يُقَالُ لَهُ وَابِصَةُ بْنُ مَعْبَدٍ مِنْ بَنِي أَسَدٍ فَقَالَ زِيَادٌ حَدَّثَنِي هَذَا الشَّيْخُ أَنَّ رَجُلًا صَلَّى خَلْفَ الصَّفِّ وَحْدَهُ وَالشَّيْخُ يَسْمَعُ فَأَمَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُعِيدَ الصَّلَاةَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَلِيِّ بْنِ شَيْبَانَ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى وَحَدِيثُ وَابِصَةَ حَدِيثٌ حَسَنٌ وَقَدْ كَرِهَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ أَنْ يُصَلِّيَ الرَّجُلُ خَلْفَ الصَّفِّ وَحْدَهُ وَقَالُوا يُعِيدُ إِذَا صَلَّى خَلْفَ الصَّفِّ وَحْدَهُ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ وَقَدْ قَالَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ يُجْزِئُهُ إِذَا صَلَّى خَلْفَ الصَّفِّ وَحْدَهُ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَابْنِ الْمُبَارَكِ وَالشَّافِعِيِّ وَقَدْ ذَهَبَ قَوْمٌ مِنْ أَهْلِ الْكُوفَةِ إِلَى حَدِيثِ وَابِصَةَ بْنِ مَعْبَدٍ أَيْضًا قَالُوا مَنْ صَلَّى خَلْفَ الصَّفِّ وَحْدَهُ يُعِيدُ مِنْهُمْ حَمَّادُ بْنُ أَبِي سُلَيْمَانَ وَابْنُ أَبِي لَيْلَى وَوَكِيعٌ وَرَوَى حَدِيثَ حُصَيْنٍ عَنْ هِلَالِ بْنِ يَسَافٍ غَيْرُ وَاحِدٍ مِثْلَ رِوَايَةِ أَبِي الْأَحْوَصِ عَنْ زِيَادِ بْنِ أَبِي الْجَعْدِ عَنْ وَابِصَةَ بْنِ مَعْبَدٍ وَفِي حَدِيثِ حُصَيْنٍ مَا يَدُلُّ عَلَى أَنَّ هِلَالًا قَدْ أَدْرَكَ وَابِصَةَ وَاخْتَلَفَ أَهْلُ الْحَدِيثِ فِي هَذَا فَقَالَ بَعْضُهُمْ حَدِيثُ عَمْرِو بْنِ مُرَّةَ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ عَمْرِو بْنِ رَاشِدٍ عَنْ وَابِصَةَ بْنِ مَعْبَدٍ أَصَحُّ وَقَالَ بَعْضُهُمْ حَدِيثُ حُصَيْنٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ زِيَادِ بْنِ أَبِي الْجَعْدِ عَنْ وَابِصَةَ بْنِ مَعْبَدٍ أَصَحُّ قَالَ أَبُو عِيسَى وَهَذَا عِنْدِي أَصَحُّ مِنْ حَدِيثِ عَمْرِو ابْنِ مُرَّةَ لِأَنَّهُ قَدْ رُوِيَ مِنْ غَيْرِ حَدِيثِ هِلَالِ بْنِ يَسَافٍ عَنْ زِيَادِ بْنِ أَبِي الْجَعْدِ عَنْ وَابِصَةَ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Hushain] dari [Hilal bin Yasaf] berkata; Ziyad bin Abu Al Ja'd memegang tanganku ketika kami sedang berada di tanah yang becek (bekas genangan banjir). Lalu ia mengajakku menemui seorang syaikh yang biasa dipanggil dengan nama [Wabishah bin Ma'bad] dari bani Asad. Ziyad berkata; \"Syaikh ini menceritakan kepadaku, pernah seorang laki-laki shalat sendirian di belakang shaf, syaikh tersebut mendengar Rasulullah shallallahu 'alaihi wasallam memerintahkan laki-laki itu untuk mengulangi shalatnya.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Ali bin Syaiban dan Ibnu Abbas.\" Abu Isa berkata; \"Hadits Wabishah ini derajatnya hasan. Sebagian ahli ilmu memakruhkan shalat sendirian di belakang imam, mereka berkata; \"Ia harus mengulangi shalatnya jika dilakukan sendirian di belakang imam.\" Pendapat ini diambil oleh Ahmad dan Ishaq. Dan sebagian ulama yang lain, \"Jika ia shalat sendirian di belakang imam maka itu telah mencukupi.\" Pendapat ini diambil oleh Sufyan Ats Tsauri, bin Al Mubarak dan Syafi'i. Beberapa ulama dari Kufah juga berpegangan dengan hadits Wabishah bin Ma'bad, mereka berkata; \"Barangsiapa shalat sendirian di belakang shaf maka ia harus menguangi shalatnya.\" Di antara yang berpendapat seperti ini adalah Hammad bin Sulaiman, Ibnu Abu laila dan Waki'. Hadits Hushain dari Hilal bin Yasaf diriwayatkan dari beberapa orang, seperti riwayat Abu Al Ahwash, dari Ziyad bin Abu Al Ja'd, dari Wabishah bin Ma'bad. Dalam hadits Hushain ini ada petunjuk bahwa Hilal pernah bertemu dengan Wabishah. Dalam hal ini terjadi perselisihan antara ahli hadits, sebagian mereka berkata; \"Hadits yang diriwayatkan dari 'Amru bin Murrah, dari Hilal bin Yasaf, dari 'Amru bin Risydin, dari Wabishah bin Ma'bad lebih shahih. sedangkan yang lain mengatakan, \"Hadits Hushain yang diriwayatkan dari Hilal bin Yasaf, dari Ziyad bin Abu Al Ja'd, dari Wabishah bin Ma'bad lebih shahih.\" Abu Isa berkata; \"Menurutku hadits ini lebih shahih dari hadits Amru bin Murrah. Sebab hadits itu juga telah diriwayatkan dari selain hadits Hilal bin Yasaf, dari Ziyad bin Abu Al Ja'd, dari Wabishah.\""},"214":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ عَمْرِو بْنِ رَاشِدٍ عَنْ وَابِصَةَ بْنِ مَعْبَدٍأَنَّ رَجُلًا صَلَّى خَلْفَ الصَّفِّ وَحْدَهُ فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُعِيدَ الصَّلَاةَقَالَ أَبُو عِيسَى و سَمِعْت الْجَارُودَ يَقُولُ سَمِعْتُ وَكِيعًا يَقُولُ إِذَا صَلَّى الرَّجُلُ خَلْفَ الصَّفِّ وَحْدَهُ فَإِنَّهُ يُعِيدُ","id":"telah menceritakan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Hilal bin Yasaf] dari [Amru bin Rasyid] dari [Wabishah bin Ma'bad] berkata; \"Seorang laki-laki shalat sendirian di belakang shaf, maka Nabi shallallahu 'alaihi wasallam memerintahkannya untuk mengulangi shalat.\" Abu Isa berkata; \"Aku mendengar 'Al Jarud berkata; \"Aku mendengar Waki' berkata; \"Jika seorang laki-laki shalat sendirian di belakang shaf, maka ia harus mengulanginya.\""},"215":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا دَاوُدُ بْنُ عَبْدِ الرَّحْمَنْ الْعَطَّارُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَقُمْتُ عَنْ يَسَارِهِ فَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَأْسِي مِنْ وَرَائِي فَجَعَلَنِي عَنْ يَمِينِهِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَنَسٍ قَالَ أَبُو عِيسَى وَحَدِيثُ ابْنِ عَبَّاسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ قَالُوا إِذَا كَانَ الرَّجُلُ مَعَ الْإِمَامِ يَقُومُ عَنْ يَمِينِ الْإِمَامِ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Daud bin Abdurrahman Al Aththar] dari ['Amru bin Dinar] dari [Kuraib] pelayan Ibnu Abbas dari [Ibnu Abbas], ia berkata; \"Suatu malam aku pernah shalat bersama Nabi shallallahu 'alaihi wasallam, aku berdiri di sisi kirinya, maka Rasulullah shallallahu 'alaihi wasallam pun memegang kepalaku dari belakang seraya memutar ke sebelah kanannya.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Anas.\" Abu Isa berkata; \"Hadits Ibnu Abbas ini derajatnya hasan shahih. Hadits ini diamalkan oleh ahli ilmu dari kalangan sabahat-sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka. Mereka berkata; \"Jika seorang laki-laki shalat bersama imam hendaklah ia shalat di sisi kananya.\""},"216":{"ar":"حَدَّثَنَا بُنْدَارٌ مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ قَالَ أَنْبَأَنَا إِسْمَعِيلُ بْنُ مُسْلِمٍ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كُنَّا ثَلَاثَةً أَنْ يَتَقَدَّمَنَا أَحَدُنَاقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَجَابِرٍ وَأَنَسِ بْنِ مَالِكٍ قَالَ أَبُو عِيسَى وَحَدِيثُ سَمُرَةَ حَدِيثٌ حَسَنٌ غَرِيبٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ قَالُوا إِذَا كَانُوا ثَلَاثَةً قَامَ رَجُلَانِ خَلْفَ الْإِمَامِ وَرُوِيَ عَنْ ابْنِ مَسْعُودٍ أَنَّهُ صَلَّى بِعَلْقَمَةَ وَالْأَسْوَدِ فَأَقَامَ أَحَدَهُمَا عَنْ يَمِينِهِ وَالْآخَرَ عَنْ يَسَارِهِ وَرَوَاهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ تَكَلَّمَ بَعْضُ النَّاسِ فِي إِسْمَعِيلَ بْنِ مُسْلِمٍ الْمَكِّيِّ مِنْ قِبَلِ حِفْظِهِ","id":"telah menceritakan kepada kami [Bundar Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Muhammad bin Abu Adi] ia berkata; telah memberitakan kepada kami [Isma'il bin Muslim] dari [Al Hasan] dari [Samrah bin Jundab] ia berkata; \"Jika kami berjumlah tiga orang, Rasulullah shallallahu 'alaihi wasallam memerintahkan kepada kami agar salah seorang dari kami maju ke depan sebagai imam.\" Abu Isa berkata; \"Dalam bab ini ada juga hadits dari Ibnu Mas'ud, Jabir dan Anas bin Malik.\" Abu Isa berkata; \"Hadits Samrah ini derajatnya hasan gharib, hadits ini diamalkan oleh para ahli ilmu. Mereka mengatakan, \"Apabila ada tiga orang, maka dua orang berdiri di belakang imam.\" Diriwayatkan dari Ibnu Mas'ud bahwa ia pernah shalat bersama Alqamah dan Al Aswad, salah seorang berdiri di sebelah kanan dan yang lain lagi berdiri di sebelah kirinya. Ia meriwayatkan juga dari Nabi shallallahu 'alaihi wasallam. Dan sebagian ahli ilmu memperbincangkan Isma'il bin Muslim Al Makki dari segi hafalannya."},"217":{"ar":"حَدَّثَنَا إِسْحَقُ الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ جَدَّتَهُ مُلَيْكَةَ دَعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِطَعَامٍ صَنَعَتْهُ فَأَكَلَ مِنْهُ ثُمَّ قَالَ قُومُوا فَلْنُصَلِّ بِكُمْ قَالَ أَنَسٌ فَقُمْتُ إِلَى حَصِيرٍ لَنَا قَدْ اسْوَدَّ مِنْ طُولِ مَا لُبِسَ فَنَضَحْتُهُ بِالْمَاءِ فَقَامَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَفَفْتُ عَلَيْهِ أَنَا وَالْيَتِيمُ وَرَاءَهُ وَالْعَجُوزُ مِنْ وَرَائِنَا فَصَلَّى بِنَا رَكْعَتَيْنِ ثُمَّ انْصَرَفَقَالَ أَبُو عِيسَى حَدِيثُ أَنَسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ قَالُوا إِذَا كَانَ مَعَ الْإِمَامِ رَجُلٌ وَامْرَأَةٌ قَامَ الرَّجُلُ عَنْ يَمِينِ الْإِمَامِ وَالْمَرْأَةُ خَلْفَهُمَا وَقَدْ احْتَجَّ بَعْضُ النَّاسِ بِهَذَا الْحَدِيثِ فِي إِجَازَةِ الصَّلَاةِ إِذَا كَانَ الرَّجُلُ خَلْفَ الصَّفِّ وَحْدَهُ وَقَالُوا إِنَّ الصَّبِيَّ لَمْ تَكُنْ لَهُ صَلَاةٌ وَكَأَنَّ أَنَسًا كَانَ خَلْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحْدَهُ فِي الصَّفِّ وَلَيْسَ الْأَمْرُ عَلَى مَا ذَهَبُوا إِلَيْهِ لِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَامَهُ مَعَ الْيَتِيمِ خَلْفَهُ فَلَوْلَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَعَلَ لِلْيَتِيمِ صَلَاةً لَمَا أَقَامَ الْيَتِيمَ مَعَهُ وَلَأَقَامَهُ عَنْ يَمِينِهِ وَقَدْ رُوِيَ عَنْ مُوسَى بْنِ أَنَسٍ عَنْ أَنَسٍ أَنَّهُ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَقَامَهُ عَنْ يَمِينِهِ وَفِي هَذَا الْحَدِيثِ دَلَالَةٌ أَنَّهُ إِنَّمَا صَلَّى تَطَوُّعًا أَرَادَ إِدْخَالَ الْبَرَكَةِ عَلَيْهِمْ","id":"telah menceritakan kepada kami [Ishaq Al Anshari] berkata; telah menceritakan kepada kami [Ma'n] berkata; telah menceritakan kepada kami [Malik bin Anas] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] bahwa neneknya (Mulaikah) mengundang Rasulullah shallallahu 'alaihi wasallam untuk jamuan makan yang ia masak. Lalu beliau makan dan bersabda: \"Berdirilah, kita akan shalat.\" Anas berkata; \"Lalu aku berdiri di atas tikar milik kami yang telah berwarna hitam karena telah lama dipakai. Aku pun memercikinya dengan air. Setelah itu Rasulullah shallallahu 'alaihi wasallam berdiri di atasnya, aku dan seorang anak yatim membuat barisan di belakangnya, sedang di belakang akan ada orang tua (nenek). Beliau shalat dua rakaat bersama kami setelah itu pergi.\" Abu Isa berkata; \"Hadits Anas ini derajatnya hasan shahih. Hadits ini juga diamalkan oleh kebanyakan ahli ilmu, mereka mengatakan, \"Jika imam bersama seorang laki-laki dan seorang wanita, maka laki-laki tersebut berdiri di sisi kanan imam sedangkan wanitanya di belakang mereka berdua. Sebagian orang berdalil dengan hadits ini atas pembolehan seseorang shalat di belakang shaf sendirian. Mereka juga mengatakan, \"Anak kecil shalatnya belum dihitung, hingga seakan-akan Anas pada waktu itu shalat di belakang Nabi shallallahu 'alaihi wasallam sendirian di belakang shaf. Namun persoalan ini tidak sebagimana yang mereka pahami, sebab waktu itu Nabi menempatkan Anas bersama dengan seorang akan kecil di belakang beliau. Sekiranya Nabi shallallahu 'alaihi wasallam tidak menghitung shalat anak yatim tersebut tentu beliau tidak akan menempatkannya bersama Anas, dan pasti Nabi akan menempatkannya (Anas) di sebelah kanannya.\" Diriwayatkan pula dari Musa bin Anas, dari Anas, bahwasanya ia pernah shalat bersama Nabi shallallahu 'alaihi wasallam, lalu beliau menempatkannya di sisi kanannya.\" Dalam hadits ini ada dalil bahwa, beliau shalat sunah bersama mereka dengan harapan agar mereka mendapatkan berkah.\""},"218":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ قَالَ و حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَعَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ الْأَعْمَشِ عَنْ إِسْمَعِيلَ بْنِ رَجَاءٍ الزُّبَيْدِيِّ عَنْ أَوْسِ بْنِ ضَمْعَجٍ قَال سَمِعْتُ أَبَا مَسْعُودٍ الْأَنْصَارِيَّ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَؤُمُّ الْقَوْمَ أَقْرَؤُهُمْ لِكِتَابِ اللَّهِ فَإِنْ كَانُوا فِي الْقِرَاءَةِ سَوَاءً فَأَعْلَمُهُمْ بِالسُّنَّةِ فَإِنْ كَانُوا فِي السُّنَّةِ سَوَاءً فَأَقْدَمُهُمْ هِجْرَةً فَإِنْ كَانُوا فِي الْهِجْرَةِ سَوَاءً فَأَكْبَرُهُمْ سِنًّا وَلَا يُؤَمُّ الرَّجُلُ فِي سُلْطَانِهِ وَلَا يُجْلَسُ عَلَى تَكْرِمَتِهِ فِي بَيْتِهِ إِلَّا بِإِذْنِهِقَالَ مَحْمُودُ بْنُ غَيْلَانَ قَالَ ابْنُ نُمَيْرٍ فِي حَدِيثِهِ أَقْدَمُهُمْ سِنًّا قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ وَأَنَسِ بْنِ مَالِكٍ وَمَالِكِ بْنِ الْحُوَيْرِثِ وَعَمْرِو بْنِ سَلَمَةَ قَالَ أَبُو عِيسَى وَحَدِيثُ أَبِي مَسْعُودٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ قَالُوا أَحَقُّ النَّاسِ بِالْإِمَامَةِ أَقْرَؤُهُمْ لِكِتَابِ اللَّهِ وَأَعْلَمُهُمْ بِالسُّنَّةِ وَقَالُوا صَاحِبُ الْمَنْزِلِ أَحَقُّ بِالْإِمَامَةِ و قَالَ بَعْضُهُمْ إِذَا أَذِنَ صَاحِبُ الْمَنْزِلِ لَغَيْرِهِ فَلَا بَأْسَ أَنْ يُصَلِّيَ بِهِ وَكَرِهَهُ بَعْضُهُمْ وَقَالُوا السُّنَّةُ أَنْ يُصَلِّيَ صَاحِبُ الْبَيْتِ قَالَ أَحْمَدُ بْنُ حَنْبَلٍ وَقَوْلُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا يُؤَمُّ الرَّجُلُ فِي سُلْطَانِهِ وَلَا يُجْلَسُ عَلَى تَكْرِمَتِهِ فِي بَيْتِهِ إِلَّا بِإِذْنِهِ فَإِذَا أَذِنَ فَأَرْجُو أَنَّ الْإِذْنَ فِي الْكُلِّ وَلَمْ يَرَ بِهِ بَأْسًا إِذَا أَذِنَ لَهُ أَنْ يُصَلِّيَ بِهِ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] berkata; dan telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dan [Abdullah bin Numair] dari [Al A'masy] dari [Isma'il bin Raja` Az Zubair] dari [Aus bin Dlam'aj] ia berkata; \"Aku mendengar [Abu Mas'ud Al Anshari] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Yang paling berhak untuk menjadi imam pada suatu kaum adalah yang paling bagus dalam membaca Al Qur`an. Jika mereka sama dalam membaca maka yang paling paham dengan sunnah. Jika mereka sama dalam sunnah maka yang paling dahulu hijrah. Jika mereka sama dalam hijrah maka yang paling tua umurnya. Janganlah seseorang menjadi imam dalam kekuasaan orang lain dan jangan duduk di tempat keistimewaannya di rumahnya kecuali dengan izinnya.\" Mahmud bin Ghailan berkata; \"Ibnu Numair menyebutkan dalam haditsnya, \"Yang paling tua umurnya.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Abu Sa'id Al Khudri, Anas bin Malik, Malik bin Al Huwairits dan 'Amru bin Salamah.\" Abu Isa berkata; \"Hadits Abu Mas'ud ini derajatnya hasan shahih. Hadits ini diamalkan oleh ahli ilmu, mereka berkata; \"Yang paling berhak untuk menjadi imam adalah yang paling bagus dalam membaca Al Qur`an dan yang paling paham dengan sunnah.\" Mereka juga berkata; \"Pemilik rumah berhak untuk menjadi imam.\" Sebagian mereka berkata; \"Jika pemilik rumah memberikan izin kepada yang lain maka tidak mengapa shalat bersamanya.\" Namun sebagian yang lain memakruhkannya, mereka mengatakan, \"Yang sunnah adalah seorang pemilik rumah yang menjadi imam.\" Imam Ahmad bin Hambal berkata; \"Sabda Rasulullah shallallahu 'alaihi wasallam: \"Janganlah seseorang menjadi imam di dalam kekuasaan orang lain dan jangan duduk di tempat keistimewaannya di rumahnya kecuali dengan izinnya.\" Jika mengizinkan maka saya berharap izin itu untuk semuanya.\" Kemudian ia berpendapat bolehnya mengimami shalat jika diizinkan olehnya (pemilik rumah).\" "},"219":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَمَّ أَحَدُكُمْ النَّاسَ فَلْيُخَفِّفْ فَإِنَّ فِيهِمْ الصَّغِيرَ وَالْكَبِيرَ وَالضَّعِيفَ وَالْمَرِيضَ فَإِذَا صَلَّى وَحْدَهُ فَلْيُصَلِّ كَيْفَ شَاءَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَدِيِّ بْنِ حَاتِمٍ وَأَنَسٍ وَجَابِرِ بْنِ سَمُرَةَ وَمَالِكِ بْنِ عَبْدِ اللَّهِ وَأَبِي وَاقِدٍ وَعُثْمَانَ بْنِ أَبِي الْعَاصِ وَأَبِي مَسْعُودٍ وَجَابِرِ بْنِ عَبْدِ اللَّهِ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى وَحَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ أَكْثَرِ أَهْلِ الْعِلْمِ اخْتَارُوا أَنْ لَا يُطِيلَ الْإِمَامُ الصَّلَاةَ مَخَافَةَ الْمَشَقَّةِ عَلَى الضَّعِيفِ وَالْكَبِيرِ وَالْمَرِيضِ قَالَ أَبُو عِيسَى وَأَبُو الزِّنَادِ اسْمُهُ عَبْدُ اللَّهِ بْنُ ذَكْوَانَ وَالْأَعْرَجُ هُوَ عَبْدُ الرَّحْمَنِ بْنُ هُرْمُزَ الْمَدِينِيُّ وَيُكْنَى أَبَا دَاوُدَ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Mughirah bin Abdurrahman] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian menjadi imam maka ringankanlah, karena di antara mereka ada anak kecil, orang tua, lemah dan orang sakit. Maka jika ia shalat sendirian hendaklah shalat sekehendaknya.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Adi bin Hatim, Anas, Jabir bin Samrah, Malik bin Abdullah, Abu Waqid, Utsman bin Abu Al 'Ash, Abu Mas'ud, Jabir bin Abdullah dan Ibnu Abbas.\" Hadits Abu Hurairah ini derajatnya hasan shahih. Ini adalah pendapat kebanyak ahli ilmu, mereka lebih memilih untuk tidak memanjangkan shalat khawatir memberatkan orang yang lemah, orang tua dan orang yang sakit.\" Abu Isa berkata; \"Abu Az Zinad namanya adalah Abdullah bin Dzakwan, sedangkan Al A'raj adalah Abdurrahman bin Hurmuz Al Madini, dan dijuluki juga dengan Abu Dawud.\""},"220":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَخَفِّ النَّاسِ صَلَاةً فِي تَمَامٍقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَاسْمُ أَبِي عَوَانَةَ وَضَّاحٌ قَالَ أَبُو عِيسَى سَأَلْتُ قُتَيْبَةَ قُلْتُ أَبُو عَوَانَةَ مَا اسْمُهُ قَالَ وَضَّاحٌ قُلْتُ ابْنُ مَنْ قَالَ لَا أَدْرِي كَانَ عَبْدًا لِامْرَأَةٍ بِالْبَصْرَةِ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abu Awanah] dari [Qatadah] dari [Anas bin Malik] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam adalah orang yang paling ringan shalatnya meskipun sempurna.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Abu Awanah namanya adalah Wadldlah.\" Abu Isa berkata; \"Aku pernah bertanya kepada Qutaibah; siapakah nama Abu Awanah?\" ia menjawab, \"Wadldlah.\" Aku bertanya lagi, \"Anak siapa?\" ia menjawab, \"Aku tidak tahu, di Bashrah ia adalah seorang budak milik seorang perempuan.\""},"221":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا مُحَمَّدُ بْنُ الْفُضَيْلِ عَنْ أَبِي سُفْيَانَ طَرِيفٍ السَّعْدِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِفْتَاحُ الصَّلَاةِ الطُّهُورُ وَتَحْرِيمُهَا التَّكْبِيرُ وَتَحْلِيلُهَا التَّسْلِيمُ وَلَا صَلَاةَ لِمَنْ لَمْ يَقْرَأْ بِالْحَمْدُ وَسُورَةٍ فِي فَرِيضَةٍ أَوْ غَيْرِهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَفِي الْبَاب عَنْ عَلِيٍّ وَعَائِشَةَ قَالَ وَحَدِيثُ عَلِيِّ بْنِ أَبِي طَالِبٍ فِي هَذَا أَجْوَدُ إِسْنَادًا وَأَصَحُّ مِنْ حَدِيثِ أَبِي سَعِيدٍ وَقَدْ كَتَبْنَاهُ فِي أَوَّلِ كِتَابِ الْوُضُوءِ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ إِنَّ تَحْرِيمَ الصَّلَاةِ التَّكْبِيرُ وَلَا يَكُونُ الرَّجُلُ دَاخِلًا فِي الصَّلَاةِ إِلَّا بِالتَّكْبِيرِ قَالَ أَبُو عِيسَى و سَمِعْت أَبَا بَكْرٍ مُحَمَّدَ بْنَ أَبَانَ مُسْتَمْلِيَ وَكِيعٍ يَقُولُ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ مَهْدِيٍّ يَقُولُ لَوْ افْتَتَحَ الرَّجُلُ الصَّلَاةَ بِسَبْعِينَ اسْمًا مِنْ أَسْمَاءِ اللَّهِ وَلَمْ يُكَبِّرْ لَمْ يُجْزِهِ وَإِنْ أَحْدَثَ قَبْلَ أَنْ يُسَلِّمَ أَمَرْتُهُ أَنْ يَتَوَضَّأَ ثُمَّ يَرْجِعَ إِلَى مَكَانِهِ فَيُسَلِّمَ إِنَّمَا الْأَمْرُ عَلَى وَجْهِهِ قَالَ وَأَبُو نَضْرَةَ اسْمُهُ الْمُنْذِرُ بْنُ مَالِكِ بْنِ قُطَعَةَ","id":"telah menceritakan kepada kami [Sufyan bin Waki'] berkata; telah menceritakan kepada kami [Muhammad bin Al Fudlail] dari [Abu Sufyan Tharif As Sa'di] dari [Abu Nadlrah] dari [Abu Sa'id] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pembuka shalat adalah bersuci, permulaannya adalah takbir, penutupnya adalah salam, dan tidaklah sah shalat orang yang tidak membaca Al Hamdulillah (Al Fatihah) dan surat (dari Al Qur'an) baik dalam shalat wajib maupun shalat-shalat yang lainnya.\" Abu Isa berkata; \"Hadits derajatnya ini hasan. Dalam bab ini ada juga hadits dari Ali dan 'Aisyah.\" Abu Isa berkata; \"Hadits Ali bin Abu Thalib dalam hal ini lebih baik sanadnya dan lebih shahih daripada hadits Abu Sa'id, dan kami telah menulisnya di awal kitab wudlu. Hadits ini diamalkan oleh ahli ilmu dari para sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka. Ini adalah pendapat Sufyan Ats Tsauri, bin Al Mubarak, Syafi'i, Ahmad dan Ishaq. Yaitu, bahwa permulaan shalat adalah takbir, dan seseorang beluam terhitung masuk dalam shalat kecuali dengan takbir.\" Abu Isa berkata; \"Aku mendengar Abu Bakar Muhammad bin Abban, penulis Waki', berkata; \"Aku mendengar Abdurrahman bin Mahdi berkata; \"Sekiranya seseorang membuka shalatnya dengan tujuh puluh nama Allah, namun ia tidak bertakbir, maka shalatnya tidak sah. Dan jika ia berhadats (batal dari suci) sebelum salam, maka aku akan memerintahkannya wudlu kemudian kembali ke tempatnya semula, setelah itu salam. Hanyasannya permasalahannya adalah di awalnya. Abu Isa berkata; \"Abu Nadlrah namanya adalah Al Mundzir bin Malik bin Qutha'ah.\""},"222":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَأَبُو سَعِيدٍ الْأَشَجُّ قَالَا حَدَّثَنَا يَحْيَى بْنُ الْيَمَانِ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ سَعِيدِ بْنِ سِمْعَانَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَبَّرَ لِلصَّلَاةِ نَشَرَ أَصَابِعَهُقَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَسَنٌ وَقَدْ رَوَى غَيْرُ وَاحِدٍ هَذَا الْحَدِيثَ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ سَعِيدِ بْنِ سِمْعَانَ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا دَخَلَ فِي الصَّلَاةِ رَفَعَ يَدَيْهِ مَدًّا وَهَذَا أَصَحُّ مِنْ رِوَايَةِ يَحْيَى بْنِ الْيَمَانِ وَأَخْطَأَ يَحْيَى بْنُ الْيَمَانِ فِي هَذَا الْحَدِيثِ","id":"telah menceritakan kepada kami [Qutaibah] dan [Abu Sa'id Al Asyaj] mereka berkata; telah menceritakan kepada kami [Yahya bin Al Yaman] dari [Ibnu Abu Dzi`b] dari [Sa'id bin Sam'an] dari [Abu Hurairah] ia berkata; \"Jika bertakbir untuk shalat Rasulullah shallallahu 'alaihi wasallam membentangkan jari-jarinya.\" Abu Isa berkata; \"Hadits Abu Hurairah derajatnya hasan. Hadits ini telah diriwayatkan dengan banyak jalur dari Ibnu Abu Dzi`b, dari Sa'id bin Sam'an, dari Abu Hurairah bahwa Nabi shallallahu 'alaihi wasallam jika masuk shalat (takbir), beliau membentangkan tangannya. Dan ini lebih shahih dari riwayat Yahya bin Al Yaman, namun Yahya bin Al Yaman salah dalam hadits ini.\""},"223":{"ar":"قَالَ و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ الْحَنَفِيُّ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدِ بْنِ سِمْعَانَ قَال سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ إِلَى الصَّلَاةِ رَفَعَ يَدَيْهِ مَدًّاقَالَ أَبُو عِيسَى قَالَ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ وَهَذَا أَصَحُّ مِنْ حَدِيثِ يَحْيَى بْنِ الْيَمَانِ وَحَدِيثُ يَحْيَى بْنِ الْيَمَانِ خَطَأٌ","id":"telah menceritakan kepada kami [Abdullah bin Abdurrahman] berkata; telah mengabarkan kepada kami [Ubaidullah bin Abdul Majid Al Hanafi] berkata; telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Sa'id bin Sam'an] ia berkata; aku mendengar [Abu Hurairah] berkata; \"Jika Rasulullah shallallahu 'alaihi wasallam berdiri shalat, beliau membentangkan tangannya.\" Abu Isa berkata; \"Abdullah bin Abdurrahman berkata; \"Hadits ini lebih shahih daripada hadits Yahya bin Al Yaman. Hadits Yahya bin Al Yaman salah.\""},"224":{"ar":"حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ وَنَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ قَالَا حَدَّثَنَا أَبُو قُتَيْبَةَ سَلْمُ بْنُ قُتَيْبَةَ عَنْ طُعْمَةَ بْنِ عَمْرٍو عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى لِلَّهِ أَرْبَعِينَ يَوْمًا فِي جَمَاعَةٍ يُدْرِكُ التَّكْبِيرَةَ الْأُولَى كُتِبَتْ لَهُ بَرَاءَتَانِ بَرَاءَةٌ مِنْ النَّارِ وَبَرَاءَةٌ مِنْ النِّفَاقِقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ أَنَسٍ مَوْقُوفًا وَلَا أَعْلَمُ أَحَدًا رَفَعَهُ إِلَّا مَا رَوَى سَلْمُ بْنُ قُتَيْبَةَ عَنْ طُعْمَةَ بْنِ عَمْرٍو عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ أَنَسٍ وَإِنَّمَا يُرْوَى هَذَا الْحَدِيثُ عَنْ حَبِيبِ بْنِ أَبِي حَبِيبٍ الْبَجَلِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَوْلَهُ حَدَّثَنَا بِذَلِكَ هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ خَالِدِ بْنِ طَهْمَانَ عَنْ حَبِيبِ بْنِ أَبِي حَبِيبٍ الْبَجَلِيِّ عَنْ أَنَسٍ نَحْوَهُ وَلَمْ يَرْفَعْهُ وَرَوَى إِسْمَعِيلُ بْنُ عَيَّاشٍ هَذَا الْحَدِيثَ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا وَهَذَا حَدِيثٌ غَيْرُ مَحْفُوظٍ وَهُوَ حَدِيثٌ مُرْسَلٌ وَعُمَارَةُ بْنُ غَزِيَّةَ لَمْ يُدْرِكْ أَنَسَ بْنَ مَالِكٍ قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ حَبِيبُ بْنُ أَبِي حَبِيبٍ يُكْنَى أَبَا الْكَشُوثَى وَيُقَالُ أَبُو عُمَيْرَةَ","id":"telah menceritakan kepada kami [Uqbah bin Mukram] dan [Nashr bin Ali Al Jahdlami] keduanya berkata; telah menceritakan kepada kami [Abu Qutaibah Salm bin Qutaibah] dari [Thu'mah bin 'Amru] dari [Habib bin Abu Tsabit] dari [Anas bin Malik] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa shalat berjama'ah selama empat puluh hari dengan mendapatkan takbir pertama ikhlas karena Allah, maka akan dicatat baginya terbebas dari dua hal; terbebas dari api neraka dan terbebas dari sifat munafik.\" Abu Isa berkata; \"Hadits ini diriwayatkan dari Anas dengan secara mauquf, dan saya tidak mengetahui seorangpun yang memarfu'kan hadits ini, kecuali hadits yang diriwayatkan Salm bin Qutaibah, dari Thu'mah bin 'Amru, dari Habib bin Abu Tsabit, dari Anas. Hanya saja hadits ini diriwayatkan dari Habib bin Abu Habib Al Bajali dari perkataan Anas bin Malik. Seperti itu pula [Hannad] menceritakan kepada kami dari [Waki'] dari [Khalid bin Thahman] dari [Habib bin Abu Habib Al Bajali] dari [Anas] sebagimana dalam hadits tersebut, namun ia tidak memarfu'kannya. Dan [Isma'il bin Ayyasy] telah meriwayatkan hadits ini dari [Umarah bin Ghaziyah] dari [Anas bin Malik] dari [Umar bin Al Khaththab] dari Nabi shallallahu 'alaihi wasallam yang semakna dengan hadits ini, namun hadits ini tidak mahfudz (tidak terjaga), hadits ini setatusnya mursal, karena Umarah bin Ghaziyah tidak bertemu dengan Anas bin Malik.\" Muhammad bin Isma'il berkata; \"Habib bin Abu Habib julukannya adalah Abu Al Kasyutsa, dan dinamakan juga dengan Abu Umairah.\""},"225":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى الْبَصْرِيُّ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ الضُّبَعِيُّ عَنْ عَلِيِّ بْنِ عَلِيٍّ الرِّفَاعِيِّ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ إِلَى الصَّلَاةِ بِاللَّيْلِ كَبَّرَ ثُمَّ يَقُولُ سُبْحَانَكَ اللَّهُمَّ وَبِحَمْدِكَ وَتَبَارَكَ اسْمُكَ وَتَعَالَى جَدُّكَ وَلَا إِلَهَ غَيْرُكَ ثُمَّ يَقُولُ اللَّهُ أَكْبَرُ كَبِيرًا ثُمَّ يَقُولُ أَعُوذُ بِاللَّهِ السَّمِيعِ الْعَلِيمِ مِنْ الشَّيْطَانِ الرَّجِيمِ مِنْ هَمْزِهِ وَنَفْخِهِ وَنَفْثِهِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَلِيٍّ وَعَائِشَةَ وَ��َبْدِ اللَّهِ بْنِ مَسْعُودٍ وَجَابِرٍ وَجُبَيْرِ بْنِ مُطْعِمٍ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى وَحَدِيثُ أَبِي سَعِيدٍ أَشْهَرُ حَدِيثٍ فِي هَذَا الْبَابِ وَقَدْ أَخَذَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ بِهَذَا الْحَدِيثِ وَأَمَّا أَكْثَرُ أَهْلِ الْعِلْمِ فَقَالُوا بِمَا رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقُولُ سُبْحَانَكَ اللَّهُمَّ وَبِحَمْدِكَ وَتَبَارَكَ اسْمُكَ وَتَعَالَى جَدُّكَ وَلَا إِلَهَ غَيْرُكَ وَهَكَذَا رُوِيَ عَنْ عُمَرَ بْنِ الْخَطَّابِ وَعَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ التَّابِعِينَ وَغَيْرِهِمْ وَقَدْ تُكُلِّمَ فِي إِسْنَادِ حَدِيثِ أَبِي سَعِيدٍ كَانَ يَحْيَى بْنُ سَعِيدٍ يَتَكَلَّمُ فِي عَلِيِّ بْنِ عَلِيٍّ الرِّفَاعِيِّ و قَالَ أَحْمَدُ لَا يَصِحُّ هَذَا الْحَدِيثُ","id":"telah menceritakan kepada kami [Muhammad bin Musa Al Bashari] berkata; telah menceritakan kepada kami [Ja'far bin Sulaiman Adl Dluba'i] dari [Ali bin Ali Ar Rifa'i] dari [Abu Al Mutawakkil] dari [Abu Sa'id Al Khudri] ia berkata; \"Jika Rasulullah shallallahu 'alaihi wasallam berdiri untuk shalat malam, beliau bertakbir dan membaca: \"SUBHAANAKA ALLAHUMMA WA BIHAMDIKA WA TABAARAKAS MUKA WA TA'ALA JADDUKA WA LAA ILAAHA ILLAA GHAIRUKA (Maha Suci Engkau Ya Allah, aku memuji-Mu, Maha Berkah akan nama-Mu, Maha Tinggi kekayaan dan kebesaran-Mu, tidak ada Tuhan yang berhak disembah selain Engkau), \" lalu membaca: \"ALLAHU AKBAR KABIIRA (Allah Maha Besar dengan sebesar-besarnya), \" lalu membaca: \"A'UUDZU BILLAHIS SAMI'IL AliIM MINASY SYAITHANIR RAJIIM MIN HAMZIHI WA NAFKHIHI WA NAFSIHI (Aku berlidung kepada Allah Yang Maha Mendengar lagi Maha Mengetahui dari setan yang terkutuk, dari godaan, tiupan dan bisikannya).\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Ali, 'Aisyah, Abdullah bin Mas'ud, Jabir, Jubair bin Muth'im dan Ibnu Umar.\" Abu Isa berkata; \"Dalam bab ini hadits Abu Sa'id adalah yang paling populer. Sebagian ahli ilmu mengamalkan hadits ini. Namun kebanyakan dari mereka berpendapat dengan hadits yang diriwayatkan dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau membaca: \"SUBHAANAKA ALLAHUMMA WA BIHAMDIKA WA TABAARAKAS MUKA WA TA'ALA JADDUKA WA LAA ILAAHA ILLAA GHAIRUKA (Maha Suci Engkau Ya Allah, aku memuji-mu, Maha Berkah akan nama-mu, Maha Tinggi kekayaan dan kebesaran-Mu, tidak ada Tuhan yang berhak disembah selain Engkau).\" Seperti ini pula riwayat dari Umar bin Al Khaththab dan Abdullah bin Mas'ud. Hadits ini banyak diamalkan oleh kebanyakan ahli ilmu dari kalangan tabi'in dan orang-orang setelah mereka. Sanad dalam hadits Abu Sa'id ini juga sempat diperbincangkan, dimana Yahya bin Sa'id memperbincangkan tentang Ali bin Ali Ar Rifa'i. Imam Ahmad mengatakan, \"Hadits ini tidak shahih.\""},"226":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَرَفَةَ وَيَحْيَى بْنُ مُوسَى قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ حَارِثَةَ بْنِ أَبِي الرِّجَالِ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا افْتَتَحَ الصَّلَاةَ قَالَ سُبْحَانَكَ اللَّهُمَّ وَبِحَمْدِكَ وَتَبَارَكَ اسْمُكَ وَتَعَالَى جَدُّكَ وَلَا إِلَهَ غَيْرُكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ عَائِشَةَ إِلَّا مِنْ هَذَا الْوَجْهِ وَحَارِثَةُ قَدْ تُكُلِّمَ فِيهِ مِنْ قِبَلِ حِفْظِهِ وَأَبُو الرِّجَالِ اسْمُهُ مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَدِينِيُّ","id":"telah menceritakan kepada kami [Al Hasan bin Arafah] dan [Yahya bin Musa] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Haritsah bin Abu Ar Rijal] dari ['Amrah] dari ['Aisyah] ia berkata; \"Apabila Nabi shallallahu 'alaihi wasallam membuka shalat beliau membaca: \"SUBHAANAKA ALLAHUMMA WA BIHAMDIKA WA TABAARAKAS MUKA WA TA'ALA JADDUKA WA LAA ILAAHA ILLAA GHAIRUKA (Maha Suci Engkau Ya Allah, aku memuji-Mu, Maha Berkah akan nama-Mu, Maha Tinggi kekayaan dan kebesaran-Mu, tidak ada Tuhan yang berhak disembah selain Engkau).\" Abu Isa berkata; \"Hadits ini tidak kami ketahui berasal dari hadits 'Aisyah selain dari jalur ini, sedangkan Haritsah telah perbincangkan dalam hal hafalannya. Adapun Abu Ar Rijal namanya adalah Muhammad bin Abdurrahman Al Madini.\""},"227":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا سَعِيدُ بْنُ إِيَاسٍ الْجُرَيْرِيُّ عَنْ قَيْسِ بْنِ عَبَايَةَ عَنْ ابْنِ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَسَمِعَنِي أَبِي وَأَنَا فِي الصَّلَاةِ أَقُولُ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ فَقَالَ لِي أَيْ بُنَيَّ مُحْدَثٌ إِيَّاكَ وَالْحَدَثَ قَالَ وَلَمْ أَرَ أَحَدًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ أَبْغَضَ إِلَيْهِ الْحَدَثُ فِي الْإِسْلَامِ يَعْنِي مِنْهُ قَالَ وَقَدْ صَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَ أَبِي بَكْرٍ وَمَعَ عُمَرَ وَمَعَ عُثْمَانَ فَلَمْ أَسْمَعْ أَحَدًا مِنْهُمْ يَقُولُهَا فَلَا تَقُلْهَا إِذَا أَنْتَ صَلَّيْتَ فَقُلْ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَقَالَ أَبُو عِيسَى حَدِيثُ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ حَدِيثٌ حَسَنٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ أَبُو بَكْرٍ وَعُمَرُ وَعُثْمَانُ وَعَلِيٌّ وَغَيْرُهُمْ وَمَنْ بَعْدَهُمْ مِنْ التَّابِعِينَ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَأَحْمَدُ وَإِسْحَقُ لَا يَرَوْنَ أَنْ يَجْهَرَ بِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ قَالُوا وَيَقُولُهَا فِي نَفْسِهِ","id":"telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] berkata; telah menceritakan kepada kami [Sa'id bin Iyas Al Jurairi] dari [Qais bin Abayah] dari [Ibnu Abdullah bin Mughaffal] ia berkata; [Ayahku] mendengarku ketika aku dalam shalat, ketika itu aku membaca, \"BISMILLAAHIIR RAHMAANIR RAHIIM (Dengan menyebut nama Allah Yang Maha Pengasih lagi Maha Pemurah), lalu ayahku berkata; \"Wahai anakku, engkau telah melakukan hal yang baru, jauhilah perkara baru!\" Ia (ayahku) berkata; \"Aku tidak pernah melihat seorang pun dari sahabat Rasulullah shallallahu 'alaihi wasallam membenci sesuatu selain perkara yang baru (diada-adakan) di dalam Islam.\" Ia berkata lagi, \"Aku pernah shalat bersama Nabi shallallahu 'alaihi wasallam, Abu Bakar, Umar dan Utsman, namun aku belum pernah melihat mereka mengucapkannya, maka janganlah engkau ucapkan itu. Jika engkau melaksanakan shalat maka bacalah, \"ALHAMDULILLAAHI RABBIL 'AALAMIIN (Segala puji bagi Allah, Rabb semesta alam).\" Abu Isa berkata; \"Hadits Abdullah bin Mughaffal ini derajatnya hasan shahih. Hadits ini diamalkan oleh kebanyakan ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka dari kalangan tabi'in. Pendapat ini juga dipegang oleh Sufyan Ats Tsauri, bin Al Mubarak, Ahmad dan Ishaq. Mereka berpendapat bahwa ucapan \"BISMILLAAHIIR RAHMAANIR RAHIIM (Dengan menyebut nama Allah Yang Maha Pengasih lagi Maha Pemurah) itu tidak dikeraskan. Mereka berkata; \"Hendaklah mereka mengucapkannya dalam hati.\""},"228":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي إِسْمَعِيلُ بْنُ حَمَّادٍ عَنْ أَبِي خَالِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْتَتِحُ صَلَاتَهُ بْ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَيْسَ إِسْنَادُهُ بِذَاكَ وَقَدْ قَالَ بِهَذَا عِدَّةٌ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ أَبُو هُرَيْرَةَ وَابْنُ عُمَرَ وَابْنُ عَبَّاسٍ وَابْنُ الزُّبَيْرِ وَمَنْ بَعْدَهُمْ مِنْ التَّابِعِينَ رَأَوْا الْجَهْرَ بْ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ وَبِهِ يَقُولُ الشَّافِعِيُّ وَإِسْمَعِيلُ بْنُ حَمَّادٍ هُوَ ابْنُ أَبِي سُلَيْمَانَ وَأَبُو خَالِدٍ يُقَالُ هُوَ أَبُو خَالِدٍ الْوَالِبِيُّ وَاسْمُهُ هُرْمُزُ وَهُوَ كُوفِيٌّ","id":"telah menceritakan kepada kami [Ahmad bin Abdah Adl Dlabi] berkata; telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] berkata; telah menceritakan kepadaku [Isma'il bin Hammad] dari [Abu Khalid] dari [Ibnu Abbas] ia berkata; \"Nabi shallallahu 'alaihi wasallam membuka shalatnya dengan membaca: \"BISMILLAAHIIR RAHMAANIR RAHIIM (Dengan menyebut nama Allah Yang Maha Pengasih lagi Maha Pemurah).\" Abu Isa berkata; \"Hadits ini sanadnya tidak kuat. Beberapa sahabat Nabi shallallahu 'alaihi wasallam berpendapat dengan hadits ini, di antara mereka adalah; Abu Hurairah, Ibnu Umar, Ibnu Abbas dan Ibnu Zubair. Juga, orang-orang setelah mereka dari kalangan tabi'in, mereka berpendapat dengan mengeraskan bacaan BISMILLAAHIIR RAHMAANIR RAHIIM. Ini adalah pendapat Syafi'i. Isma'il bin Hammad namnya adalah Ibnu Abu Sulaiman, sedangkan Abu Khalid disebut dengan Abu Khalid Al Walibi, dan namanya adalah Hurmuz. Dia adalah orang Kufah.\""},"229":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَعُمَرُ وَعُثْمَانُ يَفْتَتِحُونَ الْقِرَاءَةَ بِالْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ كَانُوا يَسْتَفْتِحُونَ الْقِرَاءَةَ بِالْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ قَالَ الشَّافِعِيُّ إِنَّمَا مَعْنَى هَذَا الْحَدِيثِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ وَعُثْمَانَ كَانُوا يَفْتَتِحُونَ الْقِرَاءَةَ بِالْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ مَعْنَاهُ أَنَّهُمْ كَانُوا يَبْدَءُونَ بِقِرَاءَةِ فَاتِحَةِ الْكِتَابَ قَبْلَ السُّورَةِ وَلَيْسَ مَعْنَاهُ أَنَّهُمْ كَانُوا لَا يَقْرَءُونَ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ وَكَانَ الشَّافِعِيُّ يَرَى أَنْ يُبْدَأَ بْ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ وَأَنْ يُجْهَرَ بِهَا إِذَا جُهِرَ بِالْقِرَاءَةِ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abu Awanah] dari [Qatadah] dari [Anas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam, Abu Bakar, Umar dan Utsman senantiasa membuka shalatnya dengan ALHAMDULILLAAHI RABBIL 'AALAMIIN (Segala puji bagi Allah, Rabb semesta alam).\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Para ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang setelah mereka mengamalkan hadits ini. Mereka membuka bacaan dengan ALHAMDULILLAAHI RABBIL 'AALAMIIN. Imam Syafi'i berkata; \"Hadits ini maknanya adalah, bahwa Nabi shallallahu 'alaihi wasallam, Abu Bakar, Umar dan Utsman membuka bacaan dengan ALHAMDULILLAAHI RABBIL 'AALAMIIN. Maksudnya, mereka memulai dengan membaca Al Fatihah sebelum membaca surat. Hal ini bukan berarti mereka tidak membaca BISMILLAAHIIR RAHMAANIR RAHIIM.\" Imam Syafi'i memandang bahwa hendaknya membuka dengan membaca BISMILLAAHIIRAHMAANIRRAHIIM dan mengeraskannya jika bacaan shalat dikeraskan.\""},"230":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنُ أَبِي عُمَرَ الْمَكِّيُّ أَبُو عَبْدِ اللَّهِ الْعَدَنِيُّ وَعَلِيُّ بْنُ حُجْرٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عُبَادَةَ بْنِ الصَّامِتِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا صَلَاةَ لِمَنْ لَمْ يَقْرَأْ بِفَاتِحَةِ الْكِتَابِقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَعَائِشَةَ وَأَنَسٍ وَأَبِي قَتَادَةَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى حَدِيثُ عُبَادَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ عُمَرُ بْنُ الْخَطَّابِ وَعَلِيُّ بْنُ أَبِي طَالِبٍ وَجَابِرُ بْنُ عَبْدِ اللَّهِ وَعِمْرَانُ بْنُ حُصَيْنٍ وَغَيْرُهُمْ قَالُوا لَا تُجْزِئُ صَلَاةٌ إِلَّا بِقِرَاءَةِ فَاتِحَةِ الْكِتَابِ و قَالَ عَلِيّ�� بْنُ أَبِي طَالِبٍ كُلُّ صَلَاةٍ لَمْ يُقْرَأْ فِيهَا بِفَاتِحَةِ الْكِتَابِ فَهِيَ خِدَاجٌ غَيْرُ تَمَامٍ وَبِهِ يَقُولُ ابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ سَمِعْت ابْنَ أَبِي عُمَرَ يَقُولُ اخْتَلَفْتُ إِلَى ابْنِ عُيَيْنَةَ ثَمَانِيَةَ عَشَرَ سَنَةً وَكَانَ الْحُمَيْدِيُّ أَكْبَرَ مِنِّي بِسَنَةٍ و سَمِعْت ابْنَ أَبِي عُمَرَ يَقُولُ حَجَجْتُ سَبْعِينَ حَجَّةً مَاشِيًا عَلَى قَدَمَيَّ","id":"telah menceritakan kepada kami [Muhammad bin Yahya bin Abu Umar Al Makki Abu Abdullah Al 'Adani] dan [Ali bin Hujr] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Mahmud Ibnu Ar Rabi'] dari [Ubadah bin Shamit] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada shalat bagi orang yang tidak membaca Al Fatihah.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Hurairah, 'Aisyah, Anas, Abu Qatadah dan Abdullah bin 'Amru.\" Abu Isa berkata; \"Hadits Ubadah bin Ash Shamit derajatnya hasan shahih. Hadits ini diamalkan oleh ulama dari kalangan sahabat Nabi shallallahu 'alaihi wasallam. Seperti Umar bin Al Khaththab, Imran bin Hushain dan selain mereka. Mereka berkata; \"Shalat tidak sah tanpa membaca Al fatihah.\" Ali bin Abi Thalib berkata; \"Setiap shalat yang tidak dibacakan di dalamnya Al Fatihah adalah kurang dan tidak sempurna.\" Pendapat ini dipegang oleh bin Al Mubarak, Syafi'i, Ahmad dan Ishaq. Aku mendengar Ibnu Abu Umar berkata; \"Aku berbeda dengan Ibnu Abu Umar delapan belas tahun, sedangkan Al Humaidi lebih tua satu tahun dari usiaku. Aku pernah mendengar Ibnu Abu Umar berkata; \"Aku melaksanakan haji sebanyak tujuh kali dengan berjalan kaki.\""},"231":{"ar":"حَدَّثَنَا بُنْدَارٌ مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ حُجْرِ بْنِ عَنْبَسٍ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ{ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }فَقَالَ آمِينَ وَمَدَّ بِهَا صَوْتَهُقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى حَدِيثُ وَائِلِ بْنِ حُجْرٍ حَدِيثٌ حَسَنٌ وَبِهِ يَقُولُ غَيْرُ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ يَرَوْنَ أَنَّ الرَّجُلَ يَرْفَعُ صَوْتَهُ بِالتَّأْمِينِ وَلَا يُخْفِيهَا وَبِهِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ وَرَوَى شُعْبَةُ هَذَا الْحَدِيثَ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ حُجْرٍ أَبِي الْعَنْبَسِ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ أَبِيهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ{ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }فَقَالَ آمِينَ وَخَفَضَ بِهَا صَوْتَهُ قَالَ أَبُو عِيسَى و سَمِعْت مُحَمَّدًا يَقُولُ حَدِيثُ سُفْيَانَ أَصَحُّ مِنْ حَدِيثِ شُعْبَةَ فِي هَذَا وَأَخْطَأَ شُعْبَةُ فِي مَوَاضِعَ مِنْ هَذَا الْحَدِيثِ فَقَالَ عَنْ حُجْرٍ أَبِي الْعَنْبَسِ وَإِنَّمَا هُوَ حُجْرُ بْنُ عَنْبَسٍ وَيُكْنَى أَبَا السَّكَنِ وَزَادَ فِيهِ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ وَلَيْسَ فِيهِ عَنْ عَلْقَمَةَ وَإِنَّمَا هُوَ عَنْ حُجْرِ بْنِ عَنْبَسٍ عَنْ وَائِلِ بْنِ حُجْرٍ وَقَالَ وَخَفَضَ بِهَا صَوْتَهُ وَإِنَّمَا هُوَ وَمَدَّ بِهَا صَوْتَهُ قَالَ أَبُو عِيسَى وَسَأَلْتُ أَبَا زُرْعَةَ عَنْ هَذَا الْحَدِيثِ فَقَالَ حَدِيثُ سُفْيَانَ فِي هَذَا أَصَحُّ مِنْ حَدِيثِ شُعْبَةَ قَالَ وَرَوَى الْعَلَاءُ بْنُ صَالِحٍ الْأَسَدِيُّ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ نَحْوَ رِوَايَةِ سُفْيَانَ قَالَ أَبُو عِيسَى حَدَّثَنَا أَبُو بَكْرٍ مُحَمَّدُ بْنُ أَبَانَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا الْعَلَاءُ بْنُ صَالِحٍ الْأَسَدِيُّ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ حُجْرِ بْنِ عَنْبَسٍ عَنْ وَائِلِ بْنِ حُجْرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ حَدِيثِ سُفْيَانَ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ","id":"telah menceritakan kepada kami [Bundar Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dan [Abdurrahman bin Mahdi] keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Salamah bin Kuhail] dari [Hujr bin Anbasah] dari [Wa`il bin Hujr] ia berkata; \"Aku mendengar Nabi shallallahu 'alaihi wasallam membaca: \"GHAIRIL MAGHDLUUBI 'ALAIHIM WA LADLAALLIIN (bukan (jalan) mereka yang dimurkai dan bukan (pula jalan) mereka yang sesat), beliau lalu mengucapkan: \"AAMIIN (semoga Allah mengAbu Alkan), \" dengan memanjangkan suaranya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ali dan Abu Hurairah.\" Abu Isa berkata; \"Hadits Wa`il bin Hujr ini derajatnya hasan. Pendapat ini banyak diambil oleh ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang setelah mereka. Mereka berpendapat bahwa seseorang hendaknya mengeraskan suara AMIN dan tidak menyuarakannya dengan pelan. Pendapat ini juga diambil oleh Imam Syafi'i, Ahmad dan Ishaq. [Syu'bah] juga meriwayatkan hadits ini dari [Salamah bin Kuhail] dari [Hujr Abu Al 'Anbasah] dari [Alqamah bin Wa`il] dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam membaca: GHAIRIL MAGHDLUUBI 'ALAIHIM WA LADLAALLIIN (bukan (jalan) mereka yang dimurkai dan bukan (pula jalan) mereka yang sesat), lalu beliau mengucapkan: \"AAMIIN (semoga Allah mengAbu Alkan), dan beliau menyuarakannya dengan pelan.\" Abu Isa berkata; \"Aku mendengar Muhammad berkata; \"Dalam hal ini hadits Sufyan lebih shahih daripada hadits Syu'bah. Syu'bah telah melakukan beberapa kesalahan kaitannya dengan hadits ini. Ia mengatakan, \"Dari Hujr Abu Al 'Anbasah, padahal yang dimaksud adalah Hujr bin 'Anbas, julukannya Abu As Sakan. Di dalamnya ia menambahkan; dari Alqamah bin Wa`il, padahal di dalamnya tidak ada Alqamah. Hanyasanya dari Hujr bin 'Anbasah, dari Wa`il bin Hujr. Dan ia mengatakan, \"Lalu beliau menyuarakannya dengan pelan, \" padahal yang benar, \"Beliau mengeraskan suaranya.\" Abu Isa berkata; \"Aku pernah bertanya kepada Abu Zur'ah tentang hadits ini, ia lalu menjawab, \"Hadits Sufyan dalam hal ini lebih shahih ketimbang hadits Syu'bah.\" Ia berkata; \"Al 'Ala bin Shalih Al Asadi meriwayatkan dari Salamah bin Kuhail sebagaimana riwayat Sufyan.\" Abu Isa berkata; \"Telah menceritakan kepada kami [Abu Bakar Muhammad bin Aban] berkata; telah menceritakan kepada kami [Abdullah bin Numair] berkata; telah menceritakan kepada kami [Al 'Ala bin Shalih Al Asadi] dari [Salamah bin Kuhail] dari [Hujr bin 'Anbas] dari [Wa`il bin Hujr] dari Nabi shallallahu 'alaihi wasallam, sebagaimana hadits Sufyan dari Salamah bin Kuhail.\""},"232":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا زَيْدُ بْنُ حُبَابٍ حَدَّثَنِي مَالِكُ بْنُ أَنَسٍ حَدَّثَنَا الزُّهْرِيُّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَمَّنَ الْإِمَامُ فَأَمِّنُوا فَإِنَّهُ مَنْ وَافَقَ تَأْمِينُهُ تَأْمِينَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِقَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al 'Ala`] berkata; telah menceritakan kepada kami [Zaid bin Hubab] berkata; telah menceritakan kepadaku [Malik bin Anas] berkata; telah menceritakan kepada kami [Az Zuhri] dari [Sa'id bin Al Musayyib] dan [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika imam mengucapkan AAMIIN maka ucapkanlah AAMIIN, sebab barangsiapa ucapan AAMIIN nya sama dengan AAMIIN nya malaikat, dosa-dosanya yang telah lalu akan diampuni.\" Abu Isa berkata; \"Hadits Abu Hurairah ini derajatnya hasan shahih.\""},"233":{"ar":"حَدَّثَنَا أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ قَالَسَكْتَتَانِ حَفِظْتُهُمَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْكَرَ ذَلِكَ عِمْرَانُ بْنُ حُصَيْنٍ وَقَالَ حَفِظْنَا سَكْتَةً فَكَتَبْنَا إِلَى أُبَيِّ بْنِ كَعْبٍ بِالْمَدِينَةِ فَكَتَبَ أُبَيٌّ أَنْ حَفِظَ سَمُرَةُ قَالَ سَعِيدٌ فَقُلْنَا لِقَتَادَةَ مَا هَاتَانِ السَّكْتَتَانِ قَالَ إِذَا دَخَلَ فِي صَلَاتِهِ وَإِذَا فَرَغَ مِنْ الْقِرَاءَةِ ثُمَّ قَالَ بَعْدَ ذَلِكَ وَإِذَا قَرَأَ{ وَلَا الضَّالِّينَ }قَالَ وَكَانَ يُعْجِبُهُ إِذَا فَرَغَ مِنْ الْقِرَاءَةِ أَنْ يَسْكُتَ حَتَّى يَتَرَادَّ إِلَيْهِ نَفَسُهُقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى حَدِيثُ سَمُرَةَ حَدِيثٌ حَسَنٌ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ يَسْتَحِبُّونَ لِلْإِمَامِ أَنْ يَسْكُتَ بَعْدَمَا يَفْتَتِحُ الصَّلَاةَ وَبَعْدَ الْفَرَاغِ مِنْ الْقِرَاءَةِ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ وَأَصْحَابُنَا","id":"telah menceritakan kepada kami [Abu Musa Muhammad bin Al Mutsanna] berkata; telah menceritakan kepada kami [Abdul A'la] dari [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Samrah] ia berkata; \"Ada dua saktah (jeda dengan tidak membaca bacaan) yang aku hafal dari Rasulullah shallallahu 'alaihi wasallam, \" namun hal itu diingkari oleh Imran bin Hushain, lalu ia berkata; \"Kami menghafal hanya ada satu saktah.\" Maka kami pun menulis surat kepada [Ubai bin Ka'ab] di Madinah, lalu Ubai menulis balasan sebagaimana yang dihafal oleh Samrah.\" Sa'id berkata; \"Kami bertanya Qatadah, \"Dua saktah itu letaknya di mana saja?\" ia menjawab, \"Jika ia telah masuk shalat dan ketika selesai dari membaca bacaan (Al Fatihah).\" Setelah itu ia berkata lagi, \"Jika membaca WALADLDLAALLIIN.\" Ia berkata; \"Yang menjadikannya ta'ajub adalah diam setelah membaca bacaan (Al Fatihah), hingga hatinya merasa ragu.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Hurairah.\" Abu Isa berkata; \"Hadits Samrah ini derajatnya hasan. Ini adalah pendapat yang diambil tidak hanya oleh satu orang saja dari kalangan ahli ilmu. Mereka menyukai seorang imam diam sejenak setelah membaca do'a iftitah (pembuka) shalat dan setelah selesai dari membaca (Al fatihah).\" Pendapat ini juga diambil oleh Ahmad, Ishaq dan sahabat-sahabat kami.\""},"234":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ قَبِيصَةَ بْنِ هُلْبٍ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَؤُمُّنَا فَيَأْخُذُ شِمَالَهُ بِيَمِينِهِقَالَ وَفِي الْبَاب عَنْ وَائِلِ بْنِ حُجْرٍ وَغُطَيْفِ بْنِ الْحَارِثِ وَابْنِ عَبَّاسٍ وَابْنِ مَسْعُودٍ وَسَهْلِ بْنِ سَعْدٍ قَالَ أَبُو عِيسَى حَدِيثُ هُلْبٍ حَدِيثٌ حَسَنٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ يَرَوْنَ أَنْ يَضَعَ الرَّجُلُ يَمِينَهُ عَلَى شِمَالِهِ فِي الصَّلَاةِ وَرَأَى بَعْضُهُمْ أَنْ يَضَعَهُمَا فَوْقَ السُّرَّةِ وَرَأَى بَعْضُهُمْ أَنْ يَضَعَهُمَا تَحْتَ السُّرَّةِ وَكُلُّ ذَلِكَ وَاسِعٌ عِنْدَهُمْ وَاسْمُ هُلْبٍ يَزِيدُ بْنُ قُنَافَةَ الطَّائِيُّ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak bin Harb] dari [Qabishah bin Hulb] dari [Ayahnya] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengimami kami, lalu beliau memegang tangan kirinya dengan tangan kanannya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Wa`il bin Hujr, Ghuthaif bin Al Harits, Ibnu Abbas, Ibnu Mas'ud dan Sahl bin Sa'd.\" Abu Isa berkata; \"Hadits Hulb derajatnya hasan. Hadits ini diamalkan oleh para ahli ilmu dari sahabat Nabi shallallahu 'alaihi wasallam tabi'in dan orang-orang setelah mereka. Mereka berpendapat hendaklah dalam shalat seseorang meletakkan tangan kanannya di atas tangan kirinya. Sebagian ulama berpendapat, hendaknya kedua tangan tersebut diletakkan di atas pusar. Dan sebagian lain berpendapat, hendaknya keduanya diletakkan di bawah pusar. Menurut mereka, semua pendapat tersebut sangat fleksibel. Adapun nama Hulb adalah Yazid bin Qunafah Ath Tha`i.\""},"235":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ عَلْقَمَةَ وَالْأَسْوَدِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَبِّرُ فِي كُلِّ خَفْضٍ وَرَفْعٍ وَقِيَامٍ وَقُعُودٍ وَأَبُو بَكْرٍ وَعُمَرُقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَنَسٍ وَابْنِ عُمَرَ وَأَبِي مَالِكٍ الْأَشْعَرِيِّ وَأَبِي مُوسَى وَعِمْرَانَ بْنِ حُصَيْنٍ وَوَائِلِ بْنِ حُجْرٍ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى حَدِيثُ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ أَبُو بَكْرٍ وَعُمَرُ وَعُثْمَانُ وَعَلِيٌّ وَغَيْرُهُمْ وَمَنْ بَعْدَهُمْ مِنْ التَّابِعِينَ وَعَلَيْهِ عَامَّةُ الْفُقَهَاءِ وَالْعُلَمَاءِ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Abdurrahman bin Al Aswad] dari [Alqamah], dan [Al Aswad] dari [Abdullah bin Mas'ud] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam, Abu Bakar dan Umar bertakbir pada setiap turun dan bangkit, pada setiap berdiri dan duduk.\" Ia berkata; \"Dalam bab ini ada juga hadits dari Abu Hurairah, Anas, Ibnu Umar, Abu Malik Al Asy'ari, Abu Musa, Imran bin Hushain, Wa`il bin Hujr dan Ibnu Abbas.\" Abu Isa berkata; \"Hadits Abdullah bin Mas'ud ini derajatnya hasan shahih. Hadits ini diamalkan oleh para sahabat Nabi shallallahu 'alaihi wasallam, di antaranya adalah Abu Bakar, Umar, Utsman, Ali dan yang lainnya. Serta orang-orang setelah mereka dari kalangan tabi'in. Ini adalah pendapat kebanyakan fuqaha dan ulama.\""},"236":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُنِيرٍ الْمَرْوَزِيُّ قَال سَمِعْتُ عَلِيَّ بْنَ الْحَسَنِ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ ابْنِ جُرَيْجٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُكَبِّرُ وَهُوَ يَهْوِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ مِنْ التَّابِعِينَ قَالُوا يُكَبِّرُ الرَّجُلُ وَهُوَ يَهْوِي لِلرُّكُوعِ وَالسُّجُودِ","id":"telah menceritakan kepada kami [Abdullah bin Munir Al Marwazi] berkata; aku mendengar [Ali bin Al Hasan] berkata; telah mengabarkan kepada kami [Abdullah bin Al Mubarak] dari [Ibnu Juraij] dari [Az Zuhri] dari [Abu Bakr bin Abdurrahman] dari [Abu Hurairah] berkata; \"Nabi shallallahu 'alaihi wasallam bertakbir ketika sedang turun (sujud).\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. ini adalah pendapat ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka dari kalangan tabi'in. Mereka berkata; \"Seorang laki-laki hendaknya bertakbir ketika rukuk dan sujud.\""},"237":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَابْنُ أَبِي عُمَرَ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا افْتَتَحَ الصَّلَاةَ يَرْفَعُ يَدَيْهِ حَتَّى يُحَاذِيَ مَنْكِبَيْهِ وَإِذَا رَكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِوَزَادَ ابْنُ أَبِي عُمَرَ فِي حَدِيثِهِ وَكَانَ لَا يَرْفَعُ بَيْنَ السَّجْدَتَيْنِ قَالَ أَبُو عِيسَى حَدَّثَنَا الْفَضْلُ بْنُ الصَّبَّاحِ الْبَغْدَادِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا الزُّهْرِيُّ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ ابْنِ أَبِي عُمَرَ قَالَ وَفِي الْبَاب عَنْ عُمَرَ وَعَلِيٍّ وَوَائِلِ بْنِ حُجْرٍ وَمَالِكِ بْنِ الْحُوَيْرِثِ وَأَنَسٍ وَأَبِي هُرَيْرَةَ وَأَبِي حُمَيْدٍ وَأَبِي أُسَيْدٍ وَسَهْلِ بْنِ سَعْدٍ وَمُحَمَّدِ بْنِ مَسْلَمَةَ وَأَبِي قَتَادَةَ وَأَبِي مُوسَى الْأَشْعَرِيِّ وَجَابِرٍ وَعُمَيْرٍ اللَّيْثِيِّ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَبِهَذَا يَقُولُ بَعْضُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ ابْنُ عُمَرَ وَجَابِرُ بْنُ عَبْدِ اللَّهِ وَأَبُو هُرَيْرَةَ وَأَنَسٌ وَابْنُ عَبَّاسٍ وَعَبْدُ اللَّهِ بْنُ الزُّبَيْرِ وَغَيْرُهُمْ وَمِنْ التَّابِعِينَ الْحَسَنُ الْبَصْرِيُّ وَعَطَاءٌ وَطَاوُسٌ وَمُجَاهِدٌ وَنَافِعٌ وَسَالِمُ بْنُ عَبْدِ اللَّهِ وَسَعِيدُ بْنُ جُبَيْرٍ وَغَيْرُهُمْ وَبِهِ يَقُولُ مَالِكٌ وَمَعْمَرٌ وَالْأَوْزَاعِيُّ وَابْنُ عُيَيْنَةَ وَعَبْدُ اللَّهِ بْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ و قَالَ عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ قَدْ ثَبَتَ حَدِيثُ مَنْ يَرْفَعُ يَدَيْهِ وَذَكَرَ حَدِيثَ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ وَلَمْ يَثْبُتْ حَدِيثُ ابْنِ مَسْعُودٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَرْفَعْ يَدَيْهِ إِلَّا فِي أَوَّلِ مَرَّةٍ حَدَّثَنَا بِذَلِكَ أَحْمَدُ بْنُ عَبْدَةَ الْآمُلِيُّ حَدَّثَنَا وَهْبُ بْنُ زَمْعَةَ عَنْ سُفْيَانَ بْنِ عَبْدِ الْمَلِكِ عَنْ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ و حَدَّثَنَا يَحْيَى بْنُ مُوسَى قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي أُوَيْسٍ قَالَ كَانَ مَالِكُ بْنُ أَنَسٍ يَرَى رَفْعَ الْيَدَيْنِ فِي الصَّلَاةِ و قَالَ يَحْيَى وَحَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ كَانَ مَعْمَرٌ يَرَى رَفْعَ الْيَدَيْنِ فِي الصَّلَاةِ و سَمِعْت الْجَارُودَ بْنَ مُعَاذٍ يَقُولُ كَانَ سُفْيَانُ بْنُ عُيَيْنَةَ وَعُمَرُ بْنُ هَارُونَ وَالنَّضْرُ بْنُ شُمَيْلٍ يَرْفَعُونَ أَيْدِيَهُمْ إِذَا افْتَتَحُوا الصَّلَاةَ وَإِذَا رَكَعُوا وَإِذَا رَفَعُوا رُءُوسَهُمْ","id":"telah menceritakan kepada kami [Qutaibah] dan [Ibnu Abu Umar] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Salim] dari [Ayahnya] ia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam ketika membuka shalat mengangkat kedua tangannya hingga sejajar dengan kedua pundaknya. Beliau juga mengangkat tangan ketika rukuk dan mengangkat kepalanya dari rukuk.\" Ibnu Umar menambahkan dalam haditsnya, \"Beliau tidak mengangkat kedua tangannya antara dua sujud.\" Abu Isa berkata; \"Telah menceritakan kepada kami [Al Fadll bin Ash Shabbah Al Baghdadi] berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] berkata; telah menceritakan kepada kami [Az Zuhri] sebagimana hadits Ibnu Abu Umar dengan sanad ini.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Umar, Ali, Wa`il bin Juhr, Malik bin Al Huwairits, Anas, Abu Hurairah, Abu Humaid, Abu Usaid, Sahl bin Sa'd, Muhammad bin Maslamah, Abu Qatadah, Abu Musa Al Asy'ari, Jabir dan Umair Al Laitsi.\" Abu Isa berkata; \"Hadits Ibnu Umar ini derajatnya hasan shahih. Pendapat ini dipegang oleh para ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam. Seperti Ibnu Umar, Jabir bin Abdullah, Abu Hurairah, Anas, Ibnu Abbas dan Abdullah Ibnu Az Zubair. Juga oleh selain mereka dari kalangan tabi'in seperti Al Hasan Al Bashri, 'Atha`, Thawus, Mujahid, Nafi', Salim bin Abdullah, Sa'id bin Jubair dan selain mereka. Pendapat ini juga diambil oleh Malik, Mu'tamar, Al Auza'I, Ibnu Uyainah, Abdullah bin Al Mubarak, Syafi'i, Ahmad dan Ishaq.\" Abdullah bin Al Mubarak berkata; \"Hadits tentang diangkatnya kedua tangan tetap (diakui). Lalu ia menyebutkan hadits Az Zuhri, dari Salim, dari ayahnya. Dan Ibnu Mas'ud bahwa Nabi shallallahu 'alaihi wasallam tidak mengangkat kepalanya kecuali di takbir pertama (takbiratul ikram) adalah tidak sah. Hal itu telah diceritakan kepada kami oleh Ahmad bin Abdah Al Amuli, ia berkata; telah menceritakan kepada kami Wahb bin Zam'ah, dari Sufyan bin Abdul Malik, dari Abdullah bin Al Mubarak.\" Ia berkata; \"Dan telah menceritakan kepada kami Yahya bin Musa, ia berkata; telah menceritakan kepada kami Isma'il bin Abu Uwais, ia berkata; \"Malik bin Anas berpandangan (diperintahkannya) mengangkat kedua tangan di dalam shalat.\" Yahya berkata; \"Abdurrazaq meriwayatkan kepada kami bahwa Ma'mar berpendapat (diperintahkannya) mengangkat tangan shalat.\" Dan aku mendengar Al Jarud bin Mu'adz berkata; \"Sufyan bin Uyainah, Umar bin Harun, An Nadlr bin Syumail, mereka mengangkat kedua tangannya ketika membuka shalat (takbiratul ihram), rukuk dan ketika mengangkat kepalanya.\""},"238":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ عَلْقَمَةَ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍأَلَا أُصَلِّي بِكُمْ صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى فَلَمْ يَرْفَعْ يَدَيْهِ إِلَّا فِي أَوَّلِ مَرَّةٍقَالَ وَفِي الْبَاب عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ مَسْعُودٍ حَدِيثٌ حَسَنٌ وَبِهِ يَقُولُ غَيْرُ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَأَهْلِ الْكُوفَةِ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari ['Ashim bin Kulaib] dari [Abdurrahman bin Al Aswad] dari [Alqamah] ia berkata; \" [Abdullah bin Mas'ud] berkata; \"Mahukah bila aku shalat bersama kalian dengan cara shalatnya Rasulullah shallallahu 'alaihi wasallam?\" lalu ia pun melaksanakan shalat dan tidak mengangkat kedua tangannya kecuali di pertama kali.\" Ia berkata; \"Dalam bab ini ada juga hadits dari Al Barra` bin 'Azib.\" Abu Isa berkata; \"Hadits Ibnu Mas'ud derajatnya hasan. Pendapat ini diamalkan tidak hanya seorang ulama dari para sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in. Ini adalah pendapat Sufyan Ats Tsauri dan penduduk Kufah.\""},"239":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ حَدَّثَنَا أَبُو حَصِينٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ قَالَقَالَ لَنَا عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ إِنَّ الرُّكَبَ سُنَّتْ لَكُمْ فَخُذُوا بِالرُّكَبِقَالَ وَفِي الْبَاب عَنْ سَعْدٍ وَأَنَسٍ وَأَبِي حُمَيْدٍ وَأَبِي أُسَيْدٍ وَسَهْلِ بْنِ سَعْدٍ وَمُحَمَّدِ بْنِ مَسْلَمَةَ وَأَبِي مَسْعُودٍ قَالَ أَبُو عِيسَى حَدِيثُ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ لَا اخْتِلَافَ بَيْنَهُمْ فِي ذَلِكَ إِلَّا مَا رُوِيَ عَنْ ابْنِ مَسْعُودٍ وَبَعْضِ أَصْحَابِهِ أَنَّهُمْ كَانُوا يُطَبِّقُونَ وَالتَّطْبِيقُ مَنْسُوخٌ عِنْدَ أَهْلِ الْعِلْمِ","id":"telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Abu Bakr bin Ayyasy] berkata; telah menceritakan kepada kami [Abu Hashin] dari [Abu Abdurrahman As Sulami] ia berkata; \" [Umar bin Al Kaththab] Radliaallahu 'anhu berkata kepada kami, \"Sesungguhnya lutut-lutut itu disunahkan untuk kalian pegang, maka peganglah.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Sa'd, Anas, Abu Humaid, Abu Usaid, Sahl bin Sa'd, Muhammad bin Maslamah dan Abu Mas'ud.\" Abu Isa berkata; \"Hadits Umar ini derajatnya hasan shahih. Hadits ini diamalkan oleh ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang setelah mereka. Mereka tidak berselisih tentang hal itu kecuali hadits yang diriwayatkan oleh Ibnu Mas'ud dan sebagian sahabatnya. Bahwasanya mereka merapatkannya. Dan menurut ahli ilmu merapatkan sudah dimansukh (dihapus).\""},"240":{"ar":"قَالَ سَعْدُ بْنُ أَبِي وَقَّاصٍكُنَّا نَفْعَلُ ذَلِكَ فَنُهِينَا عَنْهُ وَأُمِرْنَا أَنْ نَضَعَ الْأَكُفَّ عَلَى الرُّكَبِقَالَ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي يَعْفُورٍ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ أَبِيهِ سَعْدٍ بِهَذَا وَأَبُو حُمَيْدٍ السَّاعِدِيُّ اسْمُهُ عَبْدُ الرَّحْمَنِ بْنُ سَعْدِ بْنِ الْمُنْذِرِ وَأَبُو أُسَيْدٍ السَّاعِدِيُّ اسْمُهُ مَالِكُ بْنُ رَبِيعَةَ وَأَبُو حَصِينٍ اسْمُهُ عُثْمَانُ بْنُ عَاصِمٍ الْأَسَدِيُّ وَأَبُو عَبْدِ الرَّحْمَنِ السُّلَمِيُّ اسْمُهُ عَبْدُ اللَّهِ بْنُ حَبِيبٍ وَأَبُو يَعْفُورٍ عَبْدُ الرَّحْمَنِ بْنُ عُبَيْدِ بْنِ نِسْطَاسٍ وَأَبُو يَعْفُورٍ الْعَبْدِيُّ اسْمُهُ وَاقِدٌ وَيُقَالُ وَقْدَانُ وَهُوَ الَّذِي رَوَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى وَكِلَاهُمَا مِنْ أَهْلِ الْكُوفَةِ","id":"Sa'ad bin Abu Waqash berkata; \"Kami biasa melakukan hal itu lalu kami dilarang, dan kami diperintahkan untuk meletakkan telapak tangan pada lutut.\" Ia berkata; \"Telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abu Awanah] dari [Abu Ya'fur] dari [Mush'ab bin Sa'd] dari ayahnya [Sa'd] seperti ini. Dan Abu Humaid As Sa'idi namanya adalah Abdurrahman bin Sa'd bin Al Mundzir. Abu Usaid As Sa'idi namanya adalah Malik bin Rabi'ah. Abdullah bin Habib, Abu Ya'fur Abdurrahman bin Ubaid bin Nisthas. Abu Ya'fur Al 'Abdi namanya Waqid, dan disebut juga dengan Waqdan, dan dialah yang meriwayatkan dari Abdullah bin Abu Aufa, keduanya dari penduduk Kufah.\""},"241":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ بُنْدَارٌ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ حَدَّثَنَا عَبَّاسُ بْنُ سَهْلِ بْنِ سَعْدٍ قَالَاجْتَمَعَ أَبُو حُمَيْدٍ وَأَبُو أُسَيْدٍ وَسَهْلُ بْنُ سَعْدٍ وَمُحَمَّدُ بْنُ مَسْلَمَةَ فَذَكَرُوا صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو حُمَيْدٍ أَنَا أَعْلَمُكُمْ بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكَعَ فَوَضَعَ يَدَيْهِ عَلَى رُكْبَتَيْهِ كَأَنَّهُ قَابِضٌ عَلَيْهِمَا وَوَتَّرَ يَدَيْهِ فَنَحَّاهُمَا عَنْ جَنْبَيْهِقَالَ وَفِي الْبَاب عَنْ أَنَسٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي حُمَيْدٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ الَّذِي اخْتَارَهُ أَهْلُ الْعِلْمِ أَنْ يُجَافِيَ الرَّجُلُ يَدَيْهِ عَنْ جَنْبَيْهِ فِي الرُّكُوعِ وَالسُّجُودِ","id":"telah menceritakan kepada kami [Muhammad bin Basysyar Bundar] berkata; telah menceritakan kepada kami [Abu 'Amir Al 'Aqdi] berkata; telah menceritakan kepada kami [Fulaih bin Sulaiman] berkata; telah menceritakan kepada kami [Abbas bin Sahl bin Sa'd] ia berkata; \"Abu Humaid, Abu Usaid, Sahl bin Sa'd dan Muhammad bin Maslamah berkumpul seraya menyebutkan tentang (sifat) shalat Rasulullah shallallahu 'alaihi wasallam.\" [Abu Humaid] berkata; \"Aku adalah orang yang paling tahu dengan shalat Rasulullah shallallahu 'alaihi wasallam dari kalian semua. Rasulullah shallallahu 'alaihi wasallam rukuk, lalu beliau meletakkan kedua tangannya pada lutut seakan-akan beliau menggenggam kedua lututnya. Beliau menggerakkan kedua tangannya seraya merenggangkan kedua tangannya dari lambungnya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Anas.\" Abu Isa berkata; \"Hadits Abu Humaid derajatnya hasan shahih. Inilah yang dipilih oleh para ahli ilmu, yakni hendaklah ia meletakkan kedua tangannya dari lambung ketika rukuk dan sujud.\""},"242":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ إِسْحَقَ بْنِ يَزِيدَ الْهُذَلِيِّ عَنْ عَوْنِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ مَسْعُودٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَكَعَ أَحَدُكُمْ فَقَالَ فِي رُكُوعِهِ سُبْحَانَ رَبِّيَ الْعَظِيمِ ثَلَاثَ مَرَّاتٍ فَقَدْ تَمَّ رُكُوعُهُ وَذَلِكَ أَدْنَاهُ وَإِذَا سَجَدَ فَقَالَ فِي سُجُودِهِ سُبْحَانَ رَبِّيَ الْأَعْلَى ثَلَاثَ مَرَّاتٍ فَقَدْ تَمَّ سُجُودُهُ وَذَلِكَ أَدْنَاهُقَالَ وَفِي الْبَاب عَنْ حُذَيْفَةَ وَعُقْبَةَ بْنِ عَامِرٍ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ مَسْعُودٍ لَيْسَ إِسْنَادُهُ بِمُتَّصِلٍ عَوْنُ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ لَمْ يَلْقَ ابْنَ مَسْعُودٍ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ يَسْتَحِبُّونَ أَنْ لَا يَنْقُصَ الرَّجُلُ فِي الرُّكُوعِ وَالسُّجُودِ مِنْ ثَلَاثِ تَسْبِيحَاتٍ وَرُوِيَ عَنْ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ أَنَّهُ قَالَ أَسْتَحِبُّ لِلْإِمَامِ أَنْ يُسَبِّحَ خَمْسَ تَسْبِيحَاتٍ لِكَيْ يُدْرِكَ مَنْ خَلْفَهُ ثَلَاثَ تَسْبِيحَاتٍ وَهَكَذَا قَالَ إِسْحَقُ بْنُ إِبْرَاهِيمَ","id":"telah menceritakan kepada kami [Ali bin Hujr] berkata; telah mengabarkan kepada kami [Isa bin Yunus] dari [Ibnu Abu Dzi`b] dari [Ishaq bin Yazid Al Hudzali] dari [Aun bin Abdullah bin Utbah] dari [Ibnu Mas'ud] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian rukuk lalu mengucapkan dalam rukuknya; SUBHAANA RABBIAL AZHIIM (Maha Suci Tuhanku yang Maha Agung) tiga kali maka rukuknya telah sempurna. Dan itu adalah yang minimal. Kemudian ketika sujud mengucapkan; SUBHAANA RABBIAL A'LA (Maha Suci Tuhanku yang Maha Tinggi) tiga kali maka rukuknya telah sempurna. Dan itu adalah yang minimal.\" Ia berkata; \"Dalam bab ini ada juga hadits dari Hudzaifah dan Uqbah bin Amir.\" Abu Isa berkata; \"Hadits Ibnu Mas'ud sanadnya tidak bersambung, karena Aun bin Abdullah bin Utbah tidak bertemu Ibnu Mas'ud. Hadits ini diamalkan oleh para ahli ilmu, bahwa mereka menyukai agar seseorang tidak mengurangi dalam membaca tasbih dalam rukuk dan sujudnya. Dan telah diriwayatkan dari Abdullah bin Al Mubarak, ia berkata; \"Aku lebih suka bagi imam untuk bertasbih lima kali agar orang yang berada di belakangnya sempat membaca tasbih tiga kali. Ishaq bin Ibrahim juga berpendapat seperti ini.\""},"243":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ الْأَعْمَشِ قَال سَمِعْتُ سَعْدَ بْنَ عُبَيْدَةَ يُحَدِّثُ عَنْ الْمُسْتَوْرِدِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَأَنَّهُ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ رَبِّيَ الْعَظِيمِ وَفِي سُجُودِهِ سُبْحَانَ رَبِّيَ الْأَعْلَى وَمَا أَتَى عَلَى آيَةِ رَحْمَةٍ إِلَّا وَقَفَ وَسَأَلَ وَمَا أَتَى عَلَى آيَةِ عَذَابٍ إِلَّا وَقَفَ وَتَعَوَّذَقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ شُعْبَةَ نَحْوَهُ وَقَدْ رُوِيَ عَنْ حُذَيْفَةَ هَذَا الْحَدِيثُ مِنْ غَيْرِ هَذَا الْوَجْهِ أَنَّهُ صَلَّى بِاللَّيْلِ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Abu Dawud] berkata; telah memberitakan kepada kami [Syu'bah] dari [Al A'masy] berkata; aku mendengar [Sa'd bin Ubaidah] menceritakan dari [Al Mustaurid] dari [Shillah bin Zufar] dari [Hudzaifah] bahwasanya ia pernah shalat bersama Nabi shallallahu 'alaihi wasallam, dan dalam rukuknya beliau membaca: \"SUBHAANA RABBIAL AZHIIM (Maha Suci Tuhanku yang Maha Agung) dan dalam sujudnya beliau mengucapkan: \"SUBHAANA RABBIAL A'LA (Maha Suci Tuhanku yang Maha Tinggi).\" Dan tidaklah beliau melewati ayat yang berbicara tentang rahmat, beliau berhenti (berdo'a meminta rahmat), dan tidaklah beliau melewati ayat yang berbicara tentang siksa kecuali beliau berhenti dan berlindung.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\" Dan telah menceritakan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Syu'bah] seperti hadits tersebut. Hadits ini juga telah diriwayatkan dari Hudzaifah dengan jalur lain, bahwa ia pernah shalat bersama Nabi shallallahu 'alaihi wasallam, lalu ia menyebutkan hadits tersebut.\""},"244":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ ح و حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لُبْسِ الْقَسِّيِّ وَالْمُعَصْفَرِ وَعَنْ تَخَتُّمِ الذَّهَبِ وَعَنْ قِرَاءَةِ الْقُرْآنِ فِي الرُّكُوعِقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى حَدِيثُ عَلِيٍّ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ كَرِهُوا الْقِرَاءَةَ فِي الرُّكُوعِ وَالسُّجُودِ","id":"telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] berkata; telah menceritakan kepada kami [Ma'n] berkata; telah menceritakan kepada kami [Malik bin Anas]. (sanad dialihkan) telah menceritakan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] dari [Ibrahim bin Hunain] dari [Ayahnya] dari [Ali bin Abu Thalib] berkata; \"Nabi shallallahu 'alaihi wasallam melarang memakai pakaian yang keras, pakaian dicelup, cincin emas dan membaca ayat Al Quran ketika rukuk.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Abbas.\" Abu Isa berkata; \"Hadits Ali ini derajatnya hasan shahih. Ini adalah pendapat ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang setelah mereka, bahwa mereka memakruhkan membaca ayat Al Quran ketika rukuk dan sujud.\""},"245":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ أَبِي مَعْمَرٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ الْبَدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُجْزِئُ صَلَاةٌ لَا يُقِيمُ فِيهَا الرَّجُلُ يَعْنِي صُلْبَهُ فِي الرُّكُوعِ وَالسُّجُودِقَالَ وَفِي الْبَاب عَنْ عَلِيِّ بْنِ شَيْبَانَ وَأَنَسٍ وَأَبِي هُرَيْرَةَ وَرِفَاعَةَ الزُّرَقِيِّ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ يَرَوْنَ أَنْ يُقِيمَ الرَّجُلُ صُلْبَهُ فِي الرُّكُوعِ وَالسُّجُودِ و قَالَ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ مَنْ لَمْ يُقِمْ صُلْبَهُ فِي الرُّكُوعِ وَالسُّجُودِ فَصَلَاتُهُ فَاسِدَةٌ لِحَدِيثِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُجْزِئُ صَلَاةٌ لَا يُقِيمُ الرَّجُلُ فِيهَا صُلْبَهُ فِي الرُّكُوعِ وَالسُّجُودِ وَأَبُو مَعْمَرٍ اسْمُهُ عَبْدُ اللَّهِ بْنُ سَخْبَرَةَ وَأَبُو مَسْعُودٍ الْأَنْصَارِيُّ الْبَدْرِيُّ اسْمُهُ عُقْبَةُ بْنُ عَمْرٍو","id":"telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Umarah bin Umair] dari [Abu Ma'mar] dari [Abu Mas'ud Al Anshari Al Badri] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat seseorang tidak akan sempurna bila dalam rukuk dan sujud tulang punggungnya tidak lurus.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ali bin Syaiban, Anas, Abu Hurairah dan Rifa'ah Az Zuraqi.\" Abu Isa berkata; \"Hadits Abu Mas'ud Al Anshari derajatnya hasan shahih. Hadits ini diamalkan oleh ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka. Mereka berpendapat bahwa seseorang hendaknya meluruskan tulang runggungnya ketika rukuk dan sujud.\" Imam Syafi'i, Ahmad dan Ishaq mengatakan, \"Seserang yang tidak meluruskan punggungnya ketika rukuk dan sujud maka shalatnya rusak. Hal ini berdasarkan hadits Nabi shallallahu 'alaihi wasallam: \"Shalat seseorang tidak akan sempurna bila dalam rukuk dan sujud tulang punggungnya tidak lurus.\" Abu Mu'tamir namanya adalah Abdullah bin Sukhbarah, sedangkan Abu Mas'ud Al Anshari Al Badri namanya adalah Uqbah bin 'Amru.\""},"246":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي سَلَمَةَ الْمَاجِشُونُ حَدَّثَنِي عَمِّي عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ مِلْءَ السَّمَوَاتِ وَمِلْءَ الْأَرْضِ وَمِلْءَ مَا بَيْنَهُمَا وَمِلْءَ مَا شِئْتَ مِنْ شَيْءٍ بَعْدُقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَابْنِ عَبَّاسٍ وَابْنِ أَبِي أَوْفَى وَأَبِي جُحَيْفَةَ وَأَبِي سَعِيدٍ قَالَ أَبُو عِيسَى حَدِيثُ عَلِيٍّ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ بَعْضِ أَهْلِ الْعِ��ْمِ وَبِهِ يَقُولُ الشَّافِعِيُّ قَالَ يَقُولُ هَذَا فِي الْمَكْتُوبَةِ وَالتَّطَوُّعِ و قَالَ بَعْضُ أَهْلِ الْكُوفَةِ يَقُولُ هَذَا فِي صَلَاةِ التَّطَوُّعِ وَلَا يَقُولُهَا فِي صَلَاةِ الْمَكْتُوبَةِ قَالَ أَبُو عِيسَى وَإِنَّمَا يُقَالُ الْمَاجِشُونِيُّ لِأَنَّهُ مِنْ وَلَدِ الْمَاجِشُونِ","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Abu Dawud Ath Thayalisi] berkata; telah menceritakan kepada kami [Abdul Aziz bin Abdullah bin Abu Salamah Al Majisyun] berkata; telah menceritakan kepadaku [Pamanku] dari [Abdurrahman Al A'raj] dari [Ubaidullah bin Abu Rafi'] dari [Ali bin Abu Thalib] ia berkata; \"Jika Rasulullah shallallahu 'alaihi wasallam mengangkat kepalanya beliau mengucapkan: \"SAMI'AALLAHU LIMAN HAMIDAH RABBANA LAKAL HAMDU MIL`AS SAMAAWATI WA MIL`AL ARDLI WA MIL`'azza wajalla MA BAINAHUMA WA MIL`A MA SYI`TA MIN SYAI`IN BA'DU (Semoga Allah mendengar pujian orang yang memuji-Nya. Wahai Tuhan kami, hanya bagi-Mu segala pujian sepebuh langit dan bumi, dan sepenuh apa yang ada di antara keduanya, dan sepenuh apa yang Engkau kehendaki selain itu).\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Umar, Ibnu Abbas, Ibnu Abu Aufa, Abu Juhaifah dan Abu Sa'id.\" Abu Isa berkata; \"Hadits Ali ini derajatnya hasan shahih. Para ahli ilmu mengamalkan hadits ini. Pendapat ini diambil juga oleh Syafi'i. Ia berkata; \"Hendaknya seseorang membaca do'a ini baik dalam shalat wajib maupun sunnah.\" Sebagian penduduk Kufah membaca do`a ini dalam shalat sunnah dan tidak membacanya dalam shalat wajib.\" Abu Isa berkata; \"Ia disebut dengan Al Majisyun karena ia termasuk anak Al Majisyun.\""},"247":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَالَ الْإِمَامُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا وَلَكَ الْحَمْدُ فَإِنَّهُ مَنْ وَافَقَ قَوْلُهُ قَوْلَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ أَنْ يَقُولَ الْإِمَامُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ وَيَقُولَ مَنْ خَلْفَ الْإِمَامِ رَبَّنَا وَلَكَ الْحَمْدُ وَبِهِ يَقُولُ أَحْمَدُ و قَالَ ابْنُ سِيرِينَ وَغَيْرُهُ يَقُولُ مَنْ خَلْفَ الْإِمَامِ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ مِثْلَ مَا يَقُولُ الْإِمَامُ وَبِهِ يَقُولُ الشَّافِعِيُّ وَإِسْحَقُ","id":"telah menceritakan kepada kami [Ishaq bin Musa Al Ashari] berkata; telah menceritakan kepada kami [Ma'n] berkata; telah menceritakan kepada kami [Malik] dari [Sumai] dari [Abu Shalih] dari [Abu Hurairah] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika imam mengucapkan: \"SAMI'AALLAHU LIMAN HAMIDAH (Semoga Allah mendengar pujian orang yang memuji-Nya), maka ucapkanlah; \"RABBANA WA LAKAL HAMDU (Wahai Tuhan kami, dan hanya bagi-Mu segala pujian). Sebab barangsiapa ucapannya berbarengan dengan ucapan malaikat, maka dosa yang telah lalu akan diampuni.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Hadits ini diamalkan oleh sebagian ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka. Yaitu, anjuran bagi imam untuk mengucapkan; \"SAMI'AALLAHU LIMAN HAMIDAH RABBANA WA LAKAL HAMDU (Semoga Allah mendengar pujian orang yang memuji-Nya. Wahai Tuhan kami, dan hanya bagi-Mu segala pujian).\" Lalu orang-orang yang berada di belakang imam (makmum) mengucapkan; \"RABBANA WA LAKAL HAMDU (Wahai Tuhan kami, dan hanya bagi-Mu segala pujian).\" Pendapat ini diambil juga oleh Imam Ahmad. Ibnu Sirin dan selainnya berkata; \"Hendaknya makmum mengucapkan; \"SAMI'AALLAHU LIMAN HAMIDAH RABBANA WA LAKAL HAMDU (Semoga Allah mendengar pujian orang yang memuji-Nya. Wahai Tuhan kami, dan hanya bagi-Mu segala pujian). Sebagimana yang diucapkan oleh imam.\" Pendapat ini diambil juga oleh Syafi'i dan Ishaq."},"248":{"ar":"حَدَّثَنَا سَلَمَةُ بْنُ شَبِيبٍ وَأَحْمَدُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ وَالْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ وَعَبْدُ اللَّهِ بْنُ مُنِيرٍ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شَرِيكٌ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَجَدَ يَضَعُ رُكْبَتَيْهِ قَبْلَ يَدَيْهِ وَإِذَا نَهَضَ رَفَعَ يَدَيْهِ قَبْلَ رُكْبَتَيْهِقَالَ زَادَ الْحَسَنُ بْنُ عَلِيٍّ فِي حَدِيثِهِ قَالَ يَزِيدُ بْنُ هَارُونَ وَلَمْ يَرْوِ شَرِيكٌ عَنْ عَاصِمِ بْنِ كُلَيْبٍ إِلَّا هَذَا الْحَدِيثَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُ أَحَدًا رَوَاهُ مِثْلَ هَذَا عَنْ شَرِيكٍ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ يَرَوْنَ أَنْ يَضَعَ الرَّجُلُ رُكْبَتَيْهِ قَبْلَ يَدَيْهِ وَإِذَا نَهَضَ رَفَعَ يَدَيْهِ قَبْلَ رُكْبَتَيْهِ وَرَوَى هَمَّامٌ عَنْ عَاصِمٍ هَذَا مُرْسَلًا وَلَمْ يَذْكُرْ فِيهِ وَائِلَ بْنَ حُجْرٍ","id":"telah menceritakan kepada kami [Salamah bin Syabib] dan [Ahmad bin Ibrahim Ad Dauraqi] dan [Al Hasan bin Ali Al Hulwani] dan [Abdullah bin Munir] dan lain-lain mereka berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Syarik] dari ['Ashim bin Kulaib] dari [Ayahnya] dari [Wa'il bin Hujr] ia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam apabila sujud, beliau meletakkan kedua lututnya sebelum kedua tangannya, dan apabila bangkit beliau mengangkat kedua tangannya sebelum kedua lututnya.\" Ia berkata; \"[Al Hasan bin Ali] menambahkan dalam haditsnya bahwa [Yazid bin Harun] berkata; \"Syarik tidak pernah meriwayatkan dari 'Ashim bin Kulaib kecuali hadits ini.\" Abu Isa berkata; \"Hadits ini hasan gharib, dan kami tidak mengetahui seorangpun yang meriwayatkan hadits seperti ini dari Syarik. Hadits ini diamalkan oleh kebanyakan ahli ilmu, mereka berpendapat hendaknya seseorang meletakkan kedua lututnya sebelum kedua tangannya, dan mengangkat kedua tangan sebelum kedua lututnya ketika bangkit. [Hammam] meriwayatkan hadits ini dari ['Ashim] secara mursal dan tidak menyebutkan di dalamnya nama Wa'il bin Hujr.\""},"249":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نَافِعٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ حَسَنٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَعْمِدُ أَحَدُكُمْ فَيَبْرُكُ فِي صَلَاتِهِ بَرْكَ الْجَمَلِقَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ أَبِي الزِّنَادِ إِلَّا مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَبْدُ اللَّهِ بْنُ سَعِيدٍٍ الْمَقْبُرِيُّ ضَعَّفَهُ يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ وَغَيْرُهُ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abdullah bin Nafi'] berkata [Muhammad bin Abdullah bin Hasan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] berkata; \"Nabi shallallahu 'alaihi wasallam bersabda: \"Dalam shalat salah seorang dari kalian meletakkan lututnya seperti unta yang menderum.\" Abu Isa berkata; \"Hadits Abu Hurairah ini derajatnya adalah gharib, dan kami tidak mengetahuinya semacam ini dari Abu Az Zinad kecuali dari jalur ini. Hadits ini telah diriwayatkan pula dari [Abdullah bin Sa'id Al Maqburi] dari [ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam. Dan Yahya bin Sa'id Al Qaththan dan yang lainnya telah melemahkan Abdullah bin Sa'id Al Maqburi.\""},"250":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ بُنْدَارٌ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ حَدَّثَنِي عَبَّاسُ بْنُ سَهْلٍ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَجَدَ أَمْكَنَ أَنْفَهُ وَجَبْهَتَهُ مِنْ الْأَرْضِ وَنَحَّى يَدَيْهِ عَنْ جَنْبَيْهِ وَوَضَعَ كَفَّيْهِ حَذْوَ مَنْكِبَيْهِقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَوَائِلِ بْنِ حُجْرٍ وَأَبِي سَعِيدٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي حُمَيْدٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَهْلِ الْعِلْمِ أَنْ يَسْجُدَ الرَّجُلُ عَلَى جَبْهَتِهِ وَأَنْفِهِ فَإِنْ سَجَدَ عَلَى جَبْهَتِهِ دُونَ أَنْفِهِ فَقَدْ قَالَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ يُجْزِئُهُ وَقَالَ غَيْرُهُمْ لَا يُجْزِئُهُ حَتَّى يَسْجُدَ عَلَى الْجَبْهَةِ وَالْأَنْفِ","id":"telah menceritakan kepada kami [Muhammad bin Basysyar Bundar] berkata; telah menceritakan kepada kami [Abu 'Amir Al 'Aqdi] berkata; telah menceritakan kepada kami [Fulaih bin Sulaiman] berkata; telah menceritakan kepadaku [Abbas bin Sahl] dari [Abu Humaid As Sa'idi] berkata; \"Ketika sujud Nabi shallallahu 'alaihi wasallam menekankan hidung dan dahinya ke bumi, menjauhkan dua tangan dari lambungnya, dan meletakkan dua telapak tangannya sejajar dengan dua bahu.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Abbas, Wa`il bin Hujr dan Abu Sa'id.\" Abu Isa berkata; \"Hadits Abu Humaid derajatnya hasan shahih. Para ahli ilmu mengamalkan hadits ini, yakni seseorang hendaknya menempelkan hidung dan dahinya. Jika ia hanya menempelkan dahi dan tidak menempelkan hidung, maka sebagian ulama mengatakan bahwa hal itu telah mencukupi. Sedangkan sebagian yang lain mengatakan bahwa hal itu tidak mencukupi hingga ia sujud di atas hidung dan dahinya.\""},"251":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الْحَجَّاجِ عَنْ أَبِي إِسْحَقَ قَالَقُلْتُ لِلْبَرَاءِ بْنِ عَازِبٍ أَيْنَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضَعُ وَجْهَهُ إِذَا سَجَدَ فَقَالَ بَيْنَ كَفَّيْهِقَالَ وَفِي الْبَاب عَنْ وَائِلِ بْنِ حُجْرٍ وَأَبِي حُمَيْدٍ قَالَ أَبُو عِيسَى حَدِيثُ الْبَرَاءِ حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَهُوَ الَّذِي اخْتَارَهُ بَعْضُ أَهْلِ الْعِلْمِ أَنْ تَكُونَ يَدَاهُ قَرِيبًا مِنْ أُذُنَيْهِ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Al Hajjaj] dari [Abu Ishaq] ia berkata; \"Aku bertanya kepada [Al Barra` bin 'Azib]; Dimanakah Nabi shallallahu 'alaihi wasallam meletakkan wajahnya ketika sujud?\" ia menjawab, \"Antara dua telapak tangannya.\" Ia berkata; \"Dalam bab ini ada juga hadits dari Wa'il bin Hujr dan Abu Humaid.\" Abu Isa berkata; \"Hadits Al Barra` derajatnya hasan shahih gharib. Dan inilah yang menjadi pilihan sebagian ahli ilmu, yaitu kedua tangan hendaknya dekat dengan kedua telinganya.\""},"252":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا بَكْرُ بْنُ مُضَرَ عَنْ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا سَجَدَ الْعَبْدُ سَجَدَ مَعَهُ سَبْعَةُ آرَابٍ وَجْهُهُ وَكَفَّاهُ وَرُكْبَتَاهُ وَقَدْمَاهُقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَأَبِي هُرَيْرَةَ وَجَابِرٍ وَأَبِي سَعِيدٍ قَالَ أَبُو عِيسَى حَدِيثُ الْعَبَّاسِ حَدِيثٌ حَسَنٌ صَحِيحٌ وَعَلَيْهِ الْعَمَلُ عِنْدَ أَهْلِ الْعِلْمِ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Bakr bin Mudlar] dari [Ibnu Al Had] dari [Muhammad bin Ibrahim] dari ['Amir bin Sa'd bin Abu Waqash] dari [Al Abbas bin Abdul Muthallib] bahwasanya ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang hamba sujud hendaklah di atas tujuh bagian (anggota tubuhnya); wajah, kedua telapak tangan, kedua lutut, dan kedua telapak kaki.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Abbas, Abu Hurairah, Jabir dan Abu Sa'id.\" Abu Isa berkata; \"Hadits Al Abbas ini derajatnya hasam shahih. Hadits ini diamalkan oleh ahli ilmu.\""},"253":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَأُمِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَسْجُدَ عَلَى سَبْعَةِ أَعْظُمٍ وَلَا يَكُفَّ شَعْرَهُ وَلَا ثِيَابَ��ُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari ['Amru bin Dinar] dari [Thawus] dari [Ibnu Abbas] ia berkata; \"Nabi shallallahu 'alaihi wasallam diperintahkan untuk sujud di atas tujuh tulang dan tidak menahan rambut serta pakaian.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\""},"254":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ دَاوُدَ بْنِ قَيْسٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَقْرَمِ الْخُزَاعِيِّ عَنْ أَبِيهِ قَالَكُنْتُ مَعَ أَبِي بِالْقَاعِ مِنْ نَمِرَةَ فَمَرَّتْ رَكَبَةٌ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ يُصَلِّي قَالَ فَكُنْتُ أَنْظُرُ إِلَى عُفْرَتَيْ إِبْطَيْهِ إِذَا سَجَدَ أَيْ بَيَاضِهِقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَابْنِ بُحَيْنَةَ وَجَابِرٍ وَأَحْمَرَ بْنِ جَزْءٍ وَمَيْمُونَةَ وَأَبِي حُمَيْدٍ وَأَبِي مَسْعُودٍ وَأَبِي أُسَيْدٍ وَسَهْلِ بْنِ سَعْدٍ وَمُحَمَّدِ بْنِ مَسْلَمَةَ وَالْبَرَاءِ بْنِ عَازِبٍ وَعَدِيِّ بْنِ عَمِيرَةَ وَعَائِشَةَ قَالَ أَبُو عِيسَى وَأَحْمَرُ بْنُ جَزْءٍ هَذَا رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُ حَدِيثٌ وَاحِدٌ قَالَ أَبُو عِيسَى حَدِيثُ عَبْدِ اللَّهِ بْنِ أَقْرَمَ حَدِيثٌ حَسَنٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ دَاوُدَ بْنِ قَيْسٍ وَلَا نَعْرِفُ لِعَبْدِ اللَّهِ بْنِ أَقْرَمَ الْخُزَاعِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرَ هَذَا الْحَدِيثِ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَبْدُ اللَّهِ بْنُ أَرْقَمَ الزُّهْرِيُّ صَاحِبُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ كَاتِبُ أَبِي بَكْرٍ الصِّدِّيقِ","id":"telah menceritakan kepada kami [Abu Kuraib] berkata; telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Dawud bin Qais] dari [Ubaidullah bin Abdullah bin Al Aqram Al Khuza'i] dari [Ayahnya] ia berkata; \"Aku bersama ayahku berada di suatu tanah lapang di Namirah, lalu melintaslah sebuah rombongan sedangkan Rasulullah shallallahu 'alaihi wasallam berdiri shalat.\" Ia berkata; \"Aku melihat dapat melihat putihnya bagian dalam dari ketiak beliau ketika sujud.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Abbas, Ibnu Buhainah, Jabir, Ahmar bin Jaz`i, Maimunah, Abu Humaid, Abu Mas'udi, Abu Usaid, Sahl bin Sa'd, Muhammad bin Maslamah, Al Barra` bin 'Azib, Adi bin 'Amirah dan 'Aisyah.\" Abu Isa berkata; \"Hadits Abdullah bin Al Arqam derajatnya hasan, kami tidak mengetahuinya kecuali dari hadits Dawud bin Qais. Dan kami juga tidak mengetahui riwayat Abdullah bin Al Arqam dari Nabi shallallahu 'alaihi wasallam selain hadits ini. Kebanyakan para ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam mengamalkan hadits ini. Sedangkan Abdullah bin Al Arqam Az Zuhri sendiri adalah seorang sahabat Nabi shallallahu 'alaihi wasallam dan penulis Abu Bakar Ash Shiddiq.\""},"255":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَجَدَ أَحَدُكُمْ فَلْيَعْتَدِلْ وَلَا يَفْتَرِشْ ذِرَاعَيْهِ افْتِرَاشَ الْكَلْبِقَالَ وَفِي الْبَاب عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِبْلٍ وَأَنَسٍ وَالْبَرَاءِ وَأَبِي حُمَيْدٍ وَعَائِشَةَ قَالَ أَبُو عِيسَى حَدِيثُ جَابِرٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَهْلِ الْعِلْمِ يَخْتَارُونَ الِاعْتِدَالَ فِي السُّجُودِ وَيَكْرَهُونَ الِافْتِرَاشَ كَافْتِرَاشِ السَّبُعِ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian sujud hendaklah seimbangkan, dan jangan menelungkup kedua lengannya seperti menelungkupnya seekor anjing.\" Ia berkata; \"Dalam bab ini ada juga hadits dari Abdurrahman bin Syibl, Anas, Al Barra`, Abu Humaid dan 'Aisyah.\" Abu Isa berkata; \"Hadits Jabir ini derajatnya hasan shahih. Hadits ini diamalkan oleh para ahli ilmu, mereka memilih I'tidal (seimbang) ketika sujud dan memakruhkan posisi menelungkup sebagaimana binatang buas.\""},"256":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ قَال سَمِعْتُ أَنَسًا يَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اعْتَدِلُوا فِي السُّجُودِ وَلَا يَبْسُطَنَّ أَحَدُكُمْ ذِرَاعَيْهِ فِي الصَّلَاةِ بَسْطَ الْكَلْبِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Abu Dawud] berkata; telah mengabarkan kepada kami [Syu'bah] dari [Qatadah] ia berkata; \"Aku mendengar [Anas] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah salah seorang dari kalian seimbang ketika sujud, jangan membentangkan kedua siku layaknya anjing.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\""},"257":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِوَضْعِ الْيَدَيْنِ وَنَصْبِ الْقَدَمَيْنِقَالَ عَبْدُ اللَّهِ وَقَالَ مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا حَمَّادُ بْنُ مَسْعَدَةَ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عَامِرِ بْنِ سَعْدٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِوَضْعِ الْيَدَيْنِ فَذَكَرَ نَحْوَهُ وَلَمْ يَذْكُرْ فِيهِ عَنْ أَبِيهِ قَالَ أَبُو عِيسَى وَرَوَى يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ وَغَيْرُ وَاحِدٍ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عَامِرِ بْنِ سَعْدٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِوَضْعِ الْيَدَيْنِ وَنَصْبِ الْقَدَمَيْنِ مُرْسَلٌ وَهَذَا أَصَحُّ مِنْ حَدِيثِ وُهَيْبٍ وَهُوَ الَّذِي أَجْمَعَ عَلَيْهِ أَهْلُ الْعِلْمِ وَاخْتَارُوهُ","id":"telah menceritakan kepada kami [Abdullah bin Abdurrahman] berkata; telah mengabarkan kepada kami [Mu'alla bin Asad] berkata; telah menceritakan kepada kami [Wuhaib] dari [Muhammad bin 'Ajlan] dari [Muhammad bin Ibrahim] dari ['Amir bin Sa'ad bin Abu Waqqas] dari [Ayahnya] berkata; \"Nabi shallallahu 'alaihi wasallam memerintahkan untuk melekatkan kedua tangan dan menegakkan kedua telapak kaki.\" Abdullah berkata; \" [Mu'alla bin Asad] berkata; \"Telah menceritakan kepada kami [Hammad bin Mas'adah] dari [Muhammad bin 'Ajlan] dari [Muhammad bin Ibrahim] dari ['Amir bin Sa'd] berkata; \"Nabi shallallahu 'alaihi wasallam memerintahkan untuk melekatkan kedua tangan… lalu ia menyebutkan sebagaiman hadits tersebut, hanya saja ia tidak menyebutkan di dalamnya, dari ayahnya.\" Abu Isa berkata; \" [Yahya bin Sa'id Al Qaththan] dan lainnya meriwayatkan dari [Muhammad bin 'Ajlan] dari [Muhammad bin Ibrahim] dari ['Amir bin Sa'd] berkata; \"Nabi shallallahu 'alaihi wasallam memerintahkan untuk melekatkan kedua tangan dan menegakkan kedua telapak kaki.\" Hadits ini mursal, namun lebih shahih daripada hadits Wuhaib. Dan inilah yang menjadi kesepakatan dan pilihan para ahli ilmu.\""},"258":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ مُوسَى الْمَرْوَزِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَكَانَتْ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ وَإِذَا سَجَدَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ السُّجُودِ قَرِيبًا مِنْ السَّوَاءِقَالَ وَفِي الْبَاب عَنْ أَنَسٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ نَحْوَهُ قَالَ أَبُو عِيسَى حَدِيثُ الْبَرَاءِ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَهْلِ الْعِلْمِ","id":"telah menceritakan kepada kami [Ahmad bin Muhammad bin Musa Al Mawarzi] berkata; telah mengabarkan kepada kami [Abdullah bin Al Mubarak] berkata; telah mengabarkan kepada kami [Syu'bah] dari [Al Hakam] dari [Abdurrahman bin Abu Laila] dari [Al Bara` bin 'Azib] ia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam shalat, maka rukuk, mengangkat kepala dari rukuk, sujud, dan mengangkat kepala dari sujud lamanya hampir sama.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Anas. Ia berkata; \"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] sebagaimana dalam hadits.\" Abu Isa berkata; \"Hadits Al Bara` derajatnya hasan shahih. Hadits ini diamalkan oleh ahli ilmu.\""},"259":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ حَدَّثَنَا الْبَرَاءُ وَهُوَ غَيْرُ كَذُوبٍ قَالَكُنَّا إِذَا صَلَّيْنَا خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ لَمْ يَحْنِ رَجُلٌ مِنَّا ظَهْرَهُ حَتَّى يَسْجُدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَسْجُدَقَالَ وَفِي الْبَاب عَنْ أَنَسٍ وَمُعَاوِيَةَ وَابْنِ مَسْعَدَةَ صَاحِبِ الْجُيُوشِ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى حَدِيثُ الْبَرَاءِ حَدِيثٌ حَسَنٌ صَحِيحٌ وَبِهِ يَقُولُ أَهْلُ الْعِلْمِ إِنَّ مَنْ خَلْفَ الْإِمَامِ إِنَّمَا يَتْبَعُونَ الْإِمَامَ فِيمَا يَصْنَعُ لَا يَرْكَعُونَ إِلَّا بَعْدَ رُكُوعِهِ وَلَا يَرْفَعُونَ إِلَّا بَعْدَ رَفْعِهِ لَا نَعْلَمُ بَيْنَهُمْ فِي ذَلِكَ اخْتِلَافًا","id":"telah menceritakan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abdullah bin Yazid] berkata; telah menceritakan kepada kami [Al Bara`] dan ia bukanlah seorang pendusta. Ia berkata; \"Jika kami shalat di belakang Rasulullah shallallahu 'alaihi wasallam dan beliau mengangkat kepalanya dari rukuk. Maka tidak seorang pun dari kami yang menundukkan penunggungnya (rukuk) hingga Rasulullah shallallahu 'alaihi wasallam sujud, lalu kami pun ikut sujud.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Anas, Mu'awiyah, Ibnu Mas'adah dan Abu Hurairah.\" Abu Isa berkata; \"Hadits Al Bara` derajatnya hasan shahih. Pendapat ini diambil oleh ahli ilmu, bahwa makmum mengikuti (semua) yang dilakukan oleh imam, ia tidak boleh rukuk hingga imam rukuk dan tidak mengangkat kepala hingga imam mengangkat kepala. Dan kami tidak menemukan adanya perselisihan dan hal itu.\""},"260":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَلِيُّ أُحِبُّ لَكَ مَا أُحِبُّ لِنَفْسِي وَأَكْرَهُ لَكَ مَا أَكْرَهُ لِنَفْسِي لَا تُقْعِ بَيْنَ السَّجْدَتَيْنِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ عَلِيٍّ إِلَّا مِنْ حَدِيثِ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ وَقَدْ ضَعَّفَ بَعْضُ أَهْلِ الْعِلْمِ الْحَارِثَ الْأَعْوَرَ وَالْعَمَلُ عَلَى هَذَا الْحَدِيثِ عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ يَكْرَهُونَ الْإِقْعَاءَ قَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَأَنَسٍ وَأَبِي هُرَيْرَةَ","id":"telah menceritakan kepada kami [Abdullah bin Abdurrahman] berkata; telah mengabarkan kepada kami [Ubaidullah bin Musa] berkata; telah menceritakan kepada kami [Isra'il] dari [Abu Ishaq] dari [Al Harits] dari [Ali] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Wahai Ali, aku mencintai sesuatu untukmu sebagaimana aku mencintai untuk diriku, dan aku benci sesuatu yang menimpamu sebagaimana aku membencinya jika menimpaku, maka janganlah kamu menderum di antara dua sujud.\" Abu Isa berkata; \"Hadits ini tidak kami ketahui dari hadits Ali kecuali dari hadits riwayat Abu Ishaq, dari Al Harits, dari Ali. Namun sebagian ahli ilmu melemahkan Al Harits Al A'war. Banyak dari ahli ilmu yang mengamalkan hadits ini, bahwa mereka memakruhkan posisi menderum.\" Abu Isa berkata; \"Dalam bab ini ada juga hadits dari 'Aisyah, Anas dan Abu Hurairah.\""},"261":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ طَاوُسًا يَقُولُقُلْنَا لِابْنِ عَبَّاسٍ فِي الْإِقْعَاءِ عَلَى الْقَدَمَيْنِ قَالَ هِيَ السُّنَّةُ فَقُلْنَا إِنَّا لَنَرَاهُ جَفَاءً بِالرَّجُلِ قَالَ بَلْ هِيَ سُنَّةُ نَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ ذَهَبَ بَعْضُ أَهْلِ الْعِلْمِ إِلَى هَذَا الْحَدِيثِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَرَوْنَ بِالْإِقْعَاءِ بَأْسًا وَهُوَ قَوْلُ بَعْضِ أَهْلِ مَكَّةَ مِنْ أَهْلِ الْفِقْهِ وَالْعِلْمِ قَالَ وَأَكْثَرُ أَهْلِ الْعِلْمِ يَكْرَهُونَ الْإِقْعَاءَ بَيْنَ السَّجْدَتَيْنِ","id":"telah menceritakan kepada kami [Yahya bin Musa] berkata; telah menceritakan kepada kami [Abdurrazaq] berkata; telah mengabarkan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Abu Az Zubair] bahwasanya ia pernah mendengar [Thawus] berkata; \"Kami pernah bertanya kepada [Ibnu Abbas] tentang duduk Al Iq'a` (duduk di atas pantat dengan menegakkan paha dan betis) di atas dua telapak tangan?\" lalu ia menjawab, \"Itu adalah sunnah.\" Lalu kami pun berkata; \"Sesungguhnya sikap seperti kami menganggapnya kasar bagi seorang laki-laki, \" ia menjawab, \"Bahkan itu adalah sunnah nabi kalian shallallahu 'alaihi wasallam.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin Mas'ud, Abu Darda, Ibnu Abbas, Mu'adz bin Anas dan Jabir.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Sebagian ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam berpegangan dengan hadits ini, mereka berpandangan bahwa duduk iq'a` tidak apa-apa. Pendapat ini diambil oleh sebagian penduduk Makkah dari kalangan ahli fikih dan ahli ilmu. Ia berkata; \"Namun sebagian besar ahli ilmu memakruhkan duduk iq'a` di antara dua sujud.\""},"262":{"ar":"حَدَّثَنَا سَلَمَةُ بْنُ شَبِيبٍ حَدَّثَنَا زَيْدُ بْنُ حُبَابٍ عَنْ كَامِلٍ أَبِي الْعَلَاءِ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ بَيْنَ السَّجْدَتَيْنِ اللَّهُمَّ اغْفِرْ لِي وَارْحَمْنِي وَاجْبُرْنِي وَاهْدِنِي وَارْزُقْنِيحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ الْحُلْوَانِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ زَيْدِ بْنِ حُبَابٍ عَنْ كَامِلٍ أَبِي الْعَلَاءِ نَحْوَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَهَكَذَا رُوِيَ عَنْ عَلِيٍّ وَبِهِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ يَرَوْنَ هَذَا جَائِزًا فِي الْمَكْتُوبَةِ وَالتَّطَوُّعِ وَرَوَى بَعْضُهُمْ هَذَا الْحَدِيثَ عَنْ كَامِلٍ أَبِي الْعَلَاءِ مُرْسَلًا","id":"telah menceritakan kepada kami [Salamah bin Syabib] berkata; telah menceritakan kepada kami [Zaid bin Hubab] dari [Kamil Abu Al 'Ala`] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata; \"Ketika duduk di antara dua sujud, Nabi shallallahu 'alaihi wasallam membaca do`a: \"ALLAAHUMMAGHFIRLII WARHAMNII WAJBURNII WAHDINII WARZUQNII (ya Allah ampunila aku, kasihanilah aku, cukupkanlah aku, berilah aku hidayah dan berilah aku rizqi).\" Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal Al Hulwani] berkata; telah menceritakan kepada kami [Yazid bin Harun] dari [Zaid bin Hubab] dari [Kamil Abu Al 'Ala`] sebagaimana dalam hadits.\" Abu Isa berkata; \"Hadits ini derajatnya gharib, dan seperti inilah diriwayatkan dari Ali. Pendapat ini diambil oleh Imam Syafi'i, Ahmad dan Ishaq. Mereka berpandangan bahwa hal itu dibolehkan baik dalam shalat wajib maupun shalat sunnah. Dan sebagian yang lain meriwayatkan hadits ini dari Kamil Abu Al 'Ala` secara Mursal.\""},"263":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَاشْتَكَى بَعْضُ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَشَقَّةَ السُّجُودِ عَلَيْهِمْ إِذَا تَفَرَّجُوا فَقَالَ اسْتَعِينُوا بِالرُّكَبِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ اللَّيْثِ عَنْ ابْنِ عَجْلَانَ وَقَدْ رَوَى هَذَا الْحَدِيثَ سُفْيَانُ بْنُ عُيَيْنَةَ وَغَيْرُ وَاحِدٍ عَنْ سُمَيٍّ عَنْ النُّعْمَانِ بْنِ أَبِي عَيَّاشٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا وَكَأَنَّ رِوَايَةَ هَؤُلَاءِ أَصَحُّ مِنْ رِوَايَةِ اللَّيْثِ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Sumai] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; \"Sebagian sahabat Nabi shallallahu 'alaihi wasallam mengeluhkan beratnya sujud kepada Nabi shallallahu 'alaihi wasallam bila mereka harus membentangkan (tangan). Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"(Mudahkanlah) dengan meminta bantuan lutut kalian.\" Abu Isa berkata; \"Hadits ini derajatnya gharib, kami tidak mengetahui bahwa itu adalah dari hadits Abu Shalih, dari Abu Hurairah, dari Nabi shallallahu 'alaihi wasallam, kecuali dari jalur ini. Yakni dari hadits Al Laits, dari Ibnu 'Ajlan.\" Hadits ini juga telah diriwayatkan dari jalur [Sufyan bin Uyainah] dan beberapa orang dari [Sumai] dari [An Nu'man bin Abu Ayyasy] dari Nabi shallallahu 'alaihi wasallam seperti hadits tersebut. Seakan-akan riwayat mereka lebih shahih ketimbang riwayat Al Laits.\""},"264":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا هُشَيْمٌ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ اللَّيْثِيِّأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فَكَانَ إِذَا كَانَ فِي وِتْرٍ مِنْ صَلَاتِهِ لَمْ يَنْهَضْ حَتَّى يَسْتَوِيَ جَالِسًاقَالَ أَبُو عِيسَى حَدِيثُ مَالِكِ بْنِ الْحُوَيْرِثِ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ وَبِهِ يَقُولُ إِسْحَقُ وَبَعْضُ أَصْحَابِنَا وَمَالِكٌ يُكْنَى أَبَا سُلَيْمَانَ","id":"telah menceritakan kepada kami [Ali bin Hujr] berkata; telah mengabarkan kepada kami [Husyaim] dari [Khalid Al Hadza`] dari [Abu Qilabah] dari [Malik Al Huwairits Al Laitsi] bahwasanya ia pernah melihat Nabi shallallahu 'alaihi wasallam melaksanakan shalat, apabila beliau berada dalam rakaat ganjil, maka beliau tidak bangkit hingga duduk sempurna.\" Abu Isa berkata; \"Hadits Malik bin Al Huwairits derajatnya hasan shahih. Hadits ini diamalkan oleh sebagian ahli ilmu. Ini adalah pendapat Ishaq dan sebagian sahabat kami. Sedangkan Malik, julukannya adalah Abu Sulaiman.\""},"265":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا خَالِدُ بْنُ إِلْيَاسَ عَنْ صَالِحٍ مَوْلَى التَّوْأَمَةِ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَضُ فِي الصَّلَاةِ عَلَى صُدُورِ قَدَمَيْهِقَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ عَلَيْهِ الْعَمَلُ عِنْدَ أَهْلِ الْعِلْمِ يَخْتَارُونَ أَنْ يَنْهَضَ الرَّجُلُ فِي الصَّلَاةِ عَلَى صُدُورِ قَدَمَيْهِ وَخَالِدُ بْنُ إِلْيَاسَ هُوَ ضَعِيفٌ عِنْدَ أَهْلِ الْحَدِيثِ قَالَ وَيُقَالُ خَالِدُ بْنُ إِيَاسٍ أَيْضًا وَصَالِحٌ مَوْلَى التَّوْأَمَةِ هُوَ صَالِحُ بْنُ أَبِي صَالِحٍ وَأَبُو صَالِحٍ اسْمُهُ نَبْهَانُ وَهُوَ مَدَنِيٌّ","id":"telah menceritakan kepada kami [Yahya bin Musa] berkata; telah menceritakan kepada kami [Abu Awanah] berkata; telah menceritakan kepada kami [Khalid bin Ilyas] dari [Shalih] pelayah At Tau`amah, dari [Abu Hurairah] ia berkata; \"Nabi shallallahu 'alaihi wasallam bangkit dalam shalat dengan bertumpuan pada ujung jari telapak kaki.\" Abu Isa berkata; \"Hadits Abu Hurairah ini diamalkan oleh para ulama. Mereka berpendapat bahwa, hendaknya seorang laki-laki bangkit di dalam shalatnya dengan bertumpuan pada kedua telapak kaki. Dan menurut para ahli hadits Khalid bin Ilyas adalah seorang yang lemah.\" Ia berkata; \"Khalid bin Ilyas juga biasa disebut dengan nama Khalid bin Iyas. Sedangkan Shalih pelayan At Tau`amah adalah Shalih bin Abi Shalih. Sedangkan Abu Shalih sendiri namanya adalah Nabhan, yaitu seorang yang berasal dari Madinah.\""},"266":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ الْأَشْجَعِيُّ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَعَلَّمَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَعَدْنَا فِي الرَّكْعَتَيْنِ أَنْ نَقُولَ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَجَابِرٍ وَأَبِي مُوسَى وَعَائِشَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ مَسْعُودٍ قَدْ رُوِيَ عَنْهُ مِنْ غَيْرِ وَجْهٍ وَهُوَ أَصَحُّ حَدِيثٍ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي التَّشَهُّدِ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ مِنْ التَّابِعِينَ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَابْنِ الْمُبَارَكِ وَأَحْمَدَ وَإِسْحَقَ حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ مُوسَى أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ خُصَيْفٍ قَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَنَامِ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ النَّاسَ قَدْ اخْتَلَفُوا فِي التَّشَهُّدِ فَقَالَ عَلَيْكَ بِتَشَهُّدِ ابْنِ مَسْعُودٍ","id":"telah menceritakan kepada kami [Ya'qub bin Ibrahim Ad Dauraqi] berkata; telah menceritakan kepada kami [Ubaidullah Al Asyja'i] dari [Sufyan Ats Tsauri] dari [Abu Ishaq] dari [Al Aswad bin Yazid] dari [Abdullah bin Mas'ud] ia berkata; \"Kika kami sedang duduk pada rakaat kedua, Rasulullah shallallahu 'alaihi wasallam mengajari kami untuk membaca; \"ATTAHIYYATU LILLAAH WASH SHALAAWATU WATH THAYYIBAAT AS SALAAMU 'ALAIKA AYYUHAN-NABIYYU WA RAHMATULLAAHI WA BARAKAATUH, AS SALAAMU 'ALAINA WA 'ALAA 'IBAADILLAAHISH SHAALIHIIN, ASYHADU ANLAA ILAAHA ILLAALLAH, WA ASYHADU ANNA MUHAMMADAN 'ABDUHUU WA RASUULUH (Segala penghormatan hanya milik Allah. (Demikian juga) segala rahmat dan kebaikan. Semoga kesejahteraan dilimpahkan kepadamu wahai Nabi, serta rahmat dan berkah Allah. Semoga kesejahteraan dilimpahkan kepada kami dan kepada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tidak ada Tuhan yang berhak untuk disembah selain Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusan Allah.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Umar, Jabir, Abu Musa dan 'Aisyah.\" Abu Isa berkata; \"Hadits [Ibnu Mas'ud] ini telah diriwayatkan darinya dengan banyak jalur. Dalam masalah tasyahud, hadits ini adalah yang paling shahih dari Nabi shallallahu 'alaihi wasallam. Dan kebanyakan ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang setelah mereka juga telah mengamalkannya. Ini adalah pendapat yang diambil oleh Sufyan Ats Tsauri, bin Al Mubarak, Ahmad dan Ishaq.\" Telah menceritakan kepada kami Ahmad bin Muhammad bin Musa berkata; telah mengabarkan kepada kami Abdullah bin Al Mubarak dari Ma'mar dari Khushaif ia berkata; \"Aku pernah melihat Nabi shallallahu 'alaihi wasallam di dalam mimpi, lalu aku bertanya, \"Wahai Rasulullah, orang-orang telah berselisih dalam perkara tasyahud!\" lalu beliau menjawab: \"Hendaklah engkau bertasyahud sebagaimana yang dipakai Ibnu Mas'ud.\""},"267":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ وَطَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا التَّشَهُّدَ كَمَا يُعَلِّمُنَا الْقُرْآنَ فَكَانَ يَقُولُ التَّحِيَّاتُ الْمُبَارَكَاتُ الصَّلَوَاتُ الطَّيِّبَاتُ لِلَّهِ سَلَامٌ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ سَلَامٌ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِقَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عَبَّاسٍ حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ وَقَدْ رَوَى عَبْدُ الرَّحْمَنِ بْنُ حُمَيْدٍ الرُّؤَاسِيُّ هَذَا الْحَدِيثَ عَنْ أَبِي الزُّبَيْرِ نَحْوَ حَدِيثِ اللَّيْثِ بْنِ سَعْدٍ وَرَوَى أَيْمَنُ بْنُ نَابِلٍ الْمَكِّيُّ هَذَا الْحَدِيثَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ وَهُوَ غَيْرُ مَحْفُوظٍ وَذَهَبَ الشَّافِعِيُّ إِلَى حَدِيثِ ابْنِ عَبَّاسٍ فِي التَّشَهُّدِ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Laits] dari [Abu Az Zubair] dari [Sa'id bin Jubair] dan [Thawus] dari [Ibnu Abbas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengajari kami taysahud sebagimana beliau mengajari kami Al Qur`an, beliau mengucapkan: \"ATTAHIYATUL MUBARAKATUSH SHALAWATUTH THAIYYIBATULILLAH SALAAMUN 'ALAIKA AYYUHAN-NABIYYU WA RAHMATULLAAHI WA BARAKAATUH, SALAAMUN 'ALAINA WA 'ALAA 'IBAADILLAHISH SHALIHIIN ASYHADU ANLAA ILAAHA ILLAALLAH, WA ASYHADU ANNA MUHAMMADAN RASULULLAH (Segala penghormatan dan keberkahan hanya milik Allah. (Demikian juga) segala rahmat dan kebaikan. Semoga kesejahteraan dilimpahkan kepadamu wahai Nabi, serta rahmat dan berkah Allah. Semoga kesejahteraan dilimpahkan kepada kami dan kepada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tidak ada Tuhan yang berhak untuk disembah selain Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusan Allah.\" Ia berkata; \"Hadits Ibnu Abbas ini derajatnya hasan gharib shahih. [Abdurrahman bin Humaid Ar Ru`asi] juga telah meriwayatkan hadits ini dari [Abu Az Zubair] sebagimana hadits Al Laits bin Sa'd. Dan [Aiman bin Nabil Al Makki] meriwayatkan hadits ini dari [Abu Az Zubair] dari [Jabir] namun sanadnya tidak terjaga. Hingga Imam Syafi'i berpegang dengan hadits Ibnu Abbas dalam masalah tasyahud.\""},"268":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَمِنْ السُّنَّةِ أَنْ يُخْفِيَ التَّشَهُّدَقَالَ أَبُو عِيسَى حَدِيثُ ابْنِ مَسْعُودٍ حَدِيثٌ حَسَنٌ غَرِيبٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَهْلِ الْعِلْمِ","id":"telah menceritakan kepada kami [Abu Sa'id Al Asyaj] berkata; telah menceritakan kepada kami [Yunus bin Bukair] dari [Muhammad bin Ishaq] dari [Abdurrahman bin Al Aswad] dari [Ayahnya] dari [Abdullah bin Mas'ud] ia berkata; \"Ia berkata; \"Termasuk sunnah adalah menyembunyikan tasyahud.\" Abu Isa berkata; \"Hadits Ibnu Mas'ud ini derajatnya hasan gharib. Para ahli ilmu mengamalkan hadits ini.\""},"269":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ حَدَّثَنَا عَاصِمُ بْنُ كُلَيْبٍ الْجَرْمِيُّ عَنْ أَبِيهِ عَنْ ابْنِ حُجْرٍ قَالَقَدِمْتُ الْمَدِينَةَ قُلْتُ لَأَنْظُرَنَّ إِلَى صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا جَلَسَ يَعْنِي لِلتَّشَهُّدِ افْتَرَشَ رِجْلَهُ الْيُسْرَى وَوَضَعَ يَدَهُ الْيُسْرَى يَعْنِي عَلَى فَخِذِهِ الْيُسْرَى وَنَصَبَ رِجْلَهُ الْيُمْنَىقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَأَهْلِ الْكُوفَةِ وَابْنِ الْمُبَارَكِ","id":"telah menceritakan kepada kami [Abu Kuraib] berkata; telah menceritakan kepada kami [Abdullah bin Idris] berkata; telah menceritakan kepada kami ['Ashim bin Kulaib Al Jarmi] dari [Ayahnya] dari [Ibnu Hujr] ia berkata; \"Ketika aku tiba di Madinah, aku berkata; \"Sungguh, aku benar-benar akan melihat bagaimana Rasulullah shallallahu 'alaihi wasallam shalat. Ketika duduk tasyahud beliau membentangkan kaki kirinya dan meletakkan tangan kirinya -yakni di atas paha kirinya- serta menegakkan kaki kanannya.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Hadits ini diamalkan oleh kebanyakan para ahli ilmu. Ini adalah pendapat Sufyan Ats Tsauri, penduduk Kufah dan bin Al Mubarak.\""},"270":{"ar":"حَدَّثَنَا بُنْدَارٌ مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ الْمَدَنِيُّ حَدَّثَنِي عَبَّاسُ بْنُ سَهْلٍ السَّاعِدِيُّ قَالَاجْتَمَعَ أَبُو حُمَيْدٍ وَأَبُو أُسَيْدٍ وَسَهْلُ بْنُ سَعْدٍ وَمُحَمَّدُ بْنُ مَسْلَمَةَ فَذَكَرُوا صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو حُمَيْدٍ أَنَا أَعْلَمُكُمْ بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَلَسَ يَعْنِي لِلتَّشَهُّدِ فَافْتَرَشَ رِجْلَهُ الْيُسْرَى وَأَقْبَلَ بِصَدْرِ الْيُمْنَى عَلَى قِبْلَتِهِ وَوَضَعَ كَفَّهُ الْيُمْنَى عَلَى رُكْبَتِهِ الْيُمْنَى وَكَفَّهُ الْيُسْرَى عَلَى رُكْبَتِهِ الْيُسْرَى وَأَشَارَ بِأُصْبُعِهِ يَعْنِي السَّبَّابَةَقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَبِهِ يَقُولُ بَعْضُ أَهْلِ الْعِلْمِ وَهُوَ قَوْلُ الشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ قَالُوا يَقْعُدُ فِي التَّشَهُّدِ الْآخِرِ عَلَى وَرِكِهِ وَاحْتَجُّوا بِحَدِيثِ أَبِي حُمَيْدٍ قَالُوا يَقْعُدُ فِي التَّشَهُّدِ الْأَوَّلِ عَلَى رِجْلِهِ الْيُسْرَى وَيَنْصِبُ الْيُمْنَى","id":"telah menceritakan kepada kami [Bundar Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Abu 'Amir Al Aqadi] berkata; telah menceritakan kepada kami [Fulaih bin Sulaiman Al Madani] berkata; telah menceritakan kepadaku [Abbas bin Sahl As Sa'idi] ia berkata; \"Abu Humaid, Abu Usaid, Sahl bin Sa'd dan Muhammad bin Maslamah berkumpul, mereka menyebut-nyebut tentang shalat Rasulullah shallallahu 'alaihi wasallam. Lalu [Abu Humaid] berkata; \"Aku adalah orang yang paling tahu tentang shalatnya Rasulullah shallallahu 'alaihi wasallam daripada kalian semua. Rasulullah shallallahu 'alaihi wasallam duduk tasyahud seraya membentangkan kaki kirinya dan menghadapkan bagian depan kaki kananya ke arah kiblat, beliau meletakkan telapak tangan kanannya di atas lutut kanan dan telapak tangan kanan kiri di atas lutut kiri. Lalu berisyarat dengan jarinya, yakni jari telunjuk.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Sebagian ahli ilmu berpegangan dengan hadits ini. Ini adalah pendapat Imam Syafi'i, Ahmad dan Ishaq. Mereka berkata; \"Pada tasyahud akhir hendaknya seseorang duduk pada pangkal pahanya.\" Mereka berdalil dengan hadits Abu Humaid, mereka berkata; \"Pada tasyahud akhir hendaknya seseorang duduk di atas kaki kirinya dan menegakkan kaki kanannya.\""},"271":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ وَيَحْيَى بْنُ مُوسَى وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا جَلَسَ فِي الصَّلَاةِ وَضَعَ يَدَهُ الْيُمْنَى عَلَى رُكْبَتِهِ وَرَفَعَ إِصْبَعَهُ الَّتِي تَلِي الْإِبْهَامَ الْيُمْنَى يَدْعُو بِهَا وَيَدُهُ الْيُسْرَى عَلَى رُكْبَتِهِ بَاسِطَهَا عَلَيْهِقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ وَنُمَيْرٍ الْخُزَاعِيِّ وَأَبِي هُرَيْرَةَ وَأَبِي حُمَيْدٍ وَوَائِلِ بْنِ حُجْرٍ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ عُبَيْدِ اللَّهِ بْنِ عُمَرَ إِلَّا مِنْ هَذَا الْوَجْهِ وَالْعَمَلُ عَلَيْهِ عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ يَخْتَارُونَ الْإِشَارَةَ فِي التَّشَهُّدِ وَهُوَ قَوْلُ أَصْحَابِنَا","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] dan [Yahya bin Musa] dan beberapa orang mereka berkata; telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] berkata; \"Nabi shallallahu 'alaihi wasallam jika duduk di dalam shalat, beliau meletakkan tangan kanannya di atas lutut dan mengangkat jari sebelah ibu jari kanan -maksudnya jari telunjuk- dan berdo`a dengannya. Dan beliau juga meletakkan tangan kirinya di atas lutut dengan membentangkan jari-jarinya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abudllah Ibnu Az Zubair, Numair Al Khuza'I, Abu Hurairah, Abu Humaid dan Wa`il bin Hujr.\" Abu Isa berkata; \"Hadits Ibnu Umar ini derajatnya hasan gharib, kami tidak mengatahui hadits tersebut dari Ubaidullah bin Umar selain dari jalur ini. sebagian ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in mengamalkan hadits ini. mereka memilih untuk berisyarat dengan jari telunjuk ketika tasyahud. Ini adalah pendapat yang diambil oleh sahabat-sahabat kami.\""},"272":{"ar":"حَدَّثَنَا بُنْدَارٌ مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يُسَلِّمُ عَنْ يَمِينِهِ وَعَنْ يَسَارِهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِقَالَ وَفِي الْبَاب عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ وَابْنِ عُمَرَ وَجَابِرِ بْنِ سَمُرَةَ وَالْبَرَاءِ وَأَبِي سَعِيدٍ وَعَمَّارٍ وَوَائِلِ بْنِ حُجْرٍ وَعَدِيِّ بْنِ عَمِيرَةَ وَجَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ مَسْعُودٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَابْنِ الْمُبَارَكِ وَأَحْمَدَ وَإِسْحَقَ","id":"telah menceritakan kepada kami [Bundar Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, Bahwasanya beliau mengucapkan salam ke arah kanan dan kiri seraya mengucapkan: \"ASSALAAMU 'ALAIKUM WA RAHMATULLAH, ASSALAAMU 'ALAIKUM WA RAHMATULLAH (Semoga keselamatan dan rahmat Allah limpahkan kepadamu).\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Sa'd bin Abu Waqash, Ibnu Umar, Jabir bin Samrah, Al Bara`, Abu Sa'id, Ammar, Abu Wa`il bin Hujr, Adi bin Amirah, dan Jabir bin Abdullah.\" Abu Isa berkata; \"Hadits Ibnu Umar derajatnya hasan shahih. Banyak ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka yang mengamalkan hadits ini. ini adalah pendapat yang diambil oleh Sufyan Ats Tsauri, bin Al Mubarak, Ahmad dan Ishaq.\""},"273":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى النَّيْسَابُورِيُّ حَدَّثَنَا عَمْرُو بْنُ أَبِي سَلَمَةَ أَبُو حَفْصٍ التِّنِّيسِيُّ عَنْ زُهَيْرِ بْنِ مُحَمَّدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُسَلِّمُ فِي الصَّلَاةِ تَسْلِيمَةً وَاحِدَةً تِلْقَاءَ وَجْهِهِ يَمِيلُ إِلَى الشِّقِّ الْأَيْمَنِ شَيْئًاقَالَ وَفِي الْبَاب عَنْ سَهْلِ بْنِ سَعْدٍ قَالَ أَبُو عِيسَى وَحَدِيثُ عَائِشَةَ لَا نَعْرِفُهُ مَرْفُوعًا إِلَّا مِنْ هَذَا الْوَجْهِ قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ زُهَيْرُ بْنُ مُحَمَّدٍ أَهْلُ الشَّأْمِ يَرْوُونَ عَنْهُ مَنَاكِيرَ وَرِوَايَةُ أَهْلِ الْعِرَاقِ عَنْهُ أَشْبَهُ وَأَصَحُّ قَالَ مُحَمَّدٌ وَقَالَ أَحْمَدُ بْنُ حَنْبَلٍ كَأَنَّ زُهَيْرَ بْنَ مُحَمَّدٍ الَّذِي كَانَ وَقَعَ عِنْدَهُمْ لَيْسَ هُوَ هَذَا الَّذِي يُرْوَى عَنْهُ بِالْعِرَاقِ كَأَنَّهُ رَجُلٌ آخَرُ قَلَبُوا اسْمَهُ قَالَ أَبُو عِيسَى وَقَدْ قَالَ بِهِ بَعْضُ أَهْلِ الْعِلْمِ فِي التَّسْلِيمِ فِي الصَّلَاةِ وَأَصَحُّ الرِّوَايَاتِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسْلِيمَتَانِ وَعَلَيْهِ أَكْثَرُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ وَرَأَى قَوْمٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ تَسْلِيمَةً وَاحِدَةً فِي الْمَكْتُوبَةِ قَالَ الشَّافِعِيُّ إِنْ شَاءَ سَلَّمَ تَسْلِيمَةً وَاحِدَةً وَإِنْ شَاءَ سَلَّمَ تَسْلِيمَتَيْنِ","id":"telah menceritakan kepada kami [Muhammad bin Yahya An Naisaburi] berkata; telah menceritakan kepada kami ['Amru bin Abu Salamah Abu Hafsh At Tinnisi] dari [Zuhair bin Muhammad] dari [Hisyam bin Urwah] dari [Ayahnya] dari ['Aisyah] berkata; \"Rasulullah shallallahu 'alaihi wasallam salam dalam shalatnya hanya sekali salam ke arah mukanya sedikit condong ke sebelah kanan.\" Ia berkata; \"Dalam bab ini ada juga hadits dari Sahl bin Sa'd.\" Abu Isa berkata; \"Kami tidak mengetahui kemarfu'an hadits 'Aisyah kecuali dari jalur ini. Muhammad bin Isma'il berkata; \"Zuhair bin Muhammad adalah penduduk Syam, mereka meriwayatkan hadits hadits munkar darinya, sedangkan riwayat penduduk Irak yang berasal darinya lebih tepat dan lebih shahih.\" Muhammad berkata; \"Ahmad bin Hambal berkata; \"Sepertinya Zuhair bin Muhammad yang ada pada mereka bukanlah Zuhair yang hadits-haditsnya diambil oleh orang-orang Irak. Dan sepertinya ia adalah orang lain yang mereka ubah namanya.\" Abu Isa berkata; \"Sebagian ulama berpegangan dengan hadits ini kaitannya dengan salam dalam shalat. Namun riwayat yang paling shahih dari Nabi shallallahu 'alaihi wasallam adalah dua salam, dan ini diamalkan oleh kebanyakan ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang setelah mereka. Sedangkan sebagian sahabat Nabi shallallahu 'alaihi wasallam dan yang lain hanya dengan satu salam dalam shalat wajib. Imam Syafi'i berkata; \"Jika berkehendak ia boleh dengan satu salam atau dua salam.\""},"274":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ وَهِقْلُ بْنُ زِيَادٍ عَنْ الْأَوْزَاعِيِّ عَنْ قُرَّةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَحَذْفُ السَّلَامِ سُنَّةٌقَالَ عَلِيُّ بْنُ حُجْرٍ قَالَ عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ يَعْنِي أَنْ لَا يَمُدَّهُ مَدًّاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ الَّذِي يَسْتَحِبُّهُ أَهْلُ الْعِلْمِ وَرُوِيَ عَنْ إِبْرَاهِيمَ النَّخَعِيِّ أَنَّهُ قَالَ التَّكْبِيرُ جَزْمٌ وَالسَّلَامُ جَزْمٌ وَهِقْلٌ يُقَالُ كَانَ كَاتِبَ الْأَوْزَاعِيِّ","id":"telah menceritakan kepada kami [Ali bin Hujr] berkata; telah mengabarkan kepada kami [Abdullah bin Al Mubarak] dan [Hiql bin Ziyad] dari [Al Auza'i] dari [Qurrah bin Abdurrahman] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; \"Memendekkan salam adalah sunnah.\" Ali bin Hujr berkata; \"Abdullah bin Al Mubarak berkata; \"Yaitu tidak memanjangkannya.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Pendapat ini disukai (dipilih) oleh ahli ilmu.\" Dan telah diriwayatkan pula dari Ibrahim An Nakha'I, bahwasanya ia mengatakan, \"Takbir dan salam adalah mati (pendek).\" Dikatakan bahwa Hiql adalah penulis Al Auza'i.\""},"275":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَلَّمَ لَا يَقْعُدُ إِلَّا مِقْدَارَ مَا يَقُولُ اللَّهُمَّ أَنْتَ السَّلَامُ وَمِنْكَ السَّلَامُ تَبَارَكْتَ ذَا الْجَلَالِ وَالْإِكْرَامِحَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ وَأَبُو مُعَاوِيَةَ عَنْ عَاصِمٍ الْأَحْوَلِ بِهَذَا الْإِسْنَادِ نَحْوَهُ وَقَالَ تَبَارَكْتَ يَا ذَا الْجَلَالِ وَالْإِكْرَامِ قَالَ وَفِي الْبَاب عَنْ ثَوْبَانَ وَابْنِ عُمَرَ وَابْنِ عَبَّاسٍ وَأَبِي سَعِيدٍ وَأَبِي هُرَيْرَةَ وَالْمُغِيرَةِ بْنِ شُعْبَةَ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَى خَالِدٌ الْحَذَّاءُ هَذَا الْحَدِيثَ مِنْ حَدِيثِ عَائِشَةَ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ نَحْوَ حَدِيثِ عَاصِمٍ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقُولُ بَعْدَ التَّسْلِيمِ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ يُحْيِي وَيُمِيتُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ اللَّهُمَّ لَا مَانِعَ لِمَا أَعْطَيْتَ وَلَا مُعْطِيَ لِمَا مَنَعْتَ وَلَا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّ وَرُوِيَ عَنْهُ أَنَّهُ كَانَ يَقُولُ سُبْحَانَ رَبِّكَ رَبِّ الْعِزَّةِ عَمَّا يَصِفُونَ وَسَلَامٌ عَلَى الْمُرْسَلِينَ وَالْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ","id":"telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari ['Ashim Al Ahwal] dari [Abdullah bin Al Harits] dari ['Aisyah] ia berkata; \"Jika Rasulullah shallallahu 'alaihi wasallam telah selesai salam beliau tidak duduk kecuali sekadar ucapan: \"ALLAHUMMA ANTAS SALAAM WA MINKAS SALAAM DZAL JALAALI WAL IKRAAM (Ya Allah, Engkau adalah keselamatan dan dari-Mu keselamatan itu, Engkaulah pemberi berkah dan Dzat yang mempunyai keagungan dan kemuliaan).\" Telah menceritakan kepada kami [Hannad Ibnu As Sari] berkata; telah menceritakan kepada kami [Marwan bin Mu'awiyah Al Fazari] dan [Abu Mu'awiyah] dari ['Ashim Al Ahwal] dengan sanad yang serupa, beliau mengucapkan: \"TABAARAKTA YA DZAL JALAALI WAL IKRAM (Engkau Maha Pemberi berkah, wahai Dzat yang mempunyai keagungan dan kemuliaan).\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Tsauban, Ibnu Umar, Ibnu Abbas, Abu Sa'id, Abu Hurairah dan Al Mughirah bin Syu'bah.\" Abu Isa berkata; \"Hadits 'Aisyah ini derajatnya hasan shahih. [Khalid] juga telah meriwayatkan hadits ini dari hadits 'Aisyah dari [Abdullah bin Al Harits] sebagaimana hadits riwayat 'Ashim. Telah diriwayatkan dari Nabi shallallahu 'alaihi wasallam bahwasanya setelah salam beliau mengucapkan: \"LAA ILAAHA ILLAALLAH WAHDAHUU LAA SYARIIKALAH LAHUL MULKU WALAHUL HAMDU YUHYII WA YUMIT WA HUWA 'ALA KULLI SYAI'IN QADIIR, ALLAHUMMA LAA MAANI'A LIMA A'THAITA WA LAA MU'THIA LIMAA MANA'TA WA LAA YANFA'U DZAL JADDI MINKAL JADDU (Tidak ada Tuhan yang berhak untuk disembah selian Allah yang Maha Esa, tidak ada sekutu bagi-Nya. Baginya segala kekuasaan dan pujian. Dia yang menghidupkan dan mematikan. Dia Maha Kuasa atas segala sesuatu. Wahai Allah, tidak ada yang bisa mencegah apa yang Engkau berikan, serta tidak ada yang bisa memberi sesutau yang Engkau halangi, serta tidak bermanfaat kekayaan di sisi-Mu, karena hanya dari-Mu lah kekayaan).\" Diriwayatkan juga darinya bahwa Rasulullah mengucapkan: \"SUBHAANA RABBIKA RABBIL 'IZZATI 'AMMA YASHIFUUN WA SALAAMUN 'ALAL MURSALIIN WAL HAMDULILLAHI RABBIL 'ALAMIIN (Maha Suci Tuhanmu yang mempunyai keperkasaan dari apa yang mereka (orang-orang kafir) sifatkan. Kesejahteraan semoga dilimpahkan kepada para utusan Allah, dan segala puji bagi Allah, Rabb semesta alam).\""},"276":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ مُوسَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا الْأَوْزَاعِيُّ حَدَّثَنِي شَدَّادٌ أَبُو عَمَّارٍ حَدَّثَنِي أَبُو أَسْمَاءَ الرَّحَبِيُّ قَالَ حَدَّثَنِي ثَوْبَانُ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَنْصَرِفَ مِنْ صَلَاتِهِ اسْتَغْفَرَ اللَّهَ ثَلَاثَ مَرَّاتٍ ثُمَّ قَالَ اللَّهُمَّ أَنْتَ السَّلَامُ وَمِنْكَ السَّلَامُ تَبَارَكْتَ يَا ذَا الْجَلَالِ وَالْإِكْرَامِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو عَمَّارٍ اسْمُهُ شَدَّادُ بْنُ عَبْدِ اللَّهِ","id":"telah menceritakan kepada kami [Ahmad bin Muhammad bin Musa] berkata; telah menceritakan kepada kami [Abdullah bin Al Mubarak] berkata; telah mengabarkan kepada kami [Al Auza'i] berkata; telah menceritakan kepadaku [Syaddad Abu 'Ammar] berkata; telah menceritakan kepadaku [Abu Asma` Ar Rahabi] berkata; telah menceritakan kepadaku [Tsauban] pelayan Rasulullah shallallahu 'alaihi wasallam, ia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam ingin berlalu (pergi) dari shalatnya beliau beristighfar tiga kali. Setelah itu beliau mengucapkan: \"ALLAHUMMA ANTAS SALAAM WA MINKAS SALAAM TABAARAKTA YA DZAL JALAALI WAL IKRAAM (Ya Allah, Engkau adalah keselamatan dan dari-Mu keselamatan itu, Engkaulah pemberi berkah wahai Dzat yang mempunyai keagungan dan kemuliaan).\" Ia berkata; \"Hadits ini derajatnya hasan shahih. Abu 'Ammar namanya adalah Syaddad bin Abdullah.\""},"277":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ قَبِيصَةَ بْنِ هُلْبٍ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَؤُمُّنَا فَيَنْصَرِفُ عَلَى جَانِبَيْهِ جَمِيعًا عَلَى يَمِينِهِ وَعَلَى شِمَالِهِوَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَأَنَسٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى حَدِيثُ هُلْبٍ حَدِيثٌ حَسَنٌ وَعَلَيْهِ الْعَمَلُ عِنْدَ أَهْلِ الْعِلْمِ أَنَّهُ يَنْصَرِفُ عَلَى أَيِّ جَانِبَيْهِ شَاءَ إِنْ شَاءَ عَنْ يَمِينِهِ وَإِنْ شَاءَ عَنْ يَسَارِهِ وَقَدْ صَحَّ الْأَمْرَانِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيُرْوَى عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ أَنَّهُ قَالَ إِنْ كَانَتْ حَاجَتُهُ عَنْ يَمِينِهِ أَخَذَ عَنْ يَمِينِهِ وَإِنْ كَانَتْ حَاجَتُهُ عَنْ يَسَارِهِ أَخَذَ عَنْ يَسَارِهِ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak bin Harb] dari [Qabishah bin Hulb] dari [Ayahnya] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengimami kami shalat, lalu beliau berlalu dari dua sisi, kadang dari sisi kanan dan kadang dari sisi kiri.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin Mas'ud, Anas, Abdullah bin 'Amru dan Abu Hurairah.\" Abu Isa berkata; \"Hadits Hulb derajatnya hasan shahih. Hadits ini diamalkan oleh para ahli ilmu. Yakni, bahwsanya beliau pergi dari dua arah; kadang dari kanan dan kadang dari kiri, jika beliau berkehendak. Keduanya shahih dari Nabi shallallahu 'alaihi wasallam.\" Telah diriwayatkan pula dari Ali bin Abu Thalib bahwasanya ia berkata; \"Jika kepentingannya adalah dari arah kanan maka hendaklah ia pergi dari arah kanan, dan jika kepentingannya adalah dari arah kiri maka hendaklah ia pergi dari arah kiri.\""},"278":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ يَحْيَى بْنِ عَلِيِّ بْنِ يَحْيَى بْنِ خَلَّادِ بْنِ رَافِعٍ الزُّرَقِيِّ عَنْ جَدِّهِ عَنْ رِفَاعَةَ بْنِ رَافِعٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَمَا هُوَ جَالِسٌ فِي الْمَسْجِدِ يَوْمًا قَالَ رِفَاعَةُ وَنَحْنُ مَعَهُ إِذْ جَاءَهُ رَجُلٌ كَالْبَدَوِيِّ فَصَلَّى فَأَخَفَّ صَلَاتَهُ ثُمَّ انْصَرَفَ فَسَلَّمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْكَ فَارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَرَجَعَ فَصَلَّى ثُمَّ جَاءَ فَسَلَّمَ عَلَيْهِ فَقَالَ وَعَلَيْكَ فَارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَفَعَلَ ذَلِكَ مَرَّتَيْنِ أَوْ ثَلَاثًا كُلُّ ذَلِكَ يَأْتِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيُسَلِّمُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَقُولُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْكَ فَارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَخَافَ النَّاسُ وَكَبُرَ عَلَيْهِمْ أَنْ يَكُونَ مَنْ أَخَفَّ صَلَاتَهُ لَمْ يُصَلِّ فَقَالَ الرَّجُلُ فِي آخِرِ ذَلِكَ فَأَرِنِي وَعَلِّمْنِي فَإِنَّمَا أَنَا بَشَرٌ أُصِيبُ وَأُخْطِئُ فَقَالَ أَجَلْ إِذَا قُمْتَ إِلَى الصَّلَاةِ فَتَوَضَّأْ كَمَا أَمَرَكَ اللَّهُ ثُمَّ تَشَهَّدْ وَأَقِمْ فَإِنْ كَانَ مَعَكَ قُرْآنٌ فَاقْرَأْ وَإِلَّا فَاحْمَدْ اللَّهَ وَكَبِّرْهُ وَهَلِّلْهُ ثُمَّ ارْكَعْ فَاطْمَئِنَّ رَاكِعًا ثُمَّ اعْتَدِلْ قَائِمًا ثُمَّ اسْجُدْ فَاعْتَدِلْ سَاجِدًا ثُمَّ اجْلِسْ فَاطْمَئِنَّ جَالِسًا ثُمَّ قُمْ فَإِذَا فَعَلْتَ ذَلِكَ فَقَدْ تَمَّتْ صَلَاتُكَ وَإِنْ انْتَقَصْتَ مِنْهُ شَيْئًا انْتَقَصْتَ مِنْ صَلَاتِكَ قَالَ وَكَانَ هَذَا أَهْوَنَ عَلَيْهِمْ مِنْ الْأَوَّلِ أَنَّهُ مَنْ انْتَقَصَ مِنْ ذَلِكَ شَيْئًا انْتَقَصَ مِنْ صَلَاتِهِ وَلَمْ تَذْهَبْ كُلُّهَاقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَعَمَّارِ بْنِ يَاسِرٍ قَالَ أَبُو عِيسَى حَدِيثُ رِفَاعَةَ بْنِ رَافِعٍ حَدِيثٌ حَسَنٌ وَقَدْ رُوِيَ عَنْ رِفَاعَةَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ","id":"telah menceritakan kepada kami [Ali bin Hujr] berkata; telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Yahya bin Ali bin Yahya bin Khallad bin Rafi' Az Zuraqi] dari [Kakeknya] dari [Rifa'ah bin Rafi'] berkata; \"Ketika pada suatu hari Rasulullah shallallahu 'alaihi wasallam duduk bersama kami -Rifa'ah berkata; \"Kami sedang bersama beliau, \"- seorang laki-laki dusun datang kepada beliau, ia lalu shalat dan memperingan shalatnya. Setelah itu ia berlalu dan mengucapkan salam kepada Nabi shallallahu 'alaihi wasallam. Maka Nabi shallallahu 'alaihi wasallam pun bersabda kepadanya: \"Kembali dan shalatlah lagi, karena sesungguhnya engkau belum shalat!\" lalu ia mengerjakan shalat lagi dua atau tiga kali, setiap kali itu pula ia datang dan mengucapkan salam kepada Nabi shallallahu 'alaihi wasallam. Namun Nabi shallallahu 'alaihi wasallam bersabda: \"Kembali dan shalatlah lagi, karena sesungguhnya engkau belum shalat!\" maka orang-orang pun menjadi takut dan kawatir bahwa orang yang meremehkan shalat berarti belum shalat. Akhirnya laki-laki dusun itu berkata; \"Beritahukan dan ajarilah aku, karena aku hanyalah manusia biasa, kadang benar dan kadang salah, \" beliau lalu bersabda: \"Benar, jika engkau ingin shalat maka berwudlulah sebagaimana yang Allah perintahkan kepadamu, lalu bertasyahud (do`a setelah wudlu) dan dirikanlah shalat. Jika engkau mempunyai hafalan Al Qur`an maka bacalah, jika tidak maka bacalah tahmid, takbir dan tahlil. Setelah itu rukuklah dengan tenang, lalu berdiri dan sujudlah dengan tenang, setelah itu berdiri. Jika engkau kerjakan seperti itu maka sempurnalah shalatmu, namun jika engkau kurangi maka kuranglah shalatmu.\" Ia (perawi) berkata; \"Hal ini lebih ringan dari yang pertama, yakni barangsiapa mengurangi sesuatu dari hal tersebut, maka berkuranglah nilai shalatnya, namun tidak hilang semuanya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Hurairah dan Ammar bin Yasir.\" Abu Isa berkata; \"Hadits Rifa'ah ini derajatnya hasan shahih. Hadits ini juga telah diriwayatkan dari Rifa'ah dengan jalur lain.\""},"279":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ أَخْبَرَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ الْمَسْجِدَ فَدَخَلَ رَجُلٌ فَصَلَّى ثُمَّ جَاءَ فَسَلَّمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَدَّ عَلَيْهِ السَّلَامَ فَقَالَ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَرَجَعَ الرَّجُلُ فَصَلَّى كَمَا كَانَ صَلَّى ثُمَّ جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ عَلَيْهِ فَرَدَّ عَلَيْهِ السَّلَامَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ حَتَّى فَعَلَ ذَلِكَ ثَلَاثَ مِرَارٍ فَقَالَ لَهُ الرَّجُلُ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا أُحْسِنُ غَيْرَ هَذَا فَعَلِّمْنِي فَقَالَ إِذَا قُمْتَ إِلَى الصَّلَاةِ فَكَبِّرْ ثُمَّ اقْرَأْ بِمَا تَيَسَّرَ مَعَكَ مِنْ الْقُرْآنِ ثُمَّ ارْكَعْ حَتَّى تَطْمَئِنَّ رَاكِعًا ثُمَّ ارْفَعْ حَتَّى تَعْتَدِلَ قَائِمًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ ارْفَعْ حَتَّى تَطْمَئِنَّ جَالِسًا وَافْعَلْ ذَلِكَ فِي صَلَاتِكَ كُلِّهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ وَقَدْ رَوَى ابْنُ نُمَيْرٍ هَذَا الْحَدِيثَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ وَلَمْ يَذْكُرْ فِيهِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ وَرِوَايَةُ يَحْيَى بْنِ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ أَصَحُّ وَسَعِيدٌ الْمَقْبُرِيُّ قَدْ سَمِعَ مِنْ أَبِي هُرَيْرَةَ وَرَوَى عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ وَأَبُو سَعِيدٍ الْمَقْبُرِيُّ اسْمُهُ كَيْسَانُ وَسَعِيدٌ الْمَقْبُرِيُّ يُكْنَى أَبَا سَعْدٍ وَكَيْسَانُ عَبْدٌ كَانَ مُكَاتَبًا لِبَعْضِهِمْ","id":"telah menceritakan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] berkata; telah menceritakan kepada kami [Ubaidullah bin Umar] berkata; telah mengabarkan kepadaku [Sa'id bin Abu Sa'id] dari [Ayahnya] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam masuk ke dalam masjid. Lalu masuklah seorang laki-laki dan mengerjakan shalat, setelah itu ia datang seraya mengucapkan salam kepada Nabi shallallahu 'alaihi wasallam. Beliau lalu menjawab salamnya dan bersabda: \"Kembali dan shalatlah, sesungguhnya engkau belum shalat!\" lalu laki-laki itu kembali dan shalat sebagaimana yang ia lakukan, setelah itu ia datang dan mengucapkan salam kepada Nabi shallallahu 'alaihi wasallam. Beliau lalu menjawab salamnya, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepada: \"Kembali dan shalatlah, sesungguhnya engkau belum shalat!\" hingga laki-laki itu mengulanginya sampai tiga kali, setelah itu ia berkata kepada Rasulullah, \"Demi Dzat yang mengutusmu dengan kebenaran, aku tidak bisa shalat dengan baik kecuali seperti ini, untuk itu ajarilah aku!\" beliau pun bersabda: \"Jika engkau berdiri shalat, maka bertakbirlah. Setelah itu bacalah Al Qur`an yang mudah kamu baca, lalu rukuklah dengan tuma'ninah (tenang) dan berdiri lagi hingga benar-benar tegak. Setelah itu sujudlah dengan tuma'ninah dan bangun (duduk) hingga benar-benar tegak. Lakukanlah seperti itu pada semua shalatmu.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Ia berkata; \" [Ibnu Numair] juga telah meriwayatkan hadits ini dari [Ubaidullah bin Umar] dari [Sa'id Al Maqburi] dari [Abu Hurairah] hanya saja di dalamnya ia tidak menyebutkan dari Abu Hurairah. Dan riwayat Yahya bin Sa'id dari Abdullah bin Umar lebih shahih. Sedangkan Sa'id Al Maqburi telah mendengar hadits ini dari Abu Hurairah, ia meriwayatkan dari ayahnya, dari Abu Hurairah.\" Nama Abu Sa'id Al Maqburi adalah Kaisan. Dan Sa'id Al Maqburi dijuluki dengan nama Abu Sa'd. Kaisan dahulu adalah termasuk budak mereka yang memerdekakan dirinya (dengan menebus).\""},"280":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرِو بْنِ عَطَاءٍ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ قَالَسَمِعْتُهُ وَهُوَ فِي عَشَرَةٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدُهُمْ أَبُو قَتَادَةَ بْنُ رِبْعِيٍّ يَقُولُ أَنَا أَعْلَمُكُمْ بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا مَا كُنْتَ أَقْدَمَنَا لَهُ صُحْبَةً وَلَا أَكْثَرَنَا لَهُ إِتْيَانًا قَالَ بَلَى قَالُوا فَاعْرِضْ فَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ إِلَى الصَّلَاةِ اعْتَدَلَ قَائِمًا وَرَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ فَإِذَا أَرَادَ أَنْ يَرْكَعَ رَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ ثُمَّ قَالَ اللَّهُ أَكْبَرُ وَرَكَعَ ثُمَّ اعْتَدَلَ فَلَمْ يُصَوِّبْ رَأْسَهُ وَلَمْ يُقْنِعْ وَوَضَعَ يَدَيْهِ عَلَى رُكْبَتَيْهِ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ وَرَفَعَ يَدَيْهِ وَاعْتَدَلَ حَتَّى يَرْجِعَ كُلُّ عَظْمٍ فِي مَوْضِعِهِ مُعْتَدِلًا ثُمَّ أَهْوَى إِلَى الْأَرْضِ سَاجِدًا ثُمَّ قَالَ اللَّهُ أَكْبَرُ ثُمَّ جَافَى عَضُدَيْهِ عَنْ إِبْطَيْهِ وَفَتَخَ أَصَابِعَ رِجْلَيْهِ ثُمَّ ثَنَى رِجْلَهُ الْيُسْرَى وَقَعَدَ عَلَيْهَا ثُمَّ اعْتَدَلَ حَتَّى يَرْجِعَ كُلُّ عَظْمٍ فِي مَوْضِعِهِ مُعْتَدِلًا ثُمَّ أَهْوَى سَاجِدًا ثُمَّ قَالَ اللَّهُ أَكْبَرُ ثُمَّ ثَنَى رِجْلَهُ وَقَعَدَ وَاعْتَدَلَ حَتَّى يَرْجِعَ كُلُّ عَظْمٍ فِي مَوْضِعِهِ ثُمَّ نَهَضَ ثُمَّ صَنَعَ فِي الرَّكْعَةِ الثَّانِيَةِ مِثْلَ ذَلِكَ حَتَّى إِذَا قَامَ مِنْ السَّجْدَتَيْنِ كَبَّرَ وَرَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ كَمَا صَنَعَ حِينَ افْتَتَحَ الصَّلَاةَ ثُمَّ صَنَعَ كَذَلِكَ حَتَّى كَانَتْ الرَّكْعَةُ الَّتِي تَنْقَضِي فِيهَا صَلَاتُهُ أَخَّرَ رِجْلَهُ الْيُسْرَى وَقَعَدَ عَلَى شِقِّهِ مُتَوَرِّكًا ثُمَّ سَلَّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ وَمَعْنَى قَوْلِهِ وَرَفَعَ يَدَيْهِ إِذَا قَامَ مِنْ السَّجْدَتَيْنِ يَعْنِي قَامَ مِنْ الرَّكْعَتَيْنِ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَالْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ الْحُلْوَانِيُّ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا أَبُو عَاصِمٍ النَّبِيلُ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرِو بْنِ عَطَاءٍ قَال سَمِعْتُ أَبَا حُمَيْدٍ السَّاعِدِيَّ فِي عَشَرَةٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ أَبُو قَتَادَةَ بْنُ رِبْعِيٍّ فَذَكَرَ نَحْوَ حَدِيثِ يَحْيَى بْنِ سَعِيدٍ بِمَعْنَاهُ وَزَادَ فِيهِ أَبُو عَاصِمٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ هَذَا الْحَرْفَ قَالُوا صَدَقْتَ هَكَذَا صَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عِيسَى زَادَ أَبُو عَاصِمٍ الضَّحَّاكُ بْنُ مَخْلَدٍ فِي هَذَا الْحَدِيثِ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ هَذَا الْحَرْفَ قَالُوا صَدَقْتَ هَكَذَا صَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad bin Al Mutsanna] mereka berkata; telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] berkata; telah menceritakan kepada kami [Abdul Hamid bin Ja'far] berkata; telah menceritakan kepada kami [Muhammad bin 'Amru bin 'Atha`] dari [Abu Humaid As Sa'idi] ia berkata; \"Aku mendengarnya -waktu itu ia berada di antara sepuluh sahabat Nabi shallallahu 'alaihi wasallam, di antaranya adalah Abu Qatadah bin Rib'i- ia berkata; \"Aku adalah orang yang paling tahu dengan shalat Nabi shallallahu 'alaihi wasallam di antara kalian.\" Mereka berkata; \"Engkau bukan orang yang lebih dulu menjadi sahabat beliau dan tidak lebih banyak mendatanginya ketimbang kami!\" ia berkata; \"Benar, \" mereka berkata; \"Maka ceritakanlah!\" ia berkata; \"Rasulullah shallallahu 'alaihi wasallam jika berdiri shalat selalu tegak dan berimbang lalu mengangkat kedua tangannya sejajar dengan kedua bahunya. Jika beliau ingin rukuk, maka beliau kembali mengangkat kedua tangannya sejajar dengan kedua bahunya dan mengucapkan ALLAHU AKBAR. Lalu rukuk dan berimbang, tidak mengangkat atau menundukkan kepalanya, lalu meletakkan kedua tangannya pada lutut. Setelah itu beliau mengucapkan SAMI'A ALLAHU LIMAN HAMIDAH seraya mengangkat kedua tangannya secara berimbang hingga setiap tulang kembali ke tempatnya. Kemudian beliau sujud dengan diiringi ucapan ALLAHU AKBAR, beliau merenggangkan kedua tangannya menjauh dari ketiak dan melenturkan jari-jari kakinya. Beliau lalu melipat kaki kirinya dan duduk di atasnya secara berimbang hingga setiap tulang kembali ke tempatnya. Setelah itu beliau kembali sujud seraya mengucapkan ALLAHU AKBAR, lalu melipat kaki kirinya dan duduk dengan seimbang hingga setiap tulang kembali ke tempatnya. Setelah itu beliau bangkit dan melakukan seperti itu pada rakaat yang kedua. Hingga ketika beliau bangkit dari dua sujud, beliau mengangkat kedua tangannya sejajar dengan kedua bahu sebagimana ketika membuka shalat (takbiratul ihram). Beliau lalu melakukan seperti itu hingga rakaat yang terakhir, beliau melipat kaki kirinya dan duduk tawaruk (duduk dengan menempelkan pantat pada lantai) kemudian mengucapkan salam.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Ia berkata; \"Maksud dari ucapannya, \"Hingga ketika beliau bangkit dari dua sujud, beliau mengangkat kedua tangannya, \" yakni bangun dari dua rakaat shalat.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Al Hasan bin Ali Al Khallal Al Hulwani] dan selainnya, mereka berkata; telah menceritakan kepada kami [Abu 'Ashim An Nabil] berkata; telah menceritakan kepada kami [Abdul Hamid bin Ja'far] berkata; telah menceritakan kepada kami [Muhammad bin 'Amru bin 'Atha`] berkata; aku mendengar [Abu Humaid As Sa'idi] yang berada di antara sepuluh sahabat Nabi shallallahu 'alaihi wasallam yang di antaranya adalah [Abu Qatadah bin Rib'i], lalu ia menyebutkan sebagaimana hadits Yahya bin Sa'id secara makna. Dan dalam hadits tersebut ia menahbahkan; (dari Abu 'Ashim dari Abdul Hamid bin Ja'far dengan huruf ini). Mereka berkata; \"Engkau benar, demikianlah Nabi shallallahu 'alaihi wasallam shalat.\" Abu Isa berkata; \"Abu 'Ashim Adl Dlahhak bin Makhlad menambahkan dalam hadits ini; dari Abdul Hamid bin Ja'far, dengan huruf ini. Mereka berkata; \"Engkau benar, demikianlah Nabi shallallahu 'alaihi wasallam shalat.\""},"281":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ مِسْعَرٍ وَسُفْيَانَ عَنْ زِيَادِ بْنِ عَلَاقَةَ عَنْ عَمِّهِ قُطْبَةَ بْنِ مَالِكٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْفَجْرِ{ وَالنَّخْلَ بَاسِقَاتٍ }فِي الرَّكْعَةِ الْأُولَىقَالَ وَفِي الْبَاب عَنْ عَمْرِو بْنِ حُرَيْثٍ وَجَابِرِ بْنِ سَمُرَةَ وَعَبْدِ اللَّهِ بْنِ السَّائِبِ وَأَبِي بَرْزَةَ وَأُمِّ سَلَمَةَ قَالَ أَبُو عِيسَى حَدِيثُ قُطْبَةَ بْنِ مَالِكٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَرُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَرَأَ فِي الصُّبْحِ بِالْوَاقِعَةِ وَرُوِيَ عَنْهُ أَنَّهُ كَانَ يَقْرَأُ فِي الْفَجْرِ مِنْ سِتِّينَ آيَةً إِلَى مِائَةٍ وَرُوِيَ عَنْهُ أَنَّهُ قَرَأَ{ إِذَا الشَّمْسُ كُوِّرَتْ }وَرُوِي عَنْ عُمَرَ أَنَّهُ كَتَبَ إِلَى أَبِي مُوسَى أَنْ اقْرَأْ فِي الصُّبْحِ بِطِوَالِ الْمُفَصَّلِ قَالَ أَبُو عِيسَى وَعَلَى هَذَا الْعَمَلُ عِنْدَ أَهْلِ الْعِلْمِ وَبِهِ قَالَ سُفْيَانُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Waki'] dari [Mis'ar] dan [Sufyan] dari [Ziyad bin Alaqah] dari pamannya [Quthbah bin Malik] ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam membaca: \"WAN-NAKHLA BAASIQAT (dan pohon kurma yang tinggi-tinggi) pada shalat subuh di rakaat pertama.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari 'Amru bin Huraits, Jabir bin Samrah, Abdullah bin As Sa`ib, Abu Barzah dan Ummu Salamah.\" Abu Isa berkata; \"Hadits Quthbah bin Malik derajatnya hasan shahih. Diriwayatkan dari Nabi shallallahu 'alaihi wasallam bahwa beliau pada shalat subuh mambaca surat Al Waqi'ah.\" Dan telah diriwayatkan pula darinya bahwa Nabi membaca; IDZASY SYAMSU KUWWIRAT. Dan diriwayatkan pula dari Umar bahwanya ia pernah menulis surat kepada Abu Musa agar membaca surat-surat yang panjang dalam shalat subuh. Abu Isa berkata; \"Dalam hal ini para ulama sepakat untuk mengamalkannya.\" Pendapat ini diambil oleh Sufyan Ats Tsauri, bin Al Mubarak dan Syafi'i.\""},"282":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ بِالسَّمَاءِ ذَاتِ الْبُرُوجِ وَالسَّمَاءِ وَالطَّارِقِ وَشِبْهِهِمَاقَالَ وَفِي الْبَاب عَنْ خَبَّابٍ وَأَبِي سَعِيدٍ وَأَبِي قَتَادَةَ وَزَيْدِ بْنِ ثَابِتٍ وَالْبَرَاءِ بْنِ عَازِبٍ قَالَ أَبُو عِيسَى حَدِيثُ جَابِرِ بْنِ سَمُرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَرَأَ فِي الظُّهْرِ قَدْرَ تَنْزِيلِ السَّجْدَةِ وَرُوِيَ عَنْهُ أَنَّهُ كَانَ يَقْرَأُ فِي الرَّكْعَةِ الْأُولَى مِنْ الظُّهْرِ قَدْرَ ثَلَاثِينَ آيَةً وَفِي الرَّكْعَةِ الثَّانِيَةِ خَمْسَ عَشْرَةَ آيَةً وَرُوِي عَنْ عُمَرَ أَنَّهُ كَتَبَ إِلَى أَبِي مُوسَى أَنْ اقْرَأْ فِي الظُّهْرِ بِأَوْسَاطِ الْمُفَصَّلِ وَرَأَى بَعْضُ أَهْلِ الْعِلْمِ أَنَّ الْقِرَاءَةَ فِي صَلَاةِ الْعَصْرِ كَنَحْوِ الْقِرَاءَةِ فِي صَلَاةِ الْمَغْرِبِ يَقْرَأُ بِقِصَارِ الْمُفَصَّلِ وَرُوِي عَنْ إِبْرَاهِيمَ النَّخَعِيِّ أَنَّهُ قَالَ تَعْدِلُ صَلَاةُ الْعَصْرِ بِصَلَاةِ الْمَغْرِبِ فِي الْقِرَاءَةِ و قَالَ إِبْرَاهِيمُ تُضَاعَفُ صَلَاةُ الظُّهْرِ عَلَى صَلَاةِ الْعَصْرِ فِي الْقِرَاءَةِ أَرْبَعَ مِرَارٍ","id":"telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Hammad bin Salamah] dari [Simak bin Harb] dari [Jabir bin Samrah] berkata; \"Rasulullah shallallahu 'alaihi wasallam dalam shalat zhuhur dan asar membaca WAS SAMA`I DZATUL BURUJ dan WAS SAMA`I WATH THARIQ dan yang serupa dengan keduanya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Khabbab, Abu Sa'id, Abu Qatadah, Zaid bin Tsabit dan Al Bara` bin 'Azib.\" Abu Isa berkata; \"Hadits Jabir bin Samrah ini derajatnya hasan shahih. Telah diriwayatkan dari Nabi shallallahu 'alaihi wasallam bahwa beliau pada shalat zhuhur membaca surat yang sebanding dengan surat Tanzil (As Sajadah). Dan diriwayatkan pula darinya bahwa Nabi shallallahu 'alaihi wasallam di rakaat pertama pada shalat zhuhur membaca sekadar tiga puluh ayat. Sedangkan pada rakaat kedua sekadar lima belas ayat. Dan diriwayatkan dari Umar, bahwa ia pernah surat kepada Abu Musa agar membaca ia membaca surat-surat yang sedang pada shalat zhuhur. Sedangkan sebagian ahli ilmu berpendapat, bahwa bacaan pada shalat asar seperti bacaan pada shalat maghrib, yakni membaca dengan surat-surat pendek. Telah diriwayatkan dari Ibrahim An Nakha'I bahwa ia berkata; \"Bacaan pada shalat asar dan maghrib sebanding.\" Ibrahim berkata lagi, \"Bacaan pada shalat zhuhur panjangnya empat kali dari shalat asar.\""},"283":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ أُمِّهِ أُمِّ الْفَضْلِ قَالَتْخَرَجَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَاصِبٌ رَأْسَهُ فِي مَرَضِهِ فَصَلَّى الْمَغْرِبَ فَقَرَأَ بِالْمُرْسَلَاتِ قَالَتْ فَمَا صَلَّاهَا بَعْدُ حَتَّى لَقِيَ اللَّهَقَالَ وَفِي الْبَاب عَنْ جُبَيْرِ بْنِ مُطْعِمٍ وَابْنِ عُمَرَ وَأَبِي أَيُّوبَ وَزَيْدِ بْنِ ثَابِتٍ قَالَ أَبُو عِيسَى حَدِيثُ أُمِّ الْفَضْلِ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَرَأَ فِي الْمَغْرِبِ بِالْأَعْرَافِ فِي الرَّكْعَتَيْنِ كِلْتَيْهِمَا وَرُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَرَأَ فِي الْمَغْرِبِ بِالطُّورِ وَرُوِيَ عَنْ عُمَرَ أَنَّهُ كَتَبَ إِلَى أَبِي مُوسَى أَنْ اقْرَأْ فِي الْمَغْرِبِ بِقِصَارِ الْمُفَصَّلِ وَرُوِيَ عَنْ أَبِي بَكْرٍ الصِّدِّيقِ أَنَّهُ قَرَأَ فِي الْمَغْرِبِ بِقِصَارِ الْمُفَصَّلِ قَالَ وَعَلَى هَذَا الْعَمَلُ عِنْدَ أَهْلِ الْعِلْمِ وَبِهِ يَقُولُ ابْنُ الْمُبَارَكِ وَأَحْمَدُ وَإِسْحَقُ و قَالَ الشَّافِعِيُّ وَذَكَرَ عَنْ مَالِكٍ أَنَّهُ كَرِهَ أَنْ يُقْرَأَ فِي صَلَاةِ الْمَغْرِبِ بِالسُّوَرِ الطِّوَالِ نَحْوَ الطُّورِ وَالْمُرْسَلَاتِ قَالَ الشَّافِعِيُّ لَا أَكْرَهُ ذَلِكَ بَلْ أَسْتَحِبُّ أَنْ يُقْرَأَ بِهَذِهِ السُّوَرِ فِي صَلَاةِ الْمَغْرِبِ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Muhammad bin Ishaq] dari [Az Zuhri] dari [Ubaidullah bin Abdullah bin Utbah] dari [Ibnu Abbas] dari ibunya [Ummul Fadll] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam keluar menamui kami sedang kepala beliau terikat balutan karena sakit, beliau lalu shalat maghrib dan membaca surat Al Mursalat.\" Ummu Fadll berkata; \"Setelah itu beliau tidak shalat lagi hingga beliau berjumpa dengan Allah.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Jubair bin Muth'im, Ibnu Umar, Abu Ayyub dan Zaid bin Tsabit.\" Abu Isa berkata; \"Hadits Ummu Fadll derajatnya hasah shahih. Diriwayatkan dari Nabi shallallahu 'alaihi wasallam bahwa beliau membaca surat Al A'raf pada shalat maghrib di rakaat pertama dan kedua. Dan diriwayatkan pula dari Nabi shallallahu 'alaihi wasallam bahwa beliau membaca surat Ath Thur.\" Dan diriwayatkan dari Umar bahwa ia pernah menulis surat kepada Abu Musa agar membaca surat-surat pendek dalam shalat maghrib. Dan diriwayatkan dari Abu Bakar bahwa ia membaca surat-surat pendek dalam shalat maghrib. Ia berkata; \"Para ahli ilmu mengamalkan hadits ini. Pendapat ini pula yang diambil oleh bin Al Mubarak, Ahmad dan Ishaq.\" Syafi'i berkata; \"Diriwayatkan dari Malik, bahwa ia memakruhkan membaca surat-surat panjang dalam shalat maghrib semisal Ath Thur dan Al Mursalat.\" Syafi'i berkata lagi, \"Aku tidak memakruhkannya, bahkan aku suka jika surat itu dibaca dalam shalat maghrib.\""},"284":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ الْخُزَاعِيُّ الْبَصْرِيُّ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا حُسَيْنُ بْنُ وَاقِدٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْعِشَاءِ الْآخِرَةِ بِالشَّمْسِ وَضُحَاهَا وَنَحْوِهَا مِنْ السُّوَرِقَالَ وَفِي الْبَاب عَنْ الْبَرَاءِ بْنِ عَازِبٍ وَأَنَسٍ قَالَ أَبُو عِيسَى حَدِيثُ بُرَيْدَةَ حَدِيثٌ حَسَنٌ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَرَأَ فِي الْعِشَاءِ الْآخِرَةِ بِالتِّينِ وَالزَّيْتُونِ وَرُوِيَ عَنْ عُثْمَانَ بْنِ عَفَّانَ أَنَّهُ كَانَ يَقْرَأُ فِي الْعِشَاءِ بِسُوَرٍ مِنْ أَوْسَاطِ الْمُفَصَّلِ نَحْوِ سُورَةِ الْمُنَافِقِينَ وَأَشْبَاهِهَا وَرُوِيَ عَنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ أَنَّهُمْ قَرَءُوا بِأَكْثَرَ مِنْ هَذَا وَأَقَلَّ فَكَأَنَّ الْأَمْرَ عِنْدَهُمْ وَاسِعٌ فِي هَذَا وَأَحْسَنُ شَيْءٍ فِي ذَلِكَ مَا رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَرَأَ بِالشَّمْسِ وَضُحَاهَا وَالتِّينِ وَالزَّيْتُونِ","id":"telah menceritakan kepada kami [Abdah bin Abdullah Al Khuza'i Al Bashri] berkata; telah menceritakan kepada kami [Zaid bin Al Hubab] berkata; telah menceritakan kepada kami [Husain bin Waqid] dari [Abdullah bin Buraidah] dari [Ayahnya] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam dalam shalat isya` yang akhir membaca WASY SYAMSI WA DLHUHAHA dan surat-surat yang semisal.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Al Bara` bin 'Azib dan Anas.\" Abu Isa berkata; \"Hadits Buraidah ini derajatnya hasan. Diriwayatkan dari Nabi shallallahu 'alaihi wasallam bahwa beliau dalam shalat isya` yang akhir membaca WATTINI WAZZAITUN. Diriwayatkan dari Utsman bin 'Affan, dalam shalat isya` ia membaca surat-surat yang sedang semisal surat Al Munafikun dan surat-surat yang semisal.\" Telah diriwayatkan pula dari sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in bahwa mereka kadang membaca surat yang lebih panjang dan kadang dengan surat yang lebih pendek, seakan-akan perkara ini sangat fleksibel bagi mereka. Namun yang lebih baik adalah yang diriwayatkan dari Nabi shallallahu 'alaihi wasallam, beliau membaca WASY SYAMSI WA DLUHAHA dan WATTIINI WAZZAITUUN.\""},"285":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ الْأَنْصَارِيِّ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ فِي الْعِشَاءِ الْآخِرَةِ بِالتِّينِ وَالزَّيْتُونِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Yahya bin Sa'id Al Asnhari] dari [Adi bin Tsabit] dari [Al Bara` bin Azib] berkata; \"Nabi shallallahu 'alaihi wasallam dalam shalat siya` yang akhir membaca WATTIINI WAZZAITUUN.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\""},"286":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مَكْحُولٍ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ فَثَقُلَتْ عَلَيْهِ الْقِرَاءَةُ فَلَمَّا انْصَرَفَ قَالَ إِنِّي أَرَاكُمْ تَقْرَءُونَ وَرَاءَ إِمَامِكُمْ قَالَ قُلْنَا يَا رَسُولَ اللَّهِ إِي وَاللَّهِ قَالَ فَلَا تَفْعَلُوا إِلَّا بِأُمِّ الْقُرْآنِ فَإِنَّهُ لَا صَلَاةَ لِمَنْ لَمْ يَقْرَأْ بِهَاقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَعَائِشَةَ وَأَنَسٍ وَأَبِي قَتَادَةَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى حَدِيثُ عُبَادَةَ حَدِيثٌ حَسَنٌ وَرَوَى هَذَا الْحَدِيثَ الزُّهْرِيُّ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا صَلَاةَ لِمَنْ لَمْ يَقْرَأْ بِفَاتِحَةِ الْكِتَابِ قَالَ وَهَذَا أَصَحُّ وَالْعَمَلُ عَلَى هَذَا الْحَدِيثِ فِي الْقِرَاءَةِ خَلْفَ الْإِمَامِ عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَهُوَ قَوْلُ مَالِكِ بْنِ أَنَسٍ وَابْنِ الْمُبَارَكِ وَالشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ يَرَوْنَ الْقِرَاءَةَ خَلْفَ الْإِمَامِ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Muhammad bin Ishaq] dari [Makhul bin Ishaq] dari [Mahmud bin Ar Rabi'] dari [Ubadah bin Ash Shamit] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat subuh, kemudian nampak berat bagi beliau untuk membaca (ayat-ayat). Setelah selesai shalat beliau bersabda: \"Aku mengetahui bahwa kalian membaca ayat-ayat di belakangku, \" Ubadah bin Ash Shamit berkata; \"Kami berkata; \"Demi Allah, benar wahai Rasulullah.\" Beliau bersabda: \"Janganlah kalian lakukan kecuali untuk membaca surat Al fatihah, sebab shalat seseorang tidak sah tanpa membacanya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Hurairah, 'Aisyah, Anas, Abu Qatadah dan Abdullah bin 'Amru.\" Abu Isa berkata; \"Hadits Ubadah ini derajatnya hasan. [Az Zuhri] telah meriwayatkan hadits ini dari [Mahmud bin Ar Rabi'] dari [Ubadah bin Ash Shamit] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada shalat bagi orang yang tidak membaca Fatihatul Kitab (Al Fatihah).\" Ia berkata; \"Hadits ini lebih shahih. Banyak ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan tabi'in yang mengamalkan hadits ini, yaitu membaca (ayat-ayat Al Qur`an) di belakang imam.\" Ini adalah pendapat yang diambil oleh Malik bin Anas, bin Al Mubarak, Syafi'i, Ahmad dan Ishaq. Mereka semua membolehkan membaca di belakang imam.\""},"287":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ أُكَيْمَةَ اللَّيْثِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصَرَفَ مِنْ صَلَاةٍ جَهَرَ فِيهَا بِالْقِرَاءَةِ فَقَالَ هَلْ قَرَأَ مَعِي أَحَدٌ مِنْكُمْ آنِفًا فَقَالَ رَجُلٌ نَعَمْ يَا رَسُولَ اللَّهِ قَالَ إِنِّي أَقُولُ مَالِي أُنَازَعُ الْقُرْآنَ قَالَ فَانْتَهَى النَّاسُ عَنْ الْقِرَاءَةِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا جَهَرَ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الصَّلَوَاتِ بِالْقِرَاءَةِ حِينَ سَمِعُوا ذَلِكَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَعِمْرَانَ بْنِ حُصَيْنٍ وَجَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَابْنُ أُكَيْمَةَ اللَّيْثِيُّ اسْمُهُ عُمَارَةُ وَيُقَالُ عَمْرُو بْنُ أُكَيْمَةَ وَرَوَى بَعْضُ أَصْحَابِ الزُّهْرِيِّ هَذَا الْحَدِيثَ وَذَكَرُوا هَذَا الْحَرْفَ قَالَ قَالَ الزُّهْرِيُّ فَانْتَهَى النَّاسُ عَنْ الْقِرَاءَةِ حِينَ سَمِعُوا ذَلِكَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَيْسَ فِي هَذَا الْحَدِيثِ مَا يَدْخُلُ عَلَى مَنْ رَأَى الْقِرَاءَةَ خَلْفَ الْإِمَامِ لِأَنَّ أَبَا هُرَيْرَةَ هُوَ الَّذِي رَوَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا الْحَدِيثَ وَرَوَى أَبُو هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ صَلَّى صَلَاةً لَمْ يَقْرَأْ فِيهَا بِأُمِّ الْقُرْآنِ فَهِيَ خِدَاجٌ فَهِيَ خِدَاجٌ غَيْرُ تَمَامٍ فَقَالَ لَهُ حَامِلُ الْحَدِيثِ إِنِّي أَكُونُ أَحْيَانًا وَرَاءَ الْإِمَامِ قَالَ اقْرَأْ بِهَا فِي نَفْسِكَ وَرَوَى أَبُو عُثْمَانَ النَّهْدِيُّ عَنْ أَبِي هُرَيْرَةَ قَالَ أَمَرَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أُنَادِيَ أَنْ لَا صَلَاةَ إِلَّا بِقِرَاءَةِ فَاتِحَةِ الْكِتَابِ وَاخْتَارَ أَكْثَرُ أَصْحَابِ الْحَدِيثِ أَنْ لَا يَقْرَأَ الرَّجُلُ إِذَا جَهَرَ الْإِمَامُ بِالْقِرَاءَةِ وَقَالُوا يَتَتَبَّعُ سَكَتَاتِ الْإِمَامِ وَقَدْ اخْتَلَفَ أَهْلُ الْعِلْمِ فِي الْقِرَاءَةِ خَلْفَ الْإِمَامِ فَرَأَى أَكْثَرُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ وَمَنْ بَعْدَهُمْ الْقِرَاءَةَ خَلْفَ الْإِمَامِ وَبِهِ يَقُولُ مَالِكُ بْنُ أَنَسٍ وَعَبْدُ اللَّهِ بْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ وَرُوِيَ عَنْ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ أَنَّهُ قَالَ أَنَا أَقْرَأُ خَلْفَ الْإِمَامِ وَالنَّاسُ يَقْرَءُونَ إِلَّا قَوْمًا مِنْ الْكُوفِيِّينَ وَأَرَى أَنَّ مَنْ لَمْ يَقْرَأْ صَلَاتُهُ جَائِزَةٌ وَشَدَّدَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ فِي تَرْكِ قِرَاءَةِ فَاتِحَةِ الْكِتَابِ وَإِنْ كَانَ خَلْفَ الْإِمَامِ فَقَالُوا لَا تُجْزِئُ صَلَاةٌ إِلَّا بِقِرَاءَةِ فَاتِحَةِ الْكِتَابِ وَحْدَهُ كَانَ أَوْ خَلْفَ الْإِمَامِ وَذَهَبُوا إِلَى مَا رَوَى عُبَادَةُ بْنُ الصَّامِتِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَرَأَ عُبَادَةُ بْنُ الصَّامِتِ بَعْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلْفَ الْإِمَامِ وَتَأَوَّلَ قَوْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَلَاةَ إِلَّا بِقِرَاءَةِ فَاتِحَةِ الْكِتَابِ وَبِهِ يَقُولُ الشَّافِعِيُّ وَإِسْحَقُ وَغَيْرُهُمَا وَأَمَّا أَحْمَدُ بْنُ حَنْبَلٍ فَقَالَ مَعْنَى قَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَلَاةَ لِمَنْ لَمْ يَقْرَأْ بِفَاتِحَةِ الْكِتَابِ إِذَا كَانَ وَحْدَهُ وَاحْتَجَّ بِحَدِيثِ جَابِرِ بْنِ عَبْدِ اللَّهِ حَيْثُ قَالَ مَنْ صَلَّى رَكْعَةً لَمْ يَقْرَأْ فِيهَا بِأُمِّ الْقُرْآنِ فَلَمْ يُصَلِّ إِلَّا أَنْ يَكُونَ وَرَاءَ الْإِمَامِ قَالَ أَحْمَدُ بْنُ حَنْبَلٍ فَهَذَا رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَأَوَّلَ قَوْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَلَاةَ لِمَنْ لَمْ يَقْرَأْ بِفَاتِحَةِ الْكِتَابِ أَنَّ هَذَا إِذَا كَانَ وَحْدَهُ وَاخْتَارَ أَحْمَدُ مَعَ هَذَا الْقِرَاءَةَ خَلْفَ الْإِمَامِ وَأَنْ لَا يَتْرُكَ الرَّجُلُ فَاتِحَةَ الْكِتَابِ وَإِنْ كَانَ خَلْفَ الْإِمَامِ","id":"telah menceritakan kepada kami [Al Anshari] berkata; telah menceritakan kepada kami [Ma'n] berkata; telah menceritakan kepada kami [Malik bin Anas] dari [Ibnu Syihab] dari [Ibnu Ukaimah Al Laitsi] dari [Abu Hurairah] berkata; \"Rasulullah shallallahu 'alaihi wasallam berlalu dari shalat yang bacaan di dalamnya di keraskan, setelah itu beliau bertanya: \"Apakah salah seorang ada yang membaca bersama-sama dengan aku barusan?\" lalu berkatalah seseorang, \"Benar wahai Rasulullah.\" beliau bersabda: \"Kenapa aku ditandingi dalam membaca Al Qur`an!\" Abu Hurairah berkata; \"Maka orang-orang pun berhenti dari membaca (berbarengan) bersama-sama Rasulullah pada shalat-shalat yang bacaannya dikeraskan oleh Rasulullah shallallahu 'alaihi wasallam. Yaitu setelah mereka mendengar (teguran) itu dari Rasulullah shallallahu 'alaihi wasallam.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Mas'ud, Imran bin Hushain dan Jabir bin Abdullah.\" Abu Isa berkata; \"Hadits ini derajatnya hasan. Ibnu Ukaimah Al Laitsi namanya adalah Umarah. Atau disebut juga dengan 'Amru bin Ukaimah. Sebagian sahabat Az Zuhri juga telah meriwayatkan hadits ini. Dan mereka menyebutkan persis sebagimana hadits ini. Ia berkata; \"Az Zuhri berkata; \"Orang-orang berhenti dari membaca ketika mereka mendengar teguran itu dari Rasulullah shallallahu 'alaihi wasallam. Dalam hadits ini tidak dimasukkan bagi orang-orang yang berpendapat atas dibolehkannya membaca di belakang imam, sebab Abu Hurairah lah yang meriwayatkan hadits ini dari Nabi shallallahu 'alaihi wasallam. Abu Hurairah meriwayatkan dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau bersabda: \"Barangsiapa mengerjakan shalat dan tidak membaca di dalamnya Ummul Qur`an (Al Fatihah) maka shalatnya kurang, kurang dan tidak sempurna.\" Lalu orang yang meriwayatkan hadits tersebut bertanya, \"Di belakang imam kadang-kadang aku (membaca), \" beliau (langsung) bersabda: \"Bacalah dalam hatimu.\" Abu Utsman An Nahdi meriwayatkan dari Abu Hurairah, ia berkata; \"Nabi shallallahu 'alaihi wasallam memerintahkan kepadaku untuk menyerukan kepada manusia bahwa tidak ada shalat bagi orang yang tidak membaca Fatihatul Kitab (Al fatihah).\" Maka para ahli hadits pun memilih pendapat, bahwa seorang laki-laki tidak boleh membaca jika imam mengeraskan bacaan. Mereka berkata; \"Mereka mengikuti (bacaan) ketika imam berhenti diwaktu jeda.\" Para ulama berselisih pendapat mengenai hukum membaca di belakang imam, sebagian besar ulama dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, tabi'in dan orang-orang setelah mereka berpendapat atas bolehnya membaca di belakang imam. Pendapat ini diambil oleh Malik bin Anas, Abdullah bin Al Mubarak, Syafi'i, Ahmad dan Ishaq. Diriwayatkan dari Abdullah bin Al Mubarak, bahwa ia berkata; \"Aku membaca dan orang-orang membaca di belakang imam, kecuali sekelompok orang dari penduduk Kufah. Namun aku juga berpendapat bahwa orang yang tidak membacanya shalatnya tetap sah. Sebagian ulama sangat keras dalam masalah (tidak bolehnya) meninggalkan bacaan Fatihatul Kitab dalam shalat, meskipun seseorang berada di belakang imam, mereka berkata; \"Shalat tidak dianggap sah kecuali dengan bacaan Fatihatul Kitab. Baik ia shalat sendirian atau bersama imam.\" Mereka berpegangan dengan hadits riwayat Ubadah bin Ash Shamit dari Nabi shallallahu 'alaihi wasallam. Dan Ubadah bin Ash Shamit pun tetap membaca di belakang Imam setelah wafatnya Nabi shallallahu 'alaihi wasallam. Dan ia mentakwilkan sabda Nabi shallallahu 'alaihi wasallam: \"Tidak ada (sempurna) shalat bagi orang yang tidak membaca Fatihatul Kitab.\" Pendapat ini diambil oleh Syafi'i, Ishaq dan selain keduanya. Adapun Imam Ahmad, ia mengatakan, \"Makna sabda Nabi shallallahu 'alaihi wasallam: \"Tidak ada (sempurna) shalat bagi orang yang tidak membaca Fatihatul Kitab, \" yakni jika ia shalat sendirian. Lalu Imam Ahmad berdalil dengan hadits Jabir bin Abdullah, ia berkata; \"Barangsiapa shalat satu rakaat dan tidak membaca Ummul Qur`an di dalamnya maka ia belum shalat, kecuali jika ia shalat di belakang imam.\" Imam Ahmad berkata; \"Jabir adalah seorang sahabat Nabi shallallahu 'alaihi wasallam, (namun) ia tetap mentakwilkan sabda Nabi shallallahu 'alaihi wasallam: \"Tidak shalat bagi orang yang tidak membaca Fatihatul Kitab, \" bahwa hadits ini (berlaku) jika shalat sendirian.\" Namun begitu Imam Ahmad tetap memilih untuk membaca di belakang imam, dan hendaknya seorang laki-laki tidak meninggalkan (dari membaca) Fatihatul Kitab meskipun berada di belakang imam.\""},"288":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ أَبِي نُعَيْمٍ وَهْبِ بْنِ كَيْسَانَ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُمَنْ صَلَّى رَكْعَةً لَمْ يَقْرَأْ فِيهَا بِأُمِّ الْقُرْآنِ فَلَمْ يُصَلِّ إِلَّا أَنْ يَكُونَ وَرَاءَ الْإِمَامِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] berkata; telah menceritakan kepada kami [Ma'n] berkata; telah menceritakan kepada kami [Malik] dari [Abu Nu'aim Wahb bin Kaisan] bahwasanya ia pernah mendengar [Jabir bin Abdullah] berkata; \"Barangsiapa shalat satu rakaat dan tidak membaca Ummul Qur`an di dalamnya maka ia belum shalat, kecuali jika ia shalat di belakang imam.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\""},"289":{"ar":"ح��دَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ لَيْثٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَسَنِ عَنْ أُمِّهِ فَاطِمَةَ بِنْتِ الْحُسَيْنِ عَنْ جَدَّتِهَا فَاطِمَةَ الْكُبْرَى قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ الْمَسْجِدَ صَلَّى عَلَى مُحَمَّدٍ وَسَلَّمَ وَقَالَ رَبِّ اغْفِرْ لِي ذُنُوبِي وَافْتَحْ لِي أَبْوَابَ رَحْمَتِكَ وَإِذَا خَرَجَ صَلَّى عَلَى مُحَمَّدٍ وَسَلَّمَ وَقَالَ رَبِّ اغْفِرْ لِي ذُنُوبِي وَافْتَحْ لِي أَبْوَابَ فَضْلِكَو قَالَ عَلِيُّ بْنُ حُجْرٍ قَالَ إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ فَلَقِيتُ عَبْدَ اللَّهِ بْنَ الْحَسَنِ بِمَكَّةَ فَسَأَلْتُهُ عَنْ هَذَا الْحَدِيثِ فَحَدَّثَنِي بِهِ قَالَ كَانَ إِذَا دَخَلَ قَالَ رَبِّ افْتَحْ لِي بَابَ رَحْمَتِكَ وَإِذَا خَرَجَ قَالَ رَبِّ افْتَحْ لِي بَابَ فَضْلِكَ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي حُمَيْدٍ وَأَبِي أُسَيْدٍ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى حَدِيثُ فَاطِمَةَ حَدِيثٌ حَسَنٌ وَلَيْسَ إِسْنَادُهُ بِمُتَّصِلٍ وَفَاطِمَةُ بِنْتُ الْحُسَيْنِ لَمْ تُدْرِكْ فَاطِمَةَ الْكُبْرَى إِنَّمَا عَاشَتْ فَاطِمَةُ بَعْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشْهُرًا","id":"telah menceritakan kepada kami [Ali bin Hujr] berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Laits] dari [Abdullah bin Al Hasan] dari ibunya [Fatimah binti Al Husain] dari neneknya [Fatimah Al Kubra] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila Rasulullah shallallahu 'alaihi wasallam masuk ke dalam masjid ke dalam masjd beliau membaca shalawat dan salam untuk Muhammad, lalu mengucapkan: \"RABBIGHFIRLI DZUNAUBI WAFTAHLI ABWAABA RAHMATIK (Ya Allah, ampunilah dosa-dosaku dan bukanlah pintu-pintu rahmat-Mu untukku), dan jika keluar beliau juga membaca shalawat dan salam untuk Muhammad, lalu mengucapkan: \"RABBIGHFIRLI DZUNAUBI WAFTAHLI ABWAABA RAHMATIK (Ya Allah, ampunilah dosa-dosaku dan bukanlah pintu-pintu rahmat-Mu untukku).\" [Ali bin Hujr] berkata; \" [Isma'il bin Ibrahim] berkata; \"Aku bertemu dengan [Abdullah bin Al Hasan] di Makkah, lalu aku bertanya kepadanya tentang hadits ini. Maka iapun menceritakan hadits tersebut kepadaku, ia berkata; \"Jika masuk beliau membaca; \"RABBIFTAHLI BAABA RAHMATIK (Ya Allah, bukakanlah pintu rahmat-Mu), dan jika kelur beliau membaca: \"RABBIFTAHLI BABA FADLLIK (Ya Allah, bukakanlah pintu karunia-Mu).\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Humaid, Abu Usaid dan Abu Hurairah.\" Abu Isa berkata; \"Hadits Fatimah ini derajatnya hasan, akan tetapi sanadnya tidak bersambung, sebab Fatimah binti Al Husain belum pernah bertemu dengan Fatimah Al Kubra. Karena Fatimah (Al Kubra) hanya hidup beberapa bulan saja setelah wafatnya Nabi shallallahu 'alaihi wasallam.\""},"290":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ الزُّرَقِيِّ عَنْ أَبِي قَتَادَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَاءَ أَحَدُكُمْ الْمَسْجِدَ فَلْيَرْكَعْ رَكْعَتَيْنِ قَبْلَ أَنْ يَجْلِسَقَالَ وَفِي الْبَاب عَنْ جَابِرٍ وَأَبِي أُمَامَةَ وَأَبِي هُرَيْرَةَ وَأَبِي ذَرٍّ وَكَعْبِ بْنِ مَالِكٍ قَالَ أَبُو عِيسَى وَحَدِيثُ أَبِي قَتَادَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَى هَذَا الْحَدِيثَ مُحَمَّدُ بْنُ عَجْلَانَ وَغَيْرُ وَاحِدٍ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ نَحْوَ رِوَايَةِ مَالِكِ بْنِ أَنَسٍ وَرَوَى سُهَيْلُ بْنُ أَبِي صَالِحٍ هَذَا الْحَدِيثَ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ الزُّرَقِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَذَا حَدِيثٌ غَيْرُ مَحْفُوظٍ وَالصَّحِيحُ حَدِيثُ أَبِي قَتَادَةَ وَالْعَمَلُ عَلَى هَذَا الْحَدِيثِ عِنْدَ أَصْحَابِنَا اسْتَحَبُّوا إِذَا دَخَلَ الرَّجُلُ الْمَسْجِدَ أَنْ لَا يَجْلِسَ حَتَّى يُصَلِّيَ رَكْعَتَيْنِ إِلَّا أَنْ يَكُونَ لَهُ عُذْرٌ قَالَ عَلِيُّ بْنُ الْمَدِينِيِّ وَحَدِيثُ سُهَيْلِ بْنِ أَبِي صَالِحٍ خَطَأٌ أَخْبَرَنِي بِذَلِكَ إِسْحَقُ بْنُ إِبْرَاهِيمَ عَنْ عَلِيِّ بْنِ الْمَدِينِيِّ","id":"telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata; telah menceritakan kepada kami [Malik bin Anas] dari ['Amir bin Abdullah bin Az Zubair] dari ['Amru bin Sulaim Az Zuraqi] dari [Abu Qatadah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian masuk ke dalam masjid maka hendaklah ia shalat dua rakaat sebelum duduk.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Jabir, Abu Umamah, Abu Hurairah, Abu Dzar dan Ka'ab bin Malik.\" Abu Isa berkata; \"Hadits Abu Qatadah derajatnya hasan shahih. [Muhammad bin 'Ajlan] dan selainnya juga telah meriwayatkan hadits ini dari ['Amir bin Abdullah bin Az Zubair] sebagaimana riwayat Malik bin Anas.\" Suhail bin Shalih juga meriwayatkan hadits ini dari 'Amru bin Sulaim bin Az Zuraqi, dari Jabir bin Abdillah, dari Nabi shallallahu 'alaihi wasallam. Namun hadits ini sanadnya tidak terjaga. Dan hadits Abu Qatadah lah yang lebih shahih. Sahabat-sahabat kami mengamalkan hadits ini, mereka menyukai jika seseorang masuk ke dalam masjid, ia tidak duduk hingga shalat dua rakaat, kecuali ada udzur. Ali bin Al Madini berkata; \"Hadits Suhail bin Abu Shalih ini salah. Aku telah diberi kabar tentang hal itu oleh Ishaq bin Ibrahim dari Ali bin Al Madini.\""},"291":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ وَأَبُو عَمَّارٍ الْحُسَيْنُ بْنُ حُرَيْثٍ الْمَرْوَزِيُّ قَالَا حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَرْضُ كُلُّهَا مَسْجِدٌ إِلَّا الْمَقْبَرَةَ وَالْحَمَّامَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَلِيٍّ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَأَبِي هُرَيْرَةَ وَجَابِرٍ وَابْنِ عَبَّاسٍ وَحُذَيْفَةَ وَأَنَسٍ وَأَبِي أُمَامَةَ وَأَبِي ذَرٍّ قَالُوا إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جُعِلَتْ لِيَ الْأَرْضُ مَسْجِدًا وَطَهُورًا قَالَ أَبُو عِيسَى حَدِيثُ أَبِي سَعِيدٍ قَدْ رُوِيَ عَنْ عَبْدِ الْعَزِيزِ بْنِ مُحَمَّدٍ رِوَايَتَيْنِ مِنْهُمْ مَنْ ذَكَرَهُ عَنْ أَبِي سَعِيدٍ وَمِنْهُمْ مَنْ لَمْ يَذْكُرْهُ وَهَذَا حَدِيثٌ فِيهِ اضْطِرَابٌ رَوَى سُفْيَانُ الثَّوْرِيُّ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلٌ وَرَوَاهُ حَمَّادُ بْنُ سَلَمَةَ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَاهُ مُحَمَّدُ بْنُ إِسْحَقَ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ قَالَ وَكَانَ عَامَّةُ رِوَايَتِهِ عَنْ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَذْكُرْ فِيهِ عَنْ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَأَنَّ رِوَايَةَ الثَّوْرِيِّ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَثْبَتُ وَأَصَحُّ مُرْسَلًا","id":"telah menceritakan kepada kami [Ibnu Abu Umar] dan [Abu 'Ammar Al Husain bin Huraits Al Marwazi] keduanya berkata; telah bercerita kepada kami [Abdul Aziz bin Muhammad] dari ['Amru bin Yahya] dari [Ayahnya] dari [Abu Sa'id Al Khudri] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda, \"Bumi ini seluruhnya adalah masjid kecuali kuburan dan kamar mandi.\" Abu Isa berakta, \"Dalam bab ini ada juga hadits dari Ali, Abdullah bin 'Amru, Abu Hurairah, Jabir, Ibnu Abbas, Hudzaifah, Anas, Abu Umamah dan Abu Dzar. Mereka berkata; \"Nabi shallallahu 'alaihi wasallam bersabda: \"Bumi dijadikan untukku sebagai tempat sujud dan bersuci.\" Abu Isa berkata; \"Hadits Abu Sa'id ini telah diriwayatkan dari Abdul Aziz bin Muhammad dengan dua riwayat; satu riwayat ada yang menyebutkan dari Abu Sa'id dan riwayat yang lainnya tidak menyebutkan. Dalam hadits ini ada idltirab (pertentangan). [Sufyan Ats Tsauri] meriwayatkan hadits ini dari ['Amru bin Yahya] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam secara mursal, sedangkan [Hammad bin Salamah] meriwayatkannya dari ['Amru bin Yahya] dari [ayahnya] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam. [Muhammmad bin Ishaq] meriwayatkannya dari ['Amru bin Yahya] dari [ayahnya]. Kemudian ia berkata; \"Mayoritas riwayatnya dari Abu Sa'id, dari Nabi shallallahu 'alaihi wasallam. Namun dalam hadits ini ia tidak menyebutkan dari Abu Sa'id, dari Nabi shallallahu 'alaihi wasallam, seakan-akan riwayat Ats Tsauri dari 'Amru bin Yahya, dari ayahnya, dari Nabi shallallahu 'alaihi wasallam lebih kuat dan lebih shahih secara mursal.\""},"292":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ عَنْ أَبِيهِ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ عُثْمَانَ بْنِ عَفَّانَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ بَنَى لِلَّهِ مَسْجِدًا بَنَى اللَّهُ لَهُ مِثْلَهُ فِي الْجَنَّةِقَالَ وَفِي الْبَاب عَنْ أَبِي بَكْرٍ وَعُمَرَ وَعَلِيٍّ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَأَنَسٍ وَابْنِ عَبَّاسٍ وَعَائِشَةَ وَأُمِّ حَبِيبَةَ وَأَبِي ذَرٍّ وَعَمْرِو بْنِ عَبَسَةَ وَوَاثِلَةَ بْنِ الْأَسْقَعِ وَأَبِي هُرَيْرَةَ وَجَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ أَبُو عِيسَى حَدِيثُ عُثْمَانَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَمَحْمُودُ بْنُ لَبِيدٍ قَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَحْمُودُ بْنُ الرَّبِيعِ قَدْ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمَا غُلَامَانِ صَغِيرَانِ مَدَنِيَّانِ","id":"telah menceritakan kepada kami [Bundar] berkata; telah menceritakan kepada kami [Abu Bakr Al Hanafi] berkata; telah menceritakan kepada kami [Abdul Hamid bin Ja'far] dari [Ayahnya] dari [Mahmud bin Labid] dari [Utsman bin 'Affan] ia berkata; \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membangun masjid karena Allah, maka Allah akan membangunkan yang semisal di surga.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Bakar, Umar, Ali, Abdullah bin Umar, Anas, Ibnu Abbas, 'Aisyah, Ummu Habibah, Abu Dzar, Amru bin Abasah, Watsilah bin Al Asqa', Abu Hurairah dan Jabir bin Abdullah.\" Abu Isa berkata; \"Hadits Utsman ini derajatnya hasan shahih. Mahmud bin Labid pernah bertemu dengan Nabi shallallahu 'alaihi wasallam, demikian juga dengan Mahmud bin Ar Rabi' juga telah bertemu dengan Nabi shallallahu 'alaihi wasallam, keduanya adalah anak-anak kecil dari kota Madinah.\""},"293":{"ar":"وَقَدْ رُوِيَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ بَنَى لِلَّهِ مَسْجِدًا صَغِيرًا كَانَ أَوْ كَبِيرًا بَنَى اللَّهُ لَهُ بَيْتًا فِي الْجَنَّةِحَدَّثَنَا بِذَلِكَ قُتَيْبَةُ حَدَّثَنَا نُوحُ بْنُ قَيْسٍ عَنْ عَبْدِ الرَّحْمَنِ مَوْلَى قَيْسٍ عَنْ زِيَادٍ النُّمَيْرِيِّ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا","id":"Telah diriwayatkan dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau bersabda: \"Barangsiapa membangun sebuah masjid karena Allah baik kecil maupun besar, maka Allah akan membuatkan sebuah rumah baginya di surga.\" [Qutaibah] menceritakan demikian kepada kami, ia berkata; telah menceritakan kepada kami [Nuh bin Qais] dari [Abdurrahman] pelayan Qais dari [Ziyad An Numairi] dari [Anas] dari Nabi shallallahu 'alaihi wasallam seperti ini.\""},"294":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ جُحَادَةَ عَنْ أَبِي صَالِحٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَائِرَاتِ الْقُبُورِ وَالْمُتَّخِذِينَ عَلَيْهَا الْمَسَاجِدَ وَالسُّرُجَقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَعَائِشَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عَبَّاسٍ حَدِيثٌ حَسَنٌ وَأَبُو صَالِحٍ هَذَا هُوَ مَوْلَى أُمِّ هَانِئِ بِنْتِ أَبِي طَالِبٍ وَاسْمُهُ بَاذَانُ وَيُقَالُ بَاذَامُ أَيْضًا","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abdul Warits bin Sa'id] dari [Muhammad bin Juhadah] dari [Abu Shalih] dari [Ibnu Abbas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melaknat para penziarah kubur, orang-orang yang menjadikannya sebagai masjid dan orang yang memasangkan lentera padanya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Hurairah dan 'Aisyah.\" Abu Isa berkata; \"Hadits Ibnu Abbas ini derajatnya hasan. Sedangkan Abu Shalih adalah pelayan Ummu Hani` binti Abu Thalib, namanya adalah Badzan, atau dipanggil juga dengan nama Badzam.\""},"295":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَكُنَّا نَنَامُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ وَنَحْنُ شَبَابٌقَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَخَّصَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ فِي النَّوْمِ فِي الْمَسْجِدِ قَالَ ابْنُ عَبَّاسٍ لَا يَتَّخِذُهُ مَبِيتًا وَلَا مَقِيلًا وَقَوْمٌ مِنْ أَهْلِ الْعِلْمِ ذَهَبُوا إِلَى قَوْلِ ابْنِ عَبَّاسٍ","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Abdurrazaq] berkata; telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] ia berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam kami tidur di masjid, sedang waktu itu kami masih muda.\" Abu Isa berkata; \"Hadits Ibnu Umar ini derajatnya hasan shahih. Sebagian ahli ilmu memberi keringanan untuk dibolehkannya tidur di masjid.\" Ibnu Abbas berkata; \"Jangan kalian jadikan ia (masjid) sebagai tempat untuk tidur siang atau tidur malam.\" Dan sebagian dari ahli ilmu berpendapat dengan ucapan Ibnu Abbas tersebut."},"296":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ تَنَاشُدِ الْأَشْعَارِ فِي الْمَسْجِدِ وَعَنْ الْبَيْعِ وَالِاشْتِرَاءِ فِيهِ وَأَنْ يَتَحَلَّقَ النَّاسُ يَوْمَ الْجُمُعَةِ قَبْلَ الصَّلَاةِقَالَ وَفِي الْبَاب عَنْ بُرَيْدَةَ وَجَابِرٍ وَأَنَسٍ قَالَ أَبُو عِيسَى حَدِيثُ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ حَدِيثٌ حَسَنٌ وَعَمْرُو بْنُ شُعَيْبٍ هُوَ ابْنُ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ رَأَيْتُ أَحْمَدَ وَإِسْحَقَ وَذَكَرَ غَيْرَهُمَا يَحْتَجُّونَ بِحَدِيثِ عَمْرِو بْنِ شُعَيْبٍ قَالَ مُحَمَّدٌ وَقَدْ سَمِعَ شُعَيْبُ بْنُ مُحَمَّدٍ مِنْ جَدِّهِ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى وَمَنْ تَكَلَّمَ فِي حَدِيثِ عَمْرِو بْنِ شُعَيْبٍ إِنَّمَا ضَعَّفَهُ لِأَنَّهُ يُحَدِّثُ عَنْ صَحِيفَةِ جَدِّهِ كَأَنَّهُمْ رَأَوْا أَنَّهُ لَمْ يَسْمَعْ هَذِهِ الْأَحَادِيثَ مِنْ جَدِّهِ قَالَ عَلِيُّ بْنُ عَبْدِ اللَّهِ وَذُكِرَ عَنْ يَحْيَى بْنِ سَعِيدٍ أَنَّهُ قَالَ حَدِيثُ عَمْرِو بْنِ شُعَيْبٍ عِنْدَنَا وَاهٍ وَقَدْ كَرِهَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ الْبَيْعَ وَالشِّرَاءَ فِي الْمَسْجِدِ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ وَقَدْ رُوِيَ عَنْ بَعْضِ أَهْلِ الْعِلْمِ مِنْ التَّابِعِينَ رُخْصَةٌ فِي الْبَيْعِ وَالشِّرَاءِ فِي الْمَسْجِدِ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَيْرِ حَدِيثٍ رُخْصَةٌ فِي إِنْشَادِ الشِّعْرِ فِي الْمَسْجِدِ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] dari Rasulullah shallallahu 'alaihi wasallam, bahwasanya beliau melarang dari melantunkan sya'ir di dalam masjid, transaksi jual beli, dan membuat halaqah (perkumpulan) pada hari Jum'at sebelum waktu shalat.\" Ia berkata; \"Dalam bab ini ada juga hadits dari Buraidah, Jabir dan Anas.\" Abu Isa berkata; \"Hadits Abdullah bin 'Amru bin Al 'Ash ini derajatnya hasan. 'Amru bin Syu'aib adalah anak dari Muhammad bin Abdullah bin 'Amru bin Al 'Ash.\" Muhammad bin Isma'il berkata; \"Aku melihat Ahmad dan Ishaq -dan menyebutkan selain keduanya-, mereka berdalil dengan hadits 'Amru bin Syu'aib.\" Muhammad berkata; \"Syu'aib bin Muhammad telah mendengar dari kakeknya, yaitu Abdullah bin 'Amru.\" Abu Isa berkata; \"Adapun orang yang memperbincangkan hadits 'Amru bin Syu'aib dan melemahkannya adalah karena 'Amru bin Syu'aib meriwayatkan hadits dari shahifah (kitab) kakeknya. Seakan-akan mereka melihat bahwa 'Amru bin Syu'aib tidak mendengar hadits-hadits ini dari kakeknya secara langsung.\" Ali bin Abdullah berkata; \"Telah disebutkan dari Yahya bin Sa'id bahwa ia berkata; \"Hadits 'Amru bin Syu'aib bagi kami adalah hadits yang wahin (lemah).\" Sebagian ahli ilmu memakruhkan transaksi jual beli di masjid, dan ini adalah pendapat Ahmad dan Ishaq. Telah diriwayatkan dari sebagian ahli ilmu dari kalangan tabi'in bahwa ada keringanan untuk melakukan transaksi jual beli di dalam masjid. Dan telah diriwayatkan pula dari Nabi shallallahu 'alaihi wasallam dalam banyak hadits tentang keringanan untuk melantunkan sya'ir di masjid.\""},"297":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ أُنَيْسِ بْنِ أَبِي يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَامْتَرَى رَجُلٌ مِنْ بَنِي خُدْرَةَ وَرَجُلٌ مِنْ بَنِي عَمْرِو بْنِ عَوْفٍ فِي الْمَسْجِدِ الَّذِي أُسِّسَ عَلَى التَّقْوَى فَقَالَ الْخُدْرِيُّ هُوَ مَسْجِدُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ الْآخَرُ هُوَ مَسْجِدُ قُبَاءٍ فَأَتَيَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذَلِكَ فَقَالَ هُوَ هَذَا يَعْنِي مَسْجِدَهُ وَفِي ذَلِكَ خَيْرٌ كَثِيرٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ حَدَّثَنَا أَبُو بَكْرٍ عَنْ عَلِيِّ بْنِ عَبْدِ اللَّهِ قَالَ سَأَلْتُ يَحْيَى بْنَ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ أَبِي يَحْيَى الْأَسْلَمِيِّ فَقَالَ لَمْ يَكُنْ بِهِ بَأْسٌ وَأَخُوهُ أُنَيْسُ بْنُ أَبِي يَحْيَى أَثْبَتُ مِنْهُ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Hatim bin Isma'il] dari [Unais bin Abu Yahya] dari [Ayahnya] dari [Sa'id Al Khudri] ia berkata; \"Seorang dari bani Khudrah berdebat dengan seorang laki-laki dari bani 'Amru bin Auf tentang masjid yang dibangun atas dasar iman. Orang yang berasal dari bani Khudrah berkata; \"Itu adalah masjid Rasulullah shallallahu 'alaihi wasallam, \" sedangkan orang yang berasal dari bani 'Amru bin Auf berkata; \"Itu adalah masjid Quba`.\" Lalu mereka pun mendatangi Rasulullah shallallahu 'alaihi wasallam untuk mengadukan hal itu, maka beliau pun bersabda: \"Itu adalah masjid ini -yakni masjid beliau-, dan pada masjid Quba` ada kebaikan yang banyak.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\" Ia berkata; \"Telah menceritakan kepada kami Abu Bakr, dari Ali bin Abdullah, ia berkata; \"Aku bertanya kepada Yahya bin Sa'id tentang Muhammad bin Abu Yahya Al Aslami, maka ia pun menjawab, \"Dia bukan orang yang bermasalah. Saudaranya adalah Unais bin Abu Yahya, dan ia lebih bagus daripada dia.\""},"298":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ أَبُو كُرَيْبٍ وَسُفْيَانُ بْنُ وَكِيعٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ قَالَ حَدَّثَنَا أَبُو الْأَبْرَدِ مَوْلَى بَنِي خَطْمَةَ أَنَّهُ سَمِعَ أُسَيْدَ بْنَ ظُهَيْرٍ الْأَنْصَارِيَّ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الصَّلَاةُ فِي مَسْجِدِ قُبَاءٍ كَعُمْرَةٍقَالَ وَفِي الْبَاب عَنْ سَهْلِ بْنِ حُنَيْفٍ قَالَ أَبُو عِيسَى حَدِيثُ أُسَيْدٍ حَدِيثٌ حَسَنٌ غَرِيبٌ وَلَا نَعْرِفُ لِأُسَيْدِ بْنِ ظُهَيْرٍ شَيْئًا يَصِحُّ غَيْرَ هَذَا الْحَدِيثِ وَلَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ أَبِي أُسَامَةَ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ وَأَبُو الْأَبْرَدِ اسْمُهُ زِيَادٌ مَدِينِيٌّ","id":"telah menceritakan kepada kami [Muhammad bin Al 'Ala` Abu Kuraib] dan [Sufyan bin Waki'] keduanya berkata; telah menceritakan kepada kami [Abu Usamah] dari [Abdul Hamid bin Ja'far] ia berkata' telah menceritakan kepada kami [Abu Al Abrad] pelayan bani Khathmah, bahwasanya ia mendengar [Usaid bin Zhuhair Al Anshari] - ia termasuk sahabat Nabi shallallahu 'alaihi wasallam- ia menceritakan dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Shalat di masjid Quba' pahalanya sebanding dengan ibadah umrah.\" Ia berkata; \"Dalam bab ini ada juga hadits dari Sahl bin Hunaif.\" Abu Isa berkata; \"Hadits Usaid ini derajatnya hasan gharib, dan kami tidak mengetahui sedikitpun hadits shahih dari Usaid bin Zhuhair kecuali hadits ini. Dan kami juga tidak mengetahuinya kecuali dari hadits Abu Usamah, dari Abdul Hamid bin Ja'far. Sedangkan Abu Al Abrad namanya adalah Ziyad Madini.\""},"299":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ ح و حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ رَبَاحٍ وَعُبَيْدِ اللَّهِ بْنِ أَبِي عَبْدِ اللَّهِ الْأَغَرِّ عَنْ أَبِي عَبْدِ اللَّهِ الْأَغَرِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةٌ فِي مَسْجِدِي هَذَا خَيْرٌ مِنْ أَلْفِ صَلَاةٍ فِيمَا سِوَاهُ إِلَّا الْمَسْجِدَ الْحَرَامَقَالَ أَبُو عِيسَى وَلَمْ يَذْكُرْ قُتَيْبَةُ فِي حَدِيثِهِ عَنْ عُبَيْدِ اللَّهِ إِنَّمَا ذَكَرَ عَنْ زَيْدِ بْنِ رَبَاحٍ عَنْ أَبِي عَبْدِ اللَّهِ الْأَغَرِّ عَنْ أَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو عَبْدِ اللَّهِ الْأَغَرُّ اسْمُهُ سَلْمَانُ وَقَدْ رُوِيَ عَنْ أَبِي هُرَيْرَةَ مِنْ غَيْرِ وَجْهٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي الْبَاب عَنْ عَلِيٍّ وَمَيْمُونَةَ وَأَبِي سَعِيدٍ وَجُبَيْرِ بْنِ مُطْعِمٍ وَابْنِ عُمَرَ وَعَبْدِ اللَّهِ بْنِ الزُّبَيْرِ وَأَبِي ذَرٍّ","id":"telah menceritakan kepada kami [Al Anshari] berkata; telah menceritakan kepada kami [Ma'n] dari [Malik]. (sanad dialihkan) dan telah menceritakan kepada kami [Qutaibah] dari [Malik] dari [Zaid bin Rabah] dari [Ubaidullah bin Abu Abdullah Al Aghar] dari [Abu Abdullah Al Aghar] dari [Abu Hurairah] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat di masjidku ini lebih utama dengan seribu kali shalat di masjid selainnya, kecuali masjidil haram.\" Abu Isa berkata; \"Qutaibah tidak menyebutkan dalam haditsnya, dari Ubaidullah. Tetapi ia hanya menyebutkan dari Zaid bin Rabah, dari Abu Abdullah Al Aghar, dari Abu Hurairah.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Abu Abdullah Al Aghar namanya adalah Salman. Dan hadits ini juga telah diriwayatkan dari Abu Hurairah dengan banyak jalur, dari Nabi shallallahu 'alaihi wasallam.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ali, Maimunah, Abu Sa'id, Jubair bin Muth'im, Ibnu Umar, Ubaidullah bin Az Zubair dan Abu Dzar.\""},"300":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ قَزَعَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُشَدُّ الرِّحَالُ إِلَّا إِلَى ثَلَاثَةِ مَسَاجِدَ مَسْجِدِ الْحَرَامِ وَمَسْجِدِي هَذَا وَمَسْجِدِ الْأَقْصَىقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Ibnu Abu Umar] berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abdul Malik bin Umair] dari [Qaza'ah] dari [Abu Sa'id Al Khudri] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh bepergian (dengan ibadah) kecuali ke tiga masjid; masjidil haram, masjidku dan masjid al Aqsha.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\""},"301":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا تَأْتُوهَا وَأَنْتُمْ تَسْعَوْنَ وَلَكِنْ ائْتُوهَا وَأَنْتُمْ تَمْشُونَ وَعَلَيْكُمْ السَّكِينَةَ فَمَا أَدْرَكْتُمْ فَصَلُّوا وَمَا فَاتَكُمْ فَأَتِمُّواوَفِي الْبَاب عَنْ أَبِي قَتَادَةَ وَأُبَيِّ بْنِ كَعْبٍ وَأَبِي سَعِيدٍ وَزَيْدِ بْنِ ثَابِتٍ وَجَابِرٍ وَأَنَسٍ قَالَ أَبُو عِيسَى اخْتَلَفَ أَهْلُ الْعِلْمِ فِي الْمَشْيِ إِلَى الْمَسْجِدِ فَمِنْهُمْ مَنْ رَأَى الْإِسْرَاعَ إِذَا خَافَ فَوْتَ التَّكْبِيرَةِ الْأُولَى حَتَّى ذُكِرَ عَنْ بَعْضِهِمْ أَنَّهُ كَانَ يُهَرْوِلُ إِلَى الصَّلَاةِ وَمِنْهُمْ مَنْ كَرِهَ الْإِسْرَاعَ وَاخْتَارَ أَنْ يَمْشِيَ عَلَى تُؤَدَةٍ وَوَقَارٍ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ وَقَالَا الْعَمَلُ عَلَى حَدِيثِ أَبِي هُرَيْرَةَ و قَالَ إِسْحَقُ إِنْ خَافَ فَوْتَ التَّكْبِيرَةِ الْأُولَى فَلَا بَأْسَ أَنْ يُسْرِعَ فِي الْمَشْيِ حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ حَدِيثِ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ بِمَعْنَاهُ هَكَذَا قَالَ عَبْدُ الرَّزَّاقِ عِنْدَ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَذَا أَصَحُّ مِنْ حَدِيثِ يَزِيدَ بْنِ زُرَيْعٍ حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] berkata; telah menceritakan kepada kami [Yazid bin Zurai'] berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika shalat telah didirikan maka janganlah kalian datangi dengan tergesa-gesa, akan tetapi datangilah dengan berjalan dan tenang. Apa yang kalian dapati maka shalatlah dan apa yang kalian tertinggal maka sempurnakanlah.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Qatadah, Ubai bin Ka'ab, Abu Sa'id, Zaid bin Tsabit, Jabir dan Anas.\" Abu Isa berkata; \"Para ulama berselisih tentang berjalan ke masjid. sebagian berpendapat bahwa seseorang dianjurkan untuk bersegera jika dikawatirkan akan ketinggalan takbir yang pertama. Hingga disebutkan bahwa sebagian dari mereka berjalan cepat ketika menghadiri shalat. Sedangkan sebagian yang lain berpendapat atas makruhnya terburu-buru dalam menghadiri shalat. Mereka memilih untuk berjalan dengan tenang dan berwibawa. Pendapat ini diambil oleh Ahmad dan Ishaq. Mereka berdua berkata; \"Pengamalan (dalam hal ini) adalah berdasar hadits Abu Hurairah.\" Ahmad berkata; \"Jika seseorang takut kehilangan takbir pertama maka tidak mengapa untuk berjalan dengan bersegera.\" Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] berkata; telah menceritakan kepada kami [Abdurrazaq] berkata; telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyib] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, sebagaimana hadits Abu Salamah dari Abu Hurairah dengan hadits yang semakna dengan sebelumnya. Abdurrazaq berkata; \"Hadits Abu Sa'id dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam lebih shahih daripada hadits dari Yazid bin Zurai'. Telah menceritakan kepada kami [Ibnu Abu Umar] berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id bin Al Musayyib] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam sebagaimana hadits sebelumnya.\""},"302":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزَالُ أَحَدُكُمْ فِي صَلَاةٍ مَا دَامَ يَنْتَظِرُهَا وَلَا تَزَالُ الْمَلَائِكَةُ تُصَلِّي عَلَى أَحَدِكُمْ مَا دَامَ فِي الْمَسْجِدِ اللَّهُمَّ اغْفِرْ لَهُ اللَّهُمَّ ارْحَمْهُ مَا لَمْ يُحْدِثْفَقَالَ رَجُلٌ مِنْ حَضْرَمَوْتَ وَمَا الْحَدَثُ يَا أَبَا هُرَيْرَةَ قَالَ فُسَاءٌ أَوْ ضُرَاطٌ قَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَأَبِي سَعِيدٍ وَأَنَسٍ وَعَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَسَهْلِ بْنِ سَعْدٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Abdurrazaq] berkata; telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Salah seorang dari kalian akan tetap dalam hitungan shalat selama ia menunggu shalat. Dan malaikat juga akan senantiasa bershalawat selama salah seorang dari kalian berada di masjid, mereka berkata; \"Ya Allah ampunilah ia, Ya Allah rahmatilah ia, \" yakni selama ia tidak batal.\" Seorang laki-laki dari Hadramaut bertanya, \"Wahai Abu Hurairah, bagaimana ia batal?\" ia menjawab, \"Kentut tanpa suara atau pun bersuara.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ali, Abu Sa'id, Anas, Abdullah bin Mas'ud dan Sahl bin Sa'd.\" Abu Isa berkata; \"Hadits Abu Hurairah derajatnya hasan shahih.\""},"303":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى الْخُمْرَةِقَالَ وَفِي الْبَاب عَنْ أُمِّ حَبِيبَةَ وَابْنِ عُمَرَ وَأُمِّ سُلَيْمٍ وَعَائِشَةَ وَمَيْمُونَةَ وَأُمِّ كُلْثُومٍ بِنْتِ أَبِي سَلَمَةَ بْنِ عَبْدِ الْأَسَدِ وَلَمْ تَسْمَعْ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُمِّ سَلَمَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عَبَّاسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَبِهِ يَقُولُ بَعْضُ أَهْلِ الْعِلْمِ و قَالَ أَحْمَدُ وَإِسْحَقُ قَدْ ثَبَتَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةُ عَلَى الْخُمْرَةِ قَالَ أَبُو عِيسَى وَالْخُمْرَةُ هُوَ حَصِيرٌ قَصِيرٌ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak bin Harb] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat di atas khumrah (tikar kecil).\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Ummu Habibah, Ibnu Umar, 'Aisyah, Maimunah, Ummu Kultsum binti Abu Salamah bin Abdul Asad -ia belum pernah mendengar dari Nabi shallallahu 'alaihi wasallam- dan Ummu Salamah.\" Abu Isa berkata; \"Hadits Ibnu Abbas ini derajatnya hasan shahih. Ini adalah pendapat yang diambil oleh sebagian ahli ilmu.\" Ahmad dan Ishaq berkata; \"Telah ada riwayat dari Nabi shallallahu 'alaihi wasallam bahwa beliau shalat di atas khumrah.\" Abu Isa berkata; \"Khumrah adalah tikar yang pendek.\""},"304":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ عَنْ أَبِي سَعِيدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى حَصِيرٍقَالَ وَفِي الْبَاب عَنْ أَنَسٍ وَالْمُغِيرَةِ بْنِ شُعْبَةَ قَالَ أَبُو عِيسَى وَحَدِيثُ أَبِي سَعِيدٍ حَدِيثٌ حَسَنٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ إِلَّا أَنَّ قَوْمًا مِنْ أَهْلِ الْعِلْمِ اخْتَارُوا الصَّلَاةَ عَلَى الْأَرْضِ اسْتِحْبَابًا وَأَبُو سُفْيَانَ اسْمُهُ طَلْحَةُ بْنُ نَافِعٍ","id":"telah menceritakan kepada kami [Nashr bin Ali] berkata; telah menceritakan kepada kami [Isa bin Yunus] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dari [Abu Sa'id] berkata; \"Nabi shallallahu 'alaihi wasallam shalat di atas tikar.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Anas dan Al Mughirah.\" Abu Isa berkata; \"Hadits Abu Sa'id ini derajatnya hasan. Hadits ini diamalkan oleh mayoritas ulama kecuali beberapa kelompok saja dari ulama. Mereka lebih memilih shalat di atas bumi sebagai sesuatu yang sunah.\" Dan Abu Sufyan namanya adalah Thalhah bin Nafi'."},"305":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ أَبِي التَّيَّاحِ الضُّبَعِيِّ قَال سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَالِطُنَا حَتَّى إِنْ كَانَ يَقُولُ لِأَخٍ لِي صَغِيرٍ يَا أَبَا عُمَيْرٍ مَا فَعَلَ النُّغَيْرُ قَالَ وَنُضِحَ بِسَاطٌ لَنَا فَصَلَّى عَلَيْهِقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى حَدِيثُ أَنَسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ لَمْ يَرَوْا بِالصَّلَاةِ عَلَى الْبِسَاطِ وَالطُّنْفُسَةِ بَأْسًا وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ وَاسْمُ أَبِي التَّيَّاحِ يَزِيدُ بْنُ حُمَيْدٍ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Abu At Tayyah Adl Dluba'i] ia berkata; aku mendengar [Anas bin Malik] berkata; \"Rasulullah shallallahu 'alaihi wasallam selalu bergaul dengan kami, hingga beliau bersabda kepada adikku: \"Wahai Abu Umair, apa yang dilakukan oleh Nughair (nama burung)?\" Anas berkata; \"Karpet milik kami di gelar, lalu beliau shalat di atasnya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Abbas.\" Abu Isa berkata; \"Hadits Anas ini derajatnya hasan shahih. Banyak ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelahnya yang mengamalkan hadits ini, bahwa mereka tidak mempermasalahkan shalat di atas karpet atau permadani. Pendapat ini diambil oleh Ahmad dan Ishaq. Sedangkan nama Abu At Tayyah adalah Yazid bin Humaid.\""},"306":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا الْحَسَنُ بْنُ أَبِي جَعْفَرٍ عَنْ أَبِي الزُّبَيْرِ عَنْ أَبِي الطُّفَيْلِ عَنْ مُعَاذِ بْنِ جَبَلٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسْتَحِبُّ الصَّلَاةَ فِي الْحِيطَانِقَالَ أَبُو دَاوُدَ يَعْنِي الْبَسَاتِينَ قَالَ أَبُو عِيسَى حَدِيثُ مُعَاذٍ حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ الْحَسَنِ بْنِ أَبِي جَعْفَرٍ وَالْحَسَنُ بْنُ أَبِي جَعْفَرٍ قَدْ ضَعَّفَهُ يَحْيَى بْنُ سَعِيدٍ وَغَيْرُهُ وَأَبُو الزُّبَيْرِ اسْمُهُ مُحَمَّدُ بْنُ مُسْلِمِ بْنِ تَدْرُسَ وَأَبُو الطُّفَيْلِ اسْمُهُ عَامِرُ بْنُ وَاثِلَةَ","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Abu Daud] berkata; telah menceritakan kepada kami [Al Hasan bin Abu Ja'far] dari [Abu Az Zubair] dari [Abu Ath Thufail] dari [Mu'adz bin Jabal] berkata; \"Nabi shallallahu 'alaihi wasallam suka shalat di tempat yang dipagari.\" Abu Daud berkata; \"Yaitu di perkebunan.\" Abu Isa berkata; \"Hadits Mu'adz ini derajatnya gharib, dan kami tidak mengetahuinya kecuali dari hadits Al Hasan bin Abu Ja'far, sedangkan Al Hasan bin Abu Ja'far telah dilemahkan oleh Yahya bin Sa'id dan yang lainnya. Abu Zubair namanya adalah Muhammad bin Muslim bin Tadrus, dan Abu Tufail namanya adalah 'Amir bin Watsilah.\""},"307":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَهَنَّادٌ قَالَا حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وَضَعَ أَحَدُكُمْ بَيْنَ يَدَيْهِ مِثْلَ مُؤَخَّرَةِ الرَّحْلِ فَلْيُصَلِّ وَلَا يُبَالِي مَنْ مَرَّ وَرَاءَ ذَلِكَقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَسَهْلِ بْنِ أَبِي حَثْمَةَ وَابْنِ عُمَرَ وَسَبْرَةَ بْنِ مَعْبَدٍ الْجُهَنِيِّ وَأَبِي جُحَيْفَةَ وَعَائِشَةَ قَالَ أَبُو عِيسَى حَدِيثُ طَلْحَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ وَقَالُوا سُتْرَةُ الْإِمَامِ سُتْرَةٌ لِمَنْ خَلْفَهُ","id":"telah menceritakan kepada kami [Qutaibah] dan [Hannad] mereka berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak bin Harb] dari [Musa bin Thalhah] dari [Ayahnya] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian telah meletakkan (sesuatu) semisal pelana kuda di depannya, setelah itu ia tidak perlu memperdulikan siapa yang lewat di belakangnya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Hurairah, Sahl bin Abu Hatsmah, Ibnu Umar, Sabrah bin Ma'bad Al Juhani, Abu Juhaifah dan 'Aisyah.\" Abu Isa berkata; \"Hadits Thalhah derajatnya hasan shahih. Para ahli ilmu mengamalkan hadits ini, mereka berkata; \"Sutrah (pembatas) imam adalah sutrah untuk orang-orang yang dibelakangnya.\""},"308":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ أَبِي النَّضْرِ عَنْ بُسْرِ بْنِ سَعِيدٍ أَنَّ زَيْدَ بْنَ خَالِدٍ الْجُهَنِيَّ أَرْسَلَهُ إِلَى أَبِي جُهَيْمٍ يَسْأَلُهُ مَاذَا سَمِعَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَارِّ بَيْنَ يَدَيْ الْمُصَلِّي فَقَالَ أَبُو جُهَيْمٍقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ يَعْلَمُ الْمَارُّ بَيْنَ يَدَيْ الْمُصَلِّي مَاذَا عَلَيْهِ لَكَانَ أَنْ يَقِفَ أَرْبَعِينَ خَيْرٌ لَهُ مِنْ أَنْ يَمُرَّ بَيْنَ يَدَيْهِقَالَ أَبُو النَّضْرِ لَا أَدْرِي قَالَ أَرْبَعِينَ يَوْمًا أَوْ شَهْرًا أَوْ سَنَةً قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ وَأَبِي هُرَيْرَةَ وَابْنِ عُمَرَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى وَحَدِيثُ أَبِي جُهَيْمٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَأَنْ يَقِفَ أَحَدُكُمْ مِائَةَ عَامٍ خَيْرٌ لَهُ مِنْ أَنْ يَمُرَّ بَيْنَ يَدَيْ أَخِيهِ وَهُوَ يُصَلِّي وَالْعَمَلُ عَلَيْهِ عِنْدَ أَهْلِ الْعِلْمِ كَرِهُوا الْمُرُورَ بَيْنَ يَدَيْ الْمُصَلِّي وَلَمْ يَرَوْا أَنَّ ذَلِكَ يَقْطَعُ صَلَاةَ الرَّجُلِ وَاسْمُ أَبِي النَّضْرِ سَالِمٌ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ الْمَدِينِيِّ","id":"telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] berkata; telah menceritakan kepada kami Telah memberitakan kepada kami [Ma'n] berkata; telah menceritakan kepada kami [Malik bin Anas] dari [Abu An Nadlr] dari [Busr bin Sa'id] berkata; \"Zaid bin Khalid Al Juhani mengutusnya menemui Abu Juhaim untuk bertanya kepadanya tentang apa yang pernah ia dengar dari Nabi shallallahu 'alaihi wasallam berkenaan dengan seseorang yang lewat di hadapan orang yang sedang shalat. Maka [Abu Juhaim] pun berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya orang yang lewat di depan orang yang sedang shalat mengetahui apa yang akan menimpanya, sungguh ia berhenti selama empat puluh lebih baik daripada lewat di hadapannya.\" Abu An Nadlr berkata; \"Aku tidak tahu beliau mengatakan empat puluh orang, atau bulan, atau tahun.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Abu Sa'id Al Khudri, Abu Hurairah, Ibnu Umar dan Abdullah bin Umar.\" Abu Isa berkata; \"Hadits Abu Juhaim derajatnya hasan shahih. Telah diriwayatkan dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Sekiranya salah seorang dari kalian berhenti (menunggu) selama ratus tahun adalah lebih baik daripada harus melintasi saudaranya yang sedang shalat.\" Para ulama mengamalkan hadits ini, mereka memakruhkan seseorang melintas di hadapan orang yang sedang shalat. Namun mereka tidak berpandangan bahwa hal itu akan membatalkan shalat seseorang.\" Dan Abu An Nadlr namanya adalah Salim pelayan Umar bin Ubaidullah Al Madini."},"309":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكُنْتُ رَدِيفَ الْفَضْلِ عَلَى أَتَانٍ فَجِئْنَا وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِأَصْحَابِهِ بِمِنًى قَالَ فَنَزَلْنَا عَنْهَا فَوَصَلْنَا الصَّفَّ فَمَرَّتْ بَيْنَ أَيْدِيهِمْ فَلَمْ تَقْطَعْ صَلَاتَهُمْقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَائِشَةَ وَالْفَضْلِ بْنِ عَبَّاسٍ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى وَحَدِيثُ ابْنِ عَبَّاسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ مِنْ التَّابِعِينَ قَالُوا لَا يَقْطَعُ الصَّلَاةَ شَيْءٌ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَالشَّافِعِيُّ","id":"telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] berkata; telah menceritakan kepada kami [Yazid bin Zurai'] berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ubaidullah bin Utbah] dari [Ibnu Abbas] ia berkata; \"Aku membonceng Fadll di atas himar miliknya, lalu kami datang sedang Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya melaksanakan shalat di Mina.\" Ibnu Abbas berkata; \"Kami lalu turun dari atas keledai dan masuk ke dalam barisan shalat, himar itu lantas melintas di depan mereka, namun himar itu tidak menjadikan shalat mereka batal (karena melintasinya).\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari 'Aisyah, Fadll bin Abbas dan Ibnu Umar.\" Abu Isa berkata; \"Hadits Ibnu Abbas ini derajatnya hasan shahih. Mayoritas ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka dari kalangan tabi'in mengamalkan hadits ini. Mereka mengatakan, \"Tidak ada sesuatu yang membatalkan shalat.\" Pendapat ini diambil oleh Sufyan Ats Tsauri dan Syafi'i."},"310":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا يُونُسُ بْنُ عُبَيْدٍ وَمَنْصُورُ بْنُ زَاذَانَ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ قَال سَمِعْتُ أَبَا ذَرٍّ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى الرَّجُلُ وَلَيْسَ بَيْنَ يَدَيْهِ كَآخِرَةِ الرَّحْلِ أَوْ كَوَاسِطَةِ الرَّحْلِ قَطَعَ صَلَاتَهُ الْكَلْبُ الْأَسْوَدُ وَالْمَرْأَةُ وَالْحِمَارُ فَقُلْتُ لِأَبِي ذَرٍّ مَا بَالُ الْأَسْوَدِ مِنْ الْأَحْمَرِ مِنْ الْأَبْيَضِ فَقَالَ يَا ابْنَ أَخِي سَأَلْتَنِي كَمَا سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ الْكَلْبُ الْأَسْوَدُ شَيْطَانٌقَالَ وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ وَالْحَكَمِ بْنِ عَمْرٍو الْغِفَارِيِّ وَأَبِي هُرَيْرَةَ وَأَنَسٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي ذَرٍّ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ ذَهَبَ بَعْضُ أَهْلِ الْعِلْمِ إِلَيْهِ قَالُوا يَقْطَعُ الصَّلَاةَ الْحِمَارُ وَالْمَرْأَةُ وَالْكَلْبُ الْأَسْوَدُ قَالَ أَحْمَدُ الَّذِي لَا أَشُكُّ فِيهِ أَنَّ الْكَلْبَ الْأَسْوَدَ يَقْطَعُ الصَّلَاةَ وَفِي نَفْسِي مِنْ الْحِمَارِ وَالْمَرْأَةِ شَيْءٌ قَالَ إِسْحَقُ لَا يَقْطَعُهَا شَيْءٌ إِلَّا الْكَلْبُ الْأَسْوَدُ","id":"telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Husyaim] berkata; telah mengabarkan kepada kami [Yunus bin Ubaid] dan [Manshur bin Zadzan] dari [Humaid bin Hilal] dari [Abdullah bin Ash Shamit] ia berkata; \"Aku mendengar [Abu Dzar] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang laki-laki shalat sedang di depannya tidak ada pelana atau sekedup yang dipasang di atas hewan tunggangan, maka shalat akan rusak dengan melintasnya anjing hitam, wanita atau keledai.\" Maka aku pun bertanya kepada Abu Dzar, \"Kenapa harus hitam dan tidak merah atau putih?\" ia menjawab, \"Wahai saudaraku, engkau telah bertanya kepadaku dengan sesuatu yang pernah aku tanyakan kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Anjing hitam adalah setan.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Sa'id, Al Hakam bin 'Amru Al Ghifari, Abu Hurairah dan Anas.\" Abu Isa berkata; \"Hadits Abu Dzar ini derajatnya hasan shahih. Sebagian ahli ilmu berpendapat dengan hadits ini, mereka berkata; \"Shalat akan batal dengan melintasnya keledai, wanita dan anjing.\" Ahmad berkata; \"Aku tidak ragukan lagi bahwa anjing hitam dapat membatalkan shalat. Sedangkan keledai dan wanita masih menyisakan keraguan dalam hatiku.\""},"311":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي بَيْتِ أُمِّ سَلَمَةَ مُشْتَمِلًا فِي ثَوْبٍ وَاحِدٍقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَجَابِرٍ وَسَلَمَةَ بْنِ الْأَكْوَعِ وَأَنَسٍ وَعَمْرِو بْنِ أَبِي أَسِيدٍ وَأَبِي سَعِيدٍ وَكَيْسَانَ وَابْنِ عَبَّاسٍ وَعَائِشَةَ وَأُمِّ هَانِئٍ وَعَمَّارِ بْنِ يَاسِرٍ وَطَلْقِ بْنِ عَلِيٍّ وَعُبَادَةَ بْنِ الصَّامِتِ الْأَنْصَارِيِّ قَالَ أَبُو عِيسَى حَدِيثُ عُمَرَ بْنِ أَبِي سَلَمَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ مِنْ التَّابِعِينَ وَغَيْرِهِمْ قَالُوا لَا بَأْسَ بِالصَّلَاةِ فِي الثَّوْبِ الْوَاحِدِ وَقَدْ قَالَ بَعْضُ أَهْلِ الْعِلْمِ يُصَلِّي الرَّجُلُ فِي ثَوْبَيْنِ","id":"telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata; telah menceritakan kepada kami [Al Laits] dari [Hisyam bin Urwah] dari [Ayahnya] dari [Umar bin Abu Salamah] bahwasanya ia pernah melihat Rasulullah shallallahu 'alaihi wasallam shalat di rumah Ummu Salamah berselimut dengan satu kain.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Abu Hurairah, Jabir, Salamah bin Al Akwa', Anas, Umar bin Abu Asid, Abu Sa'id, Kaisan, Ibnu Abbas, 'Aisyah, Ummu Hani', 'Ammar bin Yasir, Thalq bin Ali dan Ubadah bin Ash Shamit Al Anshari.\" Abu Isa berkata; \"Hadits Umar bin Abu Salamah derajatnya hasan shahih. Mayoritas ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka dari kalangan tabi'in dan selainnya mengamalkan hadits ini. Mereka berkata; \"Tidak apa-apa shalat dengan menggunakan satu kain. Dan sebagian ahli ilmu berkata; \"Hendaknya seseorang shalat dengan dua kain.\""},"312":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ صَلَّى نَحْوَ بَيْتِ الْمَقْدِسِ سِتَّةَ أَوْ سَبْعَةَ عَشَرَ شَهْرًا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ أَنْ يُوَجِّهَ إِلَى الْكَعْبَةِ فَأَنْزَلَ اللَّهُ تَعَالَى{ قَدْ نَرَى تَقَلُّبَ وَجْهِكَ فِي السَّمَاءِ فَلَنُوَلِّيَنَّكَ قِبْلَةً تَرْضَاهَا فَوَلِّ وَجْهَكَ شَطْرَ الْمَسْجِدِ الْحَرَامِ }فَوَجَّهَ نَحْوَ الْكَعْبَةِ وَكَانَ يُحِبُّ ذَلِكَ فَصَلَّى رَجُلٌ مَعَهُ الْعَصْرَ ثُمَّ مَرَّ عَلَى قَوْمٍ مِنْ الْأَنْصَارِ وَهُمْ رُكُوعٌ فِي صَلَاةِ الْعَصْرِ نَحْوَ بَيْتِ الْمَقْدِسِ فَقَالَ هُوَ يَشْهَدُ أَنَّهُ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَّهُ قَدْ وَجَّهَ إِلَى الْكَعْبَةِ قَالَ فَانْحَرَفُوا وَهُمْ رُكُوعٌقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَابْنِ عَبَّاسٍ وَعُمَارَةَ بْنِ أَوْسٍ وَعَمْرِو بْنِ عَوْفٍ الْمُزَنِيِّ وَأَنَسٍ قَالَ أَبُو عِيسَى وَحَدِيثُ الْبَرَاءِ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ سُفْيَانُ الثَّوْرِيُّ عَنْ أَبِي إِسْحَقَ حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَ كَانُوا رُكُوعًا فِي صَلَاةِ الصُّبْحِ قَالَ أَبُو عِيسَى وَحَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Waki'] dari [Isra'il] dari [Ishaq] dari [Al Bara` bin 'Azib] ia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam datang di Madinah, beliau sempat shalat menghadap ke Baitul Maqdis selama enam atau tujuh belas bulan. Sedangkan Rasulullah shallallahu 'alaihi wasallam menyukai sekiranya beliau menghadap ke arah Ka'bah, maka Allah pun menurunkan ayat: (Sungguh Kami (sering) melihat mukamu menengadah ke langit, maka sungguh Kami akan memalingkan kamu ke kiblat yang kamu sukai. Palingkanlah mukamu ke arah Masjidil Haram). Maka beliau pun menghadap ke arah kiblat, dan beliau menyukai hal itu.\" Kemudian ada seseorang shalat asar bersama beliau. Setelah itu ia melintasi beberapa orang dari kaum Anshar yang sedang rukuk dalam shalat asar mengadap arah Baitul Maqdis, maka ia pun mengatakan -seraya bersaksi-, bahwa ia pernah shalat bersama Rasulullah shallallahu 'alaihi wasallam, dan beliau menghadap ke arah Ka'bah.\" Al Bara` berkata; \"Maka orang-orang pun berpaling ke arah Ka'bah dalam keadaan rukuk.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Umar, Ibnu Abbas, 'Umarah bin Aus, 'Amru bin 'Auf Al Muzani dan Anas.\" Abu Isa berkata; \"Hadits Al Bara` adalah hadits hasan shahih dan [Sufyan Ats Tsauri] telah meriwayatkan dari [Abu Ishaq], telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abdullah bin Dinar] dari [Ibnu Umar] ia berkata; \"Mereka rukuk di dalam shalat Shubuh.\" Abu Isa berkata; \"Hadits Ibnu Umar adalah hadits hasan shahih.\""},"313":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي مَعْشَرٍ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ قِبْلَةٌحَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي مَعْشَرٍ مِثْلَهُ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ قَدْ رُوِيَ عَنْهُ مِنْ غَيْرِ هَذَا الْوَجْهِ وَقَدْ تَكَلَّمَ بَعْضُ أَهْلِ الْعِلْمِ فِي أَبِي مَعْشَرٍ مِنْ قِبَلِ حِفْظِهِ وَاسْمُهُ نَجِيحٌ مَوْلَى بَنِي هَاشِمٍ قَالَ مُحَمَّدٌ لَا أَرْوِي عَنْهُ شَيْئًا وَقَدْ رَوَى عَنْهُ النَّاسُ قَالَ مُحَمَّدٌ وَحَدِيثُ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ الْمَخْرَمِيِّ عَنْ عُثْمَانَ بْنِ مُحَمَّدٍ الْأَخْنَسِيِّ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ أَقْوَى مِنْ حَدِيثِ أَبِي مَعْشَرٍ وَأَصَحُّ","id":"telah menceritakan kepada kami [Muhammad bin Abu Ma'syar] berkata; telah menceritakan kepada kami [Ayahku] berkata; telah menceritakan kepada kami [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Antara timur dan barat adalah arah kiblat.\" Telah menceritakan kepada kami [Yahya bin Musa] berkata; telah menceritakan kepada kami [Muhammad bin Abu Ma'syar] sebagimana dalam hadits tersebut. Abu Isa berkata; \"Hadits Abu Hurairah ini telah diriwayatkan darinya dari beberapa jalur.\" Sebagian ahli ilmu telah memperbincangkan Abu Ma'syar berkenaan masalah hafalannya, namanya adalah Najih, budak bani Hasyim. Muhammmad berkata; \"Aku tidak pernah meriwayatkan sesuatu pun darinya. Namun ada beberapa orang yang telah meriwayatkan darinya.\" Muhammad berkata lagi, \"Hadits Abdullah bin Ja'far Al Makhrami, dari Utsman bin Muhammad Al Akhnasi, dari Sa'id Al Maqburi, dari Abu Hurairah lebih kuat dan shahih ketimbang hadits Abu Ma'syar.\""},"314":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ بَكْرٍ الْمَرْوَزِيُّ حَدَّثَنَا الْمُعَلَّى بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الْمَخْرَمِيُّ عَنْ عُثْمَانَ بْنِ مُحَمَّدٍ الْأَخْنَسِيِّ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ قِبْلَةٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَإِنَّمَا قِيلَ عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الْمَخْرَمِيُّ لِأَنَّهُ مِنْ وَلَدِ الْمِسْوَرِ بْنِ مَخْرَمَةَ وَقَدْ رُوِيَ عَنْ غَيْرِ وَاحِدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ قِبْلَةٌ مِنْهُمْ عُمَرُ بْنُ الْخَطَّابِ وَعَلِيُّ بْنُ أَبِي طَالِبٍ وَابْنُ عَبَّاسٍ و قَالَ ابْنُ عُمَرَ إِذَا جَعَلْتَ الْمَغْرِبَ عَنْ يَمِينِكَ وَالْمَشْرِقَ عَنْ يَسَارِكَ فَمَا بَيْنَهُمَا قِبْلَةٌ إِذَا اسْتَقْبَلْتَ الْقِبْلَةَ و قَالَ ابْنُ الْمُبَارَكِ مَا بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ قِبْلَةٌ هَذَا لِأَهْلِ الْمَشْرِقِ وَاخْتَارَ عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ التَّيَاسُرَ لِأَهْلِ مَرْوٍ","id":"telah menceritakan kepada kami [Al Hasan Bakr Al Marwazi] berkata; telah menceritakan kepada kami [Al Mu'alla bin Manshur] berkata; telah menceritakan kepada kami [Abdullah bin Ja'far Al Makhzumi] dari [Utsman bin Muhammad Al Akhnas] dari [Sa'id Al Maqburi] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Antara timur dan barat adalah arah kiblat.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Ia disebut dengan Abdullah bin Ja'far Al Makhzumi karena ia adalah anak dari Al Miswar bin Makhramah. Telah diriwayatkan lebih dari seorang dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Antara timur dan barat adalah arah kiblat.\" Di antara yang berpendapat seperti itu adalah Umar bin Al Khaththab, Ali bin Abu Thalib dan Ibnu Abbas. Ibnu Umar berkata; \"Jika engkau jadikan arah barat pada sisi kananmu dan arah timur pada sisi kirimu, maka antara keduanya adalah arah kibat. Dan dengan begitu engkau telah menghadap ke kiblat.\" Bin Al Mubarak berkata; \"Antara timur dan barat adalah arah kiblat, dan ini adalah untuk penduduk wilayah timur.\" Dan Abdullah bin Bin Al Mubarak memilih arah kiri bagi penduduk Marwa.\""},"315":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَشْعَثُ بْنُ سَعِيدٍ السَّمَّانُ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ عَنْ أَبِيهِ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فِي لَيْلَةٍ مُظْلِمَةٍ فَلَمْ نَدْرِ أَيْنَ الْقِبْلَةُ فَصَلَّى كُلُّ رَجُلٍ مِنَّا عَلَى حِيَالِهِ فَلَمَّا أَصْبَحْنَا ذَكَرْنَا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَ{ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَيْسَ إِسْنَادُهُ بِذَاكَ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ أَشْعَثَ السَّمَّانِ وَأَشْعَثُ بْنُ سَعِيدٍ أَبُو الرَّبِيعِ السَّمَّانُ يُضَعَّفُ فِي الْحَدِيثِ وَقَدْ ذَهَبَ أَكْثَرُ أَهْلِ الْعِلْمِ إِلَى هَذَا قَالُوا إِذَا صَلَّى فِي الْغَيْمِ لِغَيْرِ الْقِبْلَةِ ثُمَّ اسْتَبَانَ لَهُ بَعْدَمَا صَلَّى أَنَّهُ صَلَّى لِغَيْرِ الْقِبْلَةِ فَإِنَّ صَلَاتَهُ جَائِزَةٌ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَأَحْمَدُ وَإِسْحَقُ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Asy'ats bin Sa'id As Samman] dari ['Ashim bin Ubaidullah] dari [Abdullah bin 'Amir bin Rabi'ah] dari [Ayahnya] ia berkata; \"Kami bersama Nabi shallallahu 'alaihi wasallam dalam sebuah perjalanan di malam yang gelap gulita hingga kami tidak mengetahui ke mana arah kiblat, maka setiap orang dari kami shalat menurut keyakinannya. Keesokan harinya hal itu kami sampaikan kepada Nabi shallallahu 'alaihi wasallam, maka turunlah ayat: \"(Maka kemanapun kamu menghadap di situlah wajah Allah).\" Abu Isa berkata; \"Hadits ini sanadnya tidak kuat, kami tidak mengetahuinya kecuali dari hadits Asy'ats As Samman, Asy'ats bin Sa'id adalah Abu Ar Rabi' As Samman, dan ia dianggap lemah dalam masalah hadits. Kebanyakan para ahli ilmu sependapat dengan pemahaman hadits ini, mereka mengatakan, \"Apabila suasa mendung seseorang shalat tidak menghadap kiblat, setelah itu mengetahui bahwa ia shalat tidak menghadap kiblat maka shalatnya sah.\" Pendapat inilah yang diambil oleh Sufyan Ats Tsauri, bin Al Mubarak, Ahmad dan Ishaq.\""},"316":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا الْمُقْرِئُ حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ عَنْ زَيْدِ بْنِ جَبِيرَةَ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُصَلَّى فِي سَبْعَةِ مَوَاطِنَ فِي الْمَزْبَلَةِ وَالْمَجْزَرَةِ وَالْمَقْبَرَةِ وَقَارِعَةِ الطَّرِيقِ وَفِي الْحَمَّامِ وَفِي مَعَاطِنِ الْإِبِلِ وَفَوْقَ ظَهْرِ بَيْتِ اللَّهِحَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا سُوَيْدُ بْنُ عَبْدِ الْعَزِيزِ عَنْ زَيْدِ بْنِ جَبِيرَةَ عَنْ دَاوُدَ بْنِ حُصَيْنٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ بِمَعْنَاهُ قَالَ وَفِي الْبَاب عَنْ أَبِي مَرْثَدٍ وَجَابِرٍ وَأَنَسٍ أَبُو مَرْثَدٍ اسْمُهُ كَنَّازُ بْنُ حُصَيْنٍ قَالَ أَبُو عِيسَى وَحَدِيثُ ابْنِ عُمَرَ إِسْنَادُهُ لَيْسَ بِذَاكَ الْقَوِيِّ وَقَدْ تُكُلِّمَ فِي زَيْدِ بْنِ جَبِيرَةَ مِنْ قِبَلِ حِفْظِهِ قَالَ أَبُو عِيسَى وَزَيْدُ بْنُ جُبَيْرٍ الْكُوفِيُّ أَثْبَتُ مِنْ هَذَا وَأَقْدَمُ وَقَدْ سَمِعَ مِنْ ابْنِ عُمَرَ وَقَدْ رَوَى اللَّيْثُ بْنُ سَعْدٍ هَذَا الْحَدِيثَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ الْعُمَرِيِّ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ وَحَدِيثُ دَاوُدَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشْبَهُ وَأَصَحُّ مِنْ حَدِيثِ اللَّيْثِ بْنِ سَعْدٍ وَعَبْدُ اللَّهِ بْنُ عُمَرَ الْعُمَرِيُّ ضَعَّفَهُ بَعْضُ أَهْلِ الْحَدِيثِ مِنْ قِبَلِ حِفْظِهِ مِنْهُمْ يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Al Muqri`] berkata; telah menceritakan kepada kami [Yahya bin Ayyub] dari [Zaid bin Jabirah] dari [Daud bin Al Hushain] dari [Nafi'] dari [Ibnu Umar] berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang shalat di tujuh tempat; tempat pembuangan sampah, tempat pemotongan hewan, pemakaman, tengah jalan, pemandian umum, tempat menderumnya unta dan di atas Ka'bah.\" Telah menceritakan kepada kami [Ali bin Hujr] berkata; telah menceritakan kepada kami [Suwaid bin Abdul Aziz] dari [Zaid bin Jabirah] dari [Daud bin Hushain] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam dengan hadits serupa secara makna.\" Ia berkata; \"Dalam bab ini ada juga hadits dari Abu Martsad, Jabir dan Anas. Abu Martsad namanya adalah Kannaz bin Hushain.\" Abu Isa berkata; \"Hadits Ibnu Umar sanadnya tidak begitu kuat, karena Zaid bin Jabirah telah perbincangkan dari segi hafalannya.\" Abu Isa berkata; \"Zaid bin Jubair Al Kufi lebih kuat dan lebih dahulu dari ini Zaid bin Jabirah, karena ia pernah mendengar dari Ibnu Umar. Dan [Laits bin Sa'ad] telah meriwayatkan hadits ini dari [Abdullah bin Umar Al Umari] dari [Nafi'] dari [Ibnu Umar] dari [Umar] dari Nabi shallallahu 'alaihi wasallam dengan hadits yang semisal dengannya. Adapun hadits Daud dari Nafi', dari Ibnu Umar, dari Nabi shallallahu 'alaihi wasallam lebih mirip dan lebih shahih dari hadits Laits bin Sa'ad, karena Abdullah bin Umar Al Umari telah dilemahkan oleh sebagian ahli hadits dari segi hafalannya. Dan di antara mereka yang melemahkannya adalah Yahya bin Sa'id Al Qaththan.\""},"317":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ أَبِي بَكْرِ بْنِ عَيَّاشٍ عَنْ هِشَامٍ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلُّوا فِي مَرَابِضِ الْغَنَمِ وَلَا تُصَلُّوا فِي أَعْطَانِ الْإِبِلِحَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ أَبِي بَكْرِ بْنِ عَيَّاشٍ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ أَوْ بِنَحْوِهِ قَالَ وَفِي الْبَاب عَنْ جَابِرِ بْنِ سَمُرَةَ وَالْبَرَاءِ وَسَبْرَةَ بْنِ مَعْبَدٍ الْجُهَنِيِّ وَعَبْدِ اللَّهِ بْنِ مُغَفَّلٍ وَابْنِ عُمَرَ وَأَنَسٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَعَلَيْهِ الْعَمَلُ عِنْدَ أَصْحَابِنَا وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ وَحَدِيثُ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثٌ غَرِيبٌ وَرَوَاهُ إِسْرَائِيلُ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ مَوْقُوفًا وَلَمْ يَرْفَعْهُ وَاسْمُ أَبِي حَصِينٍ عُثْمَانُ بْنُ عَاصِمٍ الْأَسَدِيُّ","id":"telah menceritakan kepada kami [Abu Kuraib] berkata; telah menceritakan kepada kami [Yahya bin Adam] dari [Abu Bakar bin Ayyasy] dari [Hisyam] dari [Ibnu Sirin] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalatlah kalian di kandang kambing dan jangan kalian shalat di tempat menderumnya unta.\" Telah menceritakan kepada kami [Abu Kuraib] berkata; telah menceritakan kepada kami [Yahya bin Adam] dari [Abu Bakar bin Ayyasy] dari [Abu Hashin] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam dengan hadits yang semisal atau yang semakna dengannya.\" Ia berkata; \"Dalam bab ini ada juga hadits dari Jabir bin Samrah, Al Barra`, Sabrah bin Ma'bad Al Juhani, Abdullah bin Mughaffal, Ibnu Umar dan Anas.\" Abu Isa berkata; \"Hadits Abu Hurairah ini derajatnya hasan shahih. Hadits ini diamalkan oleh sebagian sahabat kami. Dan pendapat ini juga diambil oleh Ahmad dan Ishaq. Sedangkan hadits Abu Hushain dari Abu Shalih, dari Abu Hurairah, dari Nabi shallallahu 'alaihi wasallam adalah hadits gharib. [Isra'il] telah meriwayatkannya dari [Abu Hashin] dari [Abu Shalih] dari [Abu Hurairah] secara mauquf dan ia tidak memarfu'kannya kepada Nabi shallallahu 'alaihi wasallam.\" Abu Hushain namanya adalah Utsman bin 'Ashim Al Asadi.\""},"318":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ عَنْ أَبِي التَّيَّاحِ الضُّبَعِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي فِي مَرَابِضِ الْغَنَمِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو التَّيَّاحِ الضُّبَعِيُّ اسْمُهُ يَزِيدُ بْنُ حُمَيْدٍ","id":"telah menceritakan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] dari [Abu At Tayyah Adl Dluba'i] dari [Anas bin Malik] berkata; \"Nabi shallallahu 'alaihi wasallam pernah shalat di kandang kambing.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Dan Abu At Tayyah Adl Dluba'i namanya Yazid bin Humaid.\""},"319":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ وَيَحْيَى بْنُ آدَمَ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَبَعَثَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَاجَةٍ فَجِئْتُ وَهُوَ يُصَلِّي عَلَى رَاحِلَتِهِ نَحْوَ الْمَشْرِقِ وَالسُّجُودُ أَخْفَضُ مِنْ الرُّكُوعِقَالَ وَفِي الْبَاب عَنْ أَنَسٍ وَابْنِ عُمَرَ وَأَبِي سَعِيدٍ وَعَامِرِ بْنِ رَبِيعَةَ قَالَ أَبُو عِيسَى حَدِيثُ جَابِرٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ جَابِرٍ وَالْعَمَلُ عَلَى هَذَا عِنْدَ عَامَّةِ أَهْلِ الْعِلْمِ لَا نَعْلَمُ بَيْنَهُمْ اخْتِلَافًا لَا يَرَوْنَ بَأْسًا أَنْ يُصَلِّيَ الرَّجُلُ عَلَى رَاحِلَتِهِ تَطَوُّعًا حَيْثُ مَا كَانَ وَجْهُهُ إِلَى الْقِبْلَةِ أَوْ غَيْرِهَا","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Waki'] dan [Yahya bin Adam] keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Az Zubair] dari [Jabir] ia berkata; \"Nabi shallallahu 'alaihi wasallam mengutusku pada suatu keperluan, lalu aku datang menghadap sedang beliau waktu itu shalat di atas kendaraannya menghadap ke arah timur, beliau sujud lebih rendah dari posisi rukuk.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Anas, Ibnu Umar, Abu Sa'id dan Amir bin Rabi'ah.\" Abu Isa berkata; \"Hadits Jabir ini derajatnya hasan shahih. Hadits ini telah diriwayatkan dari Jabir dengan banyak jalur. Mayoritas ahli ilmu mengamalkan hadits ini dan kami tidak mendapati adanya perselisihan di antara mereka. mereka berpendapat bahwa seseorang boleh shalat sunah di atas kendaraannya, baik kendaraannya tersebut menghadap kiblat atau selainnya.\""},"320":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى إِلَى بَعِيرِهِ أَوْ رَاحِلَتِهِ وَكَانَ يُصَلِّي عَلَى رَاحِلَتِهِ حَيْثُ مَا تَوَجَّهَتْ بِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ قَوْلُ بَعْضِ أَهْلِ الْعِلْمِ لَا يَرَوْنَ بِالصَّلَاةِ إِلَى الْبَعِيرِ بَأْسًا أَنْ يَسْتَتِرَ بِهِ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] berkata; telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] berkata; \"Nabi shallallahu 'alaihi wasallam shalat di atas unta atau kendaraannya, dan beliau shalat di atas kendaraannya menghadap kemana kendaraannya menghadap.\" Abu Isa berkata; \"Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Ini adalah pendapat yang diambil oleh sebagian ahli ilmu, bahwa mereka berpandangan tidak apa-apa shalat dengan menjadikan unta sebagai pemabatas (shalat).\""},"321":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا حَضَرَ الْعَشَاءُ وَأُقِيمَتْ الصَّلَاةُ فَابْدَءُوا بِالْعَشَاءِقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَابْنِ عُمَرَ وَسَلَمَةَ بْنِ الْأَكْوَعِ وَأُمِّ سَلَمَةَ قَالَ أَبُو عِيسَى حَدِيثُ أَنَسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَعَلَيْهِ الْعَمَلُ عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ ��َسَلَّمَ مِنْهُمْ أَبُو بَكْرٍ وَعُمَرُ وَابْنُ عُمَرَ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ يَقُولَانِ يَبْدَأُ بِالْعَشَاءِ وَإِنْ فَاتَتْهُ الصَّلَاةُ فِي الْجَمَاعَةِ قَالَ أَبُو عِيسَى سَمِعْت الْجَارُودَ يَقُولُ سَمِعْتُ وَكِيعًا يَقُولُ فِي هَذَا الْحَدِيثِ يَبْدَأُ بِالْعَشَاءِ إِذَا كَانَ طَعَامًا يَخَافُ فَسَادَهُ وَالَّذِي ذَهَبَ إِلَيْهِ بَعْضُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ أَشْبَهُ بِالِاتِّبَاعِ وَإِنَّمَا أَرَادُوا أَنْ لَا يَقُومَ الرَّجُلُ إِلَى الصَّلَاةِ وَقَلْبُهُ مَشْغُولٌ بِسَبَبِ شَيْءٍ وَقَدْ رُوِيَ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ قَالَ لَا نَقُومُ إِلَى الصَّلَاةِ وَفِي أَنْفُسِنَا شَيْءٌ","id":"telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Anas] sampai kepada kepada Nabi, beliau bersabda; \"Jika makan malam telah siap dan iqamah dikumandangkan, maka mulailah dengan makan malam.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari 'Aisyah, Ibnu Umar, Salamah bin Al Akwa' dan Ummu Salamah.\" Abu Isa berkata; \"Hadits Anas ini derajatnya hasan shahih. Hadits ini diamalkan oleh sebagian ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, seperti Abu Bakar dan Ibnu Umar. Pendapat ini juga diambil oleh Ahmad dan Ishaq, keduanya berkata; \"Hendaklah ia memulai dengan makan malam meskipun ketinggalan shalat berjama'ah.\" Abu Isa berkata; \"Aku mendengar Al Jarud berkata; \"Aku mendengar Waki' berkata tentang hadits ini, \"Hendaknya ia makan malam dahulu jika dikawatirkan makanannya menjadi rusak (busuk/basi).\" Pendapat yang dianut oleh sebagian ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan yang lainnya lebih berhak untuk diikuti, hanyasanya yang mereka inginkan adalah agar seseorang dalam mengerjakan shalat hatinya tidak disibukkan dengan sesuatu.\" Diriwayatkan dari Ibnu Abbas bahwa ia berkata; \"Kami tidak melaksanakan shalat ketika dalam hati kami masih ada sesuatu.\""},"322":{"ar":"وَرُوِي عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا وُضِعَ الْعَشَاءُ وَأُقِيمَتْ الصَّلَاةُ فَابْدَءُوا بِالْعَشَاءِقَالَ وَتَعَشَّى ابْنُ عُمَرَ وَهُوَ يَسْمَعُ قِرَاءَةَ الْإِمَامِ قَالَ حَدَّثَنَا بِذَلِكَ هَنَّادٌ حَدَّثَنَا عَبْدَةُ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ","id":"Diriwayatkan dari Ibnu Abbas, dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau bersabda: \"Jika makan malam telah tersedia dan iqamah dikumandangkan, maka dahulukanlah makan malam.\" Ia berkata; \"Ibnu Umar makan malam sedangkan ia mendengar bacaan imam.\" Ia berkata; \"Demikian [Hannad] menceritakan kepada kami, ia berkata; telah menceritakan kepada kami [Abdah] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar].\""},"323":{"ar":"حَدَّثَنَا هَارُونُ بْنُ إِسْحَقَ الْهَمْدَانِيُّ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ الْكِلَابِيُّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا نَعَسَ أَحَدُكُمْ وَهُوَ يُصَلِّي فَلْيَرْقُدْ حَتَّى يَذْهَبَ عَنْهُ النَّوْمُ فَإِنَّ أَحَدَكُمْ إِذَا صَلَّى وَهُوَ يَنْعَسُ لَعَلَّهُ يَذْهَبُ يَسْتَغْفِرُ فَيَسُبُّ نَفْسَهُقَالَ وَفِي الْبَاب عَنْ أَنَسٍ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Harun bin Ishaq Al Hamdani] berkata; telah menceritakan kepada kami [Abdah bin Sulaiman Al Kilabi] dari [Hisyam bin Urwah] dari [ayahnya] dari ['Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian mengantuk ketika sedang melaksanakan shalat, maka hendaklah ia pergi tidur. Sebab jika salah seorang dari kalian shalat dalam keadaan mengantuk, maka dimungkinkan ketika ia memohon ampunan justru mencela dirinya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Anas dan Abu Hurairah.\" Abu Isa berkata; \"Hadits 'Aisyah ini derajatnya hasan shahih.\""},"324":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ وَهَنَّادٌ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ أَبَانَ بْنِ يَزِيدَ الْعَطَّارِ عَنْ بُدَيْلِ بْنِ مَيْسَرَةَ الْعُقَيْلِيِّ عَنْ أَبِي عَطِيَّةَ رَجُلٍ مِنْهُمْ قَالَكَانَ مَالِكُ بْنُ الْحُوَيْرِثِ يَأْتِينَا فِي مُصَلَّانَا يَتَحَدَّثُ فَحَضَرَتْ الصَّلَاةُ يَوْمًا فَقُلْنَا لَهُ تَقَدَّمْ فَقَالَ لِيَتَقَدَّمْ بَعْضُكُمْ حَتَّى أُحَدِّثَكُمْ لِمَ لَا أَتَقَدَّمُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ زَارَ قَوْمًا فَلَا يَؤُمَّهُمْ وَلْيَؤُمَّهُمْ رَجُلٌ مِنْهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ قَالُوا صَاحِبُ الْمَنْزِلِ أَحَقُّ بِالْإِمَامَةِ مِنْ الزَّائِرِ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ إِذَا أَذِنَ لَهُ فَلَا بَأْسَ أَنْ يُصَلِّيَ بِهِ و قَالَ إِسْحَقُ بِحَدِيثِ مَالِكِ بْنِ الْحُوَيْرِثِ وَشَدَّدَ فِي أَنْ لَا يُصَلِّيَ أَحَدٌ بِصَاحِبِ الْمَنْزِلِ وَإِنْ أَذِنَ لَهُ صَاحِبُ الْمَنْزِلِ قَالَ وَكَذَلِكَ فِي الْمَسْجِدِ لَا يُصَلِّي بِهِمْ فِي الْمَسْجِدِ إِذَا زَارَهُمْ يَقُولُ لِيُصَلِّ بِهِمْ رَجُلٌ مِنْهُمْ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] dan [Hannad] keduanya; telah menceritakan kepada kami [Waki'] dari [Aban bjn Yazid Al Aththar] dari [Budail bin Maisarah Al Uqaili] dari [Abu 'Athiyyah] -seorang dari bani Uqail- ia berkata; \" [Malik bin Al Huwairits] datang ke tempat shalat kami untuk membicarakan sesuatu, lalu tibalah waktu shalat, kami pun berkata kepadanya, \"Hendaklah engkau maju (menjadi imam), \" namun ia menjawab, \"Hendaklah salah seorang dari kalian maju menjadi imam hingga aku ceritakan kenapa aku tidak ingin maju. Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengunjungi suatu kaum maka janganlah ia menjadi imam untuk mereka, tetapi hendaklah seorang dari mereka yang menjadi imam.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Hadits ini diamalkan oleh banyak ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka. Mereka berkata; \"Pemilik rumah lebih berhak untuk menjadi imam daripada yang berkunjung.\" Sedangkan sebagian ahli ilmu yang lain berkata; \"Jika tuan rumah memberikan izin maka tidak mengapa ia menjadi imam.\" Ishaq berpendapat berdasarkan hadits Malik bin Al Huwairits dan bersikap tegas, bahwa seseorang tidak boleh shalat dengan mengimami tuan rumah meskipun ia mendapatkan izin.\" Dan Ishaq juga mengatakan, \"Hal ini juga berlaku di dalam masjid, seseorang tidak boleh mengimami suatu kaum yang ia kunjungi. Dan hendaklah ia berkata; \"Hendaknya seorang dari mereka yang menjadi imam.\""},"325":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنِي حَبِيبُ بْنُ صَالِحٍ عَنْ يَزِيدَ بْنِ شُرَيْحٍ عَنْ أَبِي حَيٍّ الْمُؤَذِّنِ الْحِمْصِيِّ عَنْ ثَوْبَانَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِامْرِئٍ أَنْ يَنْظُرَ فِي جَوْفِ بَيْتِ امْرِئٍ حَتَّى يَسْتَأْذِنَ فَإِنْ نَظَرَ فَقَدْ دَخَلَ وَلَا يَؤُمَّ قَوْمًا فَيَخُصَّ نَفْسَهُ بِدَعْوَةٍ دُونَهُمْ فَإِنْ فَعَلَ فَقَدْ خَانَهُمْ وَلَا يَقُومُ إِلَى الصَّلَاةِ وَهُوَ حَقِنٌقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَبِي أُمَامَةَ قَالَ أَبُو عِيسَى حَدِيثُ ثَوْبَانَ حَدِيثٌ حَسَنٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ السَّفْرِ بْنِ نُسَيْرٍ عَنْ يَزِيدَ بْنِ شُرَيْحٍ عَنْ أَبِي أُمَامَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرُوِيَ هَذَا الْحَدِيثُ عَنْ يَزِيدَ بْنِ شُرَيْحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَأَنَّ حَدِيثَ يَزِيدَ بْنِ شُرَيْحٍ عَنْ أَبِي حَيٍّ الْمُؤَذِّنِ عَنْ ثَوْبَانَ فِي هَذَا أَجْوَدُ إِسْنَادًا وَأَشْهَرُ","id":"Telah menceritakan kepada kami [Ali bin Hujr] berkata; telah menceritakan kepada kami [Isma'il bin Ayyasy] berkata; telah menceritakan kepadaku [Habib bin Shalih] dari [Yazid bin Syurahbil] dari [Abu Hayy Al Mu'adzin Al Himsh] dari [Tsauban] dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seseorang melihat ke dalam rumah orang lain hingga ia mendapatkan izin, jika tetap melihat (tanpa izin) maka ia telah masuk. Dan janganlah seseorang mengimami suatu kaum lalu ia mengkhususkan do`a untuk dirinya tanpa menyertakan mereka, jika ia lakukan maka ia telah berkhianat. Dan seseorang juga tidak boleh melaksanakan shalat dalam keadaan menahan kencing.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Hurairah dan Abu Umamah.\" Abu Isa berkata; \"Hadits Tsaubah derajatnya hasan. Hadits ini telah diriwayatkan pula dari [Mu'awiyah bin Shalih] dari [As Safar bin Nusair] dari [Yazid bin Syuraih] dari [Abu Umamah] dari Nabi shallallahu 'alaihi wasallam.\" Hadits ini juga diriwayatkan dari [Yazid bin Syuraih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam. Seakan-akan hadits Yazid bin Syuraih, dari Abu Hayy Al Mu'adzin, dari Tsauban dalam persoalan ini lebih bagus sanad dan masyhur.\""},"326":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ وَاصِلِ بْنِ عَبْدِ الْأَعْلَى الْكُوفِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ الْقَاسِمِ الْأَسَدِيُّ عَنْ الْفَضْلِ بْنِ دَلْهَمٍ عَنْ الْحَسَنِ قَال سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةً رَجُلٌ أَمَّ قَوْمًا وَهُمْ لَهُ كَارِهُونَ وَامْرَأَةٌ بَاتَتْ وَزَوْجُهَا عَلَيْهَا سَاخِطٌ وَرَجُلٌ سَمِعَ حَيَّ عَلَى الْفَلَاحِ ثُمَّ لَمْ يُجِبْقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَطَلْحَةَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَأَبِي أُمَامَةَ قَالَ أَبُو عِيسَى حَدِيثُ أَنَسٍ لَا يَصِحُّ لِأَنَّهُ قَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ الْحَسَنِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلٌ قَالَ أَبُو عِيسَى وَمُحَمَّدُ بْنُ الْقَاسِمِ تَكَلَّمَ فِيهِ أَحْمَدُ بْنُ حَنْبَلٍ وَضَعَّفَهُ وَلَيْسَ بِالْحَافِظِ وَقَدْ كَرِهَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ أَنْ يَؤُمَّ الرَّجُلُ قَوْمًا وَهُمْ لَهُ كَارِهُونَ فَإِذَا كَانَ الْإِمَامُ غَيْرَ ظَالِمٍ فَإِنَّمَا الْإِثْمُ عَلَى مَنْ كَرِهَهُ و قَالَ أَحْمَدُ وَإِسْحَقُ فِي هَذَا إِذَا كَرِهَ وَاحِدٌ أَوْ اثْنَانِ أَوْ ثَلَاثَةٌ فَلَا بَأْسَ أَنْ يُصَلِّيَ بِهِمْ حَتَّى يَكْرَهَهُ أَكْثَرُ الْقَوْمِ","id":"Telah menceritakan kepada kami [Abdul A'la bin Washil bin Abdul A'la Al Kufi] berkata; telah menceritakan kepada kami [Muhammad bin Al Qasim Al Asadi] dari [Al Fadll bin Dalham] dari [Al Hasan] ia berkata; \"Aku mendengar [Anas bin Malik] berkata; \"Rasulullah shallallahu 'alaihi wasallam melaknat tiga orang; seseorang yang mengimami suatu kaum sementara mereka tidak suka, seorang istri yang bermalam sementara suaminya murka kepadanya dan seseorang yang mendengar seruan adzan Hayya 'alal falah (mari menuju kemenangan) namun tidak memenuhinya.\" Imam Tirmidzi berkata; \"Dalam bab ini ada juga hadits dari Ibnu Abbas, Thalhah, Abdullah bin 'Amru dan Abu Umamah.\" Abu Isa berkata; \"Hadits Anas tidak shahih, karena hadits diriwayatkan dari Al Hasan dari Nabi shallallahu 'alaihi wasallam secara Mursal.\" Abu Isa berkata; \"Muhammad bin Al Qasim telah diperbincangkan dan dilemahkan oleh Imam Ahmad bin Hambal, dan ia bukanlah seorang yang hafidz (hafalannya kuat). Sebagian ahli ilmu memakruhkan seseorang mengimami suatu kaum sementara mereka tidak suka, namun jika imam tersebut bukan seorang yang zhalim maka dosanya kembali kepada orang yang tidak suka kepadanya. Sementara dalam hal ini Imam Ahmad dan Ishaq berpendapat, bahwa apabila orang yang tidak suka itu hanya satu, dua atau tiga saja, maka tidak apa-apa mengimami mereka kecuali yang tidak suka adalah orang banyak.\""},"327":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ زِيَادِ بْنِ أَبِي الْجَعْدِ عَنْ عَمْرِو بْنِ الْحَارِثِ بْنِ الْمُصْطَلِقِ قَالَكَانَ يُقَالُ أَشَدُّ النَّاسِ عَذَابًا يَوْمَ الْقِيَامَةِ اثْنَانِ امْرَأَةٌ عَصَتْ زَوْجَهَا وَإِمَامُ قَوْمٍ وَهُمْ لَهُ كَ��رِهُونَقَالَ هَنَّادٌ قَالَ جَرِيرٌ قَالَ مَنْصُورٌ فَسَأَلْنَا عَنْ أَمْرِ الْإِمَامِ فَقِيلَ لَنَا إِنَّمَا عَنَى بِهَذَا أَئِمَّةً ظَلَمَةً فَأَمَّا مَنْ أَقَامَ السُّنَّةَ فَإِنَّمَا الْإِثْمُ عَلَى مَنْ كَرِهَهُ","id":"Telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Hilal bin Yasaf] dari [Ziyad bin Abu Al Ja'd] dari ['Amru bin Al Harits bin Al Mushthaliq] ia berkata; \"Disebutkan bahwa manusia yang paling berat siksanya pada hari kiamat adalah dua orang; wanita yang durhaka kepada suaminya dan imam suatu kaum sedang mereka membencinya.\" Ia berkata; \"Hannad berkata; \"Jarir berkata; \"Manshur berkata; \"Lalu kami bertanya tentang imam, lalu dikatakan kepada kami, \"Hanyasanaya yang dimaksud dalam hal ini adalah imam yang zhalim, adapun para imam yang menegakkan sunah maka dosanya adalah bagi orang membencinya.\""},"328":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ حَدَّثَنَا الْحُسَيْنُ بْنُ وَاقِدٍ حَدَّثَنَا أَبُو غَالِبٍ قَال سَمِعْتُ أَبَا أُمَامَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ لَا تُجَاوِزُ صَلَاتُهُمْ آذَانَهُمْ الْعَبْدُ الْآبِقُ حَتَّى يَرْجِعَ وَامْرَأَةٌ بَاتَتْ وَزَوْجُهَا عَلَيْهَا سَاخِطٌ وَإِمَامُ قَوْمٍ وَهُمْ لَهُ كَارِهُونَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَأَبُو غَالِبٍ اسْمُهُ حَزَوَّرٌ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] berkata; telah menceritakan kepada kami [Ali bin Al Hasan] berkata; telah menceritakan kepada kami [Al Husain bin Al Waqid] berkata; telah menceritakan kepada kami [Abu Ghalib] ia berkata; \"Aku mendengar [Abu Umamah] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga orang yang shalatnya tidak akan melampaui telinga mereka; seorang budak yang kabur hingga ia kembali, seorang istri yang bermalam sementara suaminya dalam keadaan marah dan seorang imam bagi suatu kaum sedangkan mereka tidak suka.\" Abu Isa berkata; \"Dari jalur ini, hadits ini derajatnya hasan gharib. Sedangkan Abu Ghalib namanya Hazawwar.\""},"329":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ قَالَخَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ فَرَسٍ فَجُحِشَ فَصَلَّى بِنَا قَاعِدًا فَصَلَّيْنَا مَعَهُ قُعُودًا ثُمَّ انْصَرَفَ فَقَالَ إِنَّمَا الْإِمَامُ أَوْ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا رَفَعَ فَارْفَعُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا وَلَكَ الْحَمْدُ وَإِذَا سَجَدَ فَاسْجُدُوا وَإِذَا صَلَّى قَاعِدًا فَصَلُّوا قُعُودًا أَجْمَعُونَقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَأَبِي هُرَيْرَةَ وَجَابِرٍ وَابْنِ عُمَرَ وَمُعَاوِيَةَ قَالَ أَبُو عِيسَى وَحَدِيثُ أَنَسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَّ عَنْ فَرَسٍ فَجُحِشَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ ذَهَبَ بَعْضُ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى هَذَا الْحَدِيثِ مِنْهُمْ جَابِرُ بْنُ عَبْدِ اللَّهِ وَأُسَيْدُ بْنُ حُضَيْرٍ وَأَبُو هُرَيْرَةَ وَغَيْرُهُمْ وَبِهَذَا الْحَدِيثِ يَقُولُ أَحْمَدُ وَإِسْحَقُ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ إِذَا صَلَّى الْإِمَامُ جَالِسًا لَمْ يُصَلِّ مَنْ خَلْفَهُ إِلَّا قِيَامًا فَإِنْ صَلَّوْا قُعُودًا لَمْ تُجْزِهِمْ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَمَالِكِ بْنِ أَنَسٍ وَابْنِ الْمُبَارَكِ وَالشَّافِعِيِّ","id":"Telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Anas bin Malik] bahwa ia berkata; \"Rasulullah shallallahu 'alaihi wasallam jatuh dari kudanya hingga terluka. Lalu beliau shalat bersama dengan duduk. Setekah itu beliau bangkit dan bersabda: \"Hanyasanya imam itu, atau beliau mengatakan, \"Hanyasanya dijadikannya imam itu agar diikuti, jika ia takbir maka bertakbirlah, jika ia rukuk maka rukuklah, jika ia mengangkat kepalanya maka angkatlah kepala kalian, jika ia mengucapkan: SAMI'AALLAHU LIMAN HAMIDAHU (semoga Allah mendengar pujian orang yang memuji-Nya) maka ucapkanlah: RABBANA WA LAKAL HAMDU (Wahai Rabb kami, bagi-Mu segala pujian), jika ia sujud maka sujudlah, dan jika ia shalat dengan duduk maka shalatlah kalian dengan duduk semuanya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari 'Aisyah, Abu Hurairah, Jabir, Ibnu Umar dan Mu'awiyah.\" Abu Isa berkata; \"Hadits Anas yang menyebutkan bahwa Rasulullah shallallahu 'alaihi wasallam jatuh dan terluka derajatnya adalah hasan shahih. Sebagian ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam berpegangan dengan hadits ini. Di antaranya adalah; Jabir bin Abdullah, Usaid bin Hudlair, Abu Hurairah dan selainnya. Ahmad dan Ishaq juga berpegangan dengan hadits ini. Dan sebagian ahli ilmu berkata; \"Jika imam shalat dengan duduk maka orang-orang yang ada dibelakangnya tidak shalat kecuali dengan berdiri, jika mereka shalat dengan duduk maka shalatnya tidak sah.\" Ini adalah pendapat yang diambil oleh Sufyan Ats Tsauri, Malik bin Anas, bin Al Mubarak dan Syafi'i."},"330":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا شَبَابَةُ بْنُ سَوَّارٍ عَنْ شُعْبَةَ عَنْ نُعَيْمِ بْنِ أَبِي هِنْدٍ عَنْ أَبِي وَائِلٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلْفَ أَبِي بَكْرٍ فِي مَرَضِهِ الَّذِي مَاتَ فِيهِ قَاعِدًاقَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَقَدْ رُوِيَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا صَلَّى الْإِمَامُ جَالِسًا فَصَلُّوا جُلُوسًا وَرُوِيَ عَنْهَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ فِي مَرَضِهِ وَأَبُو بَكْرٍ يُصَلِّي بِالنَّاسِ فَصَلَّى إِلَى جَنْبِ أَبِي بَكْرٍ وَالنَّاسُ يَأْتَمُّونَ بِأَبِي بَكْرٍ وَأَبُو بَكْرٍ يَأْتَمُّ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرُوِيَ عَنْهَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى خَلْفَ أَبِي بَكْرٍ قَاعِدًا وَرُوِي عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى خَلْفَ أَبِي بَكْرٍ وَهُوَ قَاعِدٌ","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Syababah bin Sawwar] dari [Syu'bah] dari [Nu'aim bin Abu Hind] dari [Abu Wa`il] dari [Masruq] dari ['Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat di belakang Abu Bakar diwaktu sakit yang membawanya pada kematian.\" Abu Isa berkata; \"Hadits 'Aisyah ini derajatnya hasan shahih gharib. Diriwayatkan dari 'Aisyah bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika imam shalat dengan duduk maka shalatlah kalian dengan duduk.\" Dan masih riwayatnya, bahwa Nabi shallallahu 'alaihi wasallam keluar di waktu sakit, sedang Abu Bakar melaksanakan shalat bersama orang-orang. Lalu beliau shalat di sisi Abu bakar, orang-orang bermakmum kepada Abu Bakar, sedangkan Abu Bakar sendiri bermakmum kepada Nabi shallallahu 'alaihi wasallam. Dan dalam riwayat 'Aisyah yang lain disebutkan, bahwa Nabi shallallahu 'alaihi wasallam shalat di belakang Abu Bakar dengan duduk. Dan diriwayatkan oleh Anas bahwa Nabi shallallahu 'alaihi wasallam shalat dengan duduk di belakang Abu Bakar."},"331":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي زِيَادٍ حَدَّثَنَا شَبَابَةُ بْنُ سَوَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ طَلْحَةَ عَنْ حُمَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرَضِهِ خَلْفَ أَبِي بَكْرٍ قَاعِدًا فِي ثَوْبٍ مُتَوَشِّحًا بِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ وَهَكَذَا رَوَاهُ يَحْيَى بْنُ أَيُّوبَ عَنْ حُمَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ وَقَدْ رَوَاهُ غَيْرُ وَاحِدٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ وَلَمْ يَذْكُرُوا فِيهِ عَنْ ثَابِتٍ وَمَنْ ذَكَرَ فِيهِ عَنْ ثَابِتٍ فَهُوَ أَصَحُّ","id":"telah menceritakan kepada kami [Abdullah bin Abu Ziyad] berkata; telah menceritakan kepada kami [Syababah bin Sawwar] berkata; telah menceritakan kepada kami [Muhammad bin Thalhah] dari [Humaid] dari [Tsabit] dari [Anas] ia berkata; \"Ketika sakit Rasulullah shallallahu 'alaihi wasallam shalat dengan duduk di belakang Abu Bakar sambil berselimutkan kain.\" Abu Isa berkata; \"Hadits ini hasan shahih.\" Ia berkata; \"Seperti inilah [Yahya bin Ayyub] meriwayatkannya dari [Humaid] dari [Tsabit] dari [Anas]. Dan tidak hanya seorang yang meriwayatkan dari Humaid dari Anas. Namun mereka tidak menyebutkan di dalamnya; dari Tsabit. Maka hadits yang di dalamnya disebutkan; dari Tsabit adalah lebih shahih.\""},"332":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا ابْنُ أَبِي لَيْلَى عَنْ الشَّعْبِيِّ قَالَصَلَّى بِنَا الْمُغِيرَةُ بْنُ شُعْبَةَ فَنَهَضَ فِي الرَّكْعَتَيْنِ فَسَبَّحَ بِهِ الْقَوْمُ وَسَبَّحَ بِهِمْ فَلَمَّا صَلَّى بَقِيَّةَ صَلَاتِهِ سَلَّمَ ثُمَّ سَجَدَ سَجْدَتَيْ السَّهْوِ وَهُوَ جَالِسٌ ثُمَّ حَدَّثَهُمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَ بِهِمْ مِثْلَ الَّذِي فَعَلَقَالَ وَفِي الْبَاب عَنْ عُقْبَةَ بْنِ عَامِرٍ وَسَعْدٍ وَعَبْدِ اللَّهِ بْنِ بُحَيْنَةَ قَالَ أَبُو عِيسَى حَدِيثُ الْمُغِيرَةِ بْنِ شُعْبَةَ قَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَ أَبُو عِيسَى وَقَدْ تَكَلَّمَ بَعْضُ أَهْلِ الْعِلْمِ فِي ابْنِ أَبِي لَيْلَى مِنْ قِبَلِ حِفْظِهِ قَالَ أَحْمَدُ لَا يُحْتَجُّ بِحَدِيثِ ابْنِ أَبِي لَيْلَى و قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ ابْنُ أَبِي لَيْلَى هُوَ صَدُوقٌ وَلَا أَرْوِي عَنْهُ لِأَنَّهُ لَا يَدْرِي صَحِيحَ حَدِيثِهِ مِنْ سَقِيمِهِ وَكُلُّ مَنْ كَانَ مِثْلَ هَذَا فَلَا أَرْوِي عَنْهُ شَيْئًا وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ رَوَاهُ سُفْيَانُ عَنْ جَابِرٍ عَنْ الْمُغِيرَةِ بْنِ شُبَيْلٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ وَجَابِرٌ الْجُعْفِيُّ قَدْ ضَعَّفَهُ بَعْضُ أَهْلِ الْعِلْمِ تَرَكَهُ يَحْيَى بْنُ سَعِيدٍ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَغَيْرُهُمَا وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ أَنَّ الرَّجُلَ إِذَا قَامَ فِي الرَّكْعَتَيْنِ مَضَى فِي صَلَاتِهِ وَسَجَدَ سَجْدَتَيْنِ مِنْهُمْ مَنْ رَأَى قَبْلَ التَّسْلِيمِ وَمِنْهُمْ مَنْ رَأَى بَعْدَ التَّسْلِيمِ وَمَنْ رَأَى قَبْلَ التَّسْلِيمِ فَحَدِيثُهُ أَصَحُّ لِمَا رَوَى الزُّهْرِيُّ وَيَحْيَى بْنُ سَعِيدٍ الْأَنْصَارِيُّ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ عَبْدِ اللَّهِ ابْنِ بُحَيْنَةَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Husyaim] berkata; telah mengabarkan kepada kami [Ibnu Abu Laila] dari [Asy Sya'bi] ia berkata; \" [Syu'bah bin Al Mughirah] shalat bersama kami, lalu pada rakaat kedua ia berdiri hingga orang-orang mengucapkan SUBHAANAALLAH, dan ia juga mengucapkannya untuk mereka. Setelah shalat ia sujud sahwi dengan dua kali sujud dalam keadaan duduk. Setelah itu ia menceritakan kepada orang-orang bahwa Rasulullah shallallahu 'alaihi wasallam juga melakukan sebagaimana yang ia lakukan.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Uqbah bin Amir, Sa'd dan Abdullah bin Buhainah.\" Abu Isa berkata; \"Hadits Al Mughirah bin Syu'bah ini telah diriwayatkan dari Al Mughirah dengan banyak jalur.\" Abu Isa berkata; \"Sebagian ahli ilmu telah memperbincangkan Ibnu Abu Laila dari sisi hafalannya. Ahmad berkata; \"Hadits Ibnu Abu Laila tidak bisa dijadikan sebagai hujah.\" Dan Muhammad bin Isma'il berkata; \"Ibnu Abu Laila seorang yang jujur, hanya saja aku tidak meriwayatkan darinya karena ia tidak bisa membedakan hadits shahih yang ia miliki. Maka terhadap siapa saja yang seperti ini aku tidak mau mengambil hadits darinya.\" Hadits ini juga diriwayatkan dari Al Mughirah bin Syu'bah dengan banyak jalur. [Sufyan] meriwayatkannya dari [Jabir] dari [Al Mughirah bin Syubail] dari [Qais bin Abu Hazim] dari [Al Mughirah bin Syu'bah]. Jabir Al Ju'fi juga dilemahkan oleh sebagian ahli ilmu. Yahya bin Sa'id, Abdurrahman bin Mahdi dan selain keduanya meninggalkannya (tidak mengambil hadits darinya).\" Hadits ini diamalkan ahli ilmu, bahwa seorang laki-laki jika berdiri pada rakaat kedua hendaknya ia tetap meneruskan shalatnya, setelah itu ia sujud dengan dua kali sujud (sahwi). Di antara mereka ada yang berpendapat bahwa sujud itu dilakukan sebelum salam, dan sebagian yang lain berpendapat bahwa sujud itu dilakukan setelah salam. Dan pendapat yang mengatakan bahwa sujud itu dilakukan sebelum salam haditsnya adalah lebih shahih, sebab hadits tersebut diriwayatkan dari Az Zuhri dan Yahya bin Sa'id Al Anshari, dari Abdurrahman Al A'raj, dari Abdullah bin Buhainah.\""},"333":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ الْمَسْعُودِيِّ عَنْ زِيَادِ بْنِ عِلَاقَةَ قَالَصَلَّى بِنَا الْمُغِيرَةُ بْنُ شُعْبَةَ فَلَمَّا صَلَّى رَكْعَتَيْنِ قَامَ وَلَمْ يَجْلِسْ فَسَبَّحَ بِهِ مَنْ خَلْفَهُ فَأَشَارَ إِلَيْهِمْ أَنْ قُومُوا فَلَمَّا فَرَغَ مِنْ صَلَاتِهِ سَلَّمَ وَسَجَدَ سَجْدَتَيْ السَّهْوِ وَسَلَّمَ وَقَالَ هَكَذَا صَنَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"telah menceritakan kepada kami [Abdullah bin Abdurrahman] berkata; telah mengabarkan kepada kami [Yazid bin Harun] dari [Al Mas'udi] dari [Ziyad bin Ilaqah] ia berkata; \" [Al Mughirah bin Syu'bah] shalat bersama kami, setelah shalat dua rakaat ia langsung bangun dan tidak duduk. Maka orang-orang pun mengucapkan tasbih (untuk mengingatkannya), namun ia memberikan isyarat kepada mereka agar berdiri. Ketika selesai shalat, ia mengucapkan salam dan sujud sahwi dengan dua kali sujud, setelah itu ia salam. Kemudian ia berkata; \"Demikianlah Rasulullah shallallahu 'alaihi wasallam melakukannya.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Dan hadits ini juga diriwayatkan dengan banyak jalur dari Al Mughirah bin Syu'bah, dari Nabi shallallahu 'alaihi wasallam.\""},"334":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ هُوَ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ أَخْبَرَنَا سَعْدُ بْنُ إِبْرَاهِيمَ قَال سَمِعْتُ أَبَا عُبَيْدَةَ بْنَ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ يُحَدِّثُ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَلَسَ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ كَأَنَّهُ عَلَى الرَّضْفِ قَالَ شُعْبَةُ ثُمَّ حَرَّكَ سَعْدٌ شَفَتَيْهِ بِشَيْءٍ فَأَقُولُ حَتَّى يَقُومَ فَيَقُولُ حَتَّى يَقُومَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ إِلَّا أَنَّ أَبَا عُبَيْدَةَ لَمْ يَسْمَعْ مِنْ أَبِيهِ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ يَخْتَارُونَ أَنْ لَا يُطِيلَ الرَّجُلُ الْقُعُودَ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ وَلَا يَزِيدَ عَلَى التَّشَهُّدِ شَيْئًا وَقَالُوا إِنْ زَادَ عَلَى التَّشَهُّدِ فَعَلَيْهِ سَجْدَتَا السَّهْوِ هَكَذَا رُوِيَ عَنْ الشَّعْبِيِّ وَغَيْرِهِ","id":"telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Abu Dawud] -yaitu Ath Thayalisi- berkata; telah menceritakan kepada kami [Syu'bah] berkata; telah mengabarkan kepada kami [Sa'd bin Ibrahim] ia berkata; \"Aku mendengar [Abu Ubaidah bin Abdullah bin Mas'ud] menceritakan dari [ayahnya], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam jika duduk pada rakaat kedua yang bagian pertama, seakan-akan beliau duduk di atas batu yang panas.\" Syu'bah berkata; \"Kemudian Sa'd mengerak-gerakkan bibirnya (membicarakan) sesuatu, aku pun bertanya, \"Hingga bangun?\" ia menjawab, \"Hingga bangun.\" Abu Isa berkata; \"Hadits ini derajatnya hasan. Hanya saja Abu Ubaidah belum pernah mendengar dari ayahnya.\" Para ahli ilmu mengamalkan hadits ini, mereka memilih bahwa seorang laki-laki hendaknya tidak berlama-lama duduk pada rakaat kedua yang pertama, dan tidak melebihi lamanya tasyahud. Mereka mengatakan lagi, \"Jika lebih lama dari tasyahud maka ia harus sujud sahwi dengan dua kali sujud.\" Demikianlah diriwayatkan dari Asy Sya'bi dan selainnya."},"335":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ نَابِلٍ صَاحِبِ الْعَبَاءِ عَنْ ابْنِ عُمَرَ عَنْ صُهَيْبٍ قَالَمَرَرْتُ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي فَسَلَّمْتُ عَلَيْهِ فَرَدَّ إِلَيَّ إِشَارَةً وَقَالَ لَا أَعْلَمُ إِلَّا أَنَّهُ قَالَ إِشَارَةً بِإِصْبَعِهِقَالَ وَفِي الْبَاب عَنْ بِلَالٍ وَأَبِي هُرَيْرَةَ وَأَنَسٍ وَعَائِشَةَ","id":"Telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Bukair bin Abdullah bin Al Asyaj] dari [Nabil] -pemilik mantel- dari [Ibnu Umar] dari [Shuhaib] ia berkata; \"Aku melewati Rasulullah shallallahu 'alaihi wasallam sedang melaksanakan shalat, lalu aku mengucapkan salam kepada beliau dan beliau membalasnya dengan isyarat.\" Ibnu Umar berkata; \"Aku tidak mengetahui kecuali bahwa Shuhaib mengatakan, \"Memberi isyarat dengan jarinya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Bilal, Abu Hurairah, Anas dan 'Aisyah.\""},"336":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قُلْتُ لِبِلَالٍكَيْفَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرُدُّ عَلَيْهِمْ حِينَ كَانُوا يُسَلِّمُونَ عَلَيْهِ وَهُوَ فِي الصَّلَاةِ قَالَ كَانَ يُشِيرُ بِيَدِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَحَدِيثُ صُهَيْبٍ حَسَنٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ اللَّيْثِ عَنْ بُكَيْرٍ وَقَدْ رُوِيَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ ابْنِ عُمَرَ قَالَ قُلْتُ لِبِلَالٍ كَيْفَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ حَيْثُ كَانُوا يُسَلِّمُونَ عَلَيْهِ فِي مَسْجِدِ بَنِي عَمْرِو بْنِ عَوْفٍ قَالَ كَانَ يَرُدُّ إِشَارَةً وَكِلَا الْحَدِيث��يْنِ عِنْدِي صَحِيحٌ لِأَنَّ قِصَّةَ حَدِيثِ صُهَيْبٍ غَيْرُ قِصَّةِ حَدِيثِ بِلَالٍ وَإِنْ كَانَ ابْنُ عُمَرَ رَوَى عَنْهُمَا فَاحْتَمَلَ أَنْ يَكُونَ سَمِعَ مِنْهُمَا جَمِيعًا","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Hisyam bin Sa'd] dari [Nafi'] dari [Ibnu Umar] ia berkata; \"Aku bertanya [Bilal], \"Bagaimana Nabi shallallahu 'alaihi wasallam menjawab salam ketika mereka mengucapkan salam kepada beliau, sementara beliau sedang melaksanakan shalat?\" Bilal menjawab, \"Beliau memberikan isyarat dengan tangannya.\" Abu Isa berkata; \"Hadits ini hasan shahih, sedangkan hadits shuhaib derajatnya hasan, dan kami tidak mengetahuinya kecuali dari hadits Laits dari Bukair. Telah diriwayatkan dari [Zaid bin Aslam] dari [Ibnu Umar] ia berkata; \"Aku bertanya Bilal, \"Bagaimana yang dilakukan oleh Nabi shallallahu 'alaihi wasallam ketika mereka mengucapkan salam kepada beliau di masjid Bani 'Amru bin Auf?\" [Bilal] menjawab, \"Beliau menjawab dengan berisyarat.\" Ia berkata; \"Kedua hadits ini menurutku adalah shahih, karena cerita dalam hadits shuhaib bukan cerita yang ada dalam hadits Bilal, dan jika Ibnu Umar telah meriwayatkan dari keduanya maka ada kemungkinan bahwa dia telah mendengar dari kedua duanya.\""},"337":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّسْبِيحُ لِلرِّجَالِ وَالتَّصْفِيقُ لِلنِّسَاءِقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَسَهْلِ بْنِ سَعْدٍ وَجَابِرٍ وَأَبِي سَعِيدٍ وَابْنِ عُمَرَ و قَالَ عَلِيٌّ كُنْتُ إِذَا اسْتَأْذَنْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي سَبَّحَ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَهْلِ الْعِلْمِ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ","id":"telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mengucapkan tasbih untuk laki-laki dan bertepuk dengan tangan untuk wanita.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ali, Sahl bin Sa'd, Jabir, Abu Sa'id dan Ibnu Umar.\" Ali berkata; \"Jika aku meminta izin kepada Nabi shallallahu 'alaihi wasallam ketika beliau sedang shalat maka beliau bertasbih.\" Abu Isa berkata; \"Hadits Abu Hurairah ini derajatnya hasan shahih. Hadits ini diamalkan oleh para ahli ilmu. Dan pendapat inilah yang diambil oleh Ahmad dan Ishaq.\""},"338":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ التَّثَاؤُبُ فِي الصَّلَاةِ مِنْ الشَّيْطَانِ فَإِذَا تَثَاءَبَ أَحَدُكُمْ فَلْيَكْظِمْ مَا اسْتَطَاعَقَالَ وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ وَجَدِّ عَدِيِّ بْنِ ثَابِتٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ كَرِهَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ التَّثَاؤُبَ فِي الصَّلَاةِ قَالَ إِبْرَاهِيمُ إِنِّي لَأَرُدُّ التَّثَاؤُبَ بِالتَّنَحْنُحِ","id":"Telah menceritakan kepada kami [Ali bin Hujr] berkata; telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Al 'Ala` bin Abdurrahman] dari [Ayahnya] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Menguap dalam shalat adalah dari setan, jika salah seorang dari kalian menguap maka handaklah ia menahan semampunya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Sa'id Al Khudri dan kakeknya Adi bin Tsabit.\" Abu Isa berkata; \"Hadits Abu Hurairah ini derajatnya hasan shahih. sebagian ahli ilmu memkaruhkan menguap dalam shalat. Ibrahim berkata; \"Sungguh, aku menahan rasa ingin menguap dengan berdehem.\""},"339":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ الرَّجُلِ وَهُوَ قَاعِدٌ فَقَالَ مَنْ صَلَّى قَائِمًا فَهُوَ أَفْضَلُ وَمَنْ صَلَّى قَاعِدًا فَلَهُ نِصْفُ أَجْرِ الْقَائِمِ وَمَنْ صَلَّى نَائِمًا فَلَهُ نِصْفُ أَجْرِ الْقَاعِدِقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَأَنَسٍ وَالسَّائِبِ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى حَدِيثُ عِمْرَانَ بْنِ حُصَيْنٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ إِبْرَاهِيمَ بْنِ طَهْمَانَ بِهَذَا الْإِسْنَادِ إِلَّا أَنَّهُ يَقُولُ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ الْمَرِيضِ فَقَالَ صَلِّ قَائِمًا فَإِنْ لَمْ تَسْتَطِعْ فَقَاعِدًا فَإِنْ لَمْ تَسْتَطِعْ فَعَلَى جَنْبٍ حَدَّثَنَا بِذَلِكَ هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ إِبْرَاهِيمَ بْنِ طَهْمَانَ عَنْ حُسَيْنٍ الْمُعَلِّمِ بِهَذَا الْحَدِيثِ قَالَ أَبُو عِيسَى وَلَا نَعْلَمُ أَحَدًا رَوَى عَنْ حُسَيْنٍ الْمُعَلِّمِ نَحْوَ رِوَايَةِ إِبْرَاهِيمَ بْنِ طَهْمَانَ وَقَدْ رَوَى أَبُو أُسَامَةَ وَغَيْرُ وَاحِدٍ عَنْ حُسَيْنٍ الْمُعَلِّمِ نَحْوَ رِوَايَةِ عِيسَى بْنِ يُونُسَ وَمَعْنَى هَذَا الْحَدِيثِ عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ فِي صَلَاةِ التَّطَوُّعِ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ أَشْعَثَ بْنِ عَبْدِ الْمَلِكِ عَنْ الْحَسَنِ قَالَ إِنْ شَاءَ الرَّجُلُ صَلَّى صَلَاةَ التَّطَوُّعِ قَائِمًا وَجَالِسًا وَمُضْطَجِعًا وَاخْتَلَفَ أَهْلُ الْعِلْمِ فِي صَلَاةِ الْمَرِيضِ إِذَا لَمْ يَسْتَطِعْ أَنْ يُصَلِّيَ جَالِسًا فَقَالَ بَعْضُ أَهْلِ الْعِلْمِ يُصَلِّي عَلَى جَنْبِهِ الْأَيْمَنِ و قَالَ بَعْضُهُمْ يُصَلِّي مُسْتَلْقِيًا عَلَى قَفَاهُ وَرِجْلَاهُ إِلَى الْقِبْلَةِ قَالَ سُفْيَانُ الثَّوْرِيُّ فِي هَذَا الْحَدِيثِ مَنْ صَلَّى جَالِسًا فَلَهُ نِصْفُ أَجْرِ الْقَائِمِ قَالَ هَذَا لِلصَّحِيحِ وَلِمَنْ لَيْسَ لَهُ عُذْرٌ يَعْنِي فِي النَّوَافِلِ فَأَمَّا مَنْ كَانَ لَهُ عُذْرٌ مِنْ مَرَضٍ أَوْ غَيْرِهِ فَصَلَّى جَالِسًا فَلَهُ مِثْلُ أَجْرِ الْقَائِمِ وَقَدْ رُوِيَ فِي بَعْضِ هَذَا الْحَدِيثِ مِثْلُ قَوْلِ سُفْيَانَ الثَّوْرِيِّ","id":"telah menceritakan kepada kami [Ali bin Hujr] berkata; telah menceritakan kepada kami [Isa bin Yunus] berkata; telah menceritakan kepada kami [Husain bin Al Muallim] dari [Abdullah bin Buraidah] dari [Imran bin Hushain] ia berkata; \"Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang shalat seorang laki-laki yang dilakukan sambil duduk, maka beliau menjawab: \"Barangsiapa shalat dengan berdiri maka lebih utama, barangsiapa shalat dengan duduk maka pahalanya adalah setengah dari shalatnya orang dengan berdiri, dan barangsiapa shalat dengan berbaring maka pahalanya adalah setengah dari shalatnya orang dengan duduk.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin Amru, Anas bin As Sa`ib dan Ibnu Umar.\" Abu Isa berkata; \"Hadits Imran bin Hushain derajatnya hasan shahih. Hadits ini juga telah diriwayatkan dari [Ibrahim bin Thahman] dengan sanad ini, hanya saja ia mengatakan; dari [Imran bin Hushain]. Ia berkata; \"Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang shalat orang yang sakit, beliau lalu menjawab: \"Shalatlah kamu dengan berdiri, jika tidak mampu maka shalatlah dengan duduk, dan jika tidak mampu maka shalatlah dengan berbaring.\" Seperti itulah [Hannad] meriwayatkan kepada kami, ia berkata; telah menceritakan kepada kami [Waki'] dari [Ibrahim bin Thahman] dari [Husain Al Mu'allim]. Abu Isa berkata; \"Kami tidak mengetahui seorang pun yang meriwayatkan dari Husain Al Amu'allim seperti riwayat Ibrahim bin Thahman. [Abu Usamah] dan banyak orang meriwayatkan dari [Husain Al Mu'allim] seperti riwayat Isa bin Yunus. Dan menurut ahli ilmu makna hadits ini berlaku dalam shalat sunnah.\" Telah menceritakan kepada kami Muhammad bin Basysyar berkata; telah menceritakan kepada kami Ibnu Abu Adi dari Asy'ats bin Abdul Malik dari Al Hasan ia berkata; \"Jika seseorang berkehendak, ia bisa shalat sunah dengan berdiri, duduk dan berbaring.\" Para ulama berbeda pendapat dengan shalatnya orang sakit dan tidak bisa shalat dengan duduk. Sebagian ahli ilmu berkata; \"Hendaknya ia shalat dengan berbaring di atas lambung kanan.\" Sedangkan sebagian ulama yang lain berkata; \"Hendaknya ia shalat terlentang dengan menghadapkan kakinya ke arah kiblat.\" Sufyan Ats Tsauri berkata tentang hadits ini, \"Barangsiapa shalat dengan duduk maka ia mendapatkan setengah pahala orang yang shalat dengan berdiri.\" Ia berkata; \"Ini berlaku bagi orang yang sehat dan orang yang tidak mempunyai udzur (yakni dalam shalat sunnah). Adapun orang yang berhalangan karena sakit atau yang lainnya lalu ia shalat dengan duduk maka ia akan mendapatkan pahala seperti orang yang berdiri. Dan sebagian hadits ini telah diriwayatkan pula seperti perkataan Sufyan Ats Tsauri.\""},"340":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ السَّائِبِ بْنِ يَزِيدَ عَنْ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ السَّهْمِيِّ عَنْ حَفْصَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سُبْحَتِهِ قَاعِدًا حَتَّى كَانَ قَبْلَ وَفَاتِهِ بِعَامٍ فَإِنَّهُ كَانَ يُصَلِّي فِي سُبْحَتِهِ قَاعِدًا وَيَقْرَأُ بِالسُّورَةِ وَيُرَتِّلُهَا حَتَّى تَكُونَ أَطْوَلَ مِنْ أَطْوَلَ مِنْهَاوَفِي الْبَاب عَنْ أُمِّ سَلَمَةَ وَأَنَسِ بْنِ مَالِكٍ قَالَ أَبُو عِيسَى حَدِيثُ حَفْصَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ نَبِيّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يُصَلِّي مِنْ اللَّيْلِ جَالِسًا فَإِذَا بَقِيَ مِنْ قِرَاءَتِهِ قَدْرُ ثَلَاثِينَ أَوْ أَرْبَعِينَ آيَةً قَامَ فَقَرَأَ ثُمَّ رَكَعَ ثُمَّ صَنَعَ فِي الرَّكْعَةِ الثَّانِيَةِ مِثْلَ ذَلِكَ وَرُوِيَ عَنْهُ أَنَّهُ كَانَ يُصَلِّي قَاعِدًا فَإِذَا قَرَأَ وَهُوَ قَائِمٌ رَكَعَ وَسَجَدَ وَهُوَ قَائِمٌ وَإِذَا قَرَأَ وَهُوَ قَاعِدٌ رَكَعَ وَسَجَدَ وَهُوَ قَاعِدٌ قَالَ أَحْمَدُ وَإِسْحَقُ وَالْعَمَلُ عَلَى كِلَا الْحَدِيثَيْنِ كَأَنَّهُمَا رَأَيَا كِلَا الْحَدِيثَيْنِ صَحِيحًا مَعْمُولًا بِهِمَا","id":"Telah menceritakan kepada kami [Al Anshar] berkata; telah menceritakan kepada kami [Ma'n] berkata; telah menceritakan kepada kami [Malik bin Anas] dari [Ibnu Syihab] dari [As Sa`ib bin Yazid] dari [Al Muthallib bin Abu Wada'ah As Sahmi] dari [Hafshah] istri Nabi shallallahu 'alaihi wasallam, ia pernah berkata; \"Aku tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam shalat sunnah dengan duduk hingga setahun menjelang kewafatannya. Beliau melaksanakan shalat sunnah sambil duduk dengan membaca surah secara tartil hingga surah itu menjadi panjang dari yang terpanjang.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ummu Salamah dan Anas bin Malik.\" Abu Isa berkata; \"Hadits Hafshah ini derajatnya hasan shahih. Telah diriwayatkan dari Nabi shallallahu 'alaihi wasallam bahwasanya beliau pernah shalat malam dengan duduk, maka ketika bacaannya tersisa kira-kira tiga puluh atau empat puluh ayat beliau berdiri dan membaca lagi, setelah itu rukuk. Beliau juga melakukan demikian di rakaat kedua.\" Diriwayatkan pula darinya bahwa Nabi shallallahu 'alaihi wasallam jika shalat dengan duduk, maka ketika membaca (surah) berliau berdiri, lalu rukuk dan sujud dengan berdiri. Ketika beliau membaca dalam keadaan duduk, maka beliau rukuk dan sujud dalam keadaan duduk. Ahmad dan Ishaq berpendapat atas dibolehkanya mengamalkan hadits ini. seakan-akan mereka berpandangan bahwa kedua hadits ini shahih dan boleh diamalkan."},"341":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ أَبِي النَّضْرِ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي جَالِسًا فَيَقْرَأُ وَهُوَ جَالِسٌ فَإِذَا بَقِيَ مِنْ قِرَاءَتِهِ قَدْرُ مَا يَكُونُ ثَلَاثِينَ أَوْ أَرْبَعِينَ آيَةً قَامَ فَقَرَأَ وَهُوَ قَائِمٌ ثُمَّ رَكَعَ وَسَجَدَ ثُمَّ صَنَعَ فِي الرَّكْعَةِ الثَّانِيَةِ مِثْلَ ذَلِكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Anshar] berkata; telah menceritakan kepada kami [Ma'n] berkata; telah menceritakan kepada kami [Malik] dari [Abu An Nadlr] dari [Abu Salamah] dari ['Aisyah] bahwa Nabi shallallahu 'alaihi wasallam pernah shalat dengan duduk. Apabila bacaan beliau tersisa kira-kira tiga puluh atau empat puluh ayat, maka beliau berdiri dan membaca (surah) dengan berdiri lalu rukuk dan sujud. Beliau juga melakukan seperti itu pada rakaat kedua.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\""},"342":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا خَالِدٌ وَهُوَ الْحَذَّاءُ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَائِشَةَ قَالَسَأَلْتُهَا عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ تَطَوُّعِهِ قَالَتْ كَانَ يُصَلِّي لَيْلًا طَوِيلًا قَائِمًا وَلَيْلًا طَوِيلًا قَاعِدًا فَإِذَا قَرَأَ وَهُوَ قَائِمٌ رَكَعَ وَسَجَدَ وَهُوَ قَائِمٌ وَإِذَا قَرَأَ وَهُوَ جَالِسٌ رَكَعَ وَسَجَدَ وَهُوَ جَالِسٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Husyaim] berkata; telah mengabarkan kepada kami [Khalid] -yaitu Al Hadzdza`- dari [Abdullah bin Syaqiq] dari ['Aisyah] ia berkata; \"Aku bertanya 'Aisyah tentang shalat sunnah Rasulullah shallallahu 'alaihi wasallam. Lalu ia menjawab, \"Beliau pernah shalat malam dalam waktu lama dengan berdiri dan pernah juga dengan duduk. Jika beliau membaca dengan berdiri maka beliau rukuk dan sujud dengan berdiri, dan jika beliau membaca dengan duduk maka beliau rukuk dan sujud dengan duduk.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\""},"343":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَاللَّهِ إِنِّي لَأَسْمَعُ بُكَاءَ الصَّبِيِّ وَأَنَا فِي الصَّلَاةِ فَأُخَفِّفُ مَخَافَةَ أَنْ تُفْتَتَنَ أُمُّهُقَالَ وَفِي الْبَاب عَنْ أَبِي قَتَادَةَ وَأَبِي سَعِيدٍ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى حَدِيثُ أَنَسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Marwan bin Mu'awiyah Al Fazari] dari [Humaid] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Allah, diwaktu shalat aku pernah mendengar tangisan bayi, maka aku mempercepat shalat tersebut khawatir ibunya menjadi terganggu.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Qatadah, Abu Sa'id dan Abu Hurairah.\" Abu Isa berkata; \"Hadits Anas ini derajatnya hasan shahih.\""},"344":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا قَبِيصَةُ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ قَتَادَةَ عَنْ ابْنِ سِيرِينَ عَنْ صَفِيَّةَ ابْنَةِ الْحَارِثِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُقْبَلُ صَلَاةُ الْحَائِضِ إِلَّا بِخِمَارٍقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَقَوْلُهُ الْحَائِضِ يَعْنِي الْمَرْأَةَ الْبَالِغَ يَعْنِي إِذَا حَاضَتْ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَهْلِ الْعِلْمِ أَنَّ الْمَرْأَةَ إِذَا أَدْرَكَتْ فَصَلَّتْ وَشَيْءٌ مِنْ شَعْرِهَا مَكْشُوفٌ لَا تَجُوزُ صَلَاتُهَا وَهُوَ قَوْلُ الشَّافِعِيِّ قَالَ لَا تَجُوزُ صَلَاةُ الْمَرْأَةِ وَشَيْءٌ مِنْ جَسَدِهَا مَكْشُوفٌ قَالَ الشَّافِعِيُّ وَقَدْ قِيلَ إِنْ كَانَ ظَهْرُ قَدَمَيْهَا مَكْشُوفًا فَصَلَاتُهَا جَائِزَةٌ","id":"Telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Qabishah] dari [Hammad bin Salamah] dari [Qatadah] dari [Ibnu Sirin] dari [Shafiyah binti Al Harits] dari ['Aisyah] ia berkata; \"Tidak sah shalat wanita yang telah haid kecuali dengan mengenakan kerudung.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin 'Amru. Sedangkan maksud dari sabda Nabi, \"Wanita yang telah haid, \"Adalah wanita yang telah berumur baligh kemudian mengalami haid.\" Abu Isa berkata; \"Hadits 'Aisyah derajatnya hasan shahih. Para ahli ilmu mengamalkan hadits ini, bahwa wanita yang telah mengalami haid kemudian melaksanakan shalat sedang rambutnya terlihat maka shalatnya tidak sah. Ini adalah pendapat yang diambil oleh Syafi'i, Ia mengatakan, \"Shalat seorang wanita tidak sah jika ada sesuatu dari bagian tubuhnya terlihat.\" Imam Syafi'i ketika ditanya; bagaimana jika pada bagian luar telapak kakinya terlihat?\" ia menjawab, \"Shalatnya sah.\""},"345":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا قَبِيصَةُ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ عِسْلِ بْنِ سُفْيَانَ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ السَّدْلِ فِي الصَّلَاةِقَالَ وَفِي الْبَاب عَنْ أَبِي جُحَيْفَةَ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ لَا نَعْرِفُهُ مِنْ حَدِيثِ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ مَرْفُوعًا إِلَّا مِنْ حَدِيثِ عِسْلِ بْنِ سُفْيَانَ وَقَدْ اخْتَلَفَ أَهْلُ الْعِلْمِ فِي السَّدْلِ فِي الصَّلَاةِ فَكَرِهَ بَعْضُهُمْ السَّدْلَ فِي الصَّلَاةِ وَقَالُوا هَكَذَا تَصْنَعُ الْيَهُودُ و قَالَ بَعْضُهُمْ إِنَّمَا كُرِهَ السَّدْلُ فِي الصَّلَاةِ إِذَا لَمْ يَكُنْ عَلَيْهِ إِلَّا ثَوْبٌ وَاحِدٌ فَأَمَّا إِذَا سَدَلَ عَلَى الْقَمِيصِ فَلَا بَأْسَ وَهُوَ قَوْلُ أَحْمَدَ وَكَرِهَ ابْنُ الْمُبَارَكِ السَّدْلَ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Hannad] berkata; telah menceritakan kepada kami [Qabishah] dari [Hammad bin Salamah] dari [Isl bin Sufyan] dari ['Atha` bin Rabah] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang dari malakukan sadl (menurunkan kain hingga menyentuh bumi) dalam shalat.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Juhaifah.\" Abu Isa berkata; \"Hadits Abu Hurairah, kami tidak mengetahuinya dari hadits 'Atha`, dari Abu Hurairah yang marfu' kecuali dari hadits Isl bin Sufyan. Para ulama berselisih pendapat tentang hukum sadl (menurunkan kain hingga menyentuh bumi) dalam shalat, sebagian mereka memakruhkannya, mereka mengatakan, \"Itu adalah perbuatan orang-orang yahudi.\" Sedangkan sebagian ulama yang lain memakruhkan hal itu jika ia tidak mempunyai kain kecuali hanya satu. Adapun jika ia melakukan sadl di atas kemeja maka tidak apa-apa.\" Ini adalah pendapat yang diambil oleh Ahmad. Sedangkan bin Al Mubarak memakruhkan sadl dalam shalat.\""},"346":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَامَ أَحَدُكُمْ إِلَى الصَّلَاةِ فَلَا يَمْسَحْ الْحَصَى فَإِنَّ الرَّحْمَةَ تُوَاجِهُهُقَالَ وَفِي الْبَاب عَنْ مُعَيْقِيبٍ وَعَلِيِّ بْنِ أَبِي طَالِبٍ وَحُذَيْفَةَ وَجَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي ذَرٍّ حَدِيثٌ حَسَنٌ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَرِهَ الْمَسْحَ فِي الصَّلَاةِ وَقَالَ إِنْ كُنْتَ لَا بُدَّ فَاعِلًا فَمَرَّةً وَاحِدَةً كَأَنَّهُ رُوِيَ عَنْهُ رُخْصَةٌ فِي الْمَرَّةِ الْوَاحِدَةِ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ","id":"Telah menceritakan kepada kami [Sa'id bin Abdurrahman Al Makhzumi] berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Abu Al Ahwash] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari kalian melaksanakan shalat maka janganlah mengusap kerikil (yang menempel dahi) sebab rahmat Allah telah menyongsongnya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Mu'aiqib, Ali bin Abu Thalib, Hudzaifah, Jabir dan Abdullah.\" Abu Isa berkata; \"Hadits Abu Dzar derajatnya hasan. Telah diriwayatkan dari Nabi shallallahu 'alaihi wasallam bahwasanya beliau memakruhkan mengusap (kerikil) dalam shalat. Beliau mengatakan, \"Jika memang engkau harus melaksanakannya maka lakukanlah dengan satu kali usapan.\" Telah diriwayatkan darinya, Bahwasanya beliau memberikan keringanan untuk satu kali usap. Hal ini diamalkan oleh para ulama."},"347":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ مُعَيْقِيبٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ مَسْحِ الْحَصَى فِي الصَّلَاةِ فَقَالَ إِنْ كُنْتَ لَا بُدَّ فَاعِلًا فَمَرَّةً وَاحِدَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Husain] berkata; telah menceritakan kepada kami [Al Walid bin Muslim] dari [Al Auza'i] dari [Yahya bin Abu Katsir] berkata; telah menceritakan kepadaku [Abu Salamah bin Abdurrahman] dari [Mu'aiqib] ia berkata; \"Aku bertanya Rasulullah shallallahu 'alaihi wasallam tentang mengusap kerikil saat shalat, maka beliau menjawab: \"Jika engkau harus melakukannya maka hendaklah dengan satu kali usapan saja.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\""},"348":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ أَخْبَرَنَا مَيْمُونٌ أَبُو حَمْزَةَ عَنْ أَبِي صَالِحٍ مَوْلَى طَلْحَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْرَأَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُلَامًا لَنَا يُقَالُ لَهُ أَفْلَحُ إِذَا سَجَدَ نَفَخَ فَقَالَ يَا أَفْلَحُ تَرِّبْ وَجْهَكَقَالَ أَحْمَدُ بْنُ مَنِيعٍ وَكَرِهَ عَبَّادُ بْنُ الْعَوَّامِ النَّفْخَ فِي الصَّلَاةِ وَقَالَ إِنْ نَفَخَ لَمْ يَقْطَعْ صَلَاتَهُ قَالَ أَحْمَدُ بْنُ مَنِيعٍ وَبِهِ نَأْخُذُ قَالَ أَبُو عِيسَى وَرَوَى بَعْضُهُمْ عَنْ أَبِي حَمْزَةَ هَذَا الْحَدِيثَ وَقَالَ مَوْلًى لَنَا يُقَالُ لَهُ رَبَاحٌ حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ مَيْمُونٍ أَبِي حَمْزَةَ بِهَذَا الْإِسْنَادِ نَحْوَهُ وَقَالَ غُلَامٌ لَنَا يُقَالُ لَهُ رَبَاحٌ قَالَ أَبُو عِيسَى وَحَدِيثُ أُمِّ سَلَمَةَ إِسْنَادُهُ لَيْسَ بِذَاكَ وَمَيْمُونٌ أَبُو حَمْزَةَ قَدْ ضَعَّفَهُ بَعْضُ أَهْلِ الْعِلْمِ وَاخْتَلَفَ أَهْلُ الْعِلْمِ فِي النَّفْخِ فِي الصَّلَاةِ فَقَالَ بَعْضُهُمْ إِنْ نَفَخَ فِي الصَّلَاةِ اسْتَقْبَلَ الصَّلَاةَ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَأَهْلِ الْكُوفَةِ و قَالَ بَعْضُهُمْ يُكْرَهُ النَّفْخُ فِي الصَّلَاةِ وَإِنْ نَفَخَ فِي صَلَاتِهِ لَمْ تَفْسُدْ صَلَاتُهُ وَهُوَ قَوْلُ أَحْمَدَ وَإِسْحَقَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Abbad bin Al Awwam] berkata; telah mengabarkan kepada kami [Maimun Abu Hamzah] dari [Abu Shalih] pelayan Thalhah, dari [Ummu Salamah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melihat budak kami yang bernama Aflah, jika sujud ia meniup (tempat sujud). Maka beliau pun bersabda: \"Wahai Aflah, biarkanlah wajahmu berdebu!\" Ahmad bin Mani' berkata; \"Abbad bin Al Awwam memakruhkan seseorang meniup dalam shalat.\" Ia berkata; \"Jika ia tetap menium maka shalatnya tidak batal.\" Ahmad bin Mani' berkata; \"Pendapat inilah yang kami ambil.\" Abu Isa berkata; \"Sebagian mereka meriwayatkan hadits ini dari Abu Hamzah. Pelayan kami yang bernama Aflah berkata; \"Telah menceritakan kepada kami [Ahmad bin Abdah Adl Dlabbi] berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Maimun Abu Hamzah] sebagaimana hadits tersebut dengan sanad ini. Ia berkata; \"Budak kami dipanggil dengan nama Aflah.\" Abu Isa berkata; \"Hadits Ummu Salamah sanadnya tidak kuat, Maimun dan Abu Hamzah telah dilemahkan oleh sebagian ahli ilmu.\" Sebagian ahli ilmu berselisih dengan tentang hukum meniup ketika shalat, sebagian mereka berkata; \"Jika meniup dalam shalat maka ia harus memulai dari awal lagi.\" Ini adalah pendapat Sufyan Ats Tsauri dan penduduk Kufah. Sedangkan yang lain memakruhkan meniup dalam shalat, jika ia meniup maka shalatnya tidak rusak. Dan ini pendapat Ahmad dan Ishaq."},"349":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّب��يَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُصَلِّيَ الرَّجُلُ مُخْتَصِرًاقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ كَرِهَ بَعْضُ أَهْلِ الْعِلْمِ الِاخْتِصَارَ فِي الصَّلَاةِ وَكَرِهَ بَعْضُهُمْ أَنْ يَمْشِيَ الرَّجُلُ مُخْتَصِرًا وَالِاخْتِصَارُ أَنْ يَضَعَ الرَّجُلُ يَدَهُ عَلَى خَاصِرَتِهِ فِي الصَّلَاةِ أَوْ يَضَعَ يَدَيْهِ جَمِيعًا عَلَى خَاصِرَتَيْهِ وَيُرْوَى أَنَّ إِبْلِيسَ إِذَا مَشَى مَشَى مُخْتَصِرًا","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata; telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin Hassan] dari [Muhammad bin Sirin] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam melarang seorang laki-laki shalat dengan melerakkan tangan di lambung.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Umar.\" Abu Isa berkata; \"Hadits Abu Hurairah derajatnya hasan shahih. Sebagian ahli ilmu memakruhkan meletakkan tangan di lambung dalam shalat. Dan sebagian yang lain memakruhkan bila seorang laki-laki berjalan dengan meletakkan tangan di lambung. Ikhtishar artinya, seorang laki-laki meletakkan tangan di lambungnya dalam shalat. Atau meletakkan kedua tangannya pada kedua lambung. Diriwayatkan bahwa Iblis jika berjalan maka ia berjalan dengan meletakkan tangan di lambung.\""},"350":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ عِمْرَانَ بْنِ مُوسَى عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ أَبِي رَافِعٍأَنَّهُ مَرَّ بِالْحَسَنِ بْنِ عَلِيٍّ وَهُوَ يُصَلِّي وَقَدْ عَقَصَ ضَفِرَتَهُ فِي قَفَاهُ فَحَلَّهَا فَالْتَفَتَ إِلَيْهِ الْحَسَنُ مُغْضَبًا فَقَالَ أَقْبِلْ عَلَى صَلَاتِكَ وَلَا تَغْضَبْ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ذَلِكَ كِفْلُ الشَّيْطَانِقَالَ وَفِي الْبَاب عَنْ أُمِّ سَلَمَةَ وَعَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي رَافِعٍ حَدِيثٌ حَسَنٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ كَرِهُوا أَنْ يُصَلِّيَ الرَّجُلُ وَهُوَ مَعْقُوصٌ شَعْرُهُ قَالَ أَبُو عِيسَى وَعِمْرَانُ بْنُ مُوسَى هُوَ الْقُرَشِيُّ الْمَكِّيُّ وَهُوَ أَخُو أَيُّوبَ بْنِ مُوسَى","id":"Telah menceritakan kepada kami [Yahya bin Musa] berkata; telah menceritakan kepada kami [Abdurrazaq] berkata; telah mengabarkan kepada kami [Ibnu Juraij] dari [Imran bin Musa] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Ayahnya] dari [Abu Rafi'] bahwasanya ia pernah melewati Hasan bin Ali ketika Hasan sedang melaksanakan shalat. Hasan waktu itu menggelung rambutnya dan meletakkannya pada tengkuk, namun Abu Rafi' mengurainya kembali. Maka Hasan pun berpaling kepadanya dengan marah. Abu Rafi' berkata; \"Kembalilah shalat dan jangan marah, karena aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Itu adalah tempat duduk setan.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ummu Salamah dan Abdullah bin Abbas.\" Abu Isa berkata; \"Hadits Abu Rafi' derajatnya hasan. Hadits ini diamalkan oleh ahli ilmu. Mereka memakruhkan seorang laki-laki shalat dengan menggelung rambutnya.\" Abu Isa berkata; \"Imran bin Musa namanya adalah Al Qurasyi Al Makki, ia adalah saudara Ayyub bin Musa.\""},"351":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا اللَّيْثُ بْنُ سَعْدٍ أَخْبَرَنَا عَبْدُ رَبِّهِ بْنُ سَعِيدٍ عَنْ عِمْرَانَ بْنِ أَبِي أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ نَافِعِ ابْنِ الْعَمْيَاءِ عَنْ رَبِيعَةَ بْنِ الْحَارِثِ عَنْ الْفَضْلِ بْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةُ مَثْنَى مَثْنَى تَشَهَّدُ فِي كُلِّ رَكْعَتَيْنِ وَتَخَشَّعُ وَتَضَرَّعُ وَتَمَسْكَنُ وَتَذَرَّعُ وَتُقْنِعُ يَدَيْكَ يَقُولُ تَرْفَعُهُمَا إِلَى رَبِّكَ مُسْتَقْبِلًا بِبُطُونِهِمَا وَجْهَكَ وَتَقُولُ يَا رَبِّ يَا رَبِّ وَمَنْ لَمْ يَفْعَلْ ذَلِكَ فَهُوَ كَذَا وَكَذَاقَالَ أَبُو عِيسَى و قَالَ غَيْرُ ابْنِ الْمُبَارَكِ فِي هَذَا الْحَدِيثِ مَنْ لَمْ يَفْعَلْ ذَلِكَ فَهِيَ خِدَاجٌ قَالَ أَبُو عِيسَى سَمِعْت مُحَمَّدَ بْنَ إِسْمَعِيلَ يَقُولُ رَوَى شُعْبَةُ هَذَا الْحَدِيثَ عَنْ عَبْدِ رَبِّهِ بْنِ سَعِيدٍ فَأَخْطَأَ فِي مَوَاضِعَ فَقَالَ عَنْ أَنَسِ بْنِ أَبِي أَنَسٍ وَهُوَ عِمْرَانُ بْنُ أَبِي أَنَسٍ وَقَالَ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ وَإِنَّمَا هُوَ عَبْدُ اللَّهِ بْنُ نَافِعِ ابْنِ الْعَمْيَاءِ عَنْ رَبِيعَةَ بْنِ الْحَارِثِ وَقَالَ شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ الْمُطَّلِبِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّمَا هُوَ عَنْ رَبِيعَةَ بْنِ الْحَارِثِ بْنِ عَبْدِ الْمُطَّلِبِ عَنْ الْفَضْلِ بْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مُحَمَّدٌ وَحَدِيثُ اللَّيْثِ بْنِ سَعْدٍ هُوَ حَدِيثٌ صَحِيحٌ يَعْنِي أَصَحَّ مِنْ حَدِيثِ شُعْبَةَ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] berkata; telah menceritakan kepada kami [Abdullah bin Al Mubarak] berkata; telah mengabarkan kepada kami [Al Laits bin Sa'd] berkata; telah mengabarkan kepada kami [Abdu Rabbih bin Sa'id] dari [Imran bin Abu Anas] dari [Abdullah bin Nafi' bin Al Amya`] dari [Rabi'ah Ibnil Harits] dari [Al Fadll bin Abbas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat itu dua rakaat dua rakaat, duduk tasyahud pada setiap dua rakaat, khusyu', tunduk, tenang dan menengadahkan kedua tanganmu.\" Beliau bersabda lagi: \"Engkau angkat kedua tanganmu pada Rabbmu dengan menghadapkan bagian depan telapak tangan ke wajahmu. Engkau katakan, \"Ya Rabb, Ya Rabb, \" dan barangsiapa tidak melakukan hal itu maka ia begini dan begini.\" Abu Isa berkata; \"Selain bin Al Mubarak dan juga yang mengatakan tentang hadits ini, \"Barangsiapa tidak melakukan seperti itu maka shalatnya kurang (tidak sempurna).\" Abu Isa berkata; \"Aku mendengar Muhammd bin Isma'il berkata; \"Syu'bah meriwayatkan hadits ini dari Abdu Rabbih bin Sa'id namun ia salah dalam beberapa tempat. Ia berkata; \"Dari Anas bin Abu Anas, dia adalah Imran bin Abu Anas.\" Ia berkata; \"Dari Abdullah bin Al Harits, padahal dia adalah Abdullan bin Nafi' bin Al Amya`, dari Rabi'ah bin Al Harits.\" Syu'bah berkata dari Abdullah bin Al Harits, dari Abdul Muthallib, dari Al fall bin Abbas, dari Nabi shallallahu 'alaihi wasallam.\" Muhammad berkata; \"Hadits Al Laits bin Sa'd derajatnya hasan shahih, yakni lebih shahih dari hadits Syu'bah.\""},"352":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ رَجُلٍ عَنْ كَعْبِ بْنِ عُجْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَوَضَّأَ أَحَدُكُمْ فَأَحْسَنَ وُضُوءَهُ ثُمَّ خَرَجَ عَامِدًا إِلَى الْمَسْجِدِ فَلَا يُشَبِّكَنَّ بَيْنَ أَصَابِعِهِ فَإِنَّهُ فِي صَلَاةٍقَالَ أَبُو عِيسَى حَدِيثُ كَعْبِ بْنِ عُجْرَةَ رَوَاهُ غَيْرُ وَاحِدٍ عَنْ ابْنِ عَجْلَانَ مِثْلَ حَدِيثِ اللَّيْثِ وَرَوَى شَرِيكٌ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا الْحَدِيثِ وَحَدِيثُ شَرِيكٍ غَيْرُ مَحْفُوظٍ","id":"Telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Sa'id Al Maqburi] dari [Seorang laki-laki] dari [Ka'ab bin 'Ujrah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian berwudlu dan membaguskannya, kemudian keluar menuju masjid, maka janganlah ia menganyam antara jari-jarinya sebab ia dalam hitungan shalat.\" Abu Isa berkata; \"Hadits Ka'ab bin 'Ujrah telah diriwayatkan dari Ibnu 'Ajlan tidak hanya oleh satu orang saja, sebagaimana hadits Al Laits.\" Dan [Syarik] meriwayatkan dari [Muhammad bin 'Ajlan] dari [ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam sebagaimana hadits ini, sedangkan hadits Syarik tidak terjaga.\""},"353":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقِيلَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الصَّلَاةِ أَفْضَلُ قَالَ طُولُ الْقُنُوتِقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ حُبْشِيٍّ وَأَنَسِ بْنِ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عِيسَى حَدِيثُ جَابِرِ بْنِ عَبْدِ اللَّهِ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Az Zubair] dari [Jabir] ia berkata; \"Pernah ditanyakan kepada Nabi, \"Shalat bagaimanakan yang paling utama?\" beliau menjawab: \"Lama dalam berdiri.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin Hubsyi dan Anas bin Malik dari Nabi shallallahu 'alaihi wasallam.\" Abu Isa berkata; \"Hadits Jabir bin Abdullah derajatnya hasan shahih. Hadits ini telah diriwayatkan dari Jabir bin Abdullah dengan banyak jalur.\""},"354":{"ar":"حَدَّثَنَا أَبُو عَمَّارٍ حَدَّثَنَا الْوَلِيدُ قَالَ و حَدَّثَنَا أَبُو مُحَمَّدٍ رَجَاءٌ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي الْوَلِيدُ بْنُ هِشَامٍ الْمُعَيْطِيُّ قَالَ حَدَّثَنِي مَعْدَانُ بْنُ طَلْحَةَ الْيَعْمَرِيُّ قَالَلَقِيتُ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَهُ دُلَّنِي عَلَى عَمَلٍ يَنْفَعُنِي اللَّهُ بِهِ وَيُدْخِلُنِي الْجَنَّةَ فَسَكَتَ عَنِّي مَلِيًّا ثُمَّ الْتَفَتَ إِلَيَّ فَقَالَ عَلَيْكَ بِالسُّجُودِ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ عَبْدٍ يَسْجُدُ لِلَّهِ سَجْدَةً إِلَّا رَفَعَهُ اللَّهُ بِهَا دَرَجَةً وَحَطَّ عَنْهُ بِهَا خَطِيئَةًقَالَ مَعْدَانُ بْنُ طَلْحَةَ فَلَقِيتُ أَبَا الدَّرْدَاءِ فَسَأَلْتُهُ عَمَّا سَأَلْتُ عَنْهُ ثَوْبَانَ فَقَالَ عَلَيْكَ بِالسُّجُودِ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ عَبْدٍ يَسْجُدُ لِلَّهِ سَجْدَةً إِلَّا رَفَعَهُ اللَّهُ بِهَا دَرَجَةً وَحَطَّ عَنْهُ بِهَا خَطِيئَةً قَالَ مَعْدَانُ بْنُ طَلْحَةَ الْيَعْمَرِيُّ وَيُقَالُ ابْنُ أَبِي طَلْحَةَ قَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَبِي أُمَامَةَ وَأَبِي فَاطِمَةَ قَالَ أَبُو عِيسَى حَدِيثُ ثَوْبَانَ وَأَبِي الدَّرْدَاءِ فِي كَثْرَةِ الرُّكُوعِ وَالسُّجُودِ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ اخْتَلَفَ أَهْلُ الْعِلْمِ فِي هَذَا الْبَابِ فَقَالَ بَعْضُهُمْ طُولُ الْقِيَامِ فِي الصَّلَاةِ أَفْضَلُ مِنْ كَثْرَةِ الرُّكُوعِ وَالسُّجُودِ و قَالَ بَعْضُهُمْ كَثْرَةُ الرُّكُوعِ وَالسُّجُودِ أَفْضَلُ مِنْ طُولِ الْقِيَامِ و قَالَ أَحْمَدُ بْنُ حَنْبَلٍ قَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا حَدِيثَانِ وَلَمْ يَقْضِ فِيهِ بِشَيْءٍ و قَالَ إِسْحَقُ أَمَّا فِي النَّهَارِ فَكَثْرَةُ الرُّكُوعِ وَالسُّجُودِ وَأَمَّا بِاللَّيْلِ فَطُولُ الْقِيَامِ إِلَّا أَنْ يَكُونَ رَجُلٌ لَهُ جُزْءٌ بِاللَّيْلِ يَأْتِي عَلَيْهِ فَكَثْرَةُ الرُّكُوعِ وَالسُّجُودِ فِي هَذَا أَحَبُّ إِلَيَّ لِأَنَّهُ يَأْتِي عَلَى جُزْئِهِ وَقَدْ رَبِحَ كَثْرَةَ الرُّكُوعِ وَالسُّجُودِ قَالَ أَبُو عِيسَى وَإِنَّمَا قَالَ إِسْحَقُ هَذَا لِأَنَّهُ كَذَا وُصِفَ صَلَاةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ وَوُصِفَ طُولُ الْقِيَامِ وَأَمَّا بِالنَّهَارِ فَلَمْ يُوصَفْ مِنْ صَلَاتِهِ مِنْ طُولِ الْقِيَامِ مَا وُصِفَ بِاللَّيْلِ","id":"Telah menceritakan kepada kami [Abu Ammar] berkata; telah menceritakan kepada kami [Al Walid] berkata; dan telah menceritakan kepada kami [Abu Muhammad Raja`] berkata; telah menceritakan kepada kami [Al Walid bin Muslim] dari [Al Auza'i] berkata; telah menceritakan kepadaku [Al Walid bin Hisyam Al Mu'aithi] berkata; telah menceritakan kepadaku [Ma'dan bin Thalhah Al Ya'mari] berkata; Aku bertemu [Tsauban] pelayan Rasulullah shallallahu 'alaihi wasallam, lalu aku bertanya kepadanya, \"Tunjukkanlah kepadaku satu amalan yang dengannya Allah memberi manfaat dan memasukkan aku ke dalam surga, \" ia diam sejenak, lalu berpaling kepadaku seraya berkata; \"Hendaklah engkau sujud, sebab aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang hamba sujud kepada Allah dengan sekali sujud kecuali dengannya Allah akan mengangkat satu derajat dan menghapus satu kesalahan.\" [Ma'dan Abu Thalhah] berkata; \"Aku bertemu dengan [Abu Darda`], lalu aku bertanya kepadanya apa yang pernah aku tanyakan kepada Tsauban, lalu ia pun menjawab, \"Hendaklah engkau sujud, sebab aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang hamba sujud kepada Allah dengan sekali sujud kecuali dengannya Allah akan mengangkat satu derajat dan menghapus satu kesalahan.\" Ia berkata; \"Ma'dan bin Thalhah Al Ya'mari, disebut juga dengan Ibnu Abu Thalhah.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Hurairah, Abu Umamah dan Abu Fatimah.\" Abu Isa berkata; \"Hadits Tsauban dan hadits Abu Darda` tentang banyaknya rukuk dan sujud derajatnya hasan shahih.\" Para ulama berselisih dalam masalah ini, sebagian mereka berkata; \"Lama berdiri dalam shalat lebih utama ketimbang memperbanyak rukuk dan sujud.\" Sedangkan sebagian yang lain berkata; \"Memperbanyak rukuk dan sujud lebih utama daripada memperpanjang lamanya berdiri.\" Ahmad berkata; \"Telah diriwayatkan dari Nabi shallallahu 'alaihi wasallam sebanyak dua hadits, namun beliau tidak memberikan keputusan.\" Sedangkan Ishaq berkata; \"Di waktu siang hendaknya ia memperbanyak rukuk dan sujud. Sedangkan di waktu malam hendaknya ia memperpanjang lama berdirinya. Kecuali seseorang yang mempunyai waktu malam yang lain (untuk shalat lagi), maka memperbanyak rukuk dan sujud lebih disukai. Sebab ia bisa menggunakan waktu tersebut hingga ia akan diuntungkan dengan memparbanyak rukuk dan sujud.\" Abu Isa berkata; \"Ishaq mengatakan demikian karena Nabi shallallahu 'alaihi wasallam disifati selalu berlama-lama ketika shalat di malam hari, sedangkan di siang hari beliau tidak berlama-lama sebagaimana di waktu malam.\""},"355":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ وَهُوَ ابْنُ إِبْرَاهِيمَ عَنْ عَلِيِّ بْنِ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ ضَمْضَمِ بْنِ جَوْسٍ عَنْ أَبِي هُرَيْرَةَ قَالَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَتْلِ الْأَسْوَدَيْنِ فِي الصَّلَاةِ الْحَيَّةُ وَالْعَقْرَبُقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَأَبِي رَافِعٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ وَكَرِهَ بَعْضُ أَهْلِ الْعِلْمِ قَتْلَ الْحَيَّةِ وَالْعَقْرَبِ فِي الصَّلَاةِ و قَالَ إِبْرَاهِيمُ إِنَّ فِي الصَّلَاةِ لَشُغْلًا وَالْقَوْلُ الْأَوَّلُ أَصَحُّ","id":"Telah menceritakan kepada kami [Ali bin Hujr] berkata; telah menceritakan kepada kami [Isma'il bin Ulayyah] -yaitu Ibnu Ibrahim- dari [Ali bin Al Mubarak] dari [Yahya bin Abu Katsir] dari [Dlamdlam bin Jaus] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk membunuh dua binatang hitam dalam shalat; ular dan kalajengking.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Abbas dan Abu Rafi'\". Abu Isa berkata; \"Hadits Abu Hurairah derajatnya hasan shahih. Para ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan selainnya mengamalkan hadits ini. Pendapat ini juga diambil oleh Ahmad dan Ishaq. Sedangkan sebagian ahli ilmu memakruhkan membunuh ular dan kalajengking dalam shalat. Ibrahim berkata; \"Sesungguhnya dalam shalat ada kesibukan.\" Pendapat pertama lebih shahih."},"356":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ الْأَعْرَجِ عَنْ عَبْدِ اللَّهِ ابْنِ بُحَيْنَةَ الْأَسَدِيِّ حَلِيفِ بَنِي عَبْدِ الْمُطَّلِبِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فِي صَلَاةِ الظُّهْرِ وَعَلَيْهِ جُلُوسٌ فَلَمَّا أَتَمَّ صَلَاتَهُ سَجَدَ سَجْدَتَيْنِ يُكَبِّرُ فِي كُلِّ سَجْدَةٍ وَهُوَ جَالِسٌ قَبْلَ أَنْ يُسَلِّمَ وَسَجَدَهُمَا النَّاسُ مَعَهُ مَكَانَ مَا نَسِيَ مِنْ الْجُلُوسِقَالَ وَفِي الْبَاب عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ","id":"Telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Al A'raj] dari [Abdullah bin Buhainah Al Asadi] sekutu bani Abdul Muthallib, bahwa Nabi shallallahu 'alaihi wasallam berdiri ketika shalat zhuhur yang seharusnya duduk. Maka ketika telah selesai beliau sujud dengan dua kali sujud, beliau bertakbir pada setiap sujud dan duduk sebelum salam. Orang-orang ikut sujud sahwi dua kali sujud bersama beliau sebagai pengganti duduk yang beliau terlupa.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abdurrahman bin Auf.\""},"357":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْأَعْلَى وَأَبُو دَاوُدَ قَالَا حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ أَنَّ أَبَا هُرَيْرَةَ وَعَبْدَ اللَّهِ بْنَ السَّائِبِ الْقَارِئَ كَانَايَسْجُدَانِ سَجْدَتَيْ السَّهْوِ قَبْلَ التَّسْلِيمِقَالَ أَبُو عِيسَى حَدِيثُ ابْنِ بُحَيْنَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ وَهُوَ قَوْلُ الشَّافِعِيِّ يَرَى سَجْدَتَيْ السَّهْوِ كُلِّهِ قَبْلَ السَّلَامِ وَيَقُولُ هَذَا النَّاسِخُ لِغَيْرِهِ مِنْ الْأَحَادِيثِ وَيَذْكُرُ أَنَّ آخِرَ فِعْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ عَلَى هَذَا و قَالَ أَحْمَدُ وَإِسْحَقُ إِذَا قَامَ الرَّجُلُ فِي الرَّكْعَتَيْنِ فَإِنَّهُ يَسْجُدُ سَجْدَتَيْ السَّهْوِ قَبْلَ السَّلَامِ عَلَى حَدِيثِ ابْنِ بُحَيْنَةَ وَعَبْدُ اللَّهِ ابْنُ بُحَيْنَةَ هُوَ عَبْدُ اللَّهِ بْنُ مَالِكٍ وَهُوَ ابْنُ بُحَيْنَةَ مَالِكٌ أَبُوهُ وَبُحَيْنَةُ أُمُّهُ هَكَذَا أَخْبَرَنِي إِسْحَقُ بْنُ مَنْصُورٍ عَنْ عَلِيِّ بْنِ عَبْدِ اللَّهِ بْنِ الْمَدِينِيِّ قَالَ أَبُو عِيسَى وَاخْتَلَفَ أَهْلُ الْعِلْمِ فِي سَجْدَتَيْ السَّهْوِ مَتَى يَسْجُدُهُمَا الرَّجُلُ قَبْلَ السَّلَامِ أَوْ بَعْدَهُ فَرَأَى بَعْضُهُمْ أَنْ يَسْجُدَهُمَا بَعْدَ السَّلَامِ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَأَهْلِ الْكُوفَةِ و قَالَ بَعْضُهُمْ يَسْجُدُهُمَا قَبْلَ السَّلَامِ وَهُوَ قَوْلُ أَكْثَرِ الْفُقَهَاءِ مِنْ أَهْلِ الْمَدِينَةِ مِثْلِ يَحْيَى بْنِ سَعِيدٍ وَرَبِيعَةَ وَغَيْرِهِمَا وَبِهِ يَقُولُ الشَّافِعِيُّ و قَالَ بَعْضُهُمْ إِذَا كَانَتْ زِيَادَةً فِي الصَّلَاةِ فَبَعْدَ السَّلَامِ وَإِذَا كَانَ نُقْصَانًا فَقَبْلَ السَّلَامِ وَهُوَ قَوْلُ مَالِكِ بْنِ أَنَسٍ و قَالَ أَحْمَدُ مَا رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَجْدَتَيْ السَّهْوِ فَيُسْتَعْمَلُ كُلٌّ عَلَى جِهَتِهِ يَرَى إِذَا قَامَ فِي الرَّكْعَتَيْنِ عَلَى حَدِيثِ ابْنِ بُحَيْنَةَ فَإِنَّهُ يَسْجُدُهُمَا قَبْلَ السَّلَامِ وَإِذَا صَلَّى الظُّهْرَ خَمْسًا فَإِنَّهُ يَسْجُدُهُمَا بَعْدَ السَّلَامِ وَإِذَا سَلَّمَ فِي الرَّكْعَتَيْنِ مِنْ الظُّهْرِ وَالْعَصْرِ فَإِنَّهُ يَسْجُدُهُمَا بَعْدَ السَّلَامِ وَكُلٌّ يُسْتَعْمَلُ عَلَى جِهَتِهِ وَكُلُّ سَهْوٍ لَيْسَ فِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذِكْرٌ فَإِنَّ سَجْدَتَيْ السَّهْوِ قَبْلَ السَّلَامِ و قَالَ إِسْحَقُ نَحْوَ قَوْلِ أَحْمَدَ فِي هَذَا كُلِّهِ إِلَّا أَنَّهُ قَالَ كُلُّ سَهْوٍ لَيْسَ فِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذِكْرٌ فَإِنْ كَانَتْ زِيَادَةً فِي الصَّلَاةِ يَسْجُدُهُمَا بَعْدَ السَّلَامِ وَإِنْ كَانَ نُقْصَانًا يَسْجُدُهُمَا قَبْلَ السَّلَامِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Abdul A'la] dan [Abu Dawud] keduanya berkata; telah menceritakan kepada kami [Hisyam] dari [Yahya bin Abi Katsir] dari [Muhammad bin Ibrahim] bahwa [Abu Hurairah] dan [Abdullah bin As Sa`ib Al Qari`] sujud dengan dua kali sujud sebelum salam.\" Abu Isa berkata; \"Hadits Ibnu Buhainah derajatnya hasan shahih. Hadits ini diamalkan oleh sebagian ahli ilmu. Dan ini adalah pendapat yang diambil oleh Syafi'i. Ia berpendapat bahwa dua sujud sahwi itu dilakukan sebelum salam. Ia mengatakan, \"Hadits ini menghapus hadits-hadits yang lain, dan ia menyebutkan juga bahwa seperti itulah terakhir kali yang dilakukan oleh Nabi shallallahu 'alaihi wasallam. Ahmad dan Ishaq berkata; \"Jika seseorang berdiri pada rakaat kedua maka ia harus sujud dua kali sebelum salam berdasarkan hadits Ibnu Buhainah. Dan Abdullah Ibnu Buhainah adalah Abdullah bin Malik. Ia adalah Ibnu Bunainah, ayahnya bernama Malik dan ibunya bernama Buhainah. Seperti inilah Ishaq bin Manshur mengabarkan kepadaku dari Ali bin Abdullah bin Al Madini.\" Abu Isa berkata; \"Para ahli ilmu berselisih pendapat kapan seseorang harus sujud sahwi, sebelum salam atau setelahnya. Sebagian mereka berpendapat bahwa itu dilakukan setelah salam. Pendapat ini diambil oleh Sufyan Ats Tsauri dan penduduk Kufah. Sedangkan sebagian yang lain berpendapat bahwa itu dilakukan sebelum salam. Pendapat ini banyak diambil oleh para fuqaha Madinah seperti Yahya bin Sa'id, Rabi'ah dan yang lainnya. Pendapat ini juga diambil oleh Imam Syafi'i. Sebagian ulama mengatakan, \"Jika itu berupa tambahan maka sujud dilakukan setelah salam, tetapi jika berupa kekurangan rakaat maka sebelum salam.\" Pendapat ini diambil oleh Malik bin Anas. Imam Ahmad berkata; \"Tidak pernah diriwayatkan dari Nabi shallallahu 'alaihi wasallam tentang dua sujud sahwi, maka hadits itu diamalkan sesuai dengan kasus yang menyertainya. Jika seseorang berdiri pada rakaat kedua sebagaimana hadits Ibnu Buhainah maka ia sujud dua kali sebelum salam. Jika ia shalat zhuhur lima rakaat maka ia sujud dua kali setelah salam. Dan jika ia salam di rakaat kedua pada shalat zhuhur atau asar maka ia sujud setelah salam. Setiap itu dilakukan sesuai dengan kasusnya. Dan setiap lupa tidak pernah disebutkan riwayat dari Nabi shallallahu 'alaihi wasallam, karena sesungguhnya dua sujud sahwi itu dilakukan sebelum salam. Dalam hal ini Imam Ishaq juga mengatakan sebagaiaman yang dikatakan oleh Imam Ahmad, hanya saja ia mengatakan, \"Dan setiap lupa tidak pernah disebutkan riwayat dari Nabi shallallahu 'alaihi wasallam, jika itu berupa tambahan dalam shalat maka ia sujud sebelum salam, namun jika kurang dalam rakaat maka ia sujud sebelum salam.\""},"358":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ خَمْسًا فَقِيلَ لَهُ أَزِيدَ فِي الصَّلَاةِ فَسَجَدَ سَجْدَتَيْنِ بَعْدَ مَا سَلَّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata; telah mengabarkan kepada kami [Abdurrahman bin Mahdi] berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari [Alqamah] dari [Abdullah bin Mas'ud] bahwa Nabi shallallahu 'alaihi wasallam pernah shalat zhuhur lima rakaat. Beliau ditanya, \"Apakah shalatnya ditambah?\" maka beliau pun sujud dua kali sebelum salam.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\""},"359":{"ar":"حَدَّثَنَا هَنَّادٌ وَمَحْمُودُ بْنُ غَيْلَانَ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ سَجْدَتَيْ السَّهْوِ بَعْدَ الْكَلَامِقَالَ وَفِي الْبَاب عَنْ مُعَاوِيَةَ وَعَبْدِ اللَّهِ بْنِ جَعْفَرٍ وَأَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Hannad] dan [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dari [Abdullah] bahwa Nabi shallallahu 'alaihi wasallam sujud sahwi dengan dua kali sujud setelah berbincang-bincang.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Mu'awiyah, Abdullah bin Ja'far dan Abu Hurairah.\""},"360":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَهُمَا بَعْدَ السَّلَامِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ أَيُّوبُ وَغَيْرُ وَاحِدٍ عَنْ ابْنِ سِيرِينَ وَحَدِيثُ ابْنِ مَسْعُودٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ قَالُوا إِذَا صَلَّى الرَّجُلُ الظُّهْرَ خَمْسًا فَصَلَاتُهُ جَائِزَةٌ وَسَجَدَ سَجْدَتَيْ السَّهْوِ وَإِنْ لَمْ يَجْلِسْ فِي الرَّابِعَةِ وَهُوَ قَوْلُ الشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ و قَالَ بَعْضُهُمْ إِذَا صَلَّى الظُّهْرَ خَمْسًا وَلَمْ يَقْعُدْ فِي الرَّابِعَةِ مِقْدَارَ التَّشَهُّدِ فَسَدَتْ صَلَاتُهُ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَبَعْضِ أَهْلِ الْكُوفَةِ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Husyaim] dari [Hisyam bin Hassan] dari [Muhammad bin Sirin] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam melakukan dua sujud sahwi setelah salam.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Hadits ini telah diriwayatkan [Ayyub] dan beberapa orang dari [Ibnu Sirin]. Dan hadits Ibnu Mas'ud derajatnya hasan shahih. Hadits ini diamalkan oleh sebagian ahli ilmu, mereka berkata; \"Jika seorang laki-laki shalat zhuhur lima rakaat maka shalat boleh (sah), dan hendaknya ia melakukan dua sujud sahwi meskipun ia tidak duduk pada rakaat keempat. Ini adalah pendapat yang diambil oleh Imam Syafi'i, Ahmad dan Ishaq. Sedangkan sebagian yang lain mengatakan, \"Jika seorang laki-laki zhuhur lima rakaat dan tidak duduk pada rakaat keempat sekadar duduk tasyahud, maka shalatnya rusak. Ini adalah pendapat yang diambil oleh Sufyan Ats Tsauri dan sebagian penduduk Kufah.\""},"361":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى النَّيْسَابُورِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ قَالَ أَخْبَرَنِي أَشْعَثُ عَنْ ابْنِ سِيرِينَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِهِمْ فَسَهَا فَسَجَدَ سَجْدَتَيْنِ ثُمَّ تَشَهَّدَ ثُمَّ سَلَّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَرَوَى مُحَمَّدُ بْنُ سِيرِينَ عَنْ أَبِي الْمُهَلَّبِ وَهُوَ عَمُّ أَبِي قِلَابَةَ غَيْرَ هَذَا الْحَدِيثِ وَرَوَى مُحَمَّدٌ هَذَا الْحَدِيثَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ وَأَبُو الْمُهَلَّبِ اسْمُهُ عَبْدُ الرَّحْمَنِ بْنُ عَمْرٍو وَيُقَالُ أَيْضًا مُعَاوِيَةُ بْنُ عَمْرٍو وَقَدْ رَوَى عَبْدُ الْوَهَّابِ الثَّقَفِيُّ وَهُشَيْمٌ وَغَيْرُ وَاحِدٍ هَذَا الْحَدِيثَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ بِطُولِهِ وَهُوَ حَدِيثُ عِمْرَانَ بْنِ حُصَيْنٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلَّمَ فِي ثَلَاثِ رَكَعَاتٍ مِنْ الْعَصْرِ فَقَامَ رَجُلٌ يُقَالُ لَهُ الْخِرْبَاقُ وَاخْتَلَفَ أَهْلُ الْعِلْمِ فِي التَّشَهُّدِ فِي سَجْدَتَيْ السَّهْوِ فَقَالَ بَعْضُهُمْ يَتَشَهَّدُ فِيهِمَا وَيُسَلِّمُ و قَالَ بَعْضُهُمْ لَيْسَ فِيهِمَا تَشَهُّدٌ وَتَسْلِيمٌ وَإِذَا سَجَدَهُمَا قَبْلَ السَّلَامِ لَمْ يَتَشَهَّدْ وَهُوَ قَوْلُ أَحْمَدَ وَإِسْحَقَ قَالَا إِذَا سَجَدَ سَجْدَتَيْ السَّهْوِ قَبْلَ السَّلَامِ لَمْ يَتَشَهَّدْ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya An Naisaburi] berkata; telah menceritakan kepada kami [Muhammad bin Abdullah Al Anshari] berkata; telah mengabarkan kepadaku [Asy'ats] dari [Ibnu Sirin] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Abu Al Muhallab] dari [Imran bin Hushain] bahwa Nabi shallallahu 'alaihi wasallam shalat bersama para sahabat kemudian lupa, beliau lalu sujud dengan dua kali sujud. Setelah itu beliau tasyahud dan salam.\" Abu Isa berkata; \"Hadits ini derajatnya hasan gharib. Muhammad bin Sirin meriwayatkan hadits yang berbeda dari Abu Al Muhallab, ia adalah paman Abu Qilabah. Sedangkan [Muhammad] meriwayatkan hadits ini dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Abu Al Muhallab] dan Abu Al Muhallab namanya adalah Abdurrahman bin 'Amru, disebut juga dengan nama Mu'awiyah bin 'Amru. [Abdul Wahhab Ats Tsaqafi] dan [Husyaim] dan beberapa orang meriwayatkan hadits ini dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dengan (lafadz) sempurna. Yaitu hadits Imran bin Hushain bahwa Nabi shallallahu 'alaihi wasallam salam di rakaat ketiga pada shalat asar. Maka berdirilah seorang laki-laki yang bernama Hirbaq. Para ahli ilmu berselisih berkenaan dengan tasyahud dalam dua sujud sahwi. Sebagian mereka berkata; \"Hendaknya seseorang bertasyahud dalam dua sujud tersebut kemudian salam.\" Sedangkan yang lainnya berkata; \"Pada dua sujud itu tidak ada tasyahud dan salam, jika ia melakukan sujud tersebut sebelum salam ia tidak harus bertasyahud.\" Ini adalah pendapat yang diambil oleh Ahmad dan Ishaq, keduanya berkata; \"Jika seseorang melakukan dua sujud sahwi sebelum salam maka ia tidak perlu bertasyahud.\""},"362":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ الدَّسْتُوَائِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِيَاضٍ يَعْنِي ابْنَ هِلَالٍ قَالَ قُلْتُ لِأَبِي سَعِيدٍأَحَدُنَا يُصَلِّي فَلَا يَدْرِي كَيْفَ صَلَّى فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى أَحَدُكُمْ فَلَمْ يَدْرِ كَيْفَ صَلَّى فَلْيَسْجُدْ سَجْدَتَيْنِ وَهُوَ جَالِسٌقَالَ وَفِي الْبَاب عَنْ عُثْمَانَ وَابْنِ مَسْعُودٍ وَعَائِشَةَ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي سَعِيدٍ حَدِيثٌ حَسَنٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ أَبِي سَعِيدٍ مِنْ غَيْرِ هَذَا الْوَجْهِ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا شَكَّ أَحَدُكُمْ فِي الْوَاحِدَةِ وَالثِّنْتَيْنِ فَلْيَجْعَلْهُمَا وَاحِدَةً وَإِذَا شَكَّ فِي الثِّنْتَيْنِ وَالثَّلَاثِ فَلْيَجْعَلْهُمَا ثِنْتَيْنِ وَيَسْجُدْ فِي ذَلِكَ سَجْدَتَيْنِ قَبْلَ أَنْ يُسَلِّمَ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَصْحَابِنَا و قَالَ بَعْضُ أَهْلِ الْعِلْمِ إِذَا شَكَّ فِي صَلَاتِهِ فَلَمْ يَدْرِ كَمْ صَلَّى فَلْيُعِدْ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] berkata; telah menceritakan kepada kami [Hisyam Ad Dastuwa`i] dari [Yahya bin Abu Katsir] dari [Iyadl] -yaitu Ibnu Hilal- ia berkata; \"Aku bertanya [Abu Sa'id]; salah seorang dari kami shalat, namun ia tidak tahu berapa rakaat ia telah salat?\" maka ia menjawab, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian shalat dan tidak tahu berapa rakaat ia telah shalat, maka hendaklah ia sujud dua kali sedang ia dalam keadaan duduk.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Utsman, Ibnu Mas'ud, 'Aisyah dan Abu Hurairah.\" Abu Isa berkata; \"Hadits Abu Sa'id ini derajatnya hasan shahih. Hadits ini juga diriwayatkan dari Abu Sa'id dengan jalur yang lain. Telah diriwayatkan dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau bersabda: \"Jika salah seorang dari kalian ragu satu atau dua rakaat maka hitunglah satu rakaat, dan jika ragu dua atau tiga maka hitunglah dua rakaat lalu sujudlah dua kali sebelum salam. Hadits ini diamalkan oleh sahabat-sahabat kami. Sedangkan sebagian ulama yang lain berpendapat, jika seseorang merasa ragu dalam shalatnya hingga tidak tahu berapa rakaat ia telah shalat, maka hendaklah ia mengulanginya.\""},"363":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّيْطَانَ يَأْتِي أَحَدَكُمْ فِي صَلَاتِهِ فَيَلْبِسُ عَلَيْهِ حَتَّى لَا يَدْرِيَ كَمْ صَلَّى فَإِذَا وَجَدَ ذَلِكَ أَحَدُكُمْ فَلْيَسْجُدْ سَجْدَتَيْنِ وَهُوَ جَالِسٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya setan datang pada salah seorang dari kalian ketika shalat, lalu mengacaukannya hingga ia tidak tahu berapa rakaat ia telah shalat. Maka jika salah seorang dari kalian mendapati yang seperti itu hendaklah ia sujud dua kali sedang ia dalam keadaan sujud.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih.\""},"364":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدٍ ابْنُ عَثْمَةَ الْبَصْرِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ إِسْحَقَ عَنْ مَكْحُولٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا سَهَا أَحَدُكُمْ فِي صَلَاتِهِ فَلَمْ يَدْرِ وَاحِدَةً صَلَّى أَوْ ثِنْتَيْنِ فَلْيَبْنِ عَلَى وَاحِدَةٍ فَإِنْ لَمْ يَدْرِ ثِنْتَيْنِ صَلَّى أَوْ ثَلَاثًا فَلْيَبْنِ عَلَى ثِنْتَيْنِ فَإِنْ لَمْ يَدْرِ ثَلَاثًا صَلَّى أَوْ أَرْبَعًا فَلْيَبْنِ عَلَى ثَلَاثٍ وَلْيَسْجُدْ سَجْدَتَيْنِ قَبْلَ أَنْ يُسَلِّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ مِنْ غَيْرِ هَذَا الْوَجْهِ رَوَاهُ الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Muhammad bin Khalid bin Atsmah Al Bashri] berkata; telah menceritakan kepada kami [Ibrahim bin Sa'd] berkata; telah menceritakan kepadaku [Muhammad bin Ishaq] dari [Makhul] dari [Kuraib] dari [Ibnu Abbas] dari [Abdurrahman bin Auf] ia berkata; \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian merasa ragu dalam shalatnya hingga tidak tahu satu rakaat atau dua rakaat yang telah ia kerjakan maka hendaknya ia hitung satu rakaat. Jika tidak tahu dua atau tiga rakaat yang telah ia kerjakan maka hendaklah ia hitung dua rakaat. Dan jika tidak tahu tiga atau empat rakaat yang telah ia kerjakan maka hendaklah ia hitung tiga rakaat. Setelah itu sujud dua kali sebelum salam.\" Abu Isa berkata; \"Hadits ini derajatnya hasan gharib shahih. Hadits ini juga telah diriwayatkan dari Abdurrahman bin Auf dengan jalur lain. [Az Zuhri] meriwayatkannya dari [Ubaidullah bin Abdullah bin Utbah] dari [Abdurrahman bin Auf] dari Nabi shallallahu 'alaihi wasallam.\""},"365":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ أَيُّوبَ بْنِ أَبِي تَمِيمَةَ وَهُوَ أَيُّوبُ السَّخْتِيَانِيُّ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصَرَفَ مِنْ اثْنَتَيْنِ فَقَالَ لَهُ ذُو الْيَدَيْنِ أَقُصِرَتْ الصَّلَاةُ أَمْ نَسِيتَ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَدَقَ ذُو الْيَدَيْنِ فَقَالَ النَّاسُ نَعَمْ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى اثْنَتَيْنِ أُخْرَيَيْنِ ثُمَّ سَلَّمَ ثُمَّ كَبَّرَ فَسَجَدَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَ ثُمَّ كَبَّرَ فَرَفَعَ ثُمَّ سَجَدَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عِمْرَانَ بْنِ حُصَيْنٍ وَابْنِ عُمَرَ وَذِي الْيَدَيْنِ قَالَ أَبُو عِيسَى وَحَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَاخْتَلَفَ أَهْلُ الْعِلْمِ فِي هَذَا الْحَدِيثِ فَقَالَ بَعْضُ أَهْلِ الْكُوفَةِ إِذَا تَكَلَّمَ فِي الصَّلَاةِ نَاسِيًا أَوْ جَاهِلًا أَوْ مَا كَانَ فَإِنَّهُ يُعِيدُ الصَّلَاةَ وَاعْتَلُّوا بِأَنَّ هَذَا الْحَدِيثَ كَانَ قَبْلَ تَحْرِيمِ الْكَلَامِ فِي الصَّلَاةِ قَالَ وَأَمَّا الشَّافِعِيُّ فَرَأَى هَذَا حَدِيثًا صَحِيحًا فَقَالَ بِهِ و قَالَ هَذَا أَصَحُّ مِنْ الْحَدِيثِ الَّذِي رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّائِمِ إِذَا أَكَلَ نَاسِيًا فَإِنَّهُ لَا يَقْضِي وَإِنَّمَا هُوَ رِزْقٌ رَزَقَهُ اللَّهُ قَالَ الشَّافِعِيُّ وَفَرَّقَ هَؤُلَاءِ بَيْنَ الْعَمْدِ وَالنِّسْيَانِ فِي أَكْلِ الصَّائِمِ بِحَدِيثِ أَبِي هُرَيْرَةَ و قَالَ أَحْمَدُ فِي حَدِيثِ أَبِي هُرَيْرَةَ إِنْ تَكَلَّمَ الْإِمَامُ فِي شَيْءٍ مِنْ صَلَاتِهِ وَهُوَ يَرَى أَنَّهُ قَدْ أَكْمَلَهَا ثُمَّ عَلِمَ أَنَّهُ لَمْ يُكْمِلْهَا يُتِمُّ صَلَاتَهُ وَمَنْ تَكَلَّمَ خَلْفَ الْإِمَامِ وَهُوَ يَعْلَمُ أَنَّ عَلَيْهِ بَقِيَّةً مِنْ الصَّلَاةِ فَعَلَيْهِ أَنْ يَسْتَقْبِلَهَا وَاحْتَجَّ بِأَنَّ الْفَرَائِضَ كَانَتْ تُزَادُ وَتُنْقَصُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّمَا تَكَلَّمَ ذُو الْيَدَيْنِ وَهُوَ عَلَى يَقِينٍ مِنْ صَلَاتِهِ أَنَّهَا تَمَّتْ وَلَيْسَ هَكَذَا الْيَوْمَ لَيْسَ لِأَحَدٍ أَنْ يَتَكَلَّمَ عَلَى مَعْنَى مَا تَكَلَّمَ ذُو الْيَدَيْنِ لِأَنَّ الْفَرَائِضَ الْيَوْمَ لَا يُزَادُ فِيهَا وَلَا يُنْقَصُ قَالَ أَحْمَدُ نَحْوًا مِنْ هَذَا الْكَلَامِ و قَالَ إِسْحَقُ نَحْوَ قَوْلِ أَحْمَدَ فِي هَذَا الْبَابِ","id":"Telah menceritakan kepada kami [Al Anshar] berkata; telah menceritakan kepada kami [Ma'n] berkata; telah menceritakan kepada kami [Malik] dari [Ayyub bin Abu Tamimah] -yaitu Ayyub As Sakhtiyani- dari [Muhammad bin Sirin] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam berlalu (pergi) setelah mengerjakan dua rakaat. Maka Dzul Yadaini bertanya kepada beliau, \"Wahai Rasulullah, shalatnya yang diringkas atau memang engkau yang lupa?\" Rasulullah shallallahu 'alaihi wasallam lalu bertanya: \"Apakah benar yang dikatakan oleh Dzul Yadaini?\" orang-orang menjawab, \"Benar, \" maka Rasulullah shallallahu 'alaihi wasallam pun berdiri shalat dua rakaat kemudian salam. Setelah itu beliau takbir dan sujud sebagaimana sujudnya yang lalu atau bahkan lebih lama, kamudian takbir dan mengangkat kepala. Setelah itu beliau sujud sebagaimana sujudnya yang lalu atau bahkan lebih lama.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Imran bin Hushain, Ibnu Umar dan Dzul Yadaini.\" Abu Isa berkata; \"Hadits Abu Hurairah ini derajatnya hasan shahih. Para ulama berselisih tentang hadits ini, sebagian penduduk Kufah berkata; \"Jika seseorang berbicara dalam shalat karena lupa, bodoh atau apapun juga, maka hendaklah ia mengulangi shalatnya. Mereka beralasan bahwa hadits ini muncul sebelum diharamkannya berbicara dalam shalat. Imam Syafi'i memandang bahwa hadits ini shahih, dan ia berpegangan dengan hadits tersebut. Imam Syafi'i berkata lagi, \"Hadits ini lebih shahih ketimbang hadits yang diriwayatkan dari Nabi shallallahu 'alaihi wasallam berkenaan dengan orang yang berpuasa; bahwa apabila ia makan karena lupa maka ia tidak perlu mengqadlanya, sebab itu adalah rizki yang Allah berikan.\" Syafi'i mengatakan, \"Bagi orang yang berpuasa, mereka membedakan antara orang yang makan dengan sengaja dan orang yang tidak sengaja, berdasarkan hadits Abu Hurairah.\" Sedangkan Imam Ahmad dalam mengomentari hadits Abu Hurairah ini ia berkata; \"Bila seorang imam berbicara tentang sesuatu dari shalatnya dan dia yakin telah menyempurnakannya, kemudian mengerti (tersadar) bahwa ia belum menyempurnakannya, maka ia harus menyempurnakan shalatnya. Dan barangsiapa berbicara di belakang imam sedangkan ia mengetahui bahwa ia masih mempunyai sisa shalat yang belum ia kerjakan, maka hendaklah ia mengulanginya. Imam Ahmad berdalil bahwa ibadah-ibadah fardlu pada masa Rasulullah shallallahu 'alaihi wasallam kadang terjadi kelebihan dan kadang terjadi kekurangan. Dzul Yadaini berbicara karena yakin bahwa shalat beliau telah sempurna, hal ini tidak sama dengan hari ini. seseorang tidak boleh berbicara semakna dengan yang dikatakan oleh Dzul Yadaini, karena ibadah-ibadah fardlu pada hari ini tidak bisa ditambah atau dikurangi.\" Dalam bab ini Ishaq berkata sebagaimana perkataan Imam Ahmad."},"366":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ سَعِيدِ بْنِ يَزِيدَ أَبِي مَسْلَمَةَ قَالَ قُلْتُ لِأَنَسِ بْنِ مَالِكٍأَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي نَعْلَيْهِ قَالَ نَعَمْقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَعَبْدِ اللَّهِ بْنِ أَبِي حَبِيبَةَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَعَمْرِو بْنِ حُرَيْثٍ وَشَدَّادِ بْنِ أَوْسٍ وَأَوْسٍ الثَّقَفِيِّ وَأَبِي هُرَيْرَةَ وَعَطَاءٍ رَجُلٍ مِنْ بَنِي شَيْبَةَ قَالَ أَبُو عِيسَى حَدِيثُ أَنَسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ","id":"Telah menceritakan kepada kami [Ali bin Hujr] berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Sa'id bin Yazid Abu Salamah] berkata; aku berkata kepada [Anas bin Malik], \"Apakah Rasulullah shallallahu 'alaihi wasallam pernah shalat dengan mengenakan dua sandal?\" ia menjawab, \"Ya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin Mas'ud, Abdullah bin Abu Habibah, Abdullah bin 'Amru dan 'Amru.\" Abu Isa berkata; \"Hadits Anas ini derajatnya hasan shahih. Dan hadits ini diamalkan oleh para ulama.\""},"367":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا غُنْدَرٌ مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْنُتُ فِي صَلَاةِ الصُّبْحِ وَالْمَغْرِبِقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَأَنَسٍ وَأَبِي هُرَيْرَةَ وَابْنِ عَبَّاسٍ وَخُفَافِ بْنِ أَيْمَاءَ بْنِ رَحْضَةَ الْغِفَارِيِّ قَالَ أَبُو عِيسَى حَدِيثُ الْبَرَاءِ حَدِيثٌ حَسَنٌ صَحِيحٌ وَاخْتَلَفَ أَهْلُ الْعِلْمِ فِي الْقُنُوتِ فِي صَلَاةِ الْفَجْرِ فَرَأَى بَعْضُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ��َغَيْرِهِمْ الْقُنُوتَ فِي صَلَاةِ الْفَجْرِ وَهُوَ قَوْلُ مَالِكٍ وَالشَّافِعِيِّ و قَالَ أَحْمَدُ وَإِسْحَقُ لَا يُقْنَتُ فِي الْفَجْرِ إِلَّا عِنْدَ نَازِلَةٍ تَنْزِلُ بِالْمُسْلِمِينَ فَإِذَا نَزَلَتْ نَازِلَةٌ فَلِلْإِمَامِ أَنْ يَدْعُوَ لِجُيُوشِ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Qutaibah] dan [Muhammad bin Al Mutsanna] keduanya berkata; telah menceritakan kepada kami [Ghundar Muhammad bin Ja'far] dari [Syu'bah] dari ['Amru bin Murrah] dari [Abdurrahman bin Abu Laila] dari [Al Bara` bin 'Azib] berkata; \"Nabi shallallahu 'alaihi wasallam melakukan qunut pada shalat subuh dan maghrib.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ali, Anas, Abu Hurairah, Ibnu Abbas dan Khaffaf bin Aima` bin Rahdlah Al Ghifari.\" Abu Isa berkata; \"Hadits Al Bara` derajatnya hasan shahih. Para ahli ilmu berselisih tentang qunut pada shalat subuh, sebagian ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan selainnya membolehkan qunut pada shalat subuh. Pendapat ini diambil oleh Imam Malik dan Syafi'i. Sedangkan Imam Ahmad dan Ishaq berkata; \"Tidak boleh melakukan qunut pada shalat subuh kecuali ketika terdapat bahaya yang menimpa kaum muslimin. Jika terjadi musibah yang menimpa kaum muslimin maka imam harus mendo`akan tentara kaum muslimin.\""},"368":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ أَبِي مَالِكٍ الْأَشْجَعِيِّ قَالَ قُلْتُ لِأَبِييَا أَبَةِ إِنَّكَ قَدْ صَلَّيْتَ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ وَعُثْمَانَ وَعَلِيِّ بْنِ أَبِي طَالِبٍ هَا هُنَا بِالْكُوفَةِ نَحْوًا مِنْ خَمْسِ سِنِينَ أَكَانُوا يَقْنُتُونَ قَالَ أَيْ بُنَيَّ مُحْدَثٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ و قَالَ سُفْيَانُ الثَّوْرِيُّ إِنْ قَنَتَ فِي الْفَجْرِ فَحَسَنٌ وَإِنْ لَمْ يَقْنُتْ فَحَسَنٌ وَاخْتَارَ أَنْ لَا يَقْنُتَ وَلَمْ يَرَ ابْنُ الْمُبَارَكِ الْقُنُوتَ فِي الْفَجْرِ قَالَ أَبُو عِيسَى وَأَبُو مَالِكٍ الْأَشْجَعِيُّ اسْمُهُ سَعْدُ بْنُ طَارِقِ بْنِ أَشْيَمَ حَدَّثَنَا صَالِحُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي مَالِكٍ الْأَشْجَعِيِّ بِهَذَا الْإِسْنَادِ نَحْوَهُ بِمَعْنَاهُ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Yazid bin Harun] dari [Abu Qilabah Al Asyja'i] ia berkata; \"Aku pernah bertanya kepada [ayahku], \"Wahai ayah, sesungguhnya engkau pernah shalat di belakang Rasulullah shallallahu 'alaihi wasallam, Abu Bakar, Umar, Utsman dan Ali di Kufah ini sekitar selama lima tahun, maka apakah mereka membaca qunut?\" ia menjawab, \"Wahai anakku, itu adalah perkara baru.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Dan hadits ini diamalkan oleh banyak ulama. Sufyan Ats Tsauri berkata; \"Jika seseorang melakukan qunut dalam shalat subuh maka itu baik, jika tidak maka itu juga baik.\" Dan Sufyan Ats Tsauri memilih untuk tidak melakukan qunut. Demikian juga Ibnu Al Mubarak, ia tidak melakukan qunut dalam shalat subuh.\" Abu Isa berkata; \"Abu Malik Al Asyja'i namanya adalah Sa'd bin Thariq bin Asyyam. Telah menceritakan kepada kami [Shalih bin Abdullah] berkata; telah menceritakan kepada kami [Abu Awanah] dari [Abu Malik Al Asyja'i] seperti makna hadits tersebut dengan sanad ini.\""},"369":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا رِفَاعَةُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ رِفَاعَةَ بْنِ رَافِعٍ الزُّرَقِيُّ عَنْ عَمِّ أَبِيهِ مُعَاذِ بْنِ رِفَاعَةَ عَنْ أَبِيهِ قَالَصَلَّيْتُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَطَسْتُ فَقُلْتُ الْحَمْدُ لِلَّهِ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ مُبَارَكًا عَلَيْهِ كَمَا يُحِبُّ رَبُّنَا وَيَرْضَى فَلَمَّا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصَرَفَ فَقَالَ مَنْ الْمُتَكَلِّمُ فِي الصَّلَاةِ فَلَمْ يَتَكَلَّمْ أَحَدٌ ثُمَّ قَالَهَا الثَّانِيَةَ مَنْ الْمُتَكَلِّمُ فِي الصَّلَاةِ فَلَمْ يَتَكَلَّمْ أَحَدٌ ثُمَّ قَالَهَا الثَّالِثَةَ مَنْ الْمُتَكَلِّمُ فِي الصَّلَاةِ فَقَالَ رِفَاعَةُ بْنُ رَافِعٍ ابْنُ عَفْرَاءَ أَنَا يَا رَسُولَ اللَّهِ قَالَ كَيْفَ قُلْتَ قَالَ قُلْتُ الْحَمْدُ لِلَّهِ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ مُبَارَكًا عَلَيْهِ كَمَا يُحِبُّ رَبُّنَا وَيَرْضَى فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَقَدْ ابْتَدَرَهَا بِضْعَةٌ وَثَلَاثُونَ مَلَكًا أَيُّهُمْ يَصْعَدُ بِهَاقَالَ وَفِي الْبَاب عَنْ أَنَسٍ وَوَائِلِ بْنِ حُجْرٍ وَعَامِرِ بْنِ رَبِيعَةَ قَالَ أَبُو عِيسَى حَدِيثُ رِفَاعَةَ حَدِيثٌ حَسَنٌ وَكَأَنَّ هَذَا الْحَدِيثَ عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ أَنَّهُ فِي التَّطَوُّعِ لِأَنَّ غَيْرَ وَاحِدٍ مِنْ التَّابِعِينَ قَالُوا إِذَا عَطَسَ الرَّجُلُ فِي الصَّلَاةِ الْمَكْتُوبَةِ إِنَّمَا يَحْمَدُ اللَّهَ فِي نَفْسِهِ وَلَمْ يُوَسِّعُوا فِي أَكْثَرَ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Rifa'ah bin Yahya bin Abdullah bin Rifa'ah Az Zuraqi] dari paman ayahnya [Mu'adz bin Rifa'ah] dari [Ayahnya] ia berkata; \"Aku pernah shalat di belakang Rasulullah shallallahu 'alaihi wasallam lalu aku bersin dan mengucapkan, \"ALHAMDULILAAHI HAMDAN KATSIRAN THAYYIBAN MUBARAKAN FIHI, MUBARAKAN 'ALAIHI KAMA YUHIBBU RABBUNA WA YARDLA (Segala puji bagi Allah dengan pujian yang banyak, baik, diberkahi di dalamnya serta diberkahi di atasnya, sebagimana Rabb kami senang dan ridla).\" Maka ketika Rasulullah shallallahu 'alaihi wasallam selesai shalat, beliau berpaling ke arah kami seraya bersabda: \"Siapa yang berbicara waktu shalat?\" tidak ada seorang pun yang menjawab, beliau lalu bertanya lagi untuk yang kedua kalinya; \"Siapa yang berbicara dalam shalat?\" tidak ada seorang pun yang menjawab, beliau lalu bertanya untuk yang ketiga kalinya: \"Siapa yang berbicara waktu shalat?\" maka Rifa'ah bin Rafi' bin Afra` menjawab, \"Saya wahai Rasulullah, \" beliau bersabda: \"Apa yang engkau ucapkan tadi?\" Rifa'ah lalu menjawab, \"Saya mengucapkan; ALHAMDULILAAHI HAMDAN KATSIRAN THAYYIBAN MUBARAKAN FIHI, MUBARAKAN 'ALAIHI KAMA YUHIBBU RABBUNA WA YARDLA (Segala puji bagi Allah dengan pujian yang banyak, baik, diberkahi di dalamnya serta diberkahi di atasnya, sebagimana Rabb kami senang dan ridla).\" Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Demi Dzat yang jiwaku ada dalam tangan-Nya, sungguh ada tiga puluh lebih malaikat saling berebut untuk membawa naik kalimat tersebut.\""},"370":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ الْحَارِثِ بْنِ شُبَيْلٍ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَكُنَّا نَتَكَلَّمُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّلَاةِ يُكَلِّمُ الرَّجُلُ مِنَّا صَاحِبَهُ إِلَى جَنْبِهِ حَتَّى نَزَلَتْ{ وَقُومُوا لِلَّهِ قَانِتِينَ }فَأُمِرْنَا بِالسُّكُوتِ وَنُهِينَا عَنْ الْكَلَامِقَالَ وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَمُعَاوِيَةَ بْنِ الْحَكَمِ قَالَ أَبُو عِيسَى حَدِيثُ زَيْدِ بْنِ أَرْقَمَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ قَالُوا إِذَا تَكَلَّمَ الرَّجُلُ عَامِدًا فِي الصَّلَاةِ أَوْ نَاسِيًا أَعَادَ الصَّلَاةَ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَابْنِ الْمُبَارَكِ وَأَهْلِ الْكُوفَةِ و قَالَ بَعْضُهُمْ إِذَا تَكَلَّمَ عَامِدًا فِي الصَّلَاةِ أَعَادَ الصَّلَاةَ وَإِنْ كَانَ نَاسِيًا أَوْ جَاهِلًا أَجْزَأَهُ وَبِهِ يَقُولُ الشَّافِعِيُّ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Husyaim] berkata; telah mengabarkan kepada kami [Isma'il bin Abu Khalid] dari [Al Harits bin Syubail] dari [Abu Amru Asy Syaibani] dari [Zaid bin Arqam] ia berkata; \"Kami berbincang-bincang di belakang Rasulullah shallallahu 'alaihi wasallam ketika shalat. Seorang dari kami berbicara dengan teman yang ada di sisinya, hingga akhirnya turunlah ayat: (Dan berdirilah untuk Allah dalam shalatmu dengan khusyu'). Lalu kami diperintahkan untuk diam dan dilarang untuk berbicara (dalam shalat).\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Mas'ud dan Mu'awiyah bin Al Hakam.\" Abu Isa berkata; \"Hadits Zaid bin Arqam derajatnya hasan shahih. Banyak ahli ilmu yang mengamalkan hadits ini, mereka mengatakan, \"Jika ada seseorang yang berbicara dalam shalat dengan sengaja atau karena lupa, maka ia harus mengulangi shalatnya.\" Pendapat ini diambil oleh Sufyan Ats Tsauri, bin Al Mubarak dan penduduk Kufah. Dan sebagian mereka mengatakan, \"Jika seseorang berbicar dalam shalat dengan sengaja maka ia harus mengulangui shalatnya, namun jika ia berbicara karena lupa atau bodoh maka shalatnya telah cukup (tidak perlu mengulanginya).\" Pendapat ini diambil oleh Imam Syafi'i."},"371":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ عَنْ عَلِيِّ بْنِ رَبِيعَةَ عَنْ أَسْمَاءَ بْنِ الْحَكَمِ الْفَزَارِيِّ قَال سَمِعْتُ عَلِيًّا يَقُولُإِنِّي كُنْتُ رَجُلًا إِذَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا نَفَعَنِي اللَّهُ مِنْهُ بِمَا شَاءَ أَنْ يَنْفَعَنِي بِهِ وَإِذَا حَدَّثَنِي رَجُلٌ مِنْ أَصْحَابِهِ اسْتَحْلَفْتُهُ فَإِذَا حَلَفَ لِي صَدَّقْتُهُ وَإِنَّهُ حَدَّثَنِي أَبُو بَكْرٍ وَصَدَقَ أَبُو بَكْرٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ رَجُلٍ يُذْنِبُ ذَنْبًا ثُمَّ يَقُومُ فَيَتَطَهَّرُ ثُمَّ يُصَلِّي ثُمَّ يَسْتَغْفِرُ اللَّهَ إِلَّا غَفَرَ اللَّهُ لَهُ ثُمَّ قَرَأَ هَذِهِ الْآيَةَ{ وَالَّذِينَ إِذَا فَعَلُوا فَاحِشَةً أَوْ ظَلَمُوا أَنْفُسَهُمْ ذَكَرُوا اللَّهَ فَاسْتَغْفَرُوا لِذُنُوبِهِمْ }إِلَى آخِرِ الْآيَةِقَالَ وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَأَبِي الدَّرْدَاءِ وَأَنَسٍ وَأَبِي أُمَامَةَ وَمُعَاذٍ وَوَاثِلَةَ وَأَبِي الْيَسَرِ وَاسْمُهُ كَعْبُ بْنُ عَمْرٍو قَالَ أَبُو عِيسَى حَدِيثُ عَلِيٍّ حَدِيثٌ حَسَنٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ عُثْمَانَ بْنِ الْمُغِيرَةِ وَرَوَى عَنْهُ شُعْبَةُ وَغَيْرُ وَاحِدٍ فَرَفَعُوهُ مِثْلَ حَدِيثِ أَبِي عَوَانَةَ وَرَوَاهُ سُفْيَانُ الثَّوْرِيُّ وَمِسْعَرٌ فَأَوْقَفَاهُ وَلَمْ يَرْفَعَاهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ رُوِيَ عَنْ مِسْعَرٍ هَذَا الْحَدِيثُ مَرْفُوعًا أَيْضًا وَلَا نَعْرِفُ لِأَسْمَاءَ بْنِ الْحَكَمِ حَدِيثًا مَرْفُوعًا إِلَّا هَذَا","id":"Telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abu Awanah] dari [Utsman bin Al Mughirah] dari [Ali bin Rabi'ah] dari [Asma` bin Al Hakam Al Fazari] ia berkata; \"Aku mendengar [Ali] berkata; \"Sesungguhnya aku adalah seorang laki-laki yang jika aku mendengar hadits dari Rasulullah shallallahu 'alaihi wasallam, maka dengannya Allah memberiku manfaat dengan sekehendak Allah memberiku manfaat. Dan jika ada seorang dari sahabat Rasulullah menceritakan kepadaku sebuah hadits, maka aku memintanya untuk bersumpah, jika ia telah bersumpah maka aku mempercayainya. [Abu Bakar] -ia adalah seorang yang jujur- pernah menceritakan kepadaku, ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang laki-laki melakukan perbuatan dosa, kemudian ia berdiri bersuci dan shalat, lalu ia meminta ampun kepada Allah kecuali Allah pasti akan mengampuninya.\" Kemudian beliau membaca ayat ini: (Dan (juga) orang-orang yang apabila mengerjakan perbuatan keji atau menganiaya diri sendiri, mereka ingat akan Allah, lalu memohon ampun terhadap dosa-dosa mereka) hingga akhir ayat.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Mas'ud, Abu Darda`, Anas, Abu Umamah, Mu'adz dan Watsilah. Abu Al Yasar namnya adalah Ka'ab bin Amru.\" Abu Isa berkata; \"Hadits Ali derajatnya hasan, dan kami tidak mengetahuinya dari jalur ini kecuali dari hadits Utsman bin Al Mughirah. [Syu'bah] dan yang selainnya meriwayatkan hadits ini dari [Utsman bin Al Mughrah], lalu mereka memarfu'kannya sebagaimana hadits Abu Awanah. [Sufyan Ats Tsauri] dan [Mis'ar] juga menceritakannya, namun keduanya hanya menceritakan secara mauquf dan tidak memarfu'kannya kepada Nabi shallallahu 'alaihi wasallam. Dan hadits ini juga pernah diriwayatkan dari Mis'ar secara marfu', dan kami tidak pernah mengetahui Asma` bin Al Hakam mempunyai hadits marfu' selain hadits ini.\""},"372":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا حَرْمَلَةُ بْنُ عَبْدِ الْعَزِيزِ بْنِ الرَّبِيعِ بْنِ سَبْرَةَ الْجُهَنِيُّ عَنْ عَمِّهِ عَبْدِ الْمَلِكِ بْنِ الرَّبِيعِ بْنِ سَبْرَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِّمُوا الصَّبِيَّ الصَّلَاةَ ابْنَ سَبْعِ سِنِينَ وَاضْرِبُوهُ عَلَيْهَا ابْنَ عَشْرٍقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى حَدِيثُ سَبْرَةَ بْنِ مَعْبَدٍ الْجُهَنِيِّ حَدِيثٌ حَسَنٌ صَحِيحٌ وَعَلَيْهِ الْعَمَلُ عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ وَقَالَا مَا تَرَكَ الْغُلَامُ بَعْدَ الْعَشْرِ مِنْ الصَّلَاةِ فَإِنَّهُ يُعِيدُ قَالَ أَبُو عِيسَى وَسَبْرَةُ هُوَ ابْنُ مَعْبَدٍ الْجُهَنِيُّ وَيُقَالُ هُوَ ابْنُ عَوْسَجَةَ","id":"Telah menceritakan kepada kami [Ali bin Hujr] berkata; telah mengabarkan kepada kami [Harmalah bin Abdul Aziz bin Ar Rabi' bin Syabrah Al Juhani] dari [Abdul Malik bin Ar Rabi' bin Sabrah] dari [Ayahnya] dari [Kakeknya] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ajarkanlah shalat kepada anak-anak diumur tujuh tahun, dan pukullah mereka ketika meninggalkan shalat di umur sepuluh tahun.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin 'Amru.\" Abu Isa berkata; \"Hadits Sabrah bin Ma'bad Al Juhani derajatnya hasan shahih.\" Sebagian ahli ilmu mengamalkan hadits ini. Dan pendapat inilah yang diambil oleh Ahmad dan Ishaq. Keduanya berkata; \"Shalat yang ditinggalkan oleh anak yang telah berumur sepuluh tahun, maka ia harus mengulanginya.\" Abu Isa berkata; \"Sabrah adalah Ibnu Ma'bad Al Juhani, ia disebut juga dengan nama Ibnu Ausajah.\""},"373":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ مُوسَى الْمُلَقَّبُ مَرْدُوَيْهِ قَالَ أَخْبَرَنَا ابْنُ الْمُبَارَكِ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ زِيَادِ بْنِ أَنْعُمٍ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ رَافِعٍ وَبَكْرَ بْنَ سَوَادَةَ أَخْبَرَاهُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَحْدَثَ يَعْنِي الرَّجُلَ وَقَدْ جَلَسَ فِي آخِرِ صَلَاتِهِ قَبْلَ أَنْ يُسَلِّمَ فَقَدْ جَازَتْ صَلَاتُهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ إِسْنَادُهُ لَيْسَ بِذَاكَ الْقَوِيِّ وَقَدْ اضْطَرَبُوا فِي إِسْنَادِهِ وَقَدْ ذَهَبَ بَعْضُ أَهْلِ الْعِلْمِ إِلَى هَذَا قَالُوا إِذَا جَلَسَ مِقْدَارَ التَّشَهُّدِ وَأَحْدَثَ قَبْلَ أَنْ يُسَلِّمَ فَقَدْ تَمَّتْ صَلَاتُهُ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ إِذَا أَحْدَثَ قَبْلَ أَنْ يَتَشَهَّدَ وَقَبْلَ أَنْ يُسَلِّمَ أَعَادَ الصَّلَاةَ وَهُوَ قَوْلُ الشَّافِعِيِّ و قَالَ أَحْمَدُ إِذَا لَمْ يَتَشَهَّدْ وَسَلَّمَ أَجْزَأَهُ لِقَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَحْلِيلُهَا التَّسْلِيمُ وَالتَّشَهُّدُ أَهْوَنُ قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي اثْنَتَيْنِ فَمَضَى فِي صَلَاتِهِ وَلَمْ يَتَشَهَّدْ و قَالَ إِسْحَقُ بْنُ إِبْرَاهِيمَ إِذَا تَشَهَّدَ وَلَمْ يُسَلِّمْ أَجْزَأَهُ وَاحْتَجَّ بِحَدِيثِ ابْنِ مَسْعُودٍ حِينَ عَلَّمَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّشَهُّدَ فَقَالَ إِذَا فَرَغْتَ مِنْ هَذَا فَقَدْ قَضَيْتَ مَا عَلَيْكَ قَالَ أَبُو عِيسَى وَعَبْدُ الرَّحْمَنِ بْنُ زِيَادِ بْنِ أَنْعُمٍ هُوَ الْأَفْرِيقِيُّ وَقَدْ ضَعَّفَهُ بَعْضُ أَهْلِ الْحَدِيثِ مِنْهُمْ يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ وَأَحْمَدُ بْنُ حَنْبَلٍ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Musa Al Mulaqqab Marduwaih] berkata; telah mengabarkan kepada kami [Ibnu Al Mubarak] berkata; telah mengabarkan kepada kami [Abdurrahman bin Ziyad bin An'um] bahwa [Abdurrahman bin Rafi'] dan [Bakr bin Sawadah] keduanya mengabarkan kepadanya, dari [Abdullah bin 'Amru] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila berhadats, yakni seorang laki-laki, sedangkan ia telah duduk diakhir shalatnya sebelum salam, maka shalatnya telah sah.\" Abu Isa berkata; \"Hadits ini sanadnya tidak begitu kuat, dan dalam sanadnya terjadi ketidak beresan. Sebagian ulama berpegangan dengan hadits ini, mereka berkata; \"Jika seseorang telah duduk sekadar duduk tasyahud kemudian berhadats sebelum salam, maka shalatnya sah.\" Sedangkan sebagian yang lain berkata; \"Jika ia berhadats sebelum tasyahud dan juga sebelum salam, maka ia harus mengulangi shalatnya.\" Ini adalah pendapat yang diambil oleh Imam Syafi'i. Imam Ahmad berkata; \"Jika seseorang belum bertasyahud kemudian salam maka shalat sah, hal ini sebagimana sabda Nabi shallallahu 'alaihi wasallam, \"(Shalat) penghalalannya adalah salam.\" Sedangkan tasyahud itu lebih ringan, sebab Nabi shallallahu 'alaihi wasallam pernah berdiri pada rakaat kedua dan beliau tetap melanjutkan shalatnya meskipun tidak bertasyahud.\" Sedangkan Imam Ishaq bin Ibrahim berkata; \"Jika seseorang bertasyahud kemudian salam maka shalatnya sah, \" Ishaq berdalil dengan hadits Ibnu Mas'ud ketika ia diajari tasyahud oleh Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika engkau telah selesai dari melakukan ini (tasyahud), maka telah selesailah apa yang menjadi kewajibanmu.\" Abu Isa berkata; \"Abdurrahman bin Ziyad bin An'um adalah Al Afriqi, dan ia telah dilemahkan oleh sebagian ahli hadits seperti Yahya bin Sa'id Al Qaththan dan Ahmad bin Hanbal."},"374":{"ar":"حَدَّثَنَا أَبُو حَفْصٍ عَمْرُو بْنُ عَلِيٍّ الْبَصْرِيُّ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا زُهَيْرُ بْنُ مُعَاوِيَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَأَصَابَنَا مَطَرٌ فَقَالَ النَّبِيُّ صَلَّ�� اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَاءَ فَلْيُصَلِّ فِي رَحْلِهِقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَسَمُرَةَ وَأَبِي الْمَلِيحِ عَنْ أَبِيهِ وَعَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ قَالَ أَبُو عِيسَى حَدِيثُ جَابِرٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَخَّصَ أَهْلُ الْعِلْمِ فِي الْقُعُودِ عَنْ الْجَمَاعَةِ فِي الْمَطَرِ وَالطِّينِ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ قَالَ أَبُو عِيسَى سَمِعْت أَبَا زُرْعَةَ يَقُولُ رَوَى عَفَّانُ بْنُ مُسْلِمٍ عَنْ عَمْرِو بْنِ عَلِيٍّ حَدِيثًا و قَالَ أَبُو زُرْعَةَ لَمْ نَرَ بِالْبَصْرَةِ أَحْفَظَ مِنْ هَؤُلَاءِ الثَّلَاثَةِ عَلِيِّ بْنِ الْمَدِينِيِّ وَابْنِ الشَّاذَكُونِيِّ وَعَمْرِو بْنِ عَلِيٍّ وَأَبُو الْمَلِيحِ اسْمُهُ عَامِرٌ وَيُقَالُ زَيْدُ بْنُ أُسَامَةَ بْنِ عُمَيْرٍ الْهُذَلِيُّ","id":"Telah menceritakan kepada kami [Abu Hafsh Amru bin Ali Al Bashri] berkata; telah menceritakan kepada kami [Abu Dawud Ath Thayalisi] berkata; telah menceritakan kepada kami [Zuhair bin Mu'awiyah] dari [Abu Az Zubair] dari [Jabir] ia berkata; \"Kami pernah bersama Nabi shallallahu 'alaihi wasallam dalam sebuah perjalanan kemudian kami kehujanan. Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Barangsiapa yang berkehendak ia boleh shalat di dalam tendanya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Umar, Samrah, Abu Al Malih dari ayahnya, dan Abdurrahman bin Samrah.\" Abu Isa berkata; \"Aku mendengar Abu Zur'ah berkata; \"Affan bin Muslim meriwayatkan dari 'Amru bin Ali sebuah hadits.\" Abu Zur'ah berkata; \"Di Bashrah kami belum pernah melihat orang yang lebih banyak hafalannya; Ali bin Al Madini, Ibnu Asy Syadzakuni dan 'Amru bin Ali.\" Abu Al Malih namanya adalah Amir, dan disebut juga dengan nama Zaid bin Usamah bin Umair Al Hudzali.\""},"375":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ حَبِيبِ بْنِ الشَّهِيدِ الْبَصْرِيُّ وَعَلِيُّ بْنُ حُجْرٍ قَالَا حَدَّثَنَا عَتَّابُ بْنُ بَشِيرٍ عَنْ خُصَيْفٍ عَنْ مُجَاهِدٍ وَعِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ الْفُقَرَاءُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّ الْأَغْنِيَاءَ يُصَلُّونَ كَمَا نُصَلِّي وَيَصُومُونَ كَمَا نَصُومُ وَلَهُمْ أَمْوَالٌ يُعْتِقُونَ وَيَتَصَدَّقُونَ قَالَ فَإِذَا صَلَّيْتُمْ فَقُولُوا سُبْحَانَ اللَّهِ ثَلَاثًا وَثَلَاثِينَ مَرَّةً وَالْحَمْدُ لِلَّهِ ثَلَاثًا وَثَلَاثِينَ مَرَّةً وَاللَّهُ أَكْبَرُ أَرْبَعًا وَثَلَاثِينَ مَرَّةً وَلَا إِلَهَ إِلَّا اللَّهُ عَشْرَ مَرَّاتٍ فَإِنَّكُمْ تُدْرِكُونَ بِهِ مَنْ سَبَقَكُمْ وَلَا يَسْبِقُكُمْ مَنْ بَعْدَكُمْقَالَ وَفِي الْبَاب عَنْ كَعْبِ بْنِ عُجْرَةَ وَأَنَسٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَزَيْدِ بْنِ ثَابِتٍ وَأَبِي الدَّرْدَاءِ وَابْنِ عُمَرَ وَأَبِي ذَرٍّ قَالَ أَبُو عِيسَى وَحَدِيثُ ابْنِ عَبَّاسٍ حَدِيثٌ حَسَنٌ غَرِيبٌ وَفِي الْبَاب أَيْضًا عَنْ أَبِي هُرَيْرَةَ وَالْمُغِيرَةِ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ خَصْلَتَانِ لَا يُحْصِيهِمَا رَجُلٌ مُسْلِمٌ إِلَّا دَخَلَ الْجَنَّةَ يُسَبِّحُ اللَّهَ فِي دُبُرِ كُلِّ صَلَاةٍ عَشْرًا وَيَحْمَدُهُ عَشْرًا وَيُكَبِّرُهُ عَشْرًا وَيُسَبِّحُ اللَّهَ عِنْدَ مَنَامِهِ ثَلَاثًا وَثَلَاثِينَ وَيَحْمَدُهُ ثَلَاثًا وَثَلَاثِينَ وَيُكَبِّرُهُ أَرْبَعًا وَثَلَاثِينَ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim bin Habib bin Asy Syahid Al Bashri] dan [Ali bin Hujr] keduanya berkata; telah menceritakan kepada kami ['Attab bin Basyir] dari [Khushaif] dari [Mujahid] dan [Ikrimah] dari [Ibnu Abbas] ia berkata; \"Orang-orang fakir datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; \"Wahai Rasulullah, orang-orang kaya shalat dan puasa sebagaimana kami shalat dan puasa, dan mereka mempunyai harta yang bisa mereka gunakan untuk membebaskan budak dan bersedekah!\" beliau bersabda: \"Jika kalian shalat maka ucapkanlah; SUBHAANAALLAH tiga puluh tiga kali, ALHAMDULILLAH tiga puluh tiga kali, ALLAHU AKBAR tiga puluh empat kali dan LAA ILAAHA ILLAALLAHU sepuluh kali. Kalian akan dapat mengungguli orang-orang sebelum kalian dan tidak akan diungguli oleh orang-orang sesudah kalian.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ka'ab bin Ujrah, Anas, Abdullah bin Amru, Zaid bin Tsabit, Abu Darda`, Ibnu Umar dan Abu Dzar.\" Abu Isa berkata; \"Hadits Ibnu Abbas derajatnya hasan gharib. Dan dalam bab ini juga ada riwayat dari Abu Hurairah dan Al Mughirah. Diriwayatkan dari Nabi shallallahu 'alaihi wasallam bahwasanya beliau bersabda: \"Dua hal, tidaklah seorang muslim menghitungnya kecuali akan masuk ke surga; bertasbih kepada Allah setiap selesai shalat sebanyak sepuluh kali, memuji Allah (tahmid) sepuluh kali dan bertakbir sepuluh kali. Dan bertasbih menjelang tidur sebanyak tiga puluh tiga kali, tahmid tiga puluh tiga kali dan takbir tiga puluh empat kali.\""},"376":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا شَبَابَةُ بْنُ سَوَّارٍ حَدَّثَنَا عُمَرُ بْنُ الرَّمَّاحِ الْبَلْخِيُّ عَنْ كَثِيرِ بْنِ زِيَادٍ عَنْ عَمْرِو بْنِ عُثْمَانَ بْنِ يَعْلَى بْنِ مُرَّةَ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّهُمْ كَانُوا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَسِيرٍ فَانْتَهَوْا إِلَى مَضِيقٍ وَحَضَرَتْ الصَّلَاةُ فَمُطِرُوا السَّمَاءُ مِنْ فَوْقِهِمْ وَالْبِلَّةُ مِنْ أَسْفَلَ مِنْهُمْ فَأَذَّنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى رَاحِلَتِهِ وَأَقَامَ أَوْ أَقَامَ فَتَقَدَّمَ عَلَى رَاحِلَتِهِ فَصَلَّى بِهِمْ يُومِئُ إِيمَاءً يَجْعَلُ السُّجُودَ أَخْفَضَ مِنْ الرُّكُوعِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ تَفَرَّدَ بِهِ عُمَرُ بْنُ الرَّمَّاحِ الْبَلْخِيُّ لَا يُعْرَفُ إِلَّا مِنْ حَدِيثِهِ وَقَدْ رَوَى عَنْهُ غَيْرُ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ وَكَذَلِكَ رُوِيَ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ صَلَّى فِي مَاءٍ وَطِينٍ عَلَى دَابَّتِهِ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ","id":"Telah menceritakan kepada kami [Yahya bin Musa] berkata; telah menceritakan kepada kami [Syababah bin Sawwar] berkata; telah menceritakan kepada kami [Umar bin Ar Rammah Al bakhil] dari [Katsir bin Ziyad] dari [Amru bin Utsman bin Ya'la bin Murrah] dari [Ayahnya] dari [Kakeknya] bahwasanya mereka bersama Nabi shallallahu 'alaihi wasallam dalam sebuah perjalanan, hingga sampailah mereka pada jalan sempit, lalu waktu shalat tiba sedangkan langit dalam keadaan hujan dan kondisi tanah tergenang air. Rasulullah shallallahu 'alaihi wasallam kemudian adzan di atas kendaraannya, lalu beliau iqamah dan maju ke depan. Setelah itu beliau shalat bersama para sahabat dengan merunduk, beliau menjadikan sujud lebih rendah dari rukuk.\" Abu Isa berkata; \"Hadits ini derajatnya hasan gharib. Umar bin Ar Ramman Al Bakhil meriwayatkan hadits ini secara sendirian, tidak diketahui ada hadits lain kecuali dari haditsnya, dan tidak hanya satu orang ulama yang meriwayatkan darinya. Demikian juga telah diriwayatkan dari Anas bin Malik, Bahwasanya ia pernah shalat di atas kendaraannya di tanah yang becek. Hadits ini diamalkan oleh para ulama, dan pendapat ini diambil pula oleh Ahmad dan Ishaq.\""},"377":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَبِشْرُ بْنُ مُعَاذٍ الْعَقَدِيُّ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى انْتَفَخَتْ قَدَمَاهُ فَقِيلَ لَهُ أَتَتَكَلَّفُ هَذَا وَقَدْ غُفِرَ لَكَ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ قَالَ أَفَلَا أَكُونُ عَبْدًا شَكُورًاقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَعَائِشَةَ قَالَ أَبُو عِيسَى حَدِيثُ الْمُغِيرَةِ بْنِ شُعْبَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] dan [Bisyr bin Mu'adz Al Aqadi] keduanya berkata; telah menceritakan kepada kami [Abu Awanah] dari [Ziyad bin Iqalah] dari [Al Mughirah bin Syu'bah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat hingga kedua kakinya bengkak, lalu dikatakan kepada beliau, \"Kenapa tuan memperberat diri, padahal dosa-dosamu yang lalu dan yang akan datang telah diampuni?\" beliau bersabda: \"Tidak sukakah bila aku menjadi orang yang bersyukur?\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Abu Hurairah dan 'Aisyah.\" Abu Isa berkata; \"Hadits Al Mughirah bin Syu'bah derajatnya hasan shahih.\""},"378":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ نَصْرِ بْنِ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا هَمَّامٌ قَالَ حَدَّثَنِي قَتَادَةُ عَنْ الْحَسَنِ عَنْ حُرَيْثِ بْنِ قَبِيصَةَ قَالَقَدِمْتُ الْمَدِينَةَ فَقُلْتُ اللَّهُمَّ يَسِّرْ لِي جَلِيسًا صَالِحًا قَالَ فَجَلَسْتُ إِلَى أَبِي هُرَيْرَةَ فَقُلْتُ إِنِّي سَأَلْتُ اللَّهَ أَنْ يَرْزُقَنِي جَلِيسًا صَالِحًا فَحَدِّثْنِي بِحَدِيثٍ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّ اللَّهَ أَنْ يَنْفَعَنِي بِهِ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أَوَّلَ مَا يُحَاسَبُ بِهِ الْعَبْدُ يَوْمَ الْقِيَامَةِ مِنْ عَمَلِهِ صَلَاتُهُ فَإِنْ صَلُحَتْ فَقَدْ أَفْلَحَ وَأَنْجَحَ وَإِنْ فَسَدَتْ فَقَدْ خَابَ وَخَسِرَ فَإِنْ انْتَقَصَ مِنْ فَرِيضَتِهِ شَيْءٌ قَالَ الرَّبُّ عَزَّ وَجَلَّ انْظُرُوا هَلْ لِعَبْدِي مِنْ تَطَوُّعٍ فَيُكَمَّلَ بِهَا مَا انْتَقَصَ مِنْ الْفَرِيضَةِ ثُمَّ يَكُونُ سَائِرُ عَمَلِهِ عَلَى ذَلِكَقَالَ وَفِي الْبَاب عَنْ تَمِيمٍ الدَّارِيِّ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ هَذَا الْوَجْهِ عَنْ أَبِي هُرَيْرَةَ وَقَدْ رَوَى بَعْضُ أَصْحَابِ الْحَسَنِ عَنْ الْحَسَنِ عَنْ قَبِيصَةَ بْنِ حُرَيْثٍ غَيْرَ هَذَا الْحَدِيثِ وَالْمَشْهُورُ هُوَ قَبِيصَةُ بْنُ حُرَيْثٍ وَرُوِي عَنْ أَنَسِ بْنِ حَكِيمٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوُ هَذَا","id":"Telah menceritakan kepada kami [Ali bin Nashr bin Ali Al Jahdlami] berkata; telah menceritakan kepada kami [Sahl bin Hammad] berkata; telah menceritakan kepada kami [Hammam] berkata; telah menceritakan kepadaku [Qatadah] dari [Al Hasan] dari [Huraits bin Qabishah] ia berkata; \"Aku datang ke Madinah, lalu aku berdo`a, \"Ya Allah, mudahkanlah aku untuk mendapat teman shalih.\" Huraits bin Qabishah berkata; \"Lalu aku berteman dengan [Abu Hurairah], aku kemudian berkata kepadanya, \"Sesungguhnya aku telah memintah kepada Allah agar memberiku rizki seorang teman yang shalih, maka bacakanlah kepadaku hadits yang pernah engkau dengar dari Rasulullah shallallahu 'alaihi wasallam, semoga dengannya Allah memberiku manfaat.\" Maka Abu Hurairah pun berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari kiamat pertama kali yang akan Allah hisab atas amalan seorang hamba adalah shalatnya, jika shalatnya baik maka ia akan beruntung dan selamat, jika shalatnya rusak maka ia akan rugi dan tidak beruntung. Jika pada amalan fardlunya ada yang kurang maka Rabb 'azza wajalla berfirman: \"Periksalah, apakah hamba-Ku mempunyai ibadah sunnah yang bisa menyempurnakan ibadah wajibnya yang kurang?\" lalu setiap amal akan diperlakukan seperti itu.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Tamim Ad Dari.\" Abu Isa berkata; \"Hadits Abu Hurairah derajatnya hasan gharib dari sisi ini. Hadits ini telah diriwayatkan juga dari Abu Hurairah dengan jalur lain. Sebagian sahabat Al Hasan juga telah meriwayatkan hadits lain dari Al Hasan, dari Qabishah bin Huraits. Dan yang lebih terkenal adalah Qabishah bin Huraits. Hadits seperti ini juga pernah diriwayatkan dari [Anas bin Hakim] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam.\""},"379":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ النَّيْسَابُورِيُّ حَدَّثَنَا إِسْحَقُ بْنُ سُلَيْمَانَ الرَّازِيُّ حَدَّثَنَا الْمُغِيرَةُ بْنُ زِيَادٍ عَنْ عَطَاءٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ثَابَرَ عَلَى ثِنْتَيْ عَشْرَةَ رَكْعَةً مِنْ السُّنَّةِ بَنَى اللَّهُ لَهُ بَيْتًا فِي الْج��نَّةِ أَرْبَعِ رَكَعَاتٍ قَبْلَ الظُّهْرِ وَرَكْعَتَيْنِ بَعْدَهَا وَرَكْعَتَيْنِ بَعْدَ الْمَغْرِبِ وَرَكْعَتَيْنِ بَعْدَ الْعِشَاءِ وَرَكْعَتَيْنِ قَبْلَ الْفَجْرِقَالَ وَفِي الْبَاب عَنْ أُمِّ حَبِيبَةَ وَأَبِي هُرَيْرَةَ وَأَبِي مُوسَى وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَمُغِيرَةُ بْنُ زِيَادٍ قَدْ تَكَلَّمَ فِيهِ بَعْضُ أَهْلِ الْعِلْمِ مِنْ قِبَلِ حِفْظِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi' An Naisaburi] berkata; telah menceritakan kepada kami [Ishaq bin Sulaiman Ar Razi] berkata; telah menceritakan kepadaku [Al Mughirah bin Ziyad] dari ['Atha`] dari ['Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjaga dalam mengerjakan shalat sunnah dua belas rakaat, maka Allah akan membangunkan rumah untuknya di surga, yaitu empat rakaat sebelum zhuhur, dua rakaat setelah zhuhur, dua rakaat setelah maghrib, dua rakaat setelah isya` dan dua rakaat sebelum subuh.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ummu Habibah, Abu Hurairah, Abu Musa dan Ibnu Umar.\" Abu Isa berkata; \"Hadits 'Aisyah derajatnya hasan gharib dari sisi ini, sedangkan Mughirah bin Ziyad telah diperbincangkan oleh para ulama dari sisi hafalannya.\""},"380":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا مُؤَمَّلٌ هُوَ ابْنُ إِسْمَعِيلَ حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ أَبِي إِسْحَقَ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُمِّ حَبِيبَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى فِي يَوْمٍ وَلَيْلَةٍ ثِنْتَيْ عَشْرَةَ رَكْعَةً بُنِيَ لَهُ بَيْتٌ فِي الْجَنَّةِ أَرْبَعًا قَبْلَ الظُّهْرِ وَرَكْعَتَيْنِ بَعْدَهَا وَرَكْعَتَيْنِ بَعْدَ الْمَغْرِبِ وَرَكْعَتَيْنِ بَعْدَ الْعِشَاءِ وَرَكْعَتَيْنِ قَبْلَ صَلَاةِ الْفَجْرِقَالَ أَبُو عِيسَى وَحَدِيثُ عَنْبَسَةَ عَنْ أُمِّ حَبِيبَةَ فِي هَذَا الْبَابِ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ عَنْبَسَةَ مِنْ غَيْرِ وَجْهٍ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Mu`ammal] -yaitu Ibnu Isma'il- berkata; telah menceritakan kepada kami [Sufyan Ats Tsauri] dari [Abu Ishaq] dari [Al Musayyib bin Rafi'] dari [Anbasah bin Abu Sufyan] dari [Ummu Habibah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa dalam sehari semalam shalat sunnah dua belas rakaat maka Allah akan membangunkan baginya rumah di surga; empat rakaat sebelum zhuhur, dua rakaat setelahnya, dua rakaat setelah maghrib, dua rakaat setelah isya` dan dua rakaat sebelum subuh.\" Abu Isa berkata; \"Hadits Anbasah dari Ummu Habibah dalam bab ini derajatnya hasan shahih, dan hadits ini juga telah diriwayatkan dari Anbasah dengan jalur lain.\""},"381":{"ar":"حَدَّثَنَا صَالِحُ بْنُ عَبْدِ اللَّهِ التِّرْمِذِيُّ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَا الْفَجْرِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَاقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَابْنِ عُمَرَ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَى أَحْمَدُ بْنُ حَنْبَلٍ عَنْ صَالِحِ بْنِ عَبْدِ اللَّهِ التِّرْمِذِيِّ حَدِيثًا","id":"Telah menceritakan kepada kami [Shalih bin Abdullah At Tirmidzi] berkata; telah menceritakan kepada kami [Abu Awanah] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] dari ['Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua rakaat sebelum fajar lebih baik dari dunia dan seisinya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ali, ibnu Umar dan Ibnu Abbas.\" Abu Isa berkata; \"Hadits 'Aisyah derajatnya hasan shahih. Dan Imam Ahmad bin Hanbal juga telah meriwayatkan sebuah hadits dari Shalih bin Abdullah At Tirmidzi.\""},"382":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ وَأَبُو عَمَّارٍ قَالَا حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ قَالَرَمَقْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهْرًا فَكَانَ يَقْرَأُ فِي الرَّكْعَتَيْنِ قَبْلَ الْفَجْرِ بِقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌقَالَ وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَأَنَسٍ وَأَبِي هُرَيْرَةَ وَابْنِ عَبَّاسٍ وَحَفْصَةَ وَعَائِشَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ وَلَا نَعْرِفُهُ مِنْ حَدِيثِ الثَّوْرِيِّ عَنْ أَبِي إِسْحَقَ إِلَّا مِنْ حَدِيثِ أَبِي أَحْمَدَ وَالْمَعْرُوفُ عِنْدَ النَّاسِ حَدِيثُ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ وَقَدْ رَوَى عَنْ أَبِي أَحْمَدَ عَنْ إِسْرَائِيلَ هَذَا الْحَدِيثُ أَيْضًا وَأَبُو أَحْمَدَ الزُّبَيْرِيُّ ثِقَةٌ حَافِظٌ قَالَ سَمِعْت بُنْدَارًا يَقُولُ مَا رَأَيْتُ أَحَدًا أَحْسَنَ حِفْظًا مِنْ أَبِي أَحْمَدَ الزُّبَيْرِيِّ وَأَبُو أَحْمَدَ اسْمُهُ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ الْكُوفِيُّ الْأَسَدِيُّ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] dan [Abu Ammar] keduanya berkata; telah menceritakan kepada kami [Abu Ahmad Az Zubairi] berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Mujahid] dari [Ibnu Umar] ia berkata; \"Aku memperhatikan Nabi shallallahu 'alaihi wasallam selama satu bulan, beliau selalu membaca QUL YAA AYYUHAL KAFIRUN dan QUL HUWAALLAHU AHAD ketika mengerjakan dua rakaat sebelum subuh.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Umar, Ibnu Mas'ud, Anas, Abu Hurairah, Ibnu Abbas, Hafshah dan 'Aisyah.\" Abu Isa berkata; \"Hadits Ibnu Umar derajatnya hasan. Aku tidak mengetahui hadits ini dari hadits Ast Tsauri dari Ishaq, kecuali dari hadits Abu Ahmad. Namun yang terkenal menurut orang-orang adalah hadits Isra'il, dari Abu Ishaq. Dan hadits ini juga diriwayatkan dari [Abu Ahma], dari [Isra'il]. Abu Ahmad adalah seorang ahli hadits yang tsiqah (dapat dipercaya) dan hafidz (banyak hafalannya). Ia berkata; \"Aku mendengar Bundar berkata; \"Aku tidak pernah melihat orang yang lebih baik hafalannya selain Abu Ahmad Az Zubairi.\" Dan Abu Ahmad namanya adalah Muhammad bin Abdullah bin Az Zubairi Al Kufi Al Asadi."},"383":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ عِيسَى الْمَرْوَزِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ قَال سَمِعْتُ مَالِكَ بْنَ أَنَسٍ عَنْ أَبِي النَّضْرِ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى رَكْعَتَيْ الْفَجْرِ فَإِنْ كَانَتْ لَهُ إِلَيَّ حَاجَةٌ كَلَّمَنِي وَإِلَّا خَرَجَ إِلَى الصَّلَاةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ كَرِهَ بَعْضُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ الْكَلَامَ بَعْدَ طُلُوعِ الْفَجْرِ حَتَّى يُصَلِّيَ صَلَاةَ الْفَجْرِ إِلَّا مَا كَانَ مِنْ ذِكْرِ اللَّهِ أَوْ مِمَّا لَا بُدَّ مِنْهُ وَهُوَ قَوْلُ أَحْمَدَ وَإِسْحَقَ","id":"Telah menceritakan kepada kami [Yusuf bin Isa Al Marwazi] berkata; telah menceritakan kepada kami [Abdullah bin Idris] berkata; Aku mendengar [Malik bin Anas] dari [Abu An Nadlr] dari [Abu Salamah] dari ['Aisyah] ia berkata; \"Setelah Nabi shallallahu 'alaihi wasallam selesai shalat dua rakaat sebelum subuh, beliau berbicara denganku jika ada keperluan dan jika tidak maka beliau ke masjid untuk shalat subuh.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Sebagian ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan selainnya memakruhkan berbicara setelah terbitnya fajar hingga melaksanakan shalat subuh, kecuali dzikir kepada Allah atau hal-hal yang tidak bisa ditunda. Ini adalah pendapat yang diambil oleh Ahmad dan Ishaq.\""},"384":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ قُدَامَةَ بْنِ مُوسَى عَنْ مُحَمَّدِ بْنِ الْحُصَيْنِ عَنْ أَبِي عَلْقَمَةَ عَنْ يَسَارٍ مَوْلَى ابْنِ عُمَرَ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا صَلَاةَ بَعْدَ الْفَجْرِ إِلَّا سَجْدَتَيْنِوَمَعْنَى هَذَا الْحَدِيثِ إِنَّمَا يَقُولُ لَا صَلَاةَ بَعْدَ طُلُوعِ الْفَجْرِ إِلَّا رَكْعَتَيْ الْفَجْرِ قَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَحَفْصَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ قُدَامَةَ بْنِ مُوسَى وَرَوَى عَنْهُ غَيْرُ وَاحِدٍ وَهُوَ مَا اجْتَمَعَ عَلَيْهِ أَهْلُ الْعِلْمِ كَرِهُوا أَنْ يُصَلِّيَ الرَّجُلُ بَعْدَ طُلُوعِ الْفَجْرِ إِلَّا رَكْعَتَيْ الْفَجْرِ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah Adl Dlabbi] berkata; telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Qudamah bin Musa] dari [Muhammad bin Al Hushain] dari [Abu Alqamah] dari [Yasar] pelayan Ibnu Umar, dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada shalat setelah fajar kecuali dua rakaat.\" Makna hadits ini adalah, bahwa tidak ada shalat setelah terbitnya fajar kecuali dua rakaat fajar. Ia berkata; \"Dalam bab ini juga ada riwayat dari Abdullah bin Amru dan hafshah.\" Abu Isa berkata; \"Hadits Ibnu Umar ini derajatnya gharib, kami tidak mengetahuinya kecuali dari hadits Qudamah bin Musa. Dan tidak hanya satu orang saja yang meriwayatkan darinya, dan ini adalah apa yang disepakati oleh ahli ilmu, yakni mereka memakruhkan seorang laki-laki melaksanakan shalat setelah terbitnya fajar kecuali dua rakaat fajar.\""},"385":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُعَاذٍ الْعَقَدِيُّ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى أَحَدُكُمْ رَكْعَتَيْ الْفَجْرِ فَلْيَضْطَجِعْ عَلَى يَمِينِهِقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ عَنْ عَائِشَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا صَلَّى رَكْعَتَيْ الْفَجْرِ فِي بَيْتِهِ اضْطَجَعَ عَلَى يَمِينِهِ وَقَدْ رَأَى بَعْضُ أَهْلِ الْعِلْمِ أَنْ يُفْعَلَ هَذَا اسْتِحْبَابًا","id":"Telah menceritakan kepada kami [Bisyr bin Mu'adz Al Aqadi] berkata; telah menceritakan kepada kami [Abdul Wahid bin Ziyad] berkata; telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian selesai melaksanakan shalat dua rakaat fajar maka hendaklah ia berbaring dengan posisi miring ke kanan.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari 'Aisyah.\" Abu Isa berkata; \"Hadits Abu Hurairah ini derajatnya hasan gharib dari jalur ini. Diriwayatkan dari 'Aisyah bahwa Nabi shallallahu 'alaihi wasallam jika shalat dua rakaat fajar di rumahnya, beliau selalu berbaring miring ke sebelah kanan. Dan sebagian ahli ilmu menganjurkan hal ini karena termasuk sunah.\""},"386":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا زَكَرِيَّا بْنُ إِسْحَقَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ قَال سَمِعْتُ عَطَاءَ بْنَ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا صَلَاةَ إِلَّا الْمَكْتُوبَةُقَالَ وَفِي الْبَاب عَنْ ابْنِ بُحَيْنَةَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَعَبْدِ اللَّهِ بْنِ سَرْجِسَ وَابْنِ عَبَّاسٍ وَأَنَسٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ وَهَكَذَا رَوَى أَيُّوبُ وَوَرْقَاءُ بْنُ عُمَرَ وَزِيَادُ بْنُ سَعْدٍ وَإِسْمَعِيلُ بْنُ مُسْلِمٍ وَمُحَمَّدُ بْنُ جُحَادَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَى حَمَّادُ بْنُ زَيْدٍ وَسُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ فَلَمْ يَرْفَعَاهُ وَالْحَدِيثُ الْمَرْفُوعُ أَصَحُّ عِنْدَنَا وَالْعَمَلُ عَلَى هَذَا عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ إِذَا أُقِيمَتْ الصَّلَاةُ أَنْ لَا يُصَلِّيَ الرَّجُلُ إِلَّا الْمَكْتُوبَةَ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَيْرِ هَذَا الْوَجْهِ رَوَاهُ عَيَّاشُ بْنُ عَبَّاسٍ الْقِتْبَانِيُّ الْمِصْرِيُّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Rauh bin Ubadah] berkata; telah menceritakan kepada kami [Zakaria bin Ishaq] berkata; telah menceritakan kepada kami [Amru bin Dinar] berkata; aku mendengar ['Atha` bin Yasar] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika iqamah telah dikumandangkan maka tidak ada shalat selain maktubah (shalat wajib).\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Buhainah, Abdullah bin Amru, Abdullah bin Sarjisy, Ibnu Abbas dan Anas.\" Abu Isa berkata; \"Hadits Abu Hurairah ini derajatnya hasan. Demikianlah [Ayyub] dan [Warqa` bin Umar] dan [Ziyad bin Sa'd] dan [Isma'il bin Muslim] dan [Muhammad bin Juhadah] meriwayatkan dari [Amru bin Dinar] dari ['Atha` bin Yasar] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam. Hammad bin Zaid dan Sufyan bin Uyainah meriwayatkan hadits ini dari Amru bin Dinar, namun keduanya tidak memarfu'kannya. Padahal menurut kami hadits marfu' adalah lebih shahih. sebagian ahli ilmu mengamalkan hadits ini, yaitu jika shalat telah dikumandangkan, seorang laki-laki tidak boleh melakukan shalat apa-pun selain shalat maktubah. Pendapat ini diambil oleh Sufyan Ats Tsauri, bin Al Mubarak, Syafi'i, Ahmad dan Ishaq. Hadits ini juga diriwayatkan dari Abu Hurairah, dari Nabi shallallahu 'alaihi wasallam dengan jalur lain. [Ayyasy bin Abbas Al Qitbani Al Mishri] meriwayatkannya dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti hadits tersebut.\""},"387":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو السَّوَّاقُ الْبَلْخِيُّ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سَعْدِ بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ جَدِّهِ قَيْسٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُقِيمَتْ الصَّلَاةُ فَصَلَّيْتُ مَعَهُ الصُّبْحَ ثُمَّ انْصَرَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَنِي أُصَلِّي فَقَالَ مَهْلًا يَا قَيْسُ أَصَلَاتَانِ مَعًا قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي لَمْ أَكُنْ رَكَعْتُ رَكْعَتَيْ الْفَجْرِ قَالَ فَلَا إِذَنْقَالَ أَبُو عِيسَى حَدِيثُ مُحَمَّدِ بْنِ إِبْرَاهِيمَ لَا نَعْرِفُهُ مِثْلَ هَذَا إِلَّا مِنْ حَدِيثِ سَعْدِ بْنِ سَعِيدٍ و قَالَ سُفْيَانُ بْنُ عُيَيْنَةَ سَمِعَ عَطَاءُ بْنُ أَبِي رَبَاحٍ مِنْ سَعْدِ بْنِ سَعِيدٍ هَذَا الْحَدِيثَ وَإِنَّمَا يُرْوَى هَذَا الْحَدِيثُ مُرْسَلًا وَقَدْ قَالَ قَوْمٌ مِنْ أَهْلِ مَكَّةَ بِهَذَا الْحَدِيثِ لَمْ يَرَوْا بَأْسًا أَنْ يُصَلِّيَ الرَّجُلُ الرَّكْعَتَيْنِ بَعْدَ الْمَكْتُوبَةِ قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ قَالَ أَبُو عِيسَى وَسَعْدُ بْنُ سَعِيدٍ هُوَ أَخُو يَحْيَى بْنِ سَعِيدٍ الْأَنْصَارِيِّ قَالَ وَقَيْسٌ هُوَ جَدُّ يَحْيَى بْنِ سَعِيدٍ الْأَنْصَارِيِّ وَيُقَالُ هُوَ قَيْسُ بْنُ عَمْرٍو وَيُقَالُ هُوَ قَيْسُ بْنُ قَهْدٍ وَإِسْنَادُ هَذَا الْحَدِيثِ لَيْسَ بِمُتَّصِلٍ مُحَمَّدُ بْنُ إِبْرَاهِيمَ التَّيْمِيُّ لَمْ يَسْمَعْ مِنْ قَيْسٍ وَرَوَى بَعْضُهُمْ هَذَا الْحَدِيثَ عَنْ سَعْدِ بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ فَرَأَى قَيْسًا وَهَذَا أَصَحُّ مِنْ حَدِيثِ عَبْدِ الْعَزِيزِ عَنْ سَعْدِ بْنِ سَعِيدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Amru As Sawwaq Al Balkhi] berkata; telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Sa'd bin Sa'id] dari [Muhammad bin Ibrahim] dari kakeknya [Qais] berkata; \"Rasulullah shallallahu 'alaihi wasallam keluar lalu iqamah dikumandangkan, aku kemudian shalat subuh bersama beliau. Setelah itu Nabi shallallahu 'alaihi wasallam berlalu dan mendapatiku sedang shalat, maka beliau pun bersabda: \"Wahai Qais tunggu! Apakah engkau mengerjakan dua shalat bersama kami?\" aku lalu menjawab, \"Wahai Rasulullah, sesungguhnya aku belum mengerjakan dua rakaat sebelum fajar, \" beliau bersabda: \"Kalau begitu silahkan.\" Abu Isa berkata; \"Kami tidak mengetahui hadits Muhammad bin Ibrahim seperti ini selain dari hadits Sa'd bin Sa'id.\" Sufyan bin Uyainah berkata; \"'Atha` bin Rabah mendengar hadits ini dari Sa'd bin Sa'id, namun hadits ini diriwayatkan secara mursal. Sebagian ulama Makkah berpegangan dengan hadits ini, mereka berkata; \"Tidak apa-apa seseorang shalat sunah dua rakaat setelah shalat maktubah (subuh) sebelum terbitnya matahari.\" Abu Isa berkata; \"Sa'd bin Sa'id adalah saudara Yahya bin Sa'id Al Anshari.\" Ia berkata; \"Qais adalah kakek Yahya bin Sa'id Al Anshari, ia juga disebut dengan nama Qais bin Amru, atau disebut juga dengan nama Qais bin Qahd. Dan sanad hadits ini tidak bersambung, sebab Muhammad bin Ibrahim At Taimi tidak mendengar dari Qais. Namun sebagian mereka meriwayatkan hadits ini dari Sa'd bin Sa'id, dari Muhammad bin Ibrahim bahwa Nabi shallallahu 'alaihi wasallam keluar dan melihat Qais, dan ini lebih shahih dari hadits Abdul Aziz, dari Sa'd bin Sa'id.\""},"388":{"ar":"حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ الْعَمِّيُّ الْبَصْرِيُّ حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَمْ يُصَلِّ رَكْعَتَيْ الْفَجْرِ فَلْيُصَلِّهِمَا بَعْدَ مَا تَطْلُعُ الشَّمْسُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ عَنْ ابْنِ عُمَرَ أَنَّهُ فَعَلَهُ وَالْعَمَلُ عَلَى هَذَا عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ قَالَ وَلَا نَعْلَمُ أَحَدًا رَوَى هَذَا الْحَدِيثَ عَنْ هَمَّامٍ بِهَذَا الْإِسْنَادِ نَحْوَ هَذَا إِلَّا عَمْرَو بْنَ عَاصِمٍ الْكِلَابِيَّ وَالْمَعْرُوفُ مِنْ حَدِيثِ قَتَادَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ رَكْعَةً مِنْ صَلَاةِ الصُّبْحِ قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ فَقَدْ أَدْرَكَ الصُّبْحَ","id":"Telah menceritakan kepada kami [Uqbah bin Mukram Al Ammi Al Bashari] berkata; telah menceritakan kepada kami [Amru bin 'Ashim] berkata; telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [An Nadlr bin Anas] dari [Basyir bin Nahik] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa belum melaksanakan dua rakaat fajar, hendaklah ia melaksanakannya setelah terbit matahari.\" Abu Isa berkata; \"Kami tidak mengetahui hadits ini kecuali dari jalur ini. Diriwayatkan dari Ibnu Umar bahwa ia juga melakukannya (melaksanakan dua rakaat fajar setelah matahari terbit). Sebagian ahli ilmu mengamalkan hadits ini. pendapat ini pula yang diambil oleh Sufyan Ats Tsauri, bin Al Mubarak, Syafi'i, Ahmad dan Ishaq. Ia berkata; \"Kami tidak mengetahui seorang pun yang meriwayatkan hadits ini dari Hammam dengan sanad ini, kecuali Amru bin 'Ashim Al Kilabi. Namun yang lebih terkenal adalah dari hadits Qatadah, dari An Nadlr bin Anas, dari Basyir bin Nahik, dari Abu Hurairah, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa mendapatkan satu rakaat shalat subuh sebelum matahari terbit, maka ia telah mendapatkan subuh.\""},"389":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيٍّ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي قَبْلَ الظُّهْرِ أَرْبَعًا وَبَعْدَهَا رَكْعَتَيْنِقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَأُمِّ حَبِيبَةَ قَالَ أَبُو عِيسَى حَدِيثُ عَلِيٍّ حَدِيثٌ حَسَنٌ حَدَّثَنَا أَبُو بَكْرٍ الْعَطَّارُ قَالَ عَلِيُّ بْنُ عَبْدِ اللَّهِ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ سُفْيَانَ قَالَ كُنَّا نَعْرِفُ فَضْلَ حَدِيثِ عَاصِمِ بْنِ ضَمْرَةَ عَلَى حَدِيثِ الْحَارِثِ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ يَخْتَارُونَ أَنْ يُصَلِّيَ الرَّجُلُ قَبْلَ الظُّهْرِ أَرْبَعَ رَكَعَاتٍ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَابْنِ الْمُبَارَكِ وَإِسْحَقَ وَأَهْلِ الْكُوفَةِ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ صَلَاةُ اللَّيْلِ وَالنَّهَارِ مَثْنَى مَثْنَى يَرَوْنَ الْفَصْلَ بَيْنَ كُلِّ رَكْعَتَيْنِ وَبِهِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Abu Amir Al Aqadi] berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari ['Ashim bin Dlamrah] dari [Ali] ia berkata; \"Nabi shallallahu 'alaihi wasallam shalat sebanyak empat rakaat sebelum zhuhur dan dua rakaat setelahnya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari 'Aisyah dan Ummu Habibah.\" Abu Isa berkata; \"Hadits Ali derajatnya hasan. Abu Bakar Al 'Aththar menceritakan kepada kami, ia berkata; Ali bin Abdullah berkata dari Yahya bin Sa'id, dari Sufyan, ia berkata; \"Kami mengetahui kelebihan hadits 'Ashim bin Dlamrah bila dibandingkan dengan hadits Al Harits.\" Kebanyakan ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan orang-orang setelah mereka mengamalkan hadits ini. Mereka memilih pendapat bahwa, seseorang hendaklah mengerjakan shalat sunnah empat rakaat sebelum zhuhur. Pendapat ini diambil oleh Sufyan Ats Tsauri, bin Al Mubarak, Ishaq dan penduduk Kufah. Sedangkan sebagian ahli ilmu mengatakan, \"Shalat di waktu malam atau pun siang hari adalah dua rakaat-dua rakaat, dan salam setiap dua tekaat. Ini adalah pendapat yang diambil oleh Syafi'i dan Ahmad.\""},"390":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ قَبْلَ الظُّهْرِ وَرَكْعَتَيْنِ بَعْدَهَاقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَعَائِشَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] berkata; \"Aku pernah shalat bersama Nabi shallallahu 'alaihi wasallam dua rakaat sebelum zhuhur dan dua rakaat setelahnya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ali dan 'Aisyah.\" Abu Isa berkata; \"Hadits Ibnu Umar derajatnya hasan shahih.\""},"391":{"ar":"حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ عُبَيْدِ اللَّهِ الْعَتَكِيُّ الْمَرْوَزِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا لَمْ يُصَلِّ أَرْبَعًا قَبْلَ الظُّهْرِ صَلَّاهُنَّ بَعْدَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ ابْنِ الْمُبَارَكِ مِنْ هَذَا الْوَجْهِ وَقَدْ رَوَاهُ قَيْسُ بْنُ الرَّبِيعِ عَنْ شُعْبَةَ عَنْ خَالِدٍ الْحَذَّاءِ نَحْوَ هَذَا وَلَا نَعْلَمُ أَحَدًا رَوَاهُ عَنْ شُعْبَةَ غَيْرَ قَيْسِ بْنِ الرَّبِيعِ وَقَدْ رُوِيَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوُ هَذَا","id":"Telah menceritakan kepada kami [Abdul Warits bin Ubaidullah Al Ataki Al Marwazi] berkata; telah mengabarkan kepada kami [Ibnu Al Mubarak] dari [Khalid Al Hadzdza`] dari [Abdullah bin Syaqiq] dari ['Aisyah] berkata; \"Jika Nabi shallallahu 'alaihi wasallam belum melaksanakan shalat empat rakaat sebelum zhuhur maka beliau melaksanakan setelahnya.\" Abu Isa berkata; \"Hadits ini derajatnya hasan gharib, kami mengetahui hadits ini dari bin Al Mubarak dari jalur ini. [Qais bin Ar Rabi'] meriwayatkannya seperti ini dari [Syu'bah] dari [Khalid bin Hadzdza`]. Dan kami tidak mengetahui seorang pun yang meriwayatkannya dari Syu'bah selain Qais bin Ar Rabi'. Diriwayatkan dari Abdurrahman bin Abu Laila dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\""},"392":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ الشُّعَيْثِيِّ عَنْ أَبِيهِ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُمِّ حَبِيبَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى قَبْلَ الظُّهْرِ أَرْبَعًا وَبَعْدَهَا أَرْبَعًا حَرَّمَهُ اللَّهُ عَلَى النَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَقَدْ رُوِيَ مِنْ غَيْرِ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Ali bin Hujr] berkata; telah mengabarkan kepada kami [Yazid bin Harun] dari [Muhammad bin Abdullah Asy Syua'itsi] dari [Ayahnya] dari [Anbasah bin Abu Sufyan] dari [Ummu Habibah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa shalat empat rakaat sebelum dan setelah zhuhur maka Allah akan mengharamkannya masuk neraka.\" Abu Isa berkata; \"Hadits ini derajatnya hasan gharib, dan hadits ini juga telah diriwayatkan dari jalur lain.\""},"393":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ مُحَمَّدُ بْنُ إِسْحَقَ الْبَغْدَادِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ التِّنِّيسِيُّ الشَّأْمِيُّ حَدَّثَنَا الْهَيْثَمُ بْنُ حُمَيْدٍ أَخْبَرَنِي الْعَلَاءُ هُوَ ابْنُ الْحَارِثِ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ قَال سَمِعْتُ أُخْتِي أُمَّ حَبِيبَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ حَافَظَ عَلَى أَرْبَعِ رَكَعَاتٍ قَبْلَ الظُّهْرِ وَأَرْبَعٍ بَعْدَهَا حَرَّمَهُ اللَّهُ عَلَى النَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَالْقَاسِمُ هُوَ ابْنُ عَبْدِ الرَّحْمَنِ يُكْنَى أَبَا عَبْدِ الرَّحْمَنِ وَهُوَ مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ خَالِدِ بْنِ يَزِيدَ بْنِ مُعَاوِيَةَ وَهُوَ ثِقَةٌ شَأْمِيٌّ وَهُوَ صَاحِبُ أَبِي أُمَامَةَ","id":"Telah menceritakan kepada kami [Abu Bakr Muhammad bin Ishaq Al Baghdadi] berkata; telah menceritakan kepada kami [Abdullah bin Yusuf Attinnisi Asy Sya`mi] berkata; telah menceritakan kepada kami [Al Haitsam bin Humaid] berkata; telah mengabarkan kepadaku [Al 'Ala`] -yaitu bin Al Harits- dari [Al Qasim Abu Abdurrahman] dari [Anbasah bin Abu Sufyan] ia berkata; \"Aku mendengar saudaraku, [Ummu Habibah], istri Nabi shallallahu 'alaihi wasallam berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bisa menjaga empat rakaat sebelum zhuhur dan empat rakaat setelahnya maka Allah akan mengharamkannya masuk neraka.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih gharib dari jalur ini. dan Al Qasim adalah Ibnu Abdurrahman, julukannya Abu Abdurrahman, yaitu pelayan Abdurrahman bin Khalid bin Yazid bin Mu'awiyah. Ia adalah seorang tsiqah dari wilayah Syam, dan ia adalah teman Abu Umamah.\""},"394":{"ar":"حَدَّثَنَا بُنْدَارٌ مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ هُوَ الْعَقَدِيُّ عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيٍّ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي قَبْلَ الْعَصْرِ أَرْبَعَ رَكَعَاتٍ يَفْصِلُ بَيْنَهُنَّ بِالتَّسْلِيمِ عَلَى الْمَلَائِكَةِ الْمُقَرَّبِينَ وَمَنْ تَبِعَهُمْ مِنْ الْمُسْلِمِينَ وَالْمُؤْمِنِينَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى حَدِيثُ عَلِيٍّ حَدِيثٌ حَسَنٌ وَاخْتَارَ إِسْحَقُ بْنُ إِبْرَاهِيمَ أَنْ لَا يُفْصَلَ فِي الْأَرْبَعِ قَبْلَ الْعَصْرِ وَاحْتَجَّ بِهَذَا الْحَدِيثِ و قَالَ إِسْحَقُ وَمَعْنَى قَوْلِهِ أَنَّهُ يَفْصِلُ بَيْنَهُنَّ بِالتَّسْلِيمِ يَعْنِي التَّشَهُّدَ وَرَأَى الشَّافِعِيُّ وَأَحْمَدُ صَلَاةَ اللَّيْلِ وَالنَّهَارِ مَثْنَى مَثْنَى يَخْتَارَانِ الْفَصْلَ فِي الْأَرْبَعِ قَبْلَ الْعَصْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Abu Amir] -yaitu Al Aqadi Abdul Malik bin Amru- dari [Sufyan] dari [Abu Ishaq] dari ['Ashim bin Dlamrah] dari [Ali] ia berkata; \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat empat rakaat sebelum asar, dan beliau memisahkan antara empat rakaat tersebut dengan mengucapkan salam kepada malaikat muqarrabin, orang-orang muslim dan mukmin yang mengikutinya.\" Abu Isa berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Umar dan Abdullah bin Amru.\" Abu Isa berkata; \"Hadits Ali ini derajatnya hasan shahih. Ishaq bin Ibrahim memilih untuk tidak memisahkan antara empat rakaat tersebut berdasarkan hadits ini.\" Ishaq berkata lagi, \"Adapun maksud dari ucapannya, \"memisahkan di antara empat rakaat itu dengan salam, \" adalah dengan tasyahud.\" Imam Syafi'i dan Ahmad berpandangan bahwa shalat yang dilakukan baik malam ataupun siang adalah dua rakaat-dua rakaat, dan keduanya memilih adanya pemisahan dalam melaksanakan shalat empat rakaat sebelum asar.\""},"395":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى وَمَحْمُودُ بْنُ غَيْلَانَ وَأَحْمَدُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ مُسْلِمِ بْنِ مِهْرَانَ سَمِعَ جَدَّهُ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَحِمَ اللَّهُ امْرَأً صَلَّى قَبْلَ الْعَصْرِ أَرْبَعًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Yahya bin Musa] dan [Mahmud Al Gahilan] dan [Ahmad bin Ibrahim Ad Dauraqi] dan selainnya berkata; telah menceritakan kepada kami [Abu Dawud Ath Thayalisi] berkata; telah menceritakan kepada kami [Muhammad bin Muslim bin Mihran] mendengar [Kakeknya] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Semoga Allah merahmati orang yang shalat empat rakaat sebelum ashar.\" Abu Isa berkata; \"Hadits ini derajatnya hasan gharib.\""},"396":{"ar":"حَدَّثَنَا أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا بَدَلُ بْنُ الْمُحَبَّرِ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ مَعْدَانَ عَنْ عَاصِمِ بْنِ بَهْدَلَةَ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ أَنَّهُ قَالَمَا أُحْصِي مَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الرَّكْعَتَيْنِ بَعْدَ الْمَغْرِبِ وَفِي الرَّكْعَتَيْنِ قَبْلَ صَلَاةِ الْفَجْرِ بِقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ مَسْعُودٍ حَدِيثٌ غَرِيبٌ مِنْ حَدِيثِ ابْنِ مَسْعُودٍ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ الْمَلِكِ بْنِ مَعْدَانَ عَنْ عَاصِمٍ","id":"Telah menceritakan kepada kami [Abu Musa Muhammad bin Al Mutsanna] berkata; telah menceritakan kepada kami [Badal bin Al Muhabbar] berkata; telah menceritakan kepada kami [Abdul Malik bin Ma'dan] dari ['Ashim bin Bahdalah] dari [Abu Wa`il] dari [Abdullah bin Mas'ud] bahwasanya ia berkata; \"Aku tidak bisa menghitung lagi apa yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam, beliau membaca QUL YAA AYYUHAL KAAFIRUUN QUL HUWAALLAHU AHAD pada dua rakaat setelah maghrib dan dua rakaat sebelum subuh.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ibnu Umar.\" Abu Isa berkata; \"Hadits Ibnu Mas'ud ini derajatnya hasan gharib, dan kami tidak mengetahui hadits keduali dari hadits Abdul Malik bin Ma'dan, dari 'Ashim.\""},"397":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ بَعْدَ الْمَغْرِبِ فِي بَيْتِهِقَالَ وَفِي الْبَاب عَنْ رَافِعِ بْنِ خَدِيجٍ وَكَعْبِ بْنِ عُجْرَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata; \"Aku pernah shalat dua rakaat setelah maghrib bersama Nabi shallallahu 'alaihi wasallam di rumahnya.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Rafi' bin Khadij dan Ka'ab bin Ujrah.\" Abu Isa berkata; \"Hadits Ibnu Umar ini derajatnya hasan shahih.\""},"398":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ الْخَلَّالُ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَحَفِظْتُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشْرَ رَكَعَاتٍ كَانَ يُصَلِّيهَا بِاللَّيْلِ وَالنَّهَارِ رَكْعَتَيْنِ قَبْلَ الظُّهْرِ وَرَكْعَتَيْنِ بَعْدَهَا وَرَكْعَتَيْنِ بَعْدَ الْمَغْرِبِ وَرَكْعَتَيْنِ بَعْدَ الْعِشَاءِ الْآخِرَةِقَالَ وَحَدَّثَتْنِي حَفْصَةُ أَنَّهُ كَانَ يُصَلِّي قَبْلَ الْفَجْرِ رَكْعَتَيْنِ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Hulwani Al Khallal] berkata; telah menceritakan kepada kami [Abdurrazaq] berkata; telah mengabarkan kepada kami [Ma'mar] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata; \"Aku menjaga dari Rasulullah shallallahu 'alaihi wasallam sepuluh rakaat yang selalu beliau laksanakan baik malam maupun siang; dua rakaat sebelum zhuhur, dua rakaat setelahnya, dua rakaat setelah maghrib, dan dua rakaat setelah shalat isya`yang akhir.\" Ia berkata; \" [Hafshah] menceritakan kepadaku bahwa beliau melaksanakan shalat dua rakaat sebelum fajar.\" Dan ini adalah hadits hasan shahih. Telah menceritakan kepada kami [Al Hasan bin Ali] berkata; telah menceritakan kepada kami [Abdurrazaq] berkata; telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam sebagaimana hadits tersebut."},"399":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ يَعْنِي مُحَمَّدَ بْنَ الْعَلَاءِ الْهَمْدَانِيَّ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا عُمَرُ بْنُ أَبِي خَثْعَمٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى بَعْدَ الْمَغْرِبِ سِتَّ رَكَعَاتٍ لَمْ يَتَكَلَّمْ فِيمَا بَيْنَهُنَّ بِسُوءٍ عُدِلْنَ لَهُ بِعِبَادَةِ ثِنْتَيْ عَشْرَةَ سَنَةًقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى بَعْدَ الْمَغْرِبِ عِشْرِينَ رَكْعَةً بَنَى اللَّهُ لَهُ بَيْتًا فِي الْجَنَّةِ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ زَيْدِ بْنِ الْحُبَابِ عَنْ عُمَرَ بْنِ أَبِي خَثْعَمٍ قَالَ و سَمِعْت مُحَمَّدَ بْنَ إِسْمَعِيلَ يَقُولُ عُمَرُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي خَثْعَمٍ مُنْكَرُ الْحَدِيثِ وَضَعَّفَهُ جِدًّا","id":"Telah menceritakan kepada kami [Abu Kuraib] -yaitu Muhammad bin Al 'Ala` Al Hamdani berkata; telah menceritakan kepada kami [Zaid bin Al Hubab] berkata; telah menceritakan kepada kami [Umar bin Abu Khats'am] dari [Yahya bin Abu katsir] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melaksanakan shalat enam rakaat setelah maghrib, kemudian ia tidak berbicara buruk di antara shalat tersebut, maka akan dihitung baginya dengan ibadah selama dua belas tahun.\" Abu Isa berkata; \"Diriwayatkan dari 'Aisyah, dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Barangsiapa shalat dua puluh rakaat setelah maghrib, maka Allah akan membangunkan baginya sebuah rumah di surga.\" Abu Isa berkata; \"Hadits Abu Hurairah ini derajatnya gharib, kami tidak mengetahuinya kecuali dari hadits Zaid bin Al Hubab, dari Umar bin Khats'am.\" Ia berkata; \"Aku mendengar Muhammad bin Isma'il mengatakan, bahwa Umar bin Abdullah bin Abu Khats'am adalah seorang munkarul hadits, dan Muhammad bin Isma'il sangat melemahkannya.\""},"400":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَ سَأَلْتُ عَائِشَةَ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْكَانَ يُصَلِّي قَبْلَ الظُّهْرِ رَكْعَتَيْنِ وَبَعْدَهَا رَكْعَتَيْنِ وَبَعْدَ الْمَغْرِبِ ثِنْتَيْنِ وَبَعْدَ الْعِشَاءِ رَكْعَتَيْنِ وَقَبْلَ الْفَجْرِ ثِنْتَيْنِقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى حَدِيثُ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَائِشَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Salamah Yahya bin Khalaf] berkata; telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] dari [Khalid Al Hadzdza`] dari [Abdullah bin Syaqiq] berkata; \"Aku pernah bertanya ['Aisyah] tentang shalat Rasulullah shallallahu 'alaihi wasallam, maka ia pun menjawab, \"Beliau biasa shalat dua rakaat sebelum zhuhur, dua rakaat setelahnya, dua rakaat setelah maghrib, dua rakaat setelah isya dan dua rakaat sebelum subuh.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Ali dan Ibnu Umar.\" Abu Isa berkata; \"Hadits Abdullah bin Syaqiq, dari 'Aisyah derajatnya hasan shahih.\""},"401":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى فَإِذَا خِفْتَ الصُّبْحَ فَأَوْتِرْ بِوَاحِدَةٍ وَاجْعَلْ آخِرَ صَلَاتِكَ وِتْرًاقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَمْرِو بْنِ عَبَسَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ أَنَّ صَلَاةَ اللَّيْلِ مَثْنَى مَثْنَى وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَابْنِ الْمُبَارَكِ وَالشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Shalat malam adalah dua raka'at dua raka'at, jika kamu khawatir akan masuk waktu subuh, maka kerjakanlah shalat witir satu raka'at, dan jadikan diakhir shalatmu dengan mengerjakan shalat witir.\" Abu Isa berkata, dalam bab ini (ada juga riwayat -pent) dari Amru bin 'Abasah, Abu Isa berkata, hadits Ibnu Umar adalah hadits hasan shahih, menurut ahli ilmu, mengamalkan hadits ini, maknanya shalat malam adalah dua raka'at dua raka'at, ini juga merupakan perkataan Sufyan At Tsauri, Ibnu Mubarrak, As Syafi'i, Ahmad dan Ishaq."},"402":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ الْحِمْيَرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ الصِّيَامِ بَعْدَ شَهْرِ رَمَضَانَ شَهْرُ اللَّهِ الْمُحَرَّمُ وَأَفْضَلُ الصَّلَاةِ بَعْدَ الْفَرِيضَةِ صَلَاةُ اللَّيْلِقَالَ وَفِي الْبَاب عَنْ جَابِرٍ وَبِلَالٍ وَأَبِي أُمَامَةَ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ أَبُو عِيسَى وَأَبُو بِشْرٍ اسْمُهُ جَعْفَرُ بْنُ أَبِي وَحْشِيَّةَ وَاسْمُ أَبِي وَحْشِيَّةَ إِيَاسٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Humaid bin Abdurrahman Al Himyari] dari [Abu Hurairah] dia berkata, bersabda: \"Sebaik baik puasa setelah puasa di bulan Ramadlan adalah puasa di bulan Muharram dan sebaik baik shalat setelah shalat wajib adalah shalat malam.\" (perawai) berkata, dan dalam bab ini (ada juga riwayat) dari Jabir, Bilal dan Abu Umamah. Abu Isa berkata, hadits Abu Hurairah adalah hadits hasan shahih, Abu Isa berkata, adapun Abu Bisyr namanya adalah Ja'far bin Abu Wahsyiyah sedangkan nama Abu Wahsyiyah adalah Wahsyiyah Iyas."},"403":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي سَلَمَةَ أَنَّهُ أَخْبَرَهُ أَنَّهُ سَأَلَ عَائِشَةَكَيْفَ كَانَتْ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ فِي رَمَضَانَ فَقَالَتْ مَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَزِيدُ فِي رَمَضَانَ وَلَا فِي غَيْرِهِ عَلَى إِحْدَى عَشْرَةَ رَكْعَةً يُصَلِّي أَرْبَعًا فَلَا تَسْأَلْ عَنْ حُسْنِهِنَّ وَطُولِهِنَّ ثُمَّ يُصَلِّي أَرْبَعًا فَلَا تَسْأَلْ عَنْ حُسْنِهِنَّ وَطُولِهِنَّ ثُمَّ يُصَلِّي ثَلَاثًا فَقَالَتْ عَائِشَةُ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتَنَامُ قَبْلَ أَنْ تُوتِرَ فَقَالَ يَا عَائِشَةُ إِنَّ عَيْنَيَّ تَنَامَانِ وَلَا يَنَامُ قَلْبِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] telah menceritakan kepada kami [Ma'an] telah menceritakan kepada kami [Malik] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Salamah] bahwa dia mengabarkan kepadanya, bahwa dia pernah bertanya kepada ['Aisyah] mengenai shalat malam pada bulan Ramadlan, Maka dia ('Aisyah radliallahu 'anha) berkata, beliau tidak pernah menambahi bilangan raka'at baik pada bulan Ramadlan atau selain dari bulan Ramadlan, yaitu sebelas raka'at, beliau mengerjakannya dengan empat rak'at, jangan kamu bertanya tentang bagusnya dan lamanya beliau shalat, kemudian beliau mengerjakan empat raka'at lagi, dan jangan bertanya tentang bagusnya dan lamanya berliau shalat, baru kemudian beliau shalat tiga raka'at. Lalu 'Aisyah berkata, wahai Rasulullah apakah tuan tidur padahal belum berwitir? Maka beliau menjawab: \"Wahai 'Aisyah, sesungguhnya mataku tertidur tapi hatiku tetap terjaga.\" Abu Isa berkata, ini adalah hadits hasan shahih."},"404":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنُ بْنُ عِيسَى حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي مِنْ اللَّيْلِ إِحْدَى عَشْرَةَ رَكْعَةً يُوتِرُ مِنْهَا بِوَاحِدَةٍ فَإِذَا فَرَغَ مِنْهَا اضْطَجَعَ عَلَى شِقِّهِ الْأَيْمَنِحَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ نَحْوَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] telah menceritakan kepada kami [Ma'n bin Isa] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah] bahwasannya Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat malam sebelas raka'at dengan satu kali witir, jika beliau selesai, beliau berbaring diatas tulang rusuknya yang sebelah kanan. Telah menceritakan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] seperti itu, Abu Isa berkata, ini adalah hadits hasan shahih."},"405":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ أَبِي جَمْرَةَ الضُّبَعِيُّ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ ثَلَاثَ عَشْرَةَ رَكْعَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو جَمْرَةَ الضُّبَعِيُّ اسْمُهُ نَصْرُ بْنُ عِمْرَانَ الضُّبَعِيُّ","id":"Telah menceritakan kepada kami [Abu Kuraib] dia berkata, telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Abu Jamrah Ad Dluba'i] dari [Ibnu Abbas] dia berkata, bahwa Nabi shallallahu 'alaihi wasallam melaksanakan shalat malam tiga belas raka'at. Abu Isa berkata, ini adalah hadis hasan shahih, sedangkan Abu Jamrah Ad Dluba'i namanya adalah Nashr bin 'Imran Adl Dluba'i."},"406":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ تِسْعَ رَكَعَاتٍقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ وَالْفَضْلِ بْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَرَوَاهُ سُفْيَانُ الثَّوْرِيُّ عَنْ الْأَعْمَشِ نَحْوَ هَذَا حَدَّثَنَا بِذَلِكَ مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ قَالَ أَبُو عِيسَى وَأَكْثَرُ مَا رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةِ اللَّيْلِ ثَلَاثَ عَشْرَةَ رَكْعَةً مَعَ الْوِتْرِ وَأَقَلُّ مَا وُصِفَ مِنْ صَلَاتِهِ بِاللَّيْلِ تِسْعُ رَكَعَاتٍ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami bahwa [Abul Ahwas] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad bin Yazid] dari [A'isyah] dia berkata, Nabi shallallahu 'alaihi wasallam melaksanakan shalat malam sembilan raka'at. (perawi) berkata, dan dalam bab ini (ada juga riwayat -pent) dari Abu Hurairah, Zaid bin Khalid dan Al Fadlal bin Abbas. Abu Isa berkata, hadits A'isyah adalah hadits hasan gharib dari jalur ini, [Sufyan Ats Tsauri] telah meriwayatkan dari [Al A'masy] dengan hadits yang semakna dengan ini, [Mahmud bin Ghailan] telah bercerita demikian kepada kami bahwa [Yahya bin Adam] telah bercerita kepada kami dari [Sufyan] dari [Al A'masy]. Abu Isa berkata, dan riwayat yang paling banyak diriwayatkan dari Nabi shallallahu 'alaihi wasallam tentang shalat malam adalah tiga belas raka'at bersama witir. Dan yang paling sedikit menyebutkan tentang shalat malam beliau adalah sembilan raka'at."},"407":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا لَمْ يُصَلِّ مِنْ اللَّيْلِ مَنَعَهُ مِنْ ذَلِكَ النَّوْمُ أَوْ غَلَبَتْهُ عَيْنَاهُ صَلَّى مِنْ النَّهَارِ ثِنْتَيْ عَشْرَةَ رَكْعَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ أَبُو عِيسَى وَسَعْدُ بْنُ هِشَامٍ هُوَ ابْنُ عَامِرٍ الْأَنْصَارِيُّ وَهِشَامُ بْنُ عَامِرٍ هُوَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا عَبَّاسٌ هُوَ ابْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ حَدَّثَنَا عَتَّابُ بْنُ الْمُثَنَّى عَنْ بَهْزِ بْنِ حَكِيمٍ قَالَ كَانَ زُرَارَةُ بْنُ أَوْفَى قَاضِيَ الْبَصْرَةِ وَكَانَ يَؤُمُّ فِي بَنِي قُشَيْرٍ فَقَرَأَ يَوْمًا فِي صَلَاةِ الصُّبْحِ{ فَإِذَا نُقِرَ فِي النَّاقُورِ فَذَلِكَ يَوْمَئِذٍ يَوْمٌ عَسِيرٌ }خَرَّ مَيِّتًا فَكُنْتُ فِيمَنْ احْتَمَلَهُ إِلَى دَارِهِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'id bin Hisyam] dari ['Aisyah] dia berkata, adalah Nabi shallallahu 'alaihi wasallam jika tidak sempat shalat malam karena ketiduran atau terserang kantuk, beliau shalat disiang hari sebanyak dua belas raka'at. Abu Isa berkata, ini adalah hadits hasan shahih. Berkata Abu Isa, Sa'ad bin Hisyam, dia adalah Ibnu 'Amir Al Anshari dan Hisyam bin 'Amir, dia merupakan salah satu dari sahabat Nabi shallallahu 'alaihi wasallam telah menceritakan kepada kami 'Abbas dia adalah Ibnu 'Abdul 'Azhim Al 'Anbari, telah menceritakan kepada kami 'Attab bin Mutsanna dari Bahs bin Hakim dia berkata, bahwa Zurarah bin Aufa seorang qadli di Bashrah pernah menjadi imam bagi Bani Qusyair, suatu hari pada saat shalat subuh dia membaca ayat FAIDZAA NUQIRA FIN NAAQUUR FADZAALIKA YAUMAIDZIN YAUMUN 'ASIIR (Apabila ditiup sangkakala, maka waktu itu adalah waktu (datangnya) hari yang sulit). Dia terjatuh dan pingsan, sedangkan saya adalah orang yang membawa kerumahnya."},"408":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ الْإِسْكَنْدَرَانِيُّ عَنْ سُ��َيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَنْزِلُ اللَّهُ إِلَى السَّمَاءِ الدُّنْيَا كُلَّ لَيْلَةٍ حِينَ يَمْضِي ثُلُثُ اللَّيْلِ الْأَوَّلُ فَيَقُولُ أَنَا الْمَلِكُ مَنْ ذَا الَّذِي يَدْعُونِي فَأَسْتَجِيبَ لَهُ مَنْ ذَا الَّذِي يَسْأَلُنِي فَأُعْطِيَهُ مَنْ ذَا الَّذِي يَسْتَغْفِرُنِي فَأَغْفِرَ لَهُ فَلَا يَزَالُ كَذَلِكَ حَتَّى يُضِيءَ الْفَجْرُقَالَ وَفِي الْبَاب عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ وَأَبِي سَعِيدٍ وَرِفَاعَةَ الْجُهَنِيِّ وَجُبَيْرِ بْنِ مُطْعِمٍ وَابْنِ مَسْعُودٍ وَأَبِي الدَّرْدَاءِ وَعُثْمَانَ بْنِ أَبِي الْعَاصِ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ أَوْجُهٍ كَثِيرَةٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرُوِيَ عَنْهُ أَنَّهُ قَالَ يَنْزِلُ اللَّهُ عَزَّ وَجَلَّ حِينَ يَبْقَى ثُلُثُ اللَّيْلِ الْآخِرُ وَهُوَ أَصَحُّ الرِّوَايَاتِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Ya'qub bin Abdurrahman Al Iskandarani] dari [Suhail bin Abu Shalih] dari [ayahnya] dari [Abu Hurairah] bahwasannya bersabda: \"Allah turun kelangit dunia setiap malamnya ketika telah berlalu sepertiga malam yang pertama, kemudian Dia berfirman; Saya adalah Raja, barang siapa yang berdo'a kepadaku niscaya Aku akan mengabulkannya, barang siapa yang meminta kepadaku niscaya Aku akan memberinya dan barang siapa yang meminta ampunan kepadaku niscaya Aku akan mengampuninya, dan Dia masih saja berfirman seperti itu sampai fajar menyingsing.\" (perawi) berkata, dan dalam bab ini (ada juga riwayat -pent) dari Ali bin Abu Thalib, Abu Sa'id Al Khudri, Rifa'ah Al Juhani, Jubair bin Muth'im, Ibnu Mas'ud, Abu Darda', dan Utsman bin Abul 'Ash. Abu Isa berkata, hadits riwayat Abu Hurairah adalah hadits hasan shahih, dan hadits ini juga diriwayatkan dari beberapa jalur dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam, dan diriwayatkan darinya bahwasannya beliau bersabda: \"Allah Azza Wa Jalla turun disepertiga malam yang terakhir.\" Ini adalah riwayat yang paling shahih."},"409":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا يَحْيَى بْنُ إِسْحَقَ هُوَ السَّالَحِينِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ الْأَنْصَارِيِّ عَنْ أَبِي قَتَادَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَبِي بَكْرٍ مَرَرْتُ بِكَ وَأَنْتَ تَقْرَأُ وَأَنْتَ تَخْفِضُ مِنْ صَوْتِكَ فَقَالَ إِنِّي أَسْمَعْتُ مَنْ نَاجَيْتُ قَالَ ارْفَعْ قَلِيلًا وَقَالَ لِعُمَرَ مَرَرْتُ بِكَ وَأَنْتَ تَقْرَأُ وَأَنْتَ تَرْفَعُ صَوْتَكَ قَالَ إِنِّي أُوقِظُ الْوَسْنَانَ وَأَطْرُدُ الشَّيْطَانَ قَالَ اخْفِضْ قَلِيلًاقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَأُمِّ هَانِئٍ وَأَنَسٍ وَأُمِّ سَلَمَةَ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَإِنَّمَا أَسْنَدَهُ يَحْيَى بْنُ إِسْحَقَ عَنْ حَمَّادِ بْنِ سَلَمَةَ وَأَكْثَرُ النَّاسِ إِنَّمَا رَوَوْا هَذَا الْحَدِيثَ عَنْ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ مُرْسَلًا","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Yahya bin Ishaq yaitu As Salahini] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit Al Bunani] dari [Abdullah bin Rabah Al Anshari] dari [Abu Qatadah] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada Abu Bakar: \"Saya melewatimu ketika kamu sedang membaca ayat kemudian kamu merendahkan suaramu.\" Maka dia (Abu Bakar radliallahu 'anhu) menjawab, sesungguhnya saya sedang memperdengarkan dzat yang saya bermunajat kepadanya, beliau bersabda: \"Keraskan sedikit suaramu.\" lalu beliau berkata kepada Umar: \"Saya melewatimu ketika kamu sedang membaca ayat kemudian kamu meninggikan suaramu.\" Maka dia (Umar RA) menjwab, sesungguhnya saya sedang membangunkan orang yang tertidur dan mengusir syetan. Kemudian beliau bersabda: \"Rendahkan sedikit suaramu.\" (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari A'isyah, Ummu Hani', Anas, Ummu Salamah, dan Ibnu Abbas. Abu Isa berkata, hadits ini gharib hanya saja yang memusnadkannya (menjadikannya bersambung sampai kepada Nabi) adalah Yahya bin Ishaq dari Hammad bin Salamah, padahal kebanyakan orang meriwayatkan hadits ini dari Tsabit dari Abdullah bin Rabah dengan Mursal."},"410":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ مُحَمَّدُ بْنُ نَافِعٍ الْبَصْرِيُّ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ عَنْ إِسْمَعِيلَ بْنِ مُسْلِ��ٍ الْعَبْدِيِّ عَنْ أَبِي الْمُتَوَكِّلِ النَّاجِيِّ عَنْ عَائِشَةَ قَالَتْقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِآيَةٍ مِنْ الْقُرْآنِ لَيْلَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abu Bakar Muhammad bin Nafi' Al Bashri] telah bercerita kepada kami [Abdush Shamad bin Abdul Warits] dari [Isma'I bin Muslim Al Abdi] dari [Abul Mutawakkil An Naji] dari [A'isyah] dia berkata, Nabi shallallahu 'alaihi wasallam melaksanakan shalat malam dengan membaca satu ayat dari Al Qur'an. Abu Isa berkata, dari jalur ini hadits ini hasan gharib."},"411":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَيْسٍ قَالَ سَأَلْتُ عَائِشَةَكَيْفَ كَانَتْ قِرَاءَةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ أَكَانَ يُسِرُّ بِالْقِرَاءَةِ أَمْ يَجْهَرُ فَقَالَتْ كُلُّ ذَلِكَ قَدْ كَانَ يَفْعَلُ رُبَّمَا أَسَرَّ بِالْقِرَاءَةِ وَرُبَّمَا جَهَرَ فَقُلْتُ الْحَمْدُ لِلَّهِ الَّذِي جَعَلَ فِي الْأَمْرِ سَعَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Mu'awiyah bin Shalih] dari [Abdullah bin Abu Qais] dia berkata, saya bertanya kepada ['Aisyah], bagaimanakah bacaan Nabi shallallahu 'alaihi wasallam pada waktu shalat malam, apakah beliau memelankan ataukah mengeraskan bacaannya? Dia menjawab, itu semua pernah dilakukan oleh beliau, terkadang beliau memelankan bacaannya dan terkadang pula beliau mengeraskan bacaannya. Saya berkata, segala puji bagi Allah yang telah menjadikan kelapangan dalam perkara ini. Abu Isa berkata, bahwa hadits ini hasan shahih gharib."},"412":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ سَالِمٍ أَبِي النَّضْرِ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ ثَابِتٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفْضَلُ صَلَاتِكُمْ فِي بُيُوتِكُمْ إِلَّا الْمَكْتُوبَةَقَالَ وَفِي الْبَاب عَنْ عُمَرَ بْنِ الْخَطَّابِ وَجَابِرِ بْنِ عَبْدِ اللَّهِ وَأَبِي سَعِيدٍ وَأَبِي هُرَيْرَةَ وَابْنِ عُمَرَ وَعَائِشَةَ وَعَبْدِ اللَّهِ بْنِ سَعْدٍ وَزَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَ أَبُو عِيسَى حَدِيثُ زَيْدِ بْنِ ثَابِتٍ حَدِيثٌ حَسَنٌ وَقَدْ اخْتَلَفَ النَّاسُ فِي رِوَايَةِ هَذَا الْحَدِيثِ فَرَوَى مُوسَى بْنُ عُقْبَةَ وَإِبْرَاهِيمُ بْنُ أَبِي النَّضْرِ عَنْ أَبِي النَّضْرِ مَرْفُوعًا وَرَوَاهُ مَالِكُ بْنُ أَنَسٍ عَنْ أَبِي النَّضْرِ وَلَمْ يَرْفَعْهُ وَأَوْقَفَهُ بَعْضُهُمْ وَالْحَدِيثُ الْمَرْفُوعُ أَصَحُّ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Abdullah bin Sa'id bin Abu Hindi] dari [Salim bin Abu Nadlr] dari [Busr bin Sa'id] dari [Zaid bin Tsabit] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sebaik-baik shalat yang kalian kerjakan adalah shalat dirumah-rumah kalian kecuali shalat wajib.\" (perawai) berkata, dalam bab ini (ada juga riwayat -pent) dari Umar bin Al Khaththab, Jabir bin Abdullah, Abu Sa'id, Abu Hurairah, Ibnu Umar, 'Aisyah, Abdullah bin Sa'ad dan Zaid bin Khalid Al Juhani. Abu Isa berkata, hadits riwayat Zaid bin Tsabit adalah hadits hasan, dan orang-orang berbeda pendapat mengenai riwayat hadits ini, [Musa bin 'Uqbah] dan [Ibrahim bin Abu An Nadlr] meriwayatkan dari [Abu An Nadlar] dengan merafa'kannya (mengangkatnya sampai kepada Nabi shallallahu 'alaihi wasallam), sedangkan Malik bin Anas meriwayatkannya dari Abu An Nadlr dengan tidak merafa'kannya, dan sebagian yang lain memauqufkannya, sedangkan riwayat yang merafa'kan adalah riwayat yang paling shahih."},"413":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلُّوا فِي بُيُوتِكُمْ وَلَا تَتَّخِذُوهَا قُبُورًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengkhabarkan kepada kami [Abdullah bin Numair] dari ['Ubaidillah bin Umar] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Shalatlah di rumah-rumah kalian dan janganlah kalian menjadikannya sebagai kuburan.\" Abu Isa berkata, ini adalah hadits hasan shahih."},"414":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَبْدِ اللَّهِ بْنِ رَاشِدٍ الزَّوْفِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُرَّةَ الزَّوْفِيِّ عَنْ خَارِجَةَ بْنِ حُذَافَةَ أَنَّهُ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ اللَّهَ أَمَدَّكُمْ بِصَلَاةٍ هِيَ خَيْرٌ لَكُمْ مِنْ حُمْرِ النَّعَمِ الْوِتْرُ جَعَلَهُ اللَّهُ لَكُمْ فِيمَا بَيْنَ صَلَاةِ الْعِشَاءِ إِلَى أَنْ يَطْلُعَ الْفَجْرُقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَبُرَيْدَةَ وَأَبِي بَصْرَةَ الْغِفَارِيِّ صَاحِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عِيسَى حَدِيثُ خَارِجَةَ بْنِ حُذَافَةَ حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ يَزِيدَ بْنِ أَبِي حَبِيبٍ وَقَدْ وَهِمَ بَعْضُ الْمُحَدِّثِينَ فِي هَذَا الْحَدِيثِ فَقَالَ عَنْ عَبْدِ اللَّهِ بْنِ رَاشِدٍ الزُّرَقِيِّ وَهُوَ وَهَمٌ فِي هَذَا وَأَبُو بَصْرَةَ الْغِفَارِيُّ اسْمُهُ حُمَيْلُ بْنُ بَصْرَةَ و قَالَ بَعْضُهُمْ جَمِيلُ بْنُ بَصْرَةَ وَلَا يَصِحُّ وَأَبُو بَصْرَةَ الْغِفَارِيُّ رَجُلٌ آخَرُ يَرْوِي عَنْ أَبِي ذَرٍّ وَهُوَ ابْنُ أَخِي أَبِي ذَرٍّ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Laits bin Sa'ad] dari [Yazid bin Abu Habib] dari [Abdullah bin Rasyid Az Zaufi] dari [Abdullah bin Abu Murrah Az Zaufi] dari [Kharijah bin Hudzafah] bahwa dia berkata, keluar menemui kami seraya bersabda: \"Sesungguhnya Allah telah menganugerahi kepada kalian shalat yang dia lebih baik dari unta merah, yaitu shalat witir, Allah telah jadikan waktunya bagi kalian antara shalat isya' sampai terbit fajar.\" (perawi) berkata, dalam bab ini, (ada juga riwayat -pent) dari Abu Hurairah, Abdullah bin Amr, Buraidah dan Abu Bashrah Al Ghifari seorang sahabat Rasulullah shallallahu 'alaihi wasallam. Abu Isa berkata, hadits Kharijah bin Hudzafah adalah hadits gharib, kami tidak mengetahuinya kecuali dari Hadits Yazid bin Abu Habib, sebagian Ahli hadits tertukar dalam masalah hadits ini dan mengatakan, dari Abdullah bin Rasyid Az Zuraqi, dan riwayat ini terbalik, adapun Abu Bashroh Al Ghifari namanya adalah Humail bin Bashrah, sebagian yang lain mengatakan Jamil bin Bashrah, tapi ini tidak benar. Adapun Abu Bashrah Al Ghifari adalah orang lain, dia telah meriwayatkan dari Abu Dzar dan dia adalah salah seorang anak saudara Abu Dzar."},"415":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيٍّ قَالَالْوِتْرُ لَيْسَ بِحَتْمٍ كَصَلَاتِكُمْ الْمَكْتُوبَةِ وَلَكِنْ سَنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ إِنَّ اللَّهَ وِتْرٌ يُحِبُّ الْوِتْرَ فَأَوْتِرُوا يَا أَهْلَ الْقُرْآنِقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَابْنِ مَسْعُودٍ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى حَدِيثُ عَلِيٍّ حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Bakar bin 'Ayyas] telah menceritakan kepada kami [Abu Ishaq] dari ['Ashim bin Dlamrah] dari [Ali] dia berkata, shalat witir tidaklah wajib sebagaimana shalat wajib kalian, akan tetapi ia merupakan sunnah Rasulullah shallallahu 'alaihi wasallam. Dan dia juga berkata, sesungguhnya Allah adalah witir (ganjil) dan menyukai dengan sesuatu yang ganjil, maka berwitirlah kalian wahai para ahli Qur'an. (perawi) berkata, dan dalam bab ini (ada juga riwayat -pent.) dari Ibnu Umar, Ibnu Mas'ud dan Ibnu 'Abbas. Abu Isa berkata, hadits Ali adalah hadits hasan."},"416":{"ar":"وَرَوَى سُفْيَانُ الثَّوْرِيُّ وَغَيْرُهُ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيٍّ قَالَالْوِتْرُ لَيْسَ بِحَتْمٍ كَهَيْئَةِ الصَّلَاةِ الْمَكْتُوبَةِ وَلَكِنْ سُنَّةٌ سَنَّهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا بِذَلِكَ مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ وَهَذَا أَصَحُّ مِنْ حَدِيثِ أَبِي بَكْرِ بْنِ عَيَّاشٍ وَقَدْ رَوَاهُ مَنْصُورُ بْنُ الْمُعْتَمِرِ عَنْ أَبِي إِسْحَقَ نَحْوَ رِوَايَةِ أَبِي بَكْرِ بْنِ عَيَّاشٍ","id":"[Sufyan At Tsauri] dan yang lainnya telah meriwayatkan dari [Abu Ishaq] dari ['Ashim bin Dlamrah] dari [Ali] dia berkata, shalat witir tidaklah wajib sebagaimana kewajiban shalat fardlu, akan tetapi ia merupakan sunnah yang disunnahkan oleh Rasulullah shallallahu 'alaihi wasallam. [Muhammad bin Basysyar] telah menceritakan kepada kami seperti itu, telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [IAbu Ishaq] dan ini adalah hadits yang paling shahih dari hadits riwayatnya Abu Bakar bin 'Ayyasy, dan [Manshur bin Al Mu'tamir] telah meriwayatkan telah meriwayatkannya dari [Abu Ishaq] seperti riwayatnya Abu Bakar bin 'Ayasy."},"417":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ إِسْرَائِيلَ عَنْ عِيسَى بْنِ أَبِي عَزَّةَ عَنْ الشَّعْبِيِّ عَنْ أَبِي ثَوْرٍ الْأَزْدِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أُوتِرَ قَبْلَ أَنْ أَنَامَقَالَ عِيسَى بْنُ أَبِي عَزَّةَ وَكَانَ الشَّعْبِيُّ يُوتِرُ أَوَّلَ اللَّيْلِ ثُمَّ يَنَامُ قَالَ وَفِي الْبَاب عَنْ أَبِي ذَرٍّ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَأَبُو ثَوْرٍ الْأَزْدِيُّ اسْمُهُ حَبِيبُ بْنُ أَبِي مُلَيْكَةَ وَقَدْ اخْتَارَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ أَنْ لَا يَنَامَ الرَّجُلُ حَتَّى يُوتِرَ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Yahya bin Zakaria bin Abu Za'idah] dari [Isra'il] dari [Isa bin Abu Azzah] dari [Asy Sya'bi] dari [Abu Tsaur Al Azdi] dari [Abu Hurairah] dia berkata, Rasulullah memerintahkan kepadaku agar melaksanakan shalat witir sebelum tidur. Isa bin Abu Azzah berkata, bahwa Asy Sya'bi melaksanakan witir di permulaan malam kemudian tidur. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Abu Dzar. Abu Isa berkata, dari jalur ini hadits Abu Hurairah adalah hadits hasan gharib, adapun Abu Tsaur Al Azdi namanya adalah Habib bin Abu Mulaikah, sebagian ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan orang orang setelah mereka memilih hendaknya seseorang tidak tidur sehingga dia berwitir."},"418":{"ar":"وَرُوِيَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ خَشِيَ مِنْكُمْ أَنْ لَا يَسْتَيْقِظَ مِنْ آخِرِ اللَّيْلِ فَلْيُوتِرْ مِنْ أَوَّلِهِ وَمَنْ طَمِعَ مِنْكُمْ أَنْ يَقُومَ مِنْ آخِرِ اللَّيْلِ فَلْيُوتِرْ مِنْ آخِرِ اللَّيْلِ فَإِنَّ قِرَاءَةَ الْقُرْآنِ فِي آخِرِ اللَّيْلِ مَحْضُورَةٌ وَهِيَ أَفْضَلُحَدَّثَنَا بِذَلِكَ هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ","id":"Telah diriwayatkan dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Barang siapa di antara kalian yang khawatir tidak bisa bangun diakhir malam, hendaknya melaksanakan shalat witir di awal malam, dan barang siapa diantara kalian yang sanggup untuk bangun diakhir malamnya, hendaknya melaksanakan shalat witir diakhir malam, karena sesungguhnya bacaan Al Qur'an di akhir malam adalah disaksikan (oleh para malaikat) dan ia merupakan (waktu) yang paling utama.\" Telah menceritakan dengan hadits itu kepada kami [Hannad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam dengan hadits itu."},"419":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ حَدَّثَنَا أَبُو حَصِينٍ عَنْ يَحْيَى بْنِ وَثَّابٍ عَنْ مَسْرُوقٍأَنَّهُ سَأَلَ عَائِشَةَ عَنْ وِتْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ مِنْ كُلِّ اللَّيْلِ قَدْ أَوْتَرَ أَوَّلَهُ وَأَوْسَطَهُ وَآخِرَهُ فَانْتَهَى وِتْرُهُ حِينَ مَاتَ إِلَى السَّحَرِقَالَ أَبُو عِيسَى أَبُو حَصِينٍ اسْمُهُ عُثْمَانُ بْنُ عَاصِمٍ الْأَسَدِيُّ قَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَجَابِرٍ وَأَبِي مَسْعُودٍ الْأَنْصَارِيِّ وَأَبِي قَتَادَةَ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ الَّذِي اخْتَارَهُ بَعْضُ أَهْلِ الْعِلْمِ الْوِتْرُ مِنْ آخِرِ اللَّيْلِ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Abu Bakar bin 'Ayasy] telah menceritakan kepada kami [Abu Hashin] dari [Yahya bin Watsab] dari [Masruq] bahwa dia bertanya kepada ['Aisyah] mengenai shalat witirnya Rasulullah Shallahu 'alaihi wa sallam, maka dia menjawab, terkadang beliau melaksanakan shalat witir diawal malam, ditengah malam dan terkadang diakhir malam, dan menjelang wafatnya beliau mengerjakan shalat witir sampai menjelang fajar, Abu Isa berkata, Abu Hashin namanya adalah 'Utsman bin 'Ashim Al Asadi, (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Ali, Jabir, Abu Mas'ud Al Anshari dan Abu Qatadah. Abu Isa berkata, haditsnya 'Aisyah adalah hadits hasan shahih, dan ia merupakan riwayat yang dipilih oleh sebagian ahli ilmu yaitu melaksanakan shalat witir diakhir malam."},"420":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ يَحْيَى بْنِ الْجَزَّارِ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِثَلَاثَ عَشْرَةَ رَكْعَةً فَلَمَّا كَبِرَ وَضَعُفَ أَوْتَرَ بِسَبْعٍقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ قَالَ أَبُو عِيسَى حَدِيثُ أُمِّ سَلَمَةَ حَدِيثٌ حَسَنٌ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَتْرُ بِثَلَاثَ عَشْرَةَ وَإِحْدَى عَشْرَةَ وَتِسْعٍ وَسَبْعٍ وَخَمْسٍ وَثَلَاثٍ وَوَاحِدَةٍ قَالَ إِسْحَقُ بْنُ إِبْرَاهِيمَ مَعْنَى مَا رُوِيَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ بِثَلَاثَ عَشْرَةَ قَالَ إِنَّمَا مَعْنَاهُ أَنَّهُ كَانَ يُصَلِّي مِنْ اللَّيْلِ ثَلَاثَ عَشْرَةَ رَكْعَةً مَعَ الْوِتْرِ فَنُسِبَتْ صَلَاةُ اللَّيْلِ إِلَى الْوِتْرِ وَرَوَى فِي ذَلِكَ حَدِيثًا عَنْ عَائِشَةَ وَاحْتَجَّ بِمَا رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ أَوْتِرُوا يَا أَهْلَ الْقُرْآنِ قَالَ إِنَّمَا عَنَى بِهِ قِيَامَ اللَّيْلِ يَقُولُ إِنَّمَا قِيَامُ اللَّيْلِ عَلَى أَصْحَابِ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Amru bin Murrah] dari [Yahya bin Jazzar] dari [Ummu Salamah] dia berkata, Nabi Shallahu 'alaihi wa sallam melaksanakan shalat witir tiga belas raka'at, namun tatkala beliau lanjut usia dan semakin lemah beliau berwitir tujuh raka'at. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari A'isyah. Abu Isa berkata, hadits Ummu Salamah adalah hadits hasan, bahwa telah diriwayatkan dari Nabi Shallahu 'alaihi wa sallam bahwa shalat witir sebanyak tiga belas raka'at, sebelas raka'at, sembilan raka'at, tujuh raka'at, lima raka'at, tiga raka'at dan satu raka'at. Ishaq bin Ibrihim berkata, maksud hadits yang telah diriwayatkan bahwa Nabi Shallahu 'alaihi wa sallam melaksanakan shalat witir sebanyak tiga belas raka'at, dia mengatakan bahwa maksudnya adalah Nabi Shallahu 'alaihi wa sallam shalat malam tiga belas raka'at bersama witir, maka shalat malam dinisbatkan kepada shalat witir, dalam hal itu telah diriwayatkan sebuah hadits dari A'isyah dengan berdalikan hadits yang diriwayatkan dari Nabi Shallahu 'alaihi wa sallam bahwa beliau bersabda: \"lakukanlah witir wahai ahli Al Qur'an!\" Ishaq berkata, bahwa maksudnya adalah shalat malam, dia mengatakan bahwa shalat malam bagi ahli Al Qur'an."},"421":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ الْكَوْسَجُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَتْ صَلَاةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ اللَّيْلِ ثَلَاثَ عَشْرَةَ رَكْعَةً يُوتِرُ مِنْ ذَلِكَ بِخَمْسٍ لَا يَجْلِسُ فِي شَيْءٍ مِنْهُنَّ إِلَّا فِي آخِرِهِنَّ فَإِذَا أَذَّنَ الْمُؤَذِّنُ قَامَ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِقَالَ وَفِي الْبَاب عَنْ أَبِي أَيُّوبَ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَأَى بَعْضُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ الْوِتْرَ بِخَمْسٍ وَقَالُوا لَا يَجْلِسُ فِي شَيْءٍ مِنْهُنَّ إِلَّا فِي آخِرِهِنَّ قَالَ أَبُو عِيسَى وَسَأَلْتُ أَبَا مُصْعَبٍ الْمَدِينِيَّ عَنْ هَذَا الْحَدِيثِ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِالتِّسْعِ وَالسَّبْعِ قُلْتُ كَيْفَ يُوتِرُ بِالتِّسْعِ وَالسَّبْعِ قَالَ يُصَلِّي مَثْنَى مَثْنَى وَيُسَلِّمُ وَيُوتِرُ بِوَاحِدَةٍ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur Al Kausaj] telah menceritakan kepada kami [Abdullah bin Numair] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [ayahnya] dari ['Aisyah] dia berkata, bahwa shalat malamnya Nabi Shallahu 'alaihi wa sallam sebanyak tiga belas raka'at termasuk witir sebanyak lima raka'at, beliau tidak duduk kecuali diakhir raka'atnya, jika seorang mu'adzin mengumandangkan adzan, beliau melanjutkan shalat dua raka'at dengan ringan. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Abu Ayub. Abu Isa berkata, haditsnya 'Aisyah adalah hadits hasan shahih, sebagian ulama telah meriwayatkan dari para sahabat Nabi Shallahu 'alaihi wa sallam dan yang lainnya bahwa beliau mengerjakan shalat witir sebanyak lima raka'at, mereka berkata, beliau tidak duduk kecuali setelah raka'at yang terakhir. Ani Isa berkata, saya bertanya kepada Abu Mush'ab Al Madini mengenai hadits ini bahwa Nabi Shallahu 'alaihi wa sallam mengerjakan witir sebanyak sembilan dan tujuh raka'at. Saya bertanya, bagaiman beliau mengerjakan shalat witir sebanyak sembilan dan tujuh raka'at? Dia menjawab, beliau shalat dua raka'at-dua raka'at, kemudian beliau salam dan witir satu raka'at."},"422":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِثَلَاثٍ يَقْرَأُ فِيهِنَّ بِتِسْعِ سُوَرٍ مِنْ الْمُفَصَّلِ يَقْرَأُ فِي كُلِّ رَكْعَةٍ بِثَلَاثِ سُوَرٍ آخِرُهُنَّ قُلْ هُوَ اللَّهُ أَحَدٌقَالَ وَفِي الْبَاب عَنْ عِمْرَانَ بْنِ حُصَيْنٍ وَعَائِشَةَ وَابْنِ عَبَّاسٍ وَأَبِي أَيُّوبَ وَعَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أُبَيِّ بْنِ كَعْبٍ وَيُرْوَى أَيْضًا عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا رَوَى بَعْضُهُمْ فَلَمْ يَذْكُرُوا فِيهِ عَنْ أُبَيٍّ وَذَكَرَ بَعْضُهُمْ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أُبَيٍّ قَالَ أَبُو عِيسَى وَقَدْ ذَهَبَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ إِلَى هَذَا وَرَأَوْا أَنْ يُوتِرَ الرَّجُلُ بِثَلَاثٍ قَالَ سُفْيَانُ إِنْ شِئْتَ أَوْتَرْتَ بِخَمْسٍ وَإِنْ شِئْتَ أَوْتَرْتَ بِثَلَاثٍ وَإِنْ شِئْتَ أَوْتَرْتَ بِرَكْعَةٍ قَالَ سُفْيَانُ وَالَّذِي أَسْتَحِبُّ أَنْ أُوتِرَ بِثَلَاثِ رَكَعَاتٍ وَهُوَ قَوْلُ ابْنِ الْمُبَارَكِ وَأَهْلِ الْكُوفَةِ حَدَّثَنَا سَعِيدُ بْنُ يَعْقُوبَ الطَّالَقَانِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ هِشَامٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَ كَانُوا يُوتِرُونَ بِخَمْسٍ وَبِثَلَاثٍ وَبِرَكْعَةٍ وَيَرَوْنَ كُلَّ ذَلِكَ حَسَنًا","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Bakar bin 'Ayyasy] dari [Abu Ishaq] dari [Al Harits] dari [Ali] dia berkata, bahwa Nabi Shallahu 'alaihi wa sallam shalat witir sebanyak tiga raka'at, beliau membaca sembilan surat dengan disambung, dalam satu raka'at beliau membaca tiga surat sekaligus, dan diraka'at terakhir beliau membaca QUL HUWALLAHU AHAD. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Imaran bin Hushain, 'Aisyah, Ibnu Abbas, Abu Ayyub, Abdurrahman bin Abza dari Ubay bin Ka'ab. Diriwayatkan pula dari Abdurrahman bin Abza dari Nabi Shallahu 'alaihi wa sallam. Ini seperti yang diriwayatkan sebagian dari mereka dengan tidak menyebutkan dari Ubay, dan sebagian yang lain menyebutkan dari Abdurrahman bin Abza dari Ubay. Abu Isa berkata, para ulama dari kalangan sahabat Nabi Shallahu 'alaihi wa sallam dan yang lainnya berpendapat dengan hadits ini yaitu hendaknya seseorang mengerjakan shalat witir sebanyak tiga raka'at. Sufyan berkata, jika kamu berkehendak boleh mengerjakan witir sebanyak lima raka'at, tiga raka'at dan jika mau, kamu bisa mengerjakan cuma hanya satu raka'at. Sufyan berkata, dan saya menganjurkan untuk mengerjakan shalat witir sebanyak tiga raka'at, ini adalah perkataan Ibnu Mubarak dan penduduk Kufah. Telah menceritakan kepada kami sa'id bin Ya'qub At Thalaqani telah menceritakan kepada kami Hammad bin Zaid dari Hisyam dari Muhammad bin Sirin dia berkata, mereka mengerjakan shalat witir sebanyak lima raka'at, tiga raka'at bahkan satu raka'at, dan mereka menganggap semuanya baik."},"423":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَنَسِ بْنِ سِيرِينَ قَالَسَأَلْتُ ابْنَ عُمَرَ فَقُلْتُ أُطِيلُ فِي رَكْعَتَيْ الْفَجْرِ فَقَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ مَثْنَى مَثْنَى وَيُوتِرُ بِرَكْعَةٍ وَكَانَ يُصَلِّي الرَّكْعَتَيْنِ وَالْأَذَانُ فِي أُذُنِهِ يَعْنِي يُخَفِّفُقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَجَابِرٍ وَالْفَضْلِ بْنِ عَبَّاسٍ وَأَبِي أَيُّوبَ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالتَّابِعِينَ رَأَوْا أَنْ يَفْصِلَ الرَّجُلُ بَيْنَ الرَّكْعَتَيْنِ وَالثَّالِثَةِ يُوتِرُ بِرَكْعَةٍ وَبِهِ يَقُولُ مَالِكٌ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad bin Zaid] dari [Anas bin Sirin] dia berkata, saya bertanya kepada [Ibnu Umar] seraya berkata, saya memanjangkan dalam dua raka'at shalat fajar, maka dia berkata, adalah Rasulullah Shallahu 'alaihi wa sallam mengerjakan shalat malam dua raka'at-dua raka'at, lalu witir satu raka'at, beliau mengerjakan sunnah (fajar) dua raka'at dengan ringan (cepat) seakan-akan telah terdengar adzan ditelinganya. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari 'Aisyah, Jabir, Fadll bin 'Abbas, Abu Ayyub dan Ibnu Abbas. Abu Isa berkata, haditsnya Ibnu Umar adalah hadits hasan shahih. Hadits ini juga diamalkan oleh sebagian ahli ilmu dari kalangan para sahabat Nabi Shallahu 'alaihi wa sallam dan para tabi'in, mereka berpendapat, hendaknya seseorang memisahkan antara raka'at kedua dan raka'at ketiga dengan witir satu raka'at, dengannya pula Malik, Syafi'i, Ahmad dan Ishaq berkata."},"424":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْوِتْرِ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ فِي رَكْعَةٍ رَكْعَةٍقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَعَائِشَةَ وَعَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أُبَيِّ بْنِ كَعْبٍ وَيُرْوَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عِيسَى وَقَدْ رُ��ِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَرَأَ فِي الْوِتْرِ فِي الرَّكْعَةِ الثَّالِثَةِ بِالْمُعَوِّذَتَيْنِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالَّذِي اخْتَارَهُ أَكْثَرُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ أَنْ يَقْرَأَ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ يَقْرَأُ فِي كُلِّ رَكْعَةٍ مِنْ ذَلِكَ بِسُورَةٍ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah mengabarkan kepada kami [Syarik] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata, adalah Nabi Shallahu 'alaihi wa sallam dalam shalat witirnya membaca SABBIHISMA RABBIKAL A'LA dan QUL YAA AYYUHAL KAAFIRUUN dan QUL HUWALLAHU AHAD dalam setiap raka'atnya. Dalam bab ini (ada juga riwayat -pent) dari Ali, 'Aisyah dan Abdurrahman bin Abza dari Ubay bin Ka'ab. Diriwayatkan dari Abdurrahman bin Abza dari Nabi Shallahu 'alaihi wa sallam. Abu Isa berkata, telah diriwayatkan dari Nabi Shallahu 'alaihi wa sallam bahwa diraka'at ketiga dalam shalat witir beliau membaca QUL HUWALLAHU AHAD. Dan (hadits) yang dipilih oleh kebanyakan ulama dari kalangan para sahabat Nabi Shallahu 'alaihi wa sallam dan orang-orang setelahnya adalah membaca SABBIHISMA RABBIKAL A'LA dan QUL YAA AYYUHAL KAAFIRUUN dan QUL HUWALLAHU AHAD disetiap raka'at dari surat tersebut."},"425":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ حَبِيبِ بْنِ الشَّهِيدِ الْبَصْرِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ الْحَرَّانِيُّ عَنْ خُصَيْفٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ جُرَيْجٍ قَالَسَأَلْنَا عَائِشَةَ بِأَيِّ شَيْءٍ كَانَ يُوتِرُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كَانَ يَقْرَأُ فِي الْأُولَى بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَفِي الثَّانِيَةِ بِقُلْ يَا أَيُّهَا الْكَافِرُونَ وَفِي الثَّالِثَةِ بِقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ قَالَ وَعَبْدُ الْعَزِيزِ هَذَا هُوَ وَالِدُ ابْنِ جُرَيْجٍ صَاحِبِ عَطَاءٍ وَابْنُ جُرَيْجٍ اسْمُهُ عَبْدُ الْمَلِكِ بْنُ عَبْدِ الْعَزِيزِ بْنِ جُرَيْجٍ وَقَدْ رَوَى يَحْيَى بْنُ سَعِيدٍ الْأَنْصَارِيُّ هَذَا الْحَدِيثَ عَنْ عَمْرَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim bin Habib bin Syahid Al Bashri] telah menceritakan kepada kami [Muhammad bin Salamah Al Harrani] dari [Khushaif] dari ['Abdul Aziz bin Juraij] dia berkata, kami bertanya kepada ['Aisyah] dengan (surat) apakah Rasulullah Shallahu 'alaihi wa sallam membaca dalam witir? Dia menjawab, pada raka'at pertama beliau membaca SABBIHISMA RABBIKAL 'A'LA, pada raka'at kedua beliau membaca QUL YAA AYYUHAL KAAFIRUUN dan pada raka'at ketiga beliau membaca QUL HUWALLAAHU AHAD dan AL MU'AWWIDZATAIN (surat Al Falaq dan An Nas). Abu Isa berkata, hadits ini hasan gharib, dia berkata, 'Abdul Aziz adalah bapaknya Ibnu Juraij sahabat Atha', dan Ibnu Juraij namanya adalah 'Abdul Malik bin Abdul 'Aziz bin Juraij, [Yahya bin Sa'id Al Anshari] telah meriwayatkan hadits ini dari [Amruah] dari ['Aisyah] dari Nabi Shallahu 'alaihi wa sallam."},"426":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ أَبِي الْحَوْرَاءِ السَّعْدِيِّ قَالَ قَالَ الْحَسَنُ بْنُ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُمَاعَلَّمَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلِمَاتٍ أَقُولُهُنَّ فِي الْوِتْرِ اللَّهُمَّ اهْدِنِي فِيمَنْ هَدَيْتَ وَعَافِنِي فِيمَنْ عَافَيْتَ وَتَوَلَّنِي فِيمَنْ تَوَلَّيْتَ وَبَارِكْ لِي فِيمَا أَعْطَيْتَ وَقِنِي شَرَّ مَا قَضَيْتَ فَإِنَّكَ تَقْضِي وَلَا يُقْضَى عَلَيْكَ وَإِنَّهُ لَا يَذِلُّ مَنْ وَالَيْتَ تَبَارَكْتَ رَبَّنَا وَتَعَالَيْتَقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ أَبِي الْحَوْرَاءِ السَّعْدِيِّ وَاسْمُهُ رَبِيعَةُ بْنُ شَيْبَانَ وَلَا نَعْرِفُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْقُنُوتِ فِي الْوِتْرِ شَيْئًا أَحْسَنَ مِنْ هَذَا وَاخْتَلَفَ أَهْلُ الْعِلْمِ فِي الْقُنُوتِ فِي الْوِتْرِ فَرَأَى عَبْدُ اللَّهِ بْنُ مَسْعُودٍ الْقُنُوتَ فِي الْوِتْرِ فِي السَّنَةِ كُلِّهَا وَاخْتَارَ الْقُنُوتَ قَبْلَ الرُّكُوعِ وَهُوَ قَوْلُ بَعْضِ أَهْلِ الْعِلْمِ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَإِسْحَقُ وَأَهْلُ الْكُوفَةِ وَقَدْ رُوِيَ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ أَنَّهُ كَانَ لَا يَقْنُتُ إِلَّا فِي النِّصْفِ الْآخِرِ مِنْ رَمَضَانَ وَكَانَ يَقْنُتُ بَعْدَ الرُّكُوعِ وَقَدْ ذَهَبَ بَعْضُ أَهْلِ الْعِلْمِ إِلَى هَذَا وَبِهِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Buraid bin Abu Maryam] dari [Abu Al Khaura' As Sa'di] dia berkata, [Al Hasan bin Ali] radliallahu 'anhuma berkata, Rasulullah Shallahu 'alaihi wa sallam mengajariku beberapa kalimat yang saya ucapkan dalam shalat witir, yaitu ALLAHUMMAHDINI FIIMAN HADAIT, WA'AAFINI FIIMAN 'AFAIT, WATAWALLANII FIIMAN TAWALLAIT, WABAARIK LII FIIMA A'THAIT, WAQINII SYARRAMA QADLAIT, FAINNAKA TAQDLI WALAA YUQDLA 'ALAIK, WAINNAHU LAA YADZILLU MAN WAALAIT, TABAARAKTA RABBANA WATA'AALAIT. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Ali. Abu Isa berkata, ini adalah hadits hasan, kami tidak mengetahui (jalur periwayatannya) selain dari jalur ini, dari hadits Abu Al Khaura' As Sa'di dan namanya adalah Rabi'ah bin Syaiban, kami juga tidak mengetahui dari Nabi Shallahu 'alaihi wa sallam sesuatupun dari qunut witir yang lebih bagus dari ini. Para ulama berbeda-beda mengenai masalah qunut witir, Abdullah bin Mas'ud berpendapat qunut witir dikerjakan disetiap tahunnya, sebagian ulama memilih untuk mengerjakan qunut sebelum ruku' diantaranya adalah perkataan Sufyan At Tsauri, Ibnu Mubarak, Ishaq dan penduduk Kufah. Telah diriwayatkan dari Ali bin Abu Thalib bahwa dia tidak melaksanakan qunut melainkan di pertengahan akhir bulan Ramadlan, dan melaksanakan qunut setelah ruku', sebagian para ulam juga berpendapat seperti ini, seperti perkataan Syafi'i dan Ahmad."},"427":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَامَ عَنْ الْوِتْرِ أَوْ نَسِيَهُ فَلْيُصَلِّ إِذَا ذَكَرَ وَإِذَا اسْتَيْقَظَ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Abdurrahman bin Zaid bin Aslam] dari [ayahnya] dari [Atha' bin Yasar] dari [Abu Sa'id Al Khudri] dia berkata, Rasulullah Shallahu 'alaihi wa sallam bersabda: \"Barang siapa yang tertidur dari (tidak mengerjakan) shalat witir atau lupa, hendaknya ia shalat waktu ia ingat atau disaat ia terbangun.\""},"428":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نَامَ عَنْ وِتْرِهِ فَلْيُصَلِّ إِذَا أَصْبَحَقَالَ أَبُو عِيسَى وَهَذَا أَصَحُّ مِنْ الْحَدِيثِ الْأَوَّلِ قَالَ أَبُو عِيسَى سَمِعْت أَبَا دَاوُدَ السِّجْزِيَّ يَعْنِي سُلَيْمَانَ بْنَ الْأَشْعَثِ يَقُولُ سَأَلْتُ ��َحْمَدَ بْنَ حَنْبَلٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ زَيْدِ بْنِ أَسْلَمَ فَقَالَ أَخُوهُ عَبْدُ اللَّهِ لَا بَأْسَ بِهِ قَالَ و سَمِعْت مُحَمَّدًا يَذْكُرُ عَنْ عَلِيِّ بْنِ عَبْدِ اللَّهِ أَنَّهُ ضَعَّفَ عَبْدَ الرَّحْمَنِ بْنَ زَيْدِ بْنِ أَسْلَمَ و قَالَ عَبْدُ اللَّهِ بْنُ زَيْدِ بْنِ أَسْلَمَ ثِقَةٌ قَالَ وَقَدْ ذَهَبَ بَعْضُ أَهْلِ الْعِلْمِ بِالْكُوفَةِ إِلَى هَذَا الْحَدِيثِ فَقَالُوا يُوتِرُ الرَّجُلُ إِذَا ذَكَرَ وَإِنْ كَانَ بَعْدَ مَا طَلَعَتْ الشَّمْسُ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ","id":"Telah menceritakan kepada kami [Qutaibah] telah bercerita kepada kami [Abdullah bin Zaid bin Aslam] dari [bapaknya] bahwa Nabi Shallahu 'alaihi wa sallam bersabda: \"Barangsiapa yang tertidur tanpa witir, maka hendaklah dia shalat di pagi harinya.\" Abu Isa berkata, hadits ini lebih shahih dari hadits yang pertama. Abu Isa berkata, saya mendengar Abu Daud As Sajzi yaitu Sulaiman bin Al Asy'ats berkata, saya bertanya kepada Ahmad bin Hambal tentang Abdurrahman bin Zaid bin Aslam, dia menjawab, dia adalah saudaranya Abdullah, dia tidak apa-apa (tidak ada masalah). Dia (Abu Isa) berkata, saya mendengar Muhammad menyebutkan tentang Ali bin Abdullah bahwa dia melemahkan (riwayat) Abdurrahman bin Zaid bin Aslam, dia berkata, Abdullah bin Zaid bin Aslam adalah Tsiqah. Dia (Abu Isa) berkata, sebagian ahli ilmu di kuffah berpendapat dengan hadits ini, mereka mengatakan, hendaknya seseorang melakukan witir ketika mengingatnya walaupun matahari telah terbit dan ini adalah pendapat Sufyan Ats Tsauri."},"429":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَادِرُوا الصُّبْحَ بِالْوِتْرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Yahya bin Zakariya bin Abu Zaidah] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwasannya Nabi Shallahu 'alaihi wa sallam bersabda: \"Bersegeralah kalian melaksanakan shalat witir menjelang shubuh.\" Abu Isa berkata, ini adalah hadits hasan shahih."},"430":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْتِرُوا قَبْلَ أَنْ تُصْبِحُوا","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Yahya bin Abu Katsir] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri] dia berkata, Rasulullah Shallahu 'alaihi wa sallam bersabda: \"Kerjakanlah shalat witir sebelum kalian shalat subuh.\""},"431":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا طَلَعَ الْفَجْرُ فَقَدْ ذَهَبَ كُلُّ صَلَاةِ اللَّيْلِ وَالْوِتْرُ فَأَوْتِرُوا قَبْلَ طُلُوعِ الْفَجْرِقَالَ أَبُو عِيسَى وَسُلَيْمَانُ بْنُ مُوسَى قَدْ تَفَرَّدَ بِهِ عَلَى هَذَا اللَّفْظِ وَرُوِي عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا وِتْرَ بَعْدَ صَلَاةِ الصُّبْحِ وَهُوَ قَوْلُ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ وَبِهِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ لَا يَرَوْنَ الْوِتْرَ بَعْدَ صَلَاةِ الصُّبْحِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] dari [Sulaiman bin Musa] dari [Nafi'] dari [Ibnu Umar] dari Nabi Shallahu 'alaihi wa sallam beliau bersabda: \"Jika fajar telah terbit, dan telah habis waktu untuk mengerjakan shalat malam serta shalat witir, maka kerjakanlah shalat witir sebelum terbitnya fajar (matahari).\" Abu Isa dan Sulaiman bin Musa berkata, lafalz hadits ini riwayatnya sendiri (tidak ada yang lain) dan telah diriwayatkan dari Nabi Shallahu 'alaihi wa sallam bahwa beliau bersabda: \"Tidak ada witir setelah shalat subuh.\" ini adalah perkataan kebanyakan para ulama, sebagaimana perkataan Syafi'i, Ahmad dan Ishaq, mereka berpendapat bahwa tidak ada witir setelah shalat shubuh."},"432":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا مُلَازِمُ بْنُ عَمْرٍو حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بَدْرٍ عَنْ قَيْسِ بْنِ طَلْقِ بْنِ عَلِيٍّ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا وِتْرَانِ فِي لَيْلَةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَاخْتَلَفَ أَهْلُ الْعِلْمِ فِي الَّذِي يُوتِرُ مِنْ أَوَّلِ اللَّيْلِ ثُمَّ يَقُومُ مِنْ آخِرِهِ فَرَأَى بَعْضُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ نَقْضَ الْوِتْرِ وَقَالُوا يُضِيفُ إِلَيْهَا رَكْعَةً وَيُصَلِّي مَا بَدَا لَهُ ثُمَّ يُوتِرُ فِي آخِرِ صَلَاتِهِ لِأَنَّهُ لَا وِتْرَانِ فِي لَيْلَةٍ وَهُوَ الَّذِي ذَهَبَ إِلَيْهِ إِسْحَقُ وَقَالَ بَعْضُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ إِذَا أَوْتَرَ مِنْ أَوَّلِ اللَّيْلِ ثُمَّ نَامَ ثُمَّ قَامَ مِنْ آخِرِ اللَّيْلِ فَإِنَّهُ يُصَلِّي مَا بَدَا لَهُ وَلَا يَنْقُضُ وِتْرَهُ وَيَدَعُ وِتْرَهُ عَلَى مَا كَانَ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَمَالِكِ بْنِ أَنَسٍ وَابْنِ الْمُبَارَكِ وَالشَّافِعِيِّ وَأَهْلِ الْكُوفَةِ وَأَحْمَدَ وَهَذَا أَصَحُّ لِأَنَّهُ قَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ صَلَّى بَعْدَ الْوِتْرِ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Mulazim bin Amru] telah menceritakan kepada kami [Abdullah bin Badr] dari [Qais bin Thalq bin Ali] dari [ayahnya] dia berkata, saya mendengar Rasulullah Shallahu 'alaihi wa sallam bersabda: \"Tidak ada dua kali witir dalam satu malam.\" Abu Isa berkata, hadits ini hasan gharib, ahli ilmu berbeda pendapat tentang orang yang melaksanakan witir di permulaan malam, kemudian dia bangun pada akhir malam. sebagian ahli ilmu dari kalangan sahabat Nabi Shallahu 'alaihi wa sallam dan orang orang setelahnya berpendapat membatalkan witir, mereka mengatakan ditambahkan kepada witir satu raka'at, kemudian shalat menurut yang nampak baginya lalu melaksanakan witir di akhir shalatnya, karena tidak ada witir dua kali dalam satu malam dan itulah yang menjadi pendapat Ishaq, sedangkan sebagian Ahli ilmu yang lain dari kalangan sahabat dan yang lainnya berpendapat bahwa jika telah melaksanakan witir di permulaan malam kemudian tidur, lalu bangun di akhir malam, maka dia melaksanakan shalat menurut yang nampak bagi dia dan jangan membatalkan witirnya (yang di permulaan malam) dan membiarkan witir yang telah dia laksanakan seperti semula, ini adalah pendapat Sufyan Ats Tsauri, Malik bin Anas, Bin Al Mubarak, Syafi'I, penduduk Kufah dan Ahmad, ini adalah pendapat yang paling shahih, karena haditsnya telah diriwayatkan dari berbagai jalur bahwa Nabi Shallahu 'alaihi wa sallam melaksanakan shalat setelah witir."},"433":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا حَمَّادُ بْنُ مَسْعَدَةَ عَنْ مَيْمُونِ بْنِ مُوسَى الْمَرَئِيِّ عَنْ الْحَسَنِ عَنْ أُمِّهِ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي بَعْدَ الْوِتْرِ رَكْعَتَيْنِقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ نَحْوُ هَذَا عَنْ أَبِي أُمَامَةَ وَعَائِشَةَ وَغَيْرِ وَاحِدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Hammad bin Mas'adah] dari [Maimun bin Musa Al Mara'I] dari [Al Hasan] dari [ibunya] dari [Ummu Salamah] bahwa Nabi Shallahu 'alaihi wa sallam melaksanakan shalat dua raka'at setelah melaksanakan shalat witir. Abu Isa berkata, hadits ini telah diriwayatkan semakna dengannya dari Abu Umamah, A'isyah dan yang lainnya dari Nabi Shallahu 'alaihi wa sallam."},"434":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ أَبِي بَكْرِ بْنِ عُمَرَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ سَعِيدِ بْنِ يَسَارٍ قَالَكُنْتُ أَمْشِي مَعَ ابْنِ عُمَرَ فِي سَفَرٍ فَتَخَلَّفْتُ عَنْهُ فَقَالَ أَيْنَ كُنْتَ فَقُلْتُ أَوْتَرْتُ فَقَالَ أَلَيْسَ لَكَ فِي رَسُولِ اللَّهِ أُسْوَةٌ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ عَلَى رَاحِلَتِهِقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ ذَهَبَ بَعْضُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ إِلَى هَذَا وَرَأَوْا أَنْ يُوتِرَ الرَّجُلُ عَلَى رَاحِلَتِهِ وَبِهِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ لَا يُوتِرُ الرَّجُلُ عَلَى الرَّاحِلَةِ وَإِذَا أَرَادَ أَنْ يُوتِرَ نَزَلَ فَأَوْتَرَ عَلَى الْأَرْضِ وَهُوَ قَوْلُ بَعْضِ أَهْلِ الْكُوفَةِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Malik bin Anas] dari [Abu Bakar bin Umar bin Abdurrahman] dari [Sa'id bin Yasar] dia berkata, saya berjalan bersama [Ibnu Umar] dalam suatu perjalanan, lantas saya menghilang darinya, dia berkata, dimanakah kamu? Saya menjawab, saya melaksanakan shalat witir, maka dia berkata, tidakkah pada diri Rasulullah Shallahu 'alaihi wa sallam terdapat teladan yang baik untukmu? Saya pernah melihat Rasulullah Shallahu 'alaihi wa sallam shalat witir diatas kendaraan. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Ibnu Abbas. Abu Isa berkata, hadits Ibnu Umar adalah hadits hasan shahih, sebagian ulama dari kalangan sahabat Nabi Shallahu 'alaihi wa sallam dan yang lainnya berpendapat atas hadits ini, yaitu hendaknya seseorang mengerjakan shalat witir diatas kendaradliallahu 'anhannya (jika bepergian), ini sebagaimana perkataan Syafi'i, Ahmad dan Ishaq. Sebagian ahli ilmu dari penduduk Kufah berpendapat bahwa hendaknya seseorang tidak melaksanakan shalat witir diatas kendaradliallahu 'anhannya, yaitu hendaknya dia turun dari kendaradliallahu 'anhannya jika ingin melaksanakan shalat witir."},"435":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ قَالَ حَدَّثَنِي مُوسَى بْنُ فُلَانِ بْنِ أَنَسٍ عَنْ عَمِّهِ ثُمَامَةَ بْنِ أَنَسِ بْنِ مَالِكٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى الضُّحَى ثِنْتَيْ عَشْرَةَ رَكْعَةً بَنَى اللَّهُ لَهُ قَصْرًا مِنْ ذَهَبٍ فِي الْجَنَّةِقَالَ وَفِي الْبَاب عَنْ أُمِّ هَانِئٍ وَأَبِي هُرَيْرَةَ وَنُعَيْمِ بْنِ هَمَّارٍ وَأَبِي ذَرٍّ وَعَائِشَةَ وَأَبِي أُمَامَةَ وَعُتْبَةَ بْنِ عَبْدٍ السُّلَمِيِّ وَابْنِ أَبِي أَوْفَى وَأَبِي سَعِيدٍ وَزَيْدِ بْنِ أَرْقَمَ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى حَدِيثُ أَنَسٍ حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al Ala'] telah menceritakan kepada kami [Yunus bin Bukair] dari [Muhammad bin Ishaq] dia berkata, telah menceritakan kepadaku [Musa bin Fulan bin Anas] dari pamannya yaitu [Tsumamah bin Anas bin Malik] dari [Anas bin Malik] dia berkata, Rasulullah Shallahu 'alaihi wa sallam bersabda: \"Barangsiapa yang melaksanakan shalat dluha dua belas raka'at, niscaya Allah akan membuatkan baginya sebuah istana dari emas di syurga.\" (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Ummu Hani', Abu Hurairah, Nu'aim bin Hammar, Abu Dzar, 'Aisyah, Abu Umamah, Utbah bin 'Abd As Sulami, Ibnu Abu Aufa, Abu Sa'id, Zaid bin Arqam dan Ibnu Abbas. Abu Isa berkata, hadits Anas adalah hadits gharib, kami tidak mengetahuinya kecuali dari jalur ini."},"436":{"ar":"حَدَّثَنَا أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ أَخْبَرَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَالَمَا أَخْبَرَنِي أَحَدٌ أَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الضُّحَى إِلَّا أُمَّ هَانِئٍ فَإِنَّهَا حَدَّثَتْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ بَيْتَهَا يَوْمَ فَتْحِ مَكَّةَ فَاغْتَسَلَ فَسَبَّحَ ثَمَانَ رَكَعَاتٍ مَا رَأَيْتُهُ صَلَّى صَلَاةً قَطُّ أَخَفَّ مِنْهَا غَيْرَ أَنَّهُ كَانَ يُتِمُّ الرُّكُوعَ وَالسُّجُودَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَكَأَنَّ أَحْمَدَ رَأَى أَصَحَّ شَيْءٍ فِي هَذَا الْبَابِ حَدِيثَ أُمِّ هَانِئٍ وَاخْتَلَفُوا فِي نُعَيْمٍ فَقَالَ بَعْضُهُمْ نُعَيْمُ بْنُ خَمَّارٍ و قَالَ بَعْضُهُمْ ابْنُ هَمَّارٍ وَيُقَالُ ابْنُ هَبَّارٍ وَيُقَالُ ابْنُ هَمَّامٍ وَالصَّحِيحُ ابْنُ هَمَّارٍ وَأَبُو نُعَيْمٍ وَهِمَ فِيهِ فَقَالَ ابْنُ حِمَازٍ وَأَخْطَأَ فِيهِ ثُمَّ تَرَكَ فَقَالَ نُعَيْمٌ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عِيسَى و أَخْبَرَنِي بِذَلِكَ عَبْدُ بْنُ حُمَيْدٍ عَنْ أَبِي نُعَيْمٍ","id":"Telah menceritakan kepada kami [Abu Musa Muhammad bin Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah mengabarkan kepada kami [Syu'bah] dari [Amru bin Murrah] dari [Abdurrahman bin Abu Laila] dia berkata, telah mengabarkan kepadaku seseorang bahwa dia melihat Nabi Shallahu 'alaihi wa sallam shalat dluha, kecuali [Ummu Hani'] bahwa dia menceritakan bahwa Rasulullah Shallahu 'alaihi wa sallam masuk kerumahnya pada ahari penaklukan kota Makkah, kemudian beliau mandi dan bertasbih (shalat) delapan raka'at, saya tidak pernah melihat beliau mengerjakan shalat lebih ringan daripadanya (shalat dluha), melainkan beliau menyempurnakan ruku' dan sujud. Abu Isa berkata, ini adalah hadits hasan shahih, sepertinya Ahmad berpendapat bahwa hadits yang paling shahih adalah hadits riwayat Ummu Hani', dan mereka berselisih mengenai Nu'aim, sebagian mereka mengatakan bahwa dia adalah Nu'aim bin Khammar dan sebagian yang lain mengatakan bahwa dia adalah Ibnu Hammar, dikatakan pula Ibnu Habbar atau Ibnu Hammam, sedangkan yang shahih adalah Ibnu Hammar. Dan Abu Nu'aim ragu mengenainya, Ibnu Himmaz berkata, bahwa menyalahkan kemudian meninggalkannya, Nu'aim berkata, dari Nabi Shallahu 'alaihi wa sallam. Abu Isa berkata, telah mengabarkan kepadaku 'Abdu bin Humaid dari Abu Nu'aim seperti riwayat tersebut."},"437":{"ar":"حَدَّثَنَا أَبُو جَعْفَرٍ السِّمْنَانِيُّ حَدَّثَنَا أَبُو مُسْهِرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِي الدَّرْدَاءِ أَوْ أَبِي ذَرٍّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اللَّهِ عَزَّ وَجَلَّ أَنَّهُ قَالَ ابْنَ آدَمَ ارْكَعْ لِي مِنْ أَوَّلِ النَّهَارِ أَرْبَعَ رَكَعَاتٍ أَكْفِكَ آخِرَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Abu Ja'far As Samnani] telah menceritakan kepada kami [Abu Mushir] telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [Jubair bin Nufair] dari [Abu Darda'] atau [Abu Dzar] dari Rasulullah Shallahu 'alaihi wa sallam dari Allah Azza Wa Jalla, Dia berfirman: \"Wahai anak Adam, ruku'lah kamu kepadaku dipermulaan siang sebanyak empat raka'at, niscaya Aku akan memenuhi kebutuhanmu di akhir siang.\" Abu Isa berkata, ini adalah hadits hasan gharib."},"438":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الْبَصْرِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ نَهَّاسِ بْنِ قَهْمٍ عَنْ شَدَّادٍ أَبِي عَمَّارٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَافَظَ عَلَى شُفْعَةِ الضُّحَى غُفِرَ لَهُ ذُنُوبُهُ وَإِنْ كَانَتْ مِثْلَ زَبَدِ الْبَحْرِقَالَ أَبُو عِيسَى وَقَدْ رَوَى وَكِيعٌ وَالنَّضْرُ بْنُ شُمَيْلٍ وَغَيْرُ وَاحِدٍ مِنْ الْأَئِمَّةِ هَذَا الْحَدِيثَ عَنْ نَهَّاسِ بْنِ قَهْمٍ وَلَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِهِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdil A'la Al Bashri] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Nahas bin Qahm] dari [Syaddad Abu 'Ammar] dari [Abu Hurairah] dia berkata, Rasulullah Shallahu 'alaihi wa sallam bersabda: \"Barang siapa yang selalu menjaga raka'at dluha, maka dosa-dosanya akan di ampuni walaupun seperti buih dilautan.\" Abu Isa berkata, hadits ini juga telah diriwayatkan [Waki'] dan [Nadlr bin Syumail] serta tidak cuma satu orang dari para ulama hadits dari [Nahs bin Qahm], kami tidak mengetahui (hadits yang lain) kecuali dari haditsnya."},"439":{"ar":"حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ الْبَغْدَادِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ رَبِيعَةَ عَنْ فُضَيْلِ بْنِ مَرْزُوقٍ عَنْ عَطِيَّةَ الْعَوْفِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكَانَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الضُّحَى حَتَّى نَقُولَ لَا يَدَعُ وَيَدَعُهَا حَتَّى نَقُولَ لَا يُصَلِّيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ziyad bin Ayyub Al Baghdadi] telah menceritakan kepada kami [Muhammad bin Rabi'ah] dari [Fudlail bin Marzuq] dari ['Athiyah Al 'Aufi] dari [Abu Sa'id Al Khudri] dia berkata, Nabi Shallahu 'alaihi wa sallam selalu mengerjakan shalat dluha sampai kami megatakan beliau tidak pernah meninggalkannya, tapi jika beliau meninggalkannya sampai kami mengatakan beliau tidak pernah mengerjakannya. Abu Isa berkata, ini adalah hadits hasan gharib."},"440":{"ar":"حَدَّثَنَا أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ مُسْلِمِ بْنِ أَبِي الْوَضَّاحِ هُوَ أَبُو سَعِيدٍ الْمُؤَدِّبُ عَنْ عَبْدِ الْكَرِيمِ الْجَزَرِيِّ عَنْ مُجَاهِدٍ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي أَرْبَعًا بَعْدَ أَنْ تَزُولَ الشَّمْسُ قَبْلَ الظُّهْرِ وَقَالَ إِنَّهَا سَاعَةٌ تُفْتَحُ فِيهَا أَبْوَابُ السَّمَاءِ وَأُحِبُّ أَنْ يَصْعَدَ لِي فِيهَا عَمَلٌ صَالِحٌقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَأَبِي أَيُّوبَ قَالَ أَبُو عِيسَى حَدِيثُ عَبْدِ اللَّهِ بْنِ السَّائِبِ حَدِيثٌ حَسَنٌ غَرِيبٌ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يُصَلِّي أَرْبَعَ رَكَعَاتٍ بَعْدَ الزَّوَالِ لَا يُسَلِّمُ إِلَّا فِي آخِرِهِنَّ","id":"Telah menceritakan kepada kami [Abu Isa Muhmmad bin Al Mutsanna] telah menceritakan kepada kami [Abu Daud At Thayalisi] telah menceritakan kepada kami [Muhammad bin Muslim bin Abu Al Wadldlah dia adalah Abu Sa'id Al Muaddib] dari ['Abdul Karim Al Jazari] dari [Mujahid] dari [Abdullah As Sa'ib] bahwasannya Rasulullah Shallahu 'alaihi wa sallam mengerjakan shalat setelah matahari mulai condong yaitu waktu sebelum dluhur sebanyak empat raka'at, beliau bersabda: \"Sesungguhnya ia merupakan waktu dibukanya pintu-pintu surga dan saya suka jika pada saat itu amalan shalihku diangkat.\" (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Ali dan Abu Ayyub. Abu Isa berkata, hadits Abdullah bin Sa'ib adalah hadits hasan gharib, dan telah diriwayatkan dari Nabi Shallahu 'alaihi wa sallam bahwasannya beliau shalat empat raka'at setelah matahari tergelinjir, dan beliau tidak salam (dalam empat raka'at tersebut) kecuali di raka'at yang terakhir."},"441":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عِيسَى بْنِ يَزِيدَ الْبَغْدَادِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ السَّهْمِيُّ و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُنِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ بَكْرٍ عَنْ فَائِدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ إِلَى اللَّهِ حَاجَةٌ أَوْ إِلَى أَحَدٍ مِنْ بَنِي آدَمَ فَلْيَتَوَضَّأْ فَلْيُحْسِنْ الْوُضُوءَ ثُمَّ لِيُصَلِّ رَكْعَتَيْنِ ثُمَّ لِيُثْنِ عَلَى اللَّهِ وَلْيُصَلِّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ لِيَقُلْ لَا إِلَهَ إِلَّا اللَّهُ الْحَلِيمُ الْكَرِيمُ سُبْحَانَ اللَّهِ رَبِّ الْعَرْشِ الْعَظِيمِ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ أَسْأَلُكَ مُوجِبَاتِ رَحْمَتِكَ وَعَزَائِمَ مَغْفِرَتِكَ وَالْغَنِيمَةَ مِنْ كُلِّ بِرٍّ وَالسَّلَامَةَ مِنْ كُلِّ إِثْمٍ لَا تَدَعْ لِي ذَنْبًا إِلَّا غَفَرْتَهُ وَلَا هَمًّا إِلَّا فَرَّجْتَهُ وَلَا حَاجَةً هِيَ لَكَ رِضًا إِلَّا قَضَيْتَهَا يَا أَرْحَمَ الرَّاحِمِينَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَفِي إِسْنَادِهِ مَقَالٌ فَائِدُ بْنُ عَبْدِ الرَّحْمَنِ يُضَعَّفُ فِي الْحَدِيثِ وَفَائِدٌ هُوَ أَبُو الْوَرْقَاءِ","id":"Telah menceritakan kepada kami [Ali bin Isa bin Yazid Al Baghdadi] telah menceritakan kepada kami [Abdullah bin Bakr As Sahmi] dan telah menceritakan kepada kami [Abdullah bin Munir] dari [Abdullah bin Bakr] dari [Fa'id bin Abdurrahman] dari [Abdullah bin Abu Aufa] dia berkata, Rasulullah Shallahu 'alaihi wa sallam bersabda: \"Barangsiapa yang mempunyai hajat (keinginan) kepada Allah atau kepada seseorang dari anak Adam, maka hendaklah dia berwudlu' dengan menyempurnakan wudlu'nya, lalu melaksanakan shalat dua raka'at, memuji kepada Allah, membaca Shalawat kepada Nabi Shallahu 'alaihi wa sallam, kemudian membaca \"LAA ILAAHA ILLALLAAHUL HALIIMUL KARIIM, SUBHANALLAAHI RABBIL 'ARSYIL 'ADZIIM, AL HAMDULILLAAHI RABBIL 'AALAMIIN, AS'ALUKA MUUJIBAATI RAHMATIKA WA AZAA'IMA MAGHFIRATIKA WAL GHANIIMATA MIN KULLI BIRRIN WAS SALAAMATA MIN KULLI ITSMIN, LAA TADA' LI DZAMBAN ILLAA GHAFARTAHU WALAA HAMMAN ILLAA FARRAJTAHU WALAA HAAJATAN HIYA LAKA RIDLAN ILLA QADLAITAHA YAA ARHAMUR RADLIALLAHU 'ANHAHIMIIN (Tidak ada Ilah yang berhak disembah selain Allah yang maha lembut lagi Mahapemurah, Mahasuci Allah Rabb pemilik 'Arsy yang Mahaagung, segala puji bagi Allah Rabb semesta Alam, aku mengharap rahmatMU, ketetapan hati (untuk meraih) ampunanMu, mendapatkan keberuntungan dengan segala kabaikan dan keselamatan dari segala perbuatan dosa, jangan Engkau biarkan dosa padaku kecuali Engkau mengampuninya, dan jangan Engkau biarkan kegundahan kecuali Engkau membukakannya, dan jangan Engkau biarkan kebutuhan-kebutuhan yang Engkau ridlai kecuali Engkau penuhi, wahai Dzat yang maha pengasih) \". Abu Isa berkata, hadits ini gharib dan dalam sanadnya ada sesutatu yang perlu dibicarakan, Fa'id bin Abdurrahman telah dilemahkan dalam masalah hadits, dan Fa'id adalah 'Abul Warqa'."},"442":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الْمَوَالِي عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا الِاسْتِخَارَةَ فِي الْأُمُورِ كُلِّهَا كَمَا يُعَلِّمُنَا السُّورَةَ مِنْ الْقُرْآنِ يَقُولُ إِذَا هَمَّ أَحَدُكُمْ بِالْأَمْرِ فَلْيَرْكَعْ رَكْعَتَيْنِ مِنْ غَيْرِ الْفَرِيضَةِ ثُمَّ لِيَقُلْ اللَّهُمَّ إِنِّي أَسْتَخِيرُكَ بِعِلْمِكَ وَأَسْتَقْدِرُكَ بِقُدْرَتِكَ وَأَسْأَلُكَ مِنْ فَضْلِكَ الْعَظِيمِ فَإِنَّكَ تَقْدِرُ وَلَا أَقْدِرُ وَتَعْلَمُ وَلَا أَعْلَمُ وَأَنْتَ عَلَّامُ الْغُيُوبِ اللَّهُمَّ إِنْ كُنْتَ تَعْلَمُ أَنَّ هَذَا الْأَمْرَ خَيْرٌ لِي فِي دِينِي وَمَعِيشَتِي وَعَاقِبَةِ أَمْرِي أَوْ قَالَ فِي عَاجِلِ أَمْرِي وَآجِلِهِ فَيَسِّرْهُ لِي ثُمَّ بَارِكْ لِي فِيهِ وَإِنْ كُنْتَ تَعْلَمُ أَنَّ هَذَا الْأَمْرَ شَرٌّ لِي فِي دِينِي وَمَعِيشَتِي وَعَاقِبَةِ أَمْرِي أَوْ قَالَ فِي عَاجِلِ أَمْرِي وَآجِلِهِ فَاصْرِفْهُ عَنِّي وَاصْرِفْنِي عَنْهُ وَاقْدُرْ لِي الْخَيْرَ حَيْثُ كَانَ ثُمَّ أَرْضِنِي بِهِ قَالَ وَيُسَمِّي حَاجَتَهُقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَأَبِي أَيُّوبَ قَالَ أَبُو عِيسَى حَدِيثُ جَابِرٍ حَدِيثٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي الْمَوَالِي وَهُوَ شَيْخٌ مَدِينِيٌّ ثِقَةٌ رَوَى عَنْهُ سُفْيَانُ حَدِيثًا وَقَدْ رَوَى عَنْ عَبْدِ الرَّحْمَنِ غَيْرُ وَاحِدٍ مِنْ الْأَئِمَّةِ وَهُوَ عَبْدُ الرَّحْمَنِ بْنُ زَيْدِ بْنِ أَبِي الْمَوَالِي","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdurrahman bin Abu Al Mawali] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] dia berkata, adalah Rasulullah Shallahu 'alaihi wa sallam mengajari kami (shalat) istikharah dalam semua perkara, sebagaimana beliau mengajari kami surat dalam Al Qur'an, beliau bersabda: \"Jika salah seorang dari kalian memiliki hajat (kebutuhan) dengan suatu perkara, hendaknya dia shalat sunnah dua raka'at, kemudian mengucapkan ALLAHUMMA INNI ASTAKHIRUKA BI 'ILMIKA WA ASTAQDIRUKA BIQADRATIKA WA AS'ALUKA MIN FADLLIKAL 'ADZIM, FAINNAKA TAQDIRU WALAA AQDIR, WA TA'LAMU WALAA A'LAM WA ANTAL 'ALLAAMUL GHUYUB, ALLAHUMMA INKUNTA TA'LAM ANNA HADZAL AMRA KHAIRUN LII FII DIINI WA MA'ISYATII WA 'AAQIBATI AMRII AU QAALA FII 'AAJILI AMRII WA AAJILIHI FAYASIRHU LII TSUMMA BAARIKLII FIIHI, WA INKUNTA TA'LAM ANNA HADZAL AMRA SYARRUN LII FII DIINI WA MA'ISYATII WA 'AAQIBATI AMRII AU QAALA FII 'AAJILI AMRII WA AAJILIHI FASHRIFHU 'ANNII WASHRIFNII 'ANHU WAQDURLII KHAIRA HAITSU KAANA TSUMMA ARDLINII BIHI. (\"Ya Allah, sesungguhnya aku meminta pilihan yang tepat kepadaMu dengan ilmu pengetahuanMu dan aku mohon kekuasaanMu (untuk mengatasi persoalanku) dengan kemahakuasaanMu. Aku mohon kepadaMu sesuatu dari anugerahMu Yang Maha Agung, sesungguhnya Engkau Mahakuasa, sedang aku tidak kuasa, Engkau mengetahui, sedang aku tidak mengetahuinya dan Engkau adalah Maha Mengetahui hal yang ghaib. Ya Allah, apabila Engkau mengetahui bahwa urusan ini (orang yang mempunyai hajat hendak-nya menyebut persoalannya) lebih baik dalam agamaku, dan akibatnya terhadap diriku atau -Nabi bersabda: …di dunia atau akhirat- sukseskanlah untukku, mudahkan jalannya, kemudian berilah berkah. Akan tetapi apabila Engkau mengetahui bahwa persoalan ini lebih berbahaya bagiku dalam agama, perekonomian dan akibatnya kepada diriku, maka singkirkan persoalan tersebut, dan jauhkan aku daripadanya, takdirkan kebaikan untukku di mana saja kebaikan itu berada, kemudian berilah kerelaanMu kepadaku).\" Beliau lantas bersabda: \"Kemudian dia mengatakan apa yang menjadi kebutuhannya.\" dalam bab ini (ada juga riwayat -pent) dari Abdullah bin Mas'ud dan Abu Ayyub. Abu Isa berkata, hadits Jabir adalah hadits shahih gharib, kami tidak mengetahuinya melainkan dari hadits Abdurrahman bin Abu Al Mawali, dia adalah syaikh Madini, seorang yang tsiqah. Sufyan At Tsauri juga telah meriwayatkan hadits darinya, dan tidak cuma seorang dari para ulama yang meriwayatkan hadits dari Abdurrahman, dia adalah Abdurrahman bin Zaid bin Abu Al Mawali."},"443":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ مُوسَى أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنِي إِسْحَقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ أُمَّ سُلَيْمٍ غَدَتْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ عَلِّمْنِي كَلِمَاتٍ أَقُولُهُنَّ فِي صَلَاتِي فَقَالَ كَبِّرِي اللَّهَ عَشْرًا وَسَبِّحِي اللَّهَ عَشْرًا وَاحْمَدِيهِ عَشْرًا ثُمَّ سَلِي مَا شِئْتِ يَقُولُ نَعَمْ نَعَمْقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَالْفَضْلِ بْنِ عَبَّاسٍ وَأَبِي رَافِعٍ قَالَ أَبُو عِيسَى حَدِيثُ أَنَسٍ حَدِيثٌ حَسَنٌ غَرِيبٌ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرُ حَدِيثٍ فِي صَلَاةِ التَّسْبِيحِ وَلَا يَصِحُّ مِنْهُ كَبِيرُ شَيْءٍ وَقَدْ رَأَى ابْنُ الْمُبَارَكِ وَغَيْرُ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ صَلَاةَ التَّسْبِيحِ وَذَكَرُوا الْفَضْلَ فِيهِ حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا أَبُو وَهْبٍ قَالَ سَأَلْتُ عَبْدَ اللَّهِ بْنَ الْمُبَارَكِ عَنْ الصَّلَاةِ الَّتِي يُسَبَّحُ فِيهَا فَقَالَ يُكَبِّرُ ثُمَّ يَقُولُ سُبْحَانَكَ اللَّهُمَّ وَبِحَمْدِكَ وَتَبَارَكَ اسْمُكَ وَتَعَالَى جَدُّكَ وَلَا إِلَهَ غَيْرُكَ ثُمَّ يَقُولُ خَمْسَ عَشْرَةَ مَرَّةً سُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ ثُمَّ يَتَعَوَّذُ وَيَقْرَأُ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ وَفَاتِحَةَ الْكِتَابِ وَسُورَةً ثُمَّ يَقُولُ عَشْرَ مَرَّاتٍ سُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ ثُمَّ يَرْكَعُ فَيَقُولُهَا عَشْرًا ثُمَّ يَرْفَعُ رَأْسَهُ مِنْ الرُّكُوعِ فَيَقُولُهَا عَشْرًا ثُمَّ يَسْجُدُ فَيَقُولُهَا عَشْرًا ثُمَّ يَرْفَعُ رَأْسَهُ فَيَقُولُهَا عَشْرًا ثُمَّ يَسْجُدُ الثَّانِيَةَ فَيَقُولُهَا عَشْرًا يُصَلِّي أَرْبَعَ رَكَعَاتٍ عَلَى هَذَا فَذَلِكَ خَمْسٌ وَسَبْعُونَ تَسْبِيحَةً فِي كُلِّ رَكْعَةٍ يَبْدَأُ فِي كُلِّ رَكْعَةٍ بِخَمْسَ عَشْرَةَ تَسْبِيحَةً ثُمَّ يَقْرَأُ ثُمَّ يُسَبِّحُ عَشْرًا فَإِنْ صَلَّى لَيْلًا فَأَحَبُّ إِلَيَّ أَنْ يُسَلِّمَ فِي الرَّكْعَتَيْنِ وَإِنْ صَلَّى نَهَارًا فَإِنْ شَاءَ سَلَّمَ وَإِنْ شَاءَ لَمْ يُسَلِّمْ قَالَ أَبُو وَهْبٍ وَأَخْبَرَنِي عَبْدُ الْعَزِيزِ بْنُ أَبِي رِزْمَةَ عَنْ عَبْدِ اللَّهِ أَنَّهُ قَالَ يَبْدَأُ فِي الرُّكُوعِ بِسُبْحَانَ رَبِيَ الْعَظِيمِ وَفِي السُّجُودِ بِسُبْحَانَ رَبِيَ الْأَعْلَى ثَلَاثًا ثُمَّ يُسَبِّحُ التَّسْبِيحَاتِ قَالَ أَحْمَدُ بْنُ عَبْدَةَ وَحَدَّثَنَا وَهْبُ بْنُ زَمْعَةَ قَالَ أَخْبَرَنِي عَبْدُ الْعَزِيزِ وَهُوَ ابْنُ أَبِي رِزْمَةَ قَالَ قُلْتُ لِعَبْدِ اللَّهِ بْنِ الْمُبَارَكِ إِنْ سَهَا فِيهَا يُسَبِّحُ فِي سَجْدَتَيْ السَّهْوِ عَشْرًا عَشْرًا قَالَ لَا إِنَّمَا هِيَ ثَلَاثُ مِائَةِ تَسْبِيحَةٍ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Musa] telah mengabarkan kepada kami [Abdullah bin Mubarak] telah mengabarkan kepada kami ['Ikrimah bin 'Ammar] telah menceritakan kepadaku [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] bahwasannya Ummu Sulaim berpagi-pagi menemui Nabi Shallahu 'alaihi wa sallam seraya berkata, ajarilah saya beberapa kalimat yang saya ucapkan didalam shalatku, maka beliau bersabda: \"Bertakbirlah kepada Allah sebanyak sepuluh kali, bertasbihlah kepada Allah sepuluh kali dan bertahmidlah (mengucapkan al hamdulillah) sepuluh kali, kemudian memohonlah (kepada Allah) apa yang kamu kehendaki, niscaya Dia akan menjawab: ya, ya, (Aku kabulkan permintaanmu).\" (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Ibnu Abbas, Abdullah bin Amru, Al Fadll bin Abbas dan Abu Rafi'. Abu Isa berkata, hadits anas adalah hadits hasan gharib, telah diriwayatkan dari Nabi Shallahu 'alaihi wa sallam selain hadits ini mengenai shalat tasbih, yang kebanyakan (riwayatnya) tidak shahih. Ibnu Mubarrak dan beberapa ulama lainnya berpendapat akan adanya shalat tasbih, mereka juga menyebutkan keutamaan shalat tasbih. Telah mengabarkan kepada kami Ahmad bin 'Abdah Telah mengabarkan kepada kami Abu Wahb dia berkata, saya bertanya kepada Abdullah bin Al Mubarak tentang shalat tasbih yang didalamnya terdapat bacaan tasbihnya, dia menjawab, ia bertakbir kemudian membaca SUBHAANAKA ALLAHUMMA WA BIHAMDIKA WA TABAARAKASMUKA WA TA'ALA JADDUKA WALAA ILAAHA GHAIRUKA kemudian dia membaca SUBHAANALLAH WALHAMDULILLAH WA LAAILAAHA ILLALLAH WALLAHU AKBAR sebanyak lima belas kali, kemudian ia berta'awudz dan membaca bismillah dilanjutkan dengan membaca surat Al fatihah dan surat yang lain, kemudian ia membaca SUBHAANALLAH WALHAMDULILLAH WA LAAILAAHA ILLALLAH WALLAHU AKBAR sebanyak sepuluh kali, kemudian ruku' dan membaca kalimat itu sepuluh kali, lalu mengangkat kepala dari ruku' dengan membaca kalimat tersebut sepuluh kali, kemudian sujud dengan membaca kalimat tersebut sepuluh kali, lalu mengangkat kepalanya dengan membaca kalimat tersebut sepuluh kali, kemudian sujud yang kedua kali dengan membaca kalimat tersebut sepuluh kali, ia melakukan seperti itu sebanyak empat raka'at, yang setiap satu raka'atnya membaca tasbih sebanyak tujuh puluh lima kali, disetiap raka'atnnya membaca lima belas kali tasbih, kemudian membaca Al Fatehah dan surat sesudahnya serta membaca tasbih sepuluh kali-sepuluh kali, jika ia shalat malam, maka yang lebih disenagi adalah salam pada setiap dua raka'atnya. Jika ia shalat disiang hari, maka ia boleh salam (di raka'at kedua) atau tidak. Abu Wahb berkata, telah mengabarkan kepadaku 'Abdul 'Aziz bin Abu Rizmah dari Abdullah bahwa dia berkata, sewaktu ruku' hendaknya dimulai dengan bacaan SUBHAANA RABBIYAL 'ADZIIMI, begitu juga waktu sujud hendaknya dimulai dengan bacaan SUBHAANA RABBIYAL A'LA sebanyak tiga kali, kemudian membaca tasbih beberapa kali bacaan. Ahmad bin 'Abdah berkata, Telah mengabarkan kepada kami Wahb bin Zam'ah dia berkata, telah mengabarkan kepadaku 'Abdul 'Aziz dia adalah Ibnu Abu Zirmah, dia berkata, saya bertanya kepada Abdullah bin Mubarak, jika seseorang lupa (waktu mengerjakan shalat tasbih) apakah ia harus membaca tasbih pada dua sujud sahwi sebanyak sepuluh kali-sepuluh kali? Dia menjawab, tidak, hanysanya (semua bacaan tasbih pada shalat tasbih) ada tiga ratus kali."},"444":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا زَيْدُ بْنُ حُبَابٍ الْعُكْلِيُّ حَدَّثَنَا مُوسَى بْنُ عُبَيْدَةَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ مَوْلَى أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِي رَافِعٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْعَبَّاسِ يَا عَمِّ أَلَا أَصِلُكَ أَلَا أَحْبُوكَ أَلَا أَنْفَعُكَ قَالَ بَلَى يَا رَسُولَ اللَّهِ قَالَ يَا عَمِّ صَلِّ أَرْبَعَ رَكَعَاتٍ تَقْرَأُ فِي كُلِّ رَكْعَةٍ بِفَاتِحَةِ الْكِتَابِ وَسُورَةٍ فَإِذَا انْقَضَتْ الْقِرَاءَةُ فَقُلْ اللَّهُ أَكْبَرُ وَالْحَمْدُ لِلَّهِ وَسُبْحَانَ اللَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ خَمْسَ عَشْرَةَ مَرَّةً قَبْلَ أَنْ تَرْكَعَ ثُمَّ ارْكَعْ فَقُلْهَا عَشْرًا ثُمَّ ارْفَعْ رَأْسَكَ فَقُلْهَا عَشْرًا ثُمَّ اسْجُدْ فَقُلْهَا عَشْرًا ثُمَّ ارْفَعْ رَأْسَكَ فَقُلْهَا عَشْرًا ثُمَّ اسْجُدْ الثَّانِيَةَ فَقُلْهَا عَشْرًا ثُمَّ ارْفَعْ رَأْسَكَ فَقُلْهَا عَشْرًا قَبْلَ أَنْ تَقُومَ فَتِلْكَ خَمْسٌ وَسَبْعُونَ فِي كُلِّ رَكْعَةٍ هِيَ ثَلَاثُ مِائَةٍ فِي أَرْبَعِ رَكَعَاتٍ فَلَوْ كَانَتْ ذُنُوبُكَ مِثْلَ رَمْلِ عَالِجٍ لَغَفَرَهَا اللَّهُ لَكَ قَالَ يَا رَسُولَ اللَّهِ وَمَنْ يَسْتَطِيعُ أَنْ يَقُولَهَا فِي كُلِّ يَوْمٍ قَالَ فَإِنْ لَمْ تَسْتَطِعْ أَنْ تَقُولَهَا فِي كُلِّ يَوْمٍ فَقُلْهَا فِي جُمْعَةٍ فَإِنْ لَمْ تَسْتَطِعْ أَنْ تَقُولَهَا فِي جُمُعَةٍ فَقُلْهَا فِي شَهْرٍ فَلَمْ يَزَلْ يَقُولُ لَهُ حَتَّى قَالَ فَقُلْهَا فِي سَنَةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ حَدِيثِ أَبِي رَافِعٍ","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al Ala'] telah menceritakan kepada kami [Zaid bin Hubab Al Uqli] telah menceritakan kepada kami [Musa bin 'Ubaidah] telah menceritakan kepada kami [Sa'id bin Abu Sa'id] budak Abu Bakar bin Muhammad bin Amru bin Hazm dari [Abu Rafi'] dia berkata, Rasulullah Shallahu 'alaihi wa sallam berkata kepada Al Abbas: \"Wahai pamanku bukankah saya telah bersilatur rahmi kepadamu, bukankah saya telah memberikan sesuatu kepadamu, dan bukankah saya telah memberikan manfaat kepadamu?\" Dia menjawab, ya, wahai Rasulullah. Beliau bersabda: \"Wahai pamanku, laksanakanlah shalat empat raka'at, pada setiap raka'atnya kamu membaca fatihatul kitab (surat Al Fatihah) dan surat (dari Al Qur'an), apabila selesai membaca, maka bacalah ALLAAHU AKBAR, WAL HAMDULILLAAH, WASUBHANALLAAHI, WALAA ILAAHA ILLALLAAH sebanyak lima kali sebelum ruku', kemudian ruku' lalu bacalah kalimat tersebut sepuluh kali, lalu angkatlah kepalamu dan bacalah kalimat tersebut sepuluh kali, kemudian sujudlah dan bacalah kalimat tersebut sepuluh kali, kemudian angkatlah kepalamu dan bacalah kalimat tersebut sepuluh kali, kemudian sujudlah untuk yang kedua dan bacalah kalimat tersebut sepuluh kali, kemudian angkatlah kepalamu dan bacalah kalimat tersebut sepuluh kali sebelum kamu berdiri, sehingga jumlahnya tujuh puluh lima dalam setiap raka'at dan tiga ratus dalam empat raka'at, seandainya dosamu seperti pasir yang bertebaran, niscaya Allah akan mengampuninya untukmu.\" dia (Abbas) bertanya, wahai Rasulullah, siapakah yang akan mampu membacanya setiap hari? Beliau menjawab: \"Jika kamu tidak mampu membcanya setiap hari, maka bacalah dalam setiap Jum'at dan jika kamu tidak mampu membacanya dalam setiap Jum'at maka bacalah dalam setiap bulan. kemudian Abbas terus menerus bertanya kepada beliau sehingga beliau bersabda: \"Maka bacalah dalam setahun.\" Abu Isa berkata, ini adalah hadits gharib, dari hadits Abu Rafi'."},"445":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ مِسْعَرٍ وَالْأَجْلَحِ وَمَالِكِ بْنِ مِغْوَلٍ عَنْ الْحَكَمِ بْنِ عُتَيْبَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَقُلْنَا يَا رَسُولَ اللَّهِ هَذَا السَّلَامُ عَلَيْكَ قَدْ عَلِمْنَا فَكَيْفَ الصَّلَاةُ عَلَيْكَ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ وَبَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌقَالَ مَحْمُودٌ قَالَ أَبُو أُسَامَةَ وَزَادَنِي زَائِدَةُ عَنْ الْأَعْمَشِ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَالَ وَنَحْنُ نَقُولُ وَعَلَيْنَا مَعَهُمْ قَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَأَبِي حُمَيْدٍ وَأَبِي مَسْعُودٍ وَطَلْحَةَ وَأَبِي سَعِيدٍ وَبُرَيْدَةَ وَزَيْدِ بْنِ خَارِجَةَ وَيُقَالُ ابْنُ جَارِيَةَ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى حَدِيثُ كَعْبِ بْنِ عُجْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَعَبْدُ الرَّحْمَنِ بْنُ أَبِي لَيْلَى كُنْيَتُهُ أَبُو عِيسَى وَأَبُو لَيْلَى اسْمُهُ يَسَارٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Usamah] dari [Mis'ar] dan [Ajlah] dan [Malik bin Mighwal] dari [Al Hakam bin 'Utaibah] dari [Abdurrahman bin Abu Laila] dari [Ka'ab bin 'Ujrah] dia berkata, kami bertanya, wahai Rasulullah, kami telah mengetahui salam keatasmu, lalu bagaimanakah caranya bershalawat keatasmu? Beliau menjawab: \"Ucapkanlah ALLAHUMMA SHALLI 'ALAA MUHAMMAD WA 'ALAA AALI MUHAMMAD KAMAA SHALLAITA 'ALAA IBRADLIALLAHU 'ANHAHIIMA INNAKA HAMIIDUM MAJIID WA BAARIK 'ALAA MUHAMMAD WA'ALAA AALI MUHAMMAD KAMAA BAARAKTA 'ALAA IBRAHIIMA INNAKA HAMIIDUM MAJIID. Mahmud berkata, Abu Usamah berkata, dan dia menambahkan kepadaku beberapa tambahan dari Al A'masy dari Al Hakam dari Abdurrahman bin Abu Laila dia berkata, sedangkan kami mengatakan \"dan kami bersama mereka.\" (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Ali, Abu Humaid, Abu Mas'ud Thalhah, Abu sa'id, Buraidah dan Zaid bin Kharijah, dikatakan pula Ibnu Jariyah dan Abu Hurairah. Abu Isa berkata, hadits Ka'ab bin 'Ujrahh adalah hadits hasan shahih, kunyahnya Abdurrahman bin Abu Laila adalah Abu Isa, sedangkan namanya Abu Laila adalah Yasar."},"446":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ بُنْدَارٌ حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدٍ ابْنُ عَثْمَةَ حَدَّثَنِي مُوسَى بْنُ يَعْقُوبَ الزَّمْعِيُّ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ كَيْسَانَ أَنَّ عَبْدَ اللَّهِ بْنَ شَدَّادٍ أَخْبَرَهُ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَوْلَى النَّاسِ بِي يَوْمَ الْقِيَامَةِ أَكْثَرُهُمْ عَلَيَّ صَلَاةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَرُوِي عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ صَلَّى عَلَيَّ صَلَاةً صَلَّى اللَّهُ عَلَيْهِ بِهَا عَشْرًا وَكَتَبَ لَهُ بِهَا عَشْرَ حَسَنَاتٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar yaitu Bundar] telah menceritakan kepada kami [Muhammad bin Khalid Ibnu Atsmah] telah menceritakan kepadaku [Musa bin Ya'qub Az Zam'i] telah menceritakan kepadaku [Abdullah bin Kaisan] bahwa [Abdullah bin Syaddad] telah mengabarkan kepadanya dari [Abdullah bin Mas'ud] bahwa Rasulullah Shallahu 'alaihi wa sallam bersabda: \"Orang yang paling dekat denganku pada hari Qiyamat adalah yang paling banyak bershalawat kepadaku.\" Abu Isa berkata, ini adalah hadits hasan gharib, telah diriwayatkan dari Nabi Shallahu 'alaihi wa sallam bahwa beliau bersabda: \"Barangsiapa yang bershalawat satu kali kepadaku, maka Allah akan memberikan shalawat sepuluh kali kepadanya dan dicatat baginya sepuluh kebaikan.\""},"447":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى عَلَيَّ صَلَاةً صَلَّى اللَّهُ عَلَيْهِ بِهَا عَشْرًاقَالَ وَفِي الْبَاب عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَعَامِرِ بْنِ رَبِيعَةَ وَعَمَّارٍ وَأَبِي طَلْحَةَ وَأَنَسٍ وَأُبَيِّ بْنِ كَعْبٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَرُوِي عَنْ سُفْيَانَ الثَّوْرِيِّ وَغَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ قَالُوا صَلَاةُ الرَّبِّ الرَّحْمَةُ وَصَلَاةُ الْمَلَائِكَةِ الِاسْتِغْفَارُ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] telah mengabarkan kepada kami [Isma'il bin ja'far] dari ['Ala' bin Abdurrahman] dari [ayahnya] dari [Abu Hurairah] dia berkata, Rasulullah Shallahu 'alaihi wa sallam bersabda: \"Barang siapa yang bershalawat kepadaku, maka Allah akan bershalawat kepadanya sepuluh kali.\" (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Abdurrahman bin 'Auf, 'Amir bin Rabi'ah, Amar, Abu Thalhah, Anas dan Ubay bin Ka'ab. Abu Isa berkata, hadits Abu Hurairah adalah hadits hasan shahih. Telah diriwayatkan dari Sufyan At Tsauri dan yang lainnya dari ahli ilmu, mereka berkata, (maksud dari) shalatnya Rabb (Allah) adalah rahmat, dan shalawatnya para malaikat adalah istighfar (permohonan ampuanan)."},"448":{"ar":"حَدَّثَنَا أَبُو دَاوُدَ سُلَيْمَانُ بْنُ سَلْمٍ الْمَصَاحِفِيُّ الْبَلْخِيُّ أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ عَنْ أَبِي قُرَّةَ الْأَسَدِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَإِنَّ الدُّعَاءَ مَوْقُوفٌ بَيْنَ السَّمَاءِ وَالْأَرْضِ لَا يَصْعَدُ مِنْهُ شَيْءٌ حَتَّى تُصَلِّيَ عَلَى نَبِيِّكَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Abu Daud Sulaiman bin Salmin Al Mashahifi Al Balkhi] telah mengabarkan kepada kami [An Nadlr bin Syumail] dari [Abu Qurrah Al Asadi] dari [Sa'id bin Al Musayyib] dari [Umar bin Al Khaththab] dia berkata, sesungguhnya do'a akan terhenti di antara bumi dan langit, ia tidak akan naik sehingga kamu bershalawat kepada Nabimu Shalallahu 'alaihi wa salam."},"449":{"ar":"حَدَّثَنَا عَبَّاسٌ الْعَنْبَرِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يَعْقُوبَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِلَا يَبِعْ فِي سُوقِنَا إِلَّا مَنْ قَدْ تَفَقَّهَ فِي الدِّينِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ عَبَّاسٌ هُوَ ابْنُ عَبْدِ الْعَظِيمِ قَالَ أَبُو عِيسَى وَالْعَلَاءُ بْنُ عَبْدِ الرَّحْمَنِ هُوَ ابْنُ يَعْقُوبَ وَهُوَ مَوْلَى الْحُرَقَةِ وَالْعَلَاءُ هُوَ مِنْ التَّابِعِينَ سَمِعَ مِنْ أَنَسِ بْنِ مَالِكٍ وَغَيْرِهِ وَعَبْدُ الرَّحْمَنِ بْنُ يَعْقُوبَ وَالِدُ الْعَلَاءِ وَهُوَ أَيْضًا مِنْ التَّابِعِينَ سَمِعَ مِنْ أَبِي هُرَيْرَةَ وَأَبِي سَعِيدٍ الْخُدْرِيِّ وَابْنِ عُمَرَ وَيَعْقُوبَ جَدُّ الْعَلَاءِ هُوَ مِنْ كِبَارِ التَّابِعِينَ أَيْضًا قَدْ أَدْرَكَ عُمَرَ بْنَ الْخَطَّابِ وَرَوَى عَنْهُ","id":"Telah mengabarkan kepada kami [Abbas Al Anbari] Telah mengabarkan kepada kami [Abdurrahman bin Mahdi] dari [Malik bin Anas] dari ['Ala' bin Abdurrahman bin Ya'qub] dari [ayahnya] dari [kakeknya] dia berkata, [Umar bin Al Khaththab] telah berkata, Janganlah ada seseorang yang berjualan dipasar kami ini, kecuali jika ia telah mendalami ilmu agama. Abu Isa berkata, ini adalah hadits hasan gharib. Abbas adalah Ibnu 'Abdil 'Adzim. Abu Isa berkata, sedangkan 'Ala' bin Abdurrahman adalah Ibnu Ya'qub seorang bekas budak Al Khurqah, 'Ala' dari generasi tabi'in, dia mendengar dari Anas bin Malik dan yang lainnya. Sedangkan Abdurrahman bin Ya'qub adalah ayahnya 'Ala', dia juga dari kalangan tabi'in yang pernah mendengar dari Abu Hurairah, Abu Sa'id Al Khudri dan Ibnu Umar. Ya'qub adalah kakeknya 'Ala', dia termasuk dari pembesar tabi'in yang pernah bertemu Umar serta meriwayatkan hadits darinya."},"450":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ يَوْمٍ طَلَعَتْ فِيهِ الشَّمْسُ يَوْمُ الْجُمُعَةِ فِيهِ خُلِقَ آدَمُ وَفِيهِ أُدْخِلَ الْجَنَّةَ وَفِيهِ أُخْرِجَ مِنْهَا وَلَا تَقُومُ السَّاعَةُ إِلَّا فِي يَوْمِ الْجُمُعَةِقَالَ وَفِي الْبَاب عَنْ أَبِي لُبَابَةَ وَسَلْمَانَ وَأَبِي ذَرٍّ وَسَعْدِ بْنِ عُبَادَةَ وَأَوْسِ بْنِ أَوْسٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah mengabarkan kepada kami [Qutaibah] Telah mengabarkan kepada kami [Al Mughirah bin Abdurrahman] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwasannya Nabi Shallahu 'alaihi wa sallam bersabda: \"Sebaik-baik hari pada saat matahari terbit adalah hari Jum'at, pada hari itulah Adam diciptakan, pada hari itu dia dimasukkan ke dalam surga dan pada hari itu juga dia dikeluarkan dari surga, dan tidak akan terjadi Kiamat kecuali pada hari Jum'at. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Abu Lubabah, Salman, Abu Dzar, Sa'ad bin 'Ubadah dan 'Aus bin 'Aus. Abu Isa berkata, hadits Abu Hurairah adalah hadits hasan shahih."},"451":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الصَّبَّاحِ الْهَاشِمِيُّ الْبَصْرِيُّ الْعَطَّارُ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ الْحَنَفِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي حُمَيْدٍ حَدَّثَنَا مُوسَى بْنُ وَرْدَانَ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الْتَمِسُوا السَّاعَةَ الَّتِي تُرْجَى فِي يَوْمِ الْجُمُعَةِ بَعْدَ الْعَصْرِ إِلَى غَيْبُوبَةِ الشَّمْسِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَيْرِ هَذَا الْوَجْهِ وَمُحَمَّدُ بْنُ أَبِي حُمَيْدٍ يُضَعَّفُ ضَعَّفَهُ بَعْضُ أَهْلِ الْعِلْمِ مِنْ قِبَلِ حِفْظِهِ وَيُقَالُ لَهُ حَمَّادُ بْنُ أَبِي حُمَيْدٍ وَيُقَالُ هُوَ أَبُو إِبْرَاهِيمَ الْأَنْصَارِيُّ وَهُوَ مُنْكَرُ الْحَدِيثِ وَرَأَى بَعْضُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ أَنَّ السَّاعَةَ الَّتِي تُرْجَى فِيهَا بَعْدَ الْعَصْرِ إِلَى أَنْ تَغْرُبَ الشَّمْسُ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ و قَالَ أَحْمَدُ أَكْثَرُ الْأَحَادِيثِ فِي السَّاعَةِ الَّتِي تُرْجَى فِيهَا إِجَابَةُ الدَّعْوَةِ أَنَّهَا بَعْدَ صَلَاةِ الْعَصْرِ وَتُرْجَى بَعْدَ زَوَالِ الشَّمْسِ","id":"Telah mengabarkan kepada kami [Abdullah bin Ash Shabah Al hasyimi Al Bashri Al 'Atthar] Telah mengabarkan kepada kami ['Ubaidullah bin 'Abdul Majid Al Hanafi] telah menceritakan kepada kami [Muhammad bin Abu Humaid] telah menceritakan kepada kami [Musa bin Wardan] dari [Anas bin Malik] dari Nabi Shallahu 'alaihi wa sallam bahwa beliau bersabda: \"Carilah oleh kalian waktu-waktu yang mustajab pada hari Jum'at setelah 'Ashar sampai tenggelamnya matahari.\" Abu Isa berkata, dari jalur ini hadits ini gharib, hadits ini juga telah diriwayatkan dari Anas dari Nabi Shallahu 'alaihi wa sallam bukan dari jalur ini, adapun Muhammad bin Abu Rafi' telah dilemahkan, sebagian ahli ilmu telah melemahkannya dari sisi hafalannya, dia dinamakan juga Hammad bin Abu Humaid dan dinamakan juga Abu Ibrahim Al Anshari yang haditsnya mungkar, sebagian ahli ilmu dari kalangan sahabat Nabi Shallahu 'alaihi wa sallam dan yang lainnya berpendapat bahwa waktu yang mustajab pada hari Jum'at adalah setelah 'Ashar sampai matahari terbit, ini adalah pendapat Ahmad dan Ishaq, Ahmad berkata, kebanyakan hadits-hadits tentang waktu yang diharapkan do'a terkabul pada hari Jum'at adalah setelah shalat 'Ashar, dan setelah matahari tergelincir."},"452":{"ar":"حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ الْبَغْدَادِيُّ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا كَثِيرُ بْنُ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عَوْفٍ الْمُزَنِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجُمُعَةِ سَاعَةً لَا يَسْأَلُ اللَّهَ الْعَبْدُ فِيهَا شَيْئًا إِلَّا آتَاهُ اللَّهُ إِيَّاهُ قَالُوا يَا رَسُولَ اللَّهِ أَيَّةُ سَاعَةٍ هِيَ قَالَ حِينَ تُقَامُ الصَّلَاةُ إِلَى الِانْصِرَافِ مِنْهَاقَالَ وَفِي الْبَاب عَنْ أَبِي مُوسَى وَأَبِي ذَرٍّ وَسَلْمَانَ وَعَبْدِ اللَّهِ بْنِ سَلَامٍ وَأَبِي لُبَابَةَ وَسَعْدِ بْنِ عُبَادَةَ وَأَبِي أُمَامَةَ قَالَ أَبُو عِيسَى حَدِيثُ عَمْرِو بْنِ عَوْفٍ حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ziyad bin Ayyub Al Baghdadi] telah menceritakan kepada kami [Abu 'Amir Al Aqadi] telah menceritakan kepada kami [Katsir bin Abdullah bin Amr bin 'Auf Al Muzani] dari [ayahnya] dari [kakeknya] dari Nabi Shallahu 'alaihi wa sallam beliau bersabda: \"Sesungguhnya pada hari Jum'at ada waktu yang tidaklah seorang hamba memohon sesuatu kepada Allah pada hari itu kecuali Allah pasti akan mengabulkannya.\" Para sahabat bertanya, wahai Rasulullah jam berapakah itu? Beliau menjawab: \"Sejak ditegakkannya shalat Jum'at sampai selesai.\" (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Abu Musa, Abu Dzar, Salman, Abdullah bin Salam, Abu Lubabah, Sa'ad bin 'Ubadah dan Abu Umamah. Abu Isa berkata, hadits Amru bin 'Auf adalah hadits hasan gharib."},"453":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ يَوْمٍ طَلَعَتْ فِيهِ الشَّمْسُ يَوْمُ الْجُمُعَةِ فِيهِ خُلِقَ آدَمُ وَفِيهِ أُدْخِلَ الْجَنَّةَ وَفِيهِ أُهْبِطَ مِنْهَا وَفِيهِ سَاعَةٌ لَا يُوَافِقُهَا عَبْدٌ مُسْلِمٌ يُصَلِّي فَيَسْأَلُ اللَّهَ فِيهَا شَيْئًا إِلَّا أَعْطَاهُ إِيَّاهُ قَالَ أَبُو هُرَيْرَةَ فَلَقِيتُ عَبْدَ اللَّهِ بْنَ سَلَامٍ فَذَكَرْتُ لَهُ هَذَا الْحَدِيثَ فَقَالَ أَنَا أَعْلَمُ بِتِلْكَ السَّاعَةِ فَقُلْتُ أَخْبِرْنِي بِهَا وَلَا تَضْنَنْ بِهَا عَلَيَّ قَالَ هِيَ بَعْدَ الْعَصْرِ إِلَى أَنْ تَغْرُبَ الشَّمْسُ فَقُلْتُ كَيْفَ تَكُونُ بَعْدَ الْعَصْرِ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُوَافِقُهَا عَبْدٌ مُسْلِمٌ وَهُوَ يُصَلِّي وَتِلْكَ السَّاعَةُ لَا يُصَلَّى فِيهَا فَقَالَ عَبْدُ اللَّهِ بْنُ سَلَامٍ أَلَيْسَ قَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ جَلَسَ مَجْلِسًا يَنْتَظِرُ الصَّلَاةَ فَهُوَ فِي صَلَاةٍ قُلْتُ بَلَى قَالَ فَهُوَ ذَاكَقَالَ أَبُو عِيسَى وَفِي الْحَدِيثِ قِصَّةٌ طَوِيلَةٌ قَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ وَمَعْنَى قَوْلِهِ أَخْبِرْنِي بِهَا وَلَا تَضْنَنْ بِهَا عَلَيَّ لَا تَبْخَلْ بِهَا عَلَيَّ وَالضَّنُّ الْبُخْلُ وَالظَّنِينُ الْمُتَّهَمُ","id":"Telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] telah menceritakan kepada kami [Ma'an] telah menceritakan kepada kami [Malik bin Anas] dari [Yazid bin Abdullah bin Hadi] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Abu Hurairan] dia berkata, Rasulullah Shallahu 'alaihi wa sallam bersabda: \"Sebaik-baik hari setelah terbitnya matahari adalah hari Jum'at, pada hari itu Adam diciptakan, pada hari itu dia dimasukkan kedalam Surga, pada hari itu juga dia dikeluarkan dari surga, dan tidaklah seorang muslim yang shalat dan memohon sesuatu kepada Allah bertepatan pada waktu itu, melainkan Allah akan mengijabahinya.\" Abu Hurairah berkata, kemudian saya menemui [Abdullah bin Salam] seraya menyebutkan hadits ini kepadanya, maka dia (Abdullah bin Salam radliallahu 'anhu) berkata, saya tahu waktu itu, lalu saya berkata kepadanya, kabarilah kepadaku waktu tersebut dan janganlah"},"454":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَتَى الْجُمُعَةَ فَلْيَغْتَسِلْقَالَ وَفِي الْبَاب عَنْ عُمَرَ وَأَبِي سَعِيدٍ وَجَابِرٍ وَالْبَرَاءِ وَعَائِشَةَ وَأَبِي الدَّرْدَاءِ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَرُوِي عَنْ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا الْحَدِيثُ أَيْضًا حَدَّثَنَا بِذَلِكَ قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ و قَالَ مُحَمَّدٌ وَحَدِيثُ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ وَحَدِيثُ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ كِلَا الْحَدِيثَيْنِ صَحِيحٌ و قَالَ بَعْضُ أَصْحَابِ الزُّهْرِيِّ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي آلُ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْغُسْلِ يَوْمَ الْجُمُعَةِ أَيْضًا وَهُوَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Salim] dari [ayahnya] bahwa dia mendengar Nabi Shallahu 'alaihi wa sallam bersabda: \"Barang siapa yang mendatangi shalat Jum'at, hendaknya ia mandi.\" (perawi berkata, dalam bab ini (ada juga riwayat -pent) dari Umar, Abu Sa'id, Jabir, Barra', 'Aisyah dan Abu Darda'. Abu Isa berkata, hadist Ibnu Umar adalah hadits hasan shahih. Telah diriwayatkan dari [Az Zuhri] dari [Abdullah bin Abdullah bin Umar] dari [ayahnya] dari Nabi Shallahu 'alaihi wa sallam. Dalam hadits ini juga telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Laits bin Sa'd] dari [Ibnu Syihab] dari [Abdullah bin Abdullah bin Umar] dari [ayahnya] bahwasannya Nabi Shallahu 'alaihi wa sallam -seperi hadits di atas-, Muhammad berkata, hadits Az Zuhri dari Salim dari ayahnya dengan hadits Abdullah bin 'Abdillah bin Umar dari ayahnya kedua-duanya adalah shahih. Sebagian sahabat Az Zuhri berkata, dari [Az Zuhri] dia berkata, telah menceritakan kepadaku keluarga [Abdullah bin Umar] dari [Umar] dari Nabi Shallahu 'alaihi wa sallam mengenai mandi pada hari Jum'at juga, ini adalah hadits hasan shahih."},"455":{"ar":"وَرَوَاهُ يُونُسُ وَمَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِبَيْنَمَا عُمَرُ بْنُ الْخَطَّابِ يَخْطُبُ يَوْمَ الْجُمُعَةِ إِذْ دَخَلَ رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيَّةُ سَاعَةٍ هَذِهِ فَقَالَ مَا هُوَ إِلَّا أَنْ سَمِعْتُ النِّدَاءَ وَمَا زِدْتُ عَلَى أَنْ تَوَضَّأْتُ قَالَ وَالْوُضُوءُ أَيْضًا وَقَدْ عَلِمْتَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِالْغُسْلِ��َدَّثَنَا بِذَلِكَ أَبُو بَكْرٍ مُحَمَّدُ بْنُ أَبَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ قَالَ و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا أَبُو صَالِحٍ عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ بِهَذَا الْحَدِيثِ وَرَوَى مَالِكٌ هَذَا الْحَدِيثَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ قَالَ بَيْنَمَا عُمَرُ بْنُ الْخَطَّابِ يَخْطُبُ يَوْمَ الْجُمُعَةِ فَذَكَرَ هَذَا الْحَدِيثَ قَالَ أَبُو عِيسَى وَسَأَلْتُ مُحَمَّدًا عَنْ هَذَا فَقَالَ الصَّحِيحُ حَدِيثُ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَ مُحَمَّدٌ وَقَدْ رُوِيَ عَنْ مَالِكٍ أَيْضًا عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ نَحْوُ هَذَا الْحَدِيثِ","id":"Telah diriwayatkan oleh [Yunus] dan [Ma'mar] dari [Az Zuhri] dari [Salim] dari [ayahnya] tatkala [Umar bin Al Khaththab] berkhutbah pada hari Jum'at, tiba-tiba seorang lelaki dari sahabat Nabi Shallahu 'alaihi wa sallam masuk (masjid), maka dia (Umar) berkata, jam berapakah sekarang? Dia menjawab, Ketika saya mendengar adzan, saya hanya mengerjakan wudlu', tidak lebih dari itu. Dia (Umar) berkata, hanya wudlu'? tidakkah kamu tahu bahwa Rasulullah Shallahu 'alaihi wa sallam memerintahkan untuk mandi? telah menceritakan kepada kami seperti itu [Abu Bakar Muhammad bin Abban], telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Az Zuhri] (perawi) berkata, (dan dari jalur lain) telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Abu Shalih Abdullah bin Shalih] telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Az Zuhri] dari [Salim] dia berkata, ketika [Umar bin Al Khaththab] sedang berkhutbah pada hari Jum'at, kemudian dia menyebutkan hadits ini. Abu Isa berkata, saya bertanya kepada Muhammad mengenai hadits ini, dia menjawab, yang benar adalah hadits Az Zuhri dari Salim dari ayahnya. Muhammad berkata, [Malik] juga telah meriwayatkan dari [Az Zuhri] dari [Salim] dari [ayahnya] seperti hadits di atas."},"456":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ وَأَبُو جَنَابٍ يَحْيَى بْنُ أَبِي حَيَّةَ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ يَحْيَى بْنِ الْحَارِثِ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ أَوْسِ بْنِ أَوْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اغْتَسَلَ يَوْمَ الْجُمُعَةِ وَغَسَّلَ وَبَكَّرَ وَابْتَكَرَ وَدَنَا وَاسْتَمَعَ وَأَنْصَتَ كَانَ لَهُ بِكُلِّ خُطْوَةٍ يَخْطُوهَا أَجْرُ سَنَةٍ صِيَامُهَا وَقِيَامُهَاقَالَ مَحْمُودٌ قَالَ وَكِيعٌ اغْتَسَلَ هُوَ وَغَسَّلَ امْرَأَتَهُ قَالَ وَيُرْوَى عَنْ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ أَنَّهُ قَالَ فِي هَذَا الْحَدِيثِ مَنْ غَسَّلَ وَاغْتَسَلَ يَعْنِي غَسَلَ رَأْسَهُ وَاغْتَسَلَ قَالَ وَفِي الْبَاب عَنْ أَبِي بَكْرٍ وَعِمْرَانَ بْنِ حُصَيْنٍ وَسَلْمَانَ وَأَبِي ذَرٍّ وَأَبِي سَعِيدٍ وَابْنِ عُمَرَ وَأَبِي أَيُّوبَ قَالَ أَبُو عِيسَى حَدِيثُ أَوْسِ بْنِ أَوْسٍ حَدِيثٌ حَسَنٌ وَأَبُو الْأَشْعَثِ الصَّنْعَانِيُّ اسْمُهُ شَرَاحِيلُ بْنُ آدَةَ وَأَبُو جَنَابٍ يَحْيَى بْنُ حَبِيبٍ الْقَصَّابُ الْكُوفِيُّ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dan [Abu Janab Yahya bin Abu Hayyah] dari [Abdullah bin Isa] dari [Yahya bin Harits] dari [Abu Al Asy'ats As Shan'ani] dari [Aus bin Aus] dia berkata, Rasulullah Shallahu 'alaihi wa sallam bersabda: \"Barang siapa mandi pada hari Jum'at, membersihkan badannya dan bersegera (pergi kemasjid) kemudian berdiam diri dengan penuh konsentrasi, mendengarkan (khutbah), maka setiap langkah yang diayunkan mendapatkan pahala seperti pahala setahun, yaitu pahala puasanya dan shalat malamnya.\" Mahmud berkata, Waki' berkata, dia sendiri mandi dan juga memandikan istrinya (mandi bersama istrinya -pent). (perawi) berkata, diriwayatkan pula dari Abdullah bin Mubarrak bahwa dia mengomentari hadits ini, barang siapa yang memandikan dan mandi maksudnya adalah membasuh kepalanya kemudian mandi. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Abu Bakar, Imran bin Hushain, Salman, Abu Dzar, Abu Sa'id, Ibnu Umar dan Abu Ayyub. Abu Isa berkata, hadits Aus bin Aus adalah hadits hasan. Abu Asy'ats As Shan'ani namanya adalah Syarahil bin Adah dan Abu Jannab Yahya bin Habib Al Qashab."},"457":{"ar":"حَدَّثَنَا أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا سَعِيدُ بْنُ سُفْيَانَ الْجَحْدَرِيُّ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ يَوْمَ الْجُمُعَةِ فَبِهَا وَنِعْمَتْ وَمَنْ اغْتَسَلَ فَالْغُسْلُ أَفْضَلُقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَعَائِشَةَ وَأَنَسٍ قَالَ أَبُو عِيسَى حَدِيثُ سَمُرَةَ حَدِيثٌ حَسَنٌ وَقَدْ رَوَاهُ بَعْضُ أَصْحَابِ قَتَادَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ وَرَوَاهُ بَعْضُهُمْ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ بَعْدَهُمْ اخْتَارُوا الْغُسْلَ يَوْمَ الْجُمُعَةِ وَرَأَوْا أَنْ يُجْزِئَ الْوُضُوءُ مِنْ الْغُسْلِ يَوْمَ الْجُمُعَةِ قَالَ الشَّافِعِيُّ وَمِمَّا يَدُلُّ عَلَى أَنَّ أَمْرَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْغُسْلِ يَوْمَ الْجُمُعَةِ أَنَّهُ عَلَى الِاخْتِيَارِ لَا عَلَى الْوُجُوبِ حَدِيثُ عُمَرَ حَيْثُ قَالَ لِعُثْمَانَ وَالْوُضُوءُ أَيْضًا وَقَدْ عَلِمْتَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِالْغُسْلِ يَوْمَ الْجُمُعَةِ فَلَوْ عَلِمَا أَنَّ أَمْرَهُ عَلَى الْوُجُوبِ لَا عَلَى الِاخْتِيَارِ لَمْ يَتْرُكْ عُمَرُ عُثْمَانَ حَتَّى يَرُدَّهُ وَيَقُولَ لَهُ ارْجِعْ فَاغْتَسِلْ وَلَمَا خَفِيَ عَلَى عُثْمَانَ ذَلِكَ مَعَ عِلْمِهِ وَلَكِنْ دَلَّ فِي هَذَا الْحَدِيثِ أَنَّ الْغُسْلَ يَوْمَ الْجُمُعَةِ فِيهِ فَضْلٌ مِنْ غَيْرِ وُجُوبٍ يَجِبُ عَلَى الْمَرْءِ فِي ذَلِكَ","id":"Telah menceritakan kepada kami [Abu Musa Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Sa'id bin Sufyan Al Jahdari] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Al Hasan] dari [Samrah bin Jundab] dia berkata, Rasulullah Shallahu 'alaihi wa sallam bersabda: \"Barang siapa yang berwudlu' pada hari Jum'at maka hal itu sudah mencukupinya dan baik, akan tetapi barang siapa yang mandi, maka mandi itu lebih utama.\" (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Abu Hurairah, 'Aisyah dan Anas. Abu Isa berkata, hadits Samrah adalah hadits hasan. Sebagian sahabat Qatadah juga telah meriwayatkan dari Qatadah dari Hasan dari Samrah bin Jundab, sebagiannya lagi meriwayatkan dari Qatadah dari Hasan dari Nabi Shallahu 'alaihi wa sallam secara mursal. Hadits ini juga diamalkan oleh ahli ilmu dari para sahabat Nabi Shallahu 'alaihi wa sallam dan generasi setelahnya, bahwa mereka memilih mandi pada hari Jum'at, akan tetapi (mereka juga berpendapat) bahwa wudlu' pada hari Jum'at telah mencukupi (sebagai pengganti) dari mandi. Syafi'i berkata, diantara hal-hal yang menunjukkan bahwa perintah Nabi Shallahu 'alaihi wa sallam untuk mandi pada hari Jum'at hanya sekedar alternatif, bukan suatu kewajiban, adalah hadits Umar yang berkata kepada Utsman \"dan wudlu' (telah cukup), sungguh kamu telah mengetahui bahwa Rasulullah Shallahu 'alaihi wa sallam memerintahkan untuk mandi pada hari Jum'at. Seandainya (Umar dan Utsman) mengetahui bahwa perintahnya adalah wajib, bukan sekedar alternatif, tentu Umar tidak akan membiarkan 'Utsman dan menolaknya untuk datang tanpa mandi terlebih dahulu, seraya berkata kepadanya \"Pulanglah dan mandilah terlebih dahulu.\" Utsman pun mengetahui hal itu, tetapi yang ditunjukkan dalam hadits tersebut bahwa mandi pad ahari Jum'at merupakan keutamaan, dan tidak diwajibkan atas seseorang."},"458":{"ar":"حَدَّثَنَا هَنَّادٌ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ فَ��َحْسَنَ الْوُضُوءَ ثُمَّ أَتَى الْجُمُعَةَ فَدَنَا وَاسْتَمَعَ وَأَنْصَتَ غُفِرَ لَهُ مَا بَيْنَهُ وَبَيْنَ الْجُمُعَةِ وَزِيَادَةُ ثَلَاثَةِ أَيَّامٍ وَمَنْ مَسَّ الْحَصَى فَقَدْ لَغَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] dia berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata, Rasulullah Shallahu 'alaihi wa sallam bersabda: \"Barang siapa berwudlu' kemudian menyempurnakan wudlu'nya lalu mendatangi shalat Jum'at, lalu dia mendekat, mendengarkan serta berdiam diri (untuk menyimak khutbah), maka akan diampuni dosa-dosanya diantara hari itu sampai Jum'at (berikutnya) dan ditambah tiga hari setelah itu. Barang siapa yang bermain kerikil, maka ia telah melakukan perbuatan sia-sia.\" Abu Isa berkata, ini adalah hadits hasan shahih."},"459":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اغْتَسَلَ يَوْمَ الْجُمُعَةِ غُسْلَ الْجَنَابَةِ ثُمَّ رَاحَ فَكَأَنَّمَا قَرَّبَ بَدَنَةً وَمَنْ رَاحَ فِي السَّاعَةِ الثَّانِيَةِ فَكَأَنَّمَا قَرَّبَ بَقَرَةً وَمَنْ رَاحَ فِي السَّاعَةِ الثَّالِثَةِ فَكَأَنَّمَا قَرَّبَ كَبْشًا أَقْرَنَ وَمَنْ رَاحَ فِي السَّاعَةِ الرَّابِعَةِ فَكَأَنَّمَا قَرَّبَ دَجَاجَةً وَمَنْ رَاحَ فِي السَّاعَةِ الْخَامِسَةِ فَكَأَنَّمَا قَرَّبَ بَيْضَةً فَإِذَا خَرَجَ الْإِمَامُ حَضَرَتْ الْمَلَائِكَةُ يَسْتَمِعُونَ الذِّكْرَقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَسَمُرَةَ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] telah menceritakan kepada kami [Ma'n] telah menceritakan kepada kami [Malik] dari [Sumayy] dari [Abu Shalih] dari [Abu Hurairah] bahwasannya Rasulullah Shallahu 'alaihi wa sallam bersabda: \"Barang siapa mandi pada hari Jum'at sebagaimana mandi janabat (besar) kemudian datang (ke tempat shalat Jum'at sebagai orang pertama kali datang), maka seakan-akan ia berkurban seekor unta, dan barang siapa yang datang pada kesempatan kedua, maka seakan-akan ia berkurban seekor sapi, barang siapa yang datang pada kesempatan ketiga, maka seakan-akan ia berkurban seekor domba yang bertanduk, barang siapa yang datang pada kesempatan keempat, maka seakan-akan ia berkurban seekor ayam, barang siapa yang datang pada kesempatan kelima, seakan-akan ia berkurban sebutir telur, tatkala seorang imam keluar (menuju mimbar), maka para Malaikat berdatangan untuk mendengarkan khutbah.\" Abu Isa berkata, hadits Abu Hurairah adalah hadits hasan shahih."},"460":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ عَبِيدَةَ بْنِ سُفْيَانَ عَنْ أَبِي الْجَعْدِ يَعْنِي الضَّمْرِيَّ وَكَانَتْ لَهُ صُحْبَةٌ فِيمَا زَعَمَ مُحَمَّدُ بْنُ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَرَكَ الْجُمُعَةَ ثَلَاثَ مَرَّاتٍ تَهَاوُنًا بِهَا طَبَعَ اللَّهُ عَلَى قَلْبِهِقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَابْنِ عَبَّاسٍ وَسَمُرَةَ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي الْجَعْدِ حَدِيثٌ حَسَنٌ قَالَ وَسَأَلْتُ مُحَمَّدًا عَنْ اسْمِ أَبِي الْجَعْدِ الضَّمْرِيِّ فَلَمْ يَعْرِفْ اسْمَهُ وَقَالَ لَا أَعْرِفُ لَهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا هَذَا الْحَدِيثَ قَالَ أَبُو عِيسَى وَلَا نَعْرِفُ هَذَا الْحَدِيثَ إِلَّا مِنْ حَدِيثِ مُحَمَّدِ بْنِ عَمْرٍو","id":"Telah menceritakan kepada kami [Ali bin Khasyram] telah mengabarkan kepada kami [Isa bin Yunus] dari [Muhammad bin Amru] dari ['Abidah bin Sufyan] dari [Abu Ja'd yaitu Adl Dlamri] dan dia pernah bertemu (dengan Rasulullah) sebagaimana yang diperkirakan Muhammad bin Amru dia berkata, Rasulullah Shallahu 'alaihi wa sallam bersabda: \"Barang siapa yang meninggalkan shalat Jum'at sebanyak tiga kali karena meremehkannya, maka Allah akan menutup hatinya.\" (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Ibnu Umar, Ibnu 'Abbas dan Samrah. Abu Isa berkata, hadits Abu Ja'd adalah hadits hasan. Dia berkata, saya bertanya kepada Muhammad mengenai namanya Abu Ja'd Ad Dlamri, tetapi ia tidak mengetahui namanya seray aberkata, saya tidak mengetahui darinya apa yang datang dari Nabi Shallahu 'alaihi wa sallam melainkan hadits ini. Abu Isa berkata, kami tidak mengetahui hadits ini kecuali dari hadits Muhammad bin Amru."},"461":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ وَمُحَمَّدُ بْنُ مَدُّوَيْهِ قَالَا حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ ثُوَيْرٍ عَنْ رَجُلٍ مِنْ أَهْلِ قُبَاءَ عَنْ أَبِيهِ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَأَمَرَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَشْهَدَ الْجُمُعَةَ مِنْ قُبَاءَوَقَدْ رُوِيَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا وَلَا يَصِحُّ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَلَا يَصِحُّ فِي هَذَا الْبَابِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْءٌ وَقَدْ رُوِيَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الْجُمُعَةُ عَلَى مَنْ آوَاهُ اللَّيْلُ إِلَى أَهْلِهِ وَهَذَا حَدِيثٌ إِسْنَادُهُ ضَعِيفٌ إِنَّمَا يُرْوَى مِنْ حَدِيثِ مُعَارِكِ بْنِ عَبَّادٍ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدٍ الْمَقْبُرِيِّ وَضَعَّفَ يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَبْدَ اللَّهِ بْنَ سَعِيدٍ الْمَقْبُرِيَّ فِي الْحَدِيثِ فَقَالَ وَاخْتَلَفَ أَهْلُ الْعِلْمِ عَلَى مَنْ تَجِبُ الْجُمُعَةُ قَالَ بَعْضُهُمْ تَجِبُ الْجُمُعَةُ عَلَى مَنْ آوَاهُ اللَّيْلُ إِلَى مَنْزِلِهِ و قَالَ بَعْضُهُمْ لَا تَجِبُ الْجُمُعَةُ إِلَّا عَلَى مَنْ سَمِعَ النِّدَاءَ وَهُوَ قَوْلُ الشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ سَمِعْت أَحْمَدَ بْنَ الْحَسَنِ يَقُولُ كُنَّا عِنْدَ أَحْمَدَ بْنِ حَنْبَلٍ فَذَكَرُوا عَلَى مَنْ تَجِبُ الْجُمُعَةُ فَلَمْ يَذْكُرْ أَحْمَدُ فِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا قَالَ أَحْمَدُ بْنُ الْحَسَنِ فَقُلْتُ لِأَحْمَدَ بْنِ حَنْبَلٍ فِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَحْمَدُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ نَعَمْ قَالَ أَحْمَدُ بْنُ الْحَسَنِ حَدَّثَنَا حَجَّاجُ بْنُ نُصَيْرٍ حَدَّثَنَا مُعَارِكُ بْنُ عَبَّادٍ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْجُمُعَةُ عَلَى مَنْ آوَاهُ اللَّيْلُ إِلَى أَهْلِهِ قَالَ فَغَضِبَ عَلَيَّ أَحْمَدُ بْنُ حَنْبَلٍ وَقَالَ لِي اسْتَغْفِرْ رَبَّكَ اسْتَغْفِرْ رَبَّكَ قَالَ أَبُو عِيسَى إِنَّمَا فَعَلَ أَحْمَدُ بْنُ حَنْبَلٍ هَذَا لِأَنَّهُ لَمْ يَعُدَّ هَذَا الْحَدِيثَ شَيْئًا وَضَعَّفَهُ لِحَالِ إِسْنَادِهِ","id":"Telah menceritakan kepada kami [Abd bin Humaid] dan [Muhammad bin Madduwaih] keduanya berkata, telah menceritakan kepada kami [Al Fadll bin Dukain] telah menceritakan kepada kami [Isra'il] dari [Tsuwair] dari [seorang lelaki penduduk Quba'] dari [ayahnya] dia termasuk dari sahabat Nabi Shallahu 'alaihi wa sallam, dia berkata, Nabi Shallahu 'alaihi wa sallam memerintahkan kami menghadiri shalat Jum'at di Quba'. Dan telah diriwayatkan dari Abu Hurairah dari Nabi Shallahu 'alaihi wa sallam dalam hal ini, namun (periwayatannya) tidak shahih. Abu Isa berkata, kami tidak mengetahui hadits ini kecuali dari jalur ini, dan dalam bab ini juga tidak ada yang sah (jalur periwayatannya). Telah diriwayatkan dari Abu Hurairah dari Nabi Shallahu 'alaihi wa sallam bahwa beliau bersabda: \"Kewajiban Jum'at adalah bagi orang yang mendapati malam bersama keluarganya.\" Hadits ini sanadnya lemah, yang diriwayatkan dari hadits Mu'arik bin 'Abbad dari Abdullah bin Sa'id Al Maqburi. Yahya bin Sa'id Al Qatthan telah melemahkan Abdullah bin Sa'id Al Maqburi dalam masalah hadits. (perawi) berkata, para ahli ilmu berbeda pendapat tentang siapakah yang diwajibkan melaksanakan shalat Jum'at, sebagian berpendapat bahwa Jum'at wajib bagi orang yang dapat bermalam dengan keluarganya, sedangkan sebagian yang lain berpendapat Jum'at tidak wajib kecuali bagi orang yang dapat mendengar panggilan, ini adalah pendapat Imam Syafi'i, Ahmad dan Ishaq, (perawi berkata) saya telah mendengar Ahmad bin Al Hasan berkata, kami berada di sisi Ahmad bin Hambal, kemudian orang-orang berbicara mengenai orang yang diwajibkan melaksanakan shalat Jum'at, Ahmad tidak menyebutkan dalam masalah itu satu haditspun dari Nabi Shallahu 'alaihi wa sallam, Ahmad bin Al Hasan berkata, maka saya berkata kepada Ahmad bin Hambal, ternyata dalam masalah ini ada riwayat dari Abu Hurairah dari Nabi Shallahu 'alaihi wa sallam. Maka Ahmad bertanya, dari Nabi Shallahu 'alaihi wa sallam? Saya menjawab, ya. Ahmad bin Al Hasan berkata, telah menceritakan kepada kami Hajjaj bin Nushair telah menceritakan kepada kami Mu'arik bin 'Abbad dari Abdullah bin Sa'id Al Maqburi dari ayahnya dari Abu Hurairah dari Nabi Shallahu 'alaihi wa sallam, beliau bersabda: \"Jum'at itu wajib bagi orang yang dapat bermalam dengan keluarganya.\" Ahmad bin Al Hasan berkata, maka Ahmad bin Hambal langsung marah kepadaku sambil berkata kepadaku, beristighfarlah kepada Rabbmu, beristighfarlah kepada Rabbmu. Abu Isa berkata, Ahmad bin Hambal melakukan demikian ini karena dia tidak menganggap hadits ini sama sekali, bahkan dia melemahkan karena sanadnya."},"462":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ عُثْمَانَ بْنِ عَبْدِ الرَّحْمَنِ التَّيْمِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي الْجُمُعَةَ حِينَ تَمِيلُ الشَّمْسُحَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ عُثْمَانَ بْنِ عَبْدِ الرَّحْمَنِ التَّيْمِيِّ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ وَفِي الْبَاب عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ وَجَابِرٍ وَالزُّبَيْرِ بْنِ الْعَوَّامِ قَالَ أَبُو عِيسَى حَدِيثُ أَنَسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ الَّذِي أَجْمَعَ عَلَيْهِ أَكْثَرُ أَهْلِ الْعِلْمِ أَنَّ وَقْتَ الْجُمُعَةِ إِذَا زَالَتْ الشَّمْسُ كَوَقْتِ الظُّهْرِ وَهُوَ قَوْلُ الشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ وَرَأَى بَعْضُهُمْ أَنَّ صَلَاةَ الْجُمُعَةِ إِذَا صُلِّيَتْ قَبْلَ الزَّوَالِ أَنَّهَا تَجُوزُ أَيْضًا و قَالَ أَحْمَدُ وَمَنْ صَلَّاهَا قَبْلَ الزَّوَالِ فَإِنَّهُ لَمْ يَرَ عَلَيْهِ إِعَادَةً","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Suraij bin Nu'man] telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Utsman bin Abdurrahman At Taimi] dari [Anas bin Malik] bahwasannya Nabi Shallahu 'alaihi wa sallam melaksanakan shalat Jum'at tatkala matahari mulai condong. Telah menceritakan kepada kami [Yahya bin Musa] telah menceritakan kepada kami [Abu Daud At Thayalisi] telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Utman bin Abdurrahman At Taimi] dari [Anas] dari Nabi Shallahu 'alaihi wa sallam sebagaimana hadits diatas. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Salamah bin Al Akwa', Jabir dan Zubair bin 'Awwam. Abu Isa berkata, hadits Anas adalah hadits hasan shahih, hadits ini juga dijadikan pijakan oleh ahli ilmu bahwa waktu Jum'at adalah ketika matahari mulai condong, sebagaimana waktu dluhur, seperti perkataan Syafi'i, Ahmad dan Ishaq. Sebagian yang lain berpendapat bahwa shalat Jum'at boleh dikerjakan sebelum tergelincirnya matahari, Ahmad juga berkata, barang siapa shalat Jum'at sebelum matahari tergelincir maka baginya tidak wajib untuk mengulanginya."},"463":{"ar":"حَدَّثَنَا أَبُو حَفْصٍ عَمْرُو بْنُ عَلِيٍّ الْفَلَّاسُ الصَّيْرَفِيُّ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ وَيَحْيَى بْنُ كَثِيرٍ أَبُو غَسَّانَ الْعَنْبَرِيُّ قَالَا حَدَّثَ��َا مُعَاذُ بْنُ الْعَلَاءِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْطُبُ إِلَى جِذْعٍ فَلَمَّا اتَّخَذَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمِنْبَرَ حَنَّ الْجِذْعُ حَتَّى أَتَاهُ فَالْتَزَمَهُ فَسَكَنَقَالَ وَفِي الْبَاب عَنْ أَنَسٍ وَجَابِرٍ وَسَهْلِ بْنِ سَعْدٍ وَأُبَيِّ بْنِ كَعْبٍ وَابْنِ عَبَّاسٍ وَأُمِّ سَلَمَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ وَمُعَاذُ بْنُ الْعَلَاءِ هُوَ بَصْرِيٌّ وَهُوَ أَخُو أَبِي عَمْرِو بْنِ الْعَلَاءِ","id":"Telah menceritakan kepada kami [Abu Hafsh Amru bin Ali Al Fallas As Shairafi] telah menceritakan kepada kami ['Utsman bin Umar] dan [Yahya bin Katsir Abu Ghatsan Al Anbari] keduanya berkata, telah menceritakan kepada kami [Mu'adz bin 'Ala'] dari [Nafi'] dari [Ibnu Umar] bahwasannya Nabi Shallahu 'alaihi wa sallam berkhutbah dengan menggunakan pelepah kurma, tatkala Nabi Shallahu 'alaihi wa sallam beralih dengan menggunakan minbar, maka pelepah tersebut menangis sehingga beliau mendatanginya dan memegangnya sampai tenang. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Anas, Jabir, Sahl bin Sa'd, Ubay bin Ka'ab, Ibnu Abbas dan Ummu Salamah. Abu Isa berkata, hadits Ibnu Umar adalah hadits hasan gharib shahih. Mu'adz bin 'Ala' adalah Bashri ia merupakan saudara laki-lakinya Amru bin 'Ala'."},"464":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ الْبَصْرِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْطُبُ يَوْمَ الْجُمُعَةِ ثُمَّ يَجْلِسُ ثُمَّ يَقُومُ فَيَخْطُبُ قَالَ مِثْلَ مَا تَفْعَلُونَ الْيَوْمَقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَجَابِرِ بْنِ عَبْدِ اللَّهِ وَجَابِرِ بْنِ سَمُرَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ الَّذِي رَآهُ أَهْلُ الْعِلْمِ أَنْ يَفْصِلَ بَيْنَ الْخُطْبَتَيْنِ بِجُلُوسٍ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah Al Bashri] telah menceritakan kepada kami [Khalid bin Harits] telah menceritakan kepada kami ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi Shallahu 'alaihi wa sallam berkhutbah pada hari Jum'at kemudian duduk, lalu berdiri melanjutkan berkhutbah. Ibnu Umar berkata, seperti yang kalian lakukan hari ini. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Ibnu 'Abbas, Jabir bin Abdullah dan Jabir bin Samrah. Abu Isa berkata, hadits Ibnu Umar adalah hadits hasan shahih, hadits tersebut juga menjadi pendapat ahli ilmu, yaitu hendaknya antara dua khutbah dipisah dengan duduk."},"465":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَهَنَّادٌ قَالَا حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكُنْتُ أُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَتْ صَلَاتُهُ قَصْدًا وَخُطْبَتُهُ قَصْدًاقَالَ وَفِي الْبَاب عَنْ عَمَّارِ بْنِ يَاسِرٍ وَابْنِ أَبِي أَوْفَى قَالَ أَبُو عِيسَى حَدِيثُ جَابِرِ بْنِ سَمُرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] dan [Hannad] keduanya berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak bin Harb] dari [Jabir bin Samrah] dia berkata, saya shalat bersama Nabi Shallahu 'alaihi wa sallam, ternyata shalatnya sederhana dan khutbahnya juga sederhana (tidak panjang). (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari 'Ammar bin Yasir dan Ibnu Abu Aufa . Abu Isa berkata, hadits Jabir bin Samrah adalah hadits hasan shahih."},"466":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءٍ عَنْ صَفْوَانَ بْنِ يَعْلَى بْنِ أُمَيَّةَ عَنْ أَبِيهِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ عَلَى الْمِنْبَرِ{ وَنَادَوْا يَا مَالِكُ }قَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَجَابِرِ بْنِ سَمُرَةَ قَالَ أَبُو عِيسَى حَدِيثُ يَعْلَى بْنِ أُمَيَّةَ حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَهُوَ حَدِيثُ ابْنِ عُيَيْنَةَ وَقَدْ اخْتَارَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ أَنْ يَقْرَأَ الْإِمَامُ فِي الْخُطْبَةِ آيًا مِنْ الْقُرْآنِ قَالَ الشَّافِعِيُّ وَإِذَا خَطَبَ الْإِمَامُ فَلَمْ يَقْرَأْ فِي خُطْبَتِهِ شَيْئًا مِنْ الْقُرْآنِ أَعَادَ الْخُطْبَةَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Amru bin Dinar] dari [Atha'] dari [Shafwan bin Ya'la bin 'Umaiyah] dari [bapaknya] dia berkata, saya telah mendengar Nabi Shallahu 'alaihi wa sallam membaca atas mimbar \"WANAADAU YAA MAALIKU\". (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Abu Hurairah dan Jabir bin Samrah. Abu Isa berkata, hadits Ya'la bin 'Umaiyah adalah hadits hasan shahih gharib, ia merupakan hadits Ibnu Uyainah, sebagian ahli ilmu memilih hendaknya imam membaca ayat dari Al Qur'an dalam khutbah. Imam Syafi'I berkata, apabila seorang imam berkhutbah, kemudian tidak membaca ayat dari Al Qur'an dalam khutbahnya, maka dia harus mengulangi khutbahnya."},"467":{"ar":"حَدَّثَنَا عَبَّادُ بْنُ يَعْقُوبَ الْكُوفِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ الْفَضْلِ بْنِ عَطِيَّةَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَوَى عَلَى الْمِنْبَرِ اسْتَقْبَلْنَاهُ بِوُجُوهِنَاقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَحَدِيثُ مَنْصُورٍ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ مُحَمَّدِ بْنِ الْفَضْلِ بْنِ عَطِيَّةَ وَمُحَمَّدُ بْنُ الْفَضْلِ بْنِ عَطِيَّةَ ضَعِيفٌ ذَاهِبُ الْحَدِيثِ عِنْدَ أَصْحَابِنَا وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ يَسْتَحِبُّونَ اسْتِقْبَالَ الْإِمَامِ إِذَا خَطَبَ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَالشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ قَالَ أَبُو عِيسَى وَلَا يَصِحُّ فِي هَذَا الْبَابِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْءٌ","id":"Telah menceritakan kepada kami [Abbad bin Ya'qub Al Kufi] telah menceritakan kepada kami [Muhammad bin Al Fadlal bin 'Athiyah] dari [Manshur] dari [Ibrahim] dari [Alqamah] dari [Abdullah bin Mas'ud] dia berkata, apabila Rasulullah Shalallhu 'alaihi wa salam berada di atas mimbar, maka kami menghadap ke arahnya dengan seluruh wajah kami. Abu Isa berkata, dalam bab ini (ada juga riwayat -pent) dari Ibnu Umar. Hadits Manshur tidak kami ketahui kecuali dari hadits Muhammad bin Al Fadll bin 'Athiyah, sedangkan Muhammad bin Al Fadll bin 'Athiyah adalah lemah.\"Dzahibul hadits\" menurut sahabat kami. Hadits ini juga diamalkan oleh para ahli ilmu dari kalangan sahabat Nabi Sahalallahu 'alaihi wa salam dan yang lainnya, bahwa mereka mengistihbabkan (menyukai) menghadap kearah imam apabila sedang berkhutbah, (hadits ini) juga sebagai pendapat Sufyan Ats Tsauri, Syafi'i, Ahmad, dan Ishaq. Abu Isa berkata, tidak sah satu haditspun dari Nabi Shallahu 'alaihi wa sallam dalam bab ini."},"468":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَبَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ يَوْمَ الْجُمُعَةِ إِذْ جَاءَ رَجُلٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَلَّيْتَ قَالَ لَا قَالَ قُمْ فَارْكَعْقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ أَصَحُّ شَيْءٍ فِي هَذَا الْبَابِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad bin Zaid] dari [Amru bin Dinar] dari [Jabir bin Abdullah] dia berkata, ketika Nabi Shallahu 'alaihi wa sallam berkhutbah pada hari Jum'at, tiba-tiba seorang laki-laki datang, maka Nabi Shallahu 'alaihi wa sallam bersabda: \"Apakah kamu sudah shalat?\" dia menjawab, belum. Beliau bersabda: \"Bangun dan kerjakanlah shalat.\" Abu Isa berkata, ini adalah hadits hasan shahih, lebih shahih dalam bab ini."},"469":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي سَرْحٍ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّدَخَلَ يَوْمَ الْجُمُعَةِ وَمَرْوَانُ يَخْطُبُ فَقَامَ يُصَلِّي فَجَاءَ الْحَرَسُ لِيُجْلِسُوهُ فَأَبَى حَتَّى صَلَّى فَلَمَّا انْصَرَفَ أَتَيْنَاهُ فَقُلْنَا رَحِمَكَ اللَّهُ إِنْ كَادُوا لَيَقَعُوا بِكَ فَقَالَ مَا كُنْتُ لِأَتْرُكَهُمَا بَعْدَ شَيْءٍ رَأَيْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ ذَكَرَ أَنَّ رَجُلًا جَاءَ يَوْمَ الْجُمُعَةِ فِي هَيْئَةٍ بَذَّةٍ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ يَوْمَ الْجُمُعَةِ فَأَمَرَهُ فَصَلَّى رَكْعَتَيْنِ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُقَالَ ابْنُ أَبِي عُمَرَ كَانَ سُفْيَانُ بْنُ عُيَيْنَةَ يُصَلِّي رَكْعَتَيْنِ إِذَا جَاءَ وَالْإِمَامُ يَخْطُبُ وَكَانَ يَأْمُرُ بِهِ وَكَانَ أَبُو عَبْدِ الرَّحْمَنِ الْمُقْرِئُ يَرَاهُ قَالَ أَبُو عِيسَى و سَمِعْت ابْنَ أَبِي عُمَرَ يَقُولُ قَالَ سُفْيَانُ بْنُ عُيَيْنَةَ كَانَ مُحَمَّدُ بْنُ عَجْلَانَ ثِقَةً مَأْمُونًا فِي الْحَدِيثِ قَالَ وَفِي الْبَاب عَنْ جَابِرٍ وَأَبِي هُرَيْرَةَ وَسَهْلِ بْنِ سَعْدٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي سَعِيدٍ الْخُدْرِيِّ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ وَبِهِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ و قَالَ بَعْضُهُمْ إِذَا دَخَلَ وَالْإِمَامُ يَخْطُبُ فَإِنَّهُ يَجْلِسُ وَلَا يُصَلِّي وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَأَهْلِ الْكُوفَةِ وَالْقَوْلُ الْأَوَّلُ أَصَحُّ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا الْعَلَاءُ بْنُ خَالِدٍ الْقُرَشِيُّ قَالَ رَأَيْتُ الْحَسَنَ الْبَصْرِيَّ دَخَلَ الْمَسْجِدَ يَوْمَ الْجُمُعَةِ وَالْإِمَامُ يَخْطُبُ فَصَلَّى رَكْعَتَيْنِ ثُمَّ جَلَسَ إِنَّمَا فَعَلَ الْحَسَنُ اتِّبَاعًا لِلْحَدِيثِ وَهُوَ رَوَى عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا الْحَدِيثَ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Umar] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Muhammad bin 'Ajlan] dari ['Iyadl bin Abdullah bin Abu Sarh] bahwa [Abu Sa'id Al Khudri] masuk masjid pada hari Jum'at, sementara Marwan sedang berkhutbah, lantas dia (Abu Sa'id) berdiri untuk melaksanakan shalat, maka datanglah para pengawalnya dan menyuruhnya untuk duduk, namun dia menolak sampai dia selesai mengerjakan shalat, ketika ia (Marwan) beranjak pergi (dari shalat Jum'at), kami mendatanginya dan berkata, Semoga Allah merahmatimu hampir saja mereka melakukan sesuatu kepadamu, Abu Sa'id berkata, saya tidak akan meniggalkan dua raka'at itu selamanya setelah saya melihatnya dari Rasulullah Shallahu 'alaihi wa sallam.\" kemudian dia menyebutkan bahwa ada seorang lelaki yang datang pada hari Jum'at dalam keadaan lusuh, Sementara Nabi Shallahu 'alaihi wa sallam sedang berkhutbah, lantas beliau menyuruhnya untuk shalat dua raka'at, padahal beliau sedang berkhutbah. Ibnu Abu Umar berkata, Sufyan bin 'Uyainah biasa melaksanakan shalat dua raka'at, padahal imam sedang berkhutbah dan dia juga memerintahkan untuk mengerjakan shalat tersebut, padahal Abu Abdurrahman Al Muqri' melihatnya. Abu Isa berkata, saya mendengar Ibnu Abu Umar berkata, Sufyan bin 'Uyainah berkata, Muhammad bin Ajlan adalah tsiqah dan terpercaya dalam periwayatan haditsnya. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Jabir, Abu Hurairah dan Sahl bin Sa'ad. Abu Isa berkata, hadits Abu Sa'id Al Khudri adalah hadits hasan shahih, hadits ini juga diamalkan oleh sebagian ahli ilmu. Ini adalah pendapat Imam Syafi'I, Ahmad dan Ishaq. Sedangkan sebagian ahli ilmu yang lain berpendapat bahwa apabila seseorang masuk (masjid) dan imam sedang berkhutbah, maka hendaknya dia duduk dan tidak melaksanakan shalat, ini adalah pendapat Sufyan Ats Tsauri dan penduduk Kufah. Sedangkan pendapat pertama adalah yang paling shahih. Telah menceritakan kepada kami Qutaibah telah menceritakan kepada kami Al 'la bin Khalid Al Qurasyi dia berkata, saya melihat Hasan Al Bashri masuk masjid pada hari Jum'at sedangkan imam berkhutbah, kemudian dia melaksanakan shalat dua raka'at lalu duduk, hanyasanya Hasan melakukan hal itu karena mengikuti hadits, dan dia telah meriwayatkan hadits ini dari Jabir dari Nabi Shallahu 'alaihi wa sallam."},"470":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ يَوْمَ الْجُمُعَةِ وَالْإِمَامُ يَخْطُبُ أَنْصِتْ فَقَدْ لَغَاقَالَ وَفِي الْبَاب عَنْ ابْنِ أَبِي أَوْفَى وَجَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَهْلِ الْعِلْمِ كَرِهُوا لِلرَّجُلِ أَنْ يَتَكَلَّمَ وَالْإِمَامُ يَخْطُبُ وَقَالُوا إِنْ تَكَلَّمَ غَيْرُهُ فَلَا يُنْكِرْ عَلَيْهِ إِلَّا بِالْإِشَارَةِ وَاخْتَلَفُوا فِي رَدِّ السَّلَامِ وَتَشْمِيتِ الْعَاطِسِ وَالْإِمَامُ يَخْطُبُ فَرَخَّصَ بَعْضُ أَهْلِ الْعِلْمِ فِي رَدِّ السَّلَامِ وَتَشْمِيتِ الْعَاطِسِ وَالْإِمَامُ يَخْطُبُ وَهُوَ قَوْلُ أَحْمَدَ وَإِسْحَقَ وَكَرِهَ بَعْضُ أَهْلِ الْعِلْمِ مِنْ التَّابِعِينَ وَغَيْرِهِمْ ذَلِكَ وَهُوَ قَوْلُ الشَّافِعِيِّ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Az Zuhri] dari [Sa'id bin Al Musayyib] dari [Abu Hurairah] bahwasannya Nabi Shallahu 'alaihi wa sallam bersabda: \"Barang siapa yang berkata \"diamlah\" pada hari Jum'at padahal imam berkhutbah, maka ia telah melakukan perbuatan sia-sia.\" (perawi) berkata, dalam bab ini, (ada juga riwayat -pent) dari Ibnu Abi Aufa dan Jabir bin Abdullah. Abu Isa berkata, hadits Abu Hurairah adalah hadits hasan shahih dan diamalkan pula oleh ahli ilmu, mereka membenci seseorang yang berbicara sedangkan imam sedang berkhutbah, mereka berkata, jika ada seseorang yang berkata, lebih baik ia tidak diperingatkan melainkan dengan isyarat. Mereka berselisih mengenai menjawab salam dan mendo'akan orang yang bersin waktu imam sedang berkhutbah, ini merupakan pendapat Ahmad dan Ishaq. Sebagian Ahli ilmu dari kalangan tabi'in dan yang lainnya membenci yang demikian itu, sebagaimana perkataan Syafi'i."},"471":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا رِشْدِينُ بْنُ سَعْدٍ عَنْ زَبَّانَ بْنِ فَائِدٍ عَنْ سَهْلِ بْنِ مُعَاذِ بْنِ أَنَسٍ الْجُهَنِيِّ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَخَطَّى رِقَابَ النَّاسِ يَوْمَ الْجُمُعَةِ اتَّخَذَ جِسْرًا إِلَى جَهَنَّمَقَالَ وَفِي الْبَاب عَنْ جَابِرٍ قَالَ أَبُو عِيسَى حَدِيثُ سَهْلِ بْنِ مُعَاذِ بْنِ أَنَسٍ الْجُهَنِيِّ حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ رِشْدِينَ بْنِ سَعْدٍ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَهْلِ الْعِلْمِ كَرِهُوا أَنْ يَتَخَطَّى الرَّجُلُ رِقَابَ النَّاسِ يَوْمَ الْجُمُعَةِ وَشَدَّدُوا فِي ذَلِكَ وَقَدْ تَكَلَّمَ بَعْضُ أَهْلِ الْعِلْمِ فِي رِشْدِينَ بْنِ سَعْدٍ وَضَعَّفَهُ مِنْ قِبَلِ حِفْظِهِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Risydin bin Sa'ad] dari [Zabban bin Faid] dari [Sahl bin Mu'adz bin Anas Al Juhani] dari [ayahnya] dia berkata, Rasulullah Shallahu 'alaihi wa sallam bersabda: \"Barangsiapa yang melangkahi pundak orang lain pda hari (khutbah) jum'at, maka ia telah mengambil jembatan menuju neraka Jahannam.\" (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Jabir. Abu Isa berkata, hadits Sahl bin Mu'adz bin Anas Al Juhani adalah hadits gharib, kami tidak mengetahuinya melainkan dari hadits Rasydin bin Sa'ad. Para ahli ilmu juga mengamalkan hadits ini bahwa mereka membenci seseorang yang melangkahi pundak orang lain pada hari (khutbah) jum'at, mereka sangat keras dalam masalah tersebut, dan sebagian ahli ilmu juga mengomentari (riwayat) Risydin bin Sa'ad, mereka melemahkan dari segi hafalannya."},"472":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ الرَّازِيُّ وَعَبَّاسُ بْنُ مُحَمَّدٍ الدُّورِيُّ قَالَا حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ الْمُقْرِئُ عَنْ سَعِيدِ بْنِ أَبِي أَيُّوبَ حَدَّثَنِي أَبُو مَرْحُومٍ عَنْ سَهْلِ بْنِ مُعَاذٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْحِبْوَةَ يَوْمَ الْجُمُعَةِ وَالْإِمَامُ يَخْطُبُقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ وَأَبُو مَرْحُومٍ اسْمُهُ عَبْدُ الرَّحِيمِ بْنُ مَيْمُونٍ وَقَدْ كَرِهَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ الْحِبْوَةَ يَوْمَ الْجُمُعَةِ وَالْإِمَامُ يَخْطُبُ وَرَخَّصَ فِي ذَلِكَ بَعْضُهُمْ مِنْهُمْ عَبْدُ اللَّهِ بْنُ عُمَرَ وَغَيْرُهُ وَبِهِ يَقُولُ أَحْمَدُ وَإِسْحَقُ لَا يَرَيَانِ بِالْحِبْوَةِ وَالْإِمَامُ يَخْطُبُ بَأْسًا","id":"Telah menceritakan kepada kami [Muhammad bin Humaid Ar Razi] dan [Abbas bin Muhammad Ad Duri] keduanya berkata, telah menceritakan kepada kami [Abu Abdurrahman Al Muqri'] dari [Sa'id bin Abu Ayyub] telah menceritakan kepadaku [Abu Marhum] dari [Sahl bin Mu'adz] dari [ayahnya] bahwasannya Nabi Shallahu 'alaihi wa sallam melarang dari duduk ihba' (duduk dengan meletakkan kedua lutut didada) pada hari (khutbah) Jum'at, sewaktu imam berkhutbah. Abu Isa berkata, ini adalah hadits hasan, namanya Abu Marhum adalah 'Abdur Rahim bin Maimun, sebagian kaum dari ahli ilmu membenci duduk ihab' pada hari (khutbah) jum'at, sewaktu imam berkhutbah, dan sebagian yang lain memberi keringanan (rukhsah) dalam urusan itu, diantaranya adalah Abdullah bin Umar dan yang lain, Ahmad dan Ishaq berkata, bahwa keduanya tidak sependapat dengan duduk ihba' pada waktu imam sedang berkhutbah."},"473":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُصَيْنٌ قَالَسَمِعْتُ عُمَارَةَ بْنَ رُوَيْبَةَ الثَّقَفِيَّ وَبِشْرُ بْنُ مَرْوَانَ يَخْطُبُ فَرَفَعَ يَدَيْهِ فِي الدُّعَاءِ فَقَالَ عُمَارَةُ قَبَّحَ اللَّهُ هَاتَيْنِ الْيُدَيَّتَيْنِ الْقُصَيَّرَتَيْنِ لَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا يَزِيدُ عَلَى أَنْ يَقُولَ هَكَذَا وَأَشَارَ هُشَيْمٌ بِالسَّبَّابَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Hushain] dia berkata, saya mendengar [Umarah bin Ruwaibah At Tsaqafi] sedangkan Bisyr bin Marwan berkhutbah, lalu dia mengangkat kedua tangannya waktu berdo'a, maka Umarah berkata, semoga Allah menghinakan kedua tanganmu yang pendek, sungguh saya telah melihat Rasulullah Shallahu 'alaihi wa sallam, beliau tidak menambah dengan mengatakan seperti ini, lalu Husyaim mengisyaratkan dengan jari telunjuknya. Abu Isa berkata, ini adalah hadits hasan shahih."},"474":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ الْخَيَّاطُ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ السَّائِبِ بْنِ يَزِيدَ قَالَكَانَ الْأَذَانُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ إِذَا خَرَجَ الْإِمَامُ وَإِذَا أُقِيمَتْ الصَّلَاةُ فَلَمَّا كَانَ عُثْمَانُ رَضِيَ اللَّهُ عَنْهُ زَادَ النِّدَاءَ الثَّالِثَ عَلَى الزَّوْرَاءِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'], telah menceritakan kepada kami [Hammad bin Khalid Al Khayyath] dari [Ibnu Abu Dzi'b] dari [Az Zuhri] dari [As Sa'ib bin Yazid] dia berkata, pada masa Rasulullah Shallahu 'alaihi wa sallam, Abu Bakar dan Umar adzan (dikumandangkan) yaitu ketika imam telah keluar (menuju masjid) dan iqamat telah ditegakkan. Akan tetapi Utsman menambah adzan ketiga diatas tempat yang jauh dari masjid. Abu Isa berkata, ini adalah hadits hasan shahih."},"475":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَلَّمُ بِالْحَاجَةِ إِذَا نَزَلَ عَنْ الْمِنْبَرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ جَرِيرِ بْنِ حَازِمٍ قَالَ و سَمِعْت مُحَمَّدًا يَقُولُ وَهِمَ جَرِيرُ بْنُ حَازِمٍ فِي هَذَا الْحَدِيثِ وَالصَّحِيحُ مَا رُوِيَ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَ أُقِيمَتْ الصَّلَاةُ فَأَخَذَ رَجُلٌ بِيَدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا زَالَ يُكَلِّمُهُ حَتَّى نَعَسَ بَعْضُ الْقَوْمِ قَالَ مُحَمَّدٌ وَالْحَدِيثُ هُوَ هَذَا وَجَرِيرُ بْنُ حَازِمٍ رُبَّمَا يَهِمُ فِي الشَّيْءِ وَهُوَ صَدُوقٌ قَالَ مُحَمَّدٌ وَهِمَ جَرِيرُ بْنُ حَازِمٍ فِي حَدِيثِ ثَابِتٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا تَقُومُوا حَتَّى تَرَوْنِي قَالَ مُحَمَّدٌ وَيُرْوَى عَنْ حَمَّادِ بْنِ زَيْدٍ قَالَ كُنَّا عِنْدَ ثَابِتٍ الْبُنَانِيِّ فَحَدَّثَ حَجَّاجٌ الصَّوَّافُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا تَقُومُوا حَتَّى تَرَوْنِي فَوَهِمَ جَرِيرٌ فَظَنَّ أَنَّ ثَابِتًا حَدَّثَهُمْ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Daud At Thayalisi] telah menceritakan kepada kami [Jarir bin Hazim] dari [Tsabit] dari [Anas bin Malik] dia berkata, adalah Nabi Shallahu 'alaihi wa sallam mengemukakan hajatnya jika turun dari mimbar. Abu Isa berkata, kami tidak mengetahui hadits ini melainkan dari hadits (riwayat) Jarir bin Hazim, dia berkata, jarir bin Hazim ragu mengenai hadits ini, dan yang shahih adalah apa yang diriwayatkan dari Tsabit dari Anas dia berkata, shalat akan didirikan, tiba-tiba seorang laki-laki memegang tangan Nabi Shallahu 'alaihi wa sallam, terus saja laki-laki tersebut mengajak bicara beliau sampai sebagian kaum mengantuk. Muhammad berkata, bahwa yang dimaksud hadits diatas adalah hadits ini, sedangkan Jarir bin Hazim kemungkinan dia adalah suduk (dapat dipercaya) jika ia ragu terhadap sesuatu. Muhammad berkata, Jarir bin hazim ragu mengenai hadits (riwayat) Tsabit dari Anas dari Nabi Shallahu 'alaihi wa sallam beliau bersabda: \"Jika shalat telah ditegakkan, janganlah kalian berdiri sehingga kalian melihatku.\" Muhammad berkata, dan hadits ini juga diriwayatkan dari Hammad bin Ziyad, dia berkata, kami bersama Tsabit Al Banani, lalu Hajjaj As Shawaf menceritakan dari Yahya bin Abu Katsir dari Abdullah bin Abu Qatadah dari ayahnya dari Nabi Shallahu 'alaihi wa sallam beliau bersabda: \"Jika shalat telah didirikan maka janganlah kalian berdiri sehingga kalian melihatku.\" kemudian Jarir ragu, dia mengira bahwasannya Tsabit telah menceritakan kepada mereka dari Anas dari Nabi Shallahu 'alaihi wa sallam."},"476":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَلَقَدْ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ مَا تُقَامُ الصَّلَاةُ يُكَلِّمُهُ الرَّجُلُ يَقُومُ بَيْنَهُ وَبَيْنَ الْقِبْلَةِ فَمَا يَزَالُ يُكَلِّمُهُ فَلَقَدْ رَأَيْتُ بَعْضَنَا يَنْعَسُ مِنْ طُولِ قِيَامِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Tsabit] dari [Anas] dia berkata, ketika shalat ditegakkan, saya melihat Nabi Shallahu 'alaihi wa sallam diajak bicara dengan seorang lelaki yang berdiri di antara beliau dan Qiblat, lelaki itu terus menerus berbicara dengan beliau, lantas saya melihat sebagian dari kami yang mengantuk karena saking lamanya Nabi Shallahu 'alaihi wa sallam berdiri dengannya. Abu Isa berkata hadits ini hasan shahih."},"477":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ اسْتَخْلَفَ مَرْوَانُ أَبَا هُرَيْرَةَ عَلَى الْمَدِينَةِ وَخَرَجَ إِلَى مَكَّةَ فَصَلَّى بِنَا أَبُو هُرَيْرَةَ يَوْمَ الْجُمُعَةِ فَقَرَأَ سُورَةَ الْجُمُعَةِ وَفِي السَّجْدَةِ الثَّانِيَةِ إِذَا جَاءَكَ الْمُنَافِقُونَ قَالَ عُبَيْدُ اللَّهِ فَأَدْرَكْتُ أَبَا هُرَيْرَةَ فَقُلْتُ لَهُ تَقْرَأُ بِسُورَتَيْنِ كَانَ عَلِيٌّ يَقْرَأُ بِهِمَا بِالْكُوفَةِ قَالَ أَبُو هُرَيْرَةَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِهِمَاقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَالنُّعْمَانِ بْنِ بَشِيرٍ وَأَبِي عِنَبَةَ الْخَوْلَانِيِّ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَرُوِي عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقْرَأُ فِي صَلَاةِ الْجُمُعَةِ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَهَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ عُبَيْدُ اللَّهِ بْنُ أَبِي رَافِعٍ كَاتِبُ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hatim bin Isma'il] dari [Ja'far bin Muhammad] dari [bapaknya] dari ['Ubaidullah bin Abu Rafi'] budaknya Rasulullah Shallahu 'alaihi wa sallam dia berkata, Marwan mengangkat Abu Hurairah menjadi gubernur Madinah, dan dia keluar menuju Makkah maka Abu Hurairah shalat Jum'at bersama kami dan membaca surat Al Jumu'ah dan dalam sujud yang kedua dia membaca surat Idza ja'akal Munafiqun, 'Ubaidullah berkata, maka saya menemui Abu Hurairah lalu saya bertanya padanya, kamu membaca dua surat yang dibaca oleh Ali di Kufah?, [Abu Hurairah] menjawab, sesungguhnya saya telah mendengar Rasulullah Shallahu 'alaihi wa sallam membaca keduanya. (perawi) berkata, dan dalam bab ini (ada juga riwayat -pent) dari Ibnu Abbas, An Nu'man bin Basyir dan Abu 'Inabah Al Khqulani. Abu Isa berkata, hadits Abu Hurairah adalah hadits hasan shahih, dan telah diriwayatkan dari Nabi Shallahu 'alaihi wa sallam bahwa beliau membaca dalam shalat Jum'at dengan SABBIHISMA RABBIKAL 'A'LA dan HAL ATAAKA HADIITSUL GHAASYIYAH. 'Ubaidullah bin Abu Rafi' adalah sekretarisnya Ali bin Abu Thalib radliallahu 'anhu."},"478":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا شَرِيكٌ عَنْ مُخَوَّلِ بْنِ رَاشِدٍ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ يَوْمَ الْجُمُعَةِ فِي صَلَاةِ الْفَجْرِ الم تَنْزِيلُ السَّجْدَةَ وَهَلْ أَتَى عَلَى الْإِنْسَانِقَالَ وَفِي الْبَاب عَنْ سَعْدٍ وَابْنِ مَسْعُودٍ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عَبَّاسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ سُفْيَانُ الثَّوْرِيُّ وَشُعْبَةُ وَغَيْرُ وَاحِدٍ عَنْ مُخَوَّلٍ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah mengabarkan kepada kami [Syarik] dari [Mukhawwal bin Rasyid] dari [Muslim Al Bathin] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata, Rasulullah Shallahu 'alaihi wa sallam shalat fajar pada hari Jum'at dengan membaca \"ALIF LAM MIM TANZIILU.... dalam surat As Sajdah, dan HAL ATAA 'ALAL INSAN.\" (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Sa'd, Ibnu Mas'ud dan Abu Hurairah. Abu Isa berkata, hadits Ibnu Abbas adalah hadits hasan shahih dan telah diriwayatkan pula oleh [Sufyan Ats Tsauri] dan [Syu'bah] dan yang lainnya dari [Mukhawwal]."},"479":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يُصَلِّي بَعْدَ الْجُمُعَةِ رَكْعَتَيْنِقَالَ وَفِي الْبَاب عَنْ جَابِرٍ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَيْضًا وَالْعَمَلُ عَلَى هَذَا عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ وَبِهِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] dari [Az Zuhri] dari [Salim] dari [ayahnya] dari Nabi Shallahu 'alaihi wa sallam bahwa beliau mengerjakan shalat dua raka'at setelah shalat jum'at. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Jabir. Abu Isa berkata, hadits Ibnu Umar adalah hasan shahih, telah diriwayatkan dari [Nafi'] dari [Ibnu Umar] juga, hadits ini juga diamalkan oleh sebagian ahli ilmu, dengannya pula Syafi'i dan Ahmad berkata."},"480":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّهُ كَانَ إِذَا صَلَّى الْجُمُعَةَ انْصَرَفَ فَصَلَّى سَجْدَتَيْنِ فِي بَيْتِهِ ثُمَّ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ ذَلِكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] bahwa apabila (selesai mengerjakan) shalat Jum'at, dia beranjak untuk melaksanakan shalat dua raka'at dirumahnya, kemudian dia berkata, adalah Rasulullah Shallahu 'alaihi wa sallam melakukan hal itu. Abu Isa berkata, ini adalah hadits hasan shahih."},"481":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ مِنْكُمْ مُصَلِّيًا بَعْدَ الْجُمُعَةِ فَلْيُصَلِّ أَرْبَعًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَلِيُّ بْنُ الْمَدِينِيِّ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ قَالَ كُنَّا نَعُدُّ سُهَيْلَ بْنَ أَبِي صَالِحٍ ثَبْتًا فِي الْحَدِيثِ وَالْعَمَلُ عَلَى هَذَا عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ وَرُوِي عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ أَنَّهُ كَانَ يُصَلِّي قَبْلَ الْجُمُعَةِ أَرْبَعًا وَبَعْدَهَا أَرْبَعًا وَقَدْ رُوِيَ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ أَمَرَ أَنْ يُصَلَّى بَعْدَ الْجُمُعَةِ رَكْعَتَيْنِ ثُمَّ أَرْبَعًا وَذَهَبَ سُفْيَانُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ إِلَى قَوْلِ ابْنِ مَسْعُودٍ و قَالَ إِسْحَقُ إِنْ صَلَّى فِي الْمَسْجِدِ يَوْمَ الْجُمُعَةِ صَلَّى أَرْبَعًا وَإِنْ صَلَّى فِي بَيْتِهِ صَلَّى رَكْعَتَيْنِ وَاحْتَجَّ بِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي بَعْدَ الْجُمُعَةِ رَكْعَتَيْنِ فِي بَيْتِهِ وَحَدِيثُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ مِنْكُمْ مُصَلِّيًا بَعْدَ الْجُمُعَةِ فَلْيُصَلِّ أَرْبَعًا قَالَ أَبُو عِيسَى وَابْنُ عُمَرَ هُوَ الَّذِي رَوَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يُصَلِّي بَعْدَ الْجُمُعَةِ رَكْعَتَيْنِ فِي بَيْتِهِ وَابْنُ عُمَرَ بَعْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي الْمَسْجِدِ بَعْدَ الْجُمُعَةِ رَكْعَتَيْنِ وَصَلَّى بَعْدَ الرَّكْعَتَيْنِ أَرْبَعًا حَدَّثَنَا بِذَلِكَ ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ قَالَ رَأَيْتُ ابْنَ عُمَرَ صَلَّى بَعْدَ الْجُمُعَةِ رَكْعَتَيْنِ ثُمَّ صَلَّى بَعْدَ ذَلِكَ أَرْبَعًا حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ مَا رَأَيْتُ أَحَدًا أَنَصَّ لِلْحَدِيثِ مِنْ الزُّهْرِيِّ وَمَا رَأَيْتُ أَحَدًا الدَّنَانِيرُ وَالدَّرَاهِمُ أَهْوَنُ عَلَيْهِ مِنْهُ إِنْ كَانَتْ الدَّنَانِيرُ وَالدَّرَاهِمُ عِنْدَهُ بِمَنْزِلَةِ الْبَعْرِ قَالَ أَبُو عِيسَى سَمِعْت ابْنَ أَبِي عُمَرَ قَال سَمِعْتُ سُفْيَانَ بْنَ عُيَيْنَةَ يَقُولُ كَانَ عَمْرُو بْنُ دِينَارٍ أَسَنَّ مِنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Suhail bin Abu Shalih] dari [ayahnya] dari [Abu Hurairah] dia berkata, Rasulullah Shallahu 'alaihi wa sallam bersabda: \"Barang siapa diantara kalian yang shalat setelah shalat Jum'at hendaknya ia shalat empat raka'at.\" Abu Isa berkata, ini adalah hadits hasan shahih. Telah menceritakan kepada kami Hasan bin Ali telah menceritakan kepada kami Ali bin Madini dari Sufyan bin 'Uyainah dia berkata, kami menganggap bahwa Suhail bin Shalih adalah tsabat dalam hadits, hadits ini juga diamalkan oleh sebagian para ulama. Diriwayatkan dari Abdullah bin Mas'ud bahwa dia shalat empat raka'at sebelum dan setela shalat jum'at sebanyak empat raka'at, dan telah diriwayatkan dari Ali bin Abu Thalib radliallahu 'anhu bahwa dia memerintahkan untuk shalat dua raka'at setelah shalat jum'at, kemudian empat raka'at, sedangkan Sufyan At Tsauri, Ibnu Mubarak berpendapat sebagaiaman perkataannya Ibnu Mas'ud. Ishaq berkata, jika pada hari Jum'at dia shalat dimasjid, maka ia shalat empat raka'at, jika ia shalat dirumahnya, maka ia shalat dua raka'at, dia berhujah bahwa Nabi Shallahu 'alaihi wa sallam shalat dua raka'at dirumahnya setelah shalat jum'at, sedangkan hadits Nabi Shallahu 'alaihi wa sallam: \"Barang siapa diantara kalian yang shalat setelah shalat Jum'at hendaknya ia shalat empat raka'at.\" Abu Isa berkata, bahwa Ibnu Umar meriwayatkan dari Nabi Shallahu 'alaihi wa sallam bahwa beliau shalat dua raka'at dirumahnya setelah shalat jum'at, dan Ibnu Umar setelah Nabi Shallahu 'alaihi wa sallam selesai melaksanakan shalat dua raka'at dimasjid, beliau shalat empat raka'at. Telah menceritakan kepada kami Ibnu Abu Umar seperti itu, telah menceritakan kepada kami Sufyan bin 'Uyainah dari Ibnu Juraij dari Atha' dia berkata, saya melihat Ibnu Umar mengerjakan shalat dua raka'at setelah shalat Jum'at, setelah itu dia shalat empat raka'at. Telah menceritakan kepada kami Sa'id bin Abdurrahman Al Mahzumi, telah menceritakan kepada kami Sufyan bin 'Uyainah dari Amru bin Dinar dia berkata, saya tidak pernah melihat seseorang yang sanggup menashkan hadits selain Az Zuhri, dan saya tidak pernah melihat seseorang yang menganggap remeh (hina) dianr dan dirham selain dia, bahwa dinar dan dinar menurutnya tak ubahnya seperti keledai. Abu Isa berkata, saya pernah mendengar Ibnu Abu Umar berkata, saya mendengar Sufyan bin 'Uyainah berkata, adalah Amru bin Dinar lebih tua dari Az Zuhri."},"482":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ وَسَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ مِنْ الصَّلَاةِ رَكْعَةً فَقَدْ أَدْرَكَ الصَّلَاةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ قَالُوا مَنْ أَدْرَكَ رَكْعَةً مِنْ الْجُمُعَةِ صَلَّى إِلَيْهَا أُخْرَى وَمَنْ أَدْرَكَهُمْ جُلُوسًا صَلَّى أَرْبَعًا وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ","id":"Telah menceritakan kepada kami [Nashr bin Ali] dan [Sa'id bin Abdurrahman] serta yang lainnya, mereka berkata, telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi Shallahu 'alaihi wa sallam bahwa beliau bersabda: \"Barangsiapa yang mendapatkan satu raka'at dalam shalat (ruku'), maka dia mendapatkan (raka'at) shalat.\" Abu Isa berkata, ini adalah hadits hasan shahih, dan diamalkan oleh kebanyakan ahli ilmu dari kalangan sahabat Nabi Shallahu 'alaihi wa sallam dan yang lainnya, mereka berkata, barangsiapa yang mendapatkan ruku' dalam shalat Jum'at maka dia harus menambah raka'at lain lagi, dan barangsiapa yang mendapatkan mereka sedang duduk, maka dia harus melaksanakan shalat empat raka'at, ini adalah pendapat Sufyan Ats Tsauri, Ibnu Al Mubarak, As Syafi'i, Ahmad dan Ishaq."},"483":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ وَعَبْدُ اللَّهِ بْنُ جَعْفَرٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَمَا كُنَّا نَتَغَذَّى فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا نَقِيلُ إِلَّا بَعْدَ الْجُمُعَةِقَالَ وَفِي الْبَاب عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَ أَبُو عِيسَى حَدِيثُ سَهْلِ بْنِ سَعْدٍ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah menceritakan kepada kami ['Abdul Aziz bin Abu Hazim] dan [Abdullah bin Ja'far] dari [Abu Hazim] dari [Sahl bin Sa'ad radliallahu 'anhu] dia berkata, bahwa kami tidak makan siang dan tidak Qailulah (tidur sebelum Dzuhur) pada masa Rasulullah Shallahu 'alaihi wa sallam kecuali setelah shalat Jum'at. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Anas bin Malik radliallahu 'anhu. Abu Isa berkata, hadits Sahl Bin Sa'ad adalah hadits hasan shahih."},"484":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ وَأَبُو خَالِدٍ الْأَحْمَرُ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا نَعَسَ أَحَدُكُمْ يَوْمَ الْجُمُعَةِ فَلْيَتَحَوَّلْ مِنْ مَجْلِسِهِ ذَلِكَقَالَ أَبُو عِ��سَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Sa'id Al Asyajj] telah menceritakan kepada kami ['Abdah bin Sulaiman] dan [Abu Khalid Al Ahmar] dari [Muhammad bin Ishaq] dari [Nafi'] dari [Ibnu Umar] dari Nabi Shallahu 'alaihi wa sallam beliau bersabda: \"Jika salah seorang kalian mengantuk pada hari Jum'at (pada saat khutbah Jum'at), hendaknya ia pindah dari tempat duduknya.\" Abu Isa berkata, ini adalah hadits hasan shahih."},"485":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْحَجَّاجِ عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدَ اللَّهِ بْنَ رَوَاحَةَ فِي سَرِيَّةٍ فَوَافَقَ ذَلِكَ يَوْمَ الْجُمُعَةِ فَغَدَا أَصْحَابُهُ فَقَالَ أَتَخَلَّفُ فَأُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَلْحَقُهُمْ فَلَمَّا صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَآهُ فَقَالَ مَا مَنَعَكَ أَنْ تَغْدُوَ مَعَ أَصْحَابِكَ فَقَالَ أَرَدْتُ أَنْ أُصَلِّيَ مَعَكَ ثُمَّ أَلْحَقَهُمْ قَالَ لَوْ أَنْفَقْتَ مَا فِي الْأَرْضِ جَمِيعًا مَا أَدْرَكْتَ فَضْلَ غَدْوَتِهِمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ قَالَ عَلِيُّ بْنُ الْمَدِينِيِّ قَالَ يَحْيَى بْنُ سَعِيدٍ وَقَالَ شُعْبَةُ لَمْ يَسْمَعْ الْحَكَمُ مِنْ مِقْسَمٍ إِلَّا خَمْسَةَ أَحَادِيثَ وَعَدَّهَا شُعْبَةُ وَلَيْسَ هَذَا الْحَدِيثُ فِيمَا عَدَّ شُعْبَةُ فَكَأَنَّ هَذَا الْحَدِيثَ لَمْ يَسْمَعْهُ الْحَكَمُ مِنْ مِقْسَمٍ وَقَدْ اخْتَلَفَ أَهْلُ الْعِلْمِ فِي السَّفَرِ يَوْمَ الْجُمُعَةِ فَلَمْ يَرَ بَعْضُهُمْ بَأْسًا بِأَنْ يَخْرُجَ يَوْمَ الْجُمُعَةِ فِي السَّفَرِ مَا لَمْ تَحْضُرْ الصَّلَاةُ و قَالَ بَعْضُهُمْ إِذَا أَصْبَحَ فَلَا يَخْرُجْ حَتَّى يُصَلِّيَ الْجُمُعَةَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hajjaj] dari [Al Hakam] dari [Miqsam] dari [Ibnu Abbas] dia berkata, Nabi Shallahu 'alaihi wa sallam mengutus Abdullah bin Rawahah dalam sebuah ekspedisi, pada saat itu bertepatan dengan hari Juma'at, kemudian sahabat-sahabatnya telah berangkat dipagi hari, lalu dia berkata, saya akan menunda keberangkatan sehingga saya bisa shalat (jum'at) bersama Rasulullah Shallahu 'alaihi wa sallam kemudian saya akan menyusul mereka, tatkala dia shalat bersama Rasulullah Shallahu 'alaihi wa sallam, beliau melihatnya, maka beliau bersabda: \"Apa yang mencegahmu untuk tidak berangkat bersama dengan para sahabatmu?\" dia menjawab, saya ingin shalat bersamamu, lalu saya akan menyusul mereka (setelah shalat). Lantas beliau bersabda: \"Sekiranya kamu menginfakkan semua yang ada dibumi, kamu tidak akan dapat menyamai keutamaan mereka berangkat dipagi hari.\" Abu Isa berkata, ini adalah hadits gharib, kami tidak mengetahuinya selain jalur ini. Ali bin Madini berkata, berkata Yahya bin Sa'id. Dan Syu'bah juga berkata, Al Hakam belum pernah mendengar dari Miqsam kecuali hanya lima haidts, kemudian Syu'bah menghitungnya (hadits yang dihafal oleh Al Hakam dari Miqsam), sedangkan hadits ini tidak termasuk yang dihitung oleh Syu'bah, maka sepertinya Al Hakam tidak mendengar hadits ini dari Miqsam. Para ahli ilmu juga berbeda pendapat mengenai safar pada hari Jum'at, bahkan sebagian mereka tidak berpendapat akan bolehnya keluar (untuk safar) pada hari Jum'at dan tidak ikut menghadiri shalat Jum'at. Sebagian yang lain berkata, jika dia berada di pagi harinya, hendaknya dia tidak keluar (untuk safar) sampai dia melaksanakan shalat Jum'at."},"486":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ الْكُوفِيُّ حَدَّثَنَا أَبُو يَحْيَى إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ التَّيْمِيُّ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَقٌّ عَلَى الْمُسْلِمِينَ أَنْ يَغْتَسِلُوا يَوْمَ الْجُمُعَةِ وَلْيَمَسَّ أَحَدُهُمْ مِنْ طِيبِ أَهْلِهِ فَإِنْ لَمْ يَجِدْ فَالْمَاءُ لَهُ طِيبٌقَالَ وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ وَشَيْخٍ مِنْ الْأَنْصَارِ حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ قَالَ أَبُو عِيسَى حَدِيثُ الْبَرَاءِ حَدِيثٌ حَسَنٌ وَرِوَايَةُ هُشَيْمٍ أَحْسَنُ مِنْ رِوَايَةِ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ وَإِسْمَعِيلُ بْنُ إِبْرَاهِيمَ التَّيْمِيُّ يُضَعَّفُ فِي الْحَدِيثِ","id":"Telah menceritakan kepada kami [Ali bin Al Hasan Al Kufi] telah menceritakan kepada kami [Abu Yahya Isma'il bin Ibrahim At Taimi] dari [Yazid bin Abu Ziyad] dari [Abdurrahman bin Abu Laila] dari [Barra' bin 'Azib] dia berkata, Rasulullah Shallahu 'alaihi wa sallam bersabda: \"Benar bagi seorang Muslim untuk mandi di hari Jum'at dan memakai wewangian keluarganya, jika ia tidak mendapatinya maka cukuplah dengan menggunakan air.\" (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Abu Sa'id dan seorang syaikh dari Anshar. Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Husyaim] dari [Yazid bin Abu Ziyad] dengan isnad seperti ini. Abu Isa berkata, hadits Barra' adalah hadits hasan, sedangkan riwayatnya Husyaim lebih baik daripada riwayatnya Isma'il bin Ibrahim At Taimi, karena Isma'il bin Ibrahim At Taimi didla'ifkan dalam (meriwayatkan) hadits."},"487":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى الْفَزَارِيُّ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَمِنْ السُّنَّةِ أَنْ تَخْرُجَ إِلَى الْعِيدِ مَاشِيًا وَأَنْ تَأْكُلَ شَيْئًا قَبْلَ أَنْ تَخْرُجَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَالْعَمَلُ عَلَى هَذَا الْحَدِيثِ عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ يَسْتَحِبُّونَ أَنْ يَخْرُجَ الرَّجُلُ إِلَى الْعِيدِ مَاشِيًا وَأَنْ يَأْكُلَ شَيْئًا قَبْلَ أَنْ يَخْرُجَ لِصَلَاةِ الْفِطْرِ قَالَ أَبُو عِيسَى وَيُسْتَحَبُّ أَنْ لَا يَرْكَبَ إِلَّا مِنْ عُذْرٍ","id":"Telah menceritakan kepada kami [Isma'il bin Musa Al Fazari] telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dari [Al Harits] dari [Ali bin Abu Thalib] dia berkata, menurut sunnah, hendaknya kamu keluar untuk shalat Ied dengan berjalan kaki, dan memakan sesuatu sebelum keluar rumah. Abu Isa berkata, hadits ini hasan, dan diamalkan oleh kebanyakan para ahli ilmu bahwa mereka menyukai seseorang keluar menuju shalat Ied dengan berjalan kaki, dan makan sesuatu sebelum keluar untuk shalat Iedul Fitri. Abu Isa berkata, dan disukai juga hendaknya tidak berkendaradliallahu 'anhan kecuali karena udzur."},"488":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ هُوَ ابْنُ عُمَرَ بْنِ حَفْصِ بْنِ عَاصِمِ بْنِ عُمَرَ بْنِ الْخَطَّابِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَعُمَرُ يُصَلُّونَ فِي الْعِيدَيْنِ قَبْلَ الْخُطْبَةِ ثُمَّ يَخْطُبُونَقَالَ وَفِي الْبَاب عَنْ جَابِرٍ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ أَنَّ صَلَاةَ الْعِيدَيْنِ قَبْلَ الْخُطْبَةِ وَيُقَالُ إِنَّ أَوَّلَ مَنْ خَطَبَ قَبْلَ الصَّلَاةِ مَرْوَانُ بْنُ الْحَكَمِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abu Usamah] dari ['Ubaidullah yaitu Ibnu Umar bin Hafs bin 'Ashim bin Umar bin Al Khaththab] dari [Nafi'] dari [Ibnu Umar] dia berkata, Rasulullah Shallahu 'alaihi wa sallam, Abu Bakar dan Umar, mereka melaksanakan shalat Iedain (Iedul fitri dan Iedul Adlha) sebelum berkhutbah, kemudian mereka berkhutbah. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Jabir dan Ibnu Abbas. Abu Isa berkata, hadits Ibnu Umar adalah hadits hasan shahih, hadits ini diamalkan oleh para ahli ilmu dari kalangan sahabat Nabi Shallahu 'alaihi wa sallam dan yang lainnya bahwa shalat Iedain (Iedul Fitri dan Iedul Adlha) dilaksanakan sebelum khutbah, dikatakan bahwa orang yang pertama kali melakukan khutbah sebelum shalat adalah Marwan bin Al Hakam."},"489":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعِيدَيْنِ غَيْرَ مَرَّةٍ وَلَا مَرَّتَيْنِ بِغَيْرِ أَذَانٍ وَلَا إِقَامَةٍقَالَ وَفِي الْبَاب عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى وَحَدِيثُ جَابِرِ بْنِ سَمُرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ أَنَّهُ لَا يُؤَذَّنُ لِصَلَاةِ الْعِيدَيْنِ وَلَا لِشَيْءٍ مِنْ النَّوَافِلِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak bin Harb] dari [Jabir bin Samrah] dia berkata, saya shalat dua hari raya bersama Nabi Shallahu 'alaihi wa sallam tidak cuma sekali atau dua kali tanpa diawali dengan adzan dan juga iqamat. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Jabir bin Abdullah dan Ibnu Abbas. Abu Isa berkata, hadits Jabir bin Samrah adalah hadits hasan shahih, para ahli ilmu dari kalanagn sahabat Nabi Shallahu 'alaihi wa sallam dan yang lainnya juga mengamalkan hadits ini bahwasannya tidak ada adzan dalam shalat dua hari raya dan tidak pula untuk shalat-shalat sunnah."},"490":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْعِيدَيْنِ وَفِي الْجُمُعَةِ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَهَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ وَرُبَّمَا اجْتَمَعَا فِي يَوْمٍ وَاحِدٍ فَيَقْرَأُ بِهِمَاقَالَ وَفِي الْبَاب عَنْ أَبِي وَاقِدٍ وَسَمُرَةَ بْنِ جُنْدَبٍ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى حَدِيثُ النُّعْمَانِ بْنِ بَشِيرٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهَكَذَا رَوَى سُفْيَانُ الثَّوْرِيُّ وَمِسْعَرٌ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ نَحْوَ حَدِيثِ أَبِي عَوَانَةَ وَأَمَّا سُفْيَانُ بْنُ عُيَيْنَةَ فَيُخْتَلَفُ عَلَيْهِ فِي الرِّوَايَةِ يُرْوَى عَنْهُ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ أَبِيهِ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ وَلَا نَعْرِفُ لِحَبِيبِ بْنِ سَالِمٍ رِوَايَةً عَنْ أَبِيهِ وَحَبِيبُ بْنُ سَالِمٍ هُوَ مَوْلَى النُّعْمَانِ بْنِ بَشِيرٍ وَرَوَى عَنْ النُّعْمَانِ بْنِ بَشِيرٍ أَحَادِيثَ وَقَدْ رُوِيَ عَنْ ابْنِ عُيَيْنَةَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ نَحْوُ رِوَايَةِ هَؤُلَاءِ وَرُوِي عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقْرَأُ فِي صَلَاةِ الْعِيدَيْنِ بِقَافٍ وَاقْتَرَبَتْ السَّاعَةُ وَبِهِ يَقُولُ الشَّافِعِيُّ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari [Ibrahim bin Muhammad bin Al Muntasyir] dari [ayahnya] dari [Habib bin Salim] dari [An Nu'man bin Basyir] dia berkata, Nabi Shallahu 'alaihi wa sallam membaca SABBIHISMA RABBIKA dan HAL ATAAKA HADIITSUL GHAATSIAH pada waktu shalat iedain (dua hari raya) dan shalat Jum'at, jika keduanya terjadi disatu hari, maka belaiu membaca keduanya. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Abu Wqaqid, Samrah bin Jundab dan Ibnu Abbas. Abu Isa berkata, hadits Nu'man bin Basyir adalah hadits hasan shahih. demikian pula [Sufyan Ats Tsauri] dan [Mis'ar] meriwayatkan dari [Ibrahim bin Muhammad bin Al Muntasyir] seperti hadits yang diriwayatkan Abu 'Awanah. Sedangkan riwayat Sufyan bin 'Uyainah mengenai hal ini masih diperselisihkan, yaitu diriwayatkan dari Ibrahim bin Muhammad bin Al Muntasyir dari ayahnya dari Habib bin Salim dari ayahnya dari Nu'man bin Basyir, akan tetapi kami tidak mengetahui Habib bin Salim memiliki riwayat dari ayahnya. Habib bin Salim adalah budak Nu'man bin Basyir yang banyak meriwayatkan dari Nu'man bin Basyir. Dan diriwayatkan dari [Ibnu Uyainah] dari [Ibrahim bin Muhammad bin Al Muntasyir] seperti riwayat mereka. Diriwayatkan pula dari Nabi shalallahu 'alaihi wa salam bahwa dalam shalat iedain (dua hari raya) beliau membaca surat QAF dan IQTARABATIS SAA'AH. Syafi'i juga berpendapat seperti ini."},"491":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنُ بْنُ عِيسَى حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ الْمَازِنِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَأَنَّ عُمَرَ بْنَ الْخَطَّابِ سَأَلَ أَبَا وَاقِدٍ اللَّيْثِيَّ مَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِهِ فِي الْفِطْرِ وَالْأَضْحَى قَالَ كَانَ يَقْرَأُ بِق وَالْقُرْآنِ الْمَجِيدِ وَاقْتَرَبَتْ السَّاعَةُ وَانْشَقَّ الْقَمَرُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا هَنَّادٌ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ قَالَ أَبُو عِيسَى وَأَبُو وَاقِدٍ اللَّيْثِيُّ اسْمُهُ الْحَارِثُ بْنُ عَوْفٍ","id":"Telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] telah menceritakan kepada kami [Ma'an bin Isa] telah menceritakan kepada kami [Malik bin Anas] dari [Dlamrah bin Sa'id Al Mazini] dari ['Ubaidillah bin Abdullah bin 'Utbah] bahwa Umar bin Al Khaththab bertanya kepada [Abu Waqid Al Laitsi], apakah Rasulullah Shallahu 'alaihi wa sallam membaca surat waktu (shalat) idul fitri dan idul adlha? Dia menjawab, beliau membaca QAAF WAL QUR'ANIL MAJIID dan IQTARABITIS SAA'AH WAN SYAQQAL QAMAR. Abu Isa berkata, ini adalah hadits hasan shahih, telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Dlamrah bin Sa'id] dengan isnad yang seperti ini, Abu Isa berkata, Abu Waqid Al Laitsi namanya adalah Al Harits bin 'Auf."},"492":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ عَمْرٍو أَبُو عَمْرٍو الْحَذَّاءُ الْمَدِينِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نَافِعٍ الصَّائِغُ عَنْ كَثِيرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَبَّرَ فِي الْعِيدَيْنِ فِي الْأُولَى سَبْعًا قَبْلَ الْقِرَاءَةِ وَفِي الْآخِرَةِ خَمْسًا قَبْلَ الْقِرَاءَةِقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَابْنِ عُمَرَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى حَدِيثُ جَدِّ كَثِيرٍ حَدِيثٌ حَسَنٌ وَهُوَ أَحْسَنُ شَيْءٍ رُوِيَ فِي هَذَا الْبَابِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْمُهُ عَمْرُو بْنُ عَوْفٍ الْمُزَنِيُّ وَالْعَمَلُ عَلَى هَذَا عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ وَهَكَذَا رُوِيَ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ صَلَّى بِالْمَدِينَةِ نَحْوَ هَذِهِ الصَّلَاةِ وَهُوَ قَوْلُ أَهْلِ الْمَدِينَةِ وَبِهِ يَقُولُ مَالِكُ بْنُ أَنَسٍ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ وَرُوِي عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ أَنَّهُ قَالَ فِي التَّكْبِيرِ فِي الْعِيدَيْنِ تِسْعَ تَكْبِيرَاتٍ فِي الرَّكْعَةِ الْأُولَى خَمْسًا قَبْلَ الْقِرَاءَةِ وَفِي الرَّكْعَةِ الثَّانِيَةِ يَبْدَأُ بِالْقِرَاءَةِ ثُمَّ يُكَبِّرُ أَرْبَعًا مَعَ تَكْبِيرَةِ الرُّكُوعِ وَقَدْ رُوِيَ عَنْ غَيْرِ وَاحِدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوُ هَذَا وَهُوَ قَوْلُ أَهْلِ الْكُوفَةِ وَبِهِ يَقُولُ سُفْيَانُ الثَّوْرِيُّ","id":"Telah menceritakan kepada kami [Muslim bin Amru Abu Amru Al Hadzdza' Al Madini] telah menceritakan kepada kami [Abdullah bin Nafi' Ash Sha'igh] dari [Katsir bin Abdullah] dari [ayahnya] dari [kakeknya] bahwa Nabi Shallahu 'alaihi wa sallam bertakbir dalam dua shalat Ied, pada raka'at pertama tujuh kali sebelum membaca ayat dan pada raka'at kedua lima kali sebelum membaca ayat. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari A'isyah, Ibnu Umar dan Abdullah bin Amru. Abu Isa berkata, hadits kakeknya Katsir adalah hadits hasan dan ini adalah hadits yang paling baik yang diriwayatkan dalam bab ini dari Nabi Shallahu 'alaihi wa sallam, adapun nama lengkapnya adalah Amru bin 'Auf Al Muzani, hadits ini diamalkan oleh sebagian ahli ilmu dari kalangan sahabat Nabi Shallahu 'alaihi wa sallam dan yang lainnya, demikianlah yang diriwayatkan dari Abu Hurairah bahwa dia shalat di Madinah seperti shalat ini, ini adalah pendapat penduduk Madinah, dan juga pandapat Malik bin Anas, Syafi'i, Ahmad dan Ishaq, telah diriwayatkan dari 'Abdulloh bin Mas'ud bahwa dia berkata tentang takbir dalam dua shalat Ied, sembilan kali takbir, pada raka'at pertama lima kali sebelum membaca ayat dan pada raka'at kedua dimulai dengan membaca ayat lalu takbir empat kali bersama dengan ruku'. Telah diriwayatkan dari banyak sahabat Nabi Shallahu 'alaihi wa sallam hadits yang semakna dengan ini dan ini adalah pendapat penduduk Kufah dan juga Sufyan Ats Tsauri."},"493":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ قَال سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ يَوْمَ الْفِطْرِ فَصَلَّى رَكْعَتَيْنِ ثُمَّ لَمْ يُصَلِّ قَبْلَهَا وَلَا بَعْدَهَاقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَأَبِي سَعِيدٍ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عَبَّاسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَيْهِ عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ وَبِهِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ وَقَدْ رَأَى طَائِفَ��ٌ مِنْ أَهْلِ الْعِلْمِ الصَّلَاةَ بَعْدَ صَلَاةِ الْعِيدَيْنِ وَقَبْلَهَا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ وَالْقَوْلُ الْأَوَّلُ أَصَحُّ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Daud At Thayalisi] dia berkata, telah memberitakan kepada kami [Syu'bah] dari ['Adi bin Tsabit] saya telah mendengar [Sa'id bin Jubair] menceritakan dari [Ibnu Abbas] bahwasannya Nabi shallallahu 'alaihi wasallam keluar (menuju tempat shalat) pada hari raya iedul fitri, kemudian beliau shalat dua raka'at, beliau tidak mengerjakan shalat baik sebelum atau sesuadahnya. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Abdullah bin Amru dan Abu sa'id. Abu Isa berkata, hadits Ibnu Abbas adalah hadits hasan shahih dan diamalkan oleh sebagian para ulama dari kalangan sahabat Nabi Shallahu 'alaihi wa sallam dan yang lainnya, dengannya pula Syafi'i, Ahmad dan Ishaq berkata. Sebagian kelompok para ulama dari kalangan sahabat Nabi Shallahu 'alaihi wa sallam dan yang lainnya yang berpendapat (diperbolehkan) shalat setelah dan sebelum shalat ied, sedangkan pendapat yang pertamalah yang paling benar."},"494":{"ar":"حَدَّثَنَا أَبُو عَمَّارٍ الْحُسَيْنُ بْنُ حُرَيْثٍ حَدَّثَنَا وَكِيعٌ عَنْ أَبَانَ بْنِ عَبْدِ اللَّهِ الْبَجَلِيِّ عَنْ أَبِي بَكْرِ بْنِ حَفْصٍ وَهُوَ ابْنُ عُمَرَ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ ابْنِ عُمَرَأَنَّهُ خَرَجَ فِي يَوْمِ عِيدٍ فَلَمْ يُصَلِّ قَبْلَهَا وَلَا بَعْدَهَا وَذَكَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَهُقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu 'Amar Al Husain bin Huraits] telah menceritakan kepada kami [Waki'] dari [Aban bin Abdullah Al Bajali] dari [Abu Bakar bin Hafsh] dia adalah Ibnu Umar bin Sa'ad bin Abu Waqash, dari [Ibnu Umar] bahwa dia keluar (menuju tempat shalat) pada hari raya id, dengan tidak mengerjakan shalat sebelumnya maupun setelahnya. Dia menyebutkan bahwa Nabi Shallahu 'alaihi wa sallam mengerjakan seperti itu. Abu Isa berkata, ini adalah hadits hasab shahih."},"495":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا مَنْصُورٌ وَهُوَ ابْنُ زَاذَانَ عَنْ ابْنِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُخْرِجُ الْأَبْكَارَ وَالْعَوَاتِقَ وَذَوَاتِ الْخُدُورِ وَالْحُيَّضَ فِي الْعِيدَيْنِ فَأَمَّا الْحُيَّضُ فَيَعْتَزِلْنَ الْمُصَلَّى وَيَشْهَدْنَ دَعْوَةَ الْمُسْلِمِينَ قَالَتْ إِحْدَاهُنَّ يَا رَسُولَ اللَّهِ إِنْ لَمْ يَكُنْ لَهَا جِلْبَابٌ قَالَ فَلْتُعِرْهَا أُخْتُهَا مِنْ جَلَابِيبِهَاحَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ بِنَحْوِهِ قَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَجَابِرٍ قَالَ أَبُو عِيسَى وَحَدِيثُ أُمِّ عَطِيَّةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ ذَهَبَ بَعْضُ أَهْلِ الْعِلْمِ إِلَى هَذَا الْحَدِيثِ وَرَخَّصَ لِلنِّسَاءِ فِي الْخُرُوجِ إِلَى الْعِيدَيْنِ وَكَرِهَهُ بَعْضُهُمْ وَرُوِي عَنْ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ أَنَّهُ قَالَ أَكْرَهُ الْيَوْمَ الْخُرُوجَ لِلنِّسَاءِ فِي الْعِيدَيْنِ فَإِنْ أَبَتِ الْمَرْأَةُ إِلَّا أَنْ تَخْرُجَ فَلْيَأْذَنْ لَهَا زَوْجُهَا أَنْ تَخْرُجَ فِي أَطْمَارِهَا الْخُلْقَانِ وَلَا تَتَزَيَّنْ فَإِنْ أَبَتْ أَنْ تَخْرُجَ كَذَلِكَ فَلِلزَّوْجِ أَنْ يَمْنَعَهَا عَنْ الْخُرُوجِ وَيُرْوَى عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ لَوْ رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَحْدَثَ النِّسَاءُ لَمَنَعَهُنَّ الْمَسْجِدَ كَمَا مُنِعَتْ نِسَاءُ بَنِي إِسْرَائِيلَ وَيُرْوَى عَنْ سُفْيَانَ الثَّوْرِيِّ أَنَّهُ كَرِهَ الْيَوْمَ الْخُرُوجَ لِلنِّسَاءِ إِلَى الْعِيدِ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Manshur] dia adalah anak laki-lakinya Zadan, dari [Ibnu Sirin] dari [Ummu 'Athiyah] bahwasannya Rasulullah Shallahu 'alaihi wa sallam memerintahkan para perawan, para budak, para wanita yang mengurung diri, para wanita haidl untuk keluar (menuju tempat shalat) pada saat dua hari raya, adapuan wanita haidl, hendaknya mereka menjauh dari tempat shalat dan menyaksikan dakwahnya kaum Muslimin. Salah seorang dari kami berkata, wahai Rasulullah bagaimanakah jika mereka tidak memiliki jilbab? Beliau bersabda: \"Hendaknya saudara perempuannya mau meminjamkan jilbab untuknya.\" telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Husyaim] dari [Hisyam bin Hasan] dari [Hafshah binti Sirin] dari [Ummu 'Athiyah] dengan riwayat seperti itu. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Ibnu Abbas dan Jabir. Abu Isa berkata, hadits Ummu 'Athiyah adalah hadits hasan shahih, dan sebagian ahli ilmu mengambil pendapat dari hadits ini dan rukhshah (keringanan) bagi para wanita haidl untuk keluar (menuju tempat shalat) pada saat hari raya (idul fitri dan idul adla), dan sebagian yang lain memakruhkannya. Dan diriwayatkan dari Abdullah bin Mubarak bahwasannya dia berkata, pada hari ini saya membenci para wanita yang ikut keluar (menuju tempat shalat) pada saat dua hari raya, jika seorang wanita enggan dan masih tetap ingin keluar, hendaknya suami mengizinkannya untuk keluar (menuju tempat shalat) dengan mengenakan pakaian biasa (pakaian yang sudah lama) dan jangan sampai mereka berhias diri, jika mereka enggan dan masih tetap untuk keluar (menuju tempat shalat), hendaknya sang suami melarang untuk keluar (menuju tempat shalat). Di riwayatkan dari 'Aisyah radliallahu 'anha dia berkata, sekiranya Rasulullah Shallahu 'alaihi wa sallam melihat apa yang telah terjadi pada wanita-wanita sekarang, niscaya beliau akan melarang mereka menuju masjid sebagaimana dilarangnya para wanita bani Isra'il. Dan diriwayatkan dari Sufyan At Tsauri bahwa hari ini dia membenci para wanita untuk keluar (menuju tempat shalat) dihari raya id."},"496":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ وَاصِلِ بْنِ عَبْدِ الْأَعْلَى الْكُوفِيُّ وَأَبُو زُرْعَةَ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ عَنْ فُلَيْحِ بْنِ سُلَيْمَانَ عَنْ سَعِيدِ بْنِ الْحَارِثِ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَرَجَ يَوْمَ الْعِيدِ فِي طَرِيقٍ رَجَعَ فِي غَيْرِهِقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ وَأَبِي رَافِعٍ قَالَ أَبُو عِيسَى وَحَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ غَرِيبٌ وَرَوَى أَبُو تُمَيْلَةَ وَيُونُسُ بْنُ مُحَمَّدٍ هَذَا الْحَدِيثَ عَنْ فُلَيْحِ بْنِ سُلَيْمَانَ عَنْ سَعِيدِ بْنِ الْحَارِثِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ وَقَدْ اسْتَحَبَّ بَعْضُ أَهْلِ الْعِلْمِ لِلْإِمَامِ إِذَا خَرَجَ فِي طَرِيقٍ أَنْ يَرْجِعَ فِي غَيْرِهِ اتِّبَاعًا لِهَذَا الْحَدِيثِ وَهُوَ قَوْلُ الشَّافِعِيِّ وَحَدِيثُ جَابِرٍ كَأَنَّهُ أَصَحُّ","id":"Telah menceritakan kepada kami ['Abdul A'la bin Washil bin 'Abdil A'la Al Kufi] dan [Abu Zur'ah] keduanya berkata, telah menceritakan kepada kami [Muhammad bin Ash Shalt] dari [Fulaih bin Sulaiman] dari [Sa'id bin Al Harits] dari [Abu Hurairah] dia berkata, adalah Nabi Shallahu 'alaihi wa sallam bila keluar (menuju tempat shalat) pada hari raya mengambil satu jalan, dan bila pulang beliau mengambil jalan yang lain. Dalam bab ini (ada juga riwayat -pent) dari Abdullah bin Umar dan Abu Rafi'. Abu Isa berkata, hadits Abu Hurairah adalah hadits hasan gharib. [Abu Tumailah] dan [Yunus bin Muhammad] telah meriwayatkan hadits ini dari [Fulaih bin Sulaiman] dari [Sa'id bin Al Harits] dari [Jabir bin Abdullah] dia berkata, sebagian ahli ilmu menganjurkan (menekankan) bagi seorang imam, jika dia keluar (menuju tempat shalat) dengan satu jalan hendaknya ia pulang dengan mengambil jalan yang lain, mengikuti hadits ini, ia merupakan perkataan Syafi'i, sepertinya hadits Jabir adalah hadits yang paling shahih."},"497":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ الصَّبَّاحِ الْبَزَّارُ الْبَغْدَادِيُّ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ عَنْ ثَوَابِ بْنِ عُتْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَخْرُجُ يَوْمَ الْفِطْرِ حَتَّى يَطْعَمَ وَلَا يَطْعَمُ يَوْمَ الْأَضْحَى حَتَّى يُصَلِّيَقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَأَنَسٍ قَالَ أَبُو عِيسَى حَدِيثُ بُرَيْدَةَ بْنِ حُصَيْبٍ الْأَسْلَمِيِّ حَدِيثٌ غَرِيبٌ و قَالَ مُحَمَّدٌ لَا أَعْرِفُ لِثَوَابِ بْنِ عُتْبَةَ غَيْرَ هَذَا الْحَدِيثِ وَقَدْ اسْتَحَبَّ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ أَنْ لَا يَخْرُجَ يَوْمَ الْفِطْرِ حَتَّى يَطْعَمَ شَيْئًا وَيُسْتَحَبُّ لَهُ أَنْ يُفْطِرَ عَلَى تَمْرٍ وَلَا يَطْعَمَ يَوْمَ الْأَضْحَى حَتَّى يَرْجِعَ","id":"Telah menceritakan kepada kami [Al Hasan bin Shabah Al Bazzar Al Baghdadi] telah menceritakan kepada kami ['Abdush Shamad bin 'Abd Al Warits] dari [Tsawab bin 'Utbah] dari [Abdullah bin Buraidah] dari [ayahnya] dia berkata, bahwa Nabi Shallahu 'alaihi wa sallam tidak keluar (ke tempat shalat) pada hari raya idul fitri sampai beliau makan terlebih dahulu, dan baliau tidak makan terlabih dahulu pada hari raya idul adlha sampai beliau shalat terlebih dahulu. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Ali dan Anas. Abu Isa berkata, hadits Buraidah bin Hushaib Al Aslami adalah hadits gharib. Muhammad berkata, dan saya tidak mengetahui (riwayatnya) Tsawab bin 'Utbah selain hadits ini. Dan dikalangan ahli ilmu menganjurkan supaya tidak keluar (menuju tempat shalat) sehingga makan sesuatu pada hari raya idul fitri, dan mereka juga menganjurkan untuk memakan kurma, dan tidak makan terlebih dahulu pada hari raya idul adla sampai dia kembali (dari tempat shalat)."},"498":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا هُشَيْمٌ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ حَفْصِ بْنِ عُبَيْدِ اللَّهِ بْنِ أَنَسٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُفْطِرُ عَلَى تَمَرَاتٍ يَوْمَ الْفِطْرِ قَبْلَ أَنْ يَخْرُجَ إِلَى الْمُصَلَّىقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Husyaim] dari [Muhammad bin Ishaq] dari [Hafsh bin 'Ubaidillah bin Anas] dari [Anas bin Malik] bahwa Nabi Shallahu 'alaihi wa sallam makan beberapa buah kurma dihari raya idul fitri sebelum keluar menuju tempat shalat. Abu Isa berkata, ini adalah hadits hasan gharib shahih."},"499":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَبْدِ الْحَكَمِ الْوَرَّاقُ الْبَغْدَادِيُّ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَسَافَرْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ وَعُثْمَانَ فَكَانُوا يُصَلُّونَ الظُّهْرَ وَالْعَصْرَ رَكْعَتَيْنِ رَكْعَتَيْنِ لَا يُصَلُّونَ قَبْلَهَا وَلَا بَعْدَهَاو قَالَ عَبْدُ اللَّهِ لَوْ كُنْتُ مُصَلِّيًا قَبْلَهَا أَوْ بَعْدَهَا لَأَتْمَمْتُهَا قَالَ وَفِي الْبَاب عَنْ عُمَرَ وَعَلِيٍّ وَابْنِ عَبَّاسٍ وَأَنَسٍ وَعِمْرَانَ بْنِ حُصَيْنٍ وَعَائِشَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ يَحْيَى بْنِ سُلَيْمٍ مِثْلَ هَذَا قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ رَجُلٍ مِنْ آلِ سُرَاقَةَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ عَطِيَّةَ الْعَوْفِيِّ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَطَوَّعُ فِي السَّفَرِ قَبْلَ الصَّلَاةِ وَبَعْدَهَا وَقَدْ صَحَّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقْصُرُ فِي السَّفَرِ وَأَبُو بَكْرٍ وَعُمَرُ وَعُثْمَانُ صَدْرًا مِنْ خِلَافَتِهِ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ وَقَدْ رُوِيَ عَنْ عَائِشَةَ أَنَّهَا كَانَتْ تُتِمُّ الصَّلَاةَ فِي السَّفَرِ وَالْعَمَلُ عَلَى مَا رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابِهِ وَهُوَ قَوْلُ الشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ إِلَّا أَنَّ الشَّافِعِيَّ يَقُولُ التَّقْصِيرُ رُخْصَةٌ لَهُ فِي السَّفَرِ فَإِنْ أَتَمَّ الصَّلَاةَ أَجْزَأَ عَنْهُ","id":"Telah menceritakan kepada kami ['Abdul Wahhab bin 'Abdul Hakam Al Warraq Al Baghdadi] telah menceritakan kepada kami [Yahya bin Sulaim] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dia berkata, saya bepergian bersama Nabi Shallahu 'alaihi wa sallam, Abu Bakar, Umar dan Utsman, maka mereka melaksanakan shalat Dzuhur dan Ashar dua raka'at-dua raka'at, mereka tidak melakukan shalat sebelum maupun sesudahnya, Abdullah berkata, jika saya melakukan shalat sebelum atau sesudahnya niscaya saya akan menyempurnakan shalatku. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Umar, Ali, Ibnu Abbas, Anas, Imran bin Hushain dan A'isyah. Abu Isa berkata, hadits Ibnu Umar adalah hadits hasan gharib, kami tidak mengetahuinya kecuali dari hadits Yahya bin Sulaim yang seperti ini. Muhammad bin Isma'il berkata, hadits ini telah diriwayatkan dari 'Ubaidullah bin Umar dari seorang lelaki keluarga Suraqah dari Abdullah bin Umar, Abu Isa berkata, telah diriwayatkan dari ['Athiyyah Al Aufi] dari [Ibnu Umar] bahwa Nabi Shallahu 'alaihi wa sallam melaksanakan shalat sunnah tathawwu' dalam bepergian baik sebelum dan sesudah shalat, dan telah shahih dari Nabi Shallahu 'alaihi wa sallam bahwa beliau mengqashar (meringkas) shalatnya sewaktu bepergian, begitu juga Abu Bakar, Umar dan awal-awal dari kekhilafahan Utsman, hadits ini diamalkan oleh kebanyakan ahli ilmu dari kalangan para sahabat Nabi Shallahu 'alaihi wa sallam dan yang lainnya, telah diriwayatkan dari A'isyah bahwa dia menyempurnakan shalat sewaktu safar (bepergian), namun yang berlaku adalah sebagaimana apa yang telah diriwayatkan dari Nabi Shallahu 'alaihi wa sallam dan para sahabatnya, ini adalah pendapat Imam Syafi'i, Ahmad dan Ishaq, namun Imam Syafi'I berkata, mengqashar (meringkas shalat) adalah sebuah keringanan bagi musafir, jika dia menyempurnakan shalat maka itu sah-sah saja."},"500":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدِ بْنِ جُدْعَانَ الْقُرَشِيُّ عَنْ أَبِي نَضْرَةَ قَالَسُئِلَ عِمْرَانُ بْنُ حُصَيْنٍ عَنْ صَلَاةِ الْمُسَافِرِ فَقَالَ حَجَجْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَكْعَتَيْنِوَحَجَجْتُ مَعَ أَبِي بَكْرٍ فَصَلَّى رَكْعَتَيْنِ وَمَعَ عُمَرَ فَصَلَّى رَكْعَتَيْنِ وَمَعَ عُثْمَانَ سِتَّ سِنِينَ مِنْ خِلَافَتِهِ أَوْ ثَمَانِيَ ثَمَانِي فَصَلَّى رَكْعَتَيْنِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Ali bin Zaid bin Jud'an Al Qurasyi] dari [Abu Nadlrah] dia berkata, [Imran bin Hushain] ditanya tentang shalatnya seorang musafir (dalam perjalanan), dia menjawab, saya melaksanakan haji bersama Rasulullah Shallahu 'alaihi wa sallam, lalu beliau shalat dua raka'at, kemudian saya melaksanakan haji bersama Abu Bakar dan dia melaksanakan shalat dua raka'at, dan bersama Umar, dia juga shalat dua raka'at, bersama Utsman selama enam atau delapan tahun pada masa kepemimpinannya juga shalat dua raka'at. Abu Isa berkata, hadits ini shahih."}};
